import functools as _functools_mod  # para lru_cache de helpers puros


@_functools_mod.lru_cache(maxsize=2048)
def _formato_rut_chile_cached(rut_str):
    """Versión cacheada — solo strings inmutables. Ver _formato_rut_chile."""
    return _formato_rut_chile_impl(rut_str)


def _formato_rut_chile(rut_str):
    """Normaliza un RUT chileno y lo formatea como 'XX.XXX.XXX-Y'.
    Si el RUT no tiene DV, lo devuelve sin guión.
    Si está vacío o inválido, devuelve string vacío.

    Ejemplos:
        '255470652'   → '25.547.065-2'
        '25547065-2'  → '25.547.065-2'
        '25.547.065'  → '25.547.065'   (sin DV, asumimos cuerpo)
        '25547065'    → '25.547.065'   (sin DV)

    PERF 2026-05-17: usa lru_cache cuando el input es str/int (la mayoría
    de los casos). En listings con cientos de RUTs repetidos esto ahorra
    cómputo (regex + reverso). Si no es hashable cae al impl directo.
    """
    if rut_str is None:
        return ""
    if isinstance(rut_str, (str, int)):
        try:
            return _formato_rut_chile_cached(str(rut_str))
        except Exception:
            pass
    return _formato_rut_chile_impl(rut_str)


def _formato_rut_chile_impl(rut_str):
    """Implementación real (no cacheada — la cache decoradora la usa)."""
    if not rut_str:
        return ""
    # Extraer solo dígitos y K (DV puede ser K para algunos RUTs)
    clean = re.sub(r"[^0-9kK]", "", str(rut_str)).upper()
    if not clean:
        return ""
    if len(clean) < 2:
        return clean
    # Heurística: si tiene 7-9 dígitos, último es DV. Si tiene < 7, asumir cuerpo sin DV.
    if len(clean) >= 7:
        cuerpo, dv = clean[:-1], clean[-1]
    else:
        cuerpo, dv = clean, ""
    # Formatear cuerpo con puntos cada 3 dígitos desde la derecha
    cuerpo_fmt = ""
    for i, c in enumerate(reversed(cuerpo)):
        if i > 0 and i % 3 == 0:
            cuerpo_fmt = "." + cuerpo_fmt
        cuerpo_fmt = c + cuerpo_fmt
    return f"{cuerpo_fmt}-{dv}" if dv else cuerpo_fmt


def _rut_cuerpo(raw):
    """Devuelve SOLO el cuerpo del RUT (sin puntos, guion ni digito verificador).

    El ERP Random guarda el RUT base en MAEEN.RTEN SIN digito verificador, asi que
    TODA busqueda por RUT debe usar el cuerpo. Daniel 30/05/2026: buscar
    '77.017.350-K' debe encontrar lo mismo que '77017350'.

    Ejemplos:
        '77.017.350-K' -> '77017350'   ;  '77017350-9' -> '77017350'
        '77017350K'    -> '77017350'   ;  '770173509'  -> '77017350'
        '77017350'     -> '77017350'   ;  '8827'       -> '8827'  (numero de doc)
        '12.345.678-9' -> '12345678'
    """
    if not raw:
        return ""
    s = str(raw).strip().upper()
    if "-" in s:                              # con guion: cuerpo = antes del guion
        return re.sub(r"[^0-9K]", "", s.split("-", 1)[0])
    s = re.sub(r"[^0-9K]", "", s)             # limpiar separadores
    if s.endswith("K"):                       # DV K pegado
        return s[:-1]
    if len(s) >= 9:                           # 9 digitos -> ultimo es DV
        return s[:-1]
    return s                                  # 8 o menos digitos -> ya es cuerpo


