# ══════════════════════════════════════════════════════════════
#  PLAYWRIGHT BROWSER POOL — instancia única reutilizada
#  Evita el overhead de launch/close (~700ms) por cada PDF.
#  Thread-safe: un Lock protege el acceso concurrente.
# ══════════════════════════════════════════════════════════════
_pw_lock     = threading.Lock()
_pw_ctx      = None   # sync_playwright() context manager
_pw_browser  = None   # Browser instance reutilizado
_pw_install_attempted = False  # Solo intentamos auto-install una vez por proceso


def _pw_install_chromium_runtime():
    """Intenta descargar Chromium en runtime cuando el build de Railway
    no lo hizo. Solo se intenta UNA VEZ por proceso (flag _pw_install_attempted).
    Tarda ~30-60s la primera vez, después queda cacheado en disco.
    """
    global _pw_install_attempted
    if _pw_install_attempted:
        return False
    import subprocess as _sp, sys as _sys, os as _os
    pw_path = _os.environ.get("PLAYWRIGHT_BROWSERS_PATH", "/app/.pw-browsers")
    print(f"[playwright] Chromium no encontrado. Auto-install en {pw_path}...", flush=True)
    try:
        # 1. Asegurar que el directorio existe y es escribible
        _os.makedirs(pw_path, exist_ok=True)
        # 2. Verificar permisos de escritura ANTES de descargar 170MB
        test_file = _os.path.join(pw_path, ".write_test")
        try:
            with open(test_file, "w") as _f:
                _f.write("ok")
            _os.remove(test_file)
        except Exception as e_perm:
            print(f"[playwright] ✗ Sin permiso de escritura en {pw_path}: {e_perm}", flush=True)
            # Fallback: usar /tmp si /app no es escribible
            pw_path = "/tmp/.pw-browsers"
            _os.environ["PLAYWRIGHT_BROWSERS_PATH"] = pw_path
            _os.makedirs(pw_path, exist_ok=True)
            print(f"[playwright] Fallback path: {pw_path}", flush=True)

        # 3. Marcar intento (después de validar path) — evita loop infinito
        _pw_install_attempted = True

        # 4. Ejecutar playwright install con env vars correctas
        env = {**_os.environ, "PLAYWRIGHT_BROWSERS_PATH": pw_path}
        result = _sp.run(
            [_sys.executable, "-m", "playwright", "install", "chromium"],
            env=env, capture_output=True, text=True, timeout=240
        )
        if result.returncode == 0:
            print(f"[playwright] ✓ Chromium instalado en {pw_path}", flush=True)
            # Listar contenido para debug
            try:
                contents = _os.listdir(pw_path)
                print(f"[playwright]   contenido: {contents[:5]}", flush=True)
            except Exception: pass
            return True
        else:
            print(f"[playwright] ✗ Install falló (exit {result.returncode}):", flush=True)
            print(f"[playwright]   stdout: {result.stdout[-500:]}", flush=True)
            print(f"[playwright]   stderr: {result.stderr[-500:]}", flush=True)
            return False
    except _sp.TimeoutExpired:
        _pw_install_attempted = True
        print(f"[playwright] ✗ Install timeout (>240s)", flush=True)
        return False
    except Exception as e:
        _pw_install_attempted = True
        print(f"[playwright] ✗ Install excepción: {type(e).__name__}: {e}", flush=True)
        return False


def _pw_browser_get():
    """Devuelve el browser compartido; lo lanza si aún no existe o murió.

    Si Chromium no está instalado (build de Railway falló), intenta
    auto-instalarlo en runtime UNA SOLA VEZ por proceso.
    """
    global _pw_ctx, _pw_browser
    with _pw_lock:
        # Verificar si el browser sigue vivo
        if _pw_browser is not None:
            try:
                _ = _pw_browser.contexts  # ping liviano
                return _pw_browser
            except Exception:
                # Murió — limpiar
                try:
                    _pw_ctx.__exit__(None, None, None)
                except Exception:
                    pass
                _pw_ctx = _pw_browser = None

        # Lanzar nuevo browser — con auto-install fallback
        from playwright.sync_api import sync_playwright
        def _try_launch():
            global _pw_ctx, _pw_browser
            _pw_ctx     = sync_playwright()
            pw          = _pw_ctx.__enter__()
            _pw_browser = pw.chromium.launch(
                args=["--no-sandbox", "--disable-dev-shm-usage",
                      "--disable-gpu", "--disable-extensions"]
            )
            return _pw_browser

        try:
            return _try_launch()
        except Exception as e_first:
            err_str = str(e_first)
            # Si el problema es Chromium ausente, intentar auto-install
            if "Executable doesn't exist" in err_str or "playwright install" in err_str:
                # Limpiar ctx parcial
                try:
                    if _pw_ctx is not None:
                        _pw_ctx.__exit__(None, None, None)
                except Exception:
                    pass
                _pw_ctx = _pw_browser = None
                # Auto-install
                if _pw_install_chromium_runtime():
                    # Reintentar launch
                    try:
                        return _try_launch()
                    except Exception as e_retry:
                        print(f"[playwright] Launch falló tras install: {e_retry}", flush=True)
                        raise
                else:
                    # Auto-install falló — propagar el error original
                    raise
            else:
                raise


class PDFEngineUnavailable(Exception):
    """Playwright/Chromium no disponible — el caller debe convertir a HTTP 503."""
    pass


def _pw_pdf(html: str, *, width: str = None, height: str = None,
            page_format: str = None, margin: dict = None,
            wait_fn: str = None, wait_timeout: int = 5000) -> bytes:
    """
    Genera PDF con el browser pool compartido.
    - width/height → tamaño personalizado (etiquetas)
    - page_format  → 'A4', 'Letter', etc.
    - wait_fn      → JS expression string para page.wait_for_function()
    - margin       → dict top/right/bottom/left en mm ('0mm')

    Si Playwright/Chromium no está instalado (problema de deploy), lanza
    PDFEngineUnavailable con mensaje útil — el endpoint que llama debe
    convertir esto a una respuesta 503 amigable, NO al traceback crudo.
    """
    try:
        browser = _pw_browser_get()
    except Exception as e:
        # Casos típicos: Chromium no instalado, versiones desincronizadas,
        # sandbox bloqueado por SELinux, etc.
        err_msg = str(e)
        print(f"[_pw_pdf] Error al obtener browser: {type(e).__name__}: {err_msg[:500]}", flush=True)
        if "Executable doesn't exist" in err_msg or "playwright install" in err_msg:
            # Extraer ruta que faltó para diagnóstico
            import re as _re
            match = _re.search(r"at ([^\s]+headless_shell[^\s]*)", err_msg)
            ruta = match.group(1) if match else "(ruta desconocida)"
            raise PDFEngineUnavailable(
                f"Chromium no se instaló en el deploy. Falta: {ruta}. "
                "El servidor intentó auto-instalarlo pero falló — revisa los logs "
                "de Railway (busca '[playwright]'). Por ahora exporta a Excel."
            ) from e
        # Otro error desconocido — re-raise para no enmascarar bugs
        raise
    page    = browser.new_page()
    try:
        page.set_content(html, wait_until="domcontentloaded")
        if wait_fn:
            try:
                page.wait_for_function(wait_fn, timeout=wait_timeout)
            except Exception:
                pass   # timeout: seguimos con lo que hay
        pdf_kw = dict(print_background=True)
        mrg = margin or {"top": "0mm", "right": "0mm",
                         "bottom": "0mm", "left": "0mm"}
        if width and height:
            pdf_kw.update(width=width, height=height, margin=mrg)
        elif page_format:
            pdf_kw.update(format=page_format, margin=mrg)
        return page.pdf(**pdf_kw)
    finally:
        page.close()

@app.template_filter('from_json')
def from_json_filter(value):
    """Parsea un string JSON almacenado en DB; devuelve lista/dict o []."""
    if not value:
        return []
    try:
        return json.loads(value)
    except Exception:
        return []


@app.template_filter('to_chile')
def to_chile_filter(value):
    """Convierte un datetime UTC (o naive asumido UTC) a hora local Chile.

    Usa zoneinfo('America/Santiago') que maneja correctamente el horario
    de verano (DST) — Chile cambia entre UTC-4 (verano) y UTC-3 (invierno)
    en algunas regiones. Si zoneinfo no está disponible (Python <3.9),
    cae a offset fijo UTC-4 (estándar Santiago continental).
    """
    if not value:
        return value
    try:
        from datetime import timezone, timedelta
        # Si es naive, asumimos UTC (que es como MySQL guarda con NOW() en
        # servidores cloud Clever Cloud / Railway por default).
        if hasattr(value, 'tzinfo'):
            if value.tzinfo is None:
                value = value.replace(tzinfo=timezone.utc)
            try:
                from zoneinfo import ZoneInfo
                return value.astimezone(ZoneInfo("America/Santiago"))
            except Exception:
                # Fallback sin zoneinfo: UTC-4 estándar Santiago
                return value.astimezone(timezone(timedelta(hours=-4)))
    except Exception:
        pass
    return value


@app.template_filter('chile_fmt')
def chile_fmt_filter(value, fmt="%d/%m/%Y %H:%M"):
    """Atajo: convierte a Chile y formatea de una. Más cómodo en plantillas
    que encadenar dos filtros. Ej: {{ user.last_login_at|chile_fmt }}
    """
    converted = to_chile_filter(value)
    if not converted:
        return ""
    try:
        return converted.strftime(fmt)
    except Exception:
        return str(converted)


@app.template_filter('rut_fmt')
def rut_fmt_filter(value):
    """Filtro Jinja: {{ cliente.rut | rut_fmt }} → '25.547.065-2'.
    Llama a _formato_rut_chile() que está definido más arriba (helper).
    """
    return _formato_rut_chile(value)


@app.template_filter('tel_chile_fmt')
def tel_chile_fmt_filter(value):
    """Filtro Jinja: formatea un teléfono chileno raw a formato legible.

    Ej:
        +56977468766   →  '+56 9 7746 8766'
        977468766      →  '+56 9 7746 8766'
        56977468766    →  '+56 9 7746 8766'
        56 9 77468766  →  '+56 9 7746 8766'
        222345678      →  '+56 2 2234 5678'  (fijo Santiago)
        56222345678    →  '+56 2 2234 5678'

    Si el formato no calza con un número chileno reconocible, devuelve el
    valor original sin modificar.

    Uso: {{ visita.contacto_tel | tel_chile_fmt }}

    Nota: aplica SOLO al texto mostrado. NO usar en href="tel:..." porque
    los protocolos necesitan el formato raw (sin espacios).
    """
    if not value:
        return ""
    # Solo dígitos
    digits = "".join(ch for ch in str(value) if ch.isdigit())
    if not digits:
        return str(value)
    # Quitar el prefijo 56 (país Chile) si está presente
    if digits.startswith("56") and len(digits) >= 10:
        digits = digits[2:]
    # Formato celular: 9 dígitos empezando con 9
    if len(digits) == 9 and digits.startswith("9"):
        return f"+56 9 {digits[1:5]} {digits[5:9]}"
    # Formato fijo: 9 dígitos (2 código área + 7 número) — Santiago: empieza con 2
    if len(digits) == 9 and not digits.startswith("9"):
        return f"+56 {digits[0]} {digits[1:5]} {digits[5:9]}"
    # Formato fijo regiones más cortos: 8 dígitos (1 código área + 7)
    if len(digits) == 8:
        return f"+56 {digits[0]} {digits[1:5]} {digits[5:8]}"
    # Si no calza con ningún patrón chileno, devolver original
    return str(value)


@app.template_filter('fromjson_safe')
def fromjson_safe_filter(value):
    """Filtro Jinja: parsea un string JSON sin lanzar excepción.
    Siempre devuelve un DICT (o {} si parseo falla o el valor es list/None).
    Esto evita AttributeError al hacer .get() en templates cuando
    el valor_json guardado es array u otro tipo no esperado.
    Uso típico: {{ tarea.valor_json | fromjson_safe }}
    """
    if not value:
        return {}
    # Si ya es dict, devolverlo
    if isinstance(value, dict):
        return value
    # Si es list u otro tipo, devolver dict vacío (defensivo)
    if not isinstance(value, str):
        return {}
    try:
        parsed = json.loads(value)
        return parsed if isinstance(parsed, dict) else {}
    except Exception:
        return {}


@app.template_filter('fkg')
def fkg_filter(value, decimals=1):
    """Formato kg estilo chileno: 2926.0 → '2.926,0' (punto miles, coma decimal, 1 decimal)"""
    try:
        n = float(value)
        formatted = f"{n:.{decimals}f}"          # "2926.0"
        int_part, dec_part = formatted.split('.')
        neg = int_part.startswith('-')
        int_abs = int_part.lstrip('-')
        # Agregar punto como separador de miles
        with_sep = ""
        for i, ch in enumerate(reversed(int_abs)):
            if i > 0 and i % 3 == 0:
                with_sep = '.' + with_sep
            with_sep = ch + with_sep
        return ('-' if neg else '') + with_sep + ',' + dec_part
    except Exception:
        return '—'

@app.template_filter('fvol')
def fvol_filter(value):
    """Formato volumen cm³ estilo chileno: 5673482 → '5.673.482' (punto miles, sin decimal)"""
    try:
        n = int(round(float(value)))
        s = str(abs(n))
        with_sep = ""
        for i, ch in enumerate(reversed(s)):
            if i > 0 and i % 3 == 0:
                with_sep = '.' + with_sep
            with_sep = ch + with_sep
        return ('-' if n < 0 else '') + with_sep
    except Exception:
        return '—'

@app.template_filter('fm3')
def fm3_filter(value):
    """Formato volumen en m³ estilo chileno (entra cm³): 5673482 → '5,673' (3 decimales, coma)."""
    try:
        m3 = float(value) / 1_000_000.0
        return f"{m3:.3f}".replace(".", ",")
    except Exception:
        return '—'

