def get_erp_conn():
    """
    Conexión de SOLO LECTURA al ERP externo (cloud.random.cl).
    Devuelve None si no se puede conectar (no interrumpe la app).
    NUNCA usar para escribir.
    """
    import pymysql, pymysql.cursors
    connect_timeout = ERP_CONFIG.get("connect_timeout", 10)
    read_timeout    = ERP_CONFIG.get("read_timeout", 15)
    try:
        return pymysql.connect(
            host=ERP_CONFIG["host"],
            port=ERP_CONFIG["port"],
            user=ERP_CONFIG["user"],
            password=ERP_CONFIG["password"],
            database=ERP_CONFIG["database"],
            connect_timeout=connect_timeout,
            read_timeout=read_timeout,
            write_timeout=read_timeout,
            charset="utf8mb4",
            cursorclass=pymysql.cursors.DictCursor,
            autocommit=True,
        )
    except Exception:
        try:
            return pymysql.connect(
                host=ERP_CONFIG["host"],
                port=ERP_CONFIG["port"],
                user=ERP_CONFIG["user"],
                password=ERP_CONFIG["password"],
                database=ERP_CONFIG["database"],
                connect_timeout=connect_timeout,
                read_timeout=read_timeout,
                write_timeout=read_timeout,
                cursorclass=pymysql.cursors.DictCursor,
                autocommit=True,
            )
        except Exception:
            return None


def get_mysql():
    """Abre una conexión directa (usada solo por init_db y utilidades internas).
    Lanza RuntimeError claro si faltan env vars (no intenta conectar a localhost).
    """
    import pymysql, pymysql.cursors
    # Falla limpia si faltan env vars — el assert es mucho más útil que
    # "Connection refused: localhost" cuando MYSQL_HOST está vacío.
    try:
        from config import assert_mysql_configured
        assert_mysql_configured()
    except ImportError:
        pass  # config.py viejo sin la función — seguir con el comportamiento previo
    return pymysql.connect(
        host=MYSQL_CONFIG["host"],
        port=MYSQL_CONFIG["port"],
        user=MYSQL_CONFIG["user"],
        password=MYSQL_CONFIG["password"],
        database=MYSQL_CONFIG["database"],
        connect_timeout=MYSQL_CONFIG.get("connect_timeout", 15),
        charset="utf8mb4",
        cursorclass=pymysql.cursors.DictCursor,
        autocommit=False,
    )


# ── Pool de conexiones ──────────────────────────────────────────
# Mantiene conexiones TCP abiertas y las reutiliza entre requests.
# Elimina el costo de ~250-400 ms por apertura en cada clic.
_db_pool = None
_db_pool_lock = threading.Lock()

def _get_pool():
    global _db_pool
    if _db_pool is not None:
        return _db_pool
    # Falla limpia con mensaje claro si faltan env vars
    try:
        from config import assert_mysql_configured
        assert_mysql_configured()
    except ImportError:
        pass
    with _db_pool_lock:
        if _db_pool is not None:          # doble chequeo post-lock
            return _db_pool
        try:
            import pymysql, pymysql.cursors
            from dbutils.pooled_db import PooledDB
            _db_pool = PooledDB(
                creator        = pymysql,
                # ── FIX 2026-05-17 ──────────────────────────────────────
                # mincached=0  → NO mantener conexiones reposando en pool.
                #                Clever Cloud / Railway egress cierran sockets
                #                idle silenciosamente tras 5-15 min sin tráfico,
                #                dejando "conexiones zombi" que bloqueaban 20s
                #                en .ping() al volver de idle (síntoma: "cuesta
                #                botarme y reconectarme").
                # maxusage=200 → recicla conexiones periódicamente (anti-leak)
                # ping=7       → verifica antes de cursor + execute + fetch
                #                (más agresivo que ping=1)
                # read_timeout=5 → si por algo queda conn muerta, falla en 5s
                #                  en vez de 20s. Write se queda en 20s para
                #                  queries grandes (inserts batch, etc).
                # ─────────────────────────────────────────────────────────
                # ── FIX 2026-05-26 (Daniel — login 10s tras inactividad) ──
                # mincached subió 0 → 2: mantiene 2 conexiones SIEMPRE vivas
                # tras boot. Primer query tras inactividad NO paga el TCP+TLS+
                # auth a Clever Cloud (~150-300ms). Antes, con mincached=0,
                # se cerraban TODAS las conexiones al devolver al pool y la
                # próxima query reabría desde cero.
                mincached      = 2,
                # maxcached 10 → 15: más conexiones reutilizables en ráfagas.
                # maxconnections 20 → 30: más concurrencia con 4 workers × 8
                # threads (Clever Cloud plan típico permite 25-50).
                maxcached      = 15,
                maxconnections = 30,
                maxusage       = 200,
                blocking       = False,
                ping           = 7,
                host           = MYSQL_CONFIG["host"],
                port           = MYSQL_CONFIG["port"],
                user           = MYSQL_CONFIG["user"],
                password       = MYSQL_CONFIG["password"],
                database       = MYSQL_CONFIG["database"],
                # connect_timeout 10 → 5: fail-fast si MySQL no responde.
                # Antes el usuario esperaba 10s para ver el error.
                connect_timeout= MYSQL_CONFIG.get("connect_timeout", 5),
                read_timeout   = 5,
                write_timeout  = 20,
                charset        = "utf8mb4",
                cursorclass    = pymysql.cursors.DictCursor,
                autocommit     = False,
                # Mantener wait_timeout de la sesión MySQL alto para que
                # NUESTRO read_timeout sea siempre el que dispare primero
                # (no MySQL cerrando la conexión por su lado).
                init_command   = "SET SESSION wait_timeout=600",
            )
            print("[ILUS] Pool de conexiones MySQL activo (DBUtils + anti-idle).")

            # ── Heartbeat MySQL en hilo daemon ──────────────────────────
            # Cada 60s ejecuta SELECT 1 para evitar que Clever Cloud / Railway
            # cierren el socket TCP por inactividad. Sin esto, los usuarios
            # que vuelven a la pestaña después de horas pagan 5-15s en el
            # primer request mientras el pool reconecta. Con heartbeat la
            # conexión queda caliente permanentemente.
            try:
                import threading as _threading_kp
                def _db_keepalive():
                    import time as _time_kp
                    while True:
                        _time_kp.sleep(60)
                        try:
                            conn = _db_pool.connection()
                            cur = conn.cursor()
                            try: cur.execute("SELECT 1")
                            finally:
                                try: cur.close()
                                except Exception: pass
                                try: conn.close()      # devuelve al pool
                                except Exception: pass
                        except Exception as _e_kp:
                            print(f"[db-keepalive] {_e_kp}", flush=True)
                _kp_thread = _threading_kp.Thread(target=_db_keepalive, daemon=True, name="db-keepalive")
                _kp_thread.start()
                print("[ILUS] DB keepalive thread iniciado (60s).")
            except Exception as _e_kp_init:
                print(f"[ILUS][WARN] keepalive init falló: {_e_kp_init}", flush=True)
        except ImportError:
            # Si DBUtils no está instalado, degrada a conexión directa
            print("[ILUS][WARN] DBUtils no disponible — sin pool de conexiones.")
            _db_pool = None
    return _db_pool


def get_db():
    """Devuelve una conexión del pool (o una directa si el pool no está disponible).
    Se reutiliza durante todo el request — una sola apertura TCP por página."""
    if "_db" not in g:
        pool = _get_pool()
        g._db = pool.connection() if pool else get_mysql()
    return g._db


# ════════════════════════════════════════════════════════════════════════
# RANDOM ERP — SQL Server READ-ONLY (Cuatro capas de seguridad)
# ════════════════════════════════════════════════════════════════════════
#
# Conexión directa a SQL Server del ERP Random (cloud.random.cl:8058).
# El usuario `usr_sport` tiene rol db_owner por ahora — mientras Random
# nos crea un usuario db_datareader puro, este código IMPONE read-only
# desde la aplicación con 4 capas:
#
#   Capa 1: WHITELIST — _random_sql_query() solo acepta SELECT/WITH
#   Capa 2: BLACKLIST — bloquea palabras peligrosas (INSERT, DROP, etc.)
#   Capa 3: PARAMETRIZACIÓN — pymssql con %s, imposible SQL injection
#   Capa 4: AUTOCOMMIT OFF — sin commit explícito, escrituras no persisten
#
# Único punto de entrada para Random ERP. Cualquier código que necesite
# leer del ERP DEBE pasar por _random_sql_query() o _random_sql_one().
# ════════════════════════════════════════════════════════════════════════

RANDOM_SQL_CFG = {
    "server":   os.environ.get("RANDOM_SQL_HOST", "cloud.random.cl"),
    "port":     int(os.environ.get("RANDOM_SQL_PORT", "8058")),
    "user":     os.environ.get("RANDOM_SQL_USER", "").strip(),
    "password": os.environ.get("RANDOM_SQL_PASS", "").strip(),
    "database": os.environ.get("RANDOM_SQL_DB",   "rd095bd01"),
}

_random_pool      = None
_random_pool_lock = threading.Lock()

# Capa 2: tokens prohibidos (case-insensitive). Si alguno aparece en el SQL,
# la query es rechazada antes de tocar la BD.
_RANDOM_FORBIDDEN_TOKENS = (
    "INSERT", "UPDATE", "DELETE", "DROP", "ALTER", "TRUNCATE",
    "EXEC", "EXECUTE", "MERGE", "GRANT", "REVOKE", "CREATE",
    "BACKUP", "RESTORE", "SHUTDOWN", "OPENROWSET", "OPENQUERY",
    "BULK", "DBCC", "KILL", "RECONFIGURE",
    "INTO ", "; ", "/*", "*/",
    "XP_CMDSHELL", "SP_CONFIGURE", "SP_EXECUTESQL",
)


def _random_sql_pool():
    """Pool perezoso de conexiones a Random SQL Server."""
    global _random_pool
    if _random_pool is not None:
        return _random_pool
    if not RANDOM_SQL_CFG["user"] or not RANDOM_SQL_CFG["password"]:
        return None  # No configurado — endpoints lo manejan devolviendo lista vacía
    with _random_pool_lock:
        if _random_pool is not None:
            return _random_pool
        try:
            import pymssql
            from dbutils.pooled_db import PooledDB
            _random_pool = PooledDB(
                creator        = pymssql,
                mincached      = 1,
                maxcached      = 3,
                maxconnections = 5,
                blocking       = True,
                ping           = 1,
                server         = RANDOM_SQL_CFG["server"],
                port           = RANDOM_SQL_CFG["port"],
                user           = RANDOM_SQL_CFG["user"],
                password       = RANDOM_SQL_CFG["password"],
                database       = RANDOM_SQL_CFG["database"],
                login_timeout  = 10,
                timeout        = 25,
                autocommit     = False,   # Capa 4: sin commit, escrituras NO persisten
                as_dict        = True,
            )
            print(f"[RANDOM SQL] Pool activo → {RANDOM_SQL_CFG['server']}:{RANDOM_SQL_CFG['port']}/{RANDOM_SQL_CFG['database']}")
        except ImportError:
            print("[RANDOM SQL][WARN] pymssql no instalado — instalar con: pip install pymssql")
            _random_pool = None
        except Exception as e:
            print(f"[RANDOM SQL][ERROR] No se pudo crear pool: {e}")
            _random_pool = None
    return _random_pool


def _random_sql_validate(sql: str) -> None:
    """
    Capa 1 + 2 de seguridad. Lanza PermissionError si la query no es segura.
    Se ejecuta SIEMPRE antes de tocar la BD.
    """
    if not sql or not isinstance(sql, str):
        raise PermissionError("Random SQL: query vacía o no es string")
    sql_clean = sql.strip()
    sql_upper = sql_clean.upper()
    # Capa 1: solo SELECT (también permitimos CTE con WITH)
    first_token = sql_upper.split(None, 1)[0] if sql_upper else ""
    if first_token not in ("SELECT", "WITH"):
        raise PermissionError(f"Random SQL: solo SELECT permitido (recibido: '{first_token}')")
    # Capa 2: blacklist de tokens en cualquier lugar
    for tok in _RANDOM_FORBIDDEN_TOKENS:
        if tok in sql_upper:
            raise PermissionError(f"Random SQL: token prohibido en query: '{tok.strip()}'")


def _random_sql_query(sql: str, params=None, max_rows: int = 500):
    """
    ÚNICO punto de entrada permitido para Random ERP SQL Server.
    Devuelve lista de dicts o None si no hay configuración / error de conexión.
    Lanza PermissionError si el SQL viola las reglas de seguridad.

    NUNCA construir SQL con f-strings o concatenación. SIEMPRE usar params.
    Ejemplo correcto:
        _random_sql_query("SELECT TOP 10 * FROM MAEEN WHERE RTEN LIKE %s", (f"{rut}%",))
    """
    _random_sql_validate(sql)   # Capas 1 y 2 — falla antes de conectar
    pool = _random_sql_pool()
    if pool is None:
        return None
    conn = None
    try:
        conn = pool.connection()
        with conn.cursor(as_dict=True) as cur:
            cur.execute(sql, params or ())
            rows = cur.fetchmany(max_rows) if max_rows else cur.fetchall()
        # Capa 4: NO llamamos conn.commit() — cualquier escritura accidental
        # se descarta al cerrar la conexión.
        return [dict(r) for r in rows]
    except PermissionError:
        raise
    except Exception as e:
        # Sanitización: no loguear los params completos (pueden contener RUTs,
        # tokens o datos personales). Solo n parámetros + tipos.
        _p_summary = f"<{len(params) if params else 0} params>" if params else "()"
        print(f"[RANDOM SQL][QUERY ERROR] {e}  ::  SQL={sql[:120]}  ::  params={_p_summary}")
        return None
    finally:
        if conn is not None:
            try: conn.close()
            except Exception: pass


def _random_sql_one(sql: str, params=None):
    """Versión que devuelve solo la primera fila o None."""
    rows = _random_sql_query(sql, params, max_rows=1)
    return rows[0] if rows else None


# ── INSTRUMENTACIÓN SQL 2026-05-26 (Daniel — audit runtime) ──────────
# Wrapper transparente que mide cada query: cuenta queries, suma tiempo,
# y loguea las que duran > _SQL_SLOW_THRESHOLD_MS. Los stats se agregan
# a flask.g para que el after_request los emita en Server-Timing y log.
# Si no estamos en request context, no hace nada (sigue funcionando).
_SQL_SLOW_THRESHOLD_MS = 250


def _sql_track(query, elapsed_ms):
    """Registra una query en el contador del request actual + log si lenta."""
    try:
        # Solo si estamos en request context (request real, no daemon/cron)
        if not hasattr(g, "_sql_count"):
            g._sql_count = 0
            g._sql_ms = 0
        g._sql_count += 1
        g._sql_ms += elapsed_ms
        if elapsed_ms > _SQL_SLOW_THRESHOLD_MS:
            # Limita el SQL en log a 300 chars para no llenar logs
            q_short = " ".join(query.split())[:300]
            try:
                ep = request.endpoint or request.path
            except Exception:
                ep = "?"
            print(f"[sql-slow] endpoint={ep} duration_ms={elapsed_ms} sql={q_short}",
                  flush=True)
    except Exception:
        # Fuera de request context o g no disponible — ignorar silenciosamente
        pass


def mysql_fetchone(query, params=None):
    _t0 = time.time()
    try:
        with get_db().cursor() as cur:
            cur.execute(query, params or ())
            return cur.fetchone()
    finally:
        _sql_track(query, int((time.time() - _t0) * 1000))


def mysql_fetchall(query, params=None):
    _t0 = time.time()
    try:
        with get_db().cursor() as cur:
            cur.execute(query, params or ())
            return cur.fetchall()
    finally:
        _sql_track(query, int((time.time() - _t0) * 1000))


def mysql_execute(query, params=None):
    _t0 = time.time()
    try:
        conn = get_db()
        with conn.cursor() as cur:
            cur.execute(query, params or ())
        conn.commit()
    finally:
        _sql_track(query, int((time.time() - _t0) * 1000))


def mysql_execute_returning_rowcount(query, params=None):
    """Igual que mysql_execute pero devuelve cur.rowcount (cuántas filas
    fueron afectadas). Útil para backfills/migraciones donde el caller
    quiere reportar cuántas filas se tocaron."""
    _t0 = time.time()
    try:
        conn = get_db()
        with conn.cursor() as cur:
            cur.execute(query, params or ())
            n = cur.rowcount
        conn.commit()
        return n
    finally:
        _sql_track(query, int((time.time() - _t0) * 1000))


