def ensure_erp_table_index():
    """Añade índice en etiquetas.SKU si no existe — mejora velocidad de búsqueda."""
    try:
        conn = get_mysql()
        with conn.cursor() as cur:
            cur.execute("""
                SELECT COUNT(*) AS cnt FROM information_schema.statistics
                WHERE table_schema = DATABASE()
                  AND table_name   = %s
                  AND index_name   = 'idx_sku'
            """, (ERP_TABLE,))
            if cur.fetchone()["cnt"] == 0:
                cur.execute(f"CREATE INDEX idx_sku ON `{ERP_TABLE}` (SKU(90))")
                conn.commit()
        conn.close()
    except Exception as e:
        print(f"[INFO] No se pudo crear índice en {ERP_TABLE}: {e}")


def sync_erp_table(product, bultos, conn):
    """
    Sincroniza los datos de app_products + app_bultos en la tabla compartida `etiquetas`.
    Usa INSERT ... ON DUPLICATE KEY UPDATE para manejar crear y editar.
    `Codigo` es la PK (INT) de esa tabla.
    """
    try:
        codigo_int = int(product.get("codigo") or 0)
        if not codigo_int:
            return

        pv_calc = lambda l, a, al: round(float(l or 0) * float(a or 0) * float(al or 0) / 4000.0, 4)

        sorted_b = sorted(bultos, key=lambda b: int(b.get("bulto_num", 0)))
        peso_total = round(sum(float(b.get("peso", 0)) for b in sorted_b), 2)
        pv_total   = round(sum(pv_calc(b.get("largo",0), b.get("ancho",0), b.get("alto",0)) for b in sorted_b), 4)

        data = {
            "Codigo":                   codigo_int,
            "SKU":                      product.get("sku", ""),
            "Nombre":                   product.get("nombre", ""),
            "Estado":                   product.get("estado", "Confirmado"),
            "Bultos":                   len(sorted_b),
            "Peso Total":               peso_total,
            "Peso Volumetrico total":   pv_total,
        }

        # Por bulto (posiciones 1–27)
        for i in range(1, 28):
            suf_dim = "" if i == 1 else str(i)            # "Largo ( cm )", "Largo ( cm )2"...
            suf_pv  = "" if i == 1 else f" {i}"           # "Peso Volumetrico", "Peso Volumetrico 2"...
            b = sorted_b[i - 1] if i <= len(sorted_b) else None
            if b:
                l = float(b.get("largo", 0))
                a = float(b.get("ancho", 0))
                al = float(b.get("alto", 0))
                p  = float(b.get("peso", 0))
                data[f"Largo ( cm ){suf_dim}"] = l
                data[f"Ancho ( cm ){suf_dim}"] = a
                data[f"Alto ( cm ){suf_dim}"]  = al
                data[f"Peso (kg){suf_dim}"]    = p
                data[f"Peso Volumetrico{suf_pv}"] = pv_calc(l, a, al)
            else:
                data[f"Largo ( cm ){suf_dim}"] = 0
                data[f"Ancho ( cm ){suf_dim}"] = 0
                data[f"Alto ( cm ){suf_dim}"]  = 0
                data[f"Peso (kg){suf_dim}"]    = 0
                data[f"Peso Volumetrico{suf_pv}"] = 0

        cols   = list(data.keys())
        c_sql  = ", ".join(f"`{c}`" for c in cols)
        p_sql  = ", ".join(["%s"] * len(cols))
        upd    = ", ".join(f"`{c}`=%s" for c in cols if c != "Codigo")
        sql    = f"INSERT INTO `{ERP_TABLE}` ({c_sql}) VALUES ({p_sql}) ON DUPLICATE KEY UPDATE {upd}"

        ins_vals = [data[c] for c in cols]
        upd_vals = [data[c] for c in cols if c != "Codigo"]

        with conn.cursor() as cur:
            cur.execute(sql, ins_vals + upd_vals)
    except Exception as exc:
        print(f"[WARN] sync_erp_table: {exc}")


def delete_from_erp_table(codigo, conn):
    """Elimina el registro de la tabla etiquetas por Codigo (PK INT)."""
    try:
        codigo_int = int(codigo or 0)
        if not codigo_int:
            return
        with conn.cursor() as cur:
            cur.execute(f"DELETE FROM `{ERP_TABLE}` WHERE `Codigo`=%s", (codigo_int,))
    except Exception as exc:
        print(f"[WARN] delete_from_erp_table: {exc}")


def init_mysql_schema():
    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            cur.execute(f"""
                CREATE TABLE IF NOT EXISTS `{AUTH_TABLE}` (
                    id           INT AUTO_INCREMENT PRIMARY KEY,
                    username     VARCHAR(190) NOT NULL UNIQUE,
                    nombre       VARCHAR(190) NOT NULL,
                    password_hash VARCHAR(255) NOT NULL,
                    phone        VARCHAR(40)  DEFAULT NULL,
                    role         VARCHAR(20)  NOT NULL DEFAULT 'editor',
                    active       TINYINT(1)   NOT NULL DEFAULT 1,
                    created_at   TIMESTAMP    NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_at   TIMESTAMP    NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
            """)
            try:
                cur.execute(f"ALTER TABLE `{AUTH_TABLE}` ADD COLUMN phone VARCHAR(40) DEFAULT NULL AFTER password_hash")
            except Exception:
                pass
            # Datos de calidad opcionales del usuario (perfil) — todos NULL-able
            for col_sql in [
                f"ALTER TABLE `{AUTH_TABLE}` ADD COLUMN foto_url   VARCHAR(500) DEFAULT NULL COMMENT 'URL de foto de perfil (Cloudinary)'",
                f"ALTER TABLE `{AUTH_TABLE}` ADD COLUMN rut        VARCHAR(20)  DEFAULT NULL",
                f"ALTER TABLE `{AUTH_TABLE}` ADD COLUMN cargo      VARCHAR(120) DEFAULT NULL",
                f"ALTER TABLE `{AUTH_TABLE}` ADD COLUMN genero     VARCHAR(20)  DEFAULT NULL COMMENT 'masculino|femenino|otro|prefiero_no_decir'",
                f"ALTER TABLE `{AUTH_TABLE}` ADD COLUMN direccion  VARCHAR(300) DEFAULT NULL",
                f"ALTER TABLE `{AUTH_TABLE}` ADD COLUMN comuna     VARCHAR(100) DEFAULT NULL",
                f"ALTER TABLE `{AUTH_TABLE}` ADD COLUMN ciudad     VARCHAR(100) DEFAULT NULL",
                f"ALTER TABLE `{AUTH_TABLE}` ADD COLUMN fecha_nac  DATE         DEFAULT NULL",
                # 2026-05-14: tracking de actividad para gestión de usuarios
                f"ALTER TABLE `{AUTH_TABLE}` ADD COLUMN last_login_at   DATETIME    DEFAULT NULL COMMENT 'Última vez que el usuario inició sesión'",
                f"ALTER TABLE `{AUTH_TABLE}` ADD COLUMN last_login_ip   VARCHAR(64) DEFAULT NULL",
                f"ALTER TABLE `{AUTH_TABLE}` ADD COLUMN login_count     INT         DEFAULT 0    COMMENT 'Total de logins exitosos del usuario'",
                # 2026-05-18: heartbeat por request — alimenta el LED online/offline en /admin/users
                f"ALTER TABLE `{AUTH_TABLE}` ADD COLUMN last_seen_at    DATETIME    DEFAULT NULL COMMENT 'Última actividad del usuario (heartbeat por request, throttle 60s)'",
                f"ALTER TABLE `{AUTH_TABLE}` ADD INDEX idx_last_seen (last_seen_at)",
            ]:
                try:
                    cur.execute(col_sql)
                except Exception:
                    pass
            cur.execute(f"""
                CREATE TABLE IF NOT EXISTS `{PRODUCTS_TABLE}` (
                    id         INT AUTO_INCREMENT PRIMARY KEY,
                    sku        VARCHAR(120) NOT NULL UNIQUE,
                    nombre     VARCHAR(255) NOT NULL,
                    estado     VARCHAR(40)  NOT NULL DEFAULT 'Pendiente',
                    codigo     VARCHAR(120) NOT NULL DEFAULT '',
                    erp_sync   TINYINT(1)   NOT NULL DEFAULT 0,
                    created_by VARCHAR(190) DEFAULT NULL,
                    updated_by VARCHAR(190) DEFAULT NULL,
                    created_at TIMESTAMP    NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    updated_at TIMESTAMP    NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
            """)
            cur.execute(f"""
                CREATE TABLE IF NOT EXISTS `{BULTOS_TABLE}` (
                    id         INT AUTO_INCREMENT PRIMARY KEY,
                    product_id INT  NOT NULL,
                    bulto_num  INT  NOT NULL,
                    largo      DECIMAL(12,2) NOT NULL DEFAULT 0,
                    ancho      DECIMAL(12,2) NOT NULL DEFAULT 0,
                    alto       DECIMAL(12,2) NOT NULL DEFAULT 0,
                    peso       DECIMAL(12,2) NOT NULL DEFAULT 0,
                    UNIQUE KEY uniq_product_bulto (product_id, bulto_num),
                    CONSTRAINT fk_bulto_product
                        FOREIGN KEY (product_id) REFERENCES `{PRODUCTS_TABLE}`(id)
                        ON DELETE CASCADE
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
            """)
            cur.execute(f"""
                CREATE TABLE IF NOT EXISTS `{PHOTOS_TABLE}` (
                    id         INT AUTO_INCREMENT PRIMARY KEY,
                    product_id INT          NOT NULL,
                    filename   VARCHAR(255) NOT NULL,
                    orden      INT          NOT NULL DEFAULT 1,
                    created_at TIMESTAMP    NOT NULL DEFAULT CURRENT_TIMESTAMP,
                    CONSTRAINT fk_photo_product
                        FOREIGN KEY (product_id) REFERENCES `{PRODUCTS_TABLE}`(id)
                        ON DELETE CASCADE
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
            """)

            for username, nombre, role, password in DEFAULT_USERS:
                cur.execute(f"SELECT id FROM `{AUTH_TABLE}` WHERE username=%s", (username,))
                existing = cur.fetchone()
                if existing:
                    cur.execute(
                        f"UPDATE `{AUTH_TABLE}` SET nombre=%s, role=%s, active=1 WHERE id=%s",
                        (nombre, role, existing["id"]),
                    )
                else:
                    cur.execute(
                        f"INSERT INTO `{AUTH_TABLE}` (username,nombre,password_hash,role,active) VALUES (%s,%s,%s,%s,1)",
                        (username, nombre, generate_password_hash(password), role),
                    )
        conn.commit()
    finally:
        conn.close()


def init_resets_table():
    """Crea la tabla de tokens de recuperación de contraseña + migración
    idempotente del flag `requires_password_change` en AUTH_TABLE.
    """
    conn = get_db()
    with conn.cursor() as cur:
        cur.execute(f"""
            CREATE TABLE IF NOT EXISTS `{RESETS_TABLE}` (
                id         INT AUTO_INCREMENT PRIMARY KEY,
                user_id    INT NOT NULL,
                token      VARCHAR(120) NOT NULL UNIQUE,
                expires_at DATETIME NOT NULL,
                used       TINYINT(1) NOT NULL DEFAULT 0,
                created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
                INDEX idx_token (token),
                INDEX idx_user  (user_id)
            ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
        """)
        # Flag: usuario debe crear/cambiar contraseña en su próximo login.
        # Lo seteamos en =1 cuando admin crea usuario sin clave manual.
        # Se limpia al activar la cuenta vía /welcome/<token> o /reset/<token>.
        try:
            cur.execute(
                f"ALTER TABLE `{AUTH_TABLE}` "
                f"ADD COLUMN requires_password_change TINYINT(1) NOT NULL DEFAULT 0"
            )
        except Exception:
            pass  # ya existe
    conn.commit()


def init_security_tables():
    """Tablas auxiliares de seguridad/observabilidad:

      app_audit_log     — trazabilidad de eventos críticos (login, reset,
                          cambios de roles). Aditivo, no interfiere con
                          lógica de negocio existente.
      app_cache_signals — bus de invalidación cross-worker. Cada worker
                          consulta `updated_at` para saber si su caché
                          local quedó obsoleto (relevante con 2+ workers
                          de gunicorn donde cada uno tiene su propio cache).
    """
    conn = get_db()
    with conn.cursor() as cur:
        cur.execute("""
            CREATE TABLE IF NOT EXISTS app_audit_log (
                id          BIGINT AUTO_INCREMENT PRIMARY KEY,
                ts          DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
                user_id     INT NULL,
                username    VARCHAR(190) NULL,
                role        VARCHAR(40)  NULL,
                ip          VARCHAR(64)  NULL,
                action      VARCHAR(60)  NOT NULL,
                target_type VARCHAR(40)  NULL,
                target_id   VARCHAR(80)  NULL,
                status      VARCHAR(20)  NOT NULL DEFAULT 'ok',
                details     TEXT NULL,
                INDEX idx_ts      (ts),
                INDEX idx_user    (user_id),
                INDEX idx_action  (action),
                INDEX idx_target  (target_type, target_id)
            ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
        """)
        cur.execute("""
            CREATE TABLE IF NOT EXISTS app_cache_signals (
                scope      VARCHAR(60) NOT NULL PRIMARY KEY,
                updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP
                            ON UPDATE CURRENT_TIMESTAMP
            ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
        """)
        # ── app_rate_limits — bucket persistente cross-worker ──────────
        # FIX seguridad 2026-05-17: antes los buckets vivían en memoria
        # de cada worker gunicorn → con 2 workers el límite efectivo se
        # duplicaba (round-robin). Ahora se persiste en BD con ventanas
        # truncadas (window_start = floor(now / window) * window) para
        # que todos los workers compartan el mismo contador.
        cur.execute("""
            CREATE TABLE IF NOT EXISTS app_rate_limits (
                scope        VARCHAR(64)  NOT NULL,
                identifier   VARCHAR(190) NOT NULL,
                window_start DATETIME     NOT NULL,
                count        INT          NOT NULL DEFAULT 1,
                PRIMARY KEY (scope, identifier, window_start),
                INDEX idx_window (window_start)
            ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
        """)
    conn.commit()


def init_transporte_tables():
    """Crea tablas del módulo Transporte y Distribución."""
    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            cur.execute("""
                CREATE TABLE IF NOT EXISTS transport_commitments (
                    id              INT AUTO_INCREMENT PRIMARY KEY,
                    tido            VARCHAR(5)   NOT NULL,
                    nudo            VARCHAR(15)  NOT NULL,
                    endo            VARCHAR(20)  NOT NULL DEFAULT '',
                    fecha_emision   DATE,
                    fecha_entrega   DATE,
                    cliente_nombre  VARCHAR(200),
                    cliente_rut     VARCHAR(20),
                    comuna          VARCHAR(100),
                    direccion       VARCHAR(300),
                    telefono        VARCHAR(50),
                    email           VARCHAR(150),
                    valor_neto      DECIMAL(14,2) DEFAULT 0,
                    valor_bruto     DECIMAL(14,2) DEFAULT 0,
                    costo_zz        DECIMAL(10,2) DEFAULT 0,
                    tiene_saldo     TINYINT(1) DEFAULT 1,
                    guia_numero     VARCHAR(20),
                    estado          VARCHAR(50) DEFAULT 'Pendiente',
                    clasificacion   ENUM('despacho','retiro','instalacion','mantencion','garantia') DEFAULT 'despacho',
                    fecha_agenda    DATE,
                    notas           TEXT,
                    erp_synced_at   DATETIME,
                    created_by      VARCHAR(190),
                    updated_by      VARCHAR(190),
                    created_at      DATETIME DEFAULT CURRENT_TIMESTAMP,
                    updated_at      DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
                    UNIQUE KEY uq_doc (tido, nudo),
                    INDEX idx_saldo    (tiene_saldo),
                    INDEX idx_estado   (estado),
                    INDEX idx_fecha    (fecha_emision),
                    INDEX idx_clasif   (clasificacion)
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
            """)
            # Migrar columna clasificacion si ya existía con ENUM antiguo
            try:
                cur.execute("""ALTER TABLE transport_commitments
                    MODIFY COLUMN clasificacion
                    ENUM('despacho','retiro','instalacion','mantencion','garantia')
                    DEFAULT 'despacho'""")
            except Exception:
                pass
            # MIGRACIÓN 2026-05-14: agregar cobertura_pct (% de cantidad ZZ
            # despachada vs total). El sync lo recalcula. Permite mostrar
            # en UI "80% despachado" sin re-consultar el ERP.
            # MIGRACIÓN 2026-05-19: agregar observaciones (OBDO completo) y
            # zz_skus (lista compactada "ZZENVIO,ZZRETIRO") para mostrar en
            # la grilla del monitor sin re-consultar el ERP.
            for _mig in [
                "ALTER TABLE transport_commitments ADD COLUMN cobertura_pct DECIMAL(5,1) DEFAULT 0 COMMENT '% del ZZ ya despachado (CAPRAD1/CAPRCO1)'",
                "ALTER TABLE transport_commitments ADD COLUMN cant_total_zz DECIMAL(12,3) DEFAULT 0 COMMENT 'Total CAPRCO1 de líneas ZZ'",
                "ALTER TABLE transport_commitments ADD COLUMN cant_despachada_zz DECIMAL(12,3) DEFAULT 0 COMMENT 'Total CAPRAD1 de líneas ZZ'",
                "ALTER TABLE transport_commitments ADD COLUMN observaciones TEXT NULL COMMENT 'OBDO crudo del ERP (incluye direccion/tel/email/notas)'",
                "ALTER TABLE transport_commitments ADD COLUMN zz_skus VARCHAR(120) NULL COMMENT 'Lista compacta de SKUs ZZ del doc, ej: ZZENVIO,ZZRETIRO'",
                # MIGRACIÓN 2026-05-24: campos de carga masiva (manifiesto → Excel FedEx/SimplyRoute).
                # Editables desde el modal del manifiesto cuando el documento viene con problemas.
                "ALTER TABLE transport_commitments ADD COLUMN region VARCHAR(80) NULL COMMENT 'Región destino (recipientCity FedEx / Habilidades SimplyRoute)'",
                "ALTER TABLE transport_commitments ADD COLUMN cod_postal VARCHAR(20) NULL COMMENT 'Código postal destino (recipientPostcode FedEx)'",
                "ALTER TABLE transport_commitments ADD COLUMN peso_export DECIMAL(10,3) DEFAULT 0 COMMENT 'Peso total kg para carga masiva (editable en manifiesto)'",
                "ALTER TABLE transport_commitments ADD COLUMN n_bultos INT DEFAULT 1 COMMENT 'Nº de bultos/paquetes para carga masiva'",
            ]:
                try: cur.execute(_mig)
                except Exception: pass
            cur.execute("""
                CREATE TABLE IF NOT EXISTS transport_commitment_lines (
                    id              INT AUTO_INCREMENT PRIMARY KEY,
                    commitment_id   INT NOT NULL,
                    koprct          VARCHAR(30) NOT NULL,
                    nokopr          VARCHAR(300),
                    cantidad        DECIMAL(12,3) DEFAULT 0,
                    cant_despachada DECIMAL(12,3) DEFAULT 0,
                    saldo           DECIMAL(12,3) DEFAULT 0,
                    bodega          VARCHAR(10),
                    peso_unitario   DECIMAL(10,3) DEFAULT 0,
                    volumen_unitario DECIMAL(14,2) DEFAULT 0,
                    FOREIGN KEY (commitment_id)
                        REFERENCES transport_commitments(id) ON DELETE CASCADE,
                    INDEX idx_comm (commitment_id),
                    INDEX idx_koprct (koprct),
                    INDEX idx_comm_saldo (commitment_id, saldo)
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
            """)
            # Migración: agregar índices si la tabla ya existía
            for _idx in [
                "ALTER TABLE transport_commitment_lines ADD INDEX idx_koprct (koprct)",
                "ALTER TABLE transport_commitment_lines ADD INDEX idx_comm_saldo (commitment_id, saldo)",
            ]:
                try: cur.execute(_idx)
                except Exception: pass
            # Migración 2026-05-25: agregar cant_despachada si la tabla
            # fue creada antes de que se añadiera esta columna al CREATE TABLE.
            # La columna es leída por tr_manifiesto_detalle →
            # SELECT cant_despachada FROM transport_commitment_lines.
            try:
                cur.execute(
                    "ALTER TABLE transport_commitment_lines "
                    "ADD COLUMN cant_despachada DECIMAL(12,3) DEFAULT 0"
                )
            except Exception:
                pass  # columna ya existe → ignorar
            cur.execute("""
                CREATE TABLE IF NOT EXISTS transport_manifests (
                    id              INT AUTO_INCREMENT PRIMARY KEY,
                    correlativo     VARCHAR(20) UNIQUE,
                    fecha           DATE NOT NULL,
                    courier         VARCHAR(80) NOT NULL,
                    estado          ENUM('En preparación','En curso','Cerrado','Entregado completo')
                                    DEFAULT 'En preparación',
                    total_items     INT DEFAULT 0,
                    peso_total      DECIMAL(10,3) DEFAULT 0,
                    vol_total       DECIMAL(14,2) DEFAULT 0,
                    peso_pred_total DECIMAL(10,3) DEFAULT 0,
                    costo_total     DECIMAL(12,2) DEFAULT 0,
                    notas           TEXT,
                    created_by      VARCHAR(190),
                    created_at      DATETIME DEFAULT CURRENT_TIMESTAMP,
                    updated_at      DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
            """)
            cur.execute("""
                CREATE TABLE IF NOT EXISTS transport_manifest_items (
                    id              INT AUTO_INCREMENT PRIMARY KEY,
                    manifest_id     INT NOT NULL,
                    commitment_id   INT NOT NULL,
                    orden           INT DEFAULT 0,
                    estado_entrega  ENUM(
                        'En preparación','Entregado a transporte',
                        'En ruta','Entregado','Entrega fallida','Devolución'
                    ) DEFAULT 'En preparación',
                    added_at        DATETIME DEFAULT CURRENT_TIMESTAMP,
                    FOREIGN KEY (manifest_id)
                        REFERENCES transport_manifests(id) ON DELETE CASCADE,
                    FOREIGN KEY (commitment_id)
                        REFERENCES transport_commitments(id),
                    UNIQUE KEY uq_item (manifest_id, commitment_id)
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
            """)
            cur.execute("""
                CREATE TABLE IF NOT EXISTS transport_logs (
                    id          INT AUTO_INCREMENT PRIMARY KEY,
                    entity_type ENUM('commitment','manifest','manifest_item') NOT NULL,
                    entity_id   INT NOT NULL,
                    accion      VARCHAR(80) NOT NULL,
                    detalle     TEXT,
                    usuario     VARCHAR(190),
                    created_at  DATETIME DEFAULT CURRENT_TIMESTAMP,
                    INDEX idx_entity (entity_type, entity_id),
                    INDEX idx_user   (usuario)
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
            """)
            # ── COURIERS ──────────────────────────────────────────────────
            cur.execute("""
                CREATE TABLE IF NOT EXISTS transport_couriers (
                    id              INT AUTO_INCREMENT PRIMARY KEY,
                    nombre          VARCHAR(120) NOT NULL,
                    rut             VARCHAR(20),
                    contacto        VARCHAR(120),
                    telefono        VARCHAR(50),
                    email           VARCHAR(150),
                    tipo            ENUM('nacional','regional','local','internacional') DEFAULT 'nacional',
                    activo          TINYINT(1) DEFAULT 1,
                    notas           TEXT,
                    logo_url        VARCHAR(400),
                    peso_max_bulto  DECIMAL(10,2) DEFAULT 0   COMMENT 'kg máx por bulto (0=sin límite)',
                    peso_max_guia   DECIMAL(10,2) DEFAULT 0   COMMENT 'kg máx por guía (0=sin límite)',
                    vol_max_bulto   DECIMAL(12,2) DEFAULT 0   COMMENT 'cm³ máx por bulto (0=sin límite)',
                    factor_vol      DECIMAL(10,4) DEFAULT 5000 COMMENT 'divisor peso volumétrico (cm³/kg)',
                    created_at      DATETIME DEFAULT CURRENT_TIMESTAMP,
                    updated_at      DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
            """)
            cur.execute("""
                CREATE TABLE IF NOT EXISTS transport_courier_tarifas (
                    id              INT AUTO_INCREMENT PRIMARY KEY,
                    courier_id      INT NOT NULL,
                    zona            VARCHAR(80) NOT NULL DEFAULT 'General',
                    peso_desde      DECIMAL(10,3) NOT NULL DEFAULT 0,
                    peso_hasta      DECIMAL(10,3) NOT NULL DEFAULT 0   COMMENT '0=sin tope',
                    precio_base     DECIMAL(10,2) NOT NULL DEFAULT 0,
                    precio_kg_extra DECIMAL(10,2) DEFAULT 0   COMMENT 'precio por kg sobre peso_desde',
                    moneda          CHAR(3) DEFAULT 'CLP',
                    activo          TINYINT(1) DEFAULT 1,
                    FOREIGN KEY (courier_id)
                        REFERENCES transport_couriers(id) ON DELETE CASCADE,
                    INDEX idx_courier (courier_id)
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
            """)
            # ── COMMUNE-BASED PRICING & CONTRACTS ────────────────────
            cur.execute("""
                CREATE TABLE IF NOT EXISTS transport_courier_comunas (
                    id            INT AUTO_INCREMENT PRIMARY KEY,
                    courier_id    INT NOT NULL,
                    codigo        VARCHAR(20),
                    sucursal      VARCHAR(120),
                    comuna        VARCHAR(120) NOT NULL,
                    zona          VARCHAR(80),
                    region        VARCHAR(80),
                    dias_transito VARCHAR(20),
                    dias_entrega  VARCHAR(50),
                    precios_json  MEDIUMTEXT,
                    FOREIGN KEY (courier_id) REFERENCES transport_couriers(id) ON DELETE CASCADE,
                    INDEX idx_courier_comuna (courier_id, comuna),
                    UNIQUE KEY uq_courier_comuna (courier_id, comuna(100))
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
            """)
            # ── AUDIT LOG DE COTIZACIONES DE COURIERS ────────────────
            # Cada cotización pasa por aquí (INSERT inmediato) más también las
            # ediciones manuales y los "marcar como validada". Es la fuente
            # de verdad para auditorías externas (FedEx) y para que Daniel
            # pueda ver QUÉ bracket se aplicó a QUÉ caso histórico.
            cur.execute("""
                CREATE TABLE IF NOT EXISTS courier_tariff_audit (
                    id                INT AUTO_INCREMENT PRIMARY KEY,
                    cotizacion_at     DATETIME DEFAULT CURRENT_TIMESTAMP,
                    cotizado_por      VARCHAR(190),
                    documento_tido    VARCHAR(10)  NULL,
                    documento_nudo    VARCHAR(40)  NULL,
                    comuna            VARCHAR(120),
                    peso_kg           DECIMAL(10,2),
                    peso_pred_kg      DECIMAL(10,2),
                    courier_id        INT,
                    courier_nombre    VARCHAR(120),
                    bracket_aplicado  VARCHAR(40),
                    precio_calculado  INT,
                    formula_aplicada  VARCHAR(200),
                    fuente            VARCHAR(40),
                    validado          TINYINT(1) DEFAULT 0,
                    notas             TEXT NULL,
                    INDEX idx_doc            (documento_tido, documento_nudo),
                    INDEX idx_courier_fecha  (courier_id, cotizacion_at),
                    INDEX idx_comuna_fecha   (comuna, cotizacion_at),
                    INDEX idx_fuente         (fuente)
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
            """)
            # ── Migraciones idempotentes 22/05/2026: trazabilidad margen+IVA ──
            # Daniel: el Excel es COSTO; el precio al cliente = costo × 1.30 × 1.19.
            # Guardamos los 4 componentes para auditoría exhaustiva (FedEx puede
            # pedir reconstruir cualquier cotización histórica con su breakdown).
            for _mig_aud in [
                "ALTER TABLE courier_tariff_audit ADD COLUMN precio_costo  INT NULL "
                "  COMMENT 'Costo del Excel (lo que ILUS paga al courier)' AFTER precio_calculado",
                "ALTER TABLE courier_tariff_audit ADD COLUMN margen_pct    DECIMAL(5,2) NULL "
                "  COMMENT '% margen comercial aplicado'",
                "ALTER TABLE courier_tariff_audit ADD COLUMN margen_clp    INT NULL "
                "  COMMENT 'CLP de margen sobre costo'",
                "ALTER TABLE courier_tariff_audit ADD COLUMN iva_pct       DECIMAL(5,2) NULL "
                "  COMMENT '% IVA aplicado (Chile 19%)'",
                "ALTER TABLE courier_tariff_audit ADD COLUMN iva_clp       INT NULL "
                "  COMMENT 'CLP de IVA sobre subtotal_neto'",
                "ALTER TABLE courier_tariff_audit ADD COLUMN precio_venta  INT NULL "
                "  COMMENT 'Precio final al cliente (costo + margen + IVA)'",
            ]:
                try:
                    cur.execute(_mig_aud)
                except Exception:
                    pass  # idempotente

            cur.execute("""
                CREATE TABLE IF NOT EXISTS transport_courier_contratos (
                    id           INT AUTO_INCREMENT PRIMARY KEY,
                    courier_id   INT NOT NULL,
                    nombre       VARCHAR(200),
                    descripcion  TEXT,
                    archivo_url  VARCHAR(400),
                    tipo         ENUM('contrato','tarifario','acuerdo','otro') DEFAULT 'contrato',
                    vigente      TINYINT(1) DEFAULT 1,
                    fecha_inicio DATE,
                    fecha_fin    DATE,
                    subido_por   VARCHAR(190),
                    created_at   DATETIME DEFAULT CURRENT_TIMESTAMP,
                    FOREIGN KEY (courier_id) REFERENCES transport_couriers(id) ON DELETE CASCADE
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
            """)
            # Migrations for transport_couriers additional fields
            for _mig in [
                "ALTER TABLE transport_couriers ADD COLUMN website VARCHAR(200)",
                "ALTER TABLE transport_couriers ADD COLUMN direccion VARCHAR(300)",
                "ALTER TABLE transport_couriers ADD COLUMN logo_square_url VARCHAR(400)",
                "ALTER TABLE transport_couriers ADD COLUMN logo_label_url VARCHAR(400)",
                "ALTER TABLE transport_couriers ADD COLUMN nombre_fantasia VARCHAR(120)",
                "ALTER TABLE transport_couriers ADD COLUMN giro VARCHAR(150)",
                "ALTER TABLE transport_couriers ADD COLUMN contacto_cargo VARCHAR(120)",
                "ALTER TABLE transport_couriers ADD COLUMN renovacion_automatica TINYINT(1) DEFAULT 0",
                # MIGRACIÓN 2026-05-24: formato de carga masiva que usa cada courier al exportar
                # un manifiesto. Valores: 'fedex' | 'simplyroute' | 'generic'.
                "ALTER TABLE transport_couriers ADD COLUMN formato_export VARCHAR(20) DEFAULT 'generic' COMMENT 'Plantilla de carga masiva: fedex | simplyroute | generic'",
            ]:
                try: cur.execute(_mig)
                except Exception: pass
            # ── DEFAULT COURIERS (idempotente — INSERT IGNORE / chequeo por nombre) ─
            # Lista canónica de couriers que aparecen en la UI y deben estar siempre.
            # No se sobreescriben los existentes (chequeo por nombre case-insensitive).
            # Alias: "Transportes Melling" (legacy) == "Transportes Milling" (canónico) —
            #        si encontramos el legacy, lo dejamos pero NO insertamos el nuevo.
            _alias_map = {
                'transportes milling': ['transportes melling'],
            }
            _defaults = [
                ('FedEx',                  'internacional'),
                ('Starken',                'nacional'),
                ('Blue Express',           'nacional'),
                ('Clickex',                'local'),
                ('Transporte Felca',       'regional'),
                ('Transportes Milling',    'nacional'),
                ('Envíame',                'nacional'),
                ('Chilexpress',            'nacional'),
            ]
            for _nom, _tipo in _defaults:
                try:
                    _key = _nom.strip().lower()
                    # Buscar el courier por nombre exacto o por alias
                    names_to_check = [_nom] + _alias_map.get(_key, [])
                    placeholders = ','.join(['LOWER(%s)'] * len(names_to_check))
                    cur.execute(
                        f"SELECT id FROM transport_couriers WHERE LOWER(nombre) IN ({placeholders})",
                        tuple(names_to_check)
                    )
                    if not cur.fetchone():
                        cur.execute(
                            "INSERT INTO transport_couriers (nombre, tipo, activo) VALUES (%s, %s, 1)",
                            (_nom, _tipo)
                        )
                except Exception:
                    pass

            # ── FORMATO DE EXPORT por courier (idempotente) ──────────────────
            # Solo setea couriers que siguen en 'generic' (no pisa cambios manuales).
            #   FedEx              → plantilla carga masiva FedEx
            #   Felca + Milling    → plantilla SimplyRoute ("Felca y Milling")
            for _patron, _fmt in [
                ('%fedex%',   'fedex'),
                ('%felca%',   'simplyroute'),
                ('%milling%', 'simplyroute'),
                ('%melling%', 'simplyroute'),  # alias legacy
                ('%clickex%', 'clickex'),
            ]:
                try:
                    cur.execute(
                        "UPDATE transport_couriers SET formato_export=%s "
                        "WHERE LOWER(nombre) LIKE %s "
                        "AND (formato_export IS NULL OR formato_export='generic')",
                        (_fmt, _patron)
                    )
                except Exception:
                    pass

            # ── SEED DEMO de tarifas — sólo para couriers SIN tarifas todavía ─
            # Si un courier ya tiene comunas cargadas (vía Excel) NO lo tocamos.
            # Si está en 0, le sembramos un set demo razonable.
            try:
                _seed_courier_tarifas_demo(cur)
            except Exception as _exc:
                print(f"[init_transporte] seed tarifas demo falló: {_exc}", flush=True)

            # ── SEED VALIDADO: Lo Barnechea — caso muestra FCV 10644 (173.89kg) ───
            # Precios extraídos del Excel maestro (auditoría 21/05/2026).
            # Esto deja Lo Barnechea como comuna 100% validada para pruebas.
            # OJO: este seed pisa los precios DEMO para Lo Barnechea — los datos
            # del Excel son la verdad oficial. NO es idempotente en el sentido
            # estricto (corre cada vez), pero sólo edita lo que necesita y
            # genera audit con fuente='validado_excel'.
            try:
                _seed_lo_barnechea_excel(cur)
            except Exception as _exc:
                print(f"[init_transporte] seed Lo Barnechea Excel falló: {_exc}", flush=True)

        conn.commit()
    finally:
        conn.close()


def _seed_lo_barnechea_excel(cur):
    """Carga precios VALIDADOS del Excel maestro para Lo Barnechea (FCV 10644).

    Caso muestra: 173.89 kg → bracket "100+".
    Idempotente — UPSERT por (courier, comuna), audit insert siempre.
    """
    import json as _json
    COMUNA = "Lo Barnechea"
    REGION = "Metropolitana"
    ZONA   = "RM"

    # Precios validados manualmente contra el Excel maestro (21/05/2026).
    # Estos son los precios CORRECTOS para 173.89 kg → bracket "100+".
    TARIFAS = [
        # (courier_name_lower_match,    {"bracket": precio_CLP_total})
        ('fedex',                       {"100+": 105237}),
        ('starken',                     {"100+": 116329}),
        ('clickex',                     {"100+": 158793}),
        ('transporte felca',            {"100+":  92281}),
        ('transportes milling',         {"100+":  96599}),
        ('blue express',                {"100+": 187558}),
        ('transportes melling',         {"100+":  96599}),  # alias legacy
        ('envíame',                     {"100+": 133923}),  # Starken vía Envíame
        # Adicionales para que rangos < 100 kg tengan algo razonable proporcional
    ]

    # Cargar mapa de couriers
    cur.execute("SELECT id, LOWER(nombre) AS k FROM transport_couriers WHERE activo=1")
    couriers = {r['k']: r['id'] for r in (cur.fetchall() or [])}

    inserted = 0
    audit_inserts = []
    for c_name, brackets_nuevos in TARIFAS:
        cid = couriers.get(c_name)
        if not cid:
            continue
        # Cargar precios actuales
        cur.execute(
            "SELECT id, precios_json FROM transport_courier_comunas "
            "WHERE courier_id=%s AND LOWER(TRIM(comuna))=LOWER(TRIM(%s))",
            (cid, COMUNA)
        )
        row = cur.fetchone()
        if row:
            try:
                precios = _json.loads(row['precios_json'] or '{}') if row['precios_json'] else {}
            except Exception:
                precios = {}
            # ── Limpiar brackets viejos que solapan con el nuevo (criterio 22/05/2026)
            # El lookup ordena por upper_bound ASC y devuelve el primer match. Si
            # mantenemos un bracket viejo "100 al 499" (upper=499) junto al
            # validado "100+" (upper=999999), el peso 173kg cae primero en
            # "100 al 499" y pierde el validado.
            #
            # Solución: para cada bracket NUEVO (ej "100+"), extraer su LOWER
            # bound (100) y borrar viejos cuyo upper > lower. Esto deja brackets
            # de pesos chicos (1, 5, 50) intactos pero quita los que solapan.
            def _peu_local(col_header):
                s = str(col_header).strip().replace(',', '.').replace(' ', '').lower()
                if '+' in s or 'mas' in s or 'more' in s:
                    return 999999.0
                for sep in ['-', 'al']:
                    if sep in s:
                        parts = s.split(sep)
                        try: return float(parts[-1])
                        except Exception: pass
                try: return float(s)
                except Exception: return 999999.0
            def _bracket_lower(col_header):
                """Extrae lower bound. '100+' → 100, '500-1999' → 500, '50' → 0."""
                s = str(col_header).strip().replace(',', '.').replace(' ', '').lower()
                # Caso "100+": el lower es el número
                if '+' in s or 'mas' in s:
                    try: return float(s.replace('+', '').replace('mas', '').strip())
                    except Exception: return 0.0
                # Caso "100al499" o "500-1999"
                for sep in ['-', 'al']:
                    if sep in s:
                        parts = s.split(sep)
                        try: return float(parts[0])
                        except Exception: pass
                # Bracket simple "50": lower = 0 (cubre 0-50)
                return 0.0

            # Para cada bracket nuevo, borrar viejos que SOLAPEN con su rango.
            # Solapan = upper_viejo > lower_nuevo.
            lowers_nuevos = sorted({_bracket_lower(k) for k in brackets_nuevos.keys()})
            min_lower_nuevo = lowers_nuevos[0] if lowers_nuevos else 0
            to_delete = [k for k in list(precios.keys())
                         if _peu_local(k) > min_lower_nuevo and k not in brackets_nuevos]
            for k in to_delete:
                precios.pop(k, None)
            precios.update(brackets_nuevos)
            cur.execute(
                "UPDATE transport_courier_comunas SET precios_json=%s WHERE id=%s",
                (_json.dumps(precios, ensure_ascii=False), row['id'])
            )
        else:
            cur.execute(
                """INSERT INTO transport_courier_comunas
                   (courier_id, comuna, zona, region, dias_transito, precios_json)
                   VALUES (%s,%s,%s,%s,%s,%s)
                   ON DUPLICATE KEY UPDATE precios_json=VALUES(precios_json)""",
                (cid, COMUNA, ZONA, REGION, '1-2 días',
                 _json.dumps(brackets_nuevos, ensure_ascii=False))
            )
        inserted += 1
        # Audit insert por cada bracket
        for bk, pv in brackets_nuevos.items():
            audit_inserts.append((cid, c_name, bk, int(pv)))

    # Insertar audit (sólo si no había ya un audit validado idéntico)
    for cid, c_name, bk, pv in audit_inserts:
        try:
            cur.execute(
                "SELECT id FROM courier_tariff_audit "
                "WHERE courier_id=%s AND LOWER(TRIM(comuna))=LOWER(TRIM(%s)) "
                "  AND bracket_aplicado=%s AND precio_calculado=%s "
                "  AND validado=1 AND fuente='validado_excel' LIMIT 1",
                (cid, COMUNA, bk, pv)
            )
            if cur.fetchone():
                continue  # ya tenemos el audit
            cur.execute(
                """INSERT INTO courier_tariff_audit
                   (cotizado_por, comuna, peso_kg, peso_pred_kg, courier_id, courier_nombre,
                    bracket_aplicado, precio_calculado, formula_aplicada, fuente, validado, notas)
                   VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)""",
                (
                    'sistema (seed)', COMUNA, 173.89, 173.89,
                    cid, c_name, bk, pv,
                    'Seed Excel maestro 21/05/2026', 'validado_excel', 1,
                    'Caso muestra FCV 10644 - 173.89kg (A.Y.M Asociados, Lo Barnechea)'
                )
            )
        except Exception as _ex:
            print(f"[seed_lo_barnechea] audit error c={c_name} bk={bk}: {_ex}", flush=True)
    if inserted:
        print(f"[seed_lo_barnechea_excel] {inserted} tarifas actualizadas + audit",
              flush=True)


def _seed_courier_tarifas_demo(cur):
    """Siembra tarifas DEMO para los couriers principales × comunas clave.

    Idempotente — sólo corre si transport_courier_comunas está vacía.
    Cada courier tiene un perfil de pricing distinto:
        Starken     → barato en RM, más caro lejos
        FedEx       → caro pero rápido (24h)
        Blue Express→ express precio medio-alto
        Clickex     → último km, RM only
        T. Felca    → económico, transit lento
        T. Milling  → económico, transit lento
        Envíame     → mid-tier nacional
        Chilexpress → tier medio
    Los precios usan el formato {"1":..., "5":..., "10":..., "25":..., "50":..., "100":..., "100+":...}.
    """
    import json as _json

    # Comunas a sembrar — (nombre, región, zona, dias_transito)
    COMUNAS = [
        # RM
        ('Santiago',         'Metropolitana', 'RM',     '1'),
        ('Las Condes',       'Metropolitana', 'RM',     '1'),
        ('Providencia',      'Metropolitana', 'RM',     '1'),
        ('Vitacura',         'Metropolitana', 'RM',     '1'),
        ('Lo Barnechea',     'Metropolitana', 'RM',     '1'),
        ('Ñuñoa',            'Metropolitana', 'RM',     '1'),
        ('Maipú',            'Metropolitana', 'RM',     '1'),
        ('Puente Alto',      'Metropolitana', 'RM',     '1'),
        ('La Florida',       'Metropolitana', 'RM',     '1'),
        ('Recoleta',         'Metropolitana', 'RM',     '1'),
        ('Independencia',    'Metropolitana', 'RM',     '1'),
        ('Renca',            'Metropolitana', 'RM',     '1'),
        ('Quinta Normal',    'Metropolitana', 'RM',     '1'),
        ('Cerrillos',        'Metropolitana', 'RM',     '1'),
        ('Pudahuel',         'Metropolitana', 'RM',     '1'),
        ('San Bernardo',     'Metropolitana', 'RM',     '1'),
        ('La Pintana',       'Metropolitana', 'RM',     '1'),
        # Regiones
        ('Viña del Mar',     'Valparaíso',    'V',      '2'),
        ('La Serena',        'Coquimbo',      'IV',     '2'),
        ('Concepción',       'Biobío',        'VIII',   '3'),
        ('Temuco',           'Araucanía',     'IX',     '3'),
        ('Puerto Montt',     'Los Lagos',     'X',      '4'),
        ('Antofagasta',      'Antofagasta',   'II',     '4'),
        ('Iquique',          'Tarapacá',      'I',      '5'),
        ('Punta Arenas',     'Magallanes',    'XII',    '5'),
    ]

    # Multiplicadores de zona — factor que se aplica al precio base RM
    ZONA_MULT = {'RM':1.00, 'V':1.20, 'IV':1.50, 'VIII':1.40, 'IX':1.55,
                 'X':1.75, 'II':2.10, 'I':2.30, 'XII':3.20}

    # Perfiles base por courier — precios "RM" (zona 1)
    # Estructura: {brackets} y multiplicador "RM-only" (None = no RM-only)
    PERFILES = {
        'starken': {
            'base': {'1':3900, '5':5800, '10':8200, '25':12500, '50':19500, '100':30500, '100+':33500},
            'rm_only': False,
            'days_rm':'2-3 días', 'days_reg':'3-5 días',
        },
        'fedex': {  # no es tabla, va a usarse vía API; igual sembramos fallback
            'base': {'1':6500, '5':9800, '10':15200, '25':32000, '50':58000, '100':95000, '100+':108000},
            'rm_only': False,
            'days_rm':'24h',     'days_reg':'1-2 días',
        },
        'blue express': {
            'base': {'1':5200, '5':7500, '10':10800, '25':17500, '50':28500, '100':42000, '100+':46000},
            'rm_only': False,
            'days_rm':'1-2 días','days_reg':'2-4 días',
        },
        'clickex': {
            'base': {'1':4500, '5':6800, '10':9800, '25':14800, '50':22500, '100':34000, '100+':37500},
            'rm_only': True,  # último km — sólo cobertura RM
            'days_rm':'24h',     'days_reg':'—',
        },
        'transporte felca': {
            'base': {'1':3200, '5':4500, '10':6800, '25':10200, '50':16500, '100':25000, '100+':28000},
            'rm_only': False,
            'days_rm':'2-4 días','days_reg':'3-5 días',
        },
        'transportes milling': {
            'base': {'1':3400, '5':4800, '10':7100, '25':10800, '50':17200, '100':26500, '100+':29500},
            'rm_only': False,
            'days_rm':'2-4 días','days_reg':'3-5 días',
        },
        'envíame': {
            'base': {'1':4100, '5':6100, '10':8800, '25':13500, '50':20500, '100':31500, '100+':35000},
            'rm_only': False,
            'days_rm':'1-2 días','days_reg':'2-4 días',
        },
        'chilexpress': {
            'base': {'1':4800, '5':7000, '10':10000, '25':15500, '50':24000, '100':36500, '100+':40500},
            'rm_only': False,
            'days_rm':'1-2 días','days_reg':'2-4 días',
        },
    }

    # Cargar mapa nombre→id (lower) de couriers activos
    cur.execute("SELECT id, LOWER(nombre) AS k FROM transport_couriers WHERE activo=1")
    couriers = {r['k']:r['id'] for r in (cur.fetchall() or [])}

    # Sólo sembrar para couriers que NO tienen tarifas todavía (preserva Excel imports).
    cur.execute("""
        SELECT c.id, LOWER(c.nombre) AS k, COUNT(cc.id) AS n
          FROM transport_couriers c
          LEFT JOIN transport_courier_comunas cc ON cc.courier_id = c.id
         WHERE c.activo = 1
         GROUP BY c.id
    """)
    tarifa_counts = {r['k']: r['n'] for r in (cur.fetchall() or [])}

    total = 0
    sembrados = []
    for c_lower, perfil in PERFILES.items():
        cid = couriers.get(c_lower)
        if not cid:
            continue
        # Si el courier YA tiene tarifas (de Excel u otra fuente), NO lo tocamos.
        if (tarifa_counts.get(c_lower) or 0) > 0:
            continue
        for nom, region, zona, dias in COMUNAS:
            es_rm = (zona == 'RM')
            # Skip si courier es RM-only y la comuna no es RM (sin cobertura)
            if perfil['rm_only'] and not es_rm:
                continue
            mult = ZONA_MULT.get(zona, 1.0)
            precios = {k: int(round(v * mult, -1)) for k, v in perfil['base'].items()}
            dias_tr = perfil['days_rm'] if es_rm else perfil['days_reg']
            try:
                cur.execute(
                    """INSERT IGNORE INTO transport_courier_comunas
                       (courier_id, comuna, zona, region, dias_transito, precios_json)
                       VALUES (%s, %s, %s, %s, %s, %s)""",
                    (cid, nom, zona, region, dias_tr, _json.dumps(precios, ensure_ascii=False))
                )
                if cur.rowcount:
                    total += 1
            except Exception:
                pass
        sembrados.append(c_lower)
    if total:
        print(f"[seed courier tarifas demo] {total} filas insertadas para couriers: {sembrados}",
              flush=True)


PICKUP_REQUESTS_TABLE = "pickup_requests"
PICKUP_PACKAGES_TABLE = "pickup_packages"
PICKUP_PROPOSALS_TABLE = "pickup_proposals"
PICKUP_LOGS_TABLE = "pickup_logs"
PICKUP_ATTACHMENTS_TABLE = "pickup_attachments"
PICKUP_SIGNATURES_TABLE = "pickup_signatures"
PICKUP_SETTINGS_TABLE = "pickup_settings"
PICKUP_TEMPLATES_TABLE = "pickup_templates"


def init_pickup_tables():
    """Crea el modulo de solicitudes de retiro en bodega."""
    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            cur.execute(f"""
                CREATE TABLE IF NOT EXISTS `{PICKUP_REQUESTS_TABLE}` (
                    id                         INT AUTO_INCREMENT PRIMARY KEY,
                    code                       VARCHAR(30) UNIQUE,
                    document_type              VARCHAR(30) NOT NULL,
                    document_number            VARCHAR(60) NOT NULL,
                    customer_name              VARCHAR(200) NOT NULL,
                    customer_rut               VARCHAR(30) NOT NULL,
                    contact_name               VARCHAR(160) NOT NULL,
                    contact_email              VARCHAR(180) NOT NULL,
                    contact_phone              VARCHAR(60) NOT NULL,
                    pickup_person_name         VARCHAR(160) NOT NULL,
                    pickup_person_rut          VARCHAR(30) NOT NULL,
                    pickup_person_phone        VARCHAR(60) NOT NULL,
                    pickup_person_relation     VARCHAR(40) NOT NULL,
                    requested_date             DATE NOT NULL,
                    requested_time_from        TIME NOT NULL,
                    requested_time_to          TIME NOT NULL,
                    proposed_date              DATE NULL,
                    proposed_time_from         TIME NULL,
                    proposed_time_to           TIME NULL,
                    confirmed_date             DATE NULL,
                    confirmed_time_from        TIME NULL,
                    confirmed_time_to          TIME NULL,
                    status                     VARCHAR(40) NOT NULL DEFAULT 'solicitud_recibida',
                    information_quality_score  INT DEFAULT 0,
                    risk_score                 INT DEFAULT 0,
                    total_packages             INT DEFAULT 0,
                    total_weight_kg            DECIMAL(12,3) DEFAULT 0,
                    total_volumetric_weight    DECIMAL(12,3) DEFAULT 0,
                    total_volume_m3            DECIMAL(12,4) DEFAULT 0,
                    invoice_total_amount       DECIMAL(14,2) DEFAULT 0,
                    observations               TEXT,
                    internal_notes             TEXT,
                    public_token               VARCHAR(160) NOT NULL,
                    signature_status           VARCHAR(30) DEFAULT 'pendiente',
                    created_ip                 VARCHAR(80),
                    created_user_agent         VARCHAR(300),
                    created_at                 DATETIME DEFAULT CURRENT_TIMESTAMP,
                    updated_at                 DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
                    closed_at                  DATETIME NULL,
                    INDEX idx_pickup_status (status),
                    INDEX idx_pickup_date (requested_date),
                    INDEX idx_pickup_doc (document_type, document_number),
                    INDEX idx_pickup_token (public_token)
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
            """)
            cur.execute(f"""
                CREATE TABLE IF NOT EXISTS `{PICKUP_PACKAGES_TABLE}` (
                    id                  INT AUTO_INCREMENT PRIMARY KEY,
                    request_id          INT NOT NULL,
                    package_number      INT NOT NULL,
                    length_cm           DECIMAL(10,2) DEFAULT 0,
                    width_cm            DECIMAL(10,2) DEFAULT 0,
                    height_cm           DECIMAL(10,2) DEFAULT 0,
                    weight_kg           DECIMAL(10,3) DEFAULT 0,
                    volumetric_weight   DECIMAL(10,3) DEFAULT 0,
                    volume_m3           DECIMAL(12,4) DEFAULT 0,
                    FOREIGN KEY (request_id) REFERENCES `{PICKUP_REQUESTS_TABLE}`(id) ON DELETE CASCADE,
                    INDEX idx_pickup_pkg (request_id)
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
            """)
            cur.execute(f"""
                CREATE TABLE IF NOT EXISTS `{PICKUP_PROPOSALS_TABLE}` (
                    id             INT AUTO_INCREMENT PRIMARY KEY,
                    request_id     INT NOT NULL,
                    proposed_by    VARCHAR(30) NOT NULL,
                    date           DATE NOT NULL,
                    time_from      TIME NOT NULL,
                    time_to        TIME NOT NULL,
                    message        TEXT,
                    reason         VARCHAR(200),
                    status         VARCHAR(30) DEFAULT 'pending',
                    token          VARCHAR(160),
                    created_at     DATETIME DEFAULT CURRENT_TIMESTAMP,
                    answered_at    DATETIME NULL,
                    FOREIGN KEY (request_id) REFERENCES `{PICKUP_REQUESTS_TABLE}`(id) ON DELETE CASCADE,
                    INDEX idx_pickup_prop (request_id, status)
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
            """)
            cur.execute(f"""
                CREATE TABLE IF NOT EXISTS `{PICKUP_LOGS_TABLE}` (
                    id          INT AUTO_INCREMENT PRIMARY KEY,
                    request_id  INT NOT NULL,
                    actor_type  VARCHAR(30) NOT NULL,
                    actor_name  VARCHAR(180),
                    action      VARCHAR(80) NOT NULL,
                    old_status  VARCHAR(40),
                    new_status  VARCHAR(40),
                    notes       TEXT,
                    ip          VARCHAR(80),
                    user_agent  VARCHAR(300),
                    created_at  DATETIME DEFAULT CURRENT_TIMESTAMP,
                    FOREIGN KEY (request_id) REFERENCES `{PICKUP_REQUESTS_TABLE}`(id) ON DELETE CASCADE,
                    INDEX idx_pickup_log (request_id, created_at)
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
            """)
            cur.execute(f"""
                CREATE TABLE IF NOT EXISTS `{PICKUP_ATTACHMENTS_TABLE}` (
                    id              INT AUTO_INCREMENT PRIMARY KEY,
                    request_id      INT NOT NULL,
                    filename        VARCHAR(260) NOT NULL,
                    original_name   VARCHAR(260),
                    mime_type       VARCHAR(120),
                    uploaded_by     VARCHAR(80) DEFAULT 'cliente',
                    created_at      DATETIME DEFAULT CURRENT_TIMESTAMP,
                    FOREIGN KEY (request_id) REFERENCES `{PICKUP_REQUESTS_TABLE}`(id) ON DELETE CASCADE
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
            """)
            cur.execute(f"""
                CREATE TABLE IF NOT EXISTS `{PICKUP_SIGNATURES_TABLE}` (
                    id              INT AUTO_INCREMENT PRIMARY KEY,
                    request_id      INT NOT NULL,
                    signer_name     VARCHAR(180) NOT NULL,
                    signer_rut      VARCHAR(30) NOT NULL,
                    accepted_terms  TINYINT(1) DEFAULT 1,
                    ip              VARCHAR(80),
                    user_agent      VARCHAR(300),
                    created_at      DATETIME DEFAULT CURRENT_TIMESTAMP,
                    FOREIGN KEY (request_id) REFERENCES `{PICKUP_REQUESTS_TABLE}`(id) ON DELETE CASCADE
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
            """)
            cur.execute(f"""
                CREATE TABLE IF NOT EXISTS `{PICKUP_SETTINGS_TABLE}` (
                    id              INT PRIMARY KEY DEFAULT 1,
                    warehouse_name  VARCHAR(160) DEFAULT 'Bodega ILUS Quilicura',
                    warehouse_addr  VARCHAR(260) DEFAULT 'Av. Presidente Eduardo Frei Montalva 9770, Bod 30, Quilicura.',
                    maps_url        VARCHAR(500) DEFAULT 'https://www.google.com/maps/search/?api=1&query=Av.%20Presidente%20Eduardo%20Frei%20Montalva%209770%20Bod%2030%20Quilicura',
                    open_time       TIME DEFAULT '09:00:00',
                    close_time      TIME DEFAULT '17:30:00',
                    work_days       VARCHAR(30) DEFAULT '1,2,3,4,5',
                    holidays        TEXT,
                    alert_enabled   TINYINT(1) DEFAULT 0,
                    alert_title     VARCHAR(160) DEFAULT 'Aviso importante',
                    alert_message   TEXT,
                    hero_image_1    VARCHAR(260),
                    hero_image_2    VARCHAR(260),
                    hero_image_3    VARCHAR(260),
                    updated_at      DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
            """)
            cur.execute(f"""
                CREATE TABLE IF NOT EXISTS `{PICKUP_TEMPLATES_TABLE}` (
                    id          INT AUTO_INCREMENT PRIMARY KEY,
                    code        VARCHAR(60) UNIQUE,
                    title       VARCHAR(180) NOT NULL,
                    body        TEXT NOT NULL,
                    channel     VARCHAR(30) DEFAULT 'email_whatsapp',
                    active      TINYINT(1) DEFAULT 1
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
            """)
            # Multi-documento (Daniel 2026-05-22): un retiro puede asociar varias
            # facturas/boletas del ERP. Cada doc guarda snapshot + peso/vol/m³ que
            # contribuyó al total del retiro. Permite "+ Agregar otra factura".
            cur.execute("""
                CREATE TABLE IF NOT EXISTS pickup_request_docs (
                    id              INT AUTO_INCREMENT PRIMARY KEY,
                    request_id      INT NOT NULL,
                    document_type   VARCHAR(30) NOT NULL,
                    document_number VARCHAR(60) NOT NULL,
                    cliente_rut     VARCHAR(30),
                    cliente_nombre  VARCHAR(200),
                    observaciones_erp TEXT,
                    peso_real_kg    DECIMAL(12,3) DEFAULT 0,
                    peso_vol_kg     DECIMAL(12,3) DEFAULT 0,
                    volumen_m3      DECIMAL(12,4) DEFAULT 0,
                    n_lineas        INT DEFAULT 0,
                    erp_snapshot    LONGTEXT,
                    added_by        VARCHAR(190),
                    added_at        DATETIME DEFAULT CURRENT_TIMESTAMP,
                    UNIQUE KEY uq_request_doc (request_id, document_type, document_number),
                    INDEX idx_request (request_id),
                    INDEX idx_cliente (cliente_rut),
                    FOREIGN KEY (request_id) REFERENCES `pickup_requests`(id) ON DELETE CASCADE
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
            """)
            # Tabla de bloqueos de retiros: días u horas no disponibles
            cur.execute("""
                CREATE TABLE IF NOT EXISTS pickup_blocks (
                    id           INT AUTO_INCREMENT PRIMARY KEY,
                    fecha        DATE NOT NULL,
                    hora_inicio  TIME NULL
                                 COMMENT 'NULL = bloquea día completo',
                    hora_fin     TIME NULL
                                 COMMENT 'NULL = bloquea hasta el cierre',
                    motivo       VARCHAR(200) DEFAULT '',
                    created_by   VARCHAR(190) DEFAULT NULL,
                    created_at   DATETIME DEFAULT CURRENT_TIMESTAMP,
                    INDEX idx_fecha (fecha)
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
            """)
            # ── ÍNDICES SECUNDARIOS (idempotentes, agregados después de auditoría) ──
            # Migran tablas ya creadas sin estos índices. Si ya existen, MySQL falla
            # con duplicate key — capturamos y seguimos.
            #
            # AUDITORÍA SEGURIDAD/PERFORMANCE (mayo 2026 — Daniel pidió cero brechas):
            # - idx_pickup_token UNIQUE: garantiza que dos solicitudes JAMÁS compartan
            #   el mismo public_token (tokens son secretos por solicitud).
            # - idx_pickup_status_date: acelera el dashboard interno con filtros
            #   combinados (status + fecha confirmada/solicitada).
            # - idx_pickup_doc: ya existía (document_type, document_number).
            # - idx_pickup_confirmed_date: usado por bandeja-hoy y calendar.
            # - idx_pickup_proposed_date: usado por _validar_disponibilidad_slot.
            # - idx_pickup_email: lookups de cliente por email (cron recordatorios).
            for _idx_mig in [
                f"ALTER TABLE `{PICKUP_REQUESTS_TABLE}` ADD INDEX idx_pickup_rut (customer_rut)",
                f"ALTER TABLE `{PICKUP_REQUESTS_TABLE}` ADD INDEX idx_pickup_created (created_at)",
                f"ALTER TABLE `{PICKUP_REQUESTS_TABLE}` ADD INDEX idx_pickup_status_date (status, requested_date)",
                f"ALTER TABLE `{PICKUP_REQUESTS_TABLE}` ADD INDEX idx_pickup_confirmed_date (confirmed_date)",
                f"ALTER TABLE `{PICKUP_REQUESTS_TABLE}` ADD INDEX idx_pickup_proposed_date (proposed_date)",
                f"ALTER TABLE `{PICKUP_REQUESTS_TABLE}` ADD INDEX idx_pickup_email (contact_email)",
                # UNIQUE en public_token: garantiza unicidad. Si hay duplicados, falla
                # silenciosamente (los habrá que limpiar manualmente) — no rompemos boot.
                f"ALTER TABLE `{PICKUP_REQUESTS_TABLE}` ADD UNIQUE INDEX uq_pickup_token (public_token)",
                "ALTER TABLE transport_commitments ADD INDEX idx_tcomm_rut (cliente_rut)",
                "ALTER TABLE transport_commitments ADD INDEX idx_tcomm_agenda (fecha_agenda)",
                f"ALTER TABLE `{PICKUP_LOGS_TABLE}` ADD INDEX idx_plog_req (request_id, created_at)",
                # Propuestas: lookup por request_id + status_pending (lo más frecuente)
                f"ALTER TABLE `{PICKUP_PROPOSALS_TABLE}` ADD INDEX idx_pprop_req_status (request_id, status)",
                # Adjuntos: lookup por request_id
                f"ALTER TABLE `{PICKUP_ATTACHMENTS_TABLE}` ADD INDEX idx_patt_req (request_id)",
                # Firmas: lookup por request_id (bandeja-hoy 'sin_firma')
                f"ALTER TABLE `{PICKUP_SIGNATURES_TABLE}` ADD INDEX idx_psig_req (request_id)",
                # Multi-doc (Daniel 2026-05-22): cubre cliente_rut + lookups por doc
                "ALTER TABLE pickup_request_docs ADD INDEX idx_prd_cliente_rut (cliente_rut)",
                "ALTER TABLE pickup_request_docs ADD INDEX idx_prd_doc (document_type, document_number)",
                # Wizard interno (Daniel 2026-05-23): con_saldo persistido por doc.
                # NULL = no se pudo verificar, 0 = sin saldo (bloqueado), 1 = con saldo.
                # Permite que el wizard sepa si el doc se puede usar para habilitar
                # el paso "Proponer fecha". Si el ERP no responde, queda NULL y la
                # UI muestra warning para verificar manualmente.
                "ALTER TABLE pickup_request_docs ADD COLUMN con_saldo TINYINT NULL DEFAULT NULL COMMENT 'NULL=no verificado, 0=sin saldo (bloqueado), 1=con saldo'",
                "ALTER TABLE pickup_request_docs ADD COLUMN saldo_zz DECIMAL(12,2) NULL DEFAULT NULL COMMENT 'Saldo monetario ZZ al momento de asociar'",
                "ALTER TABLE pickup_request_docs ADD COLUMN saldo_checked_at DATETIME NULL DEFAULT NULL COMMENT 'Cuándo se verificó el saldo por última vez'",
                # Bloqueos: lookup por fecha
                "ALTER TABLE pickup_blocks ADD INDEX idx_pblk_fecha_hora (fecha, hora_inicio)",
            ]:
                try: cur.execute(_idx_mig)
                except Exception: pass

            # ── INTEGRIDAD REFERENCIAL: limpieza de huérfanos ──
            # Daniel auditoría mayo 2026: si una OT pickup_request fue borrada y por
            # algún motivo NO se aplicó el ON DELETE CASCADE (raro, pero posible si
            # alguien hizo un DELETE sin la FK activa en tiempos antiguos), pueden
            # quedar filas hijas huérfanas. Las borramos en cada boot con audit log.
            for _orphan_table in (
                PICKUP_PACKAGES_TABLE,
                PICKUP_PROPOSALS_TABLE,
                PICKUP_LOGS_TABLE,
                PICKUP_ATTACHMENTS_TABLE,
                PICKUP_SIGNATURES_TABLE,
                "pickup_request_docs",
            ):
                try:
                    cur.execute(
                        f"SELECT COUNT(*) AS n FROM `{_orphan_table}` "
                        f"WHERE request_id NOT IN (SELECT id FROM `{PICKUP_REQUESTS_TABLE}`)"
                    )
                    _row = cur.fetchone() or {}
                    _n_orphans = int((_row.get("n") if isinstance(_row, dict) else _row[0]) or 0)
                    if _n_orphans > 0:
                        cur.execute(
                            f"DELETE FROM `{_orphan_table}` "
                            f"WHERE request_id NOT IN (SELECT id FROM `{PICKUP_REQUESTS_TABLE}`)"
                        )
                        print(f"[init_pickup_tables] CLEANUP {_orphan_table}: "
                              f"{_n_orphans} huérfanos borrados", flush=True)
                except Exception as _e_orphan:
                    # Si la tabla no existe aún o falla, no rompemos boot
                    print(f"[init_pickup_tables] cleanup {_orphan_table} skipped: {_e_orphan}",
                          flush=True)
            # Migración: capacidad por franja (peso/volumen/cupos) + colación + step
            for _mig in [
                f"ALTER TABLE `{PICKUP_SETTINGS_TABLE}` ADD COLUMN slot_minutes INT DEFAULT 60 COMMENT 'Duración de cada franja en minutos'",
                f"ALTER TABLE `{PICKUP_SETTINGS_TABLE}` ADD COLUMN slot_step_minutes INT DEFAULT 30 COMMENT 'Cada cuántos min se ofrece un nuevo bloque'",
                f"ALTER TABLE `{PICKUP_SETTINGS_TABLE}` ADD COLUMN lunch_start TIME DEFAULT '13:00:00' COMMENT 'Inicio colación'",
                f"ALTER TABLE `{PICKUP_SETTINGS_TABLE}` ADD COLUMN lunch_end TIME DEFAULT '14:00:00' COMMENT 'Fin colación'",
                f"ALTER TABLE `{PICKUP_SETTINGS_TABLE}` ADD COLUMN max_picks_per_slot INT DEFAULT 5",
                f"ALTER TABLE `{PICKUP_SETTINGS_TABLE}` ADD COLUMN max_kg_per_slot DECIMAL(10,2) DEFAULT 500.00",
                f"ALTER TABLE `{PICKUP_SETTINGS_TABLE}` ADD COLUMN max_m3_per_slot DECIMAL(10,3) DEFAULT 5.000",
                f"ALTER TABLE `{PICKUP_SETTINGS_TABLE}` ADD COLUMN max_picks_per_day INT DEFAULT 30",
                # Nuevos (mayo 2026): capacidad paralela + buffer cierre
                f"ALTER TABLE `{PICKUP_SETTINGS_TABLE}` ADD COLUMN parallel_capacity INT DEFAULT 2 COMMENT 'Retiros simultaneos por bloque'",
                f"ALTER TABLE `{PICKUP_SETTINGS_TABLE}` ADD COLUMN buffer_cierre_min INT DEFAULT 30 COMMENT 'Minutos buffer antes de close_time'",
                # ── FASE 2/3 negociación (Daniel 2026-05-29) ──
                # min_notice_hours: anticipación mínima del cliente (default 24).
                # proposal_expiry_hours: vencimiento de propuesta (default 48).
                # expires_at: timestamp de vencimiento por propuesta (ping-pong).
                f"ALTER TABLE `{PICKUP_SETTINGS_TABLE}` ADD COLUMN min_notice_hours INT DEFAULT 24 COMMENT 'Anticipacion minima del cliente en horas'",
                f"ALTER TABLE `{PICKUP_SETTINGS_TABLE}` ADD COLUMN proposal_expiry_hours INT DEFAULT 48 COMMENT 'Horas hasta que una propuesta vence'",
                f"ALTER TABLE `{PICKUP_PROPOSALS_TABLE}` ADD COLUMN expires_at DATETIME NULL DEFAULT NULL COMMENT 'Vencimiento de la propuesta (hora Chile)'",
            ]:
                try: cur.execute(_mig)
                except Exception: pass
            # Re-baseline (idempotente): los registros viejos podían tener
            # slot_minutes=60 (modelo legacy). El calendario público nuevo
            # asume bloques de 30 min. Solo actualizamos si está en 60
            # (no tocamos valores custom no-estándar).
            try:
                cur.execute(
                    f"UPDATE `{PICKUP_SETTINGS_TABLE}` SET slot_minutes=30 "
                    f"WHERE slot_minutes=60 OR slot_minutes IS NULL"
                )
            except Exception:
                pass
            # parallel_capacity NULL → 2 (default), buffer_cierre NULL → 30
            try:
                cur.execute(
                    f"UPDATE `{PICKUP_SETTINGS_TABLE}` SET parallel_capacity=2 "
                    f"WHERE parallel_capacity IS NULL"
                )
            except Exception:
                pass
            try:
                cur.execute(
                    f"UPDATE `{PICKUP_SETTINGS_TABLE}` SET buffer_cierre_min=30 "
                    f"WHERE buffer_cierre_min IS NULL"
                )
            except Exception:
                pass

            # Migración: workflow de validación de documentación (proceso interno)
            # Permite que ILUS valide los datos del cliente antes de proponer fecha.
            for _mig in [
                f"ALTER TABLE `{PICKUP_REQUESTS_TABLE}` ADD COLUMN doc_validation_status "
                f"ENUM('pendiente','en_revision','ok','incompleto') DEFAULT 'pendiente' "
                f"COMMENT 'Estado de validación de la documentación del cliente'",
                f"ALTER TABLE `{PICKUP_REQUESTS_TABLE}` ADD COLUMN doc_validated_at DATETIME NULL "
                f"COMMENT 'Fecha en que se validó la documentación'",
                f"ALTER TABLE `{PICKUP_REQUESTS_TABLE}` ADD COLUMN doc_validated_by VARCHAR(190) NULL "
                f"COMMENT 'Usuario que validó la documentación'",
                f"ALTER TABLE `{PICKUP_REQUESTS_TABLE}` ADD COLUMN doc_erp_data MEDIUMTEXT NULL "
                f"COMMENT 'JSON con snapshot del documento del ERP (header + lineas)'",
                f"ALTER TABLE `{PICKUP_REQUESTS_TABLE}` ADD COLUMN doc_validation_notes TEXT NULL "
                f"COMMENT 'Notas internas del validador'",
                f"ALTER TABLE `{PICKUP_REQUESTS_TABLE}` ADD COLUMN peso_real_kg DECIMAL(10,2) DEFAULT NULL "
                f"COMMENT 'Peso real total calculado desde catálogo'",
                f"ALTER TABLE `{PICKUP_REQUESTS_TABLE}` ADD COLUMN peso_vol_kg DECIMAL(10,2) DEFAULT NULL "
                f"COMMENT 'Peso volumétrico total calculado desde catálogo'",
                f"ALTER TABLE `{PICKUP_REQUESTS_TABLE}` ADD COLUMN tiempo_estimado_min INT DEFAULT NULL "
                f"COMMENT 'Tiempo estimado de retiro en minutos (basado en bultos)'",
                # Daniel 2026-05-23: emails adicionales para envío (cliente declarado + email del doc ERP + manualmente agregados)
                f"ALTER TABLE `{PICKUP_REQUESTS_TABLE}` ADD COLUMN extra_emails VARCHAR(800) NULL "
                f"COMMENT 'Emails adicionales separados por coma para enviar notificaciones (además del contact_email)'",
                # Email capturado desde el doc ERP al asociarlo (para luego sugerir como extra_email)
                "ALTER TABLE pickup_request_docs ADD COLUMN email_cliente_erp VARCHAR(180) NULL "
                "COMMENT 'Email del cliente del doc capturado desde ERP al asociar'",
                # Daniel 2026-05-23: flag que indica si el operador hizo selección
                # granular de líneas (true) o se retiran TODAS las líneas (default false).
                "ALTER TABLE pickup_request_docs ADD COLUMN has_seleccion_lineas TINYINT(1) "
                "NOT NULL DEFAULT 0 "
                "COMMENT 'Si 1, solo se retiran las líneas marcadas en pickup_doc_lineas'",
            ]:
                try: cur.execute(_mig)
                except Exception: pass

            # ─────────────────────────────────────────────────────────────
            # Tabla NUEVA: selección granular de líneas por doc asociado.
            # Daniel 2026-05-23: "de dos documentos, que tengan diez y diez
            # productos, podría seleccionar dos y tres productos de cada
            # factura. Eso es el dinamismo que te estoy pidiendo".
            # ─────────────────────────────────────────────────────────────
            cur.execute("""
                CREATE TABLE IF NOT EXISTS pickup_doc_lineas (
                    id                    INT AUTO_INCREMENT PRIMARY KEY,
                    request_id            INT NOT NULL,
                    doc_id                INT NOT NULL,
                    sku                   VARCHAR(80) NOT NULL,
                    descripcion           VARCHAR(300),
                    cantidad_doc          DECIMAL(12,3) DEFAULT 0
                                          COMMENT 'Cantidad original en MAEDDO',
                    cantidad_seleccionada DECIMAL(12,3) DEFAULT 0
                                          COMMENT 'Cantidad que el cliente va a retirar (≤ cantidad_doc)',
                    peso_unit_kg          DECIMAL(10,3) DEFAULT 0,
                    peso_vol_unit_kg      DECIMAL(10,3) DEFAULT 0,
                    vol_unit_m3           DECIMAL(10,5) DEFAULT 0,
                    peso_total_kg         DECIMAL(12,3) DEFAULT 0
                                          COMMENT 'peso_unit_kg * cantidad_seleccionada',
                    peso_vol_total_kg     DECIMAL(12,3) DEFAULT 0,
                    vol_total_m3          DECIMAL(12,5) DEFAULT 0,
                    incluida              TINYINT(1) NOT NULL DEFAULT 1
                                          COMMENT '1 si el operador la marcó para retirar',
                    nota_linea            VARCHAR(300) NULL,
                    created_at            DATETIME DEFAULT CURRENT_TIMESTAMP,
                    updated_at            DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
                    FOREIGN KEY (request_id) REFERENCES `pickup_requests`(id) ON DELETE CASCADE,
                    FOREIGN KEY (doc_id)     REFERENCES pickup_request_docs(id) ON DELETE CASCADE,
                    UNIQUE KEY uq_doc_sku (doc_id, sku),
                    INDEX idx_request (request_id),
                    INDEX idx_doc (doc_id),
                    INDEX idx_doc_incluida (doc_id, incluida)
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
            """)
            cur.execute(f"INSERT IGNORE INTO `{PICKUP_SETTINGS_TABLE}` (id) VALUES (1)")
            cur.execute(
                f"""UPDATE `{PICKUP_SETTINGS_TABLE}`
                    SET warehouse_addr='Av. Presidente Eduardo Frei Montalva 9770, Bod 30, Quilicura.',
                        maps_url='https://www.google.com/maps/search/?api=1&query=Av.%20Presidente%20Eduardo%20Frei%20Montalva%209770%20Bod%2030%20Quilicura'
                    WHERE id=1
                      AND (warehouse_addr IS NULL OR warehouse_addr='' OR warehouse_addr='Bodega principal ILUS, Quilicura')"""
            )
            defaults = [
                ("cierre_anticipado", "Bodega cierra anticipadamente", "Hoy la bodega cerrara anticipadamente. Si tu retiro se ve afectado, te propondremos un nuevo horario."),
                ("sin_disponibilidad", "Sin disponibilidad", "No tenemos disponibilidad para el horario solicitado. Te enviamos una propuesta alternativa para confirmar."),
                ("info_incompleta", "Falta informacion", "Necesitamos completar informacion del documento, contacto o persona autorizada para poder avanzar con tu retiro."),
                ("validar_identidad", "Validacion de identidad", "Para proteger tu pedido, necesitamos validar la identidad de la persona autorizada para retirar."),
                ("recordatorio", "Recordatorio de retiro", "Recuerda presentarte con documento de identidad y la autorizacion correspondiente si retira un tercero."),
            ]
            for code, title, body in defaults:
                cur.execute(
                    f"""INSERT IGNORE INTO `{PICKUP_TEMPLATES_TABLE}` (code,title,body)
                        VALUES (%s,%s,%s)""",
                    (code, title, body),
                )
        conn.commit()
    finally:
        conn.close()


