# ── 2026-05-18: heartbeat last_seen_at ─────────────────────────────────
# Throttle in-process: 1 update por usuario cada 60s máx. Evita que
# usuarios con muchos requests (carga de lista grande, polling) actualicen
# la fila cada segundo. El UPDATE corre en thread daemon usando conexión
# directa (pymysql.connect) — NO usa `g._db` porque eso requiere request
# context (que el thread NO tiene). Esa fue la causa raíz del bug de
# last_login_at antes del FIX 2026-05-18.
_last_seen_cache = {}
_last_seen_lock  = threading.Lock()
_LAST_SEEN_THROTTLE_SEC = 60


def _update_last_seen(uid):
    """Actualiza last_seen_at del usuario (heartbeat). Throttle 60s en
    memoria del proceso. El UPDATE corre en hilo daemon con conexión
    directa (no toca `g`)."""
    if not uid:
        return
    now_ts = time.time()
    with _last_seen_lock:
        last = _last_seen_cache.get(uid, 0)
        if (now_ts - last) < _LAST_SEEN_THROTTLE_SEC:
            return
        _last_seen_cache[uid] = now_ts

    def _do_update():
        # Conexión directa (NO usa get_db → g — el thread no tiene contexto).
        conn = None
        try:
            conn = get_mysql()
            with conn.cursor() as cur:
                cur.execute(
                    f"UPDATE `{AUTH_TABLE}` SET last_seen_at=NOW() WHERE id=%s",
                    (uid,)
                )
            conn.commit()
        except Exception as e:
            print(f"[last-seen] err uid={uid}: {e}", flush=True)
        finally:
            if conn is not None:
                try: conn.close()
                except Exception: pass

    threading.Thread(target=_do_update, daemon=True,
                     name=f"last-seen-{uid}").start()


def load_current_user():
    """
    Carga el usuario actual y sus permisos.

    Estrategia híbrida (perf + freshness):
    — Cachea user en session con TTL=60s (10s para superadmin/admin).
    — Mientras el TTL es válido, NO toca BD (~ahorra 10-40 ms por request).
    — Cuando expira, re-lee de BD (1 query indexada).
    — `permission_set(role)` usa caché en proceso por rol (invalidado por
      `admin_roles_matrix_save`), así que cambios de matriz aplican
      a más tardar 30-60s después.
    — Cambios de rol del usuario aplican al expirar el TTL o tras logout.

    PERF 2026-05-17: TTL subió de 10s → 60s para usuarios normales. En una
    navegación típica con 6-10 requests/min, esto ahorra ~5-9 queries/min
    por usuario. Superadmin/admin mantiene 10s para que cambios de rol
    en /admin/usuarios apliquen rápido al admin que está editando.

    HEARTBEAT 2026-05-18: tras cargar el usuario (sea desde caché o BD),
    invoca _update_last_seen(uid) que asincrónicamente actualiza
    last_seen_at (throttle 60s). Esto alimenta el LED online/offline.

    SHORT-CIRCUIT 2026-05-26 (Daniel — performance audit):
    rutas ultra-livianas (/ping, /_health, /static, /favicon*) NO necesitan
    session ni permisos. Salida temprana: cero lectura de cookie de sesión,
    cero query a la BD. Ahorra ~5-15ms por request en rutas que muchas
    veces se piden 5-15 veces por página (assets estáticos).
    """
    # SHORT-CIRCUIT por path
    _path = request.path or ""
    if (_path.startswith("/static/") or _path == "/ping" or _path == "/_health"
            or _path.startswith("/favicon") or _path == "/robots.txt"
            or _path == "/manifest.json"):
        g.user = None
        g.permissions = permission_set(None)
        return

    g.user = None
    g.permissions = permission_set(None)
    user_id = session.get("user_id")
    if not user_id:
        return

    # ── Intento 1: cache de session si aún fresco ──────────────────
    cached = session.get("_uc")
    if cached and cached.get("id") == user_id:
        cached_ts = cached.get("ts", 0)
        # TTL diferenciado: admin/superadmin 10s, resto 60s
        _ttl = 10 if cached.get("role") in ("superadmin", "admin") else 60
        if (time.time() - cached_ts) < _ttl:
            g.user = cached
            g.permissions = permission_set(cached["role"])
            # Heartbeat last_seen_at (throttle 60s en memoria del proceso)
            _update_last_seen(cached.get("id"))
            return
        # TTL expirado → cae a fetch fresh abajo

    # ── Intento 2: consulta BD ───────────────────────────────────────
    try:
        user = get_auth_user_by_id(user_id)
    except Exception as exc:
        session.clear()
        print(f"[load_current_user] error validando sesión user_id={user_id}: {exc}", flush=True)
        flash("No fue posible validar la sesión. Intenta iniciar sesión de nuevo.", "danger")
        return

    if not user or not user["active"]:
        session.clear()
        return

    user = dict(user)
    g.user = user
    g.permissions = permission_set(user["role"])

    # Renovar cache con timestamp
    session["_uc"] = {
        "id":       user["id"],
        "username": user["username"],
        "nombre":   user["nombre"],
        "role":     user["role"],
        "active":   user["active"],
        "ts":       time.time(),
    }

    # Heartbeat last_seen_at (throttle 60s en memoria del proceso) —
    # alimenta el LED online/offline en /admin/users.
    _update_last_seen(user["id"])


# ══════════════════════════════════════════════════════════════════════
#  AUDIT LOG — trazabilidad de eventos críticos.
#  Failure-tolerant: si la inserción falla NO interrumpe la operación
#  de negocio (solo print al stdout para que aparezca en Railway logs).
# ══════════════════════════════════════════════════════════════════════
def _audit(action: str, *, target_type: str = None, target_id=None,
           details: dict = None, status: str = "ok",
           user_override: dict = None):
    """Inserta una fila en app_audit_log. Nunca lanza excepciones al caller."""
    try:
        u = user_override if user_override is not None else (g.user if hasattr(g, "user") else None)
        user_id  = (u or {}).get("id")
        username = (u or {}).get("username")
        username = username[:190] if username else None
        role     = (u or {}).get("role")
        try:
            ip = _rl_client_ip()
        except Exception:
            ip = None
        det_json = None
        if details is not None:
            try:
                det_json = json.dumps(details, ensure_ascii=False, default=str)[:4000]
            except Exception:
                det_json = str(details)[:4000]
        conn = get_db()
        with conn.cursor() as cur:
            cur.execute(
                """INSERT INTO app_audit_log
                       (user_id, username, role, ip, action,
                        target_type, target_id, status, details)
                   VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s)""",
                (user_id, username, role, ip, action[:60],
                 target_type[:40] if target_type else None,
                 (None if target_id is None else str(target_id)[:80]),
                 status[:20], det_json)
            )
        conn.commit()
    except Exception as exc:
        try:
            print(f"[ILUS][AUDIT] error al registrar '{action}': {exc}", flush=True)
        except Exception:
            pass


# ══════════════════════════════════════════════════════════════════════
#  CACHE SIGNALS — invalidación cross-worker vía BD.
#  Cada worker mira `updated_at` de un scope y compara contra la última
#  marca local. Si avanzó, limpia el caché en memoria local. Polea como
#  máximo cada _CACHE_SIGNAL_POLL_S segundos por scope.
# ══════════════════════════════════════════════════════════════════════
_cache_signal_local: dict = {}
_cache_signal_lock = threading.Lock()
_CACHE_SIGNAL_POLL_S = 30


def _cache_signal_bump(scope: str):
    """Marca un scope como invalidado en BD (notifica a otros workers)."""
    try:
        conn = get_db()
        with conn.cursor() as cur:
            cur.execute(
                """INSERT INTO app_cache_signals (scope, updated_at)
                   VALUES (%s, UTC_TIMESTAMP())
                   ON DUPLICATE KEY UPDATE updated_at = UTC_TIMESTAMP()""",
                (scope[:60],)
            )
        conn.commit()
    except Exception as exc:
        print(f"[ILUS][CACHE-SIGNAL] bump '{scope}' falló: {exc}", flush=True)


def _cache_signal_changed(scope: str) -> bool:
    """True si el scope fue invalidado por otro worker desde el último check.
    Solo consulta la BD como máximo cada _CACHE_SIGNAL_POLL_S segundos."""
    now = time.monotonic()
    with _cache_signal_lock:
        last_ts, last_check = _cache_signal_local.get(scope, (None, 0.0))
        if (now - last_check) < _CACHE_SIGNAL_POLL_S:
            return False
    try:
        row = mysql_fetchone(
            "SELECT updated_at FROM app_cache_signals WHERE scope=%s",
            (scope[:60],)
        )
    except Exception:
        with _cache_signal_lock:
            _cache_signal_local[scope] = (last_ts, now)
        return False
    new_ts = (row or {}).get("updated_at") if row else None
    with _cache_signal_lock:
        prev_ts, _ = _cache_signal_local.get(scope, (None, 0.0))
        _cache_signal_local[scope] = (new_ts, now)
        return (new_ts is not None) and (prev_ts is None or new_ts != prev_ts)


# ══════════════════════════════════════════════════════════════════════
#  ERP CIRCUIT BREAKER — funciones (estado global se define al inicio
#  del archivo, después de _ERP init_engine).
# ══════════════════════════════════════════════════════════════════════
def _erp_breaker_is_open() -> bool:
    """True si el breaker está abierto y aún en cooldown."""
    with _erp_breaker_lock:
        opened = _erp_breaker_state["opened_at"]
        if opened == 0.0:
            return False
        if (time.time() - opened) >= _ERP_BREAKER_COOLDOWN:
            _erp_breaker_state["opened_at"] = 0.0
            return False
        return True


def _erp_breaker_record_success():
    with _erp_breaker_lock:
        _erp_breaker_state["consecutive_failures"] = 0
        _erp_breaker_state["last_success_at"]      = time.time()
        _erp_breaker_state["opened_at"]            = 0.0


def _erp_breaker_record_failure():
    with _erp_breaker_lock:
        _erp_breaker_state["consecutive_failures"] += 1
        _erp_breaker_state["last_failure_at"]       = time.time()
        if _erp_breaker_state["consecutive_failures"] >= _ERP_BREAKER_THRESHOLD:
            if _erp_breaker_state["opened_at"] == 0.0:
                _erp_breaker_state["opened_at"] = time.time()


def safe_erp_fetch_document(tido: str, nudo: str):
    """Wrapper con degradación elegante sobre `_ERP.fetch_document`.

    Retorna **(doc_or_None, status)** donde status es uno de:
      - 'ok'        → doc presente
      - 'not_found' → ERP respondió pero no encontró el documento
      - 'degraded'  → ERP caído / breaker abierto / timeout
      - 'error'     → otro error inesperado

    Recomendado para endpoints/UI que necesiten mostrar un banner
    "ERP no disponible" en vez de un 500. Los call sites antiguos siguen
    usando `_ERP.fetch_document` directo sin cambios.
    """
    if _erp_breaker_is_open():
        return None, "degraded"
    try:
        doc = _ERP.fetch_document(tido, nudo)
        _erp_breaker_record_success()
        if not doc:
            return None, "not_found"
        return doc, "ok"
    except Exception as exc:
        _erp_breaker_record_failure()
        try:
            print(f"[ILUS][ERP] fetch_document falló ({tido}/{nudo}): {exc}", flush=True)
        except Exception:
            pass
        return None, "degraded"


def erp_status_snapshot() -> dict:
    """Estado actual del ERP para UI y health checks."""
    with _erp_breaker_lock:
        s = dict(_erp_breaker_state)
    open_now = _erp_breaker_is_open()
    return {
        "available":            not open_now,
        "breaker_open":         open_now,
        "consecutive_failures": s["consecutive_failures"],
        "last_success_at":      s["last_success_at"] or None,
        "last_failure_at":      s["last_failure_at"] or None,
        "threshold":            _ERP_BREAKER_THRESHOLD,
        "cooldown_seconds":     _ERP_BREAKER_COOLDOWN,
    }


# ══════════════════════════════════════════════════════════════════════
#  RATE LIMITING — persistido en BD (cross-worker)
#  FIX seguridad 2026-05-17 (code review senior):
#  Antes los buckets vivían en memoria del worker, así que con 2 workers
#  de gunicorn el límite efectivo se duplicaba. Ahora se persiste en
#  `app_rate_limits` con ventanas truncadas; todos los workers ven el
#  mismo contador. Fallback a memoria si la BD se cae (degrada bien).
# ══════════════════════════════════════════════════════════════════════
_rl_buckets: dict = {}   # fallback in-memory si la BD falla
_rl_lock = threading.Lock()
_rl_cleanup_started = False


def _rl_client_ip():
    """IP del cliente respetando X-Forwarded-For (Railway está detrás de proxy)."""
    xff = request.headers.get("X-Forwarded-For", "")
    if xff:
        return xff.split(",")[0].strip()
    return request.remote_addr or "0.0.0.0"


def _rl_identifier() -> str:
    """Identificador para el límite. Si el usuario está autenticado usa
    user_id (más estable). Si no, cae a IP. Truncado a 190 chars."""
    try:
        u = getattr(g, "user", None)
        if u and u.get("id"):
            return f"u:{u['id']}"[:190]
    except Exception:
        pass
    return f"ip:{_rl_client_ip()}"[:190]


def _rl_check_memory_fallback(scope, max_attempts, window_seconds):
    """Backup in-memory por worker — solo se usa si la BD no responde."""
    now = time.time()
    key = (_rl_client_ip(), scope)
    with _rl_lock:
        bucket = _rl_buckets.get(key) or []
        bucket = [t for t in bucket if (now - t) < window_seconds]
        if len(bucket) >= max_attempts:
            _rl_buckets[key] = bucket
            return False
        bucket.append(now)
        _rl_buckets[key] = bucket
        if len(_rl_buckets) > 5000:
            _rl_buckets.clear()
            _rl_buckets[key] = bucket
        return True


def _rl_cleanup_loop():
    """Daemon: borra ventanas > 24h cada hora.
    Mantiene la tabla compacta sin necesidad de un cron externo."""
    while True:
        try:
            time.sleep(3600)  # 1 hora
            conn = get_mysql()
            try:
                with conn.cursor() as cur:
                    cur.execute(
                        "DELETE FROM app_rate_limits "
                        "WHERE window_start < (NOW() - INTERVAL 24 HOUR)"
                    )
                conn.commit()
            finally:
                conn.close()
        except Exception as _e_clean:
            print(f"[rate_limit cleanup] {_e_clean}", flush=True)


def _rl_check(scope: str, max_attempts: int, window_seconds: int) -> bool:
    """True si aún hay cupo; False si excedió el límite.
    Persiste en app_rate_limits (cross-worker). Fallback a memoria si la
    BD falla — preferimos NUNCA bloquear al usuario por un bug del limiter.
    """
    global _rl_cleanup_started
    # Arrancar daemon de cleanup la primera vez que se llama el limiter
    if not _rl_cleanup_started:
        try:
            threading.Thread(target=_rl_cleanup_loop, daemon=True,
                             name="rate-limit-cleanup").start()
            _rl_cleanup_started = True
        except Exception:
            pass

    identifier = _rl_identifier()
    # Ventana truncada: floor(now / window) * window → todos los workers
    # convergen al mismo bucket aunque sus relojes difieran en segundos.
    bucket_epoch = int(time.time() // window_seconds) * window_seconds
    window_start = datetime.utcfromtimestamp(bucket_epoch)

    try:
        conn = get_mysql()
        try:
            with conn.cursor() as cur:
                # UPSERT atómico: si la tupla (scope,identifier,window_start)
                # existe → +1, si no → insert con count=1.
                cur.execute(
                    "INSERT INTO app_rate_limits (scope, identifier, window_start, count) "
                    "VALUES (%s, %s, %s, 1) "
                    "ON DUPLICATE KEY UPDATE count = count + 1",
                    (scope[:64], identifier, window_start)
                )
                # Releer el count actualizado
                cur.execute(
                    "SELECT count FROM app_rate_limits "
                    "WHERE scope=%s AND identifier=%s AND window_start=%s",
                    (scope[:64], identifier, window_start)
                )
                row = cur.fetchone()
                conn.commit()
        finally:
            conn.close()
        # row puede ser dict o tupla según el cursor — handle ambos
        if not row:
            return True
        current = row.get("count") if isinstance(row, dict) else row[0]
        return (current or 0) <= max_attempts
    except Exception as exc:
        # Si la BD se cae, no bloqueamos al usuario — caemos al fallback
        # in-memory por worker (peor que cross-worker pero mejor que nada).
        print(f"[rate_limit] BD fallback: {exc}", flush=True)
        return _rl_check_memory_fallback(scope, max_attempts, window_seconds)


def rate_limited(scope: str, max_attempts: int, window_seconds: int,
                 methods=("POST",)):
    """Decorador. Aplica el límite sólo a los métodos indicados (default POST).
    Si excede: redirect a la misma URL con flash para no ejecutar la lógica
    del POST (no consume intento, no envía correo, etc.)."""
    def decorator(view):
        @wraps(view)
        def wrapped(*a, **kw):
            if request.method in methods:
                if not _rl_check(scope, max_attempts, window_seconds):
                    msg = ("Demasiados intentos. Espera unos minutos antes de "
                           "volver a intentar.")
                    accept = (request.headers.get("Accept") or "")
                    xrw    = request.headers.get("X-Requested-With", "")
                    is_ajax = (
                        xrw == "XMLHttpRequest"
                        or accept.startswith("application/json")
                        or request.is_json
                        or "/api/" in request.path
                    )
                    if is_ajax:
                        return jsonify({"ok": False, "error": msg,
                                        "error_codigo": "RATE_LIMIT"}), 429
                    flash(msg, "danger")
                    return redirect(request.path)
            return view(*a, **kw)
        return wrapped
    return decorator


# ══════════════════════════════════════════════════════════════════════
#  CSRF — protección anti Cross-Site Request Forgery
#  FIX seguridad 2026-05-17 (code review senior):
#  Antes el sistema no tenía CSRF en absoluto. Cualquier sitio externo
#  podía forzar a un técnico autenticado a hacer cualquier POST.
#
#  Implementación manual (sin flask-wtf para no agregar dependencias):
#  - Token de 32 bytes generado en sesión la primera vez que se necesita.
#  - Se compara con form.csrf_token o header X-CSRF-Token (para fetch JSON).
#  - Endpoints públicos (login, forgot, reset, welcome, retiros públicos,
#    webhooks) están en _CSRF_EXEMPT_PATHS / _CSRF_EXEMPT_PREFIXES.
#  - El helper Jinja `csrf_token()` lo expone a templates.
#  - JS global en base.html inyecta header X-CSRF-Token en todo fetch().
# ══════════════════════════════════════════════════════════════════════
_CSRF_EXEMPT_PATHS: set = {
    # endpoints públicos que ESTABLECEN o inician sesión: no pueden requerir
    # un token previo porque aún no existe sesión.
    "/login",
    "/auth/olvidar-contrasena",
    # registro/activación públicos (token via URL ya autentica el flujo)
    "/registro-tecnico-externo",
    # formularios públicos sin sesión (clientes externos solicitan retiro)
    "/retiros/solicitar",
}
# Prefijos exentos: cubren rutas dinámicas (token o id variable).
_CSRF_EXEMPT_PREFIXES: tuple = (
    "/auth/restablecer/",      # /auth/restablecer/<token>
    "/welcome/",                # /welcome/<token>
    "/retiros/seguimiento/",    # /retiros/seguimiento/<token>
    "/webhook/",                # webhooks externos (Twilio, etc.)
    "/webhooks/",               # alias plural
)


def _csrf_get_token() -> str:
    """Devuelve el token CSRF actual; lo genera si no existe."""
    tok = session.get("csrf_token")
    if not tok:
        tok = secrets.token_urlsafe(32)
        session["csrf_token"] = tok
    return tok


def _csrf_is_exempt(path: str) -> bool:
    if path in _CSRF_EXEMPT_PATHS:
        return True
    for pref in _CSRF_EXEMPT_PREFIXES:
        if path.startswith(pref):
            return True
    return False


@app.context_processor
def _inject_csrf_token():
    """Expone csrf_token() a TODOS los templates. Sin args, devuelve el
    token de la sesión actual (lo crea si no existe). Igual nombre que
    flask-wtf para que pegar snippets sea trivial."""
    return {"csrf_token": _csrf_get_token}


def _csrf_check_request():
    """Helper: valida CSRF de la request actual. Devuelve un Response
    (jsonify/redirect) si hay que rechazar, None si pasa. Se llama desde
    el `before_request` global tras cargar el usuario."""
    if request.method not in ("POST", "PUT", "DELETE", "PATCH"):
        return None
    path = request.path or ""
    if _csrf_is_exempt(path):
        return None
    token_session = session.get("csrf_token")
    token_req = (request.headers.get("X-CSRF-Token")
                 or request.form.get("csrf_token")
                 or "")
    # Comparación constante de tiempo
    if not token_session or not token_req \
            or not secrets.compare_digest(str(token_session), str(token_req)):
        # Logueo discreto pero útil para diagnosticar formularios sin token
        try:
            print(f"[CSRF] reject path={path} method={request.method} "
                  f"has_session={bool(token_session)} has_req={bool(token_req)}",
                  flush=True)
        except Exception:
            pass
        is_ajax = (
            request.headers.get("X-Requested-With") == "XMLHttpRequest"
            or (request.headers.get("Accept") or "").startswith("application/json")
            or request.is_json
            or "/api/" in path
        )
        if is_ajax:
            return jsonify({"ok": False,
                            "error": "CSRF token inválido. Recarga la página."}), 403
        flash("Tu sesión expiró o el formulario perdió validez. "
              "Recarga la página e intenta de nuevo.", "warning")
        # Si el usuario está autenticado, volvemos a la misma URL vía GET
        if getattr(g, "user", None):
            return redirect(request.path)
        # Sin sesión: al login
        return redirect(url_for("login"))
    return None


def login_required(view):
    @wraps(view)
    def wrapped(*a, **kw):
        if not g.user:
            flash("Inicia sesion para continuar.", "warning")
            return redirect(url_for("login", next=request.path))
        return view(*a, **kw)
    return wrapped


def _is_ajax_request():
    """True si la petición espera JSON (AJAX/wizard/API)."""
    return (
        request.headers.get("X-Wizard") == "1"
        or request.headers.get("X-Requested-With") == "XMLHttpRequest"
        or (request.headers.get("Accept") or "").startswith("application/json")
        or request.is_json
        or "/api/" in request.path
    )


@app.route("/api/whoami")
def api_whoami():
    """Diagnóstico: qué permisos efectivos tiene el usuario actual.
    Útil cuando el usuario reporta 'no puedo crear cliente' o 'no veo X módulo'.
    """
    if not g.user:
        return jsonify({"ok": False, "error": "Sin sesión"}), 401
    perms_dict = dict(g.permissions or {})
    return jsonify({
        "ok": True,
        "usuario": {
            "id":       g.user.get("id"),
            "username": g.user.get("username"),
            "nombre":   g.user.get("nombre"),
            "role":     g.user.get("role"),
        },
        "permissions": perms_dict,
        "modulos_visibles": [k for k in
            ("etiquetas","retiros","mantenciones","transporte","cubicador",
             "comunicaciones","admin","superadmin","ajustes")
            if perms_dict.get(k)],
    })


def require_permission(permission):
    def decorator(view):
        @wraps(view)
        def wrapped(*a, **kw):
            if not g.user:
                if _is_ajax_request():
                    return jsonify({"ok": False,
                                    "error": "Sesión expirada. Vuelve a iniciar sesión.",
                                    "error_codigo": "SIN_SESION"}), 401
                flash("Inicia sesion para continuar.", "warning")
                return redirect(url_for("login", next=request.path))
            # ★ superadmin SIEMPRE pasa todos los checks de permiso
            if g.permissions.get("superadmin"):
                return view(*a, **kw)
            if not g.permissions.get(permission):
                if _is_ajax_request():
                    return jsonify({"ok": False,
                                    "error": f"No tienes el permiso '{permission}'. "
                                             "Pide al superadministrador que lo active "
                                             "para tu rol en /admin/roles.",
                                    "error_codigo": "SIN_PERMISO",
                                    "permiso_requerido": permission}), 403
                flash("No tienes permisos para realizar esta accion.", "danger")
                return redirect(url_for("index"))
            return view(*a, **kw)
        return wrapped
    return decorator


@app.before_request
def before_request():
    """Pipeline global pre-request:
       1. Carga el usuario actual desde sesión → g.user / g.permissions.
       2. Valida CSRF en métodos mutadores (POST/PUT/DELETE/PATCH).
          DEBE correr tras load_current_user para poder redirigir a la
          misma URL si el usuario está autenticado (UX más amable que
          forzar login). Si CSRF falla, devuelve una Response y Flask
          interrumpe el pipeline."""
    load_current_user()
    csrf_resp = _csrf_check_request()
    if csrf_resp is not None:
        return csrf_resp


# ════════════════════════════════════════════════════════════════════
# PERFORMANCE — after_request: compresión gzip + cache headers static
# ════════════════════════════════════════════════════════════════════
# 2026-05-17: Antes los assets `/static/*` se servían sin Cache-Control
# agresivo, forzando al navegador a revalidar en cada navegación. Los
# HTML/JSON tampoco se comprimían (Flask no comprime por default), lo
# que multiplicaba el ancho de banda de respuestas.
#
# Implementación zero-dependency:
#  1. Cache-Control immutable + max-age=30d para /static/*  → 0 RTTs
#     adicionales al navegar entre páginas (CSS/JS/imágenes desde cache).
#  2. Gzip on-the-fly para HTML/JSON/CSS/JS/XML > 1 KB cuando el cliente
#     declara Accept-Encoding: gzip. Salta archivos ya comprimidos
#     (woff2, jpg, png, webp, mp4, zip, pdf — magic bytes).
# ════════════════════════════════════════════════════════════════════
_COMPRESSIBLE_PREFIXES = (
    "text/", "application/json", "application/javascript",
    "application/xml", "application/xhtml+xml", "application/atom+xml",
    "application/rss+xml", "image/svg+xml",
)
_GZIP_MIN_BYTES = 1024


@app.after_request
def _perf_static_cache_and_gzip(resp):
    try:
        # ── 0) Permissions-Policy: habilitar geolocation explícitamente ───
        # FIX 2026-05-17 (CRÍTICO iOS Safari + Railway/CDN):
        #   Si NO seteamos este header, algunos intermediarios (Cloudflare,
        #   Railway proxy, ciertas configuraciones de Safari) inyectan por
        #   default `Permissions-Policy: geolocation=()` que BLOQUEA TOTAL-
        #   mente navigator.geolocation.getCurrentPosition en iOS, sin
        #   mostrar siquiera el prompt nativo. El técnico ve "Pidiendo GPS…"
        #   y nunca pasa nada.
        #   Acá lo seteamos a `geolocation=(self)` que permite GPS solo en
        #   nuestro propio origin (no en iframes de terceros), que es lo
        #   que necesita la app de mantenciones (ot_ejecutar.html).
        #   También habilitamos camera para la captura de fotos de tareas.
        if "Permissions-Policy" not in resp.headers:
            resp.headers["Permissions-Policy"] = (
                "geolocation=(self), camera=(self), microphone=()"
            )

        # ── 0.1) Headers de seguridad globales ───────────────────────────
        # Code review senior 2026-05-17: el sitio no tenía las cabeceras
        # mínimas que cualquier app web moderna debe enviar:
        #   - nosniff: evita MIME-sniffing (XSS via tipo mal interpretado)
        #   - Referrer-Policy: no enviar referers con paths privados a 3os.
        #   - HSTS: fuerza HTTPS por 2 años (Railway sirve TLS válido).
        #   - X-Frame-Options SAMEORIGIN: bloquea clickjacking en iframes
        #       externos. NO usamos DENY para mantener compat con el preview
        #       interno de OTs/PDFs que se carga en iframes del mismo origen.
        #   - CSP en modo Report-Only: enumera explícitamente los orígenes
        #       permitidos (jsdelivr, maps.googleapis, cloudinary, etc.).
        #       En Report-Only por ahora — si nada se rompe en 1-2 semanas
        #       lo movemos a Content-Security-Policy (enforce).
        if "X-Content-Type-Options" not in resp.headers:
            resp.headers["X-Content-Type-Options"] = "nosniff"
        if "Referrer-Policy" not in resp.headers:
            resp.headers["Referrer-Policy"] = "strict-origin-when-cross-origin"
        if "Strict-Transport-Security" not in resp.headers:
            resp.headers["Strict-Transport-Security"] = (
                "max-age=63072000; includeSubDomains; preload"
            )
        if "X-Frame-Options" not in resp.headers:
            resp.headers["X-Frame-Options"] = "SAMEORIGIN"
        if "Content-Security-Policy-Report-Only" not in resp.headers \
                and "Content-Security-Policy" not in resp.headers:
            resp.headers["Content-Security-Policy-Report-Only"] = (
                "default-src 'self' https://cdn.jsdelivr.net "
                "https://maps.googleapis.com https://res.cloudinary.com "
                "https://*.cloudinary.com data: blob:; "
                "script-src 'self' 'unsafe-inline' https://cdn.jsdelivr.net "
                "https://maps.googleapis.com; "
                "style-src 'self' 'unsafe-inline' https://cdn.jsdelivr.net; "
                "font-src 'self' https://cdn.jsdelivr.net data:; "
                "img-src 'self' data: blob: https:; "
                "connect-src 'self' https://maps.googleapis.com "
                "https://*.cloudinary.com https://api.cloudinary.com "
                "https://api.twilio.com; "
                "frame-ancestors 'self'; "
                "base-uri 'self'; "
                "form-action 'self'"
            )

        # ── 1) Cache headers para assets estáticos ───────────────────
        # FIX 2026-05-18 (perf audit Daniel): Flask por default setea
        # `Cache-Control: no-cache` en send_static_file. Antes saltábamos
        # cuando el header ya estaba presente — pero ¡ya estaba presente
        # con valor `no-cache`! Resultado: el navegador revalidaba CSS/JS/
        # Logo.png en cada navegación. Ahora forzamos `public, max-age=30d,
        # immutable` SIEMPRE para /static/* (sobrescribimos el no-cache).
        # Si necesitás romper cache, cambiá el nombre del archivo o agregá
        # ?v=YYYYMMDD (ver favicons en base.html).
        if request.path.startswith("/static/"):
            # 30 días, immutable — los nombres de archivo cambian en el
            # commit cuando el contenido cambia (o el usuario fuerza
            # reload manual). Esto elimina ~3-8 requests de revalidación
            # por página cargada.
            resp.headers["Cache-Control"] = "public, max-age=2592000, immutable"
            # Drop Pragma/Expires legacy headers that contradict Cache-Control.
            resp.headers.pop("Pragma", None)
            resp.headers.pop("Expires", None)

        # ── 2) Gzip on-the-fly ───────────────────────────────────────
        # FIX 2026-05-18 (perf audit): Flask sirve /static/* con
        # `direct_passthrough=True` (streaming sin cargar a memoria),
        # lo que ANTES nos hacía saltar la compresión. Resultado: style.css
        # (38KB), ilus_ui.js (32KB), templates HTML grandes salían sin
        # gzip. Ahora forzamos `implicit_sequence_conversion`/`get_data()`
        # para responses estáticas compresibles. Resp.get_data() en pas-
        # sthrough cierra el stream y carga a memoria — perfectamente OK
        # para nuestros assets (todos <2MB) y agarra el compresor gzip
        # normal. Para passthrough NO compresible (PNG, JPG, woff2) sigue
        # streaming sin pasar por gzip.
        # Saltar si:
        #  - el cliente no acepta gzip
        #  - ya viene comprimido (Content-Encoding presente)
        #  - status no 200-299
        #  - body es muy chico
        #  - mime no es compresible
        if (
            "gzip" in (request.headers.get("Accept-Encoding") or "").lower()
            and "Content-Encoding" not in resp.headers
            and 200 <= resp.status_code < 300
        ):
            ctype = (resp.content_type or "").lower()
            if any(ctype.startswith(p) for p in _COMPRESSIBLE_PREFIXES):
                try:
                    # Force-read stream incluso en direct_passthrough mode.
                    # Solo lo hacemos para mimes compresibles (text/*, JSON, JS, CSS,
                    # XML, SVG) — imágenes/binaries no entran acá.
                    if getattr(resp, "direct_passthrough", False):
                        resp.direct_passthrough = False
                    data = resp.get_data()
                    if len(data) >= _GZIP_MIN_BYTES:
                        import gzip as _gzip_mod
                        # Level 6 = sweet spot entre CPU y ratio para text.
                        compressed = _gzip_mod.compress(data, compresslevel=6)
                        # Solo aplicar si efectivamente reduce tamaño
                        if len(compressed) < len(data):
                            resp.set_data(compressed)
                            resp.headers["Content-Encoding"] = "gzip"
                            resp.headers["Content-Length"] = str(len(compressed))
                            # Importante para caches/CDN: vary by encoding
                            vary = resp.headers.get("Vary") or ""
                            if "Accept-Encoding" not in vary:
                                resp.headers["Vary"] = (vary + ", Accept-Encoding").lstrip(", ")
                except Exception:
                    # Nunca rompamos la respuesta por un error de compresión
                    pass
    except Exception:
        pass
    return resp


@app.teardown_appcontext
def close_db(exc=None):
    db = g.pop("_db", None)
    if db is not None:
        try:
            db.close()
        except Exception:
            pass


# ─────────────────────────────────────────────
#  Product queries
# ─────────────────────────────────────────────

# ── Caché simple del listado de productos ──────────────────────
# Evita re-ejecutar el UNION ALL + 4 JOINs en cada recarga de inicio.
# Se invalida automáticamente al guardar/editar cualquier producto.
_listing_cache: dict = {}
_listing_cache_lock = threading.Lock()
# ⚡ PERF (Daniel 2026-05-24): TTL subido de 45s → 300s (5min). El catálogo
# cambia ESPORÁDICAMENTE (no en cada request). 5min reduce drásticamente
# el costo cold start, y _invalidate_listing_cache() se sigue llamando
# en cada CRUD de producto (alta/edit/del) para coherencia inmediata.
_LISTING_TTL = 300  # segundos

def _invalidate_listing_cache():
    """Llama esto cada vez que se crea, edita o elimina un producto."""
    with _listing_cache_lock:
        _listing_cache.clear()


def _product_listing_base_sql(search_query=""):
    """SQL común para el UNION ALL del listado (sin ORDER ni LIMIT).

    Devuelve (sql_inner, params). El caller envuelve con ORDER BY + LIMIT
    o con COUNT(*) según necesite.
    """
    erp_params = []
    app_params = []
    if search_query:
        like_u = f"%{search_query.upper()}%"
        like_p = f"%{search_query}%"
        erp_where = "WHERE UPPER(TRIM(e.`SKU`)) LIKE %s OR e.`Nombre` LIKE %s"
        app_where = "AND (p.sku LIKE %s OR p.nombre LIKE %s)"
        erp_params = [like_u, like_p]
        app_params = [like_u, like_p]
    else:
        erp_where = ""
        app_where = ""

    sql_inner = f"""
        (
          SELECT
              UPPER(TRIM(e.`SKU`))                     AS sku,
              TRIM(COALESCE(e.`Nombre`, ''))            AS nombre,
              COALESCE(p.estado, 'Pendiente')           AS estado,
              COALESCE(p.codigo, '')                    AS codigo,
              p.id                                      AS app_product_id,
              p.created_by,
              p.updated_by,
              COALESCE((SELECT COUNT(*) FROM `{BULTOS_TABLE}` b
                          WHERE b.product_id = p.id), 0)         AS total_bultos,
              COALESCE((SELECT SUM(b.peso) FROM `{BULTOS_TABLE}` b
                          WHERE b.product_id = p.id), 0)         AS peso_total,
              ROUND(COALESCE(
                  (SELECT SUM((b.largo*b.ancho*b.alto)/4000)
                     FROM `{BULTOS_TABLE}` b WHERE b.product_id = p.id), 0
              ), 2)                                              AS pv_total,
              COALESCE((SELECT COUNT(*) FROM `{PHOTOS_TABLE}` ph
                          WHERE ph.product_id = p.id), 0)        AS total_fotos
          FROM `{ERP_TABLE}` e
          LEFT JOIN `{PRODUCTS_TABLE}` p  ON p.sku = UPPER(TRIM(e.`SKU`))
          {erp_where}
        )
        UNION ALL
        (
          SELECT
              p.sku                                     AS sku,
              p.nombre                                  AS nombre,
              p.estado                                  AS estado,
              p.codigo                                  AS codigo,
              p.id                                      AS app_product_id,
              p.created_by,
              p.updated_by,
              COALESCE((SELECT COUNT(*) FROM `{BULTOS_TABLE}` b
                          WHERE b.product_id = p.id), 0)         AS total_bultos,
              COALESCE((SELECT SUM(b.peso) FROM `{BULTOS_TABLE}` b
                          WHERE b.product_id = p.id), 0)         AS peso_total,
              ROUND(COALESCE(
                  (SELECT SUM((b.largo*b.ancho*b.alto)/4000)
                     FROM `{BULTOS_TABLE}` b WHERE b.product_id = p.id), 0
              ), 2)                                              AS pv_total,
              COALESCE((SELECT COUNT(*) FROM `{PHOTOS_TABLE}` ph
                          WHERE ph.product_id = p.id), 0)        AS total_fotos
          FROM `{PRODUCTS_TABLE}` p
          LEFT JOIN `{ERP_TABLE}`      e  ON p.sku = UPPER(TRIM(e.`SKU`))
          WHERE e.`SKU` IS NULL
          {app_where}
        )
    """
    return sql_inner, erp_params + app_params


def get_product_listing_paginated(search_query="", page=1, page_size=100):
    """Devuelve {rows, total, page, page_size, total_pages, foto0, foto1, foto2}.

    ⚡ PERF MEJORA 2026-05-24 (Daniel): paginación server-side. Antes traíamos
    TODA la BD (puede ser 5K-15K SKUs) en cada visita a /, ahora solo 100.

    - LIMIT %s OFFSET %s aplicado al UNION ALL ordenado.
    - COUNT(*) total cacheado aparte (solo cambia al CRUD de productos).
    - KPI fotos (foto0/foto1/foto2) calculados sobre TODO el universo, no
      solo la página actual, para que las estadísticas sigan teniendo
      sentido. Cacheado igual que el total.
    - Búsqueda (?q=) sigue funcionando en TODA la BD (no en página actual).
    """
    # Saneamiento
    try:
        page = max(1, int(page))
    except (TypeError, ValueError):
        page = 1
    try:
        page_size = int(page_size)
    except (TypeError, ValueError):
        page_size = 100
    if page_size not in (100, 200, 500):
        page_size = 100  # default seguro

    cache_key = (search_query.strip().lower(), page, page_size)
    now = time.time()
    with _listing_cache_lock:
        entry = _listing_cache.get(cache_key)
        if entry and (now - entry[1]) < _LISTING_TTL:
            return entry[0]

    sql_inner, base_params = _product_listing_base_sql(search_query)

    # ── 1) COUNT total (cacheado por search_query separado) ──
    count_key = ("__count__", search_query.strip().lower())
    with _listing_cache_lock:
        c_entry = _listing_cache.get(count_key)
    if c_entry and (now - c_entry[1]) < _LISTING_TTL:
        total_count, foto0, foto1, foto2 = c_entry[0]
    else:
        # Conteo + KPIs en una sola pasada (usa el mismo UNION ALL)
        sql_stats = f"""
            SELECT COUNT(*) AS total,
                   SUM(CASE WHEN total_fotos = 0 THEN 1 ELSE 0 END) AS f0,
                   SUM(CASE WHEN total_fotos = 1 THEN 1 ELSE 0 END) AS f1,
                   SUM(CASE WHEN total_fotos >= 2 THEN 1 ELSE 0 END) AS f2
              FROM ({sql_inner}) AS u
        """
        stats_row = mysql_fetchone(sql_stats, base_params) or {}
        total_count = int(stats_row.get("total") or 0)
        foto0 = int(stats_row.get("f0") or 0)
        foto1 = int(stats_row.get("f1") or 0)
        foto2 = int(stats_row.get("f2") or 0)
        with _listing_cache_lock:
            _listing_cache[count_key] = ((total_count, foto0, foto1, foto2), time.time())

    total_pages = max(1, (total_count + page_size - 1) // page_size) if total_count else 1
    if page > total_pages:
        page = total_pages

    # ── 2) Página actual (LIMIT + OFFSET) ──
    offset = (page - 1) * page_size
    sql_page = f"""
        SELECT * FROM ({sql_inner}) AS u
        ORDER BY nombre, sku
        LIMIT %s OFFSET %s
    """
    rows = mysql_fetchall(sql_page, base_params + [page_size, offset])

    result = {
        "rows": rows,
        "total": total_count,
        "page": page,
        "page_size": page_size,
        "total_pages": total_pages,
        "foto0": foto0,
        "foto1": foto1,
        "foto2": foto2,
    }
    with _listing_cache_lock:
        _listing_cache[cache_key] = (result, time.time())
    return result


def get_product_listing(search_query=""):
    """Compatibilidad: devuelve TODOS los productos (sin paginar).

    Solo usar para flujos legacy que necesitan toda la lista (export Excel
    completo, scripts de mantenimiento). Para el listado web usar
    get_product_listing_paginated().

    ⚡ PERF (Daniel 2026-05-24): query reescrita para eliminar GROUP BY con
    múltiples JOINs (que generaba producto cartesiano enorme entre bultos
    y fotos antes de agrupar). Ahora usamos subqueries correlacionadas en
    SELECT — MySQL las optimiza usando índices PK y son MUCHO más rápidas
    que el GROUP BY masivo.
    """
    cache_key = ("__all__", search_query.strip().lower())
    now = time.time()
    with _listing_cache_lock:
        entry = _listing_cache.get(cache_key)
        if entry and (now - entry[1]) < _LISTING_TTL:
            return entry[0]
    sql_inner, base_params = _product_listing_base_sql(search_query)
    sql = f"SELECT * FROM ({sql_inner}) AS u ORDER BY nombre, sku"
    result = mysql_fetchall(sql, base_params)
    with _listing_cache_lock:
        _listing_cache[cache_key] = (result, time.time())
    return result


def get_erp_product_by_sku(sku):
    """Valida si un SKU existe en el catálogo del ERP Random.

    Cascada de fuentes (igual que el typeahead de búsqueda en /api/products/search):
      1) Tabla local `etiquetas` (mirror de app_products) — instantáneo, sin red
      2) REST API `/productos` del ERP Random — fuente en tiempo real
      3) SQL Server directo a MAEPR — fallback cuando la REST cae o no devuelve el SKU

    Devuelve dict {sku, nombre, estado, codigo} o None si NINGUNA fuente lo encuentra.

    Bug fix 2026-05-28 (Daniel): antes solo consultaba (1) — un mirror de productos
    YA creados en la app — por lo que TODO SKU nuevo del catálogo ERP era rechazado
    al crear el producto. SKUs reportados: 1224100919, 1110100923, 1210100922,
    1110101007, 1129100964.
    """
    sku_u = (sku or "").strip().upper()
    if not sku_u:
        return None

    # ── Fuente 1: tabla local mirror (rápida, sin red) ────────────────
    try:
        local = mysql_fetchone(
            f"""SELECT UPPER(TRIM(`SKU`)) AS sku,
                       TRIM(COALESCE(`Nombre`,'')) AS nombre,
                       TRIM(COALESCE(`Estado`,'Pendiente')) AS estado,
                       TRIM(COALESCE(`Codigo`,'')) AS codigo
                FROM `{ERP_TABLE}` WHERE UPPER(TRIM(`SKU`))=%s LIMIT 1""",
            (sku_u,),
        )
        if local:
            return local
    except Exception as _e_local:
        print(f"[get_erp_product_by_sku] local lookup failed: {_e_local}", flush=True)

    # ── Fuente 2: REST API /productos del ERP Random ──────────────────
    try:
        TOKEN = ERP_CONFIG.get("api_token", "")
        if TOKEN:
            body = _erp_get(
                "/productos",
                {
                    "search":  sku_u,
                    "empresa": "01",
                    "fields":  "KOPR,NOKOPR",
                    "visible": "true",
                    "limit":   "10",
                },
                TOKEN, timeout=6,
            )
            for p in (body.get("data") or []):
                p_sku = (p.get("KOPR") or "").strip().upper()
                if p_sku == sku_u:
                    return {
                        "sku":    p_sku,
                        "nombre": (p.get("NOKOPR") or "").strip(),
                        "estado": "Pendiente",
                        "codigo": "",
                    }
    except Exception as _e_rest:
        # No es fatal: caemos al SQL Server
        print(f"[get_erp_product_by_sku] REST lookup failed for {sku_u}: "
              f"{type(_e_rest).__name__}: {str(_e_rest)[:160]}", flush=True)

    # ── Fuente 3: SQL Server directo a MAEPR ──────────────────────────
    # Esto cubre el caso típico: SKU recién creado en el ERP que aún no
    # aparece por la REST (cache de su lado, índice desactualizado, etc.)
    try:
        rows = _random_sql_query(
            f"""SELECT TOP 1
                       LTRIM(RTRIM(KOPR))   AS sku,
                       LTRIM(RTRIM(NOKOPR)) AS nombre
                  FROM {ERP_TABLE_PRODUCTS}
                 WHERE UPPER(LTRIM(RTRIM(KOPR))) = %s""",
            (sku_u,),
            max_rows=1,
        )
        if rows:
            r = rows[0]
            return {
                "sku":    (r.get("sku") or "").strip().upper(),
                "nombre": (r.get("nombre") or "").strip(),
                "estado": "Pendiente",
                "codigo": "",
            }
    except Exception as _e_sql:
        print(f"[get_erp_product_by_sku] SQL MAEPR lookup failed for {sku_u}: "
              f"{type(_e_sql).__name__}: {str(_e_sql)[:160]}", flush=True)

    return None


def get_full(product_id):
    product = mysql_fetchone(f"SELECT * FROM `{PRODUCTS_TABLE}` WHERE id=%s", (product_id,))
    if not product:
        return None, [], []
    bultos = mysql_fetchall(
        f"SELECT * FROM `{BULTOS_TABLE}` WHERE product_id=%s ORDER BY bulto_num", (product_id,)
    )
    photos = mysql_fetchall(
        f"SELECT * FROM `{PHOTOS_TABLE}` WHERE product_id=%s ORDER BY orden", (product_id,)
    )
    return product, enrich(bultos), photos


def ensure_product_record_from_erp(sku):
    normalized = sku.strip().upper()
    existing = mysql_fetchone(f"SELECT id FROM `{PRODUCTS_TABLE}` WHERE sku=%s", (normalized,))
    if existing:
        return existing["id"]
    erp = get_erp_product_by_sku(normalized)
    if not erp:
        return None
    codigo = next_codigo()
    conn = get_db()
    with conn.cursor() as cur:
        cur.execute(
            f"""INSERT INTO `{PRODUCTS_TABLE}` (sku,nombre,estado,codigo,erp_sync,created_by,updated_by)
                VALUES (%s,%s,%s,%s,1,%s,%s)""",
            (erp["sku"], erp["nombre"], erp["estado"], codigo,
             current_username(), current_username()),
        )
        pid = cur.lastrowid
    conn.commit()
    return pid


def save_bultos_mysql(conn, product_id, form):
    with conn.cursor() as cur:
        for idx in range(1, MAX_BULTOS + 1):
            largo = to_f(form.get(f"largo_{idx}"))
            ancho = to_f(form.get(f"ancho_{idx}"))
            alto  = to_f(form.get(f"alto_{idx}"))
            peso  = to_f(form.get(f"peso_{idx}"))
            if largo > 0 or ancho > 0 or alto > 0 or peso > 0:
                cur.execute(
                    f"""INSERT INTO `{BULTOS_TABLE}` (product_id,bulto_num,largo,ancho,alto,peso)
                        VALUES (%s,%s,%s,%s,%s,%s)""",
                    (product_id, idx, largo, ancho, alto, peso),
                )


def next_codigo():
    """Devuelve el siguiente código de impresión autoincremental (001, 002, ...)."""
    row = mysql_fetchone(
        f"SELECT MAX(CAST(codigo AS UNSIGNED)) AS max_c "
        f"FROM `{PRODUCTS_TABLE}` WHERE codigo REGEXP '^[0-9]+$'"
    )
    nxt = (int(row["max_c"]) + 1) if row and row["max_c"] else 1
    return str(nxt).zfill(3)


def validate_bultos_form(form):
    """Devuelve lista de errores si los bultos no son válidos."""
    errors = []
    has_any = False
    for idx in range(1, MAX_BULTOS + 1):
        largo = to_f(form.get(f"largo_{idx}"))
        ancho = to_f(form.get(f"ancho_{idx}"))
        alto  = to_f(form.get(f"alto_{idx}"))
        peso  = to_f(form.get(f"peso_{idx}"))
        vals  = [largo, ancho, alto, peso]
        if any(v > 0 for v in vals):
            has_any = True
            if not all(v > 0 for v in vals):
                errors.append(f"Bulto {idx}: todos los valores (largo, ancho, alto, peso) deben ser mayores a 0.")
    if not has_any:
        errors.append("Debes agregar al menos un bulto con medidas y peso completos.")
    return errors


# ─────────────────────────────────────────────
#  PDF builder — Playwright (pixel-perfect al HTML preview)
# ─────────────────────────────────────────────

def _logo_data_url():
    """Logo PNG como data:image URL — se incrusta en el HTML standalone sin depender del servidor."""
    for fname in ("Logo.png", "logo.png", "LOGO.png"):
        path = os.path.join(BASE_DIR, "static", fname)
        if os.path.exists(path):
            try:
                with open(path, "rb") as f:
                    b64 = base64.b64encode(f.read()).decode()
                return f"data:image/png;base64,{b64}"
            except Exception:
                pass
    return ""


def _label_format(fmt):
    """Formatos FÍSICOS de etiqueta soportados.

    Por pedido del usuario (2026-05-13): SOLO existen 2 tamaños reales
    en producción — los formatos 150x70 y 100x70 NO EXISTEN físicamente
    y fueron eliminados de toda la base.

    Tamaños válidos:
      • "100x150" → estándar (etiqueta grande, doblada en 2 caras)
      • "100x50"  → etiqueta chica

    NOTA TÉCNICA: la "key" interna ("150x100" y "100x50") es lo que el
    template label_standalone.html usa para aplicar CSS (.label-150x100,
    .label-100x50). El usuario ve "100 × 150 mm" porque es como ILUS
    nombra el papel termico (lado corto × lado largo). Internamente
    Playwright genera el PDF a 150mm × 100mm landscape que es como están
    calibradas las impresoras.
    """
    formats = {
        "100x150": {"key": "150x100", "w": "150mm", "h": "100mm", "label": "100 × 150 mm (estándar)"},
        "100x50":  {"key": "100x50",  "w": "100mm", "h": "50mm",  "label": "100 × 50 mm"},
        # Aliases para compat con código viejo que aún use las keys antiguas:
        "150x100": {"key": "150x100", "w": "150mm", "h": "100mm", "label": "100 × 150 mm (estándar)"},
    }
    return formats.get(fmt, formats["100x150"])


def _label_bulto_data(bulto):
    data = dict(bulto)
    largo = float(data.get("largo_cm") or data.get("largo") or 0)
    ancho = float(data.get("ancho_cm") or data.get("ancho") or 0)
    alto = float(data.get("alto_cm") or data.get("alto") or 0)
    kg = float(data.get("kg") or data.get("peso") or data.get("peso_bruto") or 0)
    data.update({
        "largo": largo,
        "ancho": ancho,
        "alto": alto,
        "largo_cm": largo,
        "ancho_cm": ancho,
        "alto_cm": alto,
        "kg": kg,
        "peso": kg,
        "peso_vol": calc_pv(largo, ancho, alto),
    })
    return data


def build_labels_pdf(product, label_bultos, total_bultos, fmt="150x100"):
    """
    Genera un PDF con una o mas etiquetas usando Playwright (Chromium headless).
    El resultado es pixel-perfect idéntico al HTML preview porque usa
    el mismo template label_standalone.html y el mismo @media print CSS.
    Si Playwright no está instalado, lanza ImportError con instrucción de instalación.
    """
    # Hora Chile para que la etiqueta muestre la fecha correcta al usuario
    fecha        = _now_chile_str("%d-%m-%Y %H:%M")
    label_format = _label_format(fmt)
    enriched     = [_label_bulto_data(b) for b in label_bultos]

    html = render_template(
        "label_standalone.html",
        product      = product,
        bultos       = enriched,
        total_bultos = total_bultos,
        fecha        = fecha,
        qty_per_bulto= {},
        logo_url     = _logo_data_url(),
        fmt          = label_format["key"],
        label_format = label_format,
    )

    # Usa el browser pool — sin overhead de launch/close
    return _pw_pdf(
        html,
        width  = label_format["w"],
        height = label_format["h"],
        wait_fn = (
            "() => {"
            "  const codes = Array.from(document.querySelectorAll('.barcode'));"
            "  return codes.length > 0 && codes.every(c => c.dataset.rendered === '1');"
            "}"
        ),
    )


def build_label_pdf(product, bulto, total_bultos, fmt="150x100"):
    return build_labels_pdf(product, [bulto], total_bultos, fmt)


# ── Mantener la antigua firma por compatibilidad ── (ya no usa reportlab)
def _build_label_pdf_legacy(product, bulto, total_bultos):
    """Fallback ReportLab — ya no se usa, conservado como referencia."""
    from reportlab.lib.units import mm
    from reportlab.lib import colors
    from reportlab.pdfgen import canvas
    from reportlab.pdfbase import pdfmetrics
    from reportlab.graphics.barcode import code128

    W, H    = 150 * mm, 70 * mm
    HALF    = W / 2                 # 75 mm por cara
    HDR_H   = 14 * mm
    META_H  =  8 * mm
    NAME_H  =  9 * mm
    FTR_H   =  5 * mm
    hdr_y   = H - HDR_H
    meta_y  = hdr_y - META_H
    name_y  = meta_y - NAME_H
    body_y  = FTR_H
    body_h  = name_y - body_y      # ≈ 34mm

    BLACK = colors.black
    WHITE = colors.white
    GRAY  = colors.HexColor("#aaaaaa")
    DGRAY = colors.HexColor("#2c2c2c")

    buf   = io.BytesIO()
    c     = canvas.Canvas(buf, pagesize=(W, H))
    fecha = _now_chile_str("%d-%m-%Y %H:%M")  # Hora Chile

    # ── Intenta cargar logo (convertido a blanco via Pillow si está disponible) ──
    logo_img_path = None
    try:
        from PIL import Image as PILImage
        import tempfile
        src = os.path.join(app.static_folder, "Logo.png")
        if os.path.exists(src):
            img = PILImage.open(src).convert("RGBA")
            r, g, b, a = img.split()
            white_bg = PILImage.new("RGBA", img.size, (0, 0, 0, 255))
            # Pintar píxeles no-transparentes de blanco
            white_layer = PILImage.new("RGBA", img.size, (255, 255, 255, 255))
            white_bg.paste(white_layer, mask=a)
            tmp = tempfile.NamedTemporaryFile(suffix=".png", delete=False)
            white_bg.save(tmp.name)
            logo_img_path = tmp.name
    except Exception:
        logo_img_path = None

    def draw_half(ox):
        # ══════════════════════════════════════════
        #  HEADER  (negro, 14mm)
        # ══════════════════════════════════════════
        c.setFillColor(BLACK)
        c.rect(ox, hdr_y, HALF, HDR_H, fill=1, stroke=0)

        # Proporciones: SHS izq 40% | ILUS der 60%
        shs_w  = HALF * 0.40
        ilus_w = HALF * 0.60
        shs_cx = ox + shs_w / 2
        ilus_x = ox + shs_w          # borde derecho de SHS = borde izq de ILUS
        ilus_cx = ilus_x + ilus_w / 2

        # Separador interno
        c.setStrokeColor(DGRAY)
        c.setLineWidth(0.6)
        c.line(ilus_x, hdr_y + 1*mm, ilus_x, hdr_y + HDR_H - 1*mm)

        # — Sports Health Solutions (izquierda) —
        c.setFillColor(WHITE)
        c.setFont("Helvetica-Bold", 8)
        c.drawCentredString(shs_cx, hdr_y + 9.2*mm, "SPORTS")
        c.drawCentredString(shs_cx, hdr_y + 5.8*mm, "HEALTH")
        c.setFillColor(GRAY)
        c.setFont("Helvetica-Oblique", 4)
        c.drawCentredString(shs_cx, hdr_y + 2.2*mm, "S O L U T I O N S")

        # — Logo ILUS (derecha) —
        if logo_img_path:
            try:
                lh = HDR_H * 0.78
                lw = ilus_w * 0.82
                c.drawImage(logo_img_path,
                            ilus_cx - lw / 2,
                            hdr_y + (HDR_H - lh) / 2,
                            width=lw, height=lh,
                            preserveAspectRatio=True, mask='auto')
            except Exception:
                _draw_ilus_text(ilus_cx)
        else:
            _draw_ilus_text(ilus_cx)

    def _draw_ilus_text(cx):
        """Fallback: texto ILUS. en blanco cuando no hay imagen."""
        c.setFillColor(WHITE)
        c.setFont("Helvetica-Bold", 18)
        iw = pdfmetrics.stringWidth("ILUS.", "Helvetica-Bold", 18)
        # cx es el centro de la zona ILUS dentro de la cara actual
        c.drawCentredString(cx, hdr_y + 4*mm, "ILUS.")

    def draw_body(ox):
        # ══════════════════════════════════════════
        #  META BAR  (blanco, 8mm)
        # ══════════════════════════════════════════
        c.setFillColor(WHITE)
        c.rect(ox, meta_y, HALF, META_H, fill=1, stroke=0)
        c.setStrokeColor(BLACK)
        c.setLineWidth(0.8)
        c.line(ox, meta_y,          ox + HALF, meta_y)
        c.line(ox, meta_y + META_H, ox + HALF, meta_y + META_H)

        ty = meta_y + META_H / 2 - 1.4*mm

        # Ícono caja (aproximación con rectángulo)
        cx_icon = ox + 5*mm
        c.setFillColor(BLACK)
        c.setLineWidth(0.6)
        c.rect(cx_icon - 1.4*mm, ty + 0.3*mm, 2.8*mm, 2.8*mm, fill=0, stroke=1)

        c.setFont("Helvetica-Bold", 6.5)
        c.setFillColor(BLACK)
        c.drawString(ox + 7.5*mm, ty,
                     f"BULTO {bulto['bulto_num']} DE {total_bultos}")

        # Separador |
        sep_x = ox + HALF * 0.52
        c.setFont("Helvetica", 10)
        c.setFillColor(GRAY)
        c.drawCentredString(sep_x, ty - 0.5*mm, "|")

        c.setFont("Helvetica-Bold", 6.5)
        c.setFillColor(BLACK)
        c.drawString(sep_x + 2.5*mm, ty, "PESO BRUTO")
        c.setFont("Helvetica-Bold", 7)
        c.drawRightString(ox + HALF - 2*mm, ty,
                          f"{float(bulto['peso']):.0f} KG")

        # ══════════════════════════════════════════
        #  NOMBRE PRODUCTO  (blanco, 9mm)
        # ══════════════════════════════════════════
        c.setFillColor(WHITE)
        c.rect(ox, name_y, HALF, NAME_H, fill=1, stroke=0)
        c.setStrokeColor(BLACK)
        c.setLineWidth(0.8)
        c.line(ox, name_y, ox + HALF, name_y)

        nombre = (product["nombre"] or "").upper()
        avail  = HALF - 5*mm
        fs_n   = 7.5
        while pdfmetrics.stringWidth(nombre, "Helvetica-Bold", fs_n) > avail and fs_n > 4.5:
            fs_n -= 0.15
        c.setFont("Helvetica-Bold", fs_n)
        c.setFillColor(BLACK)
        # Si cabe en una línea
        if pdfmetrics.stringWidth(nombre, "Helvetica-Bold", fs_n) <= avail:
            c.drawString(ox + 2.5*mm, name_y + NAME_H/2 - 1.3*mm, nombre)
        else:
            # Partir en dos líneas
            mid = len(nombre) // 2
            cut = nombre.rfind(" ", 0, mid + 10) or mid
            c.setFont("Helvetica-Bold", max(fs_n - 0.3, 5.0))
            c.drawString(ox + 2.5*mm, name_y + NAME_H - 3.8*mm, nombre[:cut].strip())
            c.drawString(ox + 2.5*mm, name_y + 1.8*mm,          nombre[cut:].strip())

        # ══════════════════════════════════════════
        #  BODY  (dims izq 50% | código der 50%)
        # ══════════════════════════════════════════
        dims_w   = HALF * 0.50
        dims_end = ox + dims_w
        bc_x     = dims_end + 0.5*mm          # inicio columna código
        bc_w     = HALF - dims_w - 0.5*mm     # ancho disponible código

        # Separador vertical dims | código
        c.setStrokeColor(BLACK)
        c.setLineWidth(0.8)
        c.line(dims_end, body_y, dims_end, name_y)

        # — Dimensiones (4 filas centradas verticalmente) —
        rows = [
            ("↔",  "LARGO:",     f"{float(bulto['largo']):.0f} cm"),
            ("↕",  "ALTO:",      f"{float(bulto['alto']):.0f} cm"),
            ("⊞",  "ANCHO:",     f"{float(bulto['ancho']):.0f} cm"),
            ("🔒", "PESO VOL.:", f"{float(bulto['peso_vol']):.2f} Vol"),
        ]
        row_h  = body_h / len(rows)
        lbl_x  = ox + 3*mm      # inicio etiqueta (3mm desde borde izq)
        val_x  = dims_end - 1*mm  # valores anclados a la derecha

        for i, (ico, lbl, val) in enumerate(rows):
            ry = name_y - (i + 0.62) * row_h

            # Etiqueta
            c.setFont("Helvetica-Bold", 5.5)
            c.setFillColor(BLACK)
            c.drawString(lbl_x, ry, lbl)

            # Valor (ancla derecha)
            c.setFont("Helvetica-Bold", 6.5)
            c.drawRightString(val_x, ry, val)

        # — Barcode CODE128 —
        bc_val = (product["sku"] or "000")[:30]

        # Reservar espacio: barcode + SKU box + fecha
        sku_h    = body_h * 0.30     # caja SKU negra
        fecha_h  = 3   * mm          # línea de fecha
        bc_h     = body_h - sku_h - fecha_h - 1.5*mm  # altura barras

        bw_pt = 1.0 if len(bc_val) > 20 else (0.85 if len(bc_val) > 12 else 1.0)
        bc_y  = body_y + sku_h + fecha_h + 0.5*mm

        try:
            bar = code128.Code128(bc_val, barWidth=bw_pt,
                                  barHeight=bc_h, humanReadable=False, quiet=False)
            while bar.width > bc_w - 1*mm and bw_pt > 0.35:
                bw_pt -= 0.04
                bar = code128.Code128(bc_val, barWidth=bw_pt,
                                      barHeight=bc_h, humanReadable=False, quiet=False)
            bc_cx = bc_x + bc_w / 2
            bar.drawOn(c, bc_cx - bar.width / 2, bc_y)
        except Exception:
            pass

        # — Caja negra CÓDIGO / SKU —
        sku_y = body_y + fecha_h
        c.setFillColor(BLACK)
        c.rect(bc_x, sku_y, bc_w, sku_h, fill=1, stroke=0)

        c.setFont("Helvetica-Bold", 3.8)
        c.setFillColor(GRAY)
        c.drawCentredString(bc_x + bc_w / 2, sku_y + sku_h - 2.2*mm, "CÓDIGO / SKU")

        sku_val = product["sku"]
        fs_s    = 9.5
        while pdfmetrics.stringWidth(sku_val, "Helvetica-Bold", fs_s) > bc_w - 2*mm and fs_s > 5:
            fs_s -= 0.3
        c.setFont("Helvetica-Bold", fs_s)
        c.setFillColor(WHITE)
        c.drawCentredString(bc_x + bc_w / 2, sku_y + sku_h * 0.20, sku_val)

        # — Fecha bajo el SKU box (horizontal, no interfiere con el barcode) —
        c.setFont("Helvetica", 3.5)
        c.setFillColor(GRAY)
        c.drawCentredString(bc_x + bc_w / 2, body_y + 0.6*mm, fecha)

    # ── Dibuja las dos caras ──────────────────────────────────────────
    draw_half(0)
    draw_body(0)
    draw_half(HALF)
    draw_body(HALF)

    # ── Borde exterior ────────────────────────────────────────────────
    c.setStrokeColor(BLACK)
    c.setLineWidth(0.8)
    c.rect(0, 0, W, H, fill=0, stroke=1)

    # ── Línea de doblez central (punteada) ───────────────────────────
    c.setStrokeColor(colors.HexColor("#999999"))
    c.setLineWidth(0.6)
    c.setDash([2.5, 2.5])
    c.line(HALF, 0, HALF, H)
    c.setDash([])

    # ── Footer: franjas diagonales B&W  (-45°, igual que el HTML) ────
    c.setFillColor(BLACK)
    c.rect(0, 0, W, FTR_H, fill=1, stroke=0)
    c.setFillColor(WHITE)
    sg, sw = 8*mm, 4*mm
    for i in range(-2, int(W / sg) + 4):
        x0 = i * sg
        p  = c.beginPath()
        p.moveTo(x0, 0);            p.lineTo(x0 + sw, 0)
        p.lineTo(x0 + sw + FTR_H, FTR_H); p.lineTo(x0 + FTR_H, FTR_H)
        p.close()
        c.drawPath(p, fill=1, stroke=0)
    c.setStrokeColor(BLACK)
    c.setLineWidth(0.8)
    c.line(0, FTR_H, W, FTR_H)

    c.save()
    buf.seek(0)

    # Limpiar archivo temporal del logo blanco
    if logo_img_path:
        try:
            os.unlink(logo_img_path)
        except Exception:
            pass

    return buf.read()   # fin de _build_label_pdf_legacy


