@app.context_processor
def inject_globals():
    _role = (g.user["role"] if g.user else "") or ""
    # Marca dinámica disponible en TODOS los templates como {{ marca.name }},
    # {{ marca.logo_url }}, etc. Daniel edita comm_client_config en
    # /comunicaciones y cambia inmediatamente en el front (login, footer,
    # emails, etc) sin reiniciar.
    try:
        _marca_ctx = _get_marca()
    except Exception:
        _marca_ctx = {
            "name": "ILUS Fitness",
            "logo_url": "https://ilusfitness.com/cdn/shop/files/Logo_ILUS_Fitness_Blanco_equipamiento_para_gimnasios.png",
            "corp_color": "#DC143C",
        }
    return {
        "has_logo":    os.path.exists(os.path.join(app.static_folder, "Logo.png")),
        "current_user": g.user,
        "permissions":  g.permissions,
        "role_label":   {
                            "superadmin": "Super Administrador",
                            "admin":      "Administrador",
                            "ejecutivo":  "Ejecutivo",
                            "editor":     "Editor",
                            "lector":     "Lector",
                            "vendedor":   "Vendedor",
                            "tecnico":    "Técnico",
                        }.get(_role, "Usuario"),
        # Flag global para todos los templates: True si el usuario es 'tecnico' (solo lectura).
        # Permite ocultar botones de edición/creación/borrado sin tocar cada template.
        "is_tecnico":   (_role == "tecnico"),
        "photo_src":    _photo_src,
        # Modo embebido (iframe): default False; los endpoints que aceptan
        # ?embed=1 pueden sobreescribir pasando embed_mode=True en su render.
        "embed_mode":   False,
        # Google Maps API Key — si está vacía, el frontend hace fallback
        # a input de texto plano (sin autocomplete de direcciones).
        "google_maps_api_key": GOOGLE_MAPS_API_KEY,
        # Marca dinámica (lectura BD comm_client_config + env vars).
        # Disponible en todos los templates como {{ marca.name }} etc.
        "marca": _marca_ctx,
    }


# ─────────────────────────────────────────────
#  API — Búsqueda en ERP externo (SOLO LECTURA)
# ─────────────────────────────────────────────

@app.route("/api/sku-lookup")
@login_required
def sku_lookup():
    """
    Búsqueda exacta por SKU — usada por el escáner de código de barras.
    Responde en <50ms sin recargar la página.
    Devuelve: {status, pid?, sku, nombre, prepare_url?}
    """
    sku = request.args.get("sku", "").strip().upper()
    if not sku:
        return jsonify({"status": "not_found", "sku": ""})

    # ── 1. Buscar en app_products (nuestra BD) ───────────────────────
    hit = mysql_fetchone(
        f"SELECT id, nombre, sku FROM `{PRODUCTS_TABLE}` WHERE UPPER(TRIM(sku)) = %s",
        (sku,)
    )
    if hit:
        return jsonify({
            "status":     "found_app",
            "pid":        hit["id"],
            "sku":        hit["sku"],
            "nombre":     (hit["nombre"] or "").strip(),
            "detail_url": url_for("product_detail", pid=hit["id"]),
            "edit_url":   url_for("edit_product",   pid=hit["id"]),
        })

    # ── 2. Buscar en tabla ERP local ─────────────────────────────────
    erp_hit = None
    try:
        erp_hit = mysql_fetchone(
            f"SELECT UPPER(TRIM(`SKU`)) AS sku, TRIM(COALESCE(`Nombre`,'')) AS nombre "
            f"FROM `{ERP_TABLE}` WHERE UPPER(TRIM(`SKU`)) = %s",
            (sku,)
        )
    except Exception:
        pass

    if erp_hit:
        return jsonify({
            "status":      "found_erp",
            "sku":         erp_hit["sku"],
            "nombre":      (erp_hit["nombre"] or "").strip(),
            "prepare_url": url_for("prepare_product_from_erp", sku=erp_hit["sku"]),
        })

    # ── 3. REST API ERP — búsqueda exacta por código ─────────────────
    try:
        TOKEN = ERP_CONFIG.get("api_token", "")
        body  = _erp_get(
            "/productos",
            {"kopr": sku, "empresa": "01", "fields": "KOPR,NOKOPR", "visible": "true"},
            TOKEN, timeout=6,
        )
        items = body.get("data") or []
        if items:
            p = items[0]
            p_sku  = (p.get("KOPR") or "").strip().upper()
            p_name = (p.get("NOKOPR") or "").strip()
            if p_sku:
                return jsonify({
                    "status":      "found_erp",
                    "sku":         p_sku,
                    "nombre":      p_name,
                    "prepare_url": url_for("prepare_product_from_erp", sku=p_sku),
                })
    except Exception:
        pass

    return jsonify({"status": "not_found", "sku": sku})


@app.route("/api/product-search")
@require_permission("view")
def product_search():
    """
    Typeahead unificado para el formulario de nuevo producto.
    Fuentes: app_products → tabla ERP local → ERP REST API (fallback).

    Devuelve JSON con envelope:
      {
        "items": [{sku, nombre, source, already_exists}, ...],
        "erp_api_ok": bool,        # True si la REST API del ERP respondió OK
        "erp_api_error": str|None  # mensaje del fallo (para diagnóstico)
      }

    Compat retro: si el frontend espera un array plano (versión antigua),
    debe migrarse a leer .items — el envelope no rompe nada porque arrays
    JSON y objetos son distinguibles client-side.

    ════════════════════════════════════════════════════════════════════
    NOTA CRÍTICA (bug 2026-05-19):
    La tabla local `etiquetas` (ERP_TABLE) es un MIRROR de app_products
    via sync_erp_table(), NO un cache del catálogo ERP completo. Por
    eso, cuando la REST API del ERP cae (HTTP 502), la fuente #2 NO
    aporta SKUs "nuevos" — solo devuelve los mismos que ya están en
    app_products. Resultado: TODOS los items aparecían como "Ya
    registrado" cuando en realidad faltaba la fuente externa.
    FIX: devolver erp_api_ok=False para que el frontend muestre banner.
    ════════════════════════════════════════════════════════════════════
    """
    q = request.args.get("q", "").strip()
    if len(q) < 2:
        return jsonify({"items": [], "erp_api_ok": True, "erp_api_error": None})

    like_u  = f"%{q.upper()}%"
    results = []
    seen    = set()
    erp_api_ok = True
    erp_api_error = None

    # ── 1. app_products ──────────────────────────────────────────────
    try:
        rows = mysql_fetchall(
            f"""SELECT sku, nombre FROM `{PRODUCTS_TABLE}`
                WHERE UPPER(sku) LIKE %s OR UPPER(nombre) LIKE %s
                ORDER BY
                  CASE WHEN UPPER(sku) = %s THEN 0 ELSE 1 END,
                  nombre
                LIMIT 10""",
            (like_u, like_u, q.upper()),
        )
        for r in rows:
            sku = (r.get("sku") or "").strip().upper()
            if sku and sku not in seen:
                results.append({"sku": sku, "nombre": (r.get("nombre") or "").strip(),
                                 "source": "app", "already_exists": True})
                seen.add(sku)
    except Exception:
        pass

    # ── 2. Tabla ERP local ───────────────────────────────────────────
    # Esta tabla es un mirror de app_products+app_bultos (ver sync_erp_table).
    # Todo SKU que aparezca aquí ya está registrado por definición.
    try:
        rows2 = mysql_fetchall(
            f"""SELECT UPPER(TRIM(`SKU`)) AS sku,
                       TRIM(COALESCE(`Nombre`,'')) AS nombre
                FROM `{ERP_TABLE}`
                WHERE UPPER(TRIM(`SKU`)) LIKE %s OR UPPER(`Nombre`) LIKE %s
                ORDER BY
                  CASE WHEN UPPER(TRIM(`SKU`)) = %s THEN 0 ELSE 1 END,
                  `Nombre`
                LIMIT 20""",
            (like_u, like_u, q.upper()),
        )
        for r in rows2:
            sku = (r.get("sku") or "").strip().upper()
            if not sku or sku in seen:
                continue
            # Marcamos already_exists=True por defecto: este es un mirror.
            # La verificación final confirma con app_products de todas formas.
            results.append({"sku": sku, "nombre": (r.get("nombre") or "").strip(),
                             "source": "erp", "already_exists": True})
            seen.add(sku)
    except Exception:
        pass

    # ── 3. REST API ERP /productos — fuente en tiempo real ───────────
    erp_api_tried = False
    if len(q) >= 2:
        try:
            TOKEN = ERP_CONFIG.get("api_token", "")
            body  = _erp_get(
                "/productos",
                {
                    "search":  q,            # busca en código Y descripción
                    "empresa": "01",
                    "fields":  "KOPR,NOKOPR",
                    "visible": "true",
                    "venta":   "true",       # solo productos de venta (excluye servicios)
                },
                TOKEN, timeout=6,
            )
            erp_api_tried = True
            existing_skus = {r["sku"] for r in results}
            for p in (body.get("data") or []):
                p_sku  = (p.get("KOPR") or "").strip().upper()
                p_name = (p.get("NOKOPR") or "").strip()
                if not p_sku or p_sku in seen:
                    continue
                already = p_sku in existing_skus
                results.append({
                    "sku":           p_sku,
                    "nombre":        p_name,
                    "source":        "erp-api",
                    "already_exists": already,
                })
                seen.add(p_sku)
                if len(results) >= 25:
                    break
        except Exception as e:
            # REST API caída → marcar flag (sin banner UI; lo maneja fallback SQL).
            erp_api_ok = False
            try:
                msg = str(e)
                if len(msg) > 120:
                    msg = msg[:120] + "..."
                erp_api_error = f"{type(e).__name__}: {msg}"
            except Exception:
                erp_api_error = type(e).__name__

    # ── 4. FALLBACK SQL directo a MAEPR (cuando REST API cae) ────────
    # 2026-05-19: si la REST API del ERP no responde, vamos directo al
    # SQL Server de Random (mismo que usa Transporte/Mantenciones). Esto
    # restaura el comportamiento de búsqueda CATÁLOGO completo del ERP.
    if not erp_api_ok and len(q) >= 2:
        try:
            like_sql = f"%{q.upper()}%"
            erp_rows = _random_sql_query(
                f"""
                SELECT TOP 25
                       LTRIM(RTRIM(KOPR))   AS sku,
                       LTRIM(RTRIM(NOKOPR)) AS nombre
                  FROM {ERP_TABLE_PRODUCTS}
                 WHERE UPPER(LTRIM(RTRIM(KOPR)))   LIKE %s
                    OR UPPER(LTRIM(RTRIM(NOKOPR))) LIKE %s
                 ORDER BY KOPR
                """,
                (like_sql, like_sql),
                max_rows=25,
            ) or []
            existing_skus = {r["sku"] for r in results}
            for r in erp_rows:
                p_sku  = (r.get("sku") or "").strip().upper()
                p_name = (r.get("nombre") or "").strip()
                if not p_sku or p_sku in seen:
                    continue
                already = p_sku in existing_skus
                results.append({
                    "sku":           p_sku,
                    "nombre":        p_name,
                    "source":        "erp-sql",
                    "already_exists": already,
                })
                seen.add(p_sku)
                if len(results) >= 25:
                    break
            # SQL respondió OK → la búsqueda funcionó aunque la REST haya caído
            erp_api_ok = True
            erp_api_error = None
            print(f"[product-search] fallback SQL ERP exitoso: {len(erp_rows)} filas para q={q!r}", flush=True)
        except Exception as e2:
            print(f"[product-search] fallback SQL ERP falló: {type(e2).__name__}: {str(e2)[:200]}", flush=True)
            # Quedamos con erp_api_ok=False pero sin banner UI (Daniel pidió quitarlo)

    # ── Verificación final: consulta batch a app_products para todos los SKUs ──
    # Esto corrige casos donde la búsqueda por nombre falló (acentos/case) pero
    # el SKU SÍ existe en la BD (evita mostrar "No registrado" cuando ya está).
    if results:
        try:
            all_skus = list({r["sku"] for r in results})
            ph = ",".join(["%s"] * len(all_skus))
            verified = mysql_fetchall(
                f"SELECT UPPER(TRIM(sku)) AS sku FROM `{PRODUCTS_TABLE}` WHERE UPPER(TRIM(sku)) IN ({ph})",
                tuple(all_skus),
            )
            verified_set = {r["sku"] for r in (verified or [])}
            for r in results:
                r["already_exists"] = r["sku"] in verified_set
        except Exception:
            pass  # si falla la verificación, dejamos los valores anteriores

    # Ordenar: exactos primero, no-existentes primero, luego nombre
    results.sort(key=lambda x: (
        1 if x["already_exists"] else 0,
        0 if x["sku"] == q.upper() else 1,
        x["nombre"].lower()
    ))

    return jsonify({
        "items": results[:20],
        "erp_api_ok": erp_api_ok,
        "erp_api_error": erp_api_error,
    })


# ─────────────────────────────────────────────
#  Auth routes
# ─────────────────────────────────────────────

@app.route("/login", methods=["GET", "POST"])
@rate_limited("login", max_attempts=10, window_seconds=300)
def login():
    if g.user:
        return redirect(url_for("index"))
    next_url = request.args.get("next") or request.form.get("next") or url_for("index")
    # solo_activas=True → filtra WHERE activa=1 LIMIT 5 para el login público
    imgs = _login_images_active(solo_activas=True)
    if request.method == "POST":
        username = request.form.get("username", "").strip().lower()
        password = request.form.get("password", "")
        try:
            user = get_auth_user_by_username(username)
        except Exception as exc:
            _audit("login_error", details={"username": username, "error": str(exc)},
                   status="error")
            print(f"[login] error conectando para {username}: {exc}", flush=True)
            flash("No fue posible conectar con el servidor. Intenta nuevamente en unos segundos.", "danger")
            return render_template("login.html", next_url=next_url, username=username, login_images=imgs, marca=_get_marca())
        if not user or not user["active"] or not check_password_hash(user["password_hash"], password):
            reason = ("no_existe" if not user
                      else "inactivo" if not user["active"]
                      else "password_invalida")
            _audit("login_fail",
                   target_type="user", target_id=(user or {}).get("id"),
                   details={"username": username, "reason": reason},
                   status="fail")
            flash("Usuario o contraseña incorrectos.", "danger")
            return render_template("login.html", next_url=next_url, username=username, login_images=imgs, marca=_get_marca())
        session.clear()
        session["user_id"] = user["id"]
        # ── FIX 2026-05-18 ──────────────────────────────────────────
        # CAUSA RAÍZ del bug "Nunca se conectó" para usuarios que SÍ se
        # conectaron: la versión anterior corría en un hilo daemon y llamaba
        # a `mysql_execute()` → `get_db()` → `g._db`. Pero `g` es Flask
        # request-bound; el thread daemon corre FUERA del request context y
        # `get_db()` lanzaba `RuntimeError("Working outside of request context")`.
        # La excepción la atrapaba el except y solo printeaba al stdout, así
        # que el UPDATE NUNCA se ejecutaba para ningún login → todos los
        # usuarios quedaban con last_login_at congelado (el último valor de
        # la versión síncrona, que era 2026-05-15).
        #
        # FIX: hacerlo SÍNCRONO (el UPDATE indexado por PK toma <30ms, no
        # justifica el overhead/complejidad de un thread). Si la BD está
        # zombi peor, mejor que el usuario lo note al loguearse (10s
        # connect_timeout) que tener tracking roto para siempre.
        # Try/except envuelve para que un error de BD NO impida el login.
        # ─────────────────────────────────────────────────────────────
        # ── FIX 2026-05-27 (Daniel — login 6s): UPDATE y audit van a
        # daemon thread CON app.app_context() para que get_db() y mysql_*
        # funcionen sin RuntimeError. Esto ahorra ~1-1.5s de latencia de
        # red MySQL bloqueando el redirect del usuario.
        #
        # El bug previo (login_ok no se grababa) era porque NO se usaba
        # app_context. Ahora SÍ se usa → audit + last_login_at se graban
        # correctamente, pero asincrónicamente.
        # ──────────────────────────────────────────────────────────────
        try:
            ip = (request.headers.get("X-Forwarded-For") or request.remote_addr or "")[:64]
            _uid = user["id"]
            _uname = user["username"]
            _urole = user["role"]
            import threading as _th_login
            def _login_track_async():
                with app.app_context():
                    # Track last_login + audit en una sola llamada al thread.
                    try:
                        try:
                            mysql_execute(
                                f"UPDATE `{AUTH_TABLE}` SET last_login_at=NOW(), "
                                f"last_login_ip=%s, last_seen_at=NOW(), "
                                f"login_count=COALESCE(login_count,0)+1 WHERE id=%s",
                                (ip, _uid)
                            )
                        except Exception as _e_lst:
                            print(f"[login-track-async] fallback sin last_seen_at: {_e_lst}", flush=True)
                            try:
                                mysql_execute(
                                    f"UPDATE `{AUTH_TABLE}` SET last_login_at=NOW(), "
                                    f"last_login_ip=%s, login_count=COALESCE(login_count,0)+1 "
                                    f"WHERE id=%s",
                                    (ip, _uid)
                                )
                            except Exception as _e_lst2:
                                print(f"[login-track-async] tracking falló: {_e_lst2}", flush=True)
                        print(f"[login-track-async] OK uid={_uid} username={_uname}", flush=True)
                    except Exception as _e_lt_outer:
                        print(f"[login-track-async] outer error: {_e_lt_outer}", flush=True)

                    try:
                        _audit("login_ok",
                               target_type="user", target_id=_uid,
                               user_override={"id": _uid, "username": _uname, "role": _urole})
                    except Exception as _e_au:
                        print(f"[login-track-async] audit falló: {_e_au}", flush=True)
            _th_login.Thread(target=_login_track_async, daemon=True,
                             name=f"login-track-{_uid}").start()
        except Exception as _e_login_track:
            import traceback as _tb_lt
            print(f"[login-track] FAIL outer uid={user['id']}: {_e_login_track}\n{_tb_lt.format_exc()}", flush=True)
        flash(f"Bienvenido, {user['nombre']}.", "success")
        return redirect(next_url)
    # FIX 2026-05-18 (perf): cache privado corto (30s) en GET /login.
    # El HTML cambia muy poco entre requests y antes lo forzábamos a
    # `no-store` que invalidaba el cache del navegador en cada toque.
    # `private, max-age=30` permite back-button instantáneo sin filtrar
    # entre usuarios (Vary: Cookie ya lo segmenta) y ahorra round-trips.
    # POST sigue siendo no-cache porque retornamos render dentro del if
    # de validación, no llega acá.
    resp = make_response(render_template("login.html", next_url=next_url, username="", login_images=imgs, marca=_get_marca()))
    resp.headers["Cache-Control"] = "private, max-age=30"
    resp.headers["Vary"] = "Cookie"
    return resp


@app.route("/logout", methods=["POST"])
@login_required
def logout():
    # ── FIX 2026-05-17 ──────────────────────────────────────────
    # ORDEN crítico: limpiar sesión PRIMERO, audit DESPUÉS.
    # Si la conexión MySQL está zombi (idle largo), _audit() bloquea
    # 5-20s → el usuario percibe "no me bota". Con esta ordenación,
    # la cookie se invalida instantáneamente y el audit es best-effort.
    # ─────────────────────────────────────────────────────────────
    uid = g.user.get("id") if getattr(g, "user", None) else None
    uname = g.user.get("username") if getattr(g, "user", None) else None
    urole = g.user.get("role") if getattr(g, "user", None) else None
    session.clear()
    try:
        _audit("logout", target_type="user", target_id=uid,
               user_override={"id": uid, "username": uname, "role": urole} if uid else None)
    except Exception as _e_log:
        print(f"[logout] audit best-effort falló: {_e_log}", flush=True)
    flash("Sesion cerrada.", "success")
    return redirect(url_for("login"))


# ─────────────────────────────────────────────
#  Plantilla maestra ILUS para todos los correos
# ─────────────────────────────────────────────

def _ilus_email_html(
    titulo: str,
    subtitulo: str = "",
    saludo: str = "",
    parrafos: list = None,          # lista de strings HTML
    btn_primario_txt: str = "",
    btn_primario_url: str = "",
    btn_secundario_txt: str = "",
    btn_secundario_url: str = "",
    info_lineas: list = None,       # lista de (icono, clave, valor)
) -> str:
    """
    Genera HTML de correo con el diseño oficial ILUS:
    Header negro con logo → banda oscura título/subtítulo → cuerpo blanco → botones → footer negro.
    """
    # ── Logo y empresa desde marca dinámica (BD comm_client_config) ─────
    # Marca cambia desde /comunicaciones sin tocar código.
    try:
        marca    = _get_marca()
        logo_src = marca["logo_url"]
        company  = marca["name"]
    except Exception:
        logo_src = "https://ilusfitness.com/cdn/shop/files/Logo_ILUS_Fitness_Blanco_equipamiento_para_gimnasios.png"
        company  = "ILUS Fitness"

    # ── Info box ─────────────────────────────────────────────────────────────
    info_html = ""
    if info_lineas:
        rows_html = "".join(
            f'<p style="margin:0 0 4px;font-size:13px;color:#333">'
            f'<strong>{k}:</strong> {v}</p>'
            for _, k, v in info_lineas
        )
        info_html = (
            f'<div style="background:#f8f8f8;border-left:4px solid #DC143C;'
            f'padding:15px 18px;margin:20px 0;border-radius:6px">'
            f'{rows_html}</div>'
        )

    # ── Párrafos ─────────────────────────────────────────────────────────────
    saludo_html = (
        f'<p style="font-size:14px;color:#111827;line-height:1.6;margin:0 0 14px">'
        f'Hola <strong>{saludo}</strong>,</p>'
    ) if saludo else ""

    body_html = "".join(
        f'<p style="font-size:14px;color:#111827;line-height:1.6;margin:0 0 14px">{p}</p>'
        for p in (parrafos or [])
    )

    # ── Botones ──────────────────────────────────────────────────────────────
    btn1 = ""
    if btn_primario_txt and btn_primario_url:
        btn1 = (
            f'<a href="{btn_primario_url}" style="display:inline-block;background:#DC143C;'
            f'color:#ffffff;padding:12px 25px;text-decoration:none;font-size:13px;'
            f'border-radius:5px;margin:5px;font-weight:bold">{btn_primario_txt}</a>'
        )
    btn2 = ""
    if btn_secundario_txt and btn_secundario_url:
        btn2 = (
            f'<a href="{btn_secundario_url}" style="display:inline-block;background:#000;'
            f'color:#ffffff;padding:12px 25px;text-decoration:none;font-size:13px;'
            f'border-radius:5px;margin:5px;font-weight:bold">{btn_secundario_txt}</a>'
        )
    btns_html = (
        f'<div style="padding:0 30px 30px;text-align:center">{btn1}{btn2}</div>'
    ) if (btn1 or btn2) else ""

    # ── Branding del footer: usa la misma marca dinámica ───────────────
    try:
        marca2 = _get_marca()
    except Exception:
        marca2 = {
            "name": "ILUS Fitness",
            "support_email": "servicio.tecnico@ilusfitness.com",
            "support_url":   "https://ilusfitness.com/soporte",
        }
    brand_name    = marca2.get("name") or company
    support_email = marca2.get("support_email") or "servicio.tecnico@ilusfitness.com"
    support_url   = marca2.get("support_url") or ""
    año_actual    = datetime.now().year if 'datetime' in globals() else 2026

    soporte_html = (
        f'<a href="mailto:{support_email}" '
        f'style="color:#DC143C;text-decoration:none">{support_email}</a>'
    )
    portal_html = (
        f' &middot; <a href="{support_url}" '
        f'style="color:#9ca3af;text-decoration:none">Portal de soporte</a>'
    ) if support_url else ""

    return f"""<!DOCTYPE html>
<html lang="es">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>{titulo}</title>
</head>
<body style="margin:0;padding:0;background:#f1f2f4;font-family:Arial,Helvetica,sans-serif;color:#111827">

<div style="max-width:580px;margin:28px auto;background:#ffffff;border-radius:10px;
            overflow:hidden;box-shadow:0 6px 20px rgba(15,23,42,.10)">

  <!-- HEADER: negro + logo -->
  <div style="background:#000;padding:24px 28px;text-align:center">
    <img src="{logo_src}" alt="{brand_name}"
         style="height:48px;display:block;margin:0 auto;max-width:230px;width:auto;object-fit:contain">
  </div>

  <!-- TÍTULO: banda oscura -->
  <div style="background:#111;color:#fff;text-align:center;padding:28px 32px;border-top:1px solid #202020">
    <h1 style="margin:0;font-size:22px;line-height:1.25;font-weight:800">{titulo}</h1>
    {f'<p style="margin-top:8px;font-size:13px;line-height:1.45;color:#f3f4f6;margin-bottom:0">{subtitulo}</p>' if subtitulo else ''}
  </div>

  <!-- CONTENIDO -->
  <div style="padding:32px 30px">
    {saludo_html}
    {body_html}
    {info_html}
  </div>

  <!-- BOTONES -->
  {btns_html}

  <!-- FOOTER: negro -->
  <div style="background:#000;padding:24px 32px;text-align:center">
    <div style="color:#DC143C;font-size:13px;font-weight:700;text-transform:uppercase">{brand_name}</div>
    <div style="color:#9ca3af;font-size:11px;margin-top:5px">
      Equipamiento profesional para alto rendimiento &middot; {año_actual}
    </div>
    <div style="margin-top:14px;font-size:11px;line-height:1.6;color:#6b7280">
      Este mensaje fue enviado automáticamente desde una dirección que no recibe respuestas.<br>
      Para soporte, escribe a {soporte_html}{portal_html}
    </div>
  </div>

</div>
</body>
</html>"""


def _smtp_ipv4(host: str) -> str:
    """Devuelve una IP v4 del host SMTP para evitar fallas por IPv6 en algunos hosting."""
    import socket

    infos = socket.getaddrinfo(host, None, socket.AF_INET, socket.SOCK_STREAM)
    if not infos:
        return host
    return infos[0][4][0]


class _IPv4SMTP(smtplib.SMTP):
    def _get_socket(self, host, port, timeout):
        import socket

        ip = _smtp_ipv4(host)
        return socket.create_connection((ip, port), timeout, self.source_address)


class _IPv4SMTP_SSL(smtplib.SMTP_SSL):
    def _get_socket(self, host, port, timeout):
        import socket

        ip = _smtp_ipv4(host)
        sock = socket.create_connection((ip, port), timeout, self.source_address)
        return self.context.wrap_socket(sock, server_hostname=self._host)


def _open_smtp_client(host: str, port: int, secure: bool, timeout: int = 15, context=None):
    """Abre SMTP forzando IPv4, pero conserva el hostname para TLS/SNI."""
    if secure:
        return _IPv4SMTP_SSL(host, port, context=context, timeout=timeout)
    return _IPv4SMTP(host, port, timeout=timeout)


def _get_resend_cfg() -> dict:
    """
    Devuelve configuración de Resend API.
    Resend es necesario en hosting cloud (Railway, Heroku) porque Gmail/SMTP
    típicamente bloquea o limita conexiones desde rangos IP de proveedores cloud.
    Prioridad: env vars (Railway) → BD (configurado vía front).
    """
    # 1. Env var (Railway / Docker / local .env)
    api_key = os.environ.get("RESEND_API_KEY", "").strip()
    if api_key:
        # 2026-05-27 (Daniel): aceptar AMBOS nombres de variable.
        # Algunos despliegues usan RESEND_FROM_EMAIL en vez de RESEND_FROM_ADDR.
        _from = (os.environ.get("RESEND_FROM_ADDR", "").strip()
                 or os.environ.get("RESEND_FROM_EMAIL", "").strip()
                 or "onboarding@resend.dev")
        return {
            "api_key":   api_key,
            "from_addr": _from,
            "_source":   "env",
        }
    # 2. BD
    try:
        row = mysql_fetchone("SELECT * FROM comm_resend_config ORDER BY id DESC LIMIT 1")
        if row and row.get("api_key"):
            return {
                "api_key":   row["api_key"],
                "from_addr": row.get("from_addr") or "onboarding@resend.dev",
                "_source":   "db",
            }
    except Exception:
        pass
    return {"api_key": "", "from_addr": "", "_source": ""}


def _send_via_resend(to, subject: str, html: str, from_addr: str = None,
                     reply_to: str = None) -> bool:
    """
    Envía email vía API HTTPS de Resend (no usa puertos SMTP).
    Funciona desde cualquier IP, incluyendo cloud hosting (Railway, Heroku, AWS).

    Args:
      to: destinatario(s) - string o lista
      subject: asunto
      html: cuerpo HTML
      from_addr: opcional "Nombre <email@dominio>"; default Resend config
      reply_to: opcional buzón de respuesta (header Reply-To)

    En caso de fallo, deja info en `g._last_resend_error` (dict con message/http_code/raw_body).
    """
    import urllib.request as _ur
    import urllib.error as _ue

    cfg = _get_resend_cfg()
    if not cfg.get("api_key"):
        g._last_resend_error = {
            "name": "no_config",
            "message": "RESEND_API_KEY no está configurada (env var o BD).",
            "http_code": 0, "status_code": 0, "raw_body": "",
        }
        return False

    sender = (from_addr or cfg.get("from_addr") or "onboarding@resend.dev").strip()
    recipients = [to] if isinstance(to, str) else list(to)
    payload_dict = {
        "from": sender,
        "to": recipients,
        "subject": subject,
        "html": html,
    }
    if reply_to:
        # Resend acepta string o lista
        payload_dict["reply_to"] = reply_to
    payload = json.dumps(payload_dict).encode("utf-8")

    req = _ur.Request(
        "https://api.resend.com/emails",
        data=payload,
        headers={
            "Authorization": f"Bearer {cfg['api_key']}",
            "Content-Type":  "application/json",
        },
        method="POST",
    )
    try:
        with _ur.urlopen(req, timeout=20) as resp:
            print(f"[ILUS][RESEND] Email enviado a {recipients} (HTTP {resp.status}, source={cfg.get('_source')})")
            g._last_resend_error = None
            return True
    except _ue.HTTPError as e:
        body = ""
        try:
            body = e.read().decode("utf-8", errors="replace")
        except Exception:
            pass
        try:
            err_data = json.loads(body) if body else {}
        except Exception:
            err_data = {}
        g._last_resend_error = {
            "name":        err_data.get("name", ""),
            "message":     err_data.get("message", str(e)),
            "http_code":   e.code,
            "status_code": e.code,
            "raw_body":    body[:600],
        }
        print(f"[ILUS][RESEND] HTTP {e.code} — {body[:200]}")
        return False
    except Exception as e:
        g._last_resend_error = {
            "name":      "exception",
            "message":   str(e),
            "http_code": 0, "status_code": 0,
            "raw_body":  "",
        }
        print(f"[ILUS][RESEND] Excepción: {e}")
        return False


def _email_log(destinatario, asunto, evento, estado, error_msg=None, metadata=None):
    """Registra cada intento de envío de email para trazabilidad."""
    try:
        actor = ""
        try: actor = current_username() if g.user else "sistema"
        except Exception: actor = "sistema"
        mysql_execute(
            "INSERT INTO email_log (destinatario,asunto,evento,canal,estado,error_msg,actor,metadata) "
            "VALUES (%s,%s,%s,'email',%s,%s,%s,%s)",
            (str(destinatario)[:300], str(asunto)[:500], evento or "manual",
             estado, (error_msg or "")[:1000], actor[:190],
             json.dumps(metadata or {}, ensure_ascii=False)[:1500])
        )
    except Exception as exc:
        print(f"[EMAIL LOG] {exc}")


# ══════════════════════════════════════════════════════════════════════
# CANALES DE COMUNICACIÓN ACTIVOS — env var COMM_CANALES_ACTIVOS
#
# Daniel dio de baja Twilio: WhatsApp y SMS quedan deshabilitados del
# FLUJO automático del sistema (notificaciones de OT, accesos, etc.).
# El CÓDIGO de _send_whatsapp / _send_sms permanece en app.py, los
# endpoints admin de prueba (/api/twilio/test, /comunicaciones/whatsapp/test)
# también — para que Daniel pueda re-activar el canal en el futuro sin
# tocar código (solo env var + reinicio).
#
# Default: "email" (sólo email vía Resend está activo).
# Para reactivar WhatsApp: COMM_CANALES_ACTIVOS="email,whatsapp"
# Para todo:               COMM_CANALES_ACTIVOS="email,sms,whatsapp"
# ══════════════════════════════════════════════════════════════════════

def _canal_activo(canal: str) -> bool:
    """Retorna True si el canal está habilitado globalmente.

    Lee env var COMM_CANALES_ACTIVOS (default: 'email').
    Para que un envío automático se dispare, el canal debe aparecer en
    la lista. Por ejemplo, con COMM_CANALES_ACTIVOS='email':
       _canal_activo('email')    → True
       _canal_activo('whatsapp') → False
       _canal_activo('sms')      → False

    NO toca el kill switch global de BD ni la llave de paso por módulo —
    es un cortacorriente PREVIO. Si el canal está apagado aquí, ni siquiera
    se intenta el envío (no se llama a Twilio, no se loguea como bloqueado).
    """
    try:
        activos = (os.environ.get("COMM_CANALES_ACTIVOS") or "email").lower()
        canales = [c.strip() for c in activos.split(",") if c.strip()]
        return (canal or "").strip().lower() in canales
    except Exception:
        # Conservador: si algo falla, sólo email activo
        return (canal or "").strip().lower() == "email"


def _canales_activos_lista() -> list:
    """Devuelve la lista de canales activos en orden. Útil para diagnóstico/UI."""
    try:
        activos = (os.environ.get("COMM_CANALES_ACTIVOS") or "email").lower()
        return [c.strip() for c in activos.split(",") if c.strip()]
    except Exception:
        return ["email"]


# ══════════════════════════════════════════════════════════════════════
# KILL SWITCH GLOBAL DE COMUNICACIONES
#
# Permite al superadministrador apagar todo envío de email y/o WhatsApp
# sin tocar credenciales (útil cuando el proveedor está caído, durante
# migración, mantenimiento, o para evitar spam masivo accidental).
#
# Tabla: app_kill_switch (key, enabled, updated_by, updated_at)
#   keys: 'email', 'whatsapp'
#
# Funciones:
#   comm_is_enabled('email')  → bool   (default True si no hay registro)
#   comm_set_enabled('email', False, usuario)
#   _send_ilus_email() respeta el switch automáticamente
# ══════════════════════════════════════════════════════════════════════

# Cache en proceso para no consultar BD en cada envío
_COMM_SWITCH_CACHE = {"email": None, "whatsapp": None, "ts": 0}
_COMM_SWITCH_TTL = 30  # segundos


def comm_is_enabled(canal: str) -> bool:
    """Devuelve True si el canal está habilitado. Default True."""
    import time as _t
    now = _t.time()
    # Cache hit
    if (now - _COMM_SWITCH_CACHE["ts"]) < _COMM_SWITCH_TTL and _COMM_SWITCH_CACHE.get(canal) is not None:
        return bool(_COMM_SWITCH_CACHE[canal])
    # Recargar de BD
    try:
        rows = mysql_fetchall(
            "SELECT `key`, enabled FROM app_kill_switch WHERE `key` IN ('email','whatsapp')"
        ) or []
        _COMM_SWITCH_CACHE["ts"] = now
        for r in rows:
            _COMM_SWITCH_CACHE[r["key"]] = bool(r["enabled"])
        # Defaults para keys que no existen
        if _COMM_SWITCH_CACHE.get("email") is None: _COMM_SWITCH_CACHE["email"] = True
        if _COMM_SWITCH_CACHE.get("whatsapp") is None: _COMM_SWITCH_CACHE["whatsapp"] = True
    except Exception:
        # Si la tabla aún no existe, todo habilitado por default
        return True
    return bool(_COMM_SWITCH_CACHE.get(canal, True))


def comm_set_enabled(canal: str, enabled: bool, usuario: str = "sistema") -> bool:
    """Setea el switch. Solo válido para 'email' o 'whatsapp'."""
    if canal not in ("email", "whatsapp"):
        return False
    try:
        # Asegurar tabla existe (idempotente)
        mysql_execute("""
            CREATE TABLE IF NOT EXISTS app_kill_switch (
              `key` VARCHAR(40) PRIMARY KEY,
              enabled TINYINT(1) DEFAULT 1,
              updated_by VARCHAR(190),
              updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
            ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
        """)
        mysql_execute(
            "INSERT INTO app_kill_switch (`key`,enabled,updated_by) VALUES (%s,%s,%s) "
            "ON DUPLICATE KEY UPDATE enabled=VALUES(enabled), updated_by=VALUES(updated_by)",
            (canal, 1 if enabled else 0, usuario)
        )
        # Invalidar cache
        _COMM_SWITCH_CACHE["ts"] = 0
        return True
    except Exception as e:
        print(f"[KILL_SWITCH] Error setting {canal}={enabled}: {e}")
        return False


@app.route("/comunicaciones/kill-switch", methods=["GET"])
def comm_kill_switch_get():
    """Devuelve el estado actual del kill switch (cualquier usuario logueado puede leer)."""
    if not g.get("user"):
        return jsonify({"error": "Sin sesión"}), 401
    return jsonify({
        "email":    comm_is_enabled("email"),
        "whatsapp": comm_is_enabled("whatsapp"),
    })


@app.route("/comunicaciones/kill-switch", methods=["POST"])
def comm_kill_switch_set():
    """Cambia el estado del kill switch (solo superadmin).
    Body JSON: {"email": bool, "whatsapp": bool} — campos opcionales."""
    if not (g.get("user") and g.permissions.get("superadmin")):
        return jsonify({"error": "Solo superadmin"}), 403
    d = request.get_json(silent=True) or {}
    user = current_username() or "sistema"
    cambios = {}
    if "email" in d:
        ok = comm_set_enabled("email", bool(d["email"]), user)
        cambios["email"] = {"requested": bool(d["email"]), "ok": ok}
    if "whatsapp" in d:
        ok = comm_set_enabled("whatsapp", bool(d["whatsapp"]), user)
        cambios["whatsapp"] = {"requested": bool(d["whatsapp"]), "ok": ok}
    return jsonify({
        "ok": True,
        "cambios": cambios,
        "estado_actual": {
            "email":    comm_is_enabled("email"),
            "whatsapp": comm_is_enabled("whatsapp"),
        }
    })


# ══════════════════════════════════════════════════════════════════════
# LLAVE DE PASO POR MÓDULO (kill switch granular)
#
# Daniel necesita poder "cerrar la llave" de los correos/WhatsApp/SMS
# de cada módulo (transporte, retiros, mantenciones, comunicación
# interna, general) mientras está en pruebas, sin tocar credenciales.
#
# Tabla: comm_killswitch (modulo, email/whatsapp/sms_bloqueado, motivo)
# Cache: 30s para no consultar BD en cada envío.
#
# Funciones:
#   _modulo_canal_bloqueado(modulo, canal) → bool
#   _comm_killswitch_invalidar() — invalida cache (lo llaman los setters)
# ══════════════════════════════════════════════════════════════════════

_MODULOS_KILLSWITCH_VALIDOS = (
    "transporte",
    "retiros",
    "mantenciones",
    "comunicacion_interna",
    "general",
)

_KILLSWITCH_CACHE = {"data": None, "ts": 0}
_KILLSWITCH_TTL = 30  # segundos


def _comm_killswitch_invalidar():
    """Invalida el caché en memoria. Se llama tras cada cambio (PUT)."""
    _KILLSWITCH_CACHE["ts"] = 0
    _KILLSWITCH_CACHE["data"] = None


def _comm_killswitch_estado():
    """Devuelve dict {modulo: {email_bloqueado, whatsapp_bloqueado,
    sms_bloqueado, motivo, actualizado_por, actualizado_at}} usando caché.
    Si la tabla no existe aún, devuelve dict con todos los módulos en 0.
    """
    import time as _t
    now = _t.time()
    if (_KILLSWITCH_CACHE["data"] is not None
            and (now - _KILLSWITCH_CACHE["ts"]) < _KILLSWITCH_TTL):
        return _KILLSWITCH_CACHE["data"]

    estado = {m: {"email_bloqueado": 0, "whatsapp_bloqueado": 0,
                  "sms_bloqueado": 0, "motivo": "",
                  "actualizado_por": "", "actualizado_at": None}
              for m in _MODULOS_KILLSWITCH_VALIDOS}
    try:
        rows = mysql_fetchall(
            "SELECT modulo, email_bloqueado, whatsapp_bloqueado, sms_bloqueado, "
            "       motivo, actualizado_por, actualizado_at "
            "FROM comm_killswitch"
        ) or []
        for r in rows:
            mod = r.get("modulo") or ""
            if mod not in estado:
                estado[mod] = {"email_bloqueado": 0, "whatsapp_bloqueado": 0,
                               "sms_bloqueado": 0, "motivo": "",
                               "actualizado_por": "", "actualizado_at": None}
            estado[mod]["email_bloqueado"]    = int(r.get("email_bloqueado") or 0)
            estado[mod]["whatsapp_bloqueado"] = int(r.get("whatsapp_bloqueado") or 0)
            estado[mod]["sms_bloqueado"]      = int(r.get("sms_bloqueado") or 0)
            estado[mod]["motivo"]             = r.get("motivo") or ""
            estado[mod]["actualizado_por"]    = r.get("actualizado_por") or ""
            estado[mod]["actualizado_at"]     = r.get("actualizado_at")
    except Exception as exc:
        # Si la tabla aún no existe (primer arranque), nada bloqueado.
        print(f"[KILLSWITCH] No se pudo leer comm_killswitch: {exc}")

    _KILLSWITCH_CACHE["data"] = estado
    _KILLSWITCH_CACHE["ts"]   = now
    return estado


def _modulo_canal_bloqueado(modulo: str, canal: str) -> bool:
    """Devuelve True si el canal está bloqueado para ese módulo.

    Args:
      modulo: 'transporte' | 'retiros' | 'mantenciones' |
              'comunicacion_interna' | 'general'.
              Si no se reconoce, se usa 'general'.
      canal:  'email' | 'whatsapp' | 'sms'.
              Si no se reconoce, devuelve False (no bloquea).

    Es defensivo: cualquier excepción → False (no bloquea por error técnico).
    """
    try:
        mod = (modulo or "general").strip().lower()
        if mod not in _MODULOS_KILLSWITCH_VALIDOS:
            mod = "general"
        canal = (canal or "").strip().lower()
        key = {"email": "email_bloqueado",
               "whatsapp": "whatsapp_bloqueado",
               "sms": "sms_bloqueado"}.get(canal)
        if not key:
            return False
        estado = _comm_killswitch_estado()
        return bool(estado.get(mod, {}).get(key, 0))
    except Exception:
        return False


def _modulo_desde_evento(evento: str) -> str:
    """Heurística para mapear 'evento' (string usado en email_log) al módulo.
    Útil cuando no se pasa 'modulo' explícito al enviar."""
    if not evento:
        return "general"
    e = str(evento).lower()
    if e.startswith("retry_"):
        e = e[6:]
    # Mantenciones
    if any(t in e for t in ("ot_", "visita_", "reporte_", "mant_", "tecnico_",
                            "_visita", "_ot")):
        return "mantenciones"
    # Comunicación interna (accesos, claves, login)
    if any(t in e for t in ("password", "invite", "welcome", "acceso",
                            "login", "inicio_sesion", "cambio_pass",
                            "olvido_contrasena")):
        return "comunicacion_interna"
    # Retiros
    if any(t in e for t in ("retiro", "pickup")):
        return "retiros"
    # Transporte
    if any(t in e for t in ("pedido", "courier", "despacho", "programado",
                            "en_ruta", "en_camino", "entregado", "fallido")):
        return "transporte"
    return "general"


def _send_ilus_email(to_addr: str, subject: str, html_body: str, *,
                     evento: str = None, modulo: str = None, **kwargs) -> bool:
    """
    Envía un correo HTML usando la configuración SMTP dinámica.
    Prioridad: Resend API (Railway) → SMTP con env vars → SMTP BD → SMTP config.py
    Loguea automáticamente el resultado en email_log.

    KILL SWITCH GLOBAL: si el switch global de email está OFF, devuelve False
    sin intentar enviar. Log queda con razon='kill_switch_off'.

    LLAVE DE PASO POR MÓDULO: si el módulo identificado tiene el canal email
    bloqueado en comm_killswitch, NO envía y deja log con estado='bloqueado'.
    Si no se pasa 'modulo', se infiere del 'evento'. Default: 'general'.
    """
    # 1) KILL SWITCH GLOBAL (todo email)
    if not comm_is_enabled("email"):
        try:
            _email_log(to_addr, subject, evento, 'bloqueado',
                       error_msg='Email deshabilitado por superadmin (kill switch global ON)')
        except Exception: pass
        print(f"[EMAIL][KILL_SWITCH] Bloqueado a {to_addr}: kill switch global OFF")
        return False

    # 2) LLAVE DE PASO POR MÓDULO
    mod_resolved = (modulo or _modulo_desde_evento(evento) or "general").strip().lower()
    if _modulo_canal_bloqueado(mod_resolved, "email"):
        try:
            _email_log(to_addr, subject, evento, 'bloqueado',
                       error_msg=f'Llave de paso cerrada para módulo "{mod_resolved}" — email no enviado',
                       metadata={"modulo": mod_resolved, "killswitch": True})
        except Exception: pass
        print(f"[KILLSWITCH] modulo={mod_resolved} canal=email bloqueado por kill switch — no enviado (to={to_addr})")
        return False

    # _send_ilus_email_inner hace el envío real; lo wrappeamos
    sent = False
    err  = None
    try:
        sent = _send_ilus_email_real(to_addr, subject, html_body, **kwargs)
    except Exception as exc:
        err = str(exc)[:1000]
    # Log
    try:
        _email_log(to_addr, subject, evento, 'enviado' if sent else 'fallido',
                   error_msg=err, metadata={"modulo": mod_resolved})
    except Exception: pass
    return sent


def _get_brand_cfg() -> dict:
    """Devuelve el branding genérico ILUS, respetando overrides de env vars.

    Se invoca en CADA envío de email/WhatsApp/SMS para que los cambios en
    Railway tomen efecto sin reiniciar la app. Defaults sensatos arriba.
    """
    import os as _os_b
    return {
        "name":          (_os_b.environ.get("ILUS_BRAND_NAME")       or BRAND_CONFIG.get("name")       or "ILUS Sport & Health").strip(),
        "from_name":     (_os_b.environ.get("ILUS_BRAND_FROM_NAME")  or BRAND_CONFIG.get("from_name")  or "ILUS").strip(),
        "from_email":    (_os_b.environ.get("ILUS_BRAND_FROM_EMAIL") or BRAND_CONFIG.get("from_email") or "no-reply@ilusfitness.com").strip(),
        "reply_to":      (_os_b.environ.get("ILUS_BRAND_REPLY_TO")   or BRAND_CONFIG.get("reply_to")   or "servicio.tecnico@ilusfitness.com").strip(),
        "wa_name":       (_os_b.environ.get("ILUS_BRAND_WA_NAME")    or BRAND_CONFIG.get("wa_name")    or "ILUS").strip(),
        "support_url":   (_os_b.environ.get("ILUS_BRAND_SUPPORT_URL")  or BRAND_CONFIG.get("support_url")   or "https://ilusfitness.com/soporte").strip(),
        "support_email": (_os_b.environ.get("ILUS_BRAND_SUPPORT_EMAIL")or BRAND_CONFIG.get("support_email") or "servicio.tecnico@ilusfitness.com").strip(),
    }


# ── CACHE 2026-05-26 (Daniel — performance audit) ─────────────────────
# `_get_marca()` se invoca en TODOS los renders vía context_processor.
# Antes: 2 queries SQL por cada render HTML. Con 30 navegaciones/min eso
# son 60 queries/min innecesarias (la marca casi nunca cambia).
# Cache TTL 300s (5 min): suficientemente fresco para cambios visibles
# desde /comunicaciones y suficientemente largo para eliminar el costo.
# Llamar a _marca_cache_clear() tras editar la marca para forzar refresh.
_MARCA_CACHE = {"data": None, "ts": 0.0}
_MARCA_CACHE_TTL = 300  # 5 minutos


def _marca_cache_clear():
    """Invalida el cache de marca. Llamar tras editar comm_client_config."""
    _MARCA_CACHE["data"] = None
    _MARCA_CACHE["ts"] = 0.0


def _get_marca() -> dict:
    """Marca activa = mezcla de BD (`comm_client_config`) + env vars.
    Cacheada 5 minutos en proceso (ver _MARCA_CACHE).

    FUENTE DE VERDAD: la BD para todo lo visible al cliente final (nombre,
    logo, color, soporte). Las env vars sólo rellenan campos que no están
    en la tabla (from_email técnico, reply_to por defecto, support_url).

    Esto permite que Daniel cambie "ILUS Sport & Health" → "ILUS Fitness"
    desde /comunicaciones sin tocar código ni reiniciar. Igual con el logo
    y el color corporativo. Todas las comunicaciones (email/WhatsApp/SMS)
    invocan esta función en cada envío.

    Returns:
      dict con: name, from_name, from_email, reply_to, wa_name, logo_url,
      support_email, support_url, footer, corp_color, support_phone.
    """
    # ── Cache hit (TTL 5 min) ──
    _now = time.time()
    if _MARCA_CACHE["data"] is not None and (_now - _MARCA_CACHE["ts"]) < _MARCA_CACHE_TTL:
        return _MARCA_CACHE["data"]

    try:
        cc = _get_client_cfg() or {}
    except Exception:
        cc = {}
    try:
        be = _get_brand_cfg() or {}
    except Exception:
        be = {}

    name = (cc.get("company_name") or be.get("name") or "ILUS Fitness").strip()
    # Logo: BD primero, luego CDN ILUS Fitness oficial
    logo = (cc.get("logo_url") or "").strip()
    if not logo:
        logo = "https://ilusfitness.com/cdn/shop/files/Logo_ILUS_Fitness_Blanco_equipamiento_para_gimnasios.png"

    _result = {
        "name":          name,
        # FIX 2026-05-21 (Daniel): `name` (campo "Nombre de empresa" editable
        # en /comunicaciones) tiene prioridad sobre be.get("from_name") que
        # venía de la env var ILUS_BRAND_FROM_NAME. Daniel quiere que cuando
        # cambie el nombre de empresa desde la página, eso se refleje en TODOS
        # los emails sin tocar env vars. Igual para wa_name (WhatsApp si vuelve).
        "from_name":     (name or be.get("from_name") or "ILUS Fitness").strip(),
        "from_email":    (be.get("from_email") or "no-reply@ilusfitness.com").strip(),
        "reply_to":      (cc.get("reply_to") or be.get("reply_to") or "servicio.tecnico@ilusfitness.com").strip(),
        "wa_name":       (name or be.get("wa_name") or "ILUS Fitness").strip(),
        "logo_url":      logo,
        "support_email": (cc.get("support_email") or be.get("support_email") or "servicio.tecnico@ilusfitness.com").strip(),
        "support_url":   (be.get("support_url") or "https://ilusfitness.com/soporte").strip(),
        "footer":        f"{name} · Plataforma operacional",
        "corp_color":    (cc.get("corp_color") or "#DC143C").strip(),
        "support_phone": (cc.get("support_phone") or "").strip(),
    }
    # Guardar en cache TTL 5 min
    _MARCA_CACHE["data"] = _result
    _MARCA_CACHE["ts"]   = _now
    return _result


def _brand_subject(tema: str) -> str:
    """Subject estandarizado del email: "{marca} · {tema}".

    Marca dinámica desde `comm_client_config` (vía `_get_marca`) —
    Daniel puede cambiar el nombre de empresa en /comunicaciones
    sin tocar código.
    """
    marca = _get_marca()
    prefijo = marca["from_name"]
    tema = (tema or "").strip()
    # Evitar duplicar prefijo si quien llama ya lo agregó
    if tema.startswith(f"{prefijo} ·") or tema.startswith(f"{prefijo} -"):
        return tema
    return f"{prefijo} · {tema}" if tema else prefijo


def _brand_wa_prefix(asunto: str) -> str:
    """Prefijo WhatsApp/SMS: "🔧 {marca} · {asunto}\\n\\n"

    Marca dinámica desde `comm_client_config` (vía `_get_marca`).
    """
    marca = _get_marca()
    prefijo = marca["wa_name"]
    asunto = (asunto or "").strip()
    if asunto:
        return f"🔧 {prefijo} · {asunto}\n\n"
    return f"🔧 {prefijo}\n\n"


def _send_ilus_email_real(to_addr: str, subject: str, html_body: str) -> bool:
    """
    Implementación real con fallback configurable por env var.

    PROVIDER (env var ILUS_EMAIL_PROVIDER):
      - "smtp"   (default): Gmail SMTP primero (sale firmado como
                  daniel.aguilar@sphs.cl, no necesita DNS propio).
                  Resend queda como fallback.
      - "resend" : Resend primero (requiere DNS verificado en Resend
                  para no caer en spam). SMTP fallback.
      - "auto"   : Comportamiento legacy — intenta Resend si está
                  configurado, sino SMTP.

    Decisión 2026-05-21 (Daniel): default = "smtp" porque el DNS de
    ilusfitness.com aún no está configurado y Resend sin dominio
    propio sale como onboarding@resend.dev (cae spam). Cuando
    Joaquín configure los registros DKIM/SPF/DMARC en Resend, basta
    cambiar ILUS_EMAIL_PROVIDER=resend en Railway.

    Branding: el From siempre es genérico (BRAND_CONFIG.from_name +
    from_email). El Reply-To apunta al buzón de soporte.
    """
    marca = _get_marca()
    provider = (os.environ.get("ILUS_EMAIL_PROVIDER") or "smtp").strip().lower()
    if provider not in ("smtp", "resend", "auto"):
        provider = "smtp"

    resend_cfg = _get_resend_cfg()
    resend_disponible = bool(resend_cfg.get("api_key"))

    # ── Ramificación según provider configurado ─────────────────────────
    intentar_resend_primero = (
        (provider == "resend" and resend_disponible) or
        (provider == "auto"   and resend_disponible)
    )
    intentar_smtp_primero = (provider == "smtp")

    # ── 1. Intento Resend primero SOLO si provider lo pide ──────────────
    if intentar_resend_primero:
        # From genérico de marca — SMTP guardado sólo como fallback si el
        # dominio aún no está verificado en Resend.
        from_for_resend = None
        try:
            smtp_cfg = _get_smtp_cfg()
            brand_email = marca["from_email"] or smtp_cfg.get("from_addr") or resend_cfg.get("from_addr")
            from_name   = marca["from_name"]  or smtp_cfg.get("from_name") or "ILUS Fitness"
            if brand_email:
                from_for_resend = f"{from_name} <{brand_email}>"
        except Exception:
            pass

        if _send_via_resend(to_addr, subject, html_body,
                            from_addr=from_for_resend,
                            reply_to=marca["reply_to"]):
            return True
        # Resend falló — guardar error legible y caer a SMTP
        err = getattr(g, "_last_resend_error", None) or {}
        try:
            g._last_email_error = f"Resend: {err.get('message','fallo')} (HTTP {err.get('http_code',0)})"
        except Exception:
            pass
        print(f"[ILUS][EMAIL] Resend falló, intento SMTP como fallback…")

    # ── 2. Fallback a SMTP ──────────────────────────────────────────────
    try:
        cfg = _get_smtp_cfg()
    except Exception:
        cfg = dict(EMAIL_CONFIG)

    # Branding desde la marca (BD), SMTP credentials no se tocan
    from_name     = marca["from_name"]  or cfg.get("from_name") or "ILUS Fitness"
    from_addr_cfg = marca["from_email"] or cfg.get("from_addr") or cfg.get("smtp_user", "")
    reply_to      = marca["reply_to"]   or cfg.get("reply_to") or ""

    # ── Envío vía SMTP (único método; configurable desde el front) ──────
    msg = MIMEMultipart("alternative")
    msg["Subject"] = subject
    msg["From"]    = f"{from_name} <{from_addr_cfg}>"
    msg["To"]      = to_addr
    if reply_to:
        msg["Reply-To"] = reply_to
    msg.attach(MIMEText(html_body, "html", "utf-8"))

    host      = cfg["smtp_host"]
    port      = int(cfg.get("smtp_port", 587))
    secure    = bool(cfg.get("secure"))
    user      = cfg["smtp_user"]
    passwd    = cfg.get("smtp_pass", "")
    from_addr = from_addr_cfg or user

    def _try_send(p, sec, timeout=10):
        # Timeout reducido a 10s/intento (antes 30s). Si el endpoint
        # va a fallback Resend, el peor caso total es: SMTP attempt1
        # (10s) + SMTP attempt2 (10s) + Resend (~5s) = ~25s, no minutos.
        # Cuando Gmail rechaza credenciales el LOGIN responde en <1s, así
        # que 10s solo se gasta cuando el socket TLS pelea por handshake.
        if sec:
            with _open_smtp_client(host, p, True, timeout=timeout) as srv:
                srv.login(user, passwd)
                srv.sendmail(from_addr, [to_addr], msg.as_string())
        else:
            with _open_smtp_client(host, p, False, timeout=timeout) as srv:
                srv.ehlo()
                srv.starttls()
                srv.login(user, passwd)
                srv.sendmail(from_addr, [to_addr], msg.as_string())

    # Intentos: puerto configurado → puerto alternativo automático
    attempts = [(port, secure)]
    if port == 587 and not secure:
        attempts.append((465, True))   # fallback SSL si STARTTLS falla
    elif port == 465 and secure:
        attempts.append((587, False))  # fallback STARTTLS si SSL falla

    last_exc = None
    for p, sec in attempts:
        try:
            _try_send(p, sec)
            print(f"[ILUS][EMAIL] Enviado a {to_addr} via :{p} (source={cfg.get('_source','?')})")
            return True
        except Exception as exc:
            last_exc = exc
            print(f"[ILUS][EMAIL] Intento :{p} falló — {exc}")

    # ── 3. Si arrancamos por SMTP y falló, último intento con Resend ────
    # Solo cuando provider="smtp" (default): intentamos Resend como red
    # de respaldo. Esto cubre el caso Railway donde Gmail bloquea SMTP
    # outbound desde IPs cloud.
    if intentar_smtp_primero and resend_disponible:
        print(f"[ILUS][EMAIL] SMTP falló — último intento con Resend como respaldo")
        from_for_resend = None
        try:
            brand_email = marca["from_email"] or cfg.get("from_addr") or resend_cfg.get("from_addr")
            from_name_r = marca["from_name"]  or cfg.get("from_name") or "ILUS Fitness"
            if brand_email:
                from_for_resend = f"{from_name_r} <{brand_email}>"
        except Exception:
            pass
        if _send_via_resend(to_addr, subject, html_body,
                            from_addr=from_for_resend,
                            reply_to=marca["reply_to"]):
            print(f"[ILUS][EMAIL] Enviado a {to_addr} via Resend (fallback de SMTP)")
            return True

    try:
        g._last_email_error = str(last_exc)
    except Exception:
        pass
    print(f"[ILUS][EMAIL] Todos los intentos fallaron para {to_addr}: {last_exc}")
    return False


def _password_strength_errors(password: str) -> list[str]:
    """Politica minima para claves creadas desde enlaces publicos."""
    errors = []
    if len(password or "") < 12:
        errors.append("La contraseña debe tener al menos 12 caracteres.")
    if not re.search(r"[a-z]", password or ""):
        errors.append("Incluye al menos una letra minuscula.")
    if not re.search(r"[A-Z]", password or ""):
        errors.append("Incluye al menos una letra mayuscula.")
    if not re.search(r"\d", password or ""):
        errors.append("Incluye al menos un numero.")
    if not re.search(r"[^A-Za-z0-9]", password or ""):
        errors.append("Incluye al menos un simbolo.")
    return errors


def _issue_password_token(user_id: int, minutes: int = 60) -> tuple[str, datetime]:
    """Crea un token de un solo uso e invalida enlaces anteriores del usuario."""
    token = secrets.token_urlsafe(64)
    expires = datetime.utcnow() + timedelta(minutes=minutes)
    conn = get_db()
    with conn.cursor() as cur:
        cur.execute(
            f"UPDATE `{RESETS_TABLE}` SET used=1 WHERE user_id=%s AND used=0",
            (user_id,),
        )
        cur.execute(
            f"INSERT INTO `{RESETS_TABLE}` (user_id, token, expires_at) VALUES (%s,%s,%s)",
            (user_id, token, expires),
        )
    conn.commit()
    return token, expires


def _send_password_access_email(
    to_addr: str,
    to_name: str,
    action_url: str,
    *,
    actor_name: str = "ILUS",
    mode: str = "reset",
    minutes: int = 60,
    skip_diagnose: bool = False,
) -> bool:
    """Envía correo para crear o cambiar clave con token seguro.

    NOTA IMPORTANTE: NO se valida SMTP previamente. El flujo real
    (`_send_ilus_email_real`) intenta primero Resend (HTTPS, funciona desde
    Railway) y si falla cae a SMTP. Validar SMTP antes hacía que incluso con
    Resend configurado este email NO se enviara — el diagnose SMTP timeaba
    en Railway y Resend nunca se intentaba. El parámetro `skip_diagnose`
    se mantiene por retrocompatibilidad pero ya no controla nada.
    """
    _ = skip_diagnose  # noqa: F841 (mantener firma para callers existentes)

    is_setup     = mode == "setup"
    marca        = _get_marca()
    marca_nombre = marca["name"]
    titulo  = "Crear contraseña de acceso" if is_setup else "Cambio de contraseña solicitado"
    subject = _brand_subject(
        "Crea tu contraseña de acceso" if is_setup else "Cambio seguro de contraseña"
    )
    button = "Crear mi contraseña" if is_setup else "Restablecer contraseña"
    intro = (
        f"<strong>{actor_name}</strong> creó una cuenta para ti en el sistema {marca_nombre}."
        if is_setup
        else f"Recibimos una solicitud para cambiar la contraseña de tu cuenta {marca_nombre}."
    )
    html_body = _ilus_email_html(
        titulo=titulo,
        subtitulo="Acceso seguro con enlace de un solo uso",
        saludo=f"Hola, {to_name}",
        parrafos=[
            intro,
            "Por seguridad, la contraseña no se envía ni se escribe manualmente. "
            "Debes definirla desde el botón de este correo.",
            f"Este enlace vence en <strong>{minutes} minutos</strong>, solo puede usarse una vez "
            "y reemplaza cualquier enlace anterior.",
            f'Si no esperabas este correo, ignóralo o avísale al administrador.<br>'
            f'<span style="font-size:11px;color:#777">Enlace directo: '
            f'<a href="{action_url}" style="color:{marca["corp_color"]}">{action_url}</a></span>',
        ],
        btn_primario_txt=button,
        btn_primario_url=action_url,
        info_lineas=[
            ("", "Cuenta", to_addr),
            ("", "Solicitado por", actor_name),
        ],
    )
    sent = _send_ilus_email(to_addr, subject, html_body,
                            evento="password_access", modulo="comunicacion_interna")
    if not sent and not getattr(g, "_last_email_error", ""):
        g._last_email_error = (
            "No se pudo enviar el correo. Verifica en /comunicaciones "
            "que Resend o SMTP estén configurados correctamente."
        )
    return sent


def _portal_login_url():
    return url_for("login", _external=True)


def _send_access_notification_email(to_addr: str, to_name: str, login_url: str, *, actor_name: str = "ILUS") -> bool:
    """Notifica que el acceso al portal fue habilitado, sin compartir la clave."""
    html_body = _ilus_email_html(
        titulo="Acceso al portal ILUS habilitado",
        subtitulo="Ya puedes ingresar a la aplicacion",
        saludo=f"Hola, {to_name}",
        parrafos=[
            f"<strong>{actor_name}</strong> habilito tus credenciales de acceso al portal ILUS.",
            "Por seguridad, este correo no incluye tu contraseña. Usa la clave entregada por el administrador "
            "o solicita un cambio de contraseña desde el portal cuando el correo este disponible.",
            "Presiona el boton para ir a la aplicacion.",
        ],
        btn_primario_txt="Ingresar al portal",
        btn_primario_url=login_url,
        info_lineas=[
            ("", "Cuenta", to_addr),
            ("", "Portal", login_url),
        ],
    )
    sent = _send_ilus_email(to_addr, _brand_subject("Acceso al portal habilitado"), html_body,
                            evento="acceso_habilitado", modulo="comunicacion_interna")
    if not sent and not getattr(g, "_last_email_error", ""):
        g._last_email_error = "No se pudo enviar la notificacion de acceso por email."
    return sent


def _notify_user_access(username: str, nombre: str, phone: str = "", *,
                        mode: str = "manual", action_url: str = "",
                        email_purpose: str = "invite") -> dict:
    """
    Envia notificaciones email/WhatsApp sobre acceso o creacion/cambio de clave.

    email_purpose:
      - 'invite' (default): cuenta nueva → email "Crea tu contraseña" (mode=setup, 24h)
      - 'change': cambio solicitado por admin → email "Cambio seguro de contraseña" (mode=reset, 60min)
                  Gmail los trata como mensajes distintos (subject distinto), evita threading
                  con la invitación previa y el usuario distingue claramente cada acción.
    """
    actor = g.user["nombre"] if getattr(g, "user", None) else "ILUS"
    login_url = _portal_login_url()
    result = {"email": None, "whatsapp": None, "errors": []}

    try:
        if mode == "token" and action_url:
            if email_purpose == "change":
                # Email de cambio de contraseña — subject y CTA distintos a los de invitación
                result["email"] = _send_password_access_email(
                    username, nombre, action_url,
                    actor_name=actor, mode="reset", minutes=60
                )
            else:
                result["email"] = _send_invitation_email(username, nombre, action_url, actor)
        else:
            result["email"] = _send_access_notification_email(username, nombre, login_url, actor_name=actor)
        if not result["email"]:
            result["errors"].append(getattr(g, "_last_email_error", "") or "No se pudo enviar email.")
    except Exception as exc:
        result["email"] = False
        result["errors"].append(f"Email: {exc}")

    # WhatsApp se intenta SÓLO si el canal está activo globalmente
    # (env var COMM_CANALES_ACTIVOS). Daniel dio de baja Twilio, así
    # que por default queda en silencio. El email vía Resend ya partió
    # arriba — eso es lo importante para el flujo de acceso.
    if phone and _canal_activo("whatsapp"):
        try:
            wa_cfg = _get_wa_cfg()
            if wa_cfg.get("account_sid") and wa_cfg.get("auth_token") and wa_cfg.get("from_number"):
                marca = _get_marca()
                firma = f"\n— {marca['name']}"
                if mode == "token" and action_url and email_purpose == "change":
                    body = (
                        _brand_wa_prefix("Recupera tu contraseña")
                        + f"Hola {nombre}, recibimos una solicitud para cambiar tu contraseña.\n\n"
                          f"Define tu nueva clave aquí (válido 60 min, un solo uso):\n{action_url}\n\n"
                          f"Si no fuiste tú, ignora este mensaje."
                        + firma
                    )
                elif mode == "token" and action_url:
                    body = (
                        _brand_wa_prefix(f"Bienvenido a {marca['name']}")
                        + f"Hola {nombre}, habilitamos tu acceso al portal {marca['name']}.\n\n"
                          f"Crea tu contraseña aquí (válido 7 días):\n{action_url}\n\n"
                          f"Portal: {login_url}"
                        + firma
                    )
                else:
                    body = (
                        _brand_wa_prefix("Acceso habilitado")
                        + f"Hola {nombre}, tus credenciales del portal {marca['name']} están listas.\n\n"
                          f"Ingresa aquí: {login_url}\n"
                          f"Por seguridad, este mensaje no incluye tu contraseña."
                        + firma
                    )
                sid = _send_whatsapp(wa_cfg["account_sid"], wa_cfg["auth_token"], wa_cfg["from_number"], phone, body,
                                     modulo="comunicacion_interna")
                result["whatsapp"] = sid
            else:
                result["whatsapp"] = False
                result["errors"].append("WhatsApp no está configurado.")
        except Exception as exc:
            result["whatsapp"] = False
            result["errors"].append(f"WhatsApp: {exc}")
    elif phone:
        # Canal apagado por config (COMM_CANALES_ACTIVOS). No es un error,
        # el flujo principal va por email. Dejamos rastro discreto en log.
        result["whatsapp"] = False
        print(f"[notify_user_access] WhatsApp omitido (canal off via COMM_CANALES_ACTIVOS) phone={phone[:6]}***",
              flush=True)
    return result


def _access_notification_flash(result: dict, *, token_mode: bool = False) -> tuple[str, str]:
    """Construye un mensaje corto para el admin segun los canales que respondieron."""
    channels = []
    if result.get("email"):
        channels.append("email")
    if result.get("whatsapp"):
        channels.append("WhatsApp")
    if channels:
        action = "enlace seguro enviado" if token_mode else "notificacion de acceso enviada"
        return f"{action.capitalize()} por {', '.join(channels)}.", "success"
    errors = [str(e) for e in result.get("errors", []) if e]
    detail = " ".join(errors[:2]) or "Revisa SMTP o WhatsApp en Comunicaciones."
    return f"Usuario guardado, pero no salio la notificacion. {detail}", "warning"


