#  Recuperación de contraseña
# ─────────────────────────────────────────────

def _send_recovery_email(to_addr: str, to_name: str, reset_url: str) -> bool:
    """Olvido de contraseña — token de 60 min con flujo seguro."""
    return _send_password_access_email(
        to_addr, to_name, reset_url, actor_name="ILUS", mode="reset", minutes=60
    )


def _send_invitation_email(to_addr: str, to_name: str, set_url: str, creator_name: str = "ILUS") -> bool:
    """Alta de usuario (bienvenida) — token de 7 días."""
    return _send_password_access_email(
        to_addr, to_name, set_url, actor_name=creator_name, mode="setup", minutes=10080
    )


# ── Redirects defensivos para URLs antiguas / links rotos ──
# Si Daniel o algún usuario tiene un link viejo guardado en favoritos /
# PWA cache / email anterior con /reset-password o /forgot-password,
# lo mandamos al endpoint canónico en vez de 404.
# Reportado por Daniel 2026-05-21: el flujo "olvidaste contraseña"
# llegaba a /reset-password 404.
@app.route("/reset-password")
@app.route("/forgot-password")
@app.route("/recuperar-clave")
@app.route("/olvidaste-contrasena")
def _forgot_legacy_redirect():
    return redirect(url_for("forgot_password"), code=301)


@app.route("/auth/olvidar-contrasena", methods=["GET", "POST"])
@rate_limited("forgot", max_attempts=5, window_seconds=900)
def forgot_password():
    if g.user:
        return redirect(url_for("index"))

    if request.method == "POST":
        email_input = request.form.get("email", "").strip().lower()

        # Siempre mostrar el mismo mensaje (no revelar si el email existe)
        flash("Si el correo está registrado, recibirás instrucciones en breve.", "info")

        try:
            if EMAIL_RE.match(email_input):
                user = get_auth_user_by_username(email_input)
                if user and user.get("active"):
                    token, _expires = _issue_password_token(user["id"], minutes=60)
                    reset_url = url_for("reset_password", token=token, _external=True)

                    # Email + WhatsApp en background (no bloquea respuesta HTTP)
                    # _notify_user_access maneja ambos canales y respeta config
                    snap_user  = user["username"]
                    snap_nom   = user["nombre"]
                    snap_phone = user.get("phone") or ""
                    snap_url   = reset_url

                    def _bg_recovery():
                        try:
                            _notify_user_access(
                                snap_user, snap_nom, snap_phone,
                                mode="token",
                                action_url=snap_url,
                                email_purpose="change",
                            )
                        except Exception as _exc:
                            print(f"[ILUS][RESET][bg] fail: {_exc}", flush=True)

                    threading.Thread(target=_bg_recovery, daemon=True).start()

                    _audit("password_reset_request",
                           target_type="user", target_id=user["id"],
                           details={"username": user["username"], "channels": "email+wa_if_phone"},
                           user_override={"id": user["id"], "username": user["username"], "role": user.get("role")})
                else:
                    _audit("password_reset_request",
                           details={"email": email_input,
                                    "reason": "no_existe_o_inactivo"},
                           status="fail")
        except Exception as _e:
            print(f"[ILUS][RESET] Error en flujo de recuperación: {_e}")

        return redirect(url_for("forgot_password"))

    return render_template("forgot_password.html", marca=_get_marca())


@app.route("/auth/restablecer/<token>", methods=["GET", "POST"])
@rate_limited("reset", max_attempts=10, window_seconds=900)
def reset_password(token):
    if g.user:
        return redirect(url_for("index"))

    conn = get_db()
    row  = None
    with conn.cursor() as cur:
        cur.execute(
            f"""SELECT r.*, u.nombre, u.username
                FROM `{RESETS_TABLE}` r
                JOIN `{AUTH_TABLE}` u ON u.id = r.user_id
                WHERE r.token=%s AND r.used=0 AND r.expires_at > UTC_TIMESTAMP()""",
            (token,)
        )
        row = cur.fetchone()

    if not row:
        flash("El enlace no es válido o ha expirado.", "danger")
        return redirect(url_for("forgot_password"))

    marca = _get_marca()  # nombre/logo dinámico desde BD

    if request.method == "POST":
        pw1 = request.form.get("password", "")
        pw2 = request.form.get("password2", "")
        if pw1 != pw2:
            flash("Las contraseñas no coinciden.", "danger")
            return render_template("reset_password.html", token=token, nombre=row["nombre"], marca=marca)

        strength_errors = _password_strength_errors(pw1)
        if strength_errors:
            flash(" ".join(strength_errors), "danger")
            return render_template("reset_password.html", token=token, nombre=row["nombre"], marca=marca)

        new_hash = generate_password_hash(pw1)
        with conn.cursor() as cur:
            cur.execute(
                f"UPDATE `{AUTH_TABLE}` SET password_hash=%s WHERE id=%s",
                (new_hash, row["user_id"])
            )
            cur.execute(
                f"UPDATE `{RESETS_TABLE}` SET used=1 WHERE token=%s",
                (token,)
            )
            # Si la cuenta tenía requires_password_change=1, limpiar el flag
            try:
                cur.execute(
                    f"UPDATE `{AUTH_TABLE}` SET requires_password_change=0 WHERE id=%s",
                    (row["user_id"],)
                )
            except Exception:
                pass
        conn.commit()

        _audit("password_reset_confirm",
               target_type="user", target_id=row["user_id"],
               details={"username": row["username"]},
               user_override={"id": row["user_id"], "username": row["username"], "role": None})
        flash("Contraseña actualizada. Ahora puedes iniciar sesión.", "success")
        return redirect(url_for("login"))

    return render_template("reset_password.html", token=token, nombre=row["nombre"], marca=marca)


@app.route("/welcome/<token>", methods=["GET", "POST"])
@rate_limited("welcome", max_attempts=10, window_seconds=900)
def welcome_activate(token):
    """Activación de cuenta nueva — mismo flujo que `reset_password` pero
    con copy distinto orientado a bienvenida. Usa la misma tabla de tokens
    (`app_password_resets`) y la misma validación de expiración/uso único.

    El admin crea un usuario en /admin/users y NO recibe ni asigna la clave;
    el usuario nuevo recibe email + WhatsApp con link `/welcome/<token>` y
    define su propia contraseña aquí.
    """
    if g.user:
        return redirect(url_for("index"))

    conn = get_db()
    row  = None
    with conn.cursor() as cur:
        cur.execute(
            f"""SELECT r.*, u.nombre, u.username
                FROM `{RESETS_TABLE}` r
                JOIN `{AUTH_TABLE}` u ON u.id = r.user_id
                WHERE r.token=%s AND r.used=0 AND r.expires_at > UTC_TIMESTAMP()""",
            (token,)
        )
        row = cur.fetchone()

    if not row:
        flash("El enlace de activación no es válido o ya expiró. "
              "Pídele al administrador que te reenvíe la invitación.", "danger")
        return redirect(url_for("login"))

    marca = _get_marca()

    if request.method == "POST":
        pw1 = request.form.get("password", "")
        pw2 = request.form.get("password2", "")
        if pw1 != pw2:
            flash("Las contraseñas no coinciden.", "danger")
            return render_template("welcome.html", token=token, nombre=row["nombre"], marca=marca)

        strength_errors = _password_strength_errors(pw1)
        if strength_errors:
            flash(" ".join(strength_errors), "danger")
            return render_template("welcome.html", token=token, nombre=row["nombre"], marca=marca)

        new_hash = generate_password_hash(pw1)
        with conn.cursor() as cur:
            cur.execute(
                f"UPDATE `{AUTH_TABLE}` SET password_hash=%s WHERE id=%s",
                (new_hash, row["user_id"])
            )
            cur.execute(
                f"UPDATE `{RESETS_TABLE}` SET used=1 WHERE token=%s",
                (token,)
            )
            # Limpiar flag requires_password_change si existe (columna opcional)
            try:
                cur.execute(
                    f"UPDATE `{AUTH_TABLE}` SET requires_password_change=0 WHERE id=%s",
                    (row["user_id"],)
                )
            except Exception:
                pass  # columna no existe en este deploy — OK
        conn.commit()

        _audit("user_welcome_activate",
               target_type="user", target_id=row["user_id"],
               details={"username": row["username"]},
               user_override={"id": row["user_id"], "username": row["username"], "role": None})
        flash(f"¡Cuenta activada! Bienvenido, {row['nombre']}. Ya puedes iniciar sesión.", "success")
        return redirect(url_for("login"))

    return render_template("welcome.html", token=token, nombre=row["nombre"], marca=marca)


# ── PERFIL DE USUARIO (autogestión) ─────────────────────────────────────
# Cualquier usuario logueado puede editar SU PROPIO perfil. No es admin.
# Seguridad: el id se toma de g.user (sesión), nunca del request.

def _normalize_phone_chile(raw: str) -> str:
    """Normaliza teléfono Chile: deja solo dígitos y +; máximo 16 chars."""
    if not raw:
        return ""
    cleaned = re.sub(r"[^\d+]", "", raw.strip())
    return cleaned[:16]


@app.route("/mi-cuenta")
@login_required
def mi_cuenta():
    """Página de perfil — accesible para cualquier usuario logueado."""
    u = mysql_fetchone(
        f"SELECT id,username,nombre,phone,role,active,created_at,"
        f"foto_url,rut,cargo,genero,direccion,comuna,ciudad,fecha_nac "
        f"FROM `{AUTH_TABLE}` WHERE id=%s",
        (g.user["id"],)
    )
    if not u:
        return redirect(url_for("logout"))
    return render_template("mi_cuenta.html", usuario=dict(u))


@app.route("/mi-cuenta/datos", methods=["POST"])
@login_required
def mi_cuenta_datos():
    """
    Actualiza datos del perfil del usuario actual.
    Campos editables: nombre, phone, rut, cargo, genero, direccion, comuna, ciudad, fecha_nac.
    NO editables: username, role (eso es identidad/seguridad).
    """
    d = request.get_json(silent=True) or {}
    nombre = (d.get("nombre") or "").strip()[:190]
    phone  = _normalize_phone_chile(d.get("phone") or "")
    if len(nombre) < 2:
        return jsonify({"error": "El nombre debe tener al menos 2 caracteres"}), 400
    if phone and not re.match(r"^\+?\d{8,16}$", phone):
        return jsonify({"error": "Teléfono inválido. Usa formato +56912345678"}), 400

    rut       = (d.get("rut") or "").strip()[:20] or None
    cargo     = (d.get("cargo") or "").strip()[:120] or None
    genero    = (d.get("genero") or "").strip()[:20] or None
    direccion = (d.get("direccion") or "").strip()[:300] or None
    comuna    = (d.get("comuna") or "").strip()[:100] or None
    ciudad    = (d.get("ciudad") or "").strip()[:100] or None
    fecha_nac = (d.get("fecha_nac") or "").strip() or None
    if genero and genero not in ("masculino","femenino","otro","prefiero_no_decir"):
        genero = None

    conn = get_db()
    try:
        with conn.cursor() as cur:
            cur.execute(
                f"UPDATE `{AUTH_TABLE}` SET nombre=%s, phone=%s, rut=%s, cargo=%s, "
                f"genero=%s, direccion=%s, comuna=%s, ciudad=%s, fecha_nac=%s WHERE id=%s",
                (nombre, phone or None, rut, cargo, genero, direccion, comuna, ciudad,
                 fecha_nac, g.user["id"])
            )
        conn.commit()
        return jsonify({"ok": True, "nombre": nombre})
    except Exception as e:
        return jsonify({"error": f"No se pudo guardar: {e}"}), 500


@app.route("/mi-cuenta/foto", methods=["POST"])
@login_required
def mi_cuenta_foto():
    """
    Sube la foto de perfil del usuario a Cloudinary y guarda la URL en BD.
    Acepta multipart/form-data con campo 'foto' (jpg/png/webp, máx 5MB).
    """
    f = request.files.get("foto")
    if not f or not f.filename:
        return jsonify({"error": "No se recibió archivo"}), 400
    ext = (f.filename.rsplit(".", 1)[-1] or "").lower()
    if ext not in {"jpg","jpeg","png","webp","gif"}:
        return jsonify({"error": "Formato no permitido. Usa JPG, PNG o WEBP"}), 400
    # Tamaño máximo 5MB
    f.stream.seek(0, 2)
    size = f.stream.tell()
    f.stream.seek(0)
    if size > 5 * 1024 * 1024:
        return jsonify({"error": "Archivo demasiado grande (máx 5MB)"}), 400

    try:
        import cloudinary, cloudinary.uploader
        # Subir a Cloudinary en folder específico de avatares
        result = cloudinary.uploader.upload(
            f,
            folder=f"ilus/avatars",
            public_id=f"user_{g.user['id']}",
            overwrite=True,
            resource_type="image",
            transformation=[
                {"width": 400, "height": 400, "crop": "fill", "gravity": "face"},
                {"quality": "auto", "fetch_format": "auto"},
            ],
        )
        url = result.get("secure_url")
        if not url:
            return jsonify({"error": "Error al subir a Cloudinary"}), 500

        conn = get_db()
        try:
            with conn.cursor() as cur:
                cur.execute(
                    f"UPDATE `{AUTH_TABLE}` SET foto_url=%s WHERE id=%s",
                    (url, g.user["id"])
                )
            conn.commit()
        finally:
            conn.close()

        return jsonify({"ok": True, "url": url})
    except Exception as e:
        return jsonify({"error": f"Error al procesar imagen: {e}"}), 500


