@app.route("/products/new", methods=["GET", "POST"])
@require_permission("create")
def new_product():
    # Pre-calcular el código que se asignará (para mostrarlo en el form)
    auto_codigo = next_codigo()

    if request.method == "POST":
        sku    = request.form.get("sku",    "").strip().upper()
        nombre = request.form.get("nombre", "").strip()
        estado = request.form.get("estado", "Confirmado").strip()
        # El código NO viene del formulario: se genera server-side
        codigo = next_codigo()

        errors = []
        if not sku:
            errors.append("El SKU es requerido.")
        if not nombre:
            errors.append("El nombre es requerido.")
        if mysql_fetchone(f"SELECT id FROM `{PRODUCTS_TABLE}` WHERE sku=%s", (sku,)):
            errors.append(f"El SKU <b>{sku}</b> ya existe.")
        # ── SEGURIDAD 2026-05-26 (Daniel): solo se aceptan SKUs que existan
        # en el ERP. Bloqueo server-side para que no se puedan inventar
        # productos enviando POST con curl/cualquier herramienta. Esto va
        # en CASCADA con el bloqueo de UI (input SKU readonly + selección
        # solo desde el typeahead del ERP).
        if sku and not errors:
            try:
                erp_match = get_erp_product_by_sku(sku)
            except Exception as _e_erp:
                erp_match = None
                print(f"[new_product] error consultando ERP: {_e_erp}", flush=True)
            if not erp_match:
                errors.append(
                    f"El SKU <b>{sku}</b> no existe en el ERP. "
                    f"Solo se pueden crear productos asociados al ERP. "
                    f"Usa el buscador de arriba para seleccionar uno válido."
                )
        errors += validate_bultos_form(request.form)

        if errors:
            return render_template("product_form.html", errors=errors, product=None,
                                   fd=request.form, max_b=MAX_BULTOS, auto_codigo=codigo)

        conn = get_db()
        with conn.cursor() as cur:
            cur.execute(
                f"""INSERT INTO `{PRODUCTS_TABLE}` (sku,nombre,estado,codigo,created_by,updated_by)
                    VALUES (%s,%s,%s,%s,%s,%s)""",
                (sku, nombre, estado, codigo, current_username(), current_username()),
            )
            pid = cur.lastrowid
            save_bultos_mysql(conn, pid, request.form)
        conn.commit()

        # Sincronizar tabla compartida etiquetas
        _, bultos_sync, _ = get_full(pid)
        p_sync = {"sku": sku, "nombre": nombre, "estado": estado, "codigo": codigo}
        sync_erp_table(p_sync, bultos_sync, conn)
        conn.commit()

        _invalidate_listing_cache()
        flash(f"Producto {sku} creado con código {codigo}.", "success")
        return redirect(url_for("product_detail", pid=pid))

    return render_template("product_form.html", errors=[], product=None, fd={},
                           max_b=MAX_BULTOS, auto_codigo=auto_codigo)


@app.route("/products/edit-by-sku/<path:sku>")
@require_permission("edit")
def edit_product_by_sku(sku):
    """Redirige a /products/<id>/edit dado un SKU.
    Útil para enlaces inline desde la carga masiva o desde otros módulos."""
    sku_clean = (sku or "").strip().upper()
    row = mysql_fetchone(
        f"SELECT id FROM `{PRODUCTS_TABLE}` WHERE UPPER(TRIM(sku))=%s LIMIT 1",
        (sku_clean,)
    )
    if not row:
        flash(f"No existe ningún producto con SKU '{sku}'. Créalo primero.", "warning")
        return redirect(url_for("new_product") + f"?sku={sku_clean}")
    return redirect(url_for("edit_product", pid=row["id"]))


@app.route("/etiquetas/api/importar-desde-erp", methods=["POST"])
@require_permission("create")
def etiquetas_importar_desde_erp():
    """Importa masivamente productos desde un documento del ERP.

    Crea entradas en mant_productos con SKU + nombre del ERP, SIN bultos
    (el usuario debe agregar medidas después en la ficha del producto).

    Body JSON:
      skus: [str]  — lista de SKUs a importar
      lineas_erp: [{sku, descripcion_erp, ...}]  — datos del ERP para enriquecer
    """
    d = request.get_json(silent=True) or {}
    skus = d.get("skus") or []
    lineas_erp = d.get("lineas_erp") or []

    if not skus:
        return jsonify({"ok": False, "error": "Sin SKUs para importar"}), 400

    # Mapa SKU → descripción desde lineas_erp
    desc_map = {}
    for l in lineas_erp:
        s = (l.get("sku") or "").strip().upper()
        if s:
            desc_map[s] = (l.get("descripcion_erp") or l.get("nombre_app") or l.get("nombre") or "").strip()

    # ── FALLBACK: SKUs sin descripción → consultar catálogo ERP en paralelo ──
    skus_sin_desc = []
    for s in skus:
        su = (s or "").strip().upper()
        if su and not su.startswith("ZZ") and not desc_map.get(su):
            skus_sin_desc.append(su)

    if skus_sin_desc:
        TOKEN_I = ERP_CONFIG.get("api_token", "")
        def _lookup_erp(sku_q):
            try:
                body = _erp_get(
                    "/productos",
                    {"search": sku_q, "empresa": "01", "fields": "KOPR,NOKOPR", "visible": "true", "limit": "5"},
                    TOKEN_I, timeout=6
                )
                items = body.get("data") or []
                for it in items:
                    if (it.get("KOPR") or "").strip().upper() == sku_q:
                        return (sku_q, (it.get("NOKOPR") or "").strip())
                if items:
                    return (sku_q, (items[0].get("NOKOPR") or "").strip())
            except Exception: pass
            return (sku_q, "")
        try:
            from concurrent.futures import ThreadPoolExecutor, as_completed, TimeoutError as _FutTimeout
            with ThreadPoolExecutor(max_workers=4) as pool:
                futures = {pool.submit(_lookup_erp, s): s for s in skus_sin_desc[:30]}
                try:
                    for fut in as_completed(futures, timeout=12):
                        try:
                            sku_r, nombre_r = fut.result(timeout=2)
                            if nombre_r and not desc_map.get(sku_r):
                                desc_map[sku_r] = nombre_r
                        except Exception: pass
                except _FutTimeout:
                    pending = sum(1 for f in futures if not f.done())
                    print(f"[importar-erp] timeout 12s con {pending} SKUs pendientes; se usará 'Producto {{sku}}' como fallback")
        except Exception as _e:
            print(f"[importar-erp] enriquecer descripciones falló: {_e}")

    user = current_username() or "sistema"
    creados, existentes, errores = 0, 0, 0
    detalles = []

    conn = get_db()
    try:
        with conn.cursor() as cur:
            for sku_raw in skus:
                sku = (sku_raw or "").strip().upper()
                if not sku:
                    errores += 1; continue
                # Skip ZZ (no es producto físico)
                if sku.startswith("ZZ"):
                    detalles.append({"sku": sku, "estado": "SKIP_ZZ"})
                    continue
                # ¿Ya existe?
                exist = mysql_fetchone(
                    f"SELECT id FROM `{PRODUCTS_TABLE}` WHERE UPPER(sku)=%s LIMIT 1", (sku,)
                )
                if exist:
                    existentes += 1
                    detalles.append({"sku": sku, "estado": "YA_EXISTE", "id": exist["id"]})
                    continue
                # Crear con nombre del ERP
                nombre = desc_map.get(sku) or f"Producto {sku}"
                nombre = nombre[:300]   # límite columna
                try:
                    codigo = next_codigo()
                    cur.execute(
                        f"""INSERT INTO `{PRODUCTS_TABLE}` (sku,nombre,estado,codigo,created_by,updated_by)
                            VALUES (%s,%s,'Pendiente',%s,%s,%s)""",
                        (sku, nombre, codigo, user, user)
                    )
                    pid = cur.lastrowid
                    creados += 1
                    detalles.append({"sku": sku, "estado": "CREADO", "id": pid, "codigo": codigo, "nombre": nombre})
                except Exception as e:
                    errores += 1
                    detalles.append({"sku": sku, "estado": "ERROR", "msg": str(e)[:200]})
        conn.commit()
        try: _invalidate_listing_cache()
        except Exception: pass
    except Exception as e:
        return jsonify({"ok": False, "error": f"Error al importar: {e}"}), 500

    return jsonify({
        "ok":         True,
        "creados":    creados,
        "existentes": existentes,
        "errores":    errores,
        "total":      len(skus),
        "detalles":   detalles,
        "mensaje":    (f"{creados} producto(s) importado(s), {existentes} ya existían, "
                       f"{errores} con errores. Agrégales medidas para que tengan cubicaje."),
    })


@app.route("/products/<int:pid>/edit", methods=["GET", "POST"])
@require_permission("edit")
def edit_product(pid):
    product, bultos, photos = get_full(pid)
    if not product:
        flash("Producto no encontrado.", "danger")
        return redirect(url_for("index"))

    if request.method == "POST":
        sku    = request.form.get("sku",    "").strip().upper()
        nombre = request.form.get("nombre", "").strip()
        estado = request.form.get("estado", "Pendiente").strip()
        # El código NO se puede cambiar: siempre se conserva el valor actual
        codigo = product["codigo"]

        errors = []
        if not sku:
            errors.append("El SKU es requerido.")
        if not nombre:
            errors.append("El nombre es requerido.")
        if mysql_fetchone(f"SELECT id FROM `{PRODUCTS_TABLE}` WHERE sku=%s AND id<>%s", (sku, pid)):
            errors.append(f"El SKU <b>{sku}</b> ya está en uso.")
        errors += validate_bultos_form(request.form)

        if errors:
            return render_template("product_form.html", errors=errors, product=product,
                                   bultos=bultos, fd=request.form, max_b=MAX_BULTOS, photos=photos)

        conn = get_db()
        with conn.cursor() as cur:
            cur.execute(
                f"""UPDATE `{PRODUCTS_TABLE}`
                    SET sku=%s, nombre=%s, estado=%s, updated_by=%s
                    WHERE id=%s""",
                (sku, nombre, estado, current_username(), pid),
            )
            cur.execute(f"DELETE FROM `{BULTOS_TABLE}` WHERE product_id=%s", (pid,))
            save_bultos_mysql(conn, pid, request.form)
        conn.commit()

        # Sincronizar tabla compartida etiquetas
        _, bultos_sync, _ = get_full(pid)
        p_sync = {"sku": sku, "nombre": nombre, "estado": estado, "codigo": codigo}
        sync_erp_table(p_sync, bultos_sync, conn)
        conn.commit()

        _invalidate_listing_cache()
        flash(f"Producto {sku} actualizado.", "success")
        return redirect(url_for("product_detail", pid=pid))

    return render_template("product_form.html", errors=[], product=product,
                           bultos=bultos, photos=photos, fd={}, max_b=MAX_BULTOS)


