@app.route("/etiquetas/masivo/plantilla.xlsx")
@require_permission("print")
def etiquetas_masivo_plantilla():
    """Descarga la plantilla Excel de ejemplo para carga masiva."""
    try:
        from openpyxl import Workbook
        from openpyxl.styles import Font, PatternFill, Alignment
    except ImportError:
        return "openpyxl no instalado", 500

    wb = Workbook()
    ws = wb.active
    ws.title = "Etiquetas"

    # Headers
    headers = ["SKU", "DESCRIPCION (opcional)", "CANTIDAD (opcional, default 1)"]
    for i, h in enumerate(headers, 1):
        c = ws.cell(row=1, column=i, value=h)
        c.font = Font(bold=True, color="FFFFFF")
        c.fill = PatternFill("solid", fgColor="DC2626")
        c.alignment = Alignment(horizontal="center", vertical="center")

    # Ejemplos
    ejemplos = [
        ("1118100137", "Set Discos Training Bumpers ILUS 5 a 25 kg", 1),
        ("1129100748", "Banco Romano Ajustable ILUS Kairos", 2),
        ("1124100764", "V2 Squat Rack Integration", 1),
    ]
    for r, (sku, desc, qty) in enumerate(ejemplos, 2):
        ws.cell(row=r, column=1, value=sku)
        ws.cell(row=r, column=2, value=desc)
        ws.cell(row=r, column=3, value=qty)

    # Ancho de columnas
    ws.column_dimensions["A"].width = 18
    ws.column_dimensions["B"].width = 50
    ws.column_dimensions["C"].width = 14

    # Hoja de instrucciones
    ws2 = wb.create_sheet("Instrucciones")
    instrucciones = [
        "CARGA MASIVA DE ETIQUETAS — ILUS",
        "",
        "Cómo usar esta plantilla:",
        "",
        "1. Llena la hoja 'Etiquetas' con tus SKUs.",
        "2. La columna SKU es OBLIGATORIA — debe coincidir con un producto registrado.",
        "3. DESCRIPCION es opcional (solo informativa, no se usa para generar la etiqueta).",
        "4. CANTIDAD es opcional, default = 1 etiqueta por SKU.",
        "5. Borra las filas de ejemplo antes de subir.",
        "6. Guarda el archivo y súbelo en la página 'Carga masiva'.",
        "",
        "El sistema te devolverá un informe por cada SKU:",
        "  ✅ OK            → etiqueta generada correctamente",
        "  ⚠ SIN_BULTO     → producto existe pero no tiene medidas (largo/ancho/alto)",
        "  ❌ NO_ENCONTRADO → el SKU no existe en el catálogo",
        "  ❌ ERROR          → otro problema (se muestra el detalle)",
        "",
        "Al final puedes descargar un ZIP con todas las etiquetas (PDF).",
    ]
    for i, txt in enumerate(instrucciones, 1):
        c = ws2.cell(row=i, column=1, value=txt)
        if i == 1:
            c.font = Font(bold=True, size=14, color="DC2626")
    ws2.column_dimensions["A"].width = 80

    # Guardar a bytes
    import io
    buf = io.BytesIO()
    wb.save(buf)
    buf.seek(0)
    return Response(
        buf.getvalue(),
        mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        headers={"Content-Disposition": 'attachment; filename="plantilla_etiquetas_masivo.xlsx"'},
    )


@app.route("/etiquetas/masivo/preview", methods=["POST"])
@require_permission("print")
def etiquetas_masivo_preview():
    """Analiza un Excel SIN generar PDFs y clasifica los SKUs en 3 grupos:

      imprimibles:        SKUs con producto + bultos válidos → listas para imprimir
      faltan_medidas:     SKUs con producto en BD pero sin medidas en bultos
      faltan_productos:   SKUs que NO existen en el catálogo local

    El frontend usa esto para mostrar 2 tablas:
      - "Listas para imprimir" (con checkbox + botón "Imprimir seleccionadas")
      - "Faltan datos" (con acciones: Importar ERP / Agregar medidas / Registrar)

    Es MÁS RÁPIDO que /procesar porque NO invoca Playwright. Devuelve en <1s
    aún con 50 SKUs. Después el usuario completa los faltantes y dispara
    /procesar con la lista final.
    """
    try:
        f = request.files.get("archivo")
        if not f or not f.filename:
            return jsonify({"ok": False, "error": "No se envió archivo"}), 400
        ext = f.filename.rsplit(".", 1)[-1].lower()
        if ext not in ("xlsx", "xls"):
            return jsonify({"ok": False, "error": "Formato no permitido. Usa .xlsx"}), 400

        from openpyxl import load_workbook
        try:
            wb = load_workbook(f, data_only=True)
            ws = wb.active
        except Exception as e:
            return jsonify({"ok": False, "error": f"No se pudo leer el Excel: {e}"}), 400

        # Parsear filas
        items = []
        for row_idx, row in enumerate(ws.iter_rows(min_row=2, values_only=True), start=2):
            if not row or all(c is None for c in row[:3]):
                continue
            sku = (str(row[0]).strip() if row[0] is not None else "").upper()
            if not sku:
                continue
            desc = str(row[1]).strip() if len(row) > 1 and row[1] else ""
            try:
                qty = int(row[2]) if len(row) > 2 and row[2] else 1
                if qty < 1: qty = 1
                if qty > 50: qty = 50
            except Exception:
                qty = 1
            items.append({"row": row_idx, "sku": sku, "descripcion": desc, "cantidad": qty})

        if not items:
            return jsonify({"ok": False, "error": "El Excel está vacío o no tiene SKUs válidos en la columna A"}), 400

        # Clasificar en 3 grupos sin generar PDFs (rápido)
        imprimibles = []
        faltan_medidas = []
        faltan_productos = []

        skus_unicos = list({it["sku"] for it in items})
        # Batch lookup en una sola query
        if skus_unicos:
            ph = ",".join(["%s"] * len(skus_unicos))
            rows_db = mysql_fetchall(
                f"SELECT id, sku, nombre FROM `{PRODUCTS_TABLE}` "
                f"WHERE UPPER(TRIM(sku)) IN ({ph})",
                tuple(skus_unicos)
            ) or []
            db_by_sku = {(r["sku"] or "").upper().strip(): r for r in rows_db}
        else:
            db_by_sku = {}

        for it in items:
            sku = it["sku"]
            prod = db_by_sku.get(sku)
            if not prod:
                faltan_productos.append({**it, "motivo": "NO_EN_CATALOGO"})
                continue
            # Verificar bultos con medidas
            try:
                _p, bultos, _ = get_full(prod["id"])
                valid = [b for b in (bultos or [])
                         if float(b.get("largo") or 0) > 0
                         and float(b.get("ancho") or 0) > 0
                         and float(b.get("alto")  or 0) > 0]
                if not valid:
                    faltan_medidas.append({
                        **it,
                        "product_id": prod["id"],
                        "nombre_db": prod.get("nombre") or "",
                        "n_bultos": len(bultos or []),
                        "motivo": "SIN_MEDIDAS",
                    })
                else:
                    imprimibles.append({
                        **it,
                        "product_id": prod["id"],
                        "nombre_db": prod.get("nombre") or "",
                        "n_bultos_validos": len(valid),
                        "n_etiquetas_estimadas": len(valid) * it["cantidad"],
                    })
            except Exception as e_p:
                faltan_medidas.append({
                    **it,
                    "product_id": prod["id"],
                    "nombre_db": prod.get("nombre") or "",
                    "motivo": f"ERROR_LECTURA: {type(e_p).__name__}",
                })

        return jsonify({
            "ok": True,
            "total":            len(items),
            "imprimibles":      imprimibles,
            "faltan_medidas":   faltan_medidas,
            "faltan_productos": faltan_productos,
            "resumen": {
                "ok":               len(imprimibles),
                "sin_medidas":      len(faltan_medidas),
                "sin_producto":     len(faltan_productos),
                "etiquetas_total":  sum(i["n_etiquetas_estimadas"] for i in imprimibles),
            },
        })
    except Exception as e_global:
        import traceback as _tb
        tb_short = _tb.format_exc()[:600]
        print(f"[etiquetas_masivo_preview] ERROR: {e_global}\n{tb_short}", flush=True)
        return jsonify({
            "ok": False,
            "error": f"Error analizando Excel: {type(e_global).__name__}: {str(e_global)[:200]}",
            "detalle": tb_short,
        }), 500


@app.route("/etiquetas/masivo/procesar", methods=["POST"])
@require_permission("print")
def etiquetas_masivo_procesar():
    """Procesa el Excel subido y devuelve informe + batch_id para descargar ZIP.

    WRAP GLOBAL try/except — antes el endpoint podía caer en 500 con HTML
    cuando había timeout de Playwright o pool MySQL caduco. El frontend
    hacía r.json() que fallaba y mostraba "error sin mensaje". Ahora SIEMPRE
    devuelve JSON con detalle del error.
    """
    try:
        return _etiquetas_masivo_procesar_impl()
    except Exception as e_global:
        import traceback as _tb
        tb_short = _tb.format_exc()[:600]
        print(f"[etiquetas_masivo] ERROR GLOBAL: {e_global}\n{tb_short}", flush=True)
        return jsonify({
            "ok": False,
            "error": f"Error procesando el Excel: {type(e_global).__name__}: {str(e_global)[:200]}",
            "detalle": tb_short,
            "sugerencia": "Verifica que el Excel tenga columnas SKU/Descripción/Cantidad. Si el problema persiste, revisa el log Railway."
        }), 500


def _etiquetas_masivo_procesar_impl():
    """Implementación real; envuelta en try/except global por el endpoint."""
    _etq_batch_cleanup()

    f = request.files.get("archivo")
    if not f or not f.filename:
        return jsonify({"ok": False, "error": "No se envió archivo"}), 400
    ext = f.filename.rsplit(".", 1)[-1].lower()
    if ext not in ("xlsx", "xls"):
        return jsonify({"ok": False, "error": "Formato no permitido. Usa .xlsx"}), 400

    # Parsear Excel
    try:
        from openpyxl import load_workbook
        wb = load_workbook(f, data_only=True)
        ws = wb.active
    except Exception as e:
        return jsonify({"ok": False, "error": f"No se pudo leer el Excel: {e}"}), 400

    items = []
    for row_idx, row in enumerate(ws.iter_rows(min_row=2, values_only=True), start=2):
        if not row or all(c is None for c in row[:3]):
            continue
        sku = (str(row[0]).strip() if row[0] is not None else "").upper()
        if not sku:
            continue
        desc = str(row[1]).strip() if len(row) > 1 and row[1] else ""
        try:
            qty = int(row[2]) if len(row) > 2 and row[2] else 1
            if qty < 1: qty = 1
            if qty > 50: qty = 50
        except Exception:
            qty = 1
        items.append({"row": row_idx, "sku": sku, "descripcion": desc, "cantidad": qty})

    if not items:
        return jsonify({"ok": False, "error": "El Excel está vacío o no tiene SKUs válidos en la columna A"}), 400

    # Filtro opcional: si el frontend pasa skus_filtro (después de preview),
    # solo procesamos esos SKUs y descartamos el resto del Excel.
    skus_filtro_raw = (request.form.get("skus_filtro") or "").strip()
    if skus_filtro_raw:
        try:
            skus_permitidos = set(s.strip().upper() for s in json.loads(skus_filtro_raw) if s)
            if skus_permitidos:
                items = [it for it in items if it["sku"] in skus_permitidos]
        except Exception as e_fil:
            print(f"[etiquetas_masivo] skus_filtro inválido: {e_fil}", flush=True)

    # Procesar cada SKU (default 100x150 — único tamaño físico estándar ILUS)
    fmt = request.form.get("fmt", "100x150")
    user = current_username() or "anon"
    batch_id = f"etq_{int(time.time())}_{user[:8]}"
    resultados = []
    pdfs = {}
    ok_count = 0
    err_count = 0

    for it in items:
        sku = it["sku"]
        try:
            # Buscar producto por SKU
            prod = mysql_fetchone(
                f"SELECT id FROM `{PRODUCTS_TABLE}` WHERE UPPER(sku)=%s LIMIT 1",
                (sku,)
            )
            if not prod:
                resultados.append({**it, "estado": "NO_ENCONTRADO",
                                   "mensaje": f"SKU {sku} no existe en el catálogo"})
                err_count += 1
                continue

            product, bultos, _ = get_full(prod["id"])
            if not product:
                resultados.append({**it, "estado": "NO_ENCONTRADO",
                                   "mensaje": f"Producto #{prod['id']} no se pudo cargar"})
                err_count += 1
                continue

            # Filtrar bultos con medidas
            valid = []
            for b in bultos:
                try:
                    if float(b["largo"]) > 0 and float(b["ancho"]) > 0 and float(b["alto"]) > 0:
                        valid.append(b)
                except Exception:
                    pass
            if not valid:
                resultados.append({**it, "estado": "SIN_BULTO",
                                   "mensaje": f"Producto sin bultos con medidas (largo/ancho/alto)"})
                err_count += 1
                continue

            # Generar el PDF con N copias por bulto = cantidad solicitada
            label_bultos = []
            for b in valid:
                for _ in range(it["cantidad"]):
                    label_bultos.append(dict(b))

            pdf_bytes = build_labels_pdf(product, label_bultos, len(bultos), fmt)
            pdfs[sku] = pdf_bytes
            resultados.append({**it, "estado": "OK",
                               "mensaje": f"{len(label_bultos)} etiqueta(s) generada(s)",
                               "n_etiquetas": len(label_bultos),
                               "nombre_producto": product.get("nombre") or product.get("sku")})
            ok_count += 1
        except Exception as e:
            resultados.append({**it, "estado": "ERROR",
                               "mensaje": f"{type(e).__name__}: {str(e)[:200]}"})
            err_count += 1

    # Guardar batch en cache para descarga posterior
    _ETQ_BATCHES[batch_id] = {
        "items": resultados,
        "pdfs": pdfs,
        "ts": time.time(),
        "user": user,
    }

    return jsonify({
        "ok": True,
        "batch_id": batch_id,
        "total":   len(items),
        "ok":      ok_count,
        "errores": err_count,
        "resultados": resultados,
        "n_pdfs": len(pdfs),
    })


@app.route("/etiquetas/masivo/<batch_id>/zip")
@require_permission("print")
def etiquetas_masivo_zip(batch_id):
    """Descarga un ZIP con todos los PDFs generados en el batch."""
    batch = _ETQ_BATCHES.get(batch_id)
    if not batch:
        return ("Batch no encontrado o expirado (TTL 1h). "
                "Vuelve a subir el Excel."), 404

    import io, zipfile
    buf = io.BytesIO()
    with zipfile.ZipFile(buf, "w", zipfile.ZIP_DEFLATED) as zf:
        # Reporte CSV
        csv_lines = ["SKU,DESCRIPCION,CANTIDAD,ESTADO,MENSAJE"]
        for it in batch["items"]:
            csv_lines.append(",".join([
                f'"{it.get("sku","")}"',
                f'"{(it.get("descripcion") or "").replace(chr(34),chr(39))}"',
                str(it.get("cantidad", 1)),
                it.get("estado", ""),
                f'"{(it.get("mensaje") or "").replace(chr(34),chr(39))}"',
            ]))
        zf.writestr("_REPORTE.csv", "\n".join(csv_lines).encode("utf-8"))

        # PDFs
        for sku, pdf_bytes in batch["pdfs"].items():
            zf.writestr(f"{sku}.pdf", pdf_bytes)

    buf.seek(0)
    fecha = datetime.now().strftime("%Y%m%d_%H%M")
    return Response(
        buf.getvalue(),
        mimetype="application/zip",
        headers={"Content-Disposition": f'attachment; filename="ETIQUETAS_MASIVO_{fecha}.zip"'},
    )


# ─────────────────────────────────────────────
#  Exportar Excel
# ─────────────────────────────────────────────

@app.route("/products/export/excel")
@login_required
def export_excel():
    try:
        import openpyxl
        from openpyxl.styles import Font, PatternFill, Alignment, Border, Side
    except ImportError:
        flash("Instala openpyxl: pip install openpyxl", "danger")
        return redirect(url_for("index"))

    # ── Datos ───────────────────────────────────────────────────────────
    products = mysql_fetchall(
        f"""SELECT p.id, p.sku, p.nombre, p.estado, p.codigo,
                   p.created_by, p.updated_by, p.created_at, p.updated_at
            FROM `{PRODUCTS_TABLE}` p ORDER BY p.sku"""
    )
    bultos = mysql_fetchall(
        f"""SELECT b.product_id, b.bulto_num, b.largo, b.ancho, b.alto, b.peso,
                   ROUND((b.largo*b.ancho*b.alto)/4000, 2) AS peso_vol
            FROM `{BULTOS_TABLE}` b ORDER BY b.product_id, b.bulto_num"""
    )
    # índice de bultos por product_id
    bultos_by_pid = {}
    for b in bultos:
        bultos_by_pid.setdefault(int(b["product_id"]), []).append(b)

    wb = openpyxl.Workbook()

    # ── Estilos ─────────────────────────────────────────────────────────
    RED     = "CC0000"
    BLACK   = "111111"
    WHITE   = "FFFFFF"
    LGRAY   = "F5F5F5"
    hdr_font  = Font(name="Calibri", bold=True, color=WHITE, size=11)
    hdr_fill  = PatternFill("solid", fgColor=BLACK)
    red_fill  = PatternFill("solid", fgColor=RED)
    alt_fill  = PatternFill("solid", fgColor=LGRAY)
    center    = Alignment(horizontal="center", vertical="center")
    left      = Alignment(horizontal="left",   vertical="center", wrap_text=True)
    thin      = Side(style="thin", color="DDDDDD")
    border    = Border(left=thin, right=thin, top=thin, bottom=thin)

    def style_hdr(cell, red=False):
        cell.font      = hdr_font
        cell.fill      = red_fill if red else hdr_fill
        cell.alignment = center
        cell.border    = border

    def style_cell(cell, align=None, bold=False, color=None):
        cell.font      = Font(name="Calibri", bold=bold, color=color or "000000", size=10)
        cell.alignment = align or left
        cell.border    = border

    # ══════════════════════════════════════════
    #  Hoja 1 — Resumen productos
    # ══════════════════════════════════════════
    ws1 = wb.active
    ws1.title = "Productos"
    ws1.freeze_panes = "A2"

    hdrs1 = ["SKU", "Nombre", "Estado", "Código", "Bultos",
             "Peso Total (kg)", "Peso Vol Total", "Creado por", "Actualizado por"]
    col_w1 = [16, 45, 14, 10, 8, 16, 15, 22, 22]
    for i, (h, w) in enumerate(zip(hdrs1, col_w1), 1):
        c = ws1.cell(row=1, column=i, value=h)
        style_hdr(c, red=(i <= 1))
        ws1.column_dimensions[c.column_letter].width = w
    ws1.row_dimensions[1].height = 20

    for row_i, p in enumerate(products, 2):
        blist = bultos_by_pid.get(int(p["id"]), [])
        ptotal = sum(float(b["peso"])     for b in blist)
        pvtot  = sum(float(b["peso_vol"]) for b in blist)
        fill = alt_fill if row_i % 2 == 0 else PatternFill()
        vals = [p["sku"], p["nombre"], p["estado"], p["codigo"],
                len(blist), round(ptotal, 2), round(pvtot, 2),
                p["created_by"] or "", p["updated_by"] or ""]
        for col_i, v in enumerate(vals, 1):
            c = ws1.cell(row=row_i, column=col_i, value=v)
            c.fill   = fill
            c.border = border
            c.font   = Font(name="Calibri", size=10,
                            bold=(col_i == 1),
                            color=RED if col_i == 1 else "000000")
            c.alignment = center if col_i in (1, 3, 4, 5, 6, 7) else left
        ws1.row_dimensions[row_i].height = 16

    # ══════════════════════════════════════════
    #  Hoja 2 — Detalle bultos
    # ══════════════════════════════════════════
    ws2 = wb.create_sheet("Bultos")
    ws2.freeze_panes = "A2"

    hdrs2 = ["SKU", "Nombre", "Código", "Bulto N°",
             "Largo (cm)", "Ancho (cm)", "Alto (cm)", "Peso (kg)", "Peso Vol"]
    col_w2 = [16, 45, 10, 9, 11, 11, 11, 11, 11]
    for i, (h, w) in enumerate(zip(hdrs2, col_w2), 1):
        c = ws2.cell(row=1, column=i, value=h)
        style_hdr(c, red=(i <= 1))
        ws2.column_dimensions[c.column_letter].width = w
    ws2.row_dimensions[1].height = 20

    row_i = 2
    for p in products:
        blist = bultos_by_pid.get(int(p["id"]), [])
        for b in blist:
            fill = alt_fill if row_i % 2 == 0 else PatternFill()
            vals = [p["sku"], p["nombre"], p["codigo"], int(b["bulto_num"]),
                    float(b["largo"]), float(b["ancho"]), float(b["alto"]),
                    float(b["peso"]), float(b["peso_vol"])]
            for col_i, v in enumerate(vals, 1):
                c = ws2.cell(row=row_i, column=col_i, value=v)
                c.fill   = fill
                c.border = border
                c.font   = Font(name="Calibri", size=10,
                                bold=(col_i == 1),
                                color=RED if col_i == 1 else "000000")
                c.alignment = center if col_i != 2 else left
            ws2.row_dimensions[row_i].height = 16
            row_i += 1

    buf = io.BytesIO()
    wb.save(buf)
    buf.seek(0)
    fecha = datetime.now().strftime("%Y%m%d_%H%M")
    filename = f"ILUS_Etiquetas_{fecha}.xlsx"
    return Response(
        buf.read(),
        mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        headers={"Content-Disposition": f'attachment; filename="{filename}"'},
    )


