@app.route("/admin/users")
@require_permission("admin")
def users_index():
    # Filtros: estado (todos/activos/inactivos), búsqueda, rol
    estado_f = (request.args.get("estado") or "").strip().lower()
    rol_f    = (request.args.get("rol") or "").strip()
    q_f      = (request.args.get("q") or "").strip()

    where, params = ["1=1"], []
    if estado_f == "activos":
        where.append("active=1")
    elif estado_f == "inactivos":
        where.append("active=0")
    if rol_f:
        where.append("role=%s"); params.append(rol_f)
    if q_f:
        where.append("(username LIKE %s OR nombre LIKE %s OR phone LIKE %s OR rut LIKE %s)")
        like = f"%{q_f}%"
        params += [like, like, like, like]

    # 2026-05-18: SELECT * + columna virtual `online` calculada por SQL.
    # 2026-05-26 (audit DevTools, body era 95KB): mantenemos SELECT * para
    # NO romper el template, pero agregamos LIMIT 300 (suficiente para
    # empresas hasta 300 usuarios; más allá hay que paginar UI).
    # `online=1` si last_seen_at está a menos de 5 minutos de NOW().
    try:
        users = mysql_fetchall(
            f"SELECT *, "
            f"  CASE WHEN last_seen_at IS NOT NULL AND "
            f"            last_seen_at >= DATE_SUB(NOW(), INTERVAL 5 MINUTE) "
            f"       THEN 1 ELSE 0 END AS online "
            f"FROM `{AUTH_TABLE}` WHERE {' AND '.join(where)} "
            f"ORDER BY active DESC, online DESC, last_login_at DESC, nombre, username "
            f"LIMIT 300",
            tuple(params)
        ) or []
    except Exception as _e_ls:
        # Columna last_seen_at no existe aún → fallback
        print(f"[users_index] fallback sin last_seen_at: {_e_ls}", flush=True)
        users = mysql_fetchall(
            f"SELECT *, 0 AS online FROM `{AUTH_TABLE}` WHERE {' AND '.join(where)} "
            f"ORDER BY active DESC, last_login_at DESC, nombre, username "
            f"LIMIT 300",
            tuple(params)
        ) or []

    # Conteos para badges en la cabecera de filtros
    try:
        counts = mysql_fetchone(
            f"SELECT "
            f" SUM(CASE WHEN active=1 THEN 1 ELSE 0 END) AS activos, "
            f" SUM(CASE WHEN active=0 THEN 1 ELSE 0 END) AS inactivos, "
            f" SUM(CASE WHEN active=1 AND last_login_at >= DATE_SUB(NOW(), INTERVAL 7 DAY) "
            f"          THEN 1 ELSE 0 END) AS conectados_7d, "
            # 2026-05-18: en línea ahora = last_seen_at en los últimos 5 min
            f" SUM(CASE WHEN active=1 AND last_seen_at >= DATE_SUB(NOW(), INTERVAL 5 MINUTE) "
            f"          THEN 1 ELSE 0 END) AS online_ahora, "
            f" SUM(CASE WHEN active=1 AND (last_login_at IS NULL OR "
            f"          last_login_at < DATE_SUB(NOW(), INTERVAL 30 DAY)) THEN 1 ELSE 0 END) AS nunca_o_viejos, "
            f" COUNT(*) AS total "
            f"FROM `{AUTH_TABLE}`"
        ) or {}
    except Exception:
        counts = mysql_fetchone(
            f"SELECT "
            f" SUM(CASE WHEN active=1 THEN 1 ELSE 0 END) AS activos, "
            f" SUM(CASE WHEN active=0 THEN 1 ELSE 0 END) AS inactivos, "
            f" SUM(CASE WHEN active=1 AND last_login_at >= DATE_SUB(NOW(), INTERVAL 7 DAY) "
            f"          THEN 1 ELSE 0 END) AS conectados_7d, "
            f" 0 AS online_ahora, "
            f" SUM(CASE WHEN active=1 AND (last_login_at IS NULL OR "
            f"          last_login_at < DATE_SUB(NOW(), INTERVAL 30 DAY)) THEN 1 ELSE 0 END) AS nunca_o_viejos, "
            f" COUNT(*) AS total "
            f"FROM `{AUTH_TABLE}`"
        ) or {}

    return render_template("users.html",
        users=users,
        filtros={"estado": estado_f, "rol": rol_f, "q": q_f},
        counts=counts,
    )


@app.route("/admin/api/users/online", methods=["GET"])
@require_permission("admin")
def admin_users_online():
    """JSON compact: lista de {id, online} para refrescar LEDs sin recargar.
    Refresca cada 30s desde el frontend. Admin / superadmin only.

    `online=true` si last_seen_at está a menos de 5 minutos de NOW().
    """
    try:
        rows = mysql_fetchall(
            f"SELECT id, "
            f"       (last_seen_at IS NOT NULL AND "
            f"        last_seen_at >= DATE_SUB(NOW(), INTERVAL 5 MINUTE)) AS online "
            f"FROM `{AUTH_TABLE}` WHERE active=1"
        ) or []
        users_payload = [{"id": r["id"], "online": bool(r["online"])} for r in rows]
        online_total = sum(1 for r in users_payload if r["online"])
        return jsonify(ok=True, users=users_payload, online_total=online_total)
    except Exception as e:
        print(f"[admin_users_online] {e}", flush=True)
        return jsonify(ok=False, error="No fue posible consultar el estado en vivo"), 500


@app.route("/admin/api/users/backfill-last-login", methods=["POST"])
@require_permission("admin")
def admin_users_backfill_last_login():
    """Repara el bug histórico de tracking (commit c9440a2): para usuarios
    con last_login_at NULL pero que tienen entradas `login_ok` en
    app_audit_log, infiere last_login_at = MAX(ts) y login_count = COUNT.
    Idempotente — corre todas las veces que sea necesario.
    Solo admin/superadmin. Devuelve cuántas filas se actualizaron.
    """
    try:
        # Backfill last_login_at desde el último login_ok del audit log.
        # JOIN garantiza que solo afecta filas con audit asociado real.
        n_login = mysql_execute_returning_rowcount(
            f"UPDATE `{AUTH_TABLE}` u "
            f"JOIN (SELECT target_id, MAX(ts) AS last_ts, COUNT(*) AS n "
            f"      FROM app_audit_log "
            f"      WHERE action='login_ok' AND target_type='user' "
            f"      GROUP BY target_id) a "
            f"  ON a.target_id = CAST(u.id AS CHAR) "
            f"SET u.last_login_at = COALESCE(u.last_login_at, a.last_ts), "
            f"    u.login_count   = GREATEST(COALESCE(u.login_count,0), a.n) "
            f"WHERE u.last_login_at IS NULL OR COALESCE(u.login_count,0) < a.n"
        )
        print(f"[backfill-last-login] OK rows_updated={n_login} by={(g.user or {}).get('username')}", flush=True)
        return jsonify(ok=True, filas_actualizadas=n_login,
                       mensaje=f"Se repararon {n_login} usuario(s) usando el registro de auditoría.")
    except Exception as e:
        import traceback as _tb_bf
        print(f"[backfill-last-login] FAIL: {e}\n{_tb_bf.format_exc()}", flush=True)
        return jsonify(ok=False, error="No fue posible reparar el tracking. Revisa los logs."), 500


def _normalizar_telefono_cl(raw):
    """Normaliza un teléfono chileno a formato canónico +56XXXXXXXXX.

    Acepta entradas como:
      "9 1234 5678"     → "+56912345678"
      "+56 9 1234 5678" → "+56912345678"
      "56 9 1234 5678"  → "+56912345678"
      "912345678"       → "+56912345678"
      "21234567"        → "+5621234567" (fijo)
      "" o inválido     → "" (sin error, simplemente vacío)

    Reglas:
    - Solo dígitos (descarta +, espacios, guiones).
    - Si empieza con 56 y tiene ≥10 dígitos, quita el 56.
    - Lo que queda debe tener 8 ó 9 dígitos. Si no, devuelve cadena original
      stripped (para no perder info de algo que el usuario quizá quería).
    """
    if not raw:
        return ""
    digits = "".join(c for c in str(raw) if c.isdigit())
    if not digits:
        return ""
    # Quitar prefijo 56 si está
    if digits.startswith("56") and len(digits) >= 10:
        digits = digits[2:]
    # 8 dígitos = fijo sin código área incluido (poco común, los aceptamos)
    # 9 dígitos = formato CL típico (móvil 9XXXXXXXX o fijo 2XXXXXXXX)
    if len(digits) in (8, 9):
        return f"+56{digits}"
    # Caso raro: devolver original stripped sin formatear
    return str(raw).strip()


@app.route("/admin/users/new", methods=["GET", "POST"])
@require_permission("admin")
def new_user():
    if request.method == "POST":
        username    = request.form.get("username", "").strip().lower()
        nombre      = request.form.get("nombre",   "").strip()
        phone       = _normalizar_telefono_cl(request.form.get("phone", ""))
        role        = request.form.get("role",      "editor")
        active      = 1 if request.form.get("active") == "1" else 0
        send_invite = request.form.get("send_invite") == "1"
        wa_number   = request.form.get("wa_number", "").strip()
        manual_password = request.form.get("manual_password", "")
        is_superadmin = bool(g.permissions.get("superadmin")) if getattr(g, "permissions", None) else False

        errors = []
        if not username:
            errors.append("El correo es requerido.")
        elif not EMAIL_RE.match(username):
            errors.append("El correo no tiene un formato válido.")
        if not nombre:
            errors.append("El nombre y apellido son requeridos.")
        if phone and not re.match(r"^\+?[0-9\s\-]{7,20}$", phone):
            errors.append("El telefono WhatsApp debe usar formato internacional, por ejemplo +56912345678.")
        if not _es_rol_valido(role):
            errors.append("Rol no valido.")
        elif role == "superadmin" and not is_superadmin:
            errors.append("Solo un superadministrador puede asignar el rol superadmin.")
        if manual_password and not is_superadmin:
            errors.append("Solo un superadministrador puede definir clave manual.")
        if manual_password:
            # FIX seguridad 2026-05-17: política unificada con el resto
            # del proyecto (12+ chars, mayús/minús/dígito/símbolo).
            errors.extend(_password_strength_errors(manual_password))
        if get_auth_user_by_username(username):
            errors.append("Ese correo ya está registrado.")

        if errors:
            return render_template("user_form.html", errors=errors, user=None, fd=request.form,
                                   roles=_get_roles_disponibles())

        # Crear usuario con contraseña placeholder aleatoria.
        # - Si admin asignó manual_password, esa es la clave inicial.
        # - Si NO, generamos un placeholder aleatorio fuerte (32 hex chars)
        #   que el usuario JAMÁS conoce — solo se activa la cuenta vía
        #   /welcome/<token>. El admin NUNCA ve la clave del usuario.
        # - requires_password_change=1 cuando no hay clave manual, para
        #   que el sistema sepa que esta cuenta aún está sin activar.
        placeholder_hash = generate_password_hash(manual_password or secrets.token_hex(32))
        needs_change = 0 if manual_password else 1
        conn = get_db()
        with conn.cursor() as cur:
            # Intentamos con requires_password_change; si la columna no existe
            # (deploy antiguo), caemos al INSERT sin esa columna.
            try:
                cur.execute(
                    f"INSERT INTO `{AUTH_TABLE}` "
                    f"(username,nombre,password_hash,phone,role,active,requires_password_change) "
                    f"VALUES (%s,%s,%s,%s,%s,%s,%s)",
                    (username, nombre, placeholder_hash, phone or None, role, active, needs_change),
                )
            except Exception:
                cur.execute(
                    f"INSERT INTO `{AUTH_TABLE}` "
                    f"(username,nombre,password_hash,phone,role,active) "
                    f"VALUES (%s,%s,%s,%s,%s,%s)",
                    (username, nombre, placeholder_hash, phone or None, role, active),
                )
        conn.commit()

        # Bienvenida: token de 7 días + endpoint /welcome/<token>.
        # El envío se hace en background para no bloquear el HTTP response
        # (SMTP + WhatsApp pueden tardar 10-15s combinados).
        if send_invite and not manual_password:
            try:
                new_uid   = mysql_fetchone(f"SELECT id FROM `{AUTH_TABLE}` WHERE username=%s", (username,))["id"]
                # 10080 minutos = 7 días — bienvenida tiene ventana amplia
                token, _expires = _issue_password_token(new_uid, minutes=10080)
                # ⬇️  Endpoint dedicado a activación de cuenta (welcome.html, copy distinto)
                welcome_url = url_for("welcome_activate", token=token, _external=True)

                # _notify_user_access manda email + WhatsApp en un solo call,
                # con copy de bienvenida (mode=token, sin email_purpose=change).
                actor_name_snap = g.user["nombre"] if getattr(g, "user", None) else "ILUS"
                snap_phone = wa_number or phone or ""
                def _send_bg(_un=username, _nom=nombre, _ph=snap_phone, _url=welcome_url, _actor=actor_name_snap):
                    try:
                        _notify_user_access(
                            _un, _nom, _ph,
                            mode="token", action_url=_url,
                            email_purpose="invite",
                        )
                    except Exception as _se:
                        print(f"[new_user/bg-notify] fail: {_se}", flush=True)
                threading.Thread(target=_send_bg, daemon=True).start()
                ch = "email + WhatsApp" if snap_phone else "email"
                flash(f"✅ Usuario creado. Invitación enviada por {ch} a {username} en segundo plano.", "success")
            except Exception as _ie:
                flash(f"Usuario creado, pero falló el envío de invitación: {_ie}", "warning")
        else:
            if manual_password:
                # Notificación de clave manual también en background
                snap_user = username; snap_nombre = nombre; snap_phone = wa_number or phone
                def _notify_bg():
                    try:
                        _notify_user_access(snap_user, snap_nombre, snap_phone, mode="manual")
                    except Exception as _ne:
                        print(f"[new_user/bg-notify] fail: {_ne}", flush=True)
                threading.Thread(target=_notify_bg, daemon=True).start()
                flash("✅ Usuario creado con clave manual. Notificación enviada en segundo plano.", "success")
            else:
                flash("✅ Usuario creado. Recuerda establecer la contrasena o enviar la invitacion despues.", "success")

        if manual_password:
            flash("Clave manual asignada por superadmin.", "info")
        return redirect(url_for("users_index"))

    return render_template("user_form.html", errors=[], user=None, fd={},
                           roles=_get_roles_disponibles())


@app.route("/admin/users/<int:user_id>/edit", methods=["GET", "POST"])
@require_permission("admin")
def edit_user(user_id):
    user = get_auth_user_by_id(user_id)
    if not user:
        flash("Usuario no encontrado.", "danger")
        return redirect(url_for("users_index"))

    if request.method == "POST":
        username = request.form.get("username", "").strip().lower()
        nombre   = request.form.get("nombre",   "").strip()
        phone    = _normalizar_telefono_cl(request.form.get("phone", ""))
        manual_password = request.form.get("manual_password", "")
        is_superadmin = bool(g.permissions.get("superadmin")) if getattr(g, "permissions", None) else False
        role     = request.form.get("role",     "editor")
        active   = 1 if request.form.get("active") == "1" else 0

        errors = []
        if not username:
            errors.append("El correo es requerido.")
        elif not EMAIL_RE.match(username):
            errors.append("El correo no tiene un formato válido.")
        if not nombre:
            errors.append("El nombre y apellido son requeridos.")
        if phone and not re.match(r"^\+?[0-9\s\-]{7,20}$", phone):
            errors.append("El telefono WhatsApp debe usar formato internacional, por ejemplo +56912345678.")
        if not _es_rol_valido(role):
            errors.append("Rol no valido.")
        elif role == "superadmin" and not is_superadmin:
            errors.append("Solo un superadministrador puede asignar el rol superadmin.")
        if manual_password and not is_superadmin:
            errors.append("Solo un superadministrador puede definir clave manual.")
        if manual_password:
            # FIX seguridad 2026-05-17: política unificada con el resto
            # del proyecto (12+ chars, mayús/minús/dígito/símbolo).
            errors.extend(_password_strength_errors(manual_password))
        if mysql_fetchone(
            f"SELECT id FROM `{AUTH_TABLE}` WHERE username=%s AND id<>%s", (username, user_id)
        ):
            errors.append("Ese correo ya está en uso.")

        if errors:
            return render_template("user_form.html", errors=errors, user=user, fd=request.form,
                                   roles=_get_roles_disponibles())

        conn = get_db()
        with conn.cursor() as cur:
            if manual_password:
                cur.execute(
                    f"UPDATE `{AUTH_TABLE}` SET username=%s,nombre=%s,password_hash=%s,phone=%s,role=%s,active=%s WHERE id=%s",
                    (username, nombre, generate_password_hash(manual_password), phone or None, role, active, user_id),
                )
            else:
                cur.execute(
                    f"UPDATE `{AUTH_TABLE}` SET username=%s,nombre=%s,phone=%s,role=%s,active=%s WHERE id=%s",
                    (username, nombre, phone or None, role, active, user_id),
                )
        conn.commit()

        # Invalida caché de session si se editó el usuario actual
        if g.user and g.user["id"] == user_id:
            session.pop("_uc", None)

        if manual_password:
            result = _notify_user_access(username, nombre, phone, mode="manual")
            msg, level = _access_notification_flash(result, token_mode=False)
            flash(f"Usuario actualizado con clave manual. {msg}", level)
        else:
            flash("Usuario actualizado.", "success")
        return redirect(url_for("users_index"))

    return render_template("user_form.html", errors=[], user=user, fd={},
                           roles=_get_roles_disponibles())


@app.route("/admin/users/<int:user_id>/delete", methods=["POST"])
@require_permission("admin")
def delete_user(user_id):
    if g.user and g.user["id"] == user_id:
        flash("No puedes eliminar tu propio usuario mientras estás conectado.", "danger")
        return redirect(url_for("users_index"))

    conn = get_db()
    with conn.cursor() as cur:
        cur.execute(f"DELETE FROM `{AUTH_TABLE}` WHERE id=%s", (user_id,))
    conn.commit()

    flash("Usuario eliminado.", "warning")
    return redirect(url_for("users_index"))


@app.route("/admin/users/<int:user_id>/invite", methods=["POST"])
@require_permission("admin")
def invite_user(user_id):
    """Envía (o reenvía) el correo de invitación para crear contraseña."""
    user = get_auth_user_by_id(user_id)
    if not user:
        return jsonify({"error": "Usuario no encontrado"}), 404
    try:
        token, _expires = _issue_password_token(user_id, minutes=1440)
        set_url = url_for("reset_password", token=token, _external=True)
        result = _notify_user_access(user["username"], user["nombre"], user.get("phone") or "", mode="token", action_url=set_url)
        if result.get("email") or result.get("whatsapp"):
            msg, _level = _access_notification_flash(result, token_mode=True)
            return jsonify({"ok": True, "message": msg})
        detalle = " ".join(result.get("errors") or []) or "Revisa la configuracion SMTP o WhatsApp en Comunicaciones."
        return jsonify({"error": f"No se pudo enviar la invitacion. {detalle}"}), 500
    except Exception as exc:
        return jsonify({"error": str(exc)}), 500


