@app.route("/admin/login-imagenes", methods=["POST"])
@require_permission("admin")
def admin_login_imagenes_subir():
    """Sube UNA O VARIAS imágenes al carrusel del login (máx 5 activas).

    Soporta multi-upload (input name="imagenes" multiple) y también el
    legacy input name="imagen" (single) para compatibilidad. Valida cada
    archivo con _validate_uploaded_image() y respeta el límite de 5
    activas — si se exceden, las restantes se cargan como inactivas.
    """
    # Soporta multi-upload (imagenes[]) y legacy single (imagen)
    files = request.files.getlist("imagenes")
    legacy = request.files.get("imagen")
    if legacy and legacy.filename and legacy not in files:
        files.append(legacy)
    if not files or all(not f.filename for f in files):
        flash("Selecciona al menos una imagen.", "warning")
        return redirect(url_for("admin_login_imagenes"))

    titulo_base    = (request.form.get("titulo") or "").strip()[:200]
    subtitulo_base = (request.form.get("subtitulo") or "").strip()[:300]
    want_active    = 1 if request.form.get("activa") else 0

    # Determinar orden inicial
    row = mysql_fetchone("SELECT COALESCE(MAX(orden),0) AS mx FROM login_images")
    nx = (row or {}).get("mx", 0) + 1

    # Contar activas actuales
    activas_row = mysql_fetchone("SELECT COUNT(*) AS n FROM login_images WHERE activa=1")
    activas = (activas_row or {}).get("n", 0)

    saved = 0
    cloud_saved = 0
    errors: list[str] = []
    for i, f in enumerate(files):
        if not f or not f.filename:
            continue
        ext, err = _validate_uploaded_image(f, label=f.filename)
        if err:
            errors.append(err)
            continue
        fname = f"login_{int(time.time())}_{i}_{secure_filename(f.filename)}"

        # ── Cloudinary primero (PERSISTENTE — sobrevive deploys Railway) ─
        cloud_url = None
        cloud_pid = None
        if _CLD_READY:
            try:
                f.stream.seek(0)
                public_id = f"login_{int(time.time())}_{i}"
                # _cloud_upload_image_full devuelve {url, public_id, size}
                # — usa el public_id REAL de Cloudinary (sin regex frágil).
                _cld_res = _cloud_upload_image_full(f.stream, public_id, folder="ilus/login_carousel")
                cloud_url = _cld_res["url"]
                cloud_pid = _cld_res["public_id"]
                print(f"[login_imagenes] Cloudinary OK {fname} → {cloud_url} (pid={cloud_pid})", flush=True)
            except Exception as e_cld:
                print(f"[login_imagenes] Cloudinary FAIL {fname}: {e_cld}", flush=True)
                cloud_url = None

        # ── Filesystem fallback (también guarda copia local si se puede) ──
        try:
            f.stream.seek(0)
        except Exception:
            pass
        fpath = os.path.join(LOGIN_IMAGES_DIR, fname)
        saved_local = False
        try:
            f.save(fpath)
            saved_local = True
        except Exception as e:
            if not cloud_url:
                errors.append(f"Error guardando {f.filename}: {e}")
                continue
            print(f"[login_imagenes] filesystem fail pero Cloudinary OK: {e}", flush=True)

        # Si excede 5 activas, marcar como inactiva
        activa = want_active
        if activa and activas >= 5:
            activa = 0
        else:
            activas += activa
        try:
            mysql_execute(
                "INSERT INTO login_images "
                "(archivo_path,cloudinary_url,cloudinary_public_id,titulo,subtitulo,orden,activa,created_by) "
                "VALUES (%s,%s,%s,%s,%s,%s,%s,%s)",
                (
                    f"uploads/login/{fname}" if saved_local else None,
                    cloud_url,
                    cloud_pid,
                    titulo_base or None,
                    subtitulo_base or None,
                    nx + saved,
                    activa,
                    current_username(),
                )
            )
            saved += 1
            if cloud_url:
                cloud_saved += 1
        except Exception as e:
            errors.append(f"Error BD {f.filename}: {e}")
    if saved:
        msg = f"✅ {saved} imagen(es) agregadas al carrusel."
        if cloud_saved:
            msg += f" {cloud_saved} persistente(s) en Cloudinary."
        flash(msg, "success")
        try: _invalidate_login_images_cache()
        except Exception: pass
    for err in errors[:3]:
        flash(err, "warning")
    return redirect(url_for("admin_login_imagenes"))


@app.route("/admin/login-imagenes/<int:iid>", methods=["POST"])
@require_permission("admin")
def admin_login_imagen_update(iid):
    """Actualiza atributos (titulo, subtitulo, orden, activa) de una imagen."""
    action = request.form.get("action") or ""
    if action == "delete":
        row = mysql_fetchone(
            "SELECT archivo_path, cloudinary_public_id FROM login_images WHERE id=%s", (iid,)
        )
        if row:
            # Borrar de Cloudinary si está ahí
            if row.get("cloudinary_public_id"):
                try:
                    if _cloudinary_uploader:
                        _cloudinary_uploader.destroy(row["cloudinary_public_id"], resource_type="image")
                except Exception as e:
                    print(f"[login_imagen_del] Cloudinary delete fail: {e}", flush=True)
            # Borrar archivo local si existe
            if row.get("archivo_path"):
                try:
                    fp = os.path.join(os.path.dirname(os.path.abspath(__file__)), "static", row["archivo_path"])
                    if os.path.exists(fp): os.remove(fp)
                except Exception: pass
        mysql_execute("DELETE FROM login_images WHERE id=%s", (iid,))
        try: _invalidate_login_images_cache()
        except Exception: pass
        flash("Imagen eliminada.", "success")
    else:
        titulo    = (request.form.get("titulo") or "").strip()[:200]
        subtitulo = (request.form.get("subtitulo") or "").strip()[:300]
        orden     = int(request.form.get("orden") or 0)
        activa    = 1 if request.form.get("activa") else 0
        # Limitar a 5 activas
        if activa:
            ac = mysql_fetchone(
                "SELECT COUNT(*) AS n FROM login_images WHERE activa=1 AND id <> %s", (iid,)
            )
            if ac and ac.get("n",0) >= 5:
                activa = 0
                flash("Ya hay 5 imágenes activas. Desactiva alguna para activar esta.", "warning")
        mysql_execute(
            "UPDATE login_images SET titulo=%s, subtitulo=%s, orden=%s, activa=%s WHERE id=%s",
            (titulo, subtitulo, orden, activa, iid)
        )
        try: _invalidate_login_images_cache()
        except Exception: pass
        flash("Imagen actualizada.", "success")
    return redirect(url_for("admin_login_imagenes"))


# ═════════════════════════════════════════════════════════════════════
# CARRUSEL PÚBLICO DE RETIROS (multi-imagen desde BD)
# Mismo patrón que login_images: subir, actualizar, eliminar.
# ═════════════════════════════════════════════════════════════════════

RETIROS_IMAGES_DIR = os.path.join(UPLOADS_BASE, "retiros")
os.makedirs(RETIROS_IMAGES_DIR, exist_ok=True)


def _retiros_carousel_active():
    """Devuelve lista de imágenes activas ordenadas para el carrusel público.

    Cada item incluye 'src' que es la URL final a usar: Cloudinary si existe
    (persistente entre deploys), filesystem como fallback (puede estar perdido).
    """
    try:
        rows = mysql_fetchall(
            "SELECT id, archivo_path, cloudinary_url, titulo, subtitulo FROM retiros_carousel "
            "WHERE activa=1 ORDER BY orden ASC, id ASC"
        )
        out = []
        for r in (rows or []):
            d = dict(r)
            d["src"] = d.get("cloudinary_url") or (
                f"/static/{d['archivo_path']}" if d.get("archivo_path") else ""
            )
            out.append(d)
        return out
    except Exception:
        return []


# Cache login images — el GET /login es muy frecuente y la lista cambia
# raramente (solo en admin). TTL 120s; admin invalida explícitamente al
# editar el carrusel (ver _invalidate_login_images_cache).
_login_imgs_cache = {"active": None, "active_ts": 0.0}
_login_imgs_lock = threading.Lock()
_LOGIN_IMGS_TTL = 120


def _invalidate_login_images_cache():
    """Llamar tras INSERT/UPDATE/DELETE en login_images."""
    with _login_imgs_lock:
        _login_imgs_cache["active"] = None
        _login_imgs_cache["active_ts"] = 0.0
    try:
        _cache_signal_bump("login_images")
    except Exception:
        pass


def _login_images_active(solo_activas=False):
    """Devuelve imágenes del carrusel del login con src resuelto.

    Cada item incluye:
      - id, titulo, subtitulo, orden, activa, archivo_path, cloudinary_url
      - src       → URL final (cloudinary primero, filesystem fallback)
      - persistente → bool, True si está en Cloudinary

    Args:
      solo_activas: si True, filtra activa=1 y LIMIT 5 (para login público).
                    si False (default), trae todas (para admin/gestión).

    PERF: solo_activas=True (público) usa cache TTL 120s. La variante
    admin (solo_activas=False) NO se cachea (se invoca poco y necesita
    columnas extra).
    """
    # Solo cacheamos la variante pública (login)
    if solo_activas:
        # Cross-worker invalidation check
        try:
            if _cache_signal_changed("login_images"):
                with _login_imgs_lock:
                    _login_imgs_cache["active"] = None
                    _login_imgs_cache["active_ts"] = 0.0
        except Exception:
            pass
        now = time.time()
        with _login_imgs_lock:
            if _login_imgs_cache["active"] is not None and (now - _login_imgs_cache["active_ts"]) < _LOGIN_IMGS_TTL:
                return _login_imgs_cache["active"]
    try:
        if solo_activas:
            rows = mysql_fetchall(
                "SELECT id, archivo_path, cloudinary_url, titulo, subtitulo, orden, activa "
                "FROM login_images WHERE activa=1 "
                "ORDER BY orden ASC, id ASC LIMIT 5"
            )
        else:
            rows = mysql_fetchall(
                "SELECT id, archivo_path, cloudinary_url, titulo, subtitulo, orden, activa, "
                "       created_by, created_at "
                "FROM login_images ORDER BY orden ASC, id ASC"
            )
        out = []
        for r in (rows or []):
            d = dict(r)
            d["src"] = d.get("cloudinary_url") or (
                f"/static/{d['archivo_path']}" if d.get("archivo_path") else ""
            )
            d["persistente"] = bool(d.get("cloudinary_url"))
            out.append(d)
        if solo_activas:
            with _login_imgs_lock:
                _login_imgs_cache["active"] = out
                _login_imgs_cache["active_ts"] = time.time()
        return out
    except Exception:
        return []


# Helper de validación reutilizable (seguridad: extensión + tamaño + MIME)
# 2026-05-17: agregado HEIC/HEIF (formato default de iPhone desde iOS 11).
# Cloudinary los convierte automáticamente a JPG; en filesystem se guardan
# tal cual y se pueden visualizar con <img> en iOS/macOS (otros browsers
# muestran el cloudinary_url ya convertido).
_ALLOWED_IMAGE_EXTS = {"png", "jpg", "jpeg", "webp", "heic", "heif"}
_MAX_IMAGE_BYTES = 8 * 1024 * 1024  # 8 MB


def _validate_uploaded_image(f, label="imagen"):
    """Valida un FileStorage de imagen. Retorna (ext_ok, error_msg).

    FIX 2026-05-17: si la extensión es desconocida (iOS a veces manda
    el archivo sin extensión o como 'image' a secas), miramos el
    mimetype como fallback. Sin esto, fotos legítimas de iPhone
    eran rechazadas con "Formato no permitido".
    """
    if not f or not f.filename:
        return None, f"Selecciona un archivo ({label})."
    ext = f.filename.rsplit(".", 1)[-1].lower() if "." in f.filename else ""

    # Fallback por mime cuando la extensión no se puede determinar o es desconocida.
    # iOS Safari a veces envía files con name "image.jpg" pero mimetype real "image/heic".
    if ext not in _ALLOWED_IMAGE_EXTS:
        mime = (getattr(f, "mimetype", "") or "").lower()
        mime_to_ext = {
            "image/jpeg": "jpg", "image/jpg": "jpg",
            "image/png": "png", "image/webp": "webp",
            "image/heic": "heic", "image/heif": "heif",
        }
        if mime in mime_to_ext:
            ext = mime_to_ext[mime]
        elif mime.startswith("image/"):
            # Mime es de imagen pero no reconocemos el subtipo — aceptar como JPG
            # (Cloudinary se encarga de convertir igual)
            ext = "jpg"
        else:
            return None, f"Formato no permitido en {label}. Usa PNG/JPG/WEBP/HEIC."

    # Tamaño aproximado (lee header sin cargar todo)
    f.stream.seek(0, 2)
    size = f.stream.tell()
    f.stream.seek(0)
    if size > _MAX_IMAGE_BYTES:
        return None, f"{label}: archivo muy grande ({size//(1024*1024)} MB). Máx 8 MB."
    if size == 0:
        return None, f"{label}: archivo vacío."
    return ext, None


