@app.route("/admin/retiros-carousel/subir", methods=["POST"])
@require_permission("marketing")
def admin_retiros_carousel_subir():
    """Sube UNA O VARIAS imágenes al carrusel público de retiros.

    Soporta multi-upload (input name="imagenes" multiple). Valida cada
    archivo por extensión y tamaño máx 8MB.
    """
    files = request.files.getlist("imagenes")
    if not files or all(not f.filename for f in files):
        flash("Selecciona al menos una imagen.", "warning")
        return redirect(url_for("admin_retiros_carousel"))

    # Determinar orden inicial = max actual + 1
    row = mysql_fetchone("SELECT COALESCE(MAX(orden),0) AS mx FROM retiros_carousel")
    nx = (row or {}).get("mx", 0) + 1

    titulo_base = (request.form.get("titulo") or "").strip()[:200]
    subtitulo_base = (request.form.get("subtitulo") or "").strip()[:300]
    activa = 1 if request.form.get("activa") else 0

    saved = 0
    cloud_saved = 0
    errors = []
    for f in files:
        if not f or not f.filename:
            continue
        ext, err = _validate_uploaded_image(f, label=f.filename)
        if err:
            errors.append(err)
            continue
        fname = f"retiros_{int(time.time())}_{saved}_{secure_filename(f.filename)}"

        # ── Cloudinary primero ──────────────────────────────────────────
        cloud_url = None
        cloud_pid = None
        if _CLD_READY:
            try:
                f.stream.seek(0)
                public_id = f"retiros_{int(time.time())}_{saved}"
                _cld_res = _cloud_upload_image_full(f.stream, public_id, folder="ilus/retiros_carousel")
                cloud_url = _cld_res["url"]
                cloud_pid = _cld_res["public_id"]
                print(f"[retiros_carousel] Cloudinary OK {fname} → {cloud_url} (pid={cloud_pid})", flush=True)
            except Exception as e_cld:
                print(f"[retiros_carousel] Cloudinary FAIL {fname}: {e_cld}", flush=True)
                cloud_url = None

        # ── Filesystem fallback ─────────────────────────────────────────
        try:
            f.stream.seek(0)
        except Exception:
            pass
        fpath = os.path.join(RETIROS_IMAGES_DIR, fname)
        saved_local = False
        try:
            f.save(fpath)
            saved_local = True
        except Exception as e:
            if not cloud_url:
                errors.append(f"Error guardando {f.filename}: {e}")
                continue
            print(f"[retiros_carousel] filesystem fail pero Cloudinary OK: {e}", flush=True)

        try:
            mysql_execute(
                "INSERT INTO retiros_carousel "
                "(archivo_path,cloudinary_url,cloudinary_public_id,titulo,subtitulo,orden,activa,created_by) "
                "VALUES (%s,%s,%s,%s,%s,%s,%s,%s)",
                (
                    f"uploads/retiros/{fname}" if saved_local else None,
                    cloud_url,
                    cloud_pid,
                    titulo_base or None,
                    subtitulo_base or None,
                    nx + saved,
                    activa,
                    current_username(),
                )
            )
            saved += 1
            if cloud_url:
                cloud_saved += 1
        except Exception as e:
            errors.append(f"Error BD {f.filename}: {e}")
    if saved:
        msg = f"✅ {saved} imagen(es) agregadas al carrusel de retiros."
        if cloud_saved:
            msg += f" {cloud_saved} persistente(s) en Cloudinary."
        flash(msg, "success")
    for err in errors[:3]:
        flash(err, "warning")
    return redirect(url_for("admin_retiros_carousel"))


