@app.route("/cubicador/sync-nombre", methods=["POST"])
@login_required
def cubicador_sync_nombre():
    """Actualiza el nombre de un producto en nuestra BD con el nombre del ERP."""
    if not g.permissions.get("cubicador"):
        return jsonify({"error": "sin permiso"}), 403
    sku        = request.form.get("sku", "").strip().upper()
    nombre_erp = request.form.get("nombre_erp", "").strip()
    if not sku or not nombre_erp:
        return jsonify({"error": "datos incompletos"}), 400
    conn = get_db()
    with conn.cursor() as cur:
        cur.execute(
            f"UPDATE `{PRODUCTS_TABLE}` SET nombre=%s WHERE UPPER(TRIM(sku))=%s",
            (nombre_erp, sku)
        )
    conn.commit()
    _invalidate_listing_cache()
    return jsonify({"ok": True, "sku": sku, "nombre": nombre_erp})


# ═══════════════════════════════════════════════════════════════
#  MÓDULO: ASIGNAR Y COTIZAR
# ═══════════════════════════════════════════════════════════════

# ── Credenciales FedEx Rate API (env vars; placeholders solo si faltan) ─
# FEDEX_RATE_CLIENT_ID, FEDEX_RATE_CLIENT_SECRET, FEDEX_ACCOUNT deben
# setearse en Railway → Variables. Si faltan, los endpoints de cotización
# FedEx devuelven 503 amigable en vez de crashear.
FEDEX_RATE_CLIENT_ID     = os.environ.get("FEDEX_RATE_CLIENT_ID", "").strip()
FEDEX_RATE_CLIENT_SECRET = os.environ.get("FEDEX_RATE_CLIENT_SECRET", "").strip()
FEDEX_ACCOUNT            = os.environ.get("FEDEX_ACCOUNT", "").strip()
FEDEX_ORIGIN_POSTAL      = os.environ.get("FEDEX_ORIGIN_POSTAL", "9276181").strip()
FEDEX_ORIGIN_CITY        = os.environ.get("FEDEX_ORIGIN_CITY", "Maipu").strip()
FEDEX_OAUTH_URL          = "https://apis.fedex.com/oauth/token"
FEDEX_RATE_URL           = "https://apis.fedex.com/rate/v1/rates/quotes"

if not (FEDEX_RATE_CLIENT_ID and FEDEX_RATE_CLIENT_SECRET and FEDEX_ACCOUNT):
    print("[ILUS][FEDEX] Credenciales FedEx Rate API NO configuradas — "
          "cotización FedEx deshabilitada. Setear FEDEX_RATE_CLIENT_ID, "
          "FEDEX_RATE_CLIENT_SECRET, FEDEX_ACCOUNT en Railway → Variables.",
          flush=True)

# Cache del token OAuth (dura ~3600 s)
_fedex_token_cache = {"token": None, "expires_at": 0}
_fedex_token_lock  = threading.Lock()


def _fedex_get_token() -> str:
    """Obtiene un Bearer token de FedEx (con cache para evitar re-autenticar en cada request)."""
    import requests as _req
    # Fail-fast si las credenciales no están seteadas — evita request 401 inútil.
    if not (FEDEX_RATE_CLIENT_ID and FEDEX_RATE_CLIENT_SECRET):
        raise RuntimeError("FedEx Rate API no configurada (faltan FEDEX_RATE_CLIENT_ID/SECRET)")
    with _fedex_token_lock:
        now = time.time()
        if _fedex_token_cache["token"] and now < _fedex_token_cache["expires_at"] - 30:
            return _fedex_token_cache["token"]
        resp = _req.post(
            FEDEX_OAUTH_URL,
            data={
                "grant_type":    "client_credentials",
                "client_id":     FEDEX_RATE_CLIENT_ID,
                "client_secret": FEDEX_RATE_CLIENT_SECRET,
            },
            timeout=15,
        )
        resp.raise_for_status()
        j = resp.json()
        _fedex_token_cache["token"]      = j["access_token"]
        _fedex_token_cache["expires_at"] = now + int(j.get("expires_in", 3600))
        return _fedex_token_cache["token"]


def _fedex_calc_rate(peso_pred_kg: float, postal_destino: str,
                     es_residencial: bool = False) -> dict:
    """
    Llama a la FedEx Rate API y devuelve dict con tarifa, tiempo de tránsito, etc.
    Peso facturable = max(peso_pred_kg, 0.5) redondeado a 1 decimal.
    """
    import requests as _req
    token     = _fedex_get_token()
    peso_fact = max(round(peso_pred_kg, 1), 0.5)

    body = {
        "accountNumber": {"value": FEDEX_ACCOUNT},
        "requestedShipment": {
            "shipper": {
                "address": {
                    "city":                FEDEX_ORIGIN_CITY,
                    "postalCode":          FEDEX_ORIGIN_POSTAL,
                    "countryCode":         "CL",
                    "streetLines":         ["Aurora de Chile 2486"],
                    "residential":         False,
                    "stateOrProvinceCode": "",
                }
            },
            "recipient": {
                "address": {
                    "city":                "",
                    "postalCode":          str(postal_destino),
                    "countryCode":         "CL",
                    "streetLines":         [""],
                    "residential":         es_residencial,
                    "stateOrProvinceCode": "",
                }
            },
            "pickupType":      "DROPOFF_AT_FEDEX_LOCATION",
            "packagingType":   "YOUR_PACKAGING",
            "rateRequestType": ["ACCOUNT", "LIST"],
            "requestedPackageLineItems": [{
                "groupPackageCount": 1,
                "physicalPackaging": "YOUR_PACKAGING",
                "weight": {"units": "KG", "value": peso_fact},
            }],
        },
        "carrierCodes":            ["FDXE"],
        "returnLocalizedDateTime": True,
        "webSiteCountryCode":      "CL",
    }

    resp = _req.post(
        FEDEX_RATE_URL,
        json=body,
        headers={
            "Authorization": f"Bearer {token}",
            "Content-Type":  "application/json",
            "X-locale":      "es_CL",
        },
        timeout=20,
    )
    resp.raise_for_status()
    data  = resp.json()
    rates = data.get("output", {}).get("rateReplyDetails", [])
    if not rates:
        return {"error": "Sin tarifas disponibles en respuesta FedEx"}

    # Elegir primer rate con detalles
    best = next((r for r in rates if r.get("ratedShipmentDetails")), rates[0])
    rated_details = best.get("ratedShipmentDetails", [{}])
    detail = (
        next((d for d in rated_details if d.get("rateType") == "ACCOUNT"), None)
        or next((d for d in rated_details if d.get("rateType") == "LIST"), None)
        or (rated_details[0] if rated_details else {})
    )

    total  = float(detail.get("totalNetCharge", detail.get("totalNetFedExCharge", 0)))
    moneda = detail.get("currency", "CLP")

    recargos_raw = detail.get("shipmentRateDetail", {}).get("surCharges", [])
    recargos = [
        {"nombre": rc.get("description", rc.get("type", "")), "monto": float(rc.get("amount", 0))}
        for rc in recargos_raw
    ]

    transit_raw = best.get("operationalDetail", {}).get("transitTime", "")
    transit_map = {
        "ONE_DAY":    "1 día hábil",
        "TWO_DAYS":   "2 días hábiles",
        "THREE_DAYS": "3 días hábiles",
        "FOUR_DAYS":  "4 días hábiles",
        "FIVE_DAYS":  "5 días hábiles",
    }

    return {
        "servicio":        best.get("serviceType", "FEDEX_GROUND"),
        "tarifa":          total,
        "moneda":          moneda,
        "tiempo_transito": transit_map.get(transit_raw, transit_raw or "—"),
        "peso_facturable": peso_fact,
        "recargos":        recargos,
    }


# Mapa comunas CL → código postal (expandible)
_COMUNA_POSTAL = {
    "SANTIAGO": "8320000", "PROVIDENCIA": "7500000", "LAS CONDES": "7550000",
    "VITACURA": "7630000", "NUNOA": "7750000", "LA FLORIDA": "8240000",
    "MAIPU": "9276181", "PUDAHUEL": "9020000", "QUILICURA": "8711000",
    "RENCA": "8580000", "CERRO NAVIA": "9000000", "ESTACION CENTRAL": "9110000",
    "PENALOLEN": "7941000", "MACUL": "7901000", "SAN JOAQUIN": "8810000",
    "LA GRANJA": "8890000", "LA PINTANA": "8310000", "EL BOSQUE": "8080000",
    "SAN BERNARDO": "8060000", "BUIN": "9620000", "PIRQUE": "9650000",
    "TALAGANTE": "9760000", "PAINE": "9680000", "MELIPILLA": "9810000",
    "COLINA": "8500000", "LAMPA": "9520000", "PENARFLOR": "9760000",
    "CURACAVI": "9860000", "VALPARAISO": "2340000", "VINA DEL MAR": "2520000",
    "CONCON": "2521000", "QUILPUE": "2430000", "VILLA ALEMANA": "2490000",
    "SAN ANTONIO": "2830000", "RANCAGUA": "2820000", "TALCA": "3460000",
    "CURICO": "3340000", "LINARES": "3580000", "CHILLAN": "3780000",
    "CONCEPCION": "4030000", "TALCAHUANO": "4040000", "LOS ANGELES": "4440000",
    "TEMUCO": "4780000", "VALDIVIA": "5090000", "OSORNO": "5290000",
    "PUERTO MONTT": "5480000", "PUERTO VARAS": "5550000",
    "COYHAIQUE": "5950000", "PUNTA ARENAS": "6200000",
    "IQUIQUE": "1100000", "ARICA": "1000000", "ANTOFAGASTA": "1240000",
    "CALAMA": "1390000", "COPIAPO": "1530000", "LA SERENA": "1700000",
    "COQUIMBO": "1780000",
}


def _comuna_to_postal(comuna: str):
    """Convierte nombre de comuna a código postal CL. Devuelve None si no se conoce."""
    if not comuna:
        return None
    key = (comuna.strip().upper()
           .replace("Ñ","N").replace("Á","A").replace("É","E")
           .replace("Í","I").replace("Ó","O").replace("Ú","U"))
    return _COMUNA_POSTAL.get(key)


@app.route("/asignar", methods=["GET"])
@login_required
def asignar_cotizar():
    """Página principal del módulo Asignar y Cotizar.

    Forzamos headers anti-caché para que el navegador NUNCA sirva una
    versión vieja del HTML. Crítico porque este template es el que más
    JavaScript inline tiene y donde más sufrimos por caché del usuario.
    """
    if not g.permissions.get("cubicador"):
        flash("No tienes acceso al módulo Asignar y Cotizar.", "danger")
        return redirect(url_for("index"))
    resp = make_response(render_template("cubicador/asignar.html"))
    resp.headers["Cache-Control"] = "no-store, no-cache, must-revalidate, max-age=0"
    resp.headers["Pragma"] = "no-cache"
    resp.headers["Expires"] = "0"
    return resp


# ── Cache server-side del cubicador ERP ──────────────────────────────────────
# Memoria por worker (gunicorn). TTL corto (5 min) — los documentos del ERP
# no cambian con frecuencia y el operador típicamente busca el mismo doc
# varias veces seguidas (cubicar, ajustar, agregar al manifiesto).
# Reduce búsqueda repetida de ~3-4s a <50ms.
_CUB_DOC_CACHE = {}       # key=f"{tido}|{nudo}" → (epoch_expires, hdr, lineas)
_CUB_DOC_CACHE_TTL = 300  # 5 min
_CUB_DOC_CACHE_MAX = 200  # evicción FIFO simple si crece de más

def _cub_doc_cache_get(key):
    import time as _t
    row = _CUB_DOC_CACHE.get(key)
    if not row:
        return None
    exp, hdr, lineas = row
    if exp < _t.time():
        _CUB_DOC_CACHE.pop(key, None)
        return None
    return hdr, lineas

def _cub_doc_cache_put(key, hdr, lineas):
    import time as _t
    if len(_CUB_DOC_CACHE) >= _CUB_DOC_CACHE_MAX:
        # Eviccionar el más viejo
        try:
            oldest = min(_CUB_DOC_CACHE.items(), key=lambda kv: kv[1][0])[0]
            _CUB_DOC_CACHE.pop(oldest, None)
        except Exception:
            _CUB_DOC_CACHE.clear()
    _CUB_DOC_CACHE[key] = (_t.time() + _CUB_DOC_CACHE_TTL, hdr, lineas)

def _cub_doc_cache_invalidate(tido, nudo):
    """Llamado cuando el documento se persiste (ediciones aguas abajo del cubicador).
    Mantiene el cache fresco aunque sea un sistema READ-ONLY."""
    try:
        key = f"{(tido or '').upper()}|{nudo}"
        _CUB_DOC_CACHE.pop(key, None)
    except Exception:
        pass


@app.route("/api/asignar/documento", methods=["POST"])
@login_required
def api_asignar_documento():
    """
    Busca un documento en el ERP y devuelve header + líneas con datos de cubicaje.
    POST JSON: { tido, nudo, prefetch?, no_cache? }
    Campos de respuesta alineados con lo que usa asignar.html.

    Cache: respuesta server-side cacheada 5 min. ?prefetch=1 marca que el
    cliente está prefetcheando — el cache sigue grabándose, pero no contamos
    estadística de uso.
    """
    if not g.permissions.get("cubicador"):
        return jsonify({"error": "Sin permiso"}), 403

    data = request.get_json(silent=True) or {}
    tido = (data.get("tido") or "FCV").strip().upper()
    nudo = str(data.get("nudo") or "").strip()
    no_cache = bool(data.get("no_cache"))

    if not nudo:
        return jsonify({"error": "Número de documento requerido"}), 400

    cache_key = f"{tido}|{nudo}"
    hdr_l = None if no_cache else _cub_doc_cache_get(cache_key)
    if hdr_l:
        hdr, lineas = hdr_l
        # Marca para diagnóstico — el frontend puede mostrar "⚡ desde cache"
        _from_cache = True
    else:
        try:
            hdr, lineas = _cubicador_fetch(tido, nudo)
        except ConnectionError as ce:
            return jsonify({"error": str(ce)}), 503
        except Exception as ex:
            return jsonify({"error": f"Error al consultar ERP: {ex}"}), 500
        if hdr is not None:
            _cub_doc_cache_put(cache_key, hdr, lineas)
        _from_cache = False

    if hdr is None:
        # Devolvemos diagnóstico del motor para que el frontend pueda mostrar
        # exactamente qué variantes de NUDO se probaron contra el ERP.
        try:
            erp_diag = _ERP._doc_cached(f"{tido}|{nudo}")
        except Exception:
            erp_diag = None
        return jsonify({
            "error": f"No se encontró {tido} N° {nudo} en el ERP Random",
            "diagnostics": {
                "nudo_tried": erp_engine.nudo_variants(
                    erp_engine.TIDO_NUDO_MAP[tido][1](nudo) if tido in erp_engine.TIDO_NUDO_MAP else nudo
                ),
                "tido": tido,
                "nudo": nudo,
                "hint": "Verifica que el documento existe en el ERP Random (la app probó todas las variantes de padding que conoce)."
            }
        }), 404

    # Extraer valor de ZZ Envío (tarifa de despacho cargada en el documento)
    zzenvio_valor = 0.0
    for l in lineas:
        if l["sku"].upper() == "ZZENVIO":
            zzenvio_valor = float(l.get("vaneli", 0))
            break

    lineas_out = []
    tot_qty = tot_kg = tot_pv = tot_vol = tot_pred = tot_bultos = 0.0

    for l in lineas:
        if l.get("es_zz"):
            continue
        qty          = l["cantidad"]
        peso_kg_u    = l["peso_kg_u"]
        peso_vol_u   = l["peso_vol_u"]
        pred_u       = l["pred_u"]
        pred_tot     = l["pred_tot"]
        bultos_u     = int(l["total_bultos"])
        bultos_total = bultos_u * int(qty) if l["tiene_bultos"] else 0

        tot_qty    += qty
        tot_kg     += l["peso_kg_tot"]
        tot_pv     += l["peso_vol_tot"]
        tot_vol    += l["vol_tot"]
        tot_pred   += pred_tot
        tot_bultos += bultos_total

        lineas_out.append({
            # Nombres exactos que lee asignar.html
            "sku":             l["sku"],
            "descripcion_erp": l["descripcion_erp"] or l["nombre_app"],
            "cantidad":        qty,
            "total_bultos":    bultos_u,          # bultos por unidad
            "bultos_tot":      bultos_total,       # bultos totales
            "tiene_ficha":     l["tiene_ficha"],
            "tiene_bultos":    l["tiene_bultos"],
            "peso_kg_u":       round(peso_kg_u,  3),
            "peso_vol_u":      round(peso_vol_u, 3),
            "vol_u":           round(l["vol_u"], 1),   # cm³/u
            "pred_u":          round(pred_u,     3),
            "pred_tot":        round(pred_tot,   3),
            # Saldo por línea (fórmula oficial Random MAEDDO, ya calculado en
            # _cubicador_fetch: CAPRCO1 - CAPRAD1 - CAPREX1 - CAPRNC1, forzado a 0
            # si ESLIDO marca despacho total). READ-ONLY: solo lo exponemos al front
            # para el badge "con saldo / sin saldo". > 0 = con saldo, 0 = entregado.
            "saldo":               (round(float(l["saldo"]), 3)
                                    if l.get("saldo") is not None else None),
            "cantidad_despachada": (round(float(l["cantidad_despachada"]), 3)
                                    if l.get("cantidad_despachada") is not None else None),
        })

    # ── Enriquecer header desde OBSERVACIONES (OBDO) cuando el ERP dejó campos
    #    vacíos (típico en boletas a consumidor final: el contacto va en el OBDO,
    #    ej. "Teniente Montt 1980 ñuñoa - 976787263 - correo@x.com"). Así la
    #    factura SIEMPRE llega con datos y el cubicador puede cotizar la comuna.
    try:
        _parsed = _parse_obdo(hdr.get("observaciones") or "")
        if not (hdr.get("email") or "").strip() and _parsed["email"]:
            hdr["email"] = _parsed["email"]
        if not (hdr.get("telefono") or "").strip() and _parsed["telefono"]:
            hdr["telefono"] = _parsed["telefono"]
        if not (hdr.get("direccion") or "").strip() and _parsed["direccion"]:
            hdr["direccion"] = _parsed["direccion"]
        if not (hdr.get("comuna") or "").strip():
            _com = _parsed["comuna"] or _detect_comuna(hdr.get("direccion") or "")
            if _com:
                hdr["comuna"] = _com
    except Exception as _e_enrich:
        print(f"[asignar_documento] enriquecer OBDO falló: {_e_enrich}", flush=True)

    # ── RESOLVER DE CLIENTE 2026-05-27 (Daniel — fix CF en /asignar) ──
    # MISMO resolver que usa el cubicador: si el nombre es CF pero hay RUT
    # real, consulta MAEEN.NOKOEN por RTEN. Resuelve 'Cristian Rossi Medina'
    # en BLV 21577 en vez de 'Consumidor final'.
    try:
        _hdr_res = dict(hdr)
        _hdr_res["lineas_raw"] = lineas or []
        _res = resolve_erp_customer(_hdr_res, tido=tido, nudo=nudo)
        if _res and not _is_cf_name(_res.get("customer_name")):
            hdr["cliente_nombre"] = _res["customer_name"]
            if _res.get("customer_rut"):     hdr["cliente_rut"] = _res["customer_rut"]
            if _res.get("customer_email"):   hdr["email"] = hdr.get("email") or _res["customer_email"]
            if _res.get("customer_phone"):   hdr["telefono"] = hdr.get("telefono") or _res["customer_phone"]
            if _res.get("dispatch_address"): hdr["direccion"] = hdr.get("direccion") or _res["dispatch_address"]
            if _res.get("dispatch_commune"): hdr["comuna"] = hdr.get("comuna") or _res["dispatch_commune"]
        hdr["_resolver_diag"] = {
            "source": _res.get("source") if _res else "none",
            "confidence": _res.get("confidence") if _res else "low",
            "chain": _res.get("fallback_chain") if _res else [],
        }
        # Solo ahora, si SIGUE vacío, ponemos placeholder limpio
        if not (hdr.get("cliente_nombre") or "").strip():
            hdr["cliente_nombre"] = "Consumidor Final"
    except Exception as _e_res2:
        print(f"[asignar_documento] resolver falló: {_e_res2}", flush=True)
        if not (hdr.get("cliente_nombre") or "").strip():
            hdr["cliente_nombre"] = "Consumidor Final"

    postal_destino = _comuna_to_postal(hdr.get("comuna", ""))

    return jsonify({
        "ok":     True,
        "header": {**hdr, "postal_destino": postal_destino},
        "lineas": lineas_out,
        "totales": {
            "total_qty":    int(tot_qty),
            "total_bultos": int(tot_bultos),
            "peso_kg":      round(tot_kg,   3),
            "peso_pv":      round(tot_pv,   3),
            "vol_cm3":      round(tot_vol,  1),
            "peso_pred":    round(tot_pred, 3),
        },
        "tipos_doc":     TIPOS_DOC_CUBICADOR,
        "zzenvio_valor": round(zzenvio_valor, 0),
        "from_cache":    _from_cache,
    })


@app.route("/api/asignar/tarifa-fedex", methods=["POST"])
@login_required
def api_asignar_tarifa_fedex():
    """
    Consulta la tarifa FedEx para el envío.
    POST JSON: { peso_pred, zona_id, es_residencial, es_remoto, valor_neto }
      zona_id: 1=RM, 2=V/VI/VII, 3=VIII/IX, 4=XIV/X, 5=XI/XII, 6=I/II/III/IV
    Responde: { ok, costo_total, detalle:{servicio, tiempo_transito, peso_facturable, recargos} }
    """
    if not g.permissions.get("cubicador"):
        return jsonify({"error": "Sin permiso"}), 403

    data       = request.get_json(silent=True) or {}
    peso_pred  = float(data.get("peso_pred", 0) or 0)
    zona_id    = str(data.get("zona_id", "1")).strip()
    es_resid   = bool(data.get("es_residencial", False))
    es_remoto  = bool(data.get("es_remoto", False))
    valor_neto = float(data.get("valor_neto", 0) or 0)

    if peso_pred <= 0:
        return jsonify({"error": "Peso predominante debe ser mayor a 0"}), 400

    # Mapear zona_id → postal de referencia para la API FedEx
    _ZONA_POSTAL = {
        "1": "8320000",   # RM Santiago
        "2": "2340000",   # Valparaíso
        "3": "4030000",   # Concepción
        "4": "5480000",   # Puerto Montt
        "5": "6200000",   # Punta Arenas
        "6": "1240000",   # Antofagasta
    }
    postal_dest = _ZONA_POSTAL.get(zona_id, "8320000")

    try:
        result = _fedex_calc_rate(peso_pred, postal_dest, es_residencial=es_resid)
        if "error" in result:
            return jsonify({"error": result["error"]}), 422

        costo_base = result["tarifa"]
        # Recargos adicionales según opciones marcadas
        recargo_resid  = 4200 if es_resid  else 0
        recargo_remoto = 6800 if es_remoto else 0
        costo_total    = costo_base + recargo_resid + recargo_remoto

        return jsonify({
            "ok":          True,
            "costo_total": round(costo_total, 0),
            "detalle": {
                "servicio":        result["servicio"],
                "tiempo_transito": result["tiempo_transito"],
                "peso_facturable": result["peso_facturable"],
                "costo_base":      round(costo_base, 0),
                "recargo_resid":   recargo_resid,
                "recargo_remoto":  recargo_remoto,
                "recargos_fedex":  result.get("recargos", []),
                "moneda":          result["moneda"],
                "zona_id":         zona_id,
            },
        })
    except Exception as ex:
        import traceback
        print(f"[FEDEX ERROR] {ex}\n{traceback.format_exc()}")
        return jsonify({"error": f"Error FedEx API: {str(ex)}"}), 502


# ════════════════════════════════════════════════════════════════
#  COTIZADOR INTEGRAL DE COURIERS — todos los couriers en paralelo
# ════════════════════════════════════════════════════════════════
#  POST /api/asignar/cotizar-couriers
#
#  Devuelve cotización lado-a-lado de TODOS los couriers activos
#  para un peso + comuna + valor dado. FedEx vía API (live), el resto
#  vía tabla transport_courier_comunas. Paralelizado con
#  ThreadPoolExecutor — objetivo <2s.
# ────────────────────────────────────────────────────────────────

@app.route("/api/asignar/cotizar-couriers", methods=["POST"])
@login_required
def api_asignar_cotizar_couriers():
    """Cotiza TODOS los couriers activos en paralelo para el envío dado.

    Body JSON:
      {
        "peso_kg": 173.89,
        "peso_pred_kg": 173.89,   # opcional, si difiere del peso real
        "comuna": "Lo Barnechea",
        "es_residencial": false,
        "valor_neto": 1571566
      }

    Response:
      {
        "ok": true,
        "comuna_resuelta": "Lo Barnechea",
        "peso_facturable": 174,
        "cotizaciones": [
          {
            "courier_id": 1,
            "courier_nombre": "FedEx",
            "tiene_cobertura": true,
            "fuente": "api"|"tabla"|"no_cobertura",
            "precio": 126933,
            "moneda": "CLP",
            "tiempo_transito": "1-2 días",
            "servicio": "FedEx Standard",
            "logo_url": "...",
            "subtotal": 126933,
            "mensaje": null
          },
          ...
        ],
        "recomendado_id": 2   # el más barato con cobertura
      }
    """
    if not g.permissions.get("cubicador"):
        return jsonify({"error": "Sin permiso"}), 403

    import concurrent.futures as _cf
    import time as _t_start

    t0 = _t_start.time()
    data       = request.get_json(silent=True) or {}
    peso_kg    = float(data.get("peso_kg") or 0)
    peso_pred  = float(data.get("peso_pred_kg") or peso_kg or 0)
    comuna     = (data.get("comuna") or "").strip()
    es_resid   = bool(data.get("es_residencial", False))
    valor_neto = float(data.get("valor_neto", 0) or 0)
    # Contexto del documento para audit trail (opcional)
    doc_tido   = (data.get("tido") or "").strip() or None
    doc_nudo   = (data.get("nudo") or "").strip() or None

    # El peso facturable es max(peso_pred, peso_kg, 0.5)
    peso_fact = max(peso_pred, peso_kg, 0.5)

    if peso_fact <= 0:
        return jsonify({"error": "Peso debe ser mayor a 0"}), 400
    if not comuna:
        return jsonify({"error": "Comuna requerida para cotizar"}), 400

    # 1) Couriers activos + tarifas de la comuna en UN solo round-trip
    # Esto evita 9 queries serializadas (200ms cada una = 1.8s ahorrados).
    try:
        couriers = mysql_fetchall(
            "SELECT id, nombre, logo_url, logo_square_url, tipo "
            "FROM transport_couriers WHERE activo=1 ORDER BY nombre"
        ) or []
    except Exception as e:
        return jsonify({"error": f"Error cargando couriers: {e}"}), 500

    if not couriers:
        return jsonify({"ok": True, "cotizaciones": [], "recomendado_id": None,
                        "peso_facturable": round(peso_fact, 1),
                        "comuna_resuelta": comuna,
                        "mensaje": "No hay couriers activos configurados."})

    # Pre-cargar tarifas de la comuna para TODOS los couriers en una query
    # → mapa {courier_id: {precios_json, dias_transito, zona}}
    try:
        tarifa_rows = mysql_fetchall(
            "SELECT courier_id, precios_json, dias_transito, zona "
            "FROM transport_courier_comunas "
            "WHERE LOWER(TRIM(comuna))=LOWER(TRIM(%s))",
            (comuna,)
        ) or []
        tarifa_map = {r['courier_id']: r for r in tarifa_rows}
    except Exception as e:
        print(f"[cotizar-couriers] error pre-load tarifas: {e}", flush=True)
        tarifa_map = {}

    # Capturar el app actual para que los hilos pushen su propio app_context (sólo FedEx)
    _flask_app = app

    # Helper: resolver precio desde precios_json + peso, devolviendo TRACE completo.
    # Sin hit MySQL — usa precios_json ya cargado en memoria.
    def _resolve_precio_con_trace(precios_json_raw, peso_kg):
        """Devuelve dict { precio, bracket_aplicado, bracket_upper, formula,
                            json_brackets_disponibles, advertencias } o None."""
        if not precios_json_raw:
            return None
        try:
            precios = json.loads(precios_json_raw)
        except Exception:
            return None
        brackets = []
        for key, price in precios.items():
            if price is None:
                continue
            try:
                upper = _parse_peso_upper(key)
                brackets.append((upper, float(price), str(key)))
            except Exception:
                pass
        if not brackets:
            return None
        brackets.sort(key=lambda x: x[0])
        match = None
        formula = ""
        for upper, price, key_orig in brackets:
            if peso_kg <= upper:
                match = (upper, price, key_orig)
                formula = f"Bracket exact match: {peso_kg}kg <= {upper}kg (key='{key_orig}')"
                break
        if match is None:
            upper, price, key_orig = brackets[-1]
            match = (upper, price, key_orig)
            formula = f"Sobre bracket máximo: usa último (key='{key_orig}')"

        upper, price, key_orig = match
        advs = []
        if peso_kg >= 5 and price < 1000:
            advs.append(
                f"Precio sospechosamente bajo: ${int(price)} para {peso_kg}kg "
                f"(podría ser precio/kg en lugar de total) — verificar tabla"
            )
        elif peso_kg >= 50 and price < 5000:
            advs.append(
                f"Precio bajo para peso alto: ${int(price)} para {peso_kg}kg "
                f"(~${price/peso_kg:.0f}/kg) — verificar tabla"
            )
        elif peso_kg >= 10 and price > 0 and (price / peso_kg) < 50:
            advs.append(
                f"Tarifa <$50/kg: ${int(price)} para {peso_kg}kg → verificar tabla"
            )

        return {
            "precio": float(price),
            "bracket_aplicado": key_orig,
            "bracket_upper": float(upper),
            "formula": formula,
            "json_brackets_disponibles": [b[2] for b in brackets],
            "advertencias": advs,
        }

    # Helper: arma la cotización con el modelo NUEVO (tabla macro, sin margen/IVA).
    # 'precio' = base de tabla + seguro 1,2% (igual que la macro de SPHS).
    _ETD_MACRO = {'felca': '2-4 días', 'milling': '2-4 días',
                  'clickex': '24-48 h', 'fedex_directo': '1-2 días'}

    def _macro_cotizacion_dict(cid, nombre, logo, slug, r):
        base, seguro, precio = r["base"], r["seguro"], r["precio"]
        estimado = bool(r.get("estimado"))
        desglose = {
            "precio_costo": base, "precio_venta": precio,
            "margen_pct": 0, "margen_clp": 0, "iva_pct": 0, "iva_clp": 0,
            "seguro_clp": seguro,
        }
        formula = f"Tabla SPHS: {r['tramo']} → ${base:,}".replace(",", ".")
        if seguro:
            formula += f" + seguro 1,2% ${seguro:,}".replace(",", ".")
        formula += f" = ${precio:,}".replace(",", ".")
        return {
            "courier_id": cid, "courier_nombre": nombre, "logo_url": logo,
            "tiene_cobertura": True, "fuente": ("estimado" if estimado else "tabla"),
            "precio": precio, "precio_costo": base, "moneda": "CLP",
            "tiempo_transito": _ETD_MACRO.get(slug, "—"),
            "servicio": ("Estimado (~FedEx −10%)" if estimado else "Standard"),
            "subtotal": precio, "desglose": desglose, "mensaje": None,
            "trace": {
                "bracket": r["tramo"], "bracket_upper": None, "formula": formula,
                "fuente": ("estimado" if estimado else "tabla_macro"),
                "validado": (not estimado),
                "advertencias": (["Tarifa estimada: aún sin tabla propia para esta comuna/peso"]
                                 if estimado else []),
                "json_brackets_disponibles": [], "peso_usado": peso_fact,
                "comuna_db": r["comuna_tabla"], "desglose": desglose,
            },
        }

    def _no_cobertura_dict(cid, nombre, logo):
        return {
            "courier_id": cid, "courier_nombre": nombre, "logo_url": logo,
            "tiene_cobertura": False, "fuente": "no_cobertura",
            "mensaje": f"Sin cobertura para {comuna}",
            "trace": {"bracket": None, "bracket_upper": None,
                      "formula": f"Sin tarifa en tabla para {comuna}",
                      "fuente": "no_cobertura", "validado": False,
                      "advertencias": [f"Sin cobertura para {comuna}"],
                      "json_brackets_disponibles": [], "peso_usado": peso_fact,
                      "comuna_db": None},
        }

    # 2) Función worker que cotiza UN courier — TODO con tabla del macro.
    #    FedEx usa la tabla "FedEx Directo" (Daniel: sin API por ahora).
    #    Solo se muestran: FedEx, Felca, Milling, Clickex (Envíame vendrá pronto).
    def _cotizar_uno(c):
        cid      = c['id']
        nombre   = c['nombre'] or ''
        is_fedex = ('fedex' in _ttar._strip(nombre).lower())
        logo     = c.get('logo_url') or c.get('logo_square_url')
        slug     = 'fedex_directo' if is_fedex else _ttar.slug_para_courier(nombre)

        if slug not in ('felca', 'milling', 'clickex', 'fedex_directo'):
            return None  # Starken / Blue / Envíame / etc.: ocultos por ahora

        try:
            r = _ttar.cotizar(slug, comuna, peso_fact, valor_neto)
            d = _macro_cotizacion_dict(cid, nombre, logo, slug, r) if r \
                else _no_cobertura_dict(cid, nombre, logo)
        except Exception as ex_each:
            print(f"[cotizar courier {nombre}] error: {ex_each}", flush=True)
            d = {
                "courier_id": cid, "courier_nombre": nombre, "logo_url": logo,
                "tiene_cobertura": False, "fuente": "error",
                "mensaje": "Error al cotizar",
            }
        d["_slug"] = slug
        return d

    # 3) Ejecutar TODAS las cotizaciones en paralelo
    cotizaciones = []
    max_workers = min(len(couriers), 8) or 1
    with _cf.ThreadPoolExecutor(max_workers=max_workers) as pool:
        futures = {pool.submit(_cotizar_uno, c): c for c in couriers}
        try:
            for fut in _cf.as_completed(futures, timeout=10):
                try:
                    cotizaciones.append(fut.result(timeout=0.5))
                except Exception as e_fut:
                    c = futures[fut]
                    cotizaciones.append({
                        "courier_id": c['id'],
                        "courier_nombre": c['nombre'],
                        "logo_url": c.get('logo_url'),
                        "tiene_cobertura": False,
                        "fuente": "error",
                        "mensaje": f"Timeout o error: {e_fut}",
                    })
        except _cf.TimeoutError:
            # Si superamos el timeout global, marcamos los que no respondieron
            for fut, c in futures.items():
                if not fut.done():
                    cotizaciones.append({
                        "courier_id": c['id'],
                        "courier_nombre": c['nombre'],
                        "logo_url": c.get('logo_url'),
                        "tiene_cobertura": False,
                        "fuente": "timeout",
                        "mensaje": "Tiempo de cotización excedido",
                    })

    # Filtrar couriers excluidos (None) y DEDUPLICAR por servicio (_slug): si hay
    # dos couriers en la BD que mapean al mismo servicio (ej. "Milling" y "Melling"),
    # se conserva solo uno — preferimos el que tenga cobertura/logo.
    cotizaciones = [c for c in cotizaciones if c]
    _por_slug = {}
    for c in cotizaciones:
        sl = c.get("_slug") or c.get("courier_nombre")
        prev = _por_slug.get(sl)
        if prev is None:
            _por_slug[sl] = c
        else:
            # preferir el que tiene cobertura; si empatan, el que tiene logo
            mejor = c if (c.get("tiene_cobertura") and not prev.get("tiene_cobertura")) else prev
            if mejor is prev and not prev.get("logo_url") and c.get("logo_url"):
                mejor = c
            _por_slug[sl] = mejor
    cotizaciones = list(_por_slug.values())

    # 4) Ordenar (con cobertura primero, sin cobertura al final) y elegir recomendado
    con_cobertura = [c for c in cotizaciones if c.get('tiene_cobertura')]
    sin_cobertura = [c for c in cotizaciones if not c.get('tiene_cobertura')]
    con_cobertura.sort(key=lambda c: float(c.get('subtotal') or c.get('precio') or 99999999))
    cotizaciones_ord = con_cobertura + sin_cobertura

    recomendado_id = con_cobertura[0]['courier_id'] if con_cobertura else None

    # 5) Marcar tarifas VALIDADAS (consulta única) + INSERT audit por cada cotización.
    #    Esto produce el audit trail completo. Si la tabla audit no existe → silencioso.
    try:
        # Set de tarifas marcadas como validadas para esta comuna (1 sola query)
        validated_keys = set()
        try:
            rows_val = mysql_fetchall(
                "SELECT DISTINCT courier_id, bracket_aplicado "
                "FROM courier_tariff_audit "
                "WHERE LOWER(TRIM(comuna))=LOWER(TRIM(%s)) AND validado=1",
                (comuna,)
            ) or []
            for rv in rows_val:
                validated_keys.add((rv['courier_id'], rv['bracket_aplicado']))
        except Exception:
            pass

        cotizado_por = current_username() or 'sistema'
        for c in cotizaciones_ord:
            trace = c.get('trace') or {}
            cid = c.get('courier_id')
            bracket = trace.get('bracket')
            # Marcar validado si está en el set
            if cid and bracket and (cid, bracket) in validated_keys:
                trace['validado'] = True
                c['trace'] = trace
            # Insertar audit con desglose costo+margen+IVA completo
            try:
                audit_id = _audit_cotizacion(
                    courier_id=cid,
                    courier_nombre=c.get('courier_nombre'),
                    comuna=comuna,
                    peso_kg=peso_kg,
                    peso_pred_kg=peso_pred,
                    bracket_aplicado=bracket or '—',
                    precio_calculado=c.get('precio'),     # precio venta (con margen+IVA)
                    formula_aplicada=trace.get('formula', ''),
                    fuente=c.get('fuente', 'tabla'),
                    validado=trace.get('validado', False),
                    notas=(c.get('mensaje') or None),
                    documento_tido=doc_tido,
                    documento_nudo=doc_nudo,
                    cotizado_por=cotizado_por,
                    desglose=c.get('desglose'),           # ← componentes auditables
                )
                if audit_id:
                    c['audit_id'] = audit_id
            except Exception as ex_aud:
                print(f"[cotizar-couriers] audit error courier={cid}: {ex_aud}", flush=True)
    except Exception as ex_outer:
        print(f"[cotizar-couriers] error audit pass: {ex_outer}", flush=True)

    elapsed = round(_t_start.time() - t0, 3)
    return jsonify({
        "ok":               True,
        "comuna_resuelta":  comuna,
        "peso_facturable":  round(peso_fact, 1),
        "cotizaciones":     cotizaciones_ord,
        "recomendado_id":   recomendado_id,
        "total_couriers":   len(cotizaciones),
        "tiempo_seg":       elapsed,
    })


