def _tr_log(entity_type, entity_id, accion, detalle=""):
    """Registra un evento de trazabilidad en transport_logs."""
    try:
        conn = get_db()
        with conn.cursor() as cur:
            cur.execute(
                "INSERT INTO transport_logs (entity_type,entity_id,accion,detalle,usuario) "
                "VALUES (%s,%s,%s,%s,%s)",
                (entity_type, entity_id, accion, detalle, current_username())
            )
        conn.commit()
    except Exception:
        pass


def _norm_comuna_key(s: str) -> str:
    return (s or "").upper().replace("Ñ", "N").replace("Á", "A").replace("É", "E") \
        .replace("Í", "I").replace("Ó", "O").replace("Ú", "U")


def _detect_comuna(text: str) -> str:
    """Detecta una comuna chilena conocida dentro de texto libre (OBDO/dirección).
    Devuelve el nombre de la comuna (title-case) o '' si no encuentra."""
    if not text:
        return ""
    norm = _norm_comuna_key(text)
    best = ""
    for key in _COMUNA_POSTAL:  # claves ya normalizadas (upper, sin acentos)
        if len(key) < 4:
            continue
        if key in norm and len(key) > len(best):
            best = key
    return best.title() if best else ""


def _parse_obdo(obdo: str) -> dict:
    """Parsea texto libre OBDO: 'Nombre - dirección [comuna] - teléfono - email'.

    Extrae nombre cuando el ERP devuelve cliente genérico (BOLETA/CONSUMIDOR
    FINAL/PARTICULAR) en boletas — el dato real va en OBDO/TEXTO1.
    """
    import re as _re
    result = {"direccion": "", "telefono": "", "email": "", "comuna": "", "nombre": ""}
    if not obdo:
        return result
    original = obdo
    email_m = _re.search(r'[\w.+-]+@[\w-]+\.[a-zA-Z]{2,}', obdo)
    if email_m:
        result["email"] = email_m.group(0)
        obdo = obdo.replace(email_m.group(0), "")
    phone_m = _re.search(r'\b[\+56]*\s*[29]\d{7,8}\b', obdo)
    if phone_m:
        result["telefono"] = phone_m.group(0).strip()
        obdo = obdo.replace(phone_m.group(0), "")
    # Intentar separar nombre + dirección. Heurística: si arranca con
    # palabras alfabéticas (no dígitos), el primer trozo antes de un
    # separador típico (/, -, –, ,) o salto de línea ES el nombre.
    rest = _re.sub(r'[-–]+\s*$', '', obdo).strip(' -–\n')
    name_dir_m = _re.match(
        r'^\s*([A-Za-zÁÉÍÓÚÑáéíóúñ][A-Za-zÁÉÍÓÚÑáéíóúñ\.\' ]{1,60})\s*[/\-–,\n]\s*(.+)$',
        rest
    )
    if name_dir_m:
        candidato = name_dir_m.group(1).strip()
        resto     = name_dir_m.group(2).strip()
        # Si el candidato tiene pinta de calle (Av., Calle, Pasaje, etc.) NO es nombre
        if not _re.match(r'^(av\.?|avenida|calle|psje\.?|pasaje|camino|ruta|carretera|los|las|el|la)\b',
                         candidato, _re.IGNORECASE):
            result["nombre"]    = candidato
            result["direccion"] = resto
        else:
            result["direccion"] = rest
    else:
        result["direccion"] = rest
    result["comuna"] = _detect_comuna(original)
    return result


def _clasif_from_skus(skus):
    """Determina la clasificación de un compromiso según sus SKUs ZZ."""
    skus = [s.strip().upper() for s in skus if s]
    if not skus: return "despacho"
    if all(s == "ZZRETIRO" for s in skus): return "retiro"
    if any(s == "ZZINSTALACION" for s in skus): return "instalacion"
    if any(s in ("ZZSERVTEC", "ZZINGREPUESTO", "ZZINGARREQUIP") for s in skus): return "mantencion"
    return "despacho"


def _tr_fetch_from_erp(tido, nudo):
    """
    Obtiene un documento del ERP vía API y lo guarda/actualiza en transport_commitments.
    Usa la misma lógica de _cubicador_fetch pero orientada a transporte.
    Retorna el id del commitment o None.
    """
    from datetime import datetime as _dt

    def _parse_date(s):
        if not s:
            return None
        try:
            return _dt.fromisoformat(str(s).replace("Z", "+00:00")).date()
        except Exception:
            return None

    # ── Obtener el documento por la MISMA vía confiable que el cubicador:
    #    SQL-first (Random SQL Server). La REST /documentos/render estaba dando
    #    502 Bad Gateway y reventaba este flujo. Fallback a REST solo si SQL falla.
    doc = None
    try:
        # Cached: si el cubicador buscó este doc hace <5 min, no toca el ERP.
        doc = _cubicador_fetch_doc_via_sql_cached(tido, nudo)
    except Exception as e_sql:
        print(f"[tr_fetch] SQL falló para {tido}/{nudo}: {e_sql}", flush=True)
        doc = None

    if not doc:
        TOKEN = ERP_CONFIG.get("api_token", "")
        if tido in _ERP_TIDO_NUDO_MAP:
            erp_tido, nudo_fn = _ERP_TIDO_NUDO_MAP[tido]
            nudos = _nudo_variants(nudo_fn(nudo))
        else:
            erp_tido = tido
            nudos = _nudo_variants(nudo)
        _last_err = None
        for nv in nudos:
            try:
                body = _erp_get("/documentos/render",
                                {"tido": erp_tido, "nudo": nv, "empresa": "01"},
                                TOKEN, timeout=12)
                data = body.get("data") or []
                if data:
                    rh = data[0].get("maeedo") or {}
                    obdo = _parse_obdo((rh.get("OBDO") or rh.get("TEXTO1") or "").strip())
                    doc = {
                        "cliente_nombre": (rh.get("NOKOEN") or "").strip(),
                        "cliente_rut":    (rh.get("ENDO") or "").strip(),
                        "comuna":         (rh.get("CMEN") or rh.get("NOKOZO") or
                                           rh.get("NOKOCOMU") or "").strip(),
                        "direccion":      obdo.get("direccion") or (rh.get("DIENDESP") or "").strip(),
                        "telefono":       obdo.get("telefono") or "",
                        "email":          obdo.get("email") or "",
                        "valor_neto":     float(rh.get("VANEDO") or 0),
                        "valor_bruto":    float(rh.get("VABRDO") or 0),
                        "fecha":          rh.get("FEEMDO"),
                        "fecha_entrega":  rh.get("FEER"),
                        "guia_numero":    (rh.get("NUDO_GIA") or rh.get("NUDGIA") or "").strip() or None,
                        "lineas_raw":     data[0].get("maeddo") or [],
                    }
                    break
            except Exception as e:
                _last_err = e
                continue
        if not doc:
            return None, (f"ERP no responde: {_last_err}" if _last_err else "No encontrado en ERP")

    # ── Líneas crudas (mismo shape que usa el cubicador) y filtro ZZ ──
    raw_lineas = doc.get("lineas_raw") or []
    zz_lines = [l for l in raw_lineas
                if (l.get("KOPRCT") or "").strip().upper() in {s.upper() for s in ZZ_SKUS}]
    if not zz_lines:
        return None, "Documento sin líneas ZZ"

    saldo_total = sum(
        float(l.get("CAPRCO1") or 0) - float(l.get("CAPRAD1") or 0)
        for l in zz_lines
    )
    tiene_saldo = 1 if saldo_total > 0 else 0

    # ── Datos del header (campos friendly, ya enriquecidos por el motor/SQL) ──
    cliente_nombre = (doc.get("cliente_nombre") or "").strip().title()
    endo           = (doc.get("cliente_rut") or doc.get("endo") or "").strip()
    comuna         = (doc.get("comuna") or "").strip()
    direccion      = (doc.get("direccion") or "").strip()
    telefono       = (doc.get("telefono") or "").strip()
    email          = (doc.get("email") or "").strip()
    # Enriquecer desde OBDO si el ERP dejó vacíos (boletas a consumidor final:
    # el contacto va en observaciones). Igual criterio que el cubicador.
    _obs = (doc.get("observaciones") or "").strip()
    if _obs:
        _p = _parse_obdo(_obs)
        if not direccion and _p["direccion"]: direccion = _p["direccion"]
        if not telefono and _p["telefono"]:   telefono  = _p["telefono"]
        if not email and _p["email"]:         email     = _p["email"]
        if not comuna:                         comuna    = _p["comuna"] or _detect_comuna(direccion)
    if not cliente_nombre:
        cliente_nombre = "Consumidor final"
    valor_neto     = float(doc.get("valor_neto") or 0)
    valor_bruto    = float(doc.get("valor_bruto") or 0)
    fecha_em       = _parse_date(doc.get("fecha"))
    fecha_ent      = _parse_date(doc.get("fecha_entrega"))
    guia_numero    = doc.get("guia_numero")

    skus_upper = [(l.get("KOPRCT") or "").strip().upper() for l in zz_lines]
    clasificacion = _clasif_from_skus(skus_upper)
    costo_zz = sum(float(l.get("PPPRNE") or 0) for l in zz_lines)

    # NOTA: get_db() devuelve conexión del pool via g. NO llamar conn.close()
    # al final — teardown_appcontext la cierra. Cerrar aquí deja g._db
    # apuntando a una conexión cerrada.
    conn = get_db()
    try:
        with conn.cursor() as cur:
            cur.execute("""
                INSERT INTO transport_commitments
                  (tido,nudo,endo,fecha_emision,fecha_entrega,cliente_nombre,cliente_rut,
                   comuna,direccion,telefono,email,valor_neto,valor_bruto,costo_zz,
                   tiene_saldo,guia_numero,clasificacion,erp_synced_at,created_by,updated_by)
                VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,NOW(),%s,%s)
                ON DUPLICATE KEY UPDATE
                  fecha_emision=VALUES(fecha_emision), fecha_entrega=VALUES(fecha_entrega),
                  cliente_nombre=VALUES(cliente_nombre), cliente_rut=VALUES(cliente_rut),
                  comuna=VALUES(comuna), direccion=VALUES(direccion),
                  telefono=VALUES(telefono), email=VALUES(email),
                  valor_neto=VALUES(valor_neto), valor_bruto=VALUES(valor_bruto),
                  costo_zz=CASE WHEN costo_zz=0 THEN VALUES(costo_zz) ELSE costo_zz END,
                  tiene_saldo=VALUES(tiene_saldo), guia_numero=VALUES(guia_numero),
                  clasificacion=VALUES(clasificacion), erp_synced_at=NOW(),
                  updated_by=VALUES(updated_by)
            """, (
                tido, str(nudo), endo, fecha_em, fecha_ent,
                cliente_nombre, endo,
                comuna,
                direccion, telefono, email,
                valor_neto, valor_bruto,
                costo_zz, tiene_saldo, guia_numero, clasificacion,
                current_username(), current_username()
            ))
            comm_id = cur.lastrowid or mysql_fetchone(
                "SELECT id FROM transport_commitments WHERE tido=%s AND nudo=%s",
                (tido, str(nudo))
            )["id"]

            # zz_envio = lo que SPHS COBRÓ por el despacho (= suma PPPRNE de líneas ZZ).
            # Se preserva aparte de costo_zz (que el flujo de manifiesto sobrescribe
            # con el costo del courier). Permite el match cobrado-vs-costo en el manifiesto.
            try:
                cur.execute(
                    "UPDATE transport_commitments SET zz_envio=%s WHERE id=%s",
                    (costo_zz, comm_id)
                )
            except Exception:
                pass  # columna garantizada por _ensure_transporte_columns; no fatal

            # Líneas ZZ
            cur.execute("DELETE FROM transport_commitment_lines WHERE commitment_id=%s", (comm_id,))
            for l in zz_lines:
                cant  = float(l.get("CAPRCO1") or 0)
                cantd = float(l.get("CAPRAD1")  or 0)
                cur.execute("""
                    INSERT INTO transport_commitment_lines
                      (commitment_id,koprct,nokopr,cantidad,cant_despachada,saldo,bodega)
                    VALUES (%s,%s,%s,%s,%s,%s,%s)
                """, (comm_id,
                      (l.get("KOPRCT") or "").strip().upper(),
                      (l.get("NOKOPR") or "").strip(),
                      cant, cantd, cant - cantd,
                      (l.get("BOSULIDO") or "").strip()))
        conn.commit()
    except Exception:
        try: conn.rollback()
        except Exception: pass
        raise
    # Importante: NO cerrar conn aquí (es del pool). teardown_appcontext lo hace.

    return comm_id, None


# ── SYNC MASIVO ERP → TRANSPORTE ────────────────────────────────

def _tr_bulk_sync_erp_mysql(fecha_desde, fecha_hasta, tidos_override=None):
    """
    Sincronización masiva desde el ERP (Random SQL Server, vía _random_sql_query).

    NUEVA LÓGICA (2026-05-14):
    Trae TODOS los documentos con líneas ZZ del rango, INCLUIDOS los que
    ya fueron despachados completamente. Cada documento se clasifica en uno
    de 3 estados según su cobertura (cantidad despachada vs cantidad total):
        - 'Pendiente'           → saldo > 0 y SIN guía (NUDGIA NULL)
        - 'Despachado parcial'  → saldo > 0 y CON guía (NUDGIA con valor)
        - 'Entregado'           → saldo == 0 (todo el ZZ ya despachado)

    Eso permite ver el flujo completo del día: lo que falta, lo que se
    está moviendo, y lo que ya salió. El frontend filtra por tab.

    FIX 2026-05-19: el ERP Random es SQL Server, no MySQL. Se reescribe
    la query usando T-SQL (TOP, STUFF FOR XML PATH en vez de
    GROUP_CONCAT, CASE en vez de GREATEST, LEFT JOIN a MAEEN para nombre
    del cliente, LEFT JOIN a MAEEDOOB para observaciones, sin columnas
    inexistentes en SQL Server). Va vía `_random_sql_query` (read-only
    blindado).

    UPDATE 2026-05-19 (Daniel): el sync por defecto sólo trae **BLV** (Boleta)
    y **GDV** (Guía Despacho). El resto de TIDOs (FCV, NVV, NVI, COV…) se
    importan vía el endpoint manual `/transporte/api/importar-forzado`
    cuando el usuario superadmin lo necesita. Esto evita engordar el monitor
    con ventas-internas que no son despachos reales.
    `tidos_override` permite forzar otra lista desde código (ej. backfill).

    Retorna (count_ok, list_errors).
    """
    zz_list      = [s.upper() for s in ZZ_SKUS]
    zz_in        = ",".join(["%s"] * len(zz_list))
    TIDOS_VALIDOS = tuple(tidos_override) if tidos_override else ("BLV", "GDV")
    tido_in      = ",".join(["%s"] * len(TIDOS_VALIDOS))

    # T-SQL: agregación por header con subqueries blindadas.
    # - `STUFF((SELECT DISTINCT ',' + KOPRCT ... FOR XML PATH('')), 1, 1, '')`
    #   reemplaza a GROUP_CONCAT(DISTINCT ...) que SQL Server no soporta.
    # - `LEFT JOIN MAEEN` mapea ENDO ("RUT-DV") → MAEEN.RTEN (RUT base sin DV).
    # - `LEFT JOIN MAEEDOOB` para obs/dirección de despacho.
    # - Comuna: SQL Server no tiene las columnas NOKOZO/NOKOCOMU/etc.
    #   Solo dejamos CMEN (código de comuna). El front lo resuelve si necesita.
    sql = f"""
        SELECT
            LTRIM(RTRIM(h.TIDO)) AS TIDO,
            LTRIM(RTRIM(h.NUDO)) AS NUDO,
            LTRIM(RTRIM(COALESCE(h.ENDO, ''))) AS ENDO,
            LTRIM(RTRIM(COALESCE(h.SUENDO, ''))) AS SUENDO,
            h.FEEMDO,
            h.FEER,
            -- Nombre del cliente con fallback en cascada:
            --  1. MAEEN.NOKOENAMP (nombre largo registrado en entidades)
            --  2. MAEEN.NOKOEN (nombre corto)
            --  3. MAEEDO.SUENDO (subcliente del documento — clave para BLV
            --     a consumidor final donde no hay ENDO en MAEEN)
            --  4. literal 'Consumidor final' si nada de lo anterior existe
            LTRIM(RTRIM(COALESCE(
                NULLIF(LTRIM(RTRIM(en.NOKOENAMP)), ''),
                NULLIF(LTRIM(RTRIM(en.NOKOEN)),    ''),
                NULLIF(LTRIM(RTRIM(h.SUENDO)),     ''),
                'Consumidor final'
            ))) AS NOKOEN,
            LTRIM(RTRIM(COALESCE(o.OBDO, o.TEXTO1, ''))) AS OBDO,
            LTRIM(RTRIM(COALESCE(o.DIENDESP, ''))) AS DIENDESP,
            COALESCE(h.VANEDO, 0) AS VANEDO,
            COALESCE(h.VABRDO, 0) AS VABRDO,
            LTRIM(RTRIM(COALESCE(en.CMEN, ''))) AS COMUNA,
            -- NUDGIA no existe como columna directa en MAEEDO de SQL Server.
            -- 2026-05-20: dejamos string vacío. La lógica Python clasifica como
            -- 'Pendiente' (sin guía) cuando NUDGIA='', y como 'Despachado parcial'
            -- solo cuando hay valor. Para detectar guía-relacionada habría que
            -- hacer JOIN a MAEDOREL o consultar otra tabla — fuera de scope ahora.
            '' AS NUDGIA,
            (SELECT COALESCE(SUM(d.CAPRCO1), 0)
               FROM MAEDDO d
              WHERE d.IDMAEEDO = h.IDMAEEDO
                AND UPPER(LTRIM(RTRIM(d.KOPRCT))) IN ({zz_in})) AS cant_total_zz,
            (SELECT COALESCE(SUM(COALESCE(d.CAPRAD1, 0)), 0)
               FROM MAEDDO d
              WHERE d.IDMAEEDO = h.IDMAEEDO
                AND UPPER(LTRIM(RTRIM(d.KOPRCT))) IN ({zz_in})) AS cant_despachada_zz,
            (SELECT COALESCE(SUM(
                       CASE WHEN d.CAPRCO1 - COALESCE(d.CAPRAD1, 0) > 0
                            THEN d.CAPRCO1 - COALESCE(d.CAPRAD1, 0)
                            ELSE 0 END), 0)
               FROM MAEDDO d
              WHERE d.IDMAEEDO = h.IDMAEEDO
                AND UPPER(LTRIM(RTRIM(d.KOPRCT))) IN ({zz_in})) AS saldo_zz,
            (SELECT COALESCE(SUM(COALESCE(d.PPPRNE, 0)), 0)
               FROM MAEDDO d
              WHERE d.IDMAEEDO = h.IDMAEEDO
                AND UPPER(LTRIM(RTRIM(d.KOPRCT))) IN ({zz_in})) AS costo_zz_sum,
            STUFF(
                (SELECT ',' + UPPER(LTRIM(RTRIM(d2.KOPRCT)))
                   FROM MAEDDO d2
                  WHERE d2.IDMAEEDO = h.IDMAEEDO
                    AND UPPER(LTRIM(RTRIM(d2.KOPRCT))) IN ({zz_in})
                  GROUP BY UPPER(LTRIM(RTRIM(d2.KOPRCT)))
                  ORDER BY UPPER(LTRIM(RTRIM(d2.KOPRCT)))
                  FOR XML PATH('')), 1, 1, '') AS zz_skus
        FROM MAEEDO h
        LEFT JOIN MAEEDOOB o ON o.IDMAEEDO = h.IDMAEEDO
        LEFT JOIN MAEEN en ON LTRIM(RTRIM(en.RTEN)) =
              CASE
                WHEN CHARINDEX('-', h.ENDO) > 0
                  THEN LTRIM(RTRIM(SUBSTRING(h.ENDO, 1, CHARINDEX('-', h.ENDO) - 1)))
                ELSE LTRIM(RTRIM(COALESCE(h.ENDO, '')))
              END
        WHERE LTRIM(RTRIM(h.TIDO)) IN ({tido_in})
          AND h.FEEMDO >= %s
          AND h.FEEMDO <= %s
          AND EXISTS (
                SELECT 1 FROM MAEDDO d3
                 WHERE d3.IDMAEEDO = h.IDMAEEDO
                   AND UPPER(LTRIM(RTRIM(d3.KOPRCT))) IN ({zz_in})
          )
          AND (h.ESDO IS NULL OR LTRIM(RTRIM(h.ESDO)) <> 'NULO')
        ORDER BY h.FEEMDO DESC
    """

    # Params: 5 grupos de zz (4 subqueries + EXISTS + STUFF) + tidos + 2 fechas.
    # Recuento por orden de aparición en el SQL:
    #   subquery cant_total, cant_despachada, saldo, costo, STUFF, EXISTS  = 6
    params = (
        zz_list +  # cant_total_zz
        zz_list +  # cant_despachada_zz
        zz_list +  # saldo_zz
        zz_list +  # costo_zz_sum
        zz_list +  # STUFF (zz_skus)
        list(TIDOS_VALIDOS) +
        [fecha_desde, fecha_hasta] +
        zz_list    # EXISTS
    )

    try:
        rows = _random_sql_query(sql, tuple(params), max_rows=1000)
    except PermissionError as pe:
        return 0, [f"Error de seguridad SQL: {pe}"]
    except Exception as exc:
        print(f"[tr-bulk-sync-sql] error: {exc}", flush=True)
        return 0, [f"Error al consultar ERP: {exc}"]

    if rows is None:
        return 0, ["No se pudo conectar al ERP (SQL Server)"]
    if not rows:
        rows = []

    # PERF 2026-05-20: batch INSERT con executemany en vez de un INSERT por
    # fila. Antes: ~500ms/doc (red Chile→Paris × N round-trips). Después: 1
    # round-trip total para la tabla. 30 días: 125s → <15s típico.
    #
    # Mantiene exactamente el mismo SQL UPSERT (con la cláusula CASE que
    # protege estados manuales del operador) — MySQL evalúa el CASE por fila
    # contra el valor actual de la columna en disco, así que executemany
    # preserva la regla "no pisar decisión manual" sin cambios.
    import time as _time
    _t0 = _time.time()

    def _pd(val):
        if not val: return None
        if hasattr(val, "date"): return val.date()
        try:
            from datetime import datetime as _dt
            return _dt.fromisoformat(str(val).replace("Z", "")).date()
        except Exception:
            return None

    # Timestamp único de sync (todos los rows de esta corrida quedan con el
    # mismo erp_synced_at — equivale a NOW() del INSERT antiguo, pero ahora
    # se pasa como parámetro porque VALUES debe ser puro %s).
    from datetime import datetime as _dt_now
    _sync_now = _dt_now.now()
    count, errs = 0, []
    batch = []      # lista de tuplas para executemany
    refs  = []      # paralelo a batch — para reportar errores con TIDO/NUDO
    for row in rows:
        try:
            tido  = (row.get("TIDO") or "").strip()
            nudo  = (row.get("NUDO") or "").strip()
            endo  = (row.get("ENDO") or "").strip()
            nombre = (row.get("NOKOEN") or "").strip().title()
            obdo  = (row.get("OBDO") or "").strip()
            parsed = _parse_obdo(obdo)
            dir_  = parsed["direccion"] or (row.get("DIENDESP") or "").strip()
            tel   = parsed["telefono"]
            mail  = parsed["email"]
            comuna = (row.get("COMUNA") or "").strip()
            vneto  = float(row.get("VANEDO") or 0)
            vbruto = float(row.get("VABRDO") or 0)
            costo_zz = float(row.get("costo_zz_sum") or 0)
            guia  = (row.get("NUDGIA") or "").strip() or None
            cant_total      = float(row.get("cant_total_zz") or 0)
            cant_despachada = float(row.get("cant_despachada_zz") or 0)
            saldo_zz        = float(row.get("saldo_zz") or 0)
            zz_present = (row.get("zz_skus") or "").upper()
            _zz_list_bulk = [s.strip() for s in zz_present.split(",") if s.strip()]
            clasif = _clasif_from_skus(_zz_list_bulk) if _zz_list_bulk else "despacho"

            # ── Clasificación automática del estado según cobertura ──
            # Reglas (de más urgente a menos):
            #   saldo > 0  y SIN guía  → 'Pendiente'  (todavía hay que despachar)
            #   saldo > 0  y CON guía  → 'Despachado parcial' (salió algo, falta resto)
            #   saldo == 0             → 'Entregado'  (salió todo, doc cerrado)
            if saldo_zz <= 0:
                estado_auto = "Entregado"
                tiene_saldo_flag = 0
            elif guia:
                estado_auto = "Despachado parcial"
                tiene_saldo_flag = 1
            else:
                estado_auto = "Pendiente"
                tiene_saldo_flag = 1

            # % cobertura para mostrar en UI (ej: 80% despachado)
            cobertura_pct = 0
            if cant_total > 0:
                cobertura_pct = round((cant_despachada / cant_total) * 100, 1)

            fecha_em  = _pd(row.get("FEEMDO"))
            fecha_ent = _pd(row.get("FEER"))

            batch.append((
                tido, nudo, endo, fecha_em, fecha_ent,
                nombre, endo, comuna, dir_, tel, mail,
                obdo[:2000] if obdo else None,
                zz_present[:120] if zz_present else None,
                vneto, vbruto, costo_zz,
                tiene_saldo_flag, guia, clasif, estado_auto,
                cobertura_pct, cant_total, cant_despachada,
                _sync_now, 'sync', 'sync',
            ))
            refs.append((tido, nudo))
        except Exception as e2:
            errs.append(f"{row.get('TIDO')} {row.get('NUDO')}: {e2}")

    if not batch:
        _ms = int((_time.time() - _t0) * 1000)
        print(f"[tr-bulk-sync-sql] OK rango {fecha_desde} -> {fecha_hasta}: 0 docs en {_ms}ms (nada que insertar)", flush=True)
        return 0, errs or None

    # IMPORTANTE: el estado solo se sobreescribe automáticamente si actualmente
    # está en uno de los estados "auto-gestionados" (Pendiente, Despachado
    # parcial, Entregado, Despachado, En proceso). Si el operador marcó otro
    # estado manualmente (Problema, Garantía, Prioridad, etc.) se respeta — la
    # sincronización no debe pisar decisiones del usuario. La cláusula CASE
    # funciona idéntico bajo executemany porque MySQL evalúa por fila contra
    # el valor existente en disco.
    #
    # PERF: el VALUES(...) debe contener SOLO %s placeholders (sin NOW() ni
    # literales) — esa es la única forma de que pymysql.executemany re-escriba
    # N INSERTs en un único multi-row INSERT (ver pymysql RE_INSERT_VALUES).
    # Por eso NOW() lo movimos al ON DUPLICATE clause (erp_synced_at) y para
    # el INSERT inicial pasamos NOW() como literal `=NOW()` no es posible
    # dentro de VALUES, así que usamos CURRENT_TIMESTAMP via DEFAULT del
    # esquema. Los literales 'sync' van como placeholder en cada tupla.
    sql_upsert = """
        INSERT INTO transport_commitments
          (tido,nudo,endo,fecha_emision,fecha_entrega,
           cliente_nombre,cliente_rut,
           comuna,direccion,telefono,email,
           observaciones,zz_skus,
           valor_neto,valor_bruto,costo_zz,
           tiene_saldo,guia_numero,clasificacion,estado,
           cobertura_pct,cant_total_zz,cant_despachada_zz,
           erp_synced_at,created_by,updated_by)
        VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
        ON DUPLICATE KEY UPDATE
          fecha_emision =VALUES(fecha_emision),
          fecha_entrega =VALUES(fecha_entrega),
          cliente_nombre=VALUES(cliente_nombre),
          cliente_rut   =VALUES(cliente_rut),
          comuna        =VALUES(comuna),
          direccion     =VALUES(direccion),
          telefono      =VALUES(telefono),
          email         =VALUES(email),
          observaciones =VALUES(observaciones),
          zz_skus       =VALUES(zz_skus),
          valor_neto    =VALUES(valor_neto),
          valor_bruto   =VALUES(valor_bruto),
          costo_zz      =CASE WHEN costo_zz=0 THEN VALUES(costo_zz) ELSE costo_zz END,
          tiene_saldo   =VALUES(tiene_saldo),
          guia_numero   =VALUES(guia_numero),
          clasificacion =VALUES(clasificacion),
          estado        =CASE
                           WHEN estado IN ('Pendiente','Despachado parcial','Entregado','Despachado','En proceso')
                             THEN VALUES(estado)
                           ELSE estado
                         END,
          cobertura_pct =VALUES(cobertura_pct),
          cant_total_zz =VALUES(cant_total_zz),
          cant_despachada_zz=VALUES(cant_despachada_zz),
          erp_synced_at =VALUES(erp_synced_at)
    """

    local_conn = get_mysql()
    try:
        try:
            with local_conn.cursor() as cur:
                cur.executemany(sql_upsert, batch)
            local_conn.commit()
            count = len(batch)
        except Exception as e_bulk:
            # Si executemany falla globalmente (ej. un row con datos
            # inválidos rompe toda la batch en pymysql), caemos a
            # ejecutar fila por fila para identificar el culpable y
            # salvar las demás. No es la ruta esperada — solo seguro.
            try: local_conn.rollback()
            except Exception: pass
            print(f"[tr-bulk-sync-sql] executemany falló ({e_bulk}); fallback fila-a-fila", flush=True)
            for params_row, (tido, nudo) in zip(batch, refs):
                try:
                    with local_conn.cursor() as cur:
                        cur.execute(sql_upsert, params_row)
                    local_conn.commit()
                    count += 1
                except Exception as e_row:
                    try: local_conn.rollback()
                    except Exception: pass
                    errs.append(f"{tido} {nudo}: {e_row}")
    finally:
        local_conn.close()

    _ms = int((_time.time() - _t0) * 1000)
    print(f"[tr-bulk-sync-sql] OK rango {fecha_desde} -> {fecha_hasta}: {count} docs en {_ms}ms", flush=True)
    return count, errs or None


def _tr_import_from_excel(file_bytes, filename):
    """
    Importa documentos desde un Excel/CSV exportado del ERP.
    Detecta columnas automáticamente.
    Retorna (count_ok, list_errors, preview_rows).
    """
    import io

    # ── intentar openpyxl (xlsx) o csv ──
    rows_raw = []
    try:
        import openpyxl
        wb = openpyxl.load_workbook(io.BytesIO(file_bytes), data_only=True)
        ws = wb.active
        headers = [str(c.value or "").strip().upper() for c in next(ws.iter_rows(min_row=1, max_row=1))]
        for row in ws.iter_rows(min_row=2, values_only=True):
            rows_raw.append(dict(zip(headers, [str(v or "").strip() for v in row])))
    except Exception:
        # Fallback: CSV
        import csv
        decoded = file_bytes.decode("utf-8-sig", errors="replace")
        reader  = csv.DictReader(io.StringIO(decoded))
        for row in reader:
            rows_raw.append({k.strip().upper(): str(v or "").strip() for k, v in row.items()})

    if not rows_raw:
        return 0, ["Archivo vacío o formato no reconocido"], []

    # ── mapeo flexible de columnas ──
    COL_MAP = {
        "tido":   ["TIDO", "TIPO", "TIPO DOCUMENTO", "TIPODOC", "TIPO DOC"],
        "nudo":   ["NUDO", "NUMERO", "N°", "NDOC", "NUM DOC", "NUMERO DOC", "FOLIO"],
        "nombre": ["NOKOEN", "NOMBRE", "CLIENTE", "RAZON SOCIAL", "NOMBRE CLIENTE"],
        "fecha":  ["FEEMDO", "FECHA", "FECHA EMISION", "FECHA EMISIÓN", "FECHA DOC"],
        "sku":    ["KOPRCT", "SKU", "CODIGO", "CÓDIGO", "PRODUCTO"],
        "cant":   ["CAPRCO1", "CANTIDAD", "QTY", "CANT", "CANT PEDIDA"],
        "cantd":  ["CAPRAD1", "DESPACHADO", "DESPACHO", "CANT DESPACHADA", "ENTREGADO"],
        "costo":  ["PPPRNE", "PRECIO", "VALOR", "COSTO", "MONTO"],
        "comuna": ["CMEN", "NOKOZO", "COMUNA", "CIUDAD"],
        "dir":    ["DIENDESP", "DIRECCION", "DIRECCIÓN", "OBDO"],
        "rut":    ["ENDO", "RUT", "RUTEN", "RUT CLIENTE"],
    }

    def find_col(row, candidates):
        for c in candidates:
            if c in row:
                return row[c]
        return ""

    # Agrupar por TIDO+NUDO
    from collections import defaultdict
    docs = defaultdict(lambda: {"lineas": [], "header": {}})
    skipped = 0
    for row in rows_raw:
        tido  = find_col(row, COL_MAP["tido"]).upper().strip()
        nudo  = find_col(row, COL_MAP["nudo"]).strip()
        sku   = find_col(row, COL_MAP["sku"]).upper().strip()
        if not tido or not nudo:
            skipped += 1
            continue
        key = (tido, nudo)
        docs[key]["header"] = row
        if sku in {s.upper() for s in ZZ_SKUS}:
            docs[key]["lineas"].append(row)

    # Filtrar docs que tienen al menos una línea ZZ con saldo
    count, errs, preview = 0, [], []
    local_conn = get_mysql()
    try:
        for (tido, nudo), doc in docs.items():
            if not doc["lineas"]:
                continue  # sin líneas ZZ → ignorar
            hrow = doc["header"]
            nombre  = find_col(hrow, COL_MAP["nombre"]).title()
            fecha_s = find_col(hrow, COL_MAP["fecha"])
            comuna  = find_col(hrow, COL_MAP["comuna"])
            dir_    = find_col(hrow, COL_MAP["dir"])
            rut     = find_col(hrow, COL_MAP["rut"])
            costo   = sum(
                _safe_float(find_col(l, COL_MAP["costo"]))
                for l in doc["lineas"]
            )
            saldo   = sum(
                max(_safe_float(find_col(l, COL_MAP["cant"])) -
                    _safe_float(find_col(l, COL_MAP["cantd"])), 0)
                for l in doc["lineas"]
            )
            if saldo <= 0:
                continue
            zz_skus = {find_col(l, COL_MAP["sku"]).upper() for l in doc["lineas"]}
            clasif  = "retiro" if zz_skus == {"ZZRETIRO"} else "despacho"

            # Parsear fecha
            fecha_em = None
            if fecha_s:
                for fmt in ("%Y-%m-%d", "%d/%m/%Y", "%d-%m-%Y", "%d/%m/%y"):
                    try:
                        from datetime import datetime as _dt
                        fecha_em = _dt.strptime(fecha_s[:10], fmt).date()
                        break
                    except Exception:
                        continue

            try:
                with local_conn.cursor() as cur:
                    cur.execute("""
                        INSERT INTO transport_commitments
                          (tido,nudo,endo,fecha_emision,cliente_nombre,cliente_rut,
                           comuna,direccion,costo_zz,tiene_saldo,clasificacion,
                           erp_synced_at,created_by,updated_by)
                        VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,1,%s,NOW(),'excel','excel')
                        ON DUPLICATE KEY UPDATE
                          fecha_emision =VALUES(fecha_emision),
                          cliente_nombre=VALUES(cliente_nombre),
                          cliente_rut   =VALUES(cliente_rut),
                          comuna        =VALUES(comuna),
                          direccion     =VALUES(direccion),
                          costo_zz      =CASE WHEN costo_zz=0 THEN VALUES(costo_zz) ELSE costo_zz END,
                          tiene_saldo   =1,
                          clasificacion =VALUES(clasificacion),
                          erp_synced_at =NOW()
                    """, (tido, nudo, rut, fecha_em, nombre, rut,
                          comuna, dir_, costo, clasif))
                local_conn.commit()
                count += 1
                if len(preview) < 5:
                    preview.append({"tido": tido, "nudo": nudo, "cliente": nombre,
                                    "clasif": clasif, "saldo_lineas": saldo})
            except Exception as e2:
                errs.append(f"{tido} {nudo}: {e2}")
    finally:
        local_conn.close()

    return count, errs or None, preview


def _safe_float(v):
    try:
        return float(str(v).replace(",", ".").strip() or 0)
    except Exception:
        return 0.0


# ── RUTAS TRANSPORTE ─────────────────────────────────────────────

def _tr_required(fn):
    """Decorator: requiere permiso transporte."""
    from functools import wraps
    @wraps(fn)
    @login_required
    def wrapper(*a, **kw):
        if not g.permissions.get("transporte"):
            flash("Sin acceso al módulo Transporte.", "danger")
            return redirect(url_for("index"))
        return fn(*a, **kw)
    return wrapper


@app.route("/transporte/api/sync-hoy", methods=["POST"])
@_tr_required
def tr_sync_hoy():
    """Sincronización rápida: importa TODOS los documentos emitidos HOY al monitor.

    Reutiliza _tr_bulk_sync_erp_mysql con fecha_desde=fecha_hasta=hoy.
    Pensado para usuario hace click 1 vez al día (ej: al llegar a la oficina)
    y deja el monitor al día con cualquier factura/boleta emitida.

    Performance: típicamente 5-15 docs/día × ~300ms cada uno = 2-5 seg.
    """
    from datetime import date as _date
    hoy = _date.today()
    hoy_str = hoy.strftime("%Y-%m-%d")
    try:
        count, errs = _tr_bulk_sync_erp_mysql(hoy_str, hoy_str)
    except Exception as e:
        print(f"[tr_sync_hoy] ERROR: {e}", flush=True)
        return jsonify({"ok": False, "error": f"Error consultando ERP: {e}"}), 500
    try:
        _tr_log("commitment", 0, "sync_hoy",
                f"ERP MySQL HOY ({hoy_str}): {count} importados, {len(errs or [])} errores")
    except Exception: pass
    return jsonify({
        "ok": True,
        "fecha": hoy.strftime("%d/%m/%Y"),
        "importados": count,
        "errores": (errs or [])[:10],
        "mensaje": (
            f"✓ {count} documento(s) importados del día {hoy.strftime('%d/%m/%Y')}"
            if count else
            f"No hay documentos nuevos emitidos hoy ({hoy.strftime('%d/%m/%Y')})"
        ),
    })


@app.route("/transporte/api/sync", methods=["POST"])
@_tr_required
def tr_sync():
    """Sincronización masiva desde ERP MySQL. Recibe fecha_desde y fecha_hasta."""
    data = request.get_json(silent=True) or {}
    fecha_desde = data.get("fecha_desde") or ""
    fecha_hasta = data.get("fecha_hasta") or ""

    # Validar fechas
    from datetime import datetime as _dt, date as _date, timedelta as _td
    try:
        fd = _dt.strptime(fecha_desde, "%Y-%m-%d").date()
        fh = _dt.strptime(fecha_hasta, "%Y-%m-%d").date()
    except Exception:
        # Default: últimos 60 días
        fh = _date.today()
        fd = fh - _td(days=60)

    count, errs = _tr_bulk_sync_erp_mysql(str(fd), str(fh))
    _tr_log("commitment", 0, "sync_masivo",
            f"ERP MySQL {fd}→{fh}: {count} importados, {len(errs or [])} errores")
    return jsonify({
        "ok": True,
        "importados": count,
        "errores": (errs or [])[:10],
        "rango": f"{fd.strftime('%d/%m/%Y')} → {fh.strftime('%d/%m/%Y')}",
    })


@app.route("/transporte/api/compromisos")
@_tr_required
def tr_compromisos_json():
    """Versión JSON del monitor para carga AJAX.

    NUEVO 2026-05-14: parámetro `vista` permite filtrar por la categoría
    del flujo de transporte (en vez de mezclar todo en una sola lista):

      vista=pendientes  → docs aún por despachar (tiene_saldo=1, sin guía)
      vista=parciales   → docs con guía pero saldo > 0 (despacho parcial)
      vista=entregados  → docs completamente despachados (tiene_saldo=0)
      vista=todos       → todo (default)

    También devuelve `cobertura_pct`, `guia_numero` y los conteos de cada
    categoría para que el frontend pinte los badges del tab.
    """
    from datetime import date as _date, timedelta as _td
    periodo = request.args.get("periodo", "")
    hoy = _date.today()
    _def_desde = (hoy - _td(days=30)).strftime("%Y-%m-%d")
    _def_hasta = hoy.strftime("%Y-%m-%d")
    if periodo == "mes":   fecha_desde, fecha_hasta = _def_desde, _def_hasta
    elif periodo == "3m":  fecha_desde, fecha_hasta = (hoy-_td(days=90)).strftime("%Y-%m-%d"), _def_hasta
    elif periodo == "año": fecha_desde, fecha_hasta = hoy.strftime("%Y-01-01"), _def_hasta
    elif periodo == "todo": fecha_desde = fecha_hasta = ""
    else:
        fecha_desde = request.args.get("fecha_desde", _def_desde).strip()
        fecha_hasta = request.args.get("fecha_hasta", _def_hasta).strip()

    estado = request.args.get("estado","")
    clasif = request.args.get("clasificacion","")
    q      = request.args.get("q","").strip()
    vista  = (request.args.get("vista","") or "").strip().lower()

    where, params = [], []
    # Filtro por vista (categoría del flujo)
    if vista == "pendientes":
        where.append("tiene_saldo=1 AND (guia_numero IS NULL OR guia_numero='')")
    elif vista == "parciales":
        where.append("tiene_saldo=1 AND guia_numero IS NOT NULL AND guia_numero<>''")
    elif vista == "entregados":
        where.append("tiene_saldo=0")
    elif vista == "todos":
        pass  # sin filtro adicional
    else:
        # default histórico: solo con saldo (compat con clientes que no mandan vista)
        where.append("tiene_saldo=1")

    if estado: where.append("estado=%s"); params.append(estado)
    if clasif: where.append("clasificacion=%s"); params.append(clasif)
    if q:
        where.append("(cliente_nombre LIKE %s OR nudo LIKE %s OR tido LIKE %s OR comuna LIKE %s OR guia_numero LIKE %s)")
        qp = f"%{q}%"; params += [qp,qp,qp,qp,qp]
    if fecha_desde: where.append("fecha_emision >= %s"); params.append(fecha_desde)
    if fecha_hasta: where.append("fecha_emision <= %s"); params.append(fecha_hasta)

    rows = mysql_fetchall(
        "SELECT * FROM transport_commitments WHERE " + " AND ".join(where) +
        " ORDER BY fecha_emision DESC LIMIT 500", tuple(params)
    )

    result = []
    for r in rows:
        # NUEVO 2026-05-19: incluir direccion/observaciones/zz_skus para que
        # el monitor pueda mostrarlos sin re-consultar el ERP.
        # Las columnas pueden no existir todavía en BDs viejas — usar .get()
        # con default, ya que DictCursor de pymysql devuelve dicts reales.
        result.append({
            "id":           r["id"],
            "tido":         r["tido"],
            "nudo":         r["nudo"],
            "fecha":        r["fecha_emision"].strftime("%d/%m/%Y") if r["fecha_emision"] else "",
            "cliente":      r["cliente_nombre"] or "—",
            "rut":          r["cliente_rut"] or "",
            "comuna":       r["comuna"] or "—",
            "direccion":    r.get("direccion") or "",
            "observaciones": r.get("observaciones") or r.get("notas") or "",
            "zz_skus":      r.get("zz_skus") or "",
            "estado":       r["estado"] or "Pendiente",
            "costo_zz":     float(r["costo_zz"] or 0),
            "clasificacion":r["clasificacion"] or "despacho",
            "guia_numero":  r.get("guia_numero") or "",
            "cobertura_pct":float(r.get("cobertura_pct") or 0),
            "tiene_saldo":  int(r.get("tiene_saldo") or 0),
        })

    # Conteos por categoría — independientes del filtro `vista` aplicado.
    # Permite al frontend mostrar badge "Pendientes: 12" sin segunda llamada.
    base_where, base_params = [], []
    if clasif: base_where.append("clasificacion=%s"); base_params.append(clasif)
    if q:
        base_where.append("(cliente_nombre LIKE %s OR nudo LIKE %s OR tido LIKE %s OR comuna LIKE %s OR guia_numero LIKE %s)")
        qp = f"%{q}%"; base_params += [qp,qp,qp,qp,qp]
    if fecha_desde: base_where.append("fecha_emision >= %s"); base_params.append(fecha_desde)
    if fecha_hasta: base_where.append("fecha_emision <= %s"); base_params.append(fecha_hasta)
    base_w = (" WHERE " + " AND ".join(base_where)) if base_where else ""

    conteos_row = mysql_fetchone(
        "SELECT "
        " SUM(CASE WHEN tiene_saldo=1 AND (guia_numero IS NULL OR guia_numero='') THEN 1 ELSE 0 END) AS pendientes,"
        " SUM(CASE WHEN tiene_saldo=1 AND guia_numero IS NOT NULL AND guia_numero<>'' THEN 1 ELSE 0 END) AS parciales,"
        " SUM(CASE WHEN tiene_saldo=0 THEN 1 ELSE 0 END) AS entregados,"
        " COUNT(*) AS total"
        " FROM transport_commitments" + base_w,
        tuple(base_params)
    ) or {}

    return jsonify({
        "ok": True,
        "compromisos": result,
        "total": len(result),
        "conteos": {
            "pendientes": int(conteos_row.get("pendientes") or 0),
            "parciales":  int(conteos_row.get("parciales") or 0),
            "entregados": int(conteos_row.get("entregados") or 0),
            "total":      int(conteos_row.get("total") or 0),
        },
        "vista": vista or "default",
    })


@app.route("/transporte/api/limpiar-monitor", methods=["POST"])
@_tr_required
def tr_limpiar_monitor():
    """Borra TODOS los registros del monitor (transport_commitments).
    Requiere superadmin o admin para evitar borrados accidentales.
    El próximo sync vuelve a poblar con los datos al día desde el ERP.
    """
    if not (g.permissions.get("superadmin") or g.permissions.get("admin")):
        return jsonify({"ok": False, "error": "Solo admin/superadmin puede limpiar el monitor."}), 403

    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            # Contar antes para el log
            cur.execute("SELECT COUNT(*) AS n FROM transport_commitments")
            n_antes = (cur.fetchone() or {}).get("n", 0)
            # Borrar líneas primero (FK), después items de manifiestos vinculados, después el header.
            # Las líneas y manifest_items tienen ON DELETE CASCADE, así que con un solo DELETE basta.
            cur.execute("DELETE FROM transport_commitments")
        conn.commit()
        try:
            _tr_log("commitment", 0, "limpieza_total",
                    f"Monitor limpiado por {current_username()}: {n_antes} registros eliminados")
        except Exception:
            pass
        return jsonify({
            "ok": True,
            "eliminados": int(n_antes or 0),
            "mensaje": f"Monitor limpio. Se eliminaron {n_antes} registros. Sincroniza HOY para repoblar.",
        })
    finally:
        conn.close()


# ═══════════════════════════════════════════════════════════════════════
#  LIMPIAR-TODO (superadmin) — versión con confirm_text obligatorio
#  Daniel pidió un endpoint paralelo que exija texto exacto "LIMPIAR"
#  para evitar accidentes de teclado. Se mantiene `limpiar-monitor` arriba
#  por compatibilidad con el botón legacy.
# ═══════════════════════════════════════════════════════════════════════
@app.route("/transporte/api/limpiar-todo", methods=["POST"])
@_tr_required
def tr_limpiar_todo():
    """Borra TODOS los registros del monitor exigiendo confirm_text='LIMPIAR'.
    Solo superadmin. Usado por el botón "Limpiar monitor" del rediseño.
    """
    if not g.permissions.get("superadmin"):
        return jsonify({"ok": False, "error": "Solo superadmin puede limpiar el monitor."}), 403

    data = request.get_json(silent=True) or {}
    confirm_text = (data.get("confirm_text") or "").strip().upper()
    if confirm_text != "LIMPIAR":
        return jsonify({
            "ok": False,
            "error": "Para confirmar la operación escribe exactamente 'LIMPIAR'.",
        }), 400

    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            cur.execute("SELECT COUNT(*) AS n FROM transport_commitments")
            n_antes = (cur.fetchone() or {}).get("n", 0)
            cur.execute("DELETE FROM transport_commitments")
        conn.commit()
        try:
            _tr_log("commitment", 0, "limpieza_total_v2",
                    f"limpiar-todo por {current_username()}: {n_antes} registros eliminados")
        except Exception:
            pass
        return jsonify({
            "ok": True,
            "eliminados": int(n_antes or 0),
            "mensaje": f"Monitor limpio. Se eliminaron {n_antes} registros.",
        })
    finally:
        conn.close()


# ═══════════════════════════════════════════════════════════════════════
#  IMPORTAR-FORZADO (superadmin) — trae un doc específico por TIDO+NUDO
#  ignorando la whitelist del sync (BLV/GDV). Útil cuando hay que meter
#  un NVV, FCV, GTI etc. al monitor para probar o casos puntuales.
#  Reusa _tr_fetch_from_erp (motor blindado vía API ERP).
# ═══════════════════════════════════════════════════════════════════════
@app.route("/transporte/api/importar-forzado", methods=["POST"])
@_tr_required
def tr_importar_forzado():
    """Importa un documento puntual del ERP saltándose la whitelist del sync.

    Solo superadmin. Body JSON:
        { "tido": "NVV", "nudo": "31005" }
    Retorna { ok, id, mensaje } o { ok:false, error }.
    """
    if not g.permissions.get("superadmin"):
        return jsonify({"ok": False, "error": "Solo superadmin puede importar forzado."}), 403

    data = request.get_json(silent=True) or {}
    tido = (data.get("tido") or "").strip().upper()
    nudo = (data.get("nudo") or "").strip()
    if not tido or not nudo:
        return jsonify({"ok": False, "error": "Faltan parámetros tido/nudo."}), 400

    # Lista de TIDOs aceptados (defensiva — evita SQLi por tido raro)
    TIDOS_OK = {"FCV", "BLV", "GDV", "NVV", "NVI", "COV", "GDP", "GDI", "RGI",
                "NVR", "VD", "WEB", "GTI"}
    if tido not in TIDOS_OK:
        return jsonify({
            "ok": False,
            "error": f"TIDO '{tido}' no permitido. Usa: {', '.join(sorted(TIDOS_OK))}",
        }), 400

    try:
        comm_id, err = _tr_fetch_from_erp(tido, nudo)
    except Exception as e:
        print(f"[tr_importar_forzado] ERROR: {e}", flush=True)
        return jsonify({"ok": False, "error": f"Error consultando ERP: {e}"}), 500

    if err or not comm_id:
        return jsonify({"ok": False, "error": err or "No se pudo importar el documento."}), 404

    try:
        _tr_log("commitment", comm_id, "importar_forzado",
                f"{tido} {nudo} importado forzadamente por {current_username()}")
    except Exception:
        pass
    return jsonify({
        "ok": True,
        "id": comm_id,
        "mensaje": f"{tido} {nudo} importado al monitor (id #{comm_id}).",
    })


# ═══════════════════════════════════════════════════════════════════════
#  SYNC-STATUS — widget del header con estado del cron + del SQL ERP
#  Devuelve último sync, próximo sync, estado SQL Server y contadores.
# ═══════════════════════════════════════════════════════════════════════
@app.route("/transporte/api/sync-status", methods=["GET"])
@_tr_required
def tr_sync_status():
    """Estado en vivo del auto-sync para mostrar en el header del monitor.

    Retorna:
        {
          ok: true,
          ultimo_sync: ISO datetime UTC | None,
          ultimo_sync_relativo: "hace 23 min" | None,
          proximo_sync: ISO datetime UTC,
          proximo_sync_relativo: "en 1h 12m",
          sql_status: "ok" | "degradado" | "down",
          documentos_total: int,
          documentos_pendientes: int,
        }
    """
    import datetime as _dt
    from zoneinfo import ZoneInfo

    TZ = ZoneInfo("America/Santiago")
    now_cl = _dt.datetime.now(TZ)

    # ── Próximo slot del cron (mismas horas que _transporte_scheduler_loop)
    HORAS = [9, 12, 16]
    proxima = None
    for h in HORAS:
        cand = now_cl.replace(hour=h, minute=0, second=0, microsecond=0)
        if cand > now_cl:
            proxima = cand
            break
    if proxima is None:
        proxima = (now_cl + _dt.timedelta(days=1)).replace(
            hour=HORAS[0], minute=0, second=0, microsecond=0
        )

    def _rel(dt_target, _now=now_cl):
        delta = dt_target - _now
        secs = int(delta.total_seconds())
        sign = "en " if secs >= 0 else "hace "
        secs = abs(secs)
        if secs < 60:
            return sign + f"{secs}s"
        mins = secs // 60
        if mins < 60:
            return sign + f"{mins} min"
        hrs = mins // 60
        rem = mins % 60
        return sign + (f"{hrs}h {rem}m" if rem else f"{hrs}h")

    # ── Último sync conocido (tabla `transp_sync_lock` o `erp_synced_at` máx)
    ultimo_sync_iso = None
    ultimo_rel = None
    try:
        row = mysql_fetchone(
            "SELECT MAX(erp_synced_at) AS u FROM transport_commitments"
        )
        u = (row or {}).get("u") if row else None
        if u:
            # u puede ser datetime naive UTC del MySQL — anclar a UTC
            if u.tzinfo is None:
                u = u.replace(tzinfo=_dt.timezone.utc)
            ultimo_sync_iso = u.isoformat()
            u_cl = u.astimezone(TZ)
            ultimo_rel = _rel(u_cl)
    except Exception:
        pass

    # ── Estado SQL Server (ping rápido con una query mínima)
    sql_status = "down"
    try:
        rows = _random_sql_query("SELECT TOP 1 1 AS x", (), max_rows=1)
        if rows is not None:
            sql_status = "ok"
    except Exception as e:
        msg = str(e).lower()
        if "timeout" in msg or "timed" in msg:
            sql_status = "degradado"
        else:
            sql_status = "down"

    # ── Contadores rápidos
    documentos_total = 0
    documentos_pendientes = 0
    try:
        row = mysql_fetchone(
            "SELECT COUNT(*) AS n, "
            "  SUM(CASE WHEN tiene_saldo=1 THEN 1 ELSE 0 END) AS p "
            "FROM transport_commitments"
        )
        if row:
            documentos_total = int(row.get("n") or 0)
            documentos_pendientes = int(row.get("p") or 0)
    except Exception:
        pass

    return jsonify({
        "ok": True,
        "ultimo_sync": ultimo_sync_iso,
        "ultimo_sync_relativo": ultimo_rel,
        "proximo_sync": proxima.astimezone(_dt.timezone.utc).isoformat(),
        "proximo_sync_relativo": _rel(proxima),
        "proximo_sync_hhmm": proxima.strftime("%H:%M"),
        "sql_status": sql_status,
        "documentos_total": documentos_total,
        "documentos_pendientes": documentos_pendientes,
        "horas_cron": HORAS,
    })


# ═══════════════════════════════════════════════════════════════════════
#  SYNC MES ACTUAL — limpieza + resync de pendientes del mes en curso
# ═══════════════════════════════════════════════════════════════════════
def _tr_sync_mes_actual_bg(modo="resync"):
    """
    Sincronización del mes actual desde el primer día del mes hasta hoy.

    `modo`:
      - "resync"        → solo UPSERT desde ERP (no borra nada).
      - "limpiar_resync"→ borra pendientes del mes SIN manifiesto y luego resync.

    Trae todos los documentos BLV/FCV (+ GDV/NVV/NVI/COV) con líneas ZZ
    emitidos en el mes corriente (1 al hoy). Reutiliza la lógica probada
    de `_tr_bulk_sync_erp_mysql` para clasificación + UPSERT.

    Retorna dict: {ok, limpiados, sincronizados, errores, ts}.
    """
    from datetime import date as _date
    import datetime as _dt
    from zoneinfo import ZoneInfo

    now_cl = _dt.datetime.now(ZoneInfo("America/Santiago"))
    hoy_cl = now_cl.date()
    primer_dia = hoy_cl.replace(day=1)

    limpiados = 0
    if modo == "limpiar_resync":
        # Borrar SOLO los pendientes del mes actual que NO estén en manifiesto.
        # `transport_manifest_items` los referencia por `commitment_id`.
        # Nota: ON DELETE CASCADE en `transport_commitment_lines` se encarga
        # de las líneas. No tocamos los que YA están asignados a manifiesto.
        try:
            conn = get_mysql()
            with conn.cursor() as cur:
                cur.execute("""
                    SELECT COUNT(*) AS n FROM transport_commitments tc
                    WHERE tc.fecha_emision >= %s
                      AND tc.fecha_emision <= %s
                      AND NOT EXISTS (
                        SELECT 1 FROM transport_manifest_items mi
                         WHERE mi.commitment_id = tc.id
                      )
                """, (primer_dia, hoy_cl))
                limpiados = int((cur.fetchone() or {}).get("n", 0) or 0)
                cur.execute("""
                    DELETE tc FROM transport_commitments tc
                    WHERE tc.fecha_emision >= %s
                      AND tc.fecha_emision <= %s
                      AND NOT EXISTS (
                        SELECT 1 FROM transport_manifest_items mi
                         WHERE mi.commitment_id = tc.id
                      )
                """, (primer_dia, hoy_cl))
            conn.commit()
            conn.close()
        except Exception as e:
            print(f"[tr_sync_mes_actual] limpieza error: {e}", flush=True)

    # Resync desde ERP — del primer día del mes a hoy
    # FIX 2026-05-19: agregar logging detallado y traceback para diagnóstico
    import traceback as _tb_sync
    print(f"[transp-sync] inicio modo={modo} rango={primer_dia}..{hoy_cl}", flush=True)
    try:
        count_ok, errs = _tr_bulk_sync_erp_mysql(
            primer_dia.strftime("%Y-%m-%d"),
            hoy_cl.strftime("%Y-%m-%d"),
        )
        print(f"[transp-sync] OK sincronizados={count_ok} errores={len(errs or [])}", flush=True)
        if errs:
            for i, err in enumerate((errs or [])[:5]):
                print(f"[transp-sync] err[{i}]: {str(err)[:200]}", flush=True)
    except Exception as e:
        tb = _tb_sync.format_exc()
        print(f"[transp-sync] EXCEPCION: {e}\n{tb}", flush=True)
        # Clasificar el error para que el frontend muestre mensaje amigable
        err_msg = str(e)
        err_tipo = "ERP_DESCONOCIDO"
        if "timeout" in err_msg.lower() or "timed out" in err_msg.lower():
            err_tipo = "ERP_TIMEOUT"
            err_msg_amigable = "El ERP no respondió a tiempo. Reintenta en unos minutos."
        elif "auth" in err_msg.lower() or "login" in err_msg.lower() or "credential" in err_msg.lower():
            err_tipo = "ERP_AUTH"
            err_msg_amigable = "Credenciales ERP inválidas o expiradas. Contacta al administrador."
        elif "connection" in err_msg.lower() or "connect" in err_msg.lower():
            err_tipo = "ERP_CONNECTION"
            err_msg_amigable = "No se pudo conectar al ERP Random. Verifica conexión de red."
        elif "no module named" in err_msg.lower() or "import" in err_msg.lower():
            err_tipo = "ERP_MODULO"
            err_msg_amigable = "Módulo ERP no disponible en el servidor. Revisa requirements."
        else:
            err_msg_amigable = f"Error inesperado al consultar ERP: {err_msg[:100]}"
        return {
            "ok": False,
            "error": err_msg_amigable,
            "error_tipo": err_tipo,
            "error_detalle": err_msg[:300],
            "limpiados": limpiados,
            "sincronizados": 0,
            "errores": [{"tipo": err_tipo, "mensaje": err_msg[:300]}],
            "ts": now_cl.isoformat(),
        }

    try:
        _tr_log("commitment", 0, "sync_mes_actual",
                f"Mes {primer_dia.strftime('%Y-%m')} ({modo}): "
                f"limpiados={limpiados}, sincronizados={count_ok}, "
                f"errores={len(errs or [])}")
    except Exception:
        pass

    return {
        "ok": True,
        "limpiados": limpiados,
        "sincronizados": int(count_ok or 0),
        "errores": (errs or [])[:10],
        "rango": f"{primer_dia.strftime('%d/%m/%Y')} → {hoy_cl.strftime('%d/%m/%Y')}",
        "ts": now_cl.isoformat(),
        "mensaje": (
            f"{count_ok} documento(s) del mes actualizados"
            + (f" · {limpiados} pendientes limpiados" if limpiados else "")
        ),
    }


@app.route("/transporte/api/sync/diagnostico", methods=["GET"])
@_tr_required
def tr_sync_diagnostico():
    """Endpoint diagnóstico ERP — verifica conexión, credenciales y query de prueba.
    Útil cuando sync falla con '1 error(es) en el ERP' sin más detalle.
    """
    import time as _time_diag
    import datetime as _dt_diag
    from zoneinfo import ZoneInfo
    now_cl = _dt_diag.datetime.now(ZoneInfo("America/Santiago"))
    result = {
        "ok": True,
        "ts": now_cl.isoformat(),
        "checks": [],
    }

    # Check 1: ¿Está el módulo erp_engine cargado?
    try:
        import erp_engine
        result["checks"].append({"name": "modulo_erp_engine", "ok": True, "detalle": "Cargado"})
    except Exception as e:
        result["checks"].append({"name": "modulo_erp_engine", "ok": False, "detalle": f"NO cargado: {e}"})
        result["ok"] = False
        return jsonify(result), 200  # devolver 200 con detalle para que el frontend muestre

    # Check 2: ¿pymssql disponible?
    try:
        import pymssql
        result["checks"].append({"name": "pymssql_lib", "ok": True, "detalle": pymssql.__version__})
    except Exception as e:
        result["checks"].append({"name": "pymssql_lib", "ok": False, "detalle": f"NO instalado: {e}"})
        result["ok"] = False

    # Check 3: env vars del ERP
    import os as _os_diag
    erp_host = (_os_diag.environ.get("ERP_HOST") or "").strip()
    erp_user = (_os_diag.environ.get("ERP_USER") or "").strip()
    erp_db = (_os_diag.environ.get("ERP_DATABASE") or "").strip()
    erp_pass_present = bool(_os_diag.environ.get("ERP_PASSWORD"))
    erp_token_present = bool(_os_diag.environ.get("ERP_API_TOKEN"))
    result["checks"].append({
        "name": "env_vars",
        "ok": bool(erp_host and erp_user and (erp_pass_present or erp_token_present)),
        "detalle": {
            "ERP_HOST": erp_host if erp_host else "FALTA",
            "ERP_USER": erp_user if erp_user else "FALTA",
            "ERP_DATABASE": erp_db if erp_db else "(default)",
            "ERP_PASSWORD": "presente" if erp_pass_present else "FALTA",
            "ERP_API_TOKEN": "presente" if erp_token_present else "(opcional)",
        },
    })

    # Check 4: conexión real al ERP (con timeout 8s)
    t0 = _time_diag.time()
    try:
        client = erp_engine.get_client()
        if not client:
            result["checks"].append({"name": "erp_client", "ok": False, "detalle": "get_client() retorna None"})
            result["ok"] = False
        else:
            result["checks"].append({"name": "erp_client", "ok": True, "detalle": "Cliente inicializado"})
            # Check 5: query de prueba — peek a un documento BLV reciente
            try:
                docs = client.peek_recent(tido="BLV", limit=1)
                latency_ms = int((_time_diag.time() - t0) * 1000)
                result["checks"].append({
                    "name": "erp_query_peek",
                    "ok": True,
                    "detalle": f"Encontró {len(docs)} doc(s) en {latency_ms}ms",
                })
            except AttributeError:
                # Si peek_recent no existe, intentar fetch_document de un nudo de prueba
                try:
                    test_doc = client.fetch_document("BLV", 1)
                    latency_ms = int((_time_diag.time() - t0) * 1000)
                    result["checks"].append({
                        "name": "erp_query_test",
                        "ok": True,
                        "detalle": f"Query BLV/1 responde en {latency_ms}ms (existe={bool(test_doc)})",
                    })
                except Exception as e2:
                    result["checks"].append({
                        "name": "erp_query_test",
                        "ok": False,
                        "detalle": f"Query falla: {str(e2)[:200]}",
                    })
                    result["ok"] = False
            except Exception as e:
                result["checks"].append({
                    "name": "erp_query_peek",
                    "ok": False,
                    "detalle": f"Query falla: {str(e)[:200]}",
                })
                result["ok"] = False
    except Exception as e:
        import traceback as _tb_diag
        result["checks"].append({
            "name": "erp_conexion",
            "ok": False,
            "detalle": f"{str(e)[:200]}",
            "traceback": _tb_diag.format_exc()[:1000],
        })
        result["ok"] = False

    # Resumen
    fallidos = [c for c in result["checks"] if not c["ok"]]
    result["resumen"] = {
        "total_checks": len(result["checks"]),
        "fallidos": len(fallidos),
        "primer_error": fallidos[0]["detalle"] if fallidos else None,
    }
    return jsonify(result)


@app.route("/transporte/api/sync/mes-actual", methods=["POST"])
@_tr_required
def tr_sync_mes_actual():
    """Sincroniza TODOS los BLV+FCV del mes corriente desde ERP.

    Body opcional (JSON): {"limpiar": true} → borra pendientes del mes que
    no tengan manifiesto antes de resincronizar. Por defecto solo UPSERT.

    Permiso: admin / superadmin (limpieza). Usuarios con permiso transporte
    pueden disparar el resync sin limpiar.
    """
    data = request.get_json(silent=True) or {}
    quiere_limpiar = bool(data.get("limpiar"))
    if quiere_limpiar and not (g.permissions.get("superadmin") or g.permissions.get("admin")):
        return jsonify({
            "ok": False,
            "error": "Solo admin/superadmin puede limpiar pendientes."
        }), 403
    modo = "limpiar_resync" if quiere_limpiar else "resync"
    res = _tr_sync_mes_actual_bg(modo=modo)
    return jsonify(res), (200 if res.get("ok") else 500)


# ═══════════════════════════════════════════════════════════════════════
#  SCHEDULER CRON-LIKE — sync automático 09:00 / 11:00 / 15:00 / 17:00 CL
# ═══════════════════════════════════════════════════════════════════════
def _ensure_transp_sync_lock_table():
    """Tabla idempotente para coordinar el sync cross-worker."""
    try:
        conn = get_mysql()
        with conn.cursor() as cur:
            cur.execute("""
                CREATE TABLE IF NOT EXISTS transp_sync_lock (
                    id          INT PRIMARY KEY,
                    slot_hora   VARCHAR(20)  NOT NULL DEFAULT '',
                    hora_lock   DATETIME     NOT NULL,
                    worker_id   INT          NOT NULL,
                    ultima_corrida DATETIME  DEFAULT NULL
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
            """)
        conn.commit()
        conn.close()
    except Exception as e:
        print(f"[transp-cron] no se pudo asegurar transp_sync_lock: {e}", flush=True)


def _tr_intentar_lock_slot(slot_str):
    """Intenta tomar el lock para un slot dado (ej. '2026-05-19 09:00').

    Solo el primer worker que llegue insertará la fila. Los demás
    fallarán con duplicate key. Devuelve True si SE OBTUVO el lock
    (es decir, este worker debe correr la sync).
    """
    try:
        conn = get_mysql()
        with conn.cursor() as cur:
            # PRIMARY KEY = id=1 fijo. Usamos UPDATE con WHERE para distinguir
            # quién corre. Estrategia: insertar/upsert con `slot_hora` único.
            # Si la fila tiene un slot_hora != actual, lo pisamos y ganamos.
            # Si ya tiene el slot_hora actual, NO ganamos (otro worker corrió).
            cur.execute("""
                INSERT INTO transp_sync_lock (id, slot_hora, hora_lock, worker_id, ultima_corrida)
                VALUES (1, %s, NOW(), %s, NULL)
                ON DUPLICATE KEY UPDATE
                  slot_hora = IF(slot_hora = VALUES(slot_hora), slot_hora, VALUES(slot_hora)),
                  hora_lock = IF(slot_hora = VALUES(slot_hora), hora_lock, VALUES(hora_lock)),
                  worker_id = IF(slot_hora = VALUES(slot_hora), worker_id, VALUES(worker_id))
            """, (slot_str, os.getpid()))
            # Verificar si nosotros somos los holders del slot
            cur.execute("SELECT worker_id, slot_hora FROM transp_sync_lock WHERE id=1")
            row = cur.fetchone() or {}
        conn.commit()
        conn.close()
        return (row.get("worker_id") == os.getpid() and row.get("slot_hora") == slot_str)
    except Exception as e:
        print(f"[transp-cron] lock error: {e}", flush=True)
        return False


def _tr_marcar_lock_completado(slot_str):
    """Después de correr la sync, marca ultima_corrida en la fila."""
    try:
        conn = get_mysql()
        with conn.cursor() as cur:
            cur.execute(
                "UPDATE transp_sync_lock SET ultima_corrida=NOW() WHERE id=1 AND slot_hora=%s",
                (slot_str,)
            )
        conn.commit()
        conn.close()
    except Exception as e:
        print(f"[transp-cron] marcar completado: {e}", flush=True)


def _transporte_scheduler_loop():
    """Hilo daemon: dispara sync mes-actual a 09/11/15/17 hora Chile.

    Estrategia anti-doble-ejecución con 2 workers Gunicorn:
      1. Cada worker corre su propio loop pero ambos hacen lock en
         `transp_sync_lock` antes de ejecutar la sync.
      2. El primer worker en llegar gana el lock; el segundo lo detecta
         y se salta el slot.

    Se calcula la próxima hora objetivo en cada vuelta y se duerme hasta
    1 minuto antes para minimizar drift. A los 10s del slot real, intenta
    obtener el lock y, si lo logra, corre la sync.
    """
    import datetime as _dt
    import time as _time
    from zoneinfo import ZoneInfo

    # NUEVA CADENCIA (Daniel 2026-05-19): sync 3 veces al día (09/12/16)
    # en vez de 4. Coincide con los turnos de bodega (mañana / postlunch / tarde).
    HORAS_SYNC = [9, 12, 16]
    TZ = ZoneInfo("America/Santiago")
    _ensure_transp_sync_lock_table()
    print(f"[transp-cron] arrancado en worker pid={os.getpid()} "
          f"(horas: {HORAS_SYNC})", flush=True)

    while True:
        try:
            now_cl = _dt.datetime.now(TZ)

            # ── Calcular próximo slot ──
            proxima = None
            for h in HORAS_SYNC:
                candidato = now_cl.replace(hour=h, minute=0, second=0, microsecond=0)
                if candidato > now_cl:
                    proxima = candidato
                    break
            if proxima is None:
                # Pasó la última (17:00). Esperar hasta 09:00 del día siguiente.
                proxima = (now_cl + _dt.timedelta(days=1)).replace(
                    hour=HORAS_SYNC[0], minute=0, second=0, microsecond=0
                )

            espera_seg = max(1.0, (proxima - now_cl).total_seconds())
            print(f"[transp-cron] próxima sync: {proxima.strftime('%Y-%m-%d %H:%M')} "
                  f"(en {espera_seg/60:.1f} min)", flush=True)
            _time.sleep(espera_seg)

            # Reintentar tomar lock en ventana de 30 seg
            slot_str = proxima.strftime("%Y-%m-%d %H:%M")
            soy_holder = _tr_intentar_lock_slot(slot_str)
            if not soy_holder:
                print(f"[transp-cron] slot {slot_str} tomado por otro worker, "
                      f"este worker (pid={os.getpid()}) lo omite", flush=True)
                _time.sleep(60)   # esperar 1 min para que avance el clock
                continue

            print(f"[transp-cron] disparando sync mes-actual para slot {slot_str} "
                  f"(pid={os.getpid()})", flush=True)
            try:
                res = _tr_sync_mes_actual_bg(modo="resync")
                print(f"[transp-cron] sync OK: {res.get('mensaje','')} "
                      f"(errs={len(res.get('errores') or [])})", flush=True)
            except Exception as e:
                print(f"[transp-cron] sync falló: {e}", flush=True)
            finally:
                _tr_marcar_lock_completado(slot_str)
        except Exception as e:
            print(f"[transp-cron] loop error: {e}", flush=True)
            _time.sleep(300)  # esperar 5 min ante error inesperado


# Arranca el thread en el módulo. Evita doble arranque si por alguna
# razón se importa más de una vez (defensa por nombre de thread).
def _start_transp_scheduler_once():
    import threading as _th
    nombre = "transp-cron"
    for t in _th.enumerate():
        if t.name == nombre and t.is_alive():
            return
    # Solo arrancar si NO estamos en modo migrations-skip o si lo está, igual
    # arranca: el job consulta el ERP, no las migraciones locales.
    try:
        t = _th.Thread(target=_transporte_scheduler_loop, daemon=True, name=nombre)
        t.start()
    except Exception as e:
        print(f"[transp-cron] no se pudo arrancar: {e}", flush=True)


try:
    _start_transp_scheduler_once()
except Exception as _e_sched:
    print(f"[transp-cron] startup error: {_e_sched}", flush=True)


# ═════════════════════════════════════════════════════════════════════
#  PLAN 2026-05-21 — CRON DAEMON MANTENCIONES (06:00 hora Chile)
#  Auto-calendariza contratos + crea notificaciones internas + (opcional)
#  envía emails recordatorio. Patrón idéntico a _transporte_scheduler_loop
#  con lock anti-doble-corrida (mant_cron_lock).
# ═════════════════════════════════════════════════════════════════════

def _mant_intentar_lock_slot(slot_str):
    """Intenta tomar el lock del cron de mantenciones para un slot dado.
    PRIMARY KEY = slot_str — solo el primer worker que llegue gana."""
    try:
        conn = get_mysql()
        with conn.cursor() as cur:
            try:
                cur.execute(
                    "INSERT INTO mant_cron_lock (slot_str, taken_by, taken_at) "
                    "VALUES (%s, %s, NOW())",
                    (slot_str, os.getpid())
                )
                soy_holder = True
            except Exception:
                soy_holder = False
        conn.commit()
        conn.close()
        return soy_holder
    except Exception as e:
        print(f"[mant-cron] lock error: {e}", flush=True)
        return False


def _mant_marcar_lock_completado(slot_str):
    """Marca el slot como completado. Usa get_mysql() directo (no get_db())
    para funcionar también desde fuera de un app_context."""
    try:
        conn = get_mysql()
        with conn.cursor() as cur:
            cur.execute(
                "UPDATE mant_cron_lock SET completed_at=NOW() WHERE slot_str=%s",
                (slot_str,)
            )
        conn.commit()
        conn.close()
    except Exception as e:
        print(f"[mant-cron] marcar completado: {e}", flush=True)


def _mantenciones_cron_run_once(slot_str=""):
    """Ejecuta UNA pasada del cron de mantenciones. Devuelve dict con métricas.

    Pasos:
        1. Auto-calendarización de contratos vigentes.
        2. Notificaciones internas (batch INSERT con executemany).
        3. Email recordatorio si MANT_RECORDATORIOS_EMAIL_ENABLED=1, sino DRY-RUN.

    Idempotente: si se corre 2x el mismo día, no duplica notificaciones
    (helper _mant_notificar ya chequea duplicados).
    """
    import time as _time
    from datetime import datetime as _dtm, date as _date
    import calendar as _cal

    _t0 = _time.time()
    metricas = {
        "calendarizadas": 0,
        "notif_visita_proxima": 0,
        "notif_visita_atrasada": 0,
        "notif_factura_pendiente": 0,
        "notif_garantia_por_vencer": 0,
        "notif_contrato_por_vencer": 0,
        "emails_dry_run": 0,
        "emails_enviados": 0,
        "errores": [],
    }

    email_flag = os.environ.get("MANT_RECORDATORIOS_EMAIL_ENABLED", "0").strip().lower()
    email_on = email_flag in ("1", "true", "yes", "on")

    # ── Feature flag global: ¿el cron PUEDE crear OTs automáticamente? ──
    # 2026-05-22 — Daniel reportó OTs auto-creadas que él NO pidió. Por
    # default este flag queda en "0" (OFF) y el cron solo genera
    # NOTIFICACIONES sugerentes para Aarón Urbina (ejecutivo SSTT). La
    # creación real de la OT queda como acción manual.
    # Para reactivar el comportamiento anterior: setear
    # MANT_AUTO_CALENDAR_ENABLED=1 en Railway (NO RECOMENDADO).
    auto_calendar_flag = os.environ.get(
        "MANT_AUTO_CALENDAR_ENABLED", "0"
    ).strip().lower()
    auto_calendar_on = auto_calendar_flag in ("1", "true", "yes", "on")
    # Daniel 30/05/2026: la creación AUTOMÁTICA de OTs queda DESACTIVADA de
    # forma definitiva. El sistema solo SUGIERE (notificaciones/IA), nunca
    # crea OTs por su cuenta. Se ignora MANT_AUTO_CALENDAR_ENABLED para evitar
    # reactivaciones accidentales — la IA propondrá las OTs y el usuario decide.
    auto_calendar_on = False
    metricas["auto_calendar_on"] = auto_calendar_on
    metricas["sugerencias_creadas"] = 0

    # ── Paso 1: Auto-calendarización de contratos ────────────────────
    try:
        contratos = mysql_fetchall(
            "SELECT ct.id, ct.cliente_id, ct.fecha_inicio, ct.fecha_vencimiento, "
            "       ct.es_indefinido, ct.frecuencia_meses, ct.ai_frecuencia_sug, "
            "       c.razon_social "
            "FROM mant_contratos ct "
            "JOIN mant_clientes c ON c.id = ct.cliente_id "
            "WHERE ct.estado IN ('vigente','indefinido') "
            "  AND COALESCE(ct.auto_calendar_enabled, 1) = 1 "
            "  AND COALESCE(ct.frecuencia_meses, ct.ai_frecuencia_sug, 0) > 0 "
        ) or []

        hoy = _date.today()
        batch_visitas = []
        # Sugerencias para Aarón cuando el flag esté OFF (modo default)
        sugerencias_notif = []

        for ct in contratos:
            freq = ct.get("frecuencia_meses") or ct.get("ai_frecuencia_sug") or 0
            if freq <= 0:
                continue
            cid = ct["cliente_id"]
            ctid = ct["id"]

            if ct.get("es_indefinido") or not ct.get("fecha_vencimiento"):
                hasta = hoy + timedelta(days=180)  # 6 meses de runway para indefinidos
            else:
                hasta = ct.get("fecha_vencimiento")
                if isinstance(hasta, _dtm): hasta = hasta.date()
                if hasta <= hoy:
                    continue

            # Meses ya programados para evitar duplicar
            try:
                existentes = mysql_fetchall(
                    "SELECT YEAR(fecha_programada) AS y, MONTH(fecha_programada) AS m "
                    "FROM mant_visitas WHERE contrato_id=%s AND tipo='preventiva' "
                    "  AND estado NOT IN ('anulada','cancelada') "
                    "  AND fecha_programada >= %s",
                    (ctid, hoy)
                ) or []
            except Exception:
                existentes = []
            existentes_set = {(r["y"], r["m"]) for r in existentes}

            # Última visita realizada (para calcular días desde última)
            try:
                ult = mysql_fetchone(
                    "SELECT MAX(COALESCE(fecha_realizada, fecha_programada)) AS f "
                    "FROM mant_visitas "
                    "WHERE contrato_id=%s AND tipo='preventiva' "
                    "  AND estado NOT IN ('anulada','cancelada')",
                    (ctid,)
                ) or {}
                ult_fecha = ult.get("f")
                if isinstance(ult_fecha, _dtm):
                    ult_fecha = ult_fecha.date()
            except Exception:
                ult_fecha = None
            dias_desde = (hoy - ult_fecha).days if ult_fecha else None

            # Generar fechas a partir de hoy + freq
            cursor_d = hoy + timedelta(days=int(freq) * 30)
            limite = 0
            sugerencias_de_este_contrato = []
            while cursor_d <= hasta and limite < 24:  # cap 24 visitas/contrato/corrida
                limite += 1
                if (cursor_d.year, cursor_d.month) not in existentes_set:
                    if auto_calendar_on:
                        # Modo legacy: crear la OT automáticamente
                        batch_visitas.append((
                            cid, ctid,
                            f"Mantención preventiva — {ct.get('razon_social','')}"[:200],
                            cursor_d, "preventiva", "programada",
                            "mant-cron",
                        ))
                    else:
                        # Modo nuevo (default): guardar la sugerencia
                        sugerencias_de_este_contrato.append(cursor_d)
                    existentes_set.add((cursor_d.year, cursor_d.month))
                anio = cursor_d.year
                mes  = cursor_d.month + int(freq)
                while mes > 12:
                    mes -= 12
                    anio += 1
                try:
                    dia = min(cursor_d.day, _cal.monthrange(anio, mes)[1])
                    cursor_d = _date(anio, mes, dia)
                except ValueError:
                    break

            # Si en modo "solo-sugerir" hay huecos, dejar UNA sugerencia
            # auditable por contrato (no por fecha) — el usuario decidirá
            # si la acepta (crea la OT) o la rechaza con motivo.
            if not auto_calendar_on and sugerencias_de_este_contrato:
                razon = ct.get("razon_social", "") or f"Contrato #{ctid}"
                f1 = sugerencias_de_este_contrato[0]
                rest = len(sugerencias_de_este_contrato) - 1
                cuerpo = (
                    f"Cliente con contrato preventivo cada {int(freq)} mes(es). "
                )
                if dias_desde is not None:
                    cuerpo += f"Han pasado {dias_desde} días desde la última visita. "
                cuerpo += (
                    f"Próxima sugerida: {f1.strftime('%d/%m/%Y')}"
                    + (f" (+{rest} más a futuro)" if rest > 0 else "")
                    + ". Considera agendar la OT en el cliente."
                )
                sugerencias_notif.append({
                    "tipo": "agendar_visita",
                    "origen": "cron",
                    "prioridad": "media",
                    "titulo": f"Sugerencia mantención: {razon}",
                    "cuerpo": cuerpo,
                    "url_accion": f"/mantenciones/clientes/{cid}",
                    "cliente_id": cid,
                    "entidad": "contrato",
                    "entidad_id": ctid,
                    "metadata": {
                        "frecuencia_meses": int(freq),
                        "dias_desde_ultima": dias_desde,
                        "primera_fecha_sugerida": str(f1),
                        "huecos_futuros": rest,
                    },
                })

        # Insertar OTs solo si el flag está ON
        if batch_visitas:
            try:
                conn = get_mysql()
                with conn.cursor() as cur:
                    cur.executemany(
                        "INSERT INTO mant_visitas "
                        "  (cliente_id, contrato_id, titulo, fecha_programada, "
                        "   tipo, estado, created_by) "
                        "VALUES (%s,%s,%s,%s,%s,%s,%s)",
                        batch_visitas
                    )
                    metricas["calendarizadas"] = cur.rowcount
                conn.commit()
                conn.close()
            except Exception as e:
                metricas["errores"].append(f"calendarizacion: {e}")

        # Insertar sugerencias (modo default — flag OFF)
        # Va a mant_sugerencias_evidencia (auditable) y además crea notif
        # interna en la campana que linkea a la sugerencia.
        if sugerencias_notif:
            try:
                metricas["sugerencias_creadas"] = _sugerencia_batch_crear(
                    sugerencias_notif
                )
                print(
                    f"[mant-cron] AUTO-CALENDAR OFF — generadas "
                    f"{metricas['sugerencias_creadas']} sugerencia(s) "
                    f"(de {len(sugerencias_notif)} candidatas — "
                    f"el resto eran duplicadas)",
                    flush=True,
                )
            except Exception as e:
                metricas["errores"].append(f"sugerencias: {e}")
    except Exception as e:
        metricas["errores"].append(f"paso_calendarizacion: {e}")

    # ── Paso 2: Notificaciones internas + Sugerencias (batch) ──────────
    # FILOSOFÍA 2026-05-22: el sistema NUNCA toma acciones, solo sugiere.
    # Los recordatorios sobre OTs YA existentes (visita_proxima /
    # visita_atrasada) siguen como notif al técnico — no son acciones
    # nuevas, son alarmas. Los eventos que SÍ implican una acción nueva
    # (factura pendiente, garantía por vencer, contrato por vencer) ahora
    # van como SUGERENCIAS auditables que el usuario debe aceptar/rechazar.
    try:
        notif_batch = []        # recordatorios al técnico (notif simple)
        sugerencias_batch = []  # acciones que requieren decisión humana

        # 2a — Visitas próximas (3-7 días) → notif al técnico (recordatorio)
        rows = mysql_fetchall(
            "SELECT v.id, v.cliente_id, v.fecha_programada, v.titulo, "
            "       v.tipo, v.tecnico_user_id, c.razon_social "
            "FROM mant_visitas v "
            "JOIN mant_clientes c ON c.id = v.cliente_id "
            "WHERE v.estado='programada' "
            "  AND v.fecha_programada BETWEEN (CURDATE() + INTERVAL 3 DAY) "
            "                            AND (CURDATE() + INTERVAL 7 DAY)"
        ) or []
        for r in rows:
            f = r["fecha_programada"]
            if isinstance(f, _dtm): f = f.date()
            notif_batch.append({
                "destino_user_id": r.get("tecnico_user_id"),
                "tipo": "visita_proxima",
                "prioridad": "media",
                "titulo": f"Visita próxima ({r.get('tipo')}): {r.get('razon_social','')}",
                "cuerpo": f"Visita programada para el {f.strftime('%d/%m/%Y')}",
                "url_accion": f"/mantenciones/ot/{r['id']}",
                "cliente_id": r["cliente_id"],
                "visita_id":  r["id"],
            })
        metricas["notif_visita_proxima"] = len(rows)

        # 2b — Visitas atrasadas → notif al técnico (alarma)
        rows = mysql_fetchall(
            "SELECT v.id, v.cliente_id, v.fecha_programada, v.titulo, "
            "       v.tipo, v.tecnico_user_id, c.razon_social, "
            "       DATEDIFF(CURDATE(), v.fecha_programada) AS dias_atraso "
            "FROM mant_visitas v "
            "JOIN mant_clientes c ON c.id = v.cliente_id "
            "WHERE v.estado='programada' "
            "  AND v.fecha_programada < CURDATE()"
        ) or []
        for r in rows:
            f = r["fecha_programada"]
            if isinstance(f, _dtm): f = f.date()
            notif_batch.append({
                "destino_user_id": r.get("tecnico_user_id"),
                "tipo": "visita_atrasada",
                "prioridad": "alta",
                "titulo": f"Visita atrasada {r.get('dias_atraso')}d: {r.get('razon_social','')}",
                "cuerpo": f"Visita {r.get('tipo')} del {f.strftime('%d/%m/%Y')} sin ejecutar",
                "url_accion": f"/mantenciones/ot/{r['id']}",
                "cliente_id": r["cliente_id"],
                "visita_id":  r["id"],
            })
        metricas["notif_visita_atrasada"] = len(rows)

        # 2c — Facturas pendientes (visitas completadas hace >3d sin
        # factura) → SUGERENCIA tipo 'regularizar_factura'. El usuario
        # decide si emite o no la factura (puede haber casos legítimos).
        rows = mysql_fetchall(
            "SELECT v.id, v.cliente_id, v.fecha_realizada, v.fecha_programada, "
            "       v.titulo, v.estado_facturacion, c.razon_social, "
            "       DATEDIFF(CURDATE(), COALESCE(v.fecha_realizada, v.fecha_programada)) AS dias "
            "FROM mant_visitas v "
            "JOIN mant_clientes c ON c.id = v.cliente_id "
            "WHERE v.estado='completada' "
            "  AND v.estado_facturacion IN ('sin_cotizar','cotizado','con_oc') "
            "  AND COALESCE(v.cubierto_por,'contrato') != 'garantia' "
            "  AND COALESCE(v.fecha_realizada, v.fecha_programada) < (CURDATE() - INTERVAL 3 DAY)"
        ) or []
        for r in rows:
            sugerencias_batch.append({
                "tipo": "regularizar_factura",
                "origen": "cron",
                "prioridad": "alta",
                "titulo": f"Factura pendiente: {r.get('razon_social','')} ({r.get('dias')}d)",
                "cuerpo": (f"Visita completada sin factura emitida. "
                           f"Estado actual: {r.get('estado_facturacion')}. "
                           f"Considera emitir cotización/factura."),
                "url_accion": f"/mantenciones/clientes/{r['cliente_id']}#finanzas",
                "cliente_id": r["cliente_id"],
                "entidad": "visita",
                "entidad_id": r["id"],
                "metadata": {
                    "dias_pendiente": int(r.get("dias") or 0),
                    "estado_facturacion": r.get("estado_facturacion"),
                },
            })
        metricas["notif_factura_pendiente"] = len(rows)

        # 2d — Garantía por vencer → SUGERENCIA tipo 'revisar_garantia'.
        # El usuario decide si contacta al cliente para renovar la garantía.
        try:
            rows = mysql_fetchall(
                "SELECT m.id AS maquina_id, m.cliente_id, m.nombre, "
                "       m.fecha_fin_garantia, c.razon_social, "
                "       DATEDIFF(m.fecha_fin_garantia, CURDATE()) AS dias_restantes "
                "FROM mant_maquinas m "
                "JOIN mant_clientes c ON c.id = m.cliente_id "
                "WHERE m.fecha_fin_garantia BETWEEN CURDATE() AND (CURDATE() + INTERVAL 30 DAY) "
                "  AND COALESCE(m.estado, 'activo') = 'activo' "
            ) or []
        except Exception:
            rows = []  # tabla puede no tener fecha_fin_garantia
        for r in rows:
            sugerencias_batch.append({
                "tipo": "revisar_garantia",
                "origen": "cron",
                "prioridad": "media",
                "titulo": f"Garantía por vencer: {r.get('razon_social','')}",
                "cuerpo": (f"Equipo {r.get('nombre','')} — garantía vence en "
                           f"{r.get('dias_restantes')} días. Considera "
                           f"contactar al cliente para renovar."),
                "url_accion": f"/mantenciones/clientes/{r['cliente_id']}#equipos",
                "cliente_id": r["cliente_id"],
                "entidad": "maquina",
                "entidad_id": r["maquina_id"],
                "metadata": {
                    "dias_restantes": int(r.get("dias_restantes") or 0),
                    "equipo": r.get("nombre"),
                },
            })
        metricas["notif_garantia_por_vencer"] = len(rows)

        # 2e — Contratos por vencer (60 días) → SUGERENCIA tipo 'renovar_contrato'
        rows = mysql_fetchall(
            "SELECT ct.id, ct.cliente_id, ct.fecha_vencimiento, "
            "       c.razon_social, DATEDIFF(ct.fecha_vencimiento, CURDATE()) AS dias "
            "FROM mant_contratos ct "
            "JOIN mant_clientes c ON c.id = ct.cliente_id "
            "WHERE ct.estado='vigente' "
            "  AND COALESCE(ct.es_indefinido, 0) = 0 "
            "  AND ct.fecha_vencimiento BETWEEN CURDATE() AND (CURDATE() + INTERVAL 60 DAY)"
        ) or []
        for r in rows:
            sugerencias_batch.append({
                "tipo": "renovar_contrato",
                "origen": "cron",
                "prioridad": "media",
                "titulo": f"Contrato por vencer: {r.get('razon_social','')}",
                "cuerpo": (f"Vence en {r.get('dias')} días. Considera "
                           f"preparar la renegociación con el cliente."),
                "url_accion": f"/mantenciones/clientes/{r['cliente_id']}#contratos",
                "cliente_id": r["cliente_id"],
                "entidad": "contrato",
                "entidad_id": r["id"],
                "metadata": {
                    "dias_restantes": int(r.get("dias") or 0),
                },
            })
        metricas["notif_contrato_por_vencer"] = len(rows)

        # Insertar notif técnico (visita próxima/atrasada) — alarma
        if notif_batch:
            insertadas = _mant_notificar_batch(notif_batch)
            print(f"[mant-cron] notif recordatorios técnico: {insertadas} "
                  f"(de {len(notif_batch)} candidatas)",
                  flush=True)

        # Insertar sugerencias (paso 2c, 2d, 2e) — acciones humanas
        if sugerencias_batch:
            n_sug = _sugerencia_batch_crear(sugerencias_batch)
            metricas["sugerencias_creadas"] = (
                metricas.get("sugerencias_creadas", 0) + n_sug
            )
            print(f"[mant-cron] sugerencias paso 2: {n_sug} "
                  f"(de {len(sugerencias_batch)} candidatas — "
                  f"el resto eran duplicadas)",
                  flush=True)
    except Exception as e:
        metricas["errores"].append(f"paso_notificaciones: {e}")

    # ── Paso 3: Email recordatorio (DRY-RUN o real según flag) ──────
    try:
        # 3a — Visitas próximas: email al cliente (si tiene email + flag ON)
        rows = mysql_fetchall(
            "SELECT v.id, v.cliente_id, v.fecha_programada, v.titulo, "
            "       c.razon_social, c.contacto_email, "
            "       v.recordatorio_visita_enviado_at "
            "FROM mant_visitas v "
            "JOIN mant_clientes c ON c.id = v.cliente_id "
            "WHERE v.estado='programada' "
            "  AND v.fecha_programada BETWEEN (CURDATE() + INTERVAL 3 DAY) "
            "                            AND (CURDATE() + INTERVAL 7 DAY) "
            "  AND v.recordatorio_visita_enviado_at IS NULL"
        ) or []
        for r in rows:
            email = (r.get("contacto_email") or "").strip()
            f = r.get("fecha_programada")
            if isinstance(f, _dtm): f = f.date()
            asunto = f"Recordatorio visita {f.strftime('%d/%m/%Y')} — {r.get('razon_social','')}"
            if not email_on:
                metricas["emails_dry_run"] += 1
                print(f"[mant-cron][DRY-RUN] email a {email or '(sin email)'} "
                      f"re: {asunto}", flush=True)
                continue
            if not email:
                continue
            # Modo ON: enviar email real
            try:
                _send_ilus_email(
                    email, _brand_subject(asunto),
                    f"<p>Recordatorio: visita programada para {f.strftime('%d/%m/%Y')}</p>",
                    evento="mant_recordatorio_visita", modulo="mantenciones",
                )
                mysql_execute(
                    "UPDATE mant_visitas SET recordatorio_visita_enviado_at=NOW() WHERE id=%s",
                    (r["id"],)
                )
                metricas["emails_enviados"] += 1
            except Exception as e_em:
                metricas["errores"].append(f"email visita {r['id']}: {e_em}")

        # 3b — Facturas pendientes: email a admin interno
        rows = mysql_fetchall(
            "SELECT v.id, v.cliente_id, c.razon_social, "
            "       v.recordatorio_factura_enviado_at "
            "FROM mant_visitas v "
            "JOIN mant_clientes c ON c.id = v.cliente_id "
            "WHERE v.estado='completada' "
            "  AND v.estado_facturacion IN ('sin_cotizar','cotizado','con_oc') "
            "  AND COALESCE(v.cubierto_por,'contrato') != 'garantia' "
            "  AND COALESCE(v.fecha_realizada, v.fecha_programada) < (CURDATE() - INTERVAL 7 DAY) "
            "  AND v.recordatorio_factura_enviado_at IS NULL"
        ) or []
        for r in rows:
            asunto = f"Factura pendiente: {r.get('razon_social','')}"
            if not email_on:
                metricas["emails_dry_run"] += 1
                print(f"[mant-cron][DRY-RUN] email factura pendiente re: {asunto}",
                      flush=True)
                continue
            try:
                _send_ilus_email(
                    "daniel.aguilar@sphs.cl", _brand_subject(asunto),
                    f"<p>Visita completada sin facturar (>7 días)</p>",
                    evento="mant_recordatorio_factura", modulo="mantenciones",
                )
                mysql_execute(
                    "UPDATE mant_visitas SET recordatorio_factura_enviado_at=NOW() WHERE id=%s",
                    (r["id"],)
                )
                metricas["emails_enviados"] += 1
            except Exception as e_em:
                metricas["errores"].append(f"email factura {r['id']}: {e_em}")
    except Exception as e:
        metricas["errores"].append(f"paso_email: {e}")

    # ── Paso 4: RECORDATORIOS 24h DE RETIROS ──────────────────────────────
    # Daniel pidió que el cron de mantenciones también dispare los
    # recordatorios de retiros confirmados para mañana. Reusamos esta
    # corrida diaria (06:00 CL) para que no haya un cron extra.
    metricas["pickup_reminders_sent"]    = 0
    metricas["pickup_reminders_omitted"] = 0
    try:
        from datetime import date as _date_p
        from pymysql.err import Error as _PyMyErr  # noqa: F401  (importable check)
    except Exception:
        pass
    try:
        pick_rows = mysql_fetchall(
            """SELECT * FROM pickup_requests
               WHERE status='agenda_confirmada'
                 AND DATE(confirmed_date) = DATE_ADD(CURDATE(), INTERVAL 1 DAY)
                 AND reminder_24h_sent IS NULL"""
        ) or []
        print(f"[mant-cron] retiros con recordatorio 24h pendientes: {len(pick_rows)}",
              flush=True)
        # Importamos notify desde el módulo retiros (registrado en app_context)
        # de forma robusta: si el módulo no exportó el helper, hacemos el
        # send mínimo aquí mismo usando _ilus_email_html.
        from pickups_module import PICKUP_STATUS  # no rompe nada
        for r in pick_rows:
            try:
                rd = dict(r)
                # Inline notify minimalista — reusa la plantilla recordatorio_24h
                tpl = mysql_fetchone(
                    "SELECT asunto, cuerpo FROM comm_templates "
                    "WHERE modulo='retiros' AND estado='recordatorio_24h' "
                    "  AND canal='email' LIMIT 1"
                )
                if not tpl:
                    metricas["pickup_reminders_omitted"] += 1
                    continue
                # Construir variables locales (mismo set que _render_pickup_vars)
                follow_url = ""
                try:
                    follow_url = url_for("pickup_public_tracking",
                                         token=rd["public_token"], _external=True)
                except Exception: pass
                tf = str(rd.get("confirmed_time_from") or "")[:5]
                tt = str(rd.get("confirmed_time_to") or "")[:5]
                # Settings de bodega (defaults sensatos para evitar romper)
                wcfg = mysql_fetchone("SELECT * FROM pickup_settings WHERE id=1") or {}
                vars_ = {
                    "code":              rd.get("code") or "",
                    "cliente":           rd.get("customer_name") or "",
                    "persona_retira":    rd.get("pickup_person_name") or rd.get("contact_name") or "",
                    "documento":         f"{(rd.get('document_type') or '').upper()} {rd.get('document_number') or ''}".strip(),
                    "fecha_solicitada":  str(rd.get("requested_date") or ""),
                    "fecha_propuesta":   str(rd.get("proposed_date") or ""),
                    "fecha_confirmada":  str(rd.get("confirmed_date") or ""),
                    "horario":           f"{tf} - {tt}" if tf else "",
                    "n_bultos":          str(rd.get("total_packages") or 0),
                    "kg":                str(rd.get("total_weight_kg") or 0),
                    "m3":                str(rd.get("total_volume_m3") or 0),
                    "warehouse_name":    wcfg.get("warehouse_name") or "Bodega ILUS Quilicura",
                    "warehouse_addr":    wcfg.get("warehouse_addr") or "",
                    "link_seguimiento":  follow_url,
                }
                asunto = tpl.get("asunto") or "Recordatorio: tu retiro es mañana"
                cuerpo = tpl.get("cuerpo") or ""
                for k, v in vars_.items():
                    asunto = asunto.replace("{{" + k + "}}", str(v)).replace("{{ " + k + " }}", str(v))
                    cuerpo = cuerpo.replace("{{" + k + "}}", str(v)).replace("{{ " + k + " }}", str(v))
                # Envoltorio HTML ILUS
                html = _ilus_email_html(
                    titulo=asunto,
                    subtitulo=f"{rd.get('code') or ''} - {vars_['documento']}",
                    saludo=vars_["persona_retira"],
                    parrafos=[cuerpo],
                    btn_primario_txt="Ver detalle del retiro",
                    btn_primario_url=follow_url,
                    btn_secundario_txt="Cómo llegar",
                    btn_secundario_url=(wcfg.get("maps_url") or ""),
                )
                sent = _send_ilus_email(
                    rd.get("contact_email"),
                    _brand_subject(asunto),
                    html,
                    evento="pickup_reminder_24h",
                    modulo="retiros",
                )
                if sent:
                    mysql_execute(
                        "UPDATE pickup_requests SET reminder_24h_sent=NOW() WHERE id=%s",
                        (rd["id"],),
                    )
                    metricas["pickup_reminders_sent"] += 1
                else:
                    metricas["pickup_reminders_omitted"] += 1
            except Exception as _e_pr:
                metricas["pickup_reminders_omitted"] += 1
                metricas["errores"].append(f"pickup_recordatorio {dict(r).get('code','?')}: {_e_pr}")
    except Exception as e:
        metricas["errores"].append(f"paso_pickup_reminders: {e}")

    # ── Paso final: Resumen IA del día (Daniel 2026-05-26) ──────────────
    # Si hubo actividad significativa (≥ 1 alerta), pedimos a Claude que
    # genere un resumen accionable y lo enviamos como notificación al
    # superadmin. Si no hubo nada relevante, saltamos (cero tokens).
    try:
        total_signals = (
            metricas.get("notif_visita_proxima", 0)
            + metricas.get("notif_visita_atrasada", 0)
            + metricas.get("notif_garantia_por_vencer", 0)
            + metricas.get("notif_contrato_por_vencer", 0)
        )
        if total_signals >= 1:
            _ia_alertas_resumir_diario(metricas)
    except Exception as _e_ia_res:
        print(f"[mant-cron] resumen IA falló (no critico): {_e_ia_res}", flush=True)

    metricas["tiempo_ms"] = int((_time.time() - _t0) * 1000)
    print(
        f"[mant-cron] OK slot={slot_str or 'manual'} "
        f"auto_cal={'ON' if metricas.get('auto_calendar_on') else 'OFF'} "
        f"calendarizadas={metricas['calendarizadas']} "
        f"sugerencias={metricas.get('sugerencias_creadas', 0)} "
        f"notif_visita={metricas['notif_visita_proxima']}+{metricas['notif_visita_atrasada']} "
        f"notif_factura={metricas['notif_factura_pendiente']} "
        f"notif_garantia={metricas['notif_garantia_por_vencer']} "
        f"notif_contrato={metricas['notif_contrato_por_vencer']} "
        f"emails={metricas['emails_enviados']} dry_run={metricas['emails_dry_run']} "
        f"pickup_24h={metricas.get('pickup_reminders_sent',0)}+{metricas.get('pickup_reminders_omitted',0)} "
        f"tiempo={metricas['tiempo_ms']}ms "
        f"errores={len(metricas['errores'])}",
        flush=True
    )
    return metricas


# ══════════════════════════════════════════════════════════════════════
# IA · ALERTAS PROACTIVAS DIARIAS — resumen accionable del estado
# operativo del negocio (Daniel 2026-05-26: "que la app me diga cada
# mañana qué tengo que mirar primero")
# ══════════════════════════════════════════════════════════════════════
def _ia_alertas_resumir_diario(metricas):
    """Genera un resumen IA del estado de mantenciones del día y lo envía
    como notificación al superadmin. 1 sola llamada a Claude (tier=sonnet)
    con métricas + top de items críticos. Si la IA falla, igualmente envía
    el resumen "crudo" (sin IA) — cero costo de oportunidad.

    Se invoca al final de _mantenciones_cron_run_once.
    """
    from datetime import date as _d

    # 1) Recolectar lista corta de items críticos (no todo, solo lo más urgente)
    contratos_criticos = mysql_fetchall(
        "SELECT ct.id, ct.nombre, ct.fecha_vencimiento, c.razon_social "
        "  FROM mant_contratos ct "
        "  JOIN mant_clientes c ON c.id=ct.cliente_id "
        " WHERE ct.estado IN ('vigente','indefinido') "
        "   AND ct.fecha_vencimiento IS NOT NULL "
        "   AND ct.fecha_vencimiento BETWEEN CURDATE() AND DATE_ADD(CURDATE(), INTERVAL 30 DAY) "
        " ORDER BY ct.fecha_vencimiento ASC LIMIT 10"
    ) or []

    visitas_atrasadas = mysql_fetchall(
        "SELECT v.id, v.fecha_programada, v.tipo, c.razon_social "
        "  FROM mant_visitas v "
        "  JOIN mant_clientes c ON c.id=v.cliente_id "
        " WHERE v.estado='programada' AND v.fecha_programada < CURDATE() "
        " ORDER BY v.fecha_programada ASC LIMIT 10"
    ) or []

    if not contratos_criticos and not visitas_atrasadas:
        return  # nada urgente

    # 2) Resumir con Claude (Sonnet — clasificación + redacción, no opus)
    items_text = []
    for ct in contratos_criticos:
        dias = (ct["fecha_vencimiento"] - _d.today()).days if ct.get("fecha_vencimiento") else 0
        items_text.append(
            f"- Contrato '{ct.get('nombre') or ''}' de {ct.get('razon_social') or '#'+str(ct['id'])} "
            f"vence en {dias}d ({ct['fecha_vencimiento']})"
        )
    for v in visitas_atrasadas:
        dias = (_d.today() - v["fecha_programada"]).days if v.get("fecha_programada") else 0
        items_text.append(
            f"- Visita {v.get('tipo') or ''} de {v.get('razon_social') or '#'+str(v['id'])} "
            f"atrasada {dias}d (era {v['fecha_programada']})"
        )

    items_block = "\n".join(items_text[:15])
    metricas_block = (
        f"Visitas próximas: {metricas.get('notif_visita_proxima',0)}, "
        f"Visitas atrasadas: {metricas.get('notif_visita_atrasada',0)}, "
        f"Garantías por vencer: {metricas.get('notif_garantia_por_vencer',0)}, "
        f"Contratos por vencer: {metricas.get('notif_contrato_por_vencer',0)}"
    )

    prompt = (
        "Te paso el estado operativo de mantenciones de hoy. "
        "Genera un RESUMEN ACCIONABLE de máximo 5 bullets, ordenados por urgencia. "
        "Cada bullet: <acción concreta> + <cliente/contrato afectado>. "
        "Lenguaje claro español NEUTRO (no argentino, no chileno). "
        "Devuelve JSON con campos: titulo (string corto), bullets (array de strings), "
        "prioridad ('alta'|'media'|'baja').\n\n"
        f"MÉTRICAS DEL DÍA: {metricas_block}\n\nITEMS CRÍTICOS:\n{items_block}"
    )

    data, err = _claude_call(
        prompt_usuario=prompt,
        prompt_sistema="Eres un asistente operativo de servicios técnicos. "
                       "Generas resúmenes accionables, breves y priorizados.",
        max_tokens=600, expect_json=True, tier='sonnet',
        log_endpoint="ia_alertas_diarias",
    )

    if err or not data:
        # Fallback: usar el block crudo sin IA, igual notificamos
        titulo = "Resumen de mantenciones del día"
        bullets = items_text[:5]
        prioridad = "media"
    else:
        titulo = (data.get("titulo") or "Resumen IA del día").strip()[:120]
        bullets = data.get("bullets") or []
        prioridad = (data.get("prioridad") or "media").strip().lower()
        if prioridad not in ("alta", "media", "baja"):
            prioridad = "media"

    cuerpo = "\n".join(["• " + b for b in bullets[:8] if b])
    if not cuerpo:
        cuerpo = items_block

    # 3) Insertar notificación al superadmin (usuario 'admin' o 'daniel')
    # Buscamos el primer usuario con rol superadmin para destinar la alerta.
    try:
        super_user = mysql_fetchone(
            f"SELECT id FROM `{AUTH_TABLE}` "
            f" WHERE role='superadmin' AND COALESCE(activo,1)=1 "
            f" ORDER BY id ASC LIMIT 1"
        )
        super_id = int(super_user["id"]) if super_user else None
    except Exception:
        super_id = None

    if super_id:
        try:
            _mant_notificar(
                destino_user_id=super_id,
                tipo="ia_alerta_proactiva",
                titulo=titulo,
                cuerpo=cuerpo,
                url_accion="/mantenciones",
                prioridad=prioridad,
            )
        except Exception as _e_not:
            print(f"[ia_alertas_diarias] no se pudo notificar: {_e_not}", flush=True)

    print(f"[ia_alertas_diarias] resumen generado, prioridad={prioridad}, "
          f"bullets={len(bullets)}", flush=True)


# NOTA: el endpoint manual /api/ia/alertas-diarias-run vive más abajo,
# después de la definición del decorador @_mant_required (línea ~23476).
# Si se pone acá arriba, Python falla con NameError en boot.


def _mantenciones_scheduler_run_now():
    """Helper para testing manual: ejecuta el cron una vez sin esperar
    a las 06:00. Usable desde Python REPL local:

        >>> from app import _mantenciones_scheduler_run_now
        >>> _mantenciones_scheduler_run_now()
    """
    return _mant_cron_run_with_lock(slot_str_override="manual")


def _mant_cron_run_with_lock(slot_str_override=None):
    """Ejecuta el cron tomando el lock primero. Asegura un app_context()
    para que los helpers que usan Flask `g` funcionen aunque se llamen
    desde un REPL/REPL/thread fuera de un request."""
    import datetime as _dt
    from zoneinfo import ZoneInfo
    TZ = ZoneInfo("America/Santiago")
    if slot_str_override:
        slot_str = slot_str_override
    else:
        slot_str = _dt.datetime.now(TZ).strftime("%Y-%m-%d 06:00")
    if not _mant_intentar_lock_slot(slot_str):
        print(f"[mant-cron] slot {slot_str} tomado por otro worker, skip", flush=True)
        return {"skipped": True, "slot": slot_str}
    try:
        # Si ya hay un app_context (tests, REPL con app pusheada), reutiliza.
        # Si no, abre uno nuevo. Try/except evita doble push.
        try:
            from flask import current_app as _ca
            _ca.name  # ping — si falla, no hay app_context
            return _mantenciones_cron_run_once(slot_str=slot_str)
        except RuntimeError:
            with app.app_context():
                return _mantenciones_cron_run_once(slot_str=slot_str)
    finally:
        _mant_marcar_lock_completado(slot_str)


def _mantenciones_scheduler_loop():
    """Hilo daemon: dispara el cron de mantenciones a las 06:00 hora Chile.
    Patrón espejo del transp scheduler con lock en mant_cron_lock.

    Importante: corre dentro de `app.app_context()` para que helpers que
    usan Flask `g` (mysql_fetchall via get_db, current_username, etc.)
    funcionen sin RuntimeError."""
    import datetime as _dt
    import time as _time
    from zoneinfo import ZoneInfo

    HORA_RUN = 6     # 06:00 hora Chile
    TZ = ZoneInfo("America/Santiago")
    print(f"[mant-cron] arrancado en worker pid={os.getpid()} "
          f"(hora: {HORA_RUN:02d}:00 CL)", flush=True)

    while True:
        try:
            now_cl = _dt.datetime.now(TZ)
            proxima = now_cl.replace(hour=HORA_RUN, minute=0, second=0, microsecond=0)
            if proxima <= now_cl:
                proxima = proxima + _dt.timedelta(days=1)
            espera_seg = max(1.0, (proxima - now_cl).total_seconds())
            print(f"[mant-cron] próxima corrida: {proxima.strftime('%Y-%m-%d %H:%M')} "
                  f"(en {espera_seg/60:.1f} min)", flush=True)
            _time.sleep(espera_seg)

            slot_str = proxima.strftime("%Y-%m-%d %H:%M")
            if not _mant_intentar_lock_slot(slot_str):
                print(f"[mant-cron] slot {slot_str} tomado por otro worker, skip",
                      flush=True)
                _time.sleep(120)  # esperar 2 min para avanzar el clock
                continue

            print(f"[mant-cron] disparando cron para slot {slot_str} "
                  f"(pid={os.getpid()})", flush=True)
            try:
                # app_context() permite usar Flask `g` desde un thread sin
                # request — necesario para mysql_fetchall (get_db), helpers,
                # etc. NO pushea request_context (no necesitamos session).
                with app.app_context():
                    _mantenciones_cron_run_once(slot_str=slot_str)
            except Exception as e:
                print(f"[mant-cron] corrida falló: {e}", flush=True)
            finally:
                _mant_marcar_lock_completado(slot_str)
        except Exception as e:
            print(f"[mant-cron] loop error: {e}", flush=True)
            _time.sleep(300)  # esperar 5 min ante error inesperado


def _start_mant_scheduler_once():
    import threading as _th
    nombre = "mant-cron"
    for t in _th.enumerate():
        if t.name == nombre and t.is_alive():
            return
    try:
        t = _th.Thread(target=_mantenciones_scheduler_loop, daemon=True, name=nombre)
        t.start()
    except Exception as e:
        print(f"[mant-cron] no se pudo arrancar: {e}", flush=True)


try:
    _start_mant_scheduler_once()
except Exception as _e_msched:
    print(f"[mant-cron] startup error: {_e_msched}", flush=True)


@app.route("/transporte/api/inline-bulto", methods=["POST"])
@_tr_required
def tr_inline_bulto():
    """Guarda medidas de un producto inline desde el modal de detalle.
    Acepta 'bultos': [{largo,ancho,alto,peso}, ...] o campos sueltos (compat.).
    """
    data   = request.get_json(silent=True) or {}
    sku    = (data.get("sku") or "").strip().upper()
    nombre = (data.get("nombre") or "").strip()

    if not sku:
        return jsonify({"error": "Falta el SKU"}), 400

    # Aceptar lista de bultos O campos sueltos (retrocompat.)
    bultos_raw = data.get("bultos") or []
    if not bultos_raw:
        # compatibilidad con versión anterior (campos individuales)
        if data.get("largo"):
            bultos_raw = [{
                "largo": data.get("largo"), "ancho": data.get("ancho"),
                "alto":  data.get("alto"),  "peso":  data.get("peso"),
            }]

    bultos = []
    for b in bultos_raw:
        l = float(b.get("largo") or 0)
        a = float(b.get("ancho") or 0)
        h = float(b.get("alto")  or 0)
        p = float(b.get("peso")  or 0)
        if l and a and h and p:
            bultos.append((l, a, h, p))

    if not bultos:
        return jsonify({"error": "Debes ingresar al menos un bulto con todos sus campos"}), 400

    conn = get_db()
    try:
        with conn.cursor() as cur:
            # Buscar o crear producto
            cur.execute(f"SELECT id FROM `{PRODUCTS_TABLE}` WHERE UPPER(TRIM(sku))=%s LIMIT 1", (sku,))
            row = cur.fetchone()
            if row:
                pid = row["id"]
            else:
                cur.execute(
                    f"INSERT INTO `{PRODUCTS_TABLE}` (sku, nombre, estado, created_by, updated_by) "
                    f"VALUES (%s,%s,'activo',%s,%s)",
                    (sku, nombre or sku, current_username(), current_username())
                )
                pid = cur.lastrowid

            # Reemplazar bultos existentes
            cur.execute(f"DELETE FROM `{BULTOS_TABLE}` WHERE product_id=%s", (pid,))
            for idx, (l, a, h, p) in enumerate(bultos, start=1):
                cur.execute(
                    f"INSERT INTO `{BULTOS_TABLE}` (product_id, bulto_num, largo, ancho, alto, peso) "
                    f"VALUES (%s,%s,%s,%s,%s,%s)",
                    (pid, idx, l, a, h, p)
                )
        conn.commit()
    except Exception as e:
        return jsonify({"error": str(e)}), 500

    # Calcular y retornar totales agregados de todos los bultos
    total_kg  = round(sum(b[3] for b in bultos), 4)
    total_pv  = round(sum(b[0] * b[1] * b[2] for b in bultos) / 4000.0, 4)
    pred      = round(max(total_kg, total_pv), 4)
    return jsonify({
        "ok":      True,
        "peso_kg": total_kg,
        "peso_vol": total_pv,
        "pred":    pred,
    })


@app.route("/transporte/api/upload-foto", methods=["POST"])
@_tr_required
def tr_upload_foto():
    """Sube hasta 2 fotos a un producto (por SKU) desde el modal de transporte."""
    sku = (request.form.get("sku") or "").strip().upper()
    if not sku:
        return jsonify({"error": "Falta el SKU"}), 400
    file = request.files.get("foto")
    if not file or not file.filename:
        return jsonify({"error": "Sin archivo"}), 400
    if not allowed_file(file.filename):
        return jsonify({"error": "Formato no permitido (JPG, PNG, WEBP)"}), 400

    conn = get_db()
    try:
        with conn.cursor() as cur:
            cur.execute(f"SELECT id FROM `{PRODUCTS_TABLE}` WHERE UPPER(TRIM(sku))=%s LIMIT 1", (sku,))
            row = cur.fetchone()
            if row:
                pid = row["id"]
            else:
                cur.execute(
                    f"INSERT INTO `{PRODUCTS_TABLE}` (sku,nombre,estado,created_by,updated_by) VALUES (%s,%s,'activo',%s,%s)",
                    (sku, sku, current_username(), current_username()),
                )
                pid = cur.lastrowid

            cur.execute(f"SELECT COUNT(*) AS n FROM `{PHOTOS_TABLE}` WHERE product_id=%s", (pid,))
            n = (cur.fetchone() or {}).get("n", 0)
            if n >= MAX_PHOTOS:
                return jsonify({"error": f"Máximo {MAX_PHOTOS} fotos por producto"}), 400

            ext = secure_filename(file.filename).rsplit(".", 1)[-1].lower()
            ts  = int(datetime.now().timestamp())
            if _CLD_READY:
                try:
                    filename = _cloud_upload(file, public_id=f"p{pid}_{ts}", folder="ilus/products")
                except Exception as exc:
                    return jsonify({"error": f"Error Cloudinary: {exc}"}), 500
            else:
                filename = f"p{pid}_{ts}.{ext}"
                file.save(os.path.join(UPLOAD_FOLDER, filename))

            cur.execute(
                f"INSERT INTO `{PHOTOS_TABLE}` (product_id,filename,orden) VALUES (%s,%s,%s)",
                (pid, filename, n + 1),
            )
        conn.commit()
        return jsonify({"ok": True, "url": _photo_src(filename), "total": n + 1})
    except Exception as e:
        return jsonify({"error": str(e)}), 500


@app.route("/transporte/api/importar-excel", methods=["POST"])
@_tr_required
def tr_importar_excel():
    """Importa documentos desde un Excel/CSV exportado del ERP."""
    f = request.files.get("archivo")
    if not f or not f.filename:
        return jsonify({"error": "Sin archivo"}), 400
    ext = f.filename.rsplit(".", 1)[-1].lower()
    if ext not in ("xlsx", "xls", "csv"):
        return jsonify({"error": "Solo se aceptan .xlsx, .xls o .csv"}), 400
    data = f.read()
    count, errs, preview = _tr_import_from_excel(data, f.filename)
    _tr_log("commitment", 0, "importar_excel",
            f"Archivo {f.filename}: {count} importados")
    return jsonify({
        "ok": True,
        "importados": count,
        "errores": (errs or [])[:10],
        "preview": preview,
    })


@app.route("/transporte/")
@_tr_required
def transporte_index():
    """Pantalla principal de Transporte.

    🔒 BLINDADO — NO TOCAR salvo bug confirmado por el usuario
    ════════════════════════════════════════════════════════════════════
    Todo el módulo /transporte/* funciona OK en producción y el usuario
    lo usa a diario. Si modificás un endpoint de aquí, probá CADA vista:
      - /transporte/ (dashboard)
      - /transporte/manifiestos
      - /transporte/couriers + /transporte/couriers/<id>
      - /transporte/api/* (los AJAX del dashboard)

    El cubicador (que es parte de Transporte en la UI) tiene su propio
    blindaje en cubicador_export_excel y _cubicador_fetch.
    ════════════════════════════════════════════════════════════════════
    """
    from datetime import date as _date, timedelta as _td

    periodo = request.args.get("periodo", "")
    hoy     = _date.today()

    # Fechas por defecto: último mes
    _default_desde = (hoy - _td(days=30)).strftime("%Y-%m-%d")
    _default_hasta = hoy.strftime("%Y-%m-%d")

    if periodo == "mes":
        fecha_desde, fecha_hasta = _default_desde, _default_hasta
    elif periodo == "3m":
        fecha_desde = (hoy - _td(days=90)).strftime("%Y-%m-%d")
        fecha_hasta = _default_hasta
    elif periodo == "año":
        fecha_desde = hoy.strftime("%Y-01-01")
        fecha_hasta = _default_hasta
    elif periodo == "todo":
        fecha_desde, fecha_hasta = "", ""
    else:
        fecha_desde = request.args.get("fecha_desde", _default_desde).strip()
        fecha_hasta = request.args.get("fecha_hasta", _default_hasta).strip()

    filtros = {
        "estado":        request.args.get("estado", ""),
        "clasificacion": request.args.get("clasificacion", ""),
        "q":             request.args.get("q", "").strip(),
        "fecha_desde":   fecha_desde,
        "fecha_hasta":   fecha_hasta,
    }

    where, params = ["tiene_saldo=1"], []
    if filtros["estado"]:
        where.append("estado=%s"); params.append(filtros["estado"])
    if filtros["clasificacion"]:
        where.append("clasificacion=%s"); params.append(filtros["clasificacion"])
    if filtros["q"]:
        where.append("(cliente_nombre LIKE %s OR nudo LIKE %s OR tido LIKE %s OR comuna LIKE %s)")
        q = f"%{filtros['q']}%"; params += [q, q, q, q]
    if filtros["fecha_desde"]:
        where.append("fecha_emision >= %s"); params.append(filtros["fecha_desde"])
    if filtros["fecha_hasta"]:
        where.append("fecha_emision <= %s"); params.append(filtros["fecha_hasta"])

    sql = ("SELECT * FROM transport_commitments WHERE " +
           " AND ".join(where) + " ORDER BY fecha_emision DESC LIMIT 500")
    compromisos = mysql_fetchall(sql, tuple(params))

    # Manifiestos activos para asignación rápida
    manifiestos = mysql_fetchall(
        "SELECT id,correlativo,courier,estado FROM transport_manifests "
        "WHERE estado IN ('En preparación','En curso') ORDER BY id DESC"
    )
    return render_template(
        "transporte/index.html",
        compromisos=compromisos,
        filtros=filtros,
        estados=ESTADOS_COMPROMISO,
        estado_colors=ESTADO_COLORS,
        couriers=COURIERS,
        manifiestos=manifiestos,
    )


@app.route("/transporte/api/agregar", methods=["POST"])
@_tr_required
def tr_agregar():
    """Agrega un documento al monitor desde el ERP."""
    tido = (request.form.get("tido") or "FCV").strip().upper()
    nudo = (request.form.get("nudo") or "").strip()
    if not nudo:
        return jsonify({"error": "Ingresa el número de documento"}), 400
    comm_id, err = _tr_fetch_from_erp(tido, nudo)
    if err:
        return jsonify({"error": err}), 404
