# ── MANIFIESTOS ──────────────────────────────────────────────────

@app.route("/transporte/manifiestos")
@_tr_required
def tr_manifiestos():
    # Filtros + búsqueda libre + paginación.
    # Búsqueda (q) matchea contra correlativo, courier y notas (LIKE %q%).
    # page=1 default. Page size = 50 (balance entre fluidez y scroll mobile).
    PAGE_SIZE = 50
    filtros = {
        "courier": request.args.get("courier", "").strip(),
        "estado":  request.args.get("estado", "").strip(),
        "q":       request.args.get("q", "").strip(),
    }
    try:
        page = max(1, int(request.args.get("page", "1")))
    except Exception:
        page = 1

    where, params = ["1=1"], []
    if filtros["courier"]:
        where.append("courier=%s"); params.append(filtros["courier"])
    if filtros["estado"]:
        where.append("estado=%s"); params.append(filtros["estado"])
    if filtros["q"]:
        q_like = f"%{filtros['q']}%"
        where.append("(correlativo LIKE %s OR courier LIKE %s OR notas LIKE %s)")
        params.extend([q_like, q_like, q_like])

    where_sql = " AND ".join(where)
    # Total para paginación (count separado, barato con WHERE indexado)
    total_row = mysql_fetchone(
        "SELECT COUNT(*) AS n FROM transport_manifests WHERE " + where_sql,
        tuple(params)
    ) or {}
    total = int(total_row.get("n") or 0)
    total_pages = max(1, (total + PAGE_SIZE - 1) // PAGE_SIZE)
    if page > total_pages:
        page = total_pages

    offset = (page - 1) * PAGE_SIZE
    manifiestos = mysql_fetchall(
        "SELECT * FROM transport_manifests WHERE " + where_sql +
        " ORDER BY fecha DESC, id DESC LIMIT %s OFFSET %s",
        tuple(params) + (PAGE_SIZE, offset)
    )
    return render_template(
        "transporte/manifiestos.html",
        manifiestos=manifiestos,
        filtros=filtros,
        couriers=COURIERS,
        estados_manifest=["En preparación", "En curso", "Cerrado", "Entregado completo"],
        paginacion={
            "page": page,
            "total_pages": total_pages,
            "total": total,
            "page_size": PAGE_SIZE,
            "has_prev": page > 1,
            "has_next": page < total_pages,
        },
    )


@app.route("/transporte/manifiestos/nuevo", methods=["POST"])
@_tr_required
def tr_crear_manifiesto():
    courier = request.form.get("courier", "").strip()
    fecha   = request.form.get("fecha", "").strip()
    notas   = request.form.get("notas", "").strip()
    if not courier or not fecha:
        return jsonify({"error": "courier y fecha son obligatorios"}), 400

    conn = get_db()
    try:
        with conn.cursor() as cur:
            # Correlativo auto: MAN-YYYY-NNNN
            cur.execute(
                "SELECT COUNT(*)+1 AS n FROM transport_manifests "
                "WHERE YEAR(created_at)=YEAR(NOW())"
            )
            n = (cur.fetchone() or {}).get("n", 1)
            from datetime import datetime as _dt
            corr = f"MAN-{_dt.now().year}-{int(n):04d}"
            cur.execute(
                "INSERT INTO transport_manifests (correlativo,fecha,courier,notas,created_by) "
                "VALUES (%s,%s,%s,%s,%s)",
                (corr, fecha, courier, notas, current_username())
            )
            mid = cur.lastrowid
        conn.commit()
    finally:
        conn.close()

    _tr_log("manifest", mid, "creado", f"courier={courier} fecha={fecha}")
    return jsonify({"ok": True, "id": mid, "correlativo": corr})


@app.route("/transporte/manifiestos/<int:mid>")
@_tr_required
def tr_manifiesto_detalle(mid):
    try:
        manifiesto = mysql_fetchone(
            "SELECT * FROM transport_manifests WHERE id=%s", (mid,)
        )
        if not manifiesto:
            flash("Manifiesto no encontrado", "danger")
            return redirect(url_for("tr_manifiestos"))

        def _fetch_items():
            return mysql_fetchall("""
                SELECT mi.*, c.tido, c.nudo, c.cliente_nombre, c.comuna,
                       c.direccion, c.telefono, c.email, c.region, c.cod_postal,
                       c.tiene_saldo, COALESCE(c.cobertura_pct, 0) AS cobertura_pct,
                       COALESCE(c.peso_export, 0) AS peso_export,
                       COALESCE(c.n_bultos, 1) AS n_bultos,
                       c.valor_bruto, c.costo_zz, c.clasificacion,
                       COALESCE(c.zz_envio, 0)          AS zz_envio,
                       COALESCE(c.costo_courier, 0)     AS costo_courier,
                       c.autorizado_por, c.motivo_envio,
                       COALESCE(c.es_garantia, 0)       AS es_garantia,
                       COALESCE(c.peso_real, 0)         AS peso_real,
                       COALESCE(c.peso_vol, 0)          AS peso_vol,
                       COALESCE(c.volumen_m3, 0)        AS volumen_m3,
                       COALESCE(c.peso_predominante, 0) AS peso_predominante,
                       c.productos_json
                FROM transport_manifest_items mi
                JOIN transport_commitments c ON c.id = mi.commitment_id
                WHERE mi.manifest_id=%s
                ORDER BY mi.orden, mi.id
            """, (mid,))

        items = _fetch_items()

        # ── AUTO-SANE: items viejos sin datos financieros completos ──
        # costo_courier viejo se guardaba en costo_zz; zz_envio (lo cobrado) se
        # recupera del ERP por la vía SQL estable. Una sola vez por item.
        _healed = False
        for it in items:
            cid = it["commitment_id"]
            if (not it.get("costo_courier")) and float(it.get("costo_zz") or 0) > 0:
                try:
                    mysql_execute(
                        "UPDATE transport_commitments SET costo_courier=%s "
                        "WHERE id=%s AND COALESCE(costo_courier,0)=0",
                        (float(it["costo_zz"]), cid))
                    _healed = True
                except Exception as e_h1:
                    print(f"[manif heal costo] {e_h1}", flush=True)
            if (not it.get("zz_envio")) and it.get("tido") and it.get("nudo"):
                try:
                    _tr_fetch_from_erp(it["tido"], str(it["nudo"]))  # repuebla zz_envio/peso/vol
                    _healed = True
                except Exception as e_h2:
                    print(f"[manif heal zz_envio] {e_h2}", flush=True)
        if _healed:
            items = _fetch_items()  # releer con los datos ya sanados

        # Productos por factura (árbol manifiesto → factura → productos).
        # Una sola query batch para todos los commitments del manifiesto.
        comm_ids = [it["commitment_id"] for it in items]
        prod_por_comm = {}
        if comm_ids:
            _ph = ",".join(["%s"] * len(comm_ids))
            for pl in (mysql_fetchall(
                f"""SELECT commitment_id, koprct, nokopr, cantidad, cant_despachada, saldo
                    FROM transport_commitment_lines
                    WHERE commitment_id IN ({_ph})
                    ORDER BY id""", tuple(comm_ids)) or []):
                prod_por_comm.setdefault(pl["commitment_id"], []).append(pl)
        # Enriquecer cada item con margen y sus productos
        for it in items:
            cobrado = float(it.get("zz_envio") or 0)
            costo   = float(it.get("costo_courier") or 0)
            it["margen_clp"] = round(cobrado - costo)
            it["margen_pct"] = round((cobrado - costo) / cobrado * 100, 1) if cobrado > 0 else None
            it["sin_precio"] = (cobrado <= 0)
            it["es_perdida"] = (cobrado > 0 and costo > cobrado)
            # Productos: preferir los declarados desde el cubicador (productos_json,
            # productos REALES); si no hay, caer a commitment_lines (líneas ZZ).
            _prods = []
            if it.get("productos_json"):
                try:
                    import json as _jp
                    _prods = _jp.loads(it["productos_json"]) or []
                except Exception:
                    _prods = []
            it["productos"] = _prods if _prods else prod_por_comm.get(it["commitment_id"], [])

        logs = mysql_fetchall(
            "SELECT * FROM transport_logs WHERE entity_type='manifest' AND entity_id=%s "
            "ORDER BY created_at DESC LIMIT 30", (mid,)
        )
        return render_template(
            "transporte/manifiesto_detalle.html",
            manifiesto=manifiesto,
            items=items,
            logs=logs,
            estados_entrega=ESTADOS_ENTREGA,
            estados_manifest=["En preparación", "En curso", "Cerrado", "Entregado completo"],
            couriers=COURIERS,
        )
    except Exception as e:
        import traceback, html as _htmlmod
        tb = traceback.format_exc()
        print(f"[manifiesto_detalle {mid}] ERROR:\n{tb}", flush=True)
        # Página de error amigable (no extiende base.html para evitar fallos en cascada)
        msg = _htmlmod.escape(f"{type(e).__name__}: {e}")
        return (f"""<!doctype html><html lang="es"><head><meta charset="utf-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>Error al cargar manifiesto</title>
<style>body{{font-family:system-ui,Segoe UI,Roboto,sans-serif;background:#fafafa;color:#0f172a;padding:32px;max-width:760px;margin:0 auto}}
.card{{background:#fff;border:1px solid #e5e7eb;border-radius:12px;padding:24px;box-shadow:0 2px 8px rgba(0,0,0,.05)}}
h1{{color:#dc2626;font-size:1.2rem}} code{{background:#fee2e2;color:#991b1b;padding:8px 10px;border-radius:8px;display:block;white-space:pre-wrap;font-size:.82rem;margin-top:10px}}
a{{color:#dc2626;font-weight:700;text-decoration:none}}</style></head>
<body><div class="card">
<h1>⚠️ No se pudo cargar el manifiesto #{mid}</h1>
<p>El manifiesto se guardó, pero hubo un error al mostrar el detalle. Manda esta captura a soporte:</p>
<code>{msg}</code>
<p style="margin-top:16px"><a href="/transporte/manifiestos">← Volver a manifiestos</a></p>
</div></body></html>""", 500)


# ════════════════════════════════════════════════════════════════════════
#  ETIQUETAS DE TRANSPORTE (bultos por manifiesto / por factura)
#  ───────────────────────────────────────────────────────────────────────
#  Replica la técnica del módulo de etiquetas de Productos (label_standalone.html):
#    • Código de barras CODE128 vía JsBarcode (CDN) en el front.
#    • Template standalone imprimible con @page + page-break-after por etiqueta.
#  Una etiqueta por bulto: n_bultos por factura (mínimo 1), numeradas "X de N".
#  Remitente FIJO. NO toca el ERP — solo lee tablas MySQL propias (transport_*).
# ════════════════════════════════════════════════════════════════════════

# Remitente fijo de todas las etiquetas (origen de los despachos).
ILUS_REMITENTE = {
    "nombre":    "SPORT AND HEALTH SOLUTIONS",
    "direccion": "Eduardo Frei Montalva 9770, Bod 30, Quilicura",
}


def _tr_etiqueta_facturas(commitment_ids):
    """Construye la estructura de etiquetas para una lista de commitment_ids.

    Devuelve una lista de dicts (una por FACTURA), cada uno con sus N bultos
    expandidos (n_bultos, mínimo 1). Lee SOLO de transport_commitments
    (tablas propias MySQL). Mantiene el orden de entrada de los ids.
    """
    if not commitment_ids:
        return []
    _ph  = ",".join(["%s"] * len(commitment_ids))
    rows = mysql_fetchall(
        "SELECT id, tido, nudo, cliente_nombre, comuna, direccion, telefono, "
        "       COALESCE(n_bultos, 1) AS n_bultos "
        "FROM transport_commitments "
        f"WHERE id IN ({_ph})",
        tuple(commitment_ids),
    ) or []
    by_id = {r["id"]: r for r in rows}

    facturas = []
    for cid in commitment_ids:
        c = by_id.get(cid)
        if not c:
            continue
        total = int(c.get("n_bultos") or 1)
        if total < 1:
            total = 1
        doc = (f"{(c.get('tido') or '').strip()} {(c.get('nudo') or '').strip()}").strip()
        facturas.append({
            "commitment_id": cid,
            "doc_numero":    (c.get("nudo") or "").strip(),
            "doc_tipo":      (c.get("tido") or "").strip(),
            "doc_full":      doc,
            "cliente":       (c.get("cliente_nombre") or "").strip(),
            "telefono":      (c.get("telefono") or "").strip(),
            "direccion":     (c.get("direccion") or "").strip(),
            "comuna":        (c.get("comuna") or "").strip(),
            "total_bultos":  total,
            "bultos":        [{"num": n, "total": total} for n in range(1, total + 1)],
        })
    return facturas


def _tr_upsert_labels(facturas, manifest_id=None, courier=""):
    """UPSERT de filas en transport_labels (una por bulto) con estado 'generada'.

    Alimenta el tracking aguas abajo. Idempotente por (commitment_id, manifest_id,
    bulto_num) gracias a la UNIQUE KEY de la tabla. Si la tabla no existe todavía
    (cold-start raro), no rompe la generación de etiquetas — solo loguea.
    """
    if not facturas:
        return
    try:
        conn = get_db()
        with conn.cursor() as cur:
            for f in facturas:
                for b in f["bultos"]:
                    cur.execute(
                        "INSERT INTO transport_labels "
                        "  (commitment_id, manifest_id, bulto_num, bulto_total, courier, estado) "
                        "VALUES (%s,%s,%s,%s,%s,'generada') "
                        "ON DUPLICATE KEY UPDATE "
                        "  bulto_total=VALUES(bulto_total), "
                        "  courier=VALUES(courier), "
                        "  updated_at=NOW()",
                        (f["commitment_id"], manifest_id or 0, b["num"], b["total"], courier or ""),
                    )
        conn.commit()
    except Exception as e_lbl:
        print(f"[tr_labels] upsert falló (no bloquea impresión): {e_lbl}", flush=True)


@app.route("/transporte/manifiestos/<int:mid>/etiquetas")
@_tr_required
def tr_manifiesto_etiquetas(mid):
    """Etiquetas de bultos de TODAS las facturas de un manifiesto."""
    manifiesto = mysql_fetchone(
        "SELECT * FROM transport_manifests WHERE id=%s", (mid,)
    )
    if not manifiesto:
        flash("Manifiesto no encontrado", "danger")
        return redirect(url_for("tr_manifiestos"))

    items = mysql_fetchall(
        "SELECT commitment_id FROM transport_manifest_items "
        "WHERE manifest_id=%s ORDER BY orden, id", (mid,)
    ) or []
    commitment_ids = [it["commitment_id"] for it in items]
    facturas = _tr_etiqueta_facturas(commitment_ids)

    courier = manifiesto.get("courier") or ""
    _tr_upsert_labels(facturas, manifest_id=mid, courier=courier)

    total_etiquetas = sum(f["total_bultos"] for f in facturas)
    _tr_log("manifest", mid, "etiquetas generadas",
            f"{len(facturas)} facturas, {total_etiquetas} bultos")

    return render_template(
        "transporte/etiquetas.html",
        facturas    = facturas,
        remitente   = ILUS_REMITENTE,
        fecha       = _now_chile_str("%d-%m-%Y %H:%M"),
        titulo      = f"Etiquetas · Manifiesto {manifiesto.get('correlativo') or mid}",
        courier     = courier,
        total_etiquetas = total_etiquetas,
    )


