def _tr_manifiesto_export_impl(mid):
    try:
        import openpyxl
        from openpyxl.styles import Font, PatternFill, Alignment
    except Exception:
        flash("openpyxl no está instalado en el servidor.", "danger")
        return redirect(url_for("tr_manifiesto_detalle", mid=mid))
    from io import BytesIO
    from flask import send_file

    man = mysql_fetchone("SELECT * FROM transport_manifests WHERE id=%s", (mid,))
    if not man:
        flash("Manifiesto no encontrado", "danger")
        return redirect(url_for("tr_manifiestos"))

    items = _tr_manifiesto_items_export(mid)
    if not items:
        flash("Este manifiesto no tiene items para exportar.", "warning")
        return redirect(url_for("tr_manifiesto_detalle", mid=mid))

    # Defensivo: si la columna formato_export aún no existe (ensure no corrió
    # o falló), no rompemos el export — caemos a la auto-detección por nombre.
    try:
        fmt_row = mysql_fetchone(
            "SELECT formato_export FROM transport_couriers WHERE LOWER(nombre)=LOWER(%s) LIMIT 1",
            (man.get("courier") or "",)
        )
        formato = ((fmt_row or {}).get("formato_export") or "").strip().lower()
    except Exception as _e_fmt:
        print(f"[manif_export] formato_export SELECT falló: {_e_fmt}", flush=True)
        formato = ""

    # Auto-detección por nombre del courier (robusto: no depende del seed
    # de init_transporte_tables, que en prod está skipeado). Daniel pidió que
    # el export SIEMPRE produzca el formato correcto para cargar al sistema
    # externo (SimplyRoute / FedEx Bulk / Clickex).
    if not formato or formato == "generic":
        _cname = (man.get("courier") or "").strip().lower()
        if "fedex" in _cname:
            formato = "fedex"
        elif "clickex" in _cname:
            formato = "clickex"
        elif "felca" in _cname or "milling" in _cname or "melling" in _cname:
            formato = "simplyroute"
        else:
            formato = "generic"

    wb = openpyxl.Workbook()
    ws = wb.active
    HDR_FILL  = PatternFill("solid", fgColor="0A0A0A")
    HDR_FONT  = Font(color="FFFFFF", bold=True)
    MISS_FILL = PatternFill("solid", fgColor="FEE2E2")  # rojo claro = dato faltante

    def _hdr(headers):
        for ci, h in enumerate(headers, 1):
            cell = ws.cell(1, ci, h)
            cell.font = HDR_FONT
            cell.fill = HDR_FILL
            cell.alignment = Alignment(horizontal="center", wrap_text=True)

    def _falta(v):
        return not str(v or "").strip()

    # Sanitiza strings para Excel: openpyxl lanza IllegalCharacterError si un
    # texto trae caracteres de control (llegan desde el ERP en notas/dirección/
    # observaciones). Los quitamos antes de escribir la celda. (Daniel 30/05/2026)
    import re as _re_xc
    _ILLEGAL_XLSX = _re_xc.compile(r"[\x00-\x08\x0b\x0c\x0e-\x1f]")
    def _xc(v):
        return _ILLEGAL_XLSX.sub("", v) if isinstance(v, str) else v

    # Helpers FedEx: la plantilla oficial limita ciertos campos a 35 chars
    # (senderContactName, senderLine1, senderLine2, recipientContactName,
    # recipientLine1, recipientLine2). Hay que truncar/dividir inteligente
    # para que FedEx no rechace la carga masiva.
    FEDEX_MAX = 35

    def _trunc(v, n=FEDEX_MAX):
        s = (v or "").strip()
        return s[:n]

    def _split_address(addr, n=FEDEX_MAX):
        """Divide una dirección larga en (line1, line2) sin cortar palabras.
        Si cabe en n chars → (addr, ''). Si no, busca el último espacio/coma
        antes del límite y rompe ahí; el resto va a line2 (también truncado a n).
        """
        s = (addr or "").strip()
        if len(s) <= n:
            return s, ""
        # Buscar último separador natural antes del límite
        cut = -1
        for sep in (", ", " - ", " "):
            cut = s.rfind(sep, 0, n)
            if cut > n // 2:  # evita cortes demasiado tempranos
                break
        if cut <= n // 2:
            cut = n  # fallback: corte duro
        line1 = s[:cut].rstrip(" ,-")
        line2 = s[cut:].lstrip(" ,-")[:n]
        return line1, line2

    if formato == "fedex":
        ws.title = "FedEx"
        s = _tr_sender_cfg()
        _hdr([
            "reference", "senderContactName", "senderCompany", "senderContactNumber",
            "senderEmail", "senderLine1", "senderLine2", "senderPostcode", "senderState",
            "senderCity", "senderCountry", "recipientContactName", "recipientCompany",
            "recipientContactNumber", "recipientEmail", "recipientLine1", "recipientLine2",
            "recipientLine3", "recipientPostcode", "recipientState", "recipientCity",
            "recipientCountry", "packageType", "numberOfPackages", "packageWeight",
            "weightUnits", "length", "width", "height", "serviceType", "currencyType",
            "recipientDeliveryNotification", "recipientExceptionNotification",
            "recipientShipAlertNotification", "recipientNotificationLanguageCode",
            "senderExceptionNotification",
        ])
        # Sender pre-truncado una vez (es FIJO por instancia)
        sender_name  = _trunc(s["name"])
        sender_l1, sender_l2_split = _split_address(s["line1"])
        # Si el sender ya tiene line2 propio (config) y line1 cabía, respetar.
        if not sender_l2_split:
            sender_l2 = _trunc(s.get("line2", ""))
        else:
            sender_l2 = sender_l2_split

        for ri, it in enumerate(items, 2):
            nbult = max(1, int(it.get("n_bultos") or 1))
            peso  = float(it.get("peso_kg") or 0)
            ppp   = round(peso / nbult, 3) if nbult else peso
            # Recipient: nombre + address con split inteligente
            rcp_name = _trunc(it.get("cliente_nombre") or "")
            rcp_l1, rcp_l2 = _split_address(it.get("direccion") or "")
            row = [
                it.get("nudo") or "",
                sender_name, s["company"], s["phone"], s["email"], sender_l1, sender_l2,
                s["postcode"], s["state"], s["city"], s["country"],
                rcp_name, "",
                it.get("telefono") or "", it.get("email") or "",
                rcp_l1, rcp_l2, "",
                it.get("cod_postal") or "", "CL",
                _trunc(it.get("region") or it.get("comuna") or "", 35), "CL",
                "YOUR_PACKAGING", nbult, ppp, "KGS", 1, 1, 1,
                "FEDEX_PRIORITY", "CLP", "Y", "Y", "Y", "ES", "Y",
            ]
            for ci, v in enumerate(row, 1):
                ws.cell(ri, ci, _xc(v))
            if _falta(it.get("telefono")): ws.cell(ri, 14).fill = MISS_FILL
            if _falta(it.get("email")):    ws.cell(ri, 15).fill = MISS_FILL

    elif formato == "simplyroute":
        ws.title = "Felca y Milling"
        _hdr([
            "Título*   Requerido", "Dirección completa*   Requerido", "Carga",
            "Hora inicial", "Hora final", "Tiempo de servicio", "Notas", "Latitud",
            "Longitud", "Id de referencia", "Habilidades requeridas", "Habilidades KILOS",
            "Persona de contacto", "Teléfono de contacto", "Hora inicial 2", "Hora final 2",
            "Carga 2", "Carga 3", "Prioridad", "SMS", "Correo electrónico de contacto",
            "Carga pick", "Carga pick 2", "Carga pick 3", "Fecha programada", "Tipo de visita",
        ])
        for ri, it in enumerate(items, 2):
            nombre = (it.get("cliente_nombre") or "").strip()
            nudo   = it.get("nudo") or ""
            comuna = (it.get("comuna") or "").strip()
            dirc   = (it.get("direccion") or "").strip()
            peso   = round(float(it.get("peso_kg") or 0), 2)
            titulo = (f"{nudo} - {nombre}").strip(" -")
            row = [
                titulo, (f"{dirc} ,{comuna}").strip(" ,"),
                max(1, int(it.get("n_bultos") or 1)),
                "09:00:00", "23:59:00", 3, (it.get("notas") or ""), "", "",
                nudo, comuna, peso, nombre, it.get("telefono") or "",
                "", "", "", "", "", "", it.get("email") or "",
                "", "", "", "", "",
            ]
            for ci, v in enumerate(row, 1):
                ws.cell(ri, ci, _xc(v))
            if _falta(it.get("telefono")): ws.cell(ri, 14).fill = MISS_FILL
            if _falta(it.get("email")):    ws.cell(ri, 21).fill = MISS_FILL

    elif formato == "clickex":
        ws.title = "Clickex"
        # Formato Clickex (11 cols, tomado del .xlsx que entrega Clickex).
        _hdr([
            "Cliente", "Direccion", "Depto/Casa", "Comuna", "Referencia",
            "Telefono", "Correo", "Orden Seller", "Peso Total",
            "Monto Declarado", "Bultos",
        ])
        s = _tr_sender_cfg()
        seller = s.get("company") or "Sport and Health Solutions SPA"
        for ri, it in enumerate(items, 2):
            nbult = max(1, int(it.get("n_bultos") or 1))
            peso  = round(float(it.get("peso_kg") or 0), 2)
            valor = float(it.get("valor_bruto") or 0)
            row = [
                it.get("cliente_nombre") or "",
                it.get("direccion") or "",
                "",  # Depto/Casa (campo libre opcional)
                it.get("comuna") or "",
                it.get("nudo") or "",   # Referencia interna = nº documento
                it.get("telefono") or "",
                it.get("email") or "",
                seller,
                peso,
                valor,
                nbult,
            ]
            for ci, v in enumerate(row, 1):
                ws.cell(ri, ci, _xc(v))
            if _falta(it.get("telefono")): ws.cell(ri, 6).fill = MISS_FILL
            if _falta(it.get("email")):    ws.cell(ri, 7).fill = MISS_FILL

    else:  # generic
        ws.title = "Manifiesto"
        _hdr(["Documento", "Cliente", "Comuna", "Dirección", "Teléfono", "Email",
              "Peso (kg)", "Bultos"])
        for ri, it in enumerate(items, 2):
            row = [
                (f"{it.get('tido') or ''} {it.get('nudo') or ''}").strip(),
                it.get("cliente_nombre") or "", it.get("comuna") or "",
                it.get("direccion") or "", it.get("telefono") or "",
                it.get("email") or "", round(float(it.get("peso_kg") or 0), 2),
                max(1, int(it.get("n_bultos") or 1)),
            ]
            for ci, v in enumerate(row, 1):
                ws.cell(ri, ci, _xc(v))
            if _falta(it.get("telefono")): ws.cell(ri, 5).fill = MISS_FILL
            if _falta(it.get("email")):    ws.cell(ri, 6).fill = MISS_FILL

    buf = BytesIO()
    wb.save(buf)
    buf.seek(0)
    try:
        _tr_log("manifest", mid, "exportado", f"formato={formato} items={len(items)}")
    except Exception:
        pass
    safe_corr = (man.get("correlativo") or f"MAN{mid}").replace("/", "-")
    # Nombre estilo macro de Daniel: "Felca_30052026_13.24.xlsx",
    # "DocumentosFedEx_30052026_13.26.xlsx", "Clickex_..", "Milling_..".
    from datetime import datetime as _dt_now
    _stamp = _dt_now.now().strftime("%d%m%Y_%H.%M")
    if formato == "fedex":
        _fname = f"DocumentosFedEx_{_stamp}.xlsx"
    elif formato in ("simplyroute", "clickex"):
        # Para SimplyRoute usamos el nombre del courier (Felca/Milling); Clickex su propio.
        _parts = (man.get("courier") or "").strip().split()
        _courier = (_parts[-1] if _parts else "") or ("Clickex" if formato == "clickex" else "Manifiesto")
        _courier_clean = _courier.replace("/", "-").replace(" ", "_")
        _fname = f"{_courier_clean}_{_stamp}.xlsx"
    else:
        _fname = f"{safe_corr}_{formato}.xlsx"
    return send_file(
        buf,
        mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        as_attachment=True,
        download_name=_fname,
    )


# ── MANIFIESTOS: asignar compromiso desde drag-drop ──────────────────────────

@app.route("/transporte/api/manifiestos/asignar", methods=["POST"])
@_tr_required
def tr_asignar_a_manifiesto():
    """Asigna uno o más compromisos a un manifiesto (crea si mid=None)."""
    data         = request.get_json(silent=True) or {}
    commitment_ids = data.get("commitment_ids", [])
    mid          = data.get("manifest_id")     # None → crear nuevo

    if not commitment_ids:
        return jsonify({"error": "sin compromisos"}), 400

    conn = get_db()
    with conn.cursor() as cur:
        # crear manifiesto nuevo si no se indicó uno
        if not mid:
            courier = data.get("courier", "Por asignar")
            fecha   = data.get("fecha") or __import__("datetime").date.today().isoformat()
            cur.execute(
                "SELECT COALESCE(MAX(CAST(SUBSTRING(correlativo,4) AS UNSIGNED)),0)+1 FROM transport_manifests"
            )
            num = cur.fetchone()[0] or 1
            correlativo = f"MAN{num:04d}"
            cur.execute(
                """INSERT INTO transport_manifests (correlativo, fecha, courier, created_by)
                   VALUES (%s,%s,%s,%s)""",
                (correlativo, fecha, courier, current_user.correo),
            )
            mid = cur.lastrowid
        else:
            correlativo = None

        added, dupes = 0, 0
        for cid in commitment_ids:
            try:
                cur.execute(
                    """INSERT IGNORE INTO transport_manifest_items
                       (manifest_id, commitment_id) VALUES (%s,%s)""",
                    (mid, cid),
                )
                if cur.rowcount:
                    added += 1
                else:
                    dupes += 1
            except Exception:
                dupes += 1

        # recalcular total_items
        cur.execute(
            "UPDATE transport_manifests SET total_items=(SELECT COUNT(*) FROM transport_manifest_items WHERE manifest_id=%s) WHERE id=%s",
            (mid, mid),
        )

    conn.commit()
    return jsonify({"ok": True, "manifest_id": mid, "correlativo": correlativo, "added": added, "duplicados": dupes})


# ════════════════════════════════════════════════════════════════════════
#  CUBICADOR → MANIFIESTO
#  Endpoint para enviar el resultado de la cotización del cubicador
#  directamente a un manifiesto (existente o nuevo).
# ════════════════════════════════════════════════════════════════════════

@app.route("/transporte/api/manifiestos/abiertos", methods=["GET"])
@_tr_required
def tr_manifiestos_abiertos():
    """Devuelve manifiestos abiertos para el selector del cubicador.

    Estados considerados "abiertos": 'En preparación', 'En curso'.

    Query params:
      ?courier=Nombre  → filtra ESTRICTAMENTE los del mismo courier.
                         Decisión Daniel (2026-05-31): Clickex no puede mezclar
                         con Milling/Felca. Cada manifiesto = un solo courier.
      ?strict=0        → modo legacy: solo ORDENA por courier preferido pero
                         devuelve todos (para vistas administrativas).
    """
    courier_pref = (request.args.get("courier") or "").strip()
    strict = request.args.get("strict", "1") != "0"  # default estricto
    try:
        if strict and courier_pref:
            rows = mysql_fetchall("""
                SELECT id, correlativo, fecha, courier, estado,
                       COALESCE(total_items, 0) AS total_items,
                       COALESCE(costo_total, 0) AS costo_total
                  FROM transport_manifests
                 WHERE estado IN ('En preparación','En curso')
                   AND LOWER(TRIM(courier)) = LOWER(TRIM(%s))
                 ORDER BY fecha DESC, id DESC
                 LIMIT 50
            """, (courier_pref,)) or []
            # Conteo de "otros couriers" para mostrar info al operador
            other_row = mysql_fetchone("""
                SELECT COUNT(*) AS n FROM transport_manifests
                 WHERE estado IN ('En preparación','En curso')
                   AND LOWER(TRIM(courier)) <> LOWER(TRIM(%s))
            """, (courier_pref,)) or {}
            other_count = int(other_row.get("n") or 0)
        else:
            rows = mysql_fetchall("""
                SELECT id, correlativo, fecha, courier, estado,
                       COALESCE(total_items, 0) AS total_items,
                       COALESCE(costo_total, 0) AS costo_total
                  FROM transport_manifests
                 WHERE estado IN ('En preparación','En curso')
                 ORDER BY (courier=%s) DESC, fecha DESC, id DESC
                 LIMIT 50
            """, (courier_pref,)) or []
            other_count = 0
    except Exception as e:
        return jsonify({"error": f"Error consultando manifiestos: {e}"}), 500

    for r in rows:
        # Normalizar fecha a YYYY-MM-DD para el frontend
        if r.get("fecha"):
            r["fecha"] = r["fecha"].isoformat() if hasattr(r["fecha"], "isoformat") else str(r["fecha"])
    return jsonify({
        "ok": True,
        "manifiestos": rows,
        "courier_filtro": courier_pref if strict else "",
        "strict": strict,
        "otros_courier_count": other_count,
    })


@app.route("/transporte/api/cubicador/enviar-manifiesto", methods=["POST"])
@_tr_required
def tr_cubicador_enviar_manifiesto():
    """Flujo unificado: desde el cubicador, persiste el commitment (tido,nudo)
    y lo adjunta a un manifiesto existente o crea uno nuevo.

    Body JSON:
      tido, nudo:        documento del cubicador (obligatorio)
      courier:           nombre del courier (obligatorio, ej. 'FedEx')
      costo_cotizado:    costo a guardar en transport_commitments.costo_zz
      manifest_id:       ID si va a manifiesto existente, None para crear nuevo
      fecha:             solo si crea nuevo (YYYY-MM-DD)
      notas:             solo si crea nuevo (opcional)
    """
    data = request.get_json(silent=True) or {}
    tido = (data.get("tido") or "").strip().upper()
    nudo = str(data.get("nudo") or "").strip()
    courier = (data.get("courier") or "").strip()[:80]
    costo_cot = data.get("costo_cotizado")
    mid_in = data.get("manifest_id")

    if not tido or not nudo:
        return jsonify({"error": "tido y nudo son obligatorios"}), 400
    if not courier:
        return jsonify({"error": "Selecciona un courier antes de enviar"}), 400

    # 0) Validar coherencia courier ↔ manifiesto destino.
    #    Decisión Daniel (2026-05-31): un manifiesto = un solo courier. Si el
    #    operador elige FedEx pero apunta a un manifiesto de Clickex, rechazar
    #    explícito (no autocorregir silencioso).
    if mid_in:
        try:
            _man_row = mysql_fetchone(
                "SELECT courier, estado FROM transport_manifests WHERE id=%s",
                (int(mid_in),)
            )
            if not _man_row:
                return jsonify({"error": f"Manifiesto #{mid_in} no existe."}), 404
            _man_courier = (_man_row.get("courier") or "").strip()
            if _man_courier and _man_courier.lower() != courier.lower():
                return jsonify({
                    "error": (
                        f"El manifiesto seleccionado es de courier "
                        f"\"{_man_courier}\" y estás cotizando con \"{courier}\". "
                        f"Crea un manifiesto nuevo o elige uno de {courier}."
                    ),
                    "courier_manifiesto": _man_courier,
                    "courier_cotizado": courier,
                }), 409
            if (_man_row.get("estado") or "").strip() not in ("En preparación", "En curso"):
                return jsonify({
                    "error": f"Manifiesto #{mid_in} está en estado "
                             f"\"{_man_row.get('estado')}\" — no se pueden agregar items."
                }), 409
        except ValueError:
            return jsonify({"error": "manifest_id inválido"}), 400
        except Exception as e_check:
            print(f"[cub_enviar_manif] check coherencia courier falló: {e_check}", flush=True)
            # No bloqueamos por errores transitorios de check — el flujo sigue.

    # 1) Upsert commitment desde ERP (helper existente, ya probado)
    try:
        comm_id, err = _tr_fetch_from_erp(tido, nudo)
    except Exception as e_erp:
        print(f"[cub_enviar_manif] _tr_fetch_from_erp reventó: {e_erp}", flush=True)
        return jsonify({"error": f"No se pudo leer el documento del ERP: {e_erp}"}), 502
    if err:
        return jsonify({"error": f"ERP: {err}"}), 404
    if not comm_id:
        return jsonify({"error": "No se pudo registrar el documento en el sistema."}), 500

    # 2) Persistir costo del courier (lo que paga SPHS). Se guarda en costo_courier
    #    (para el match cobrado-vs-costo del manifiesto) y también en costo_zz (legacy).
    try:
        if costo_cot is not None and float(costo_cot) > 0:
            mysql_execute(
                "UPDATE transport_commitments SET costo_zz=%s, costo_courier=%s WHERE id=%s",
                (float(costo_cot), float(costo_cot), comm_id)
            )
    except Exception as e_cost:
        print(f"[cub_enviar_manif] no se pudo guardar costo: {e_cost}", flush=True)

    # 2c) Autorización / motivo / garantía (control financiero, visión Daniel).
    #     Obligatorio cuando el envío va a pérdida o sin precio. No fatal si falla.
    _autoriz = (data.get("autorizado_por") or "").strip()[:190]
    _motivo  = (data.get("motivo_envio") or "").strip()[:500]
    _garant  = 1 if data.get("es_garantia") else 0
    if _autoriz or _motivo or _garant:
        try:
            mysql_execute(
                "UPDATE transport_commitments SET autorizado_por=%s, motivo_envio=%s, "
                "es_garantia=%s WHERE id=%s",
                (_autoriz or None, _motivo or None, _garant, comm_id)
            )
        except Exception as e_auth:
            print(f"[cub_enviar_manif] no se pudo guardar autorización: {e_auth}", flush=True)

    # 2d) Persistir cubicaje declarado (peso real/vol/volumen/predominante + bultos).
    #     Datos que el operador VE en el cubicador → quedan declarados en el
    #     commitment y corren aguas abajo (manifiesto, etiquetas, KPIs). No fatal.
    try:
        _pr = float(data.get("peso_real") or 0)
        _pv = float(data.get("peso_vol") or 0)
        _vm = float(data.get("volumen_m3") or 0)
        _pp = float(data.get("peso_predominante") or 0)
        _nb = data.get("n_bultos")
        _sets, _vals = [], []
        if _pr > 0: _sets.append("peso_real=%s");         _vals.append(_pr)
        if _pv > 0: _sets.append("peso_vol=%s");          _vals.append(_pv)
        if _vm > 0: _sets.append("volumen_m3=%s");        _vals.append(_vm)
        if _pp > 0: _sets.append("peso_predominante=%s"); _vals.append(_pp)
        if _nb not in (None, ""):
            _sets.append("n_bultos=%s"); _vals.append(max(1, int(float(_nb))))
        if _sets:
            _vals.append(comm_id)
            mysql_execute(
                f"UPDATE transport_commitments SET {', '.join(_sets)} WHERE id=%s",
                tuple(_vals)
            )
    except Exception as e_cub:
        print(f"[cub_enviar_manif] no se pudo guardar cubicaje: {e_cub}", flush=True)

    # 2e) Persistir DATOS DEL HEADER del frontend (lo que el operador VE/EDITA en
    #     el cubicador). Garantiza que la factura llegue COMPLETA al manifiesto
    #     sin depender de qué vía (REST/SQL) repobló el commitment, y conserva
    #     las ediciones del operador. Solo campos no vacíos (no pisa con vacío).
    try:
        _hdr_map = {
            "cliente_nombre": (data.get("cliente_nombre") or "").strip()[:200],
            "cliente_rut":    (data.get("cliente_rut") or "").strip()[:20],
            "email":          (data.get("email") or "").strip()[:150],
            "telefono":       (data.get("telefono") or "").strip()[:50],
            "direccion":      (data.get("direccion") or "").strip()[:300],
            "comuna":         (data.get("comuna") or "").strip()[:100],
        }
        _hs, _hv = [], []
        for col, val in _hdr_map.items():
            if val:
                _hs.append(f"{col}=%s"); _hv.append(val)
        _vn = data.get("valor_neto")
        if _vn not in (None, "") and float(_vn) > 0:
            _hs.append("valor_neto=%s"); _hv.append(float(_vn))
        if _hs:
            _hv.append(comm_id)
            mysql_execute(
                f"UPDATE transport_commitments SET {', '.join(_hs)} WHERE id=%s",
                tuple(_hv)
            )
    except Exception as e_hdr:
        print(f"[cub_enviar_manif] no se pudo guardar header: {e_hdr}", flush=True)

    # 2f) Productos declarados (árbol manifiesto → factura → productos). Se guardan
    #     como JSON aparte de transport_commitment_lines (que alimenta el saldo).
    try:
        _prods = data.get("productos")
        if isinstance(_prods, list) and _prods:
            import json as _json_mod
            _clean = []
            for p in _prods[:200]:
                if not isinstance(p, dict):
                    continue
                _clean.append({
                    "koprct":   str(p.get("sku") or p.get("koprct") or "")[:40],
                    "nokopr":   str(p.get("nombre") or p.get("descripcion_erp") or p.get("nokopr") or "")[:300],
                    "cantidad": p.get("cantidad") or 0,
                    "saldo":    p.get("saldo"),
                })
            mysql_execute(
                "UPDATE transport_commitments SET productos_json=%s WHERE id=%s",
                (_json_mod.dumps(_clean, ensure_ascii=False), comm_id)
            )
    except Exception as e_prod:
        print(f"[cub_enviar_manif] no se pudo guardar productos: {e_prod}", flush=True)

    # 2b) Persistir notas de entrega (visible para el courier; alimenta la
    #     columna "Notas" del export SimplyRoute). No es fatal si falla.
    notas_entrega = (data.get("notas_entrega") or "").strip()
    if notas_entrega:
        try:
            mysql_execute(
                "UPDATE transport_commitments SET notas=%s WHERE id=%s",
                (notas_entrega[:2000], comm_id)
            )
        except Exception as e_notas:
            print(f"[cub_enviar_manif] no se pudo guardar notas_entrega: {e_notas}", flush=True)

    # 3) Resolver manifest_id (crear si hace falta) y agregar el item.
    conn = get_db()
    correlativo = None
    added = False
    try:
        with conn.cursor() as cur:
            if not mid_in:
                # Crear manifiesto nuevo
                fecha_in = (data.get("fecha") or "").strip()
                if not fecha_in:
                    fecha_in = datetime.now().date().isoformat()
                notas = (data.get("notas") or "").strip()[:500]
                # Correlativo MAN-AAAA-NNNN (sincronizado con tr_crear_manifiesto)
                cur.execute(
                    "SELECT COUNT(*)+1 AS n FROM transport_manifests "
                    "WHERE YEAR(created_at)=YEAR(NOW())"
                )
                _r = cur.fetchone() or {}
                n = int(_r.get("n", 1))
                correlativo = f"MAN-{datetime.now().year}-{n:04d}"
                cur.execute(
                    """INSERT INTO transport_manifests
                       (correlativo, fecha, courier, notas, created_by)
                       VALUES (%s,%s,%s,%s,%s)""",
                    (correlativo, fecha_in, courier, notas, current_username())
                )
                mid = cur.lastrowid
                try: _tr_log("manifest", mid, "creado (cubicador)",
                            f"courier={courier} fecha={fecha_in}")
                except Exception: pass
            else:
                # Validar manifiesto existente
                mid = int(mid_in)
                row = mysql_fetchone(
                    "SELECT estado, correlativo FROM transport_manifests WHERE id=%s",
                    (mid,)
                )
                if not row:
                    return jsonify({"error": "Manifiesto no encontrado"}), 404
                if row["estado"] in ("Cerrado", "Entregado completo"):
                    return jsonify({
                        "error": "El manifiesto está cerrado y no acepta más items."
                    }), 409
                correlativo = row["correlativo"]

            # 4) Adjuntar item (idempotente por UNIQUE)
            cur.execute(
                "INSERT IGNORE INTO transport_manifest_items "
                "(manifest_id, commitment_id) VALUES (%s,%s)",
                (mid, comm_id)
            )
            added = bool(cur.rowcount)

            # 5) Recalcular totales del manifiesto
            cur.execute("""
                UPDATE transport_manifests m SET
                  total_items = (SELECT COUNT(*) FROM transport_manifest_items
                                  WHERE manifest_id = m.id),
                  costo_total = (SELECT COALESCE(SUM(c.costo_zz), 0)
                                   FROM transport_manifest_items mi
                                   JOIN transport_commitments c ON c.id = mi.commitment_id
                                  WHERE mi.manifest_id = m.id)
                WHERE m.id = %s
            """, (mid,))
        conn.commit()
    except Exception as e_tx:
        try: conn.rollback()
        except Exception: pass
        return jsonify({"error": f"Error al adjuntar al manifiesto: {e_tx}"}), 500

    try:
        _tr_log(
            "manifest", mid,
            "item agregado (cubicador)" if added else "item duplicado (cubicador)",
            f"commitment_id={comm_id} tido={tido} nudo={nudo} courier={courier}"
        )
    except Exception: pass

    return jsonify({
        "ok": True,
        "manifest_id": mid,
        "correlativo": correlativo,
        "commitment_id": comm_id,
        "added": added,
        "duplicate": not added,
    })


# ── COURIERS — helper functions ──────────────────────────────────────────────

def _parse_peso_upper(col_header) -> float:
    """Converts a weight column header to its upper bound in kg."""
    s = str(col_header).strip().replace(',', '.').replace(' ', '').lower()
    # Special cases
    if '+' in s or 'mas' in s or 'more' in s:
        return 999999.0
    # Range like "100al499", "500-1999", "1001-5000"
    for sep in ['-', 'al']:
        if sep in s:
            parts = s.split(sep)
            try:
                return float(parts[-1])
            except Exception:
                pass
    # Single number
    try:
        return float(s)
    except Exception:
        return 999999.0


# ══════════════════════════════════════════════════════════════════════════
#  COURIERS — MARGEN + IVA (criterio Daniel 22/05/2026)
#
#  El Excel maestro de tarifas representa el COSTO que ILUS paga al courier.
#  El precio final al cliente es:
#      subtotal_neto = costo × (1 + margen_pct/100)
#      precio_venta  = subtotal_neto × (1 + iva_pct/100)
#
#  Defaults: margen 30%, IVA 19% (Chile).
#  Ambos configurables vía env vars:
#      ILUS_COURIER_MARGEN_PCT (default 30)
#      ILUS_IVA_PCT            (default 19)
#  Esto permite ajustar el margen sin redeploy de código si Daniel
#  decide cambiar la política comercial.
# ══════════════════════════════════════════════════════════════════════════
def _courier_margen_iva_cfg() -> dict:
    """Lee config margen/IVA de env vars o defaults."""
    try:
        mpct = float(os.environ.get("ILUS_COURIER_MARGEN_PCT", "30") or 30)
    except Exception:
        mpct = 30.0
    try:
        ipct = float(os.environ.get("ILUS_IVA_PCT", "19") or 19)
    except Exception:
        ipct = 19.0
    return {"margen_pct": mpct, "iva_pct": ipct}


def _courier_aplicar_margen_iva(precio_costo: float, *, margen_pct: float = None,
                                 iva_pct: float = None) -> dict:
    """Aplica margen comercial + IVA al precio de costo del courier.

    Returns dict con desglose completo (cada componente redondeado a CLP):
        {
            "precio_costo":  36317,    # del Excel (lo que ILUS paga al courier)
            "margen_pct":    30.0,
            "margen_clp":    10895,
            "subtotal_neto": 47212,    # costo + margen (lo que ILUS factura sin IVA)
            "iva_pct":       19.0,
            "iva_clp":       8970,
            "precio_venta":  56182,    # lo que paga el cliente (con IVA)
        }
    """
    cfg = _courier_margen_iva_cfg()
    mpct = float(margen_pct if margen_pct is not None else cfg["margen_pct"])
    ipct = float(iva_pct    if iva_pct    is not None else cfg["iva_pct"])
    costo = float(precio_costo or 0)
    margen_clp = costo * (mpct / 100.0)
    subtotal_neto = costo + margen_clp
    iva_clp = subtotal_neto * (ipct / 100.0)
    precio_venta = subtotal_neto + iva_clp
    return {
        "precio_costo":  round(costo, 0),
        "margen_pct":    mpct,
        "margen_clp":    round(margen_clp, 0),
        "subtotal_neto": round(subtotal_neto, 0),
        "iva_pct":       ipct,
        "iva_clp":       round(iva_clp, 0),
        "precio_venta":  round(precio_venta, 0),
    }


def _courier_tarifa_lookup(courier_id: int, comuna: str, peso_kg: float,
                            return_trace: bool = False):
    """
    Returns the price (float) for a given courier+commune+weight.

    LEGACY: cuando ``return_trace=False`` mantiene la firma antigua (devuelve
    solo el precio o None). Esto evita romper callers existentes.

    NUEVO: con ``return_trace=True`` devuelve un dict con TODO el detalle del
    cálculo — bracket aplicado, fórmula, fuente, advertencias. Imprescindible
    para auditoría (FedEx puede revisar cualquier cotización histórica).

        {
          "precio": 105237,
          "bracket_aplicado": "100+",
          "bracket_upper": 999999.0,
          "formula": "Bracket exact match",
          "fuente": "tabla",
          "validado": True,            # ← si la tarifa fue marcada manualmente
          "peso_usado": 173.89,
          "comuna_normalizada": "lo barnechea",
          "comuna_db": "Lo Barnechea",
          "json_brackets_disponibles": ["1","5","10","25","50","100","100+"],
          "advertencias": ["..."],
        }
    """
    comuna_norm = (comuna or '').strip().lower()
    row = mysql_fetchone(
        "SELECT comuna, precios_json, dias_transito FROM transport_courier_comunas "
        "WHERE courier_id=%s AND LOWER(TRIM(comuna))=LOWER(TRIM(%s))",
        (courier_id, comuna)
    )

    def _trace_empty(reason: str, fuente: str = "no_cobertura"):
        if not return_trace:
            return None
        return {
            "precio": None,
            "bracket_aplicado": None,
            "bracket_upper": None,
            "formula": reason,
            "fuente": fuente,
            "validado": False,
            "peso_usado": float(peso_kg),
            "comuna_normalizada": comuna_norm,
            "comuna_db": None,
            "json_brackets_disponibles": [],
            "advertencias": [reason],
        }

    if not row or not row.get('precios_json'):
        return _trace_empty(f"Sin tarifa para '{comuna}' (courier_id={courier_id})")

    try:
        precios = json.loads(row['precios_json'])
    except Exception as ex_json:
        return _trace_empty(f"precios_json inválido: {ex_json}", fuente="error")

    # Build sorted bracket list — guardamos también la KEY original para trace
    brackets = []  # [(upper:float, price:float, key_original:str)]
    for key, price in precios.items():
        if price is None:
            continue
        try:
            upper = _parse_peso_upper(key)
            brackets.append((upper, float(price), str(key)))
        except Exception:
            pass
    brackets.sort(key=lambda x: x[0])
    if not brackets:
        return _trace_empty("No hay brackets numéricos válidos en precios_json", fuente="error")

    # Buscar el bracket aplicable
    bracket_match = None
    formula = ""
    for upper, price, key_orig in brackets:
        if peso_kg <= upper:
            bracket_match = (upper, price, key_orig)
            formula = f"Bracket exact match: peso {peso_kg}kg <= {upper}kg (key='{key_orig}')"
            break
    if bracket_match is None:
        # Sobre el bracket máximo → usar el último (último precio definido)
        upper, price, key_orig = brackets[-1]
        bracket_match = (upper, price, key_orig)
        formula = f"Sobre bracket máximo: usa último (key='{key_orig}', upper={upper}kg)"

    upper, price, key_orig = bracket_match

    # ── Validación: ¿es validado manualmente? ───────────────────────
    validado_flag = False
    fuente_aplicada = "tabla"
    try:
        last_audit = mysql_fetchone(
            "SELECT validado, fuente FROM courier_tariff_audit "
            "WHERE courier_id=%s AND LOWER(TRIM(comuna))=LOWER(TRIM(%s)) "
            "  AND bracket_aplicado=%s AND validado=1 "
            "ORDER BY cotizacion_at DESC LIMIT 1",
            (courier_id, comuna, key_orig)
        )
        if last_audit:
            validado_flag = True
            fuente_aplicada = last_audit.get('fuente') or 'validado_excel'
    except Exception:
        # tabla puede no existir aún (primer arranque) — ignorar
        pass

    # ── Detección de tarifas SOSPECHOSAS ────────────────────────────
    # Si el precio resultante es muy bajo en relación al peso, alertar.
    # Reglas defensivas:
    #   - Precio < $1.000 para peso > 5 kg → muy probablemente está en $/kg en lugar de total
    #   - Precio < (peso × $50) → ratio absurdo (<$50/kg sospechoso)
    #   - Precio < $5.000 para peso > 50 kg → sospechoso
    advertencias = []
    if peso_kg >= 5 and price < 1000:
        advertencias.append(
            f"Precio sospechosamente bajo: ${int(price)} para {peso_kg}kg "
            f"(podría ser precio/kg en lugar de total) — verificar tabla"
        )
    elif peso_kg >= 50 and price < 5000:
        advertencias.append(
            f"Precio bajo para peso alto: ${int(price)} para {peso_kg}kg "
            f"(~${price/peso_kg:.0f}/kg) — verificar tabla"
        )
    elif peso_kg >= 10 and price > 0 and (price / peso_kg) < 50:
        advertencias.append(
            f"Tarifa <$50/kg: ${int(price)} para {peso_kg}kg → verificar tabla"
        )

    if not return_trace:
        return float(price)

    return {
        "precio": float(price),
        "bracket_aplicado": key_orig,
        "bracket_upper": upper,
        "formula": formula,
        "fuente": fuente_aplicada,
        "validado": validado_flag,
        "peso_usado": float(peso_kg),
        "comuna_normalizada": comuna_norm,
        "comuna_db": row.get('comuna'),
        "json_brackets_disponibles": [b[2] for b in brackets],
        "advertencias": advertencias,
    }


def _audit_cotizacion(*, courier_id, courier_nombre, comuna, peso_kg, peso_pred_kg,
                       bracket_aplicado, precio_calculado, formula_aplicada,
                       fuente, validado=False, notas=None,
                       documento_tido=None, documento_nudo=None,
                       cotizado_por=None, desglose=None) -> int:
    """Inserta una fila en courier_tariff_audit y devuelve el id.

    No-throw: si la tabla todavía no existe (primer arranque) o hay error,
    silencioso → devuelve None. El audit nunca debe tirar la cotización.

    Args:
        precio_calculado: histórico — equivale al precio_venta (lo que ve el cliente).
        desglose: dict de _courier_aplicar_margen_iva() para guardar componentes
                  costo/margen/iva separados (auditable por FedEx).
    """
    try:
        conn = get_db()
        with conn.cursor() as cur:
            # Construir el INSERT con o sin columnas de desglose dependiendo de
            # si existen (migración idempotente — la primera vez no existirán).
            d = desglose or {}
            pcosto = int(d.get("precio_costo")) if d.get("precio_costo") is not None else None
            pventa = int(d.get("precio_venta")) if d.get("precio_venta") is not None else None
            mpct   = float(d.get("margen_pct")) if d.get("margen_pct") is not None else None
            mclp   = int(d.get("margen_clp")) if d.get("margen_clp") is not None else None
            ipct   = float(d.get("iva_pct")) if d.get("iva_pct") is not None else None
            iclp   = int(d.get("iva_clp")) if d.get("iva_clp") is not None else None
            try:
                cur.execute(
                    """INSERT INTO courier_tariff_audit
                       (cotizado_por, documento_tido, documento_nudo, comuna,
                        peso_kg, peso_pred_kg, courier_id, courier_nombre,
                        bracket_aplicado, precio_calculado, formula_aplicada,
                        fuente, validado, notas,
                        precio_costo, margen_pct, margen_clp,
                        iva_pct, iva_clp, precio_venta)
                       VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,
                               %s,%s,%s,%s,%s,%s)""",
                    (
                        cotizado_por or current_username() or 'sistema',
                        documento_tido, documento_nudo, (comuna or '')[:120],
                        float(peso_kg or 0), float(peso_pred_kg or peso_kg or 0),
                        int(courier_id) if courier_id else None,
                        (courier_nombre or '')[:120],
                        (bracket_aplicado or '')[:40],
                        int(round(precio_calculado)) if precio_calculado is not None else None,
                        (formula_aplicada or '')[:200],
                        (fuente or 'tabla')[:40],
                        1 if validado else 0,
                        notas,
                        pcosto, mpct, mclp, ipct, iclp, pventa,
                    )
                )
            except Exception:
                # Fallback: las columnas nuevas (precio_costo, margen_*, iva_*,
                # precio_venta) aún no aplicaron — INSERT con schema legacy.
                cur.execute(
                    """INSERT INTO courier_tariff_audit
                       (cotizado_por, documento_tido, documento_nudo, comuna,
                        peso_kg, peso_pred_kg, courier_id, courier_nombre,
                        bracket_aplicado, precio_calculado, formula_aplicada,
                        fuente, validado, notas)
                       VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)""",
                    (
                        cotizado_por or current_username() or 'sistema',
                        documento_tido, documento_nudo, (comuna or '')[:120],
                        float(peso_kg or 0), float(peso_pred_kg or peso_kg or 0),
                        int(courier_id) if courier_id else None,
                        (courier_nombre or '')[:120],
                        (bracket_aplicado or '')[:40],
                        int(round(precio_calculado)) if precio_calculado is not None else None,
                        (formula_aplicada or '')[:200],
                        (fuente or 'tabla')[:40],
                        1 if validado else 0,
                        notas,
                    )
                )
            audit_id = cur.lastrowid
        conn.commit()
        return audit_id
    except Exception as ex_audit:
        print(f"[_audit_cotizacion] error: {ex_audit}", flush=True)
        return None


