def _comm_seed_default_templates(overwrite=False):
    try:
        user = current_username() or "system"
    except Exception:
        user = "system"
    conn = get_db()
    try:
        with conn.cursor() as cur:
            for estado, channels in _comm_template_defaults().items():
                for canal, (asunto, cuerpo) in channels.items():
                    if overwrite:
                        cur.execute(
                            """INSERT INTO comm_templates (estado, canal, asunto, cuerpo, updated_by)
                               VALUES (%s,%s,%s,%s,%s)
                               ON DUPLICATE KEY UPDATE
                                 asunto=VALUES(asunto),
                                 cuerpo=VALUES(cuerpo),
                                 updated_by=VALUES(updated_by),
                                 activo=1""",
                            (estado, canal, asunto, cuerpo, user),
                        )
                    else:
                        cur.execute(
                            """INSERT IGNORE INTO comm_templates
                               (estado, canal, asunto, cuerpo, updated_by)
                               VALUES (%s,%s,%s,%s,%s)""",
                            (estado, canal, asunto, cuerpo, user),
                        )
        conn.commit()
    finally:
        conn.close()


def _get_smtp_cfg():
    """
    Config SMTP — prioridad:
      1. Variables de entorno Railway (SMTP_HOST / SMTP_USER / SMTP_PASS …)
      2. Fila guardada en BD (comm_smtp_config)
      3. EMAIL_CONFIG de config.py
    Las env vars garantizan que la config sobreviva cualquier redeploy o reset de BD.
    """
    # ── 1. Fila en BD (máxima prioridad: lo que el usuario configura) ───
    try:
        row = mysql_fetchone(
            "SELECT * FROM comm_smtp_config WHERE id=1 LIMIT 1"
        )
        if row and row.get("smtp_user"):
            return {
                "smtp_host": row["smtp_host"] or "smtp.gmail.com",
                "smtp_port": int(row["smtp_port"] or 587),
                "smtp_user": row["smtp_user"],
                "smtp_pass": row["smtp_pass"] or "",
                "from_name": row["from_name"] or "ILUS Sport & Health",
                "from_addr": row["from_addr"] or row["smtp_user"],
                "secure":    bool(row.get("secure")),
                "_source":   "db",
            }
    except Exception:
        pass
    # ── 2. Variables de entorno (respaldo para despliegue) ──────────────
    # Acepta tanto SMTP_PASS (atajo legacy) como SMTP_PASSWORD (lo que está
    # en .env.example y lo más natural) — evita el caso silencioso de Daniel
    # 2026-05-21 donde el .env tenía SMTP_PASSWORD pero el código solo
    # leía SMTP_PASS, así caía a la BD con creds viejas.
    env_user = os.environ.get("SMTP_USER", "").strip()
    env_pass = (os.environ.get("SMTP_PASSWORD") or os.environ.get("SMTP_PASS") or "").strip()
    if env_user and env_pass:
        return {
            "smtp_host": os.environ.get("SMTP_HOST", "smtp.gmail.com").strip(),
            "smtp_port": int(os.environ.get("SMTP_PORT", "587")),
            "smtp_user": env_user,
            "smtp_pass": env_pass,
            "from_name": os.environ.get("SMTP_FROM_NAME", "ILUS Sport & Health").strip(),
            "from_addr": os.environ.get("SMTP_FROM_ADDR", env_user).strip(),
            "secure":    os.environ.get("SMTP_SECURE", "").lower() in ("1","true","yes"),
            "_source":   "env",
        }
    # ── 3. config.py ────────────────────────────────────────────────────
    cfg = dict(EMAIL_CONFIG)
    cfg["_source"] = "config"
    return cfg


def _safe_smtp_cfg(cfg=None):
    cfg = dict(cfg or _get_smtp_cfg())
    if cfg.get("smtp_pass"):
        cfg["smtp_pass"] = "••••••••"
    return cfg


# Cache local del client config — se invalida al guardar config o cross-worker
# vía app_cache_signals. TTL 60s evita martillar la BD en cada render que
# usa el filtro `chile_fmt` o el _ilus_email_html. Default ~775 jsonify y
# muchos templates lo invocan indirectamente.
_client_cfg_cache = {"data": None, "ts": 0.0}
_client_cfg_lock = threading.Lock()
_CLIENT_CFG_TTL = 60


def _invalidate_client_cfg_cache():
    """Llamar tras INSERT/UPDATE en comm_client_config."""
    with _client_cfg_lock:
        _client_cfg_cache["ts"] = 0.0
        _client_cfg_cache["data"] = None
    try:
        _cache_signal_bump("client_cfg")
    except Exception:
        pass


def _get_client_cfg():
    """Lee comm_client_config con cache TTL 60s (cross-worker invalidable)."""
    # Cross-worker invalidation check (≤1 query cada 30s por scope)
    try:
        if _cache_signal_changed("client_cfg"):
            with _client_cfg_lock:
                _client_cfg_cache["ts"] = 0.0
                _client_cfg_cache["data"] = None
    except Exception:
        pass
    now = time.time()
    with _client_cfg_lock:
        if _client_cfg_cache["data"] is not None and (now - _client_cfg_cache["ts"]) < _CLIENT_CFG_TTL:
            return _client_cfg_cache["data"]
    try:
        row = mysql_fetchone(
            "SELECT * FROM comm_client_config WHERE id=1 LIMIT 1"
        )
        if row:
            data = dict(row)
            with _client_cfg_lock:
                _client_cfg_cache["data"] = data
                _client_cfg_cache["ts"] = now
            return data
    except Exception:
        pass
    fallback = {"company_name": "ILUS Sport & Health", "corp_color": "#CC0000"}
    with _client_cfg_lock:
        _client_cfg_cache["data"] = fallback
        _client_cfg_cache["ts"] = now
    return fallback


def _get_wa_cfg():
    """Config de WhatsApp Twilio.

    PRECEDENCIA (importante):
      1. Env vars Railway (TWILIO_ACCOUNT_SID / TWILIO_AUTH_TOKEN / TWILIO_WHATSAPP_FROM)
         → SIEMPRE ganan, son fuente de verdad en producción.
      2. BD (comm_whatsapp_config) → fallback de retrocompatibilidad para
         instalaciones donde la config aún está sólo en la tabla.

    POR QUÉ env > BD: el admin a veces guarda un SID viejo en BD y luego rota
    credenciales en Railway. Si BD ganaba (como hasta antes), los envíos
    seguían usando el SID viejo y fallaban con error críptico. Ahora rotar
    credenciales solo requiere editar la env var en Railway.

    Env vars esperadas:
      TWILIO_ACCOUNT_SID      (ej: AC1234567890abcdef...)
      TWILIO_AUTH_TOKEN       (ej: abc123...)
      TWILIO_WHATSAPP_FROM    (ej: whatsapp:+14155238886 — sandbox o número aprobado)
    """
    import os as _os_wa
    cfg = {}
    # 1) BD como base (retrocompat — la UI de comunicaciones escribe aquí)
    try:
        row = mysql_fetchone(
            "SELECT * FROM comm_whatsapp_config WHERE id=1 LIMIT 1"
        )
        if row:
            cfg = dict(row)
    except Exception:
        pass

    # 2) Env vars Railway → OVERRIDE (ganan siempre cuando estén presentes)
    env_sid  = (_os_wa.environ.get("TWILIO_ACCOUNT_SID") or "").strip()
    env_tok  = (_os_wa.environ.get("TWILIO_AUTH_TOKEN") or "").strip()
    env_from = (_os_wa.environ.get("TWILIO_WHATSAPP_FROM") or "").strip()
    if env_sid:
        cfg["account_sid"] = env_sid
    if env_tok:
        cfg["auth_token"] = env_tok
    if env_from:
        # Normaliza: si no trae prefix "whatsapp:" lo agrega
        cfg["from_number"] = env_from if env_from.startswith("whatsapp:") else f"whatsapp:{env_from}"
    # Marca origen para diagnóstico
    if env_sid or env_tok or env_from:
        cfg["_source"] = "env"
    elif cfg:
        cfg["_source"] = "db"
    return cfg


def _get_sms_cfg():
    """Config de SMS Twilio. Lee SOLO de env vars (no hay tabla BD para SMS).
    Env vars:
      TWILIO_ACCOUNT_SID
      TWILIO_AUTH_TOKEN
      TWILIO_PHONE_FROM   (ej: +14155551234 — número Twilio comprado)
    """
    import os as _os_sms
    return {
        "account_sid": (_os_sms.environ.get("TWILIO_ACCOUNT_SID") or "").strip(),
        "auth_token":  (_os_sms.environ.get("TWILIO_AUTH_TOKEN") or "").strip(),
        "from_number": (_os_sms.environ.get("TWILIO_PHONE_FROM") or "").strip(),
    }


def _send_sms(account_sid, auth_token, from_num, to_num, body, *, modulo: str = None):
    """Envía SMS vía Twilio. Lanza RuntimeError si twilio no está instalado.

    modulo: opcional — si se pasa y la llave de paso está cerrada para
    ese módulo, NO envía y devuelve un sid pseudo 'blocked-by-killswitch'
    (las llamadoras no se rompen, pero queda registro de que se omitió).
    """
    # LLAVE DE PASO POR MÓDULO (sms)
    mod = (modulo or "general").strip().lower()
    if _modulo_canal_bloqueado(mod, "sms"):
        print(f"[KILLSWITCH] modulo={mod} canal=sms bloqueado por kill switch — no enviado (to={to_num})")
        try:
            _comm_log_entry("sms", to_num or "", "SMS bloqueado", "bloqueado",
                            f"Llave de paso cerrada para módulo {mod}")
        except Exception: pass
        return "blocked-by-killswitch"

    import re as _re
    try:
        from twilio.rest import Client as _TwilioClient
    except ImportError:
        raise RuntimeError("El paquete 'twilio' no está instalado. Ejecuta: pip install twilio")
    m = _re.search(r'(AC[a-f0-9]{32})', account_sid or "", _re.I)
    if m:
        account_sid = m.group(1)
    if not account_sid or not account_sid.upper().startswith("AC"):
        raise ValueError("El Account SID debe comenzar con 'AC'")
    if not auth_token or auth_token in ("[AuthToken]",):
        raise ValueError("Ingresa un Auth Token válido")
    # Normalizar números: SIN prefijo whatsapp:, con + internacional
    from_num = from_num.replace("whatsapp:", "").strip()
    to_num = to_num.strip()
    if not to_num.startswith("+"):
        # Asumir Chile si solo tiene dígitos (formato 9xxxxxxxx → +569xxxxxxxx)
        digits = _re.sub(r'\D', '', to_num)
        if digits.startswith("9") and len(digits) == 9:
            to_num = "+56" + digits
        elif digits.startswith("56"):
            to_num = "+" + digits
        else:
            to_num = "+" + digits
    client = _TwilioClient(account_sid, auth_token)
    msg = client.messages.create(from_=from_num, to=to_num, body=body)
    return msg.sid


def _twilio_diagnostico():
    """Retorna dict con estado de configuración Twilio (sin exponer secretos)."""
    wa = _get_wa_cfg()
    sms = _get_sms_cfg()
    def _mask(s):
        if not s: return None
        s = str(s)
        if len(s) <= 8: return "***"
        return s[:4] + "..." + s[-4:]
    return {
        "whatsapp": {
            "configurado": bool(wa.get("account_sid") and wa.get("auth_token") and wa.get("from_number")),
            "account_sid": _mask(wa.get("account_sid")),
            "from_number": wa.get("from_number") or None,
        },
        "sms": {
            "configurado": bool(sms.get("account_sid") and sms.get("auth_token") and sms.get("from_number")),
            "account_sid": _mask(sms.get("account_sid")),
            "from_number": sms.get("from_number") or None,
        },
    }


def _comm_log_entry(canal, dest, asunto, estado, detalle=""):
    try:
        conn = get_db()
        with conn.cursor() as cur:
            cur.execute(
                "INSERT INTO comm_log (canal,destinatario,asunto,estado,detalle,enviado_por) "
                "VALUES (%s,%s,%s,%s,%s,%s)",
                (canal, dest[:300], (asunto or "")[:500], estado,
                 (detalle or "")[:2000], current_username()),
            )
        conn.commit()
    except Exception:
        pass


def _send_email_dinamico(to, subject, html_body, cfg=None):
    """Envía email usando config SMTP dinámica (DB o config.py).

    Timeout reducido a 10s/intento (era 15s) — en Railway un Gmail
    colgado puede tomar minutos si cada paso del handshake/login
    espera el default. 10s es suficiente para LAN razonable.
    """
    import ssl as _ssl
    cfg = cfg or _get_smtp_cfg()
    cc = _get_client_cfg()
    msg = MIMEMultipart("alternative")
    msg["Subject"] = subject
    msg["From"]    = f"{cfg['from_name']} <{cfg.get('from_addr', cfg['smtp_user'])}>"
    msg["To"]      = to
    recipients = [to]
    if cc.get("reply_to"):
        msg["Reply-To"] = cc["reply_to"]
    cc_addrs = [a.strip() for a in (cc.get("email_cc") or "").replace(";", ",").split(",") if a.strip()]
    bcc_addrs = [a.strip() for a in (cc.get("email_bcc") or "").replace(";", ",").split(",") if a.strip()]
    if cc_addrs:
        msg["Cc"] = ", ".join(cc_addrs)
    recipients.extend(cc_addrs + bcc_addrs)
    msg.attach(MIMEText(html_body, "html", "utf-8"))
    host   = cfg["smtp_host"]
    port   = int(cfg.get("smtp_port", 587))
    secure = cfg.get("secure", False)
    if secure:
        ctx = _ssl.create_default_context()
        with _open_smtp_client(host, port, True, timeout=10, context=ctx) as srv:
            srv.login(cfg["smtp_user"], cfg["smtp_pass"])
            srv.sendmail(cfg.get("from_addr", cfg["smtp_user"]), recipients, msg.as_string())
    else:
        with _open_smtp_client(host, port, False, timeout=10) as srv:
            srv.ehlo()
            srv.starttls()
            srv.login(cfg["smtp_user"], cfg["smtp_pass"])
            srv.sendmail(cfg.get("from_addr", cfg["smtp_user"]), recipients, msg.as_string())


def _smtp_cfg_from_request(data=None):
    data = data or {}
    prev = _get_smtp_cfg()
    smtp_pass = (data.get("pass") or "").strip()
    is_masked = smtp_pass.startswith("â€¢") or smtp_pass == "••••••••" or set(smtp_pass or "") == {"•"}
    bullet = chr(8226)
    is_masked = (
        is_masked
        or smtp_pass == (bullet * 8)
        or set(smtp_pass or "") == {bullet}
        or (bool(smtp_pass) and not any(ch.isalnum() for ch in smtp_pass))
    )
    if is_masked:
        smtp_pass = ""
    if not smtp_pass or smtp_pass == "••••••••":
        smtp_pass = prev.get("smtp_pass") or ""
    host = (data.get("host") or prev.get("smtp_host") or "smtp.gmail.com").strip()
    port = int(data.get("port") or prev.get("smtp_port") or 587)
    secure = bool(data.get("secure")) if "secure" in data else bool(prev.get("secure"))
    if "gmail.com" in host.lower():
        if port == 587 and secure:
            secure = False
        elif port == 465 and not secure:
            secure = True
    return {
        "smtp_host": host,
        "smtp_port": port,
        "smtp_user": (data.get("user") or prev.get("smtp_user") or "").strip(),
        "smtp_pass": smtp_pass,
        "from_name": (data.get("fromName") or prev.get("from_name") or "ILUS Sport & Health").strip(),
        "from_addr": (data.get("fromAddr") or prev.get("from_addr") or data.get("user") or prev.get("smtp_user") or "").strip(),
        "secure": secure,
    }


def _smtp_connection_diagnose(cfg):
    """Valida conexion SMTP y login sin enviar ningun correo."""
    import socket
    import ssl as _ssl

    host = (cfg.get("smtp_host") or "").strip()
    port = int(cfg.get("smtp_port") or 0)
    user = (cfg.get("smtp_user") or "").strip()
    password = cfg.get("smtp_pass") or ""
    secure = bool(cfg.get("secure"))

    checks = []
    suggestions = []
    if not host:
        return {"ok": False, "stage": "config", "message": "Falta el servidor SMTP.", "suggestions": ["Ingresa smtp.gmail.com para Gmail."]}
    if not port:
        return {"ok": False, "stage": "config", "message": "Falta el puerto SMTP.", "suggestions": ["Usa 587 con STARTTLS o 465 con SSL."]}
    if not user:
        return {"ok": False, "stage": "config", "message": "Falta el email usuario SMTP.", "suggestions": ["Ingresa la cuenta que autentica el correo."]}
    if not password:
        return {"ok": False, "stage": "config", "message": "Falta la contraseña / App Password.", "suggestions": ["Guarda una App Password de Gmail de 16 caracteres."]}

    gmail = "gmail.com" in host.lower()
    if gmail and secure and port != 465:
        suggestions.append("Para Gmail con SSL/TLS marcado usa puerto 465, o desmarca SSL/TLS y usa puerto 587.")
    if gmail and not secure and port != 587:
        suggestions.append("Para Gmail con STARTTLS normalmente se usa puerto 587 y SSL/TLS desmarcado.")
    if gmail and " " in password:
        suggestions.append("Gmail permite mostrar la App Password con espacios, pero si falla prueba guardarla sin espacios.")

    try:
        ipv4 = _smtp_ipv4(host)
        if ipv4 and ipv4 != host:
            checks.append(f"DNS IPv4 resuelto: {ipv4}")
        if secure:
            checks.append(f"Conectando con SSL a {host}:{port}")
            ctx = _ssl.create_default_context()
            # Timeout 30s: en Railway/cloud el handshake TLS con Gmail puede demorar
            # 15-25s por enrutamiento adicional. Antes era 10s y daba timeout falso.
            with _open_smtp_client(host, port, True, timeout=30, context=ctx) as srv:
                checks.append("Servidor SSL respondio correctamente")
                srv.ehlo()
                checks.append("Autenticando usuario SMTP")
                srv.login(user, password)
        else:
            checks.append(f"Conectando a {host}:{port}")
            with _open_smtp_client(host, port, False, timeout=30) as srv:
                srv.ehlo()
                if srv.has_extn("starttls"):
                    checks.append("STARTTLS disponible; negociando cifrado")
                    ctx = _ssl.create_default_context()
                    srv.starttls(context=ctx)
                    srv.ehlo()
                else:
                    checks.append("El servidor no anuncia STARTTLS")
                    suggestions.append("Si el servidor exige cifrado, activa SSL/TLS con puerto 465 o usa puerto 587 con STARTTLS.")
                checks.append("Autenticando usuario SMTP")
                srv.login(user, password)
        checks.append("Credenciales aceptadas. La aplicacion puede enviar correos.")
        return {
            "ok": True,
            "stage": "auth",
            "message": "Conexion SMTP verificada. Host, puerto, cifrado y credenciales estan correctos.",
            "checks": checks,
            "suggestions": suggestions,
        }
    except smtplib.SMTPAuthenticationError as exc:
        code = getattr(exc, "smtp_code", "")
        detail = (getattr(exc, "smtp_error", b"") or b"").decode("utf-8", "ignore")
        hints = [
            "Revisa que el email usuario sea correcto.",
            "Si usas Gmail, no uses tu clave normal: crea una App Password de 16 caracteres.",
            "Verifica que la verificacion en 2 pasos este activa en la cuenta Gmail.",
        ]
        return {"ok": False, "stage": "auth", "message": f"Autenticacion rechazada por el servidor SMTP ({code}).", "detail": detail, "checks": checks, "suggestions": hints + suggestions}
    except (smtplib.SMTPConnectError, smtplib.SMTPServerDisconnected, socket.timeout, TimeoutError) as exc:
        hints = [
            "Revisa host y puerto.",
            "Para Gmail usa 587 sin SSL/TLS marcado, o 465 con SSL/TLS marcado.",
            "Si estás en Railway o hosting cloud, Gmail suele bloquear el puerto SMTP saliente. "
            "Configura RESEND_API_KEY como variable de entorno (resend.com — 100 envíos/día gratis) "
            "y el sistema lo usará como ruta principal automáticamente.",
        ]
        return {"ok": False, "stage": "connect", "message": "No se pudo conectar correctamente al servidor SMTP.", "detail": str(exc), "checks": checks, "suggestions": hints + suggestions}
    except _ssl.SSLError as exc:
        hints = [
            "Hay una mezcla incorrecta entre puerto y tipo de cifrado.",
            "Para 587 desmarca SSL/TLS; para 465 marca SSL/TLS.",
        ]
        return {"ok": False, "stage": "tls", "message": "Error de SSL/TLS al negociar la conexion.", "detail": str(exc), "checks": checks, "suggestions": hints + suggestions}
    except OSError as exc:
        hints = [
            "El host o puerto no responde desde esta aplicacion.",
            "Revisa si el firewall o el hosting bloquea SMTP saliente.",
            "Prueba Gmail con smtp.gmail.com puerto 587 y SSL/TLS desmarcado.",
        ]
        return {"ok": False, "stage": "network", "message": "Error de red conectando al SMTP.", "detail": str(exc), "checks": checks, "suggestions": hints + suggestions}
    except smtplib.SMTPException as exc:
        return {"ok": False, "stage": "smtp", "message": "El servidor SMTP respondio con un error.", "detail": str(exc), "checks": checks, "suggestions": suggestions}


def _comm_render_email_document(title, body_html, subtitle=""):
    """Renderiza un fragmento HTML dentro del diseño corporativo actual.

    ANTI-DOUBLE-WRAP (fix 2026-05-21):
    Si `body_html` ya viene como documento HTML completo (contiene <!DOCTYPE>,
    <html>, <body>, o ya incluye el header de marca ILUS), NO se vuelve a
    envolver — se retorna tal cual. Esto evita el "header duplicado" que
    sufrían los envíos manuales y las pruebas de plantilla que pasaban por
    `_buildEmailHtml(...)` en el front y luego pegaban en el endpoint.
    """
    if _email_html_is_full_document(body_html):
        return body_html

    cc = _get_client_cfg()
    color = cc.get("corp_color") or "#CC0000"
    company = cc.get("company_name") or "ILUS Sport & Health"
    logo = cc.get("logo_url") or ""
    header = _email_header_ilus(title, subtitle, color, logo, company)
    body = _email_body_section(body_html)
    footer = _email_footer_ilus(company)
    return _email_wrapper(_email_card(header, body, footer), company)


def _email_html_is_full_document(html: str) -> bool:
    """¿El HTML ya viene como documento completo o como fragmento?

    Heurística: si trae <!doctype>, <html>, <head> o <body>, NO se debe
    envolver de nuevo con la plantilla corporativa porque produciría
    doble header + doble footer.
    """
    if not html:
        return False
    h = html.lower()
    for marker in ("<!doctype", "<html", "<head", "<body"):
        if marker in h:
            return True
    return False


