def _comm_apply_demo_replacements(html: str) -> str:
    """Reemplaza placeholders {{xxx}} con valores DEMO.

    USO: SOLO para envío manual desde /comunicaciones (no para envíos reales).
    - Tokens conocidos → valor realista.
    - Tokens desconocidos → "[xxx demo]" para que sea evidente que es prueba.
    """
    if not html or "{{" not in html:
        return html
    import re as _re
    mapa = _comm_demo_replacements()

    def _sub(match):
        key = (match.group(1) or "").strip()
        if key in mapa:
            return mapa[key]
        return f"[{key} demo]"

    return _re.sub(r"\{\{\s*([\w\.]+)\s*\}\}", _sub, html)


def _send_whatsapp(account_sid, auth_token, from_num, to_num, body, *, modulo: str = None):
    """Envía WhatsApp vía Twilio. Lanza RuntimeError si twilio no está instalado.

    modulo: opcional — si se pasa y la llave de paso está cerrada para
    ese módulo, NO envía y devuelve un sid pseudo 'blocked-by-killswitch'.
    """
    # LLAVE DE PASO POR MÓDULO (whatsapp)
    mod = (modulo or "general").strip().lower()
    if _modulo_canal_bloqueado(mod, "whatsapp"):
        print(f"[KILLSWITCH] modulo={mod} canal=whatsapp bloqueado por kill switch — no enviado (to={to_num})")
        try:
            _comm_log_entry("whatsapp", to_num or "", "WhatsApp bloqueado", "bloqueado",
                            f"Llave de paso cerrada para módulo {mod}")
        except Exception: pass
        return "blocked-by-killswitch"

    import re as _re
    try:
        from twilio.rest import Client as _TwilioClient
    except ImportError:
        raise RuntimeError(
            "El paquete 'twilio' no está instalado. "
            "Ejecuta: pip install twilio"
        )
    m = _re.search(r'(AC[a-f0-9]{32})', account_sid or "", _re.I)
    if m:
        account_sid = m.group(1)
    if not account_sid.upper().startswith("AC"):
        raise ValueError("El Account SID debe comenzar con 'AC'")
    if auth_token in ("[AuthToken]", "", None):
        raise ValueError("Ingresa un Auth Token válido")
    from_num = from_num if from_num.startswith("whatsapp:") else f"whatsapp:{from_num}"
    to_num   = to_num   if to_num.startswith("whatsapp:")   else f"whatsapp:{to_num}"
    client   = _TwilioClient(account_sid, auth_token)
    msg      = client.messages.create(from_=from_num, to=to_num, body=body)
    return msg.sid


