@app.route("/comunicaciones/cliente/config", methods=["POST"])
@_require_superadmin
def comm_client_save():
    d = request.get_json(silent=True) or {}

    # ── Logo: si llega como data:image/...;base64,xxx, subirlo a Cloudinary ──
    # 2026-05-21 (Daniel): Gmail bloquea imágenes embebidas como data URL.
    # Antes guardábamos el base64 directo en BD → el logo no se veía en Gmail
    # (solo en Outlook). Ahora interceptamos: si llega data URL, lo subimos a
    # Cloudinary y guardamos la URL pública https://res.cloudinary.com/...
    # que SÍ funciona en TODOS los clientes (Gmail, Outlook, Yahoo, etc.)
    logo_input = (d.get("logo_url") or "").strip()
    if logo_input.startswith("data:image/"):
        try:
            import base64 as _b64, cloudinary, cloudinary.uploader
            cld_name = os.environ.get("CLOUDINARY_CLOUD_NAME", "").strip()
            cld_key  = os.environ.get("CLOUDINARY_API_KEY", "").strip()
            cld_sec  = os.environ.get("CLOUDINARY_API_SECRET", "").strip()
            if cld_name and cld_key and cld_sec:
                cloudinary.config(
                    cloud_name=cld_name, api_key=cld_key, api_secret=cld_sec, secure=True
                )
                header, b64 = logo_input.split(",", 1)
                img_bytes = _b64.b64decode(b64)
                resp = cloudinary.uploader.upload(
                    img_bytes, folder="ilus/branding",
                    public_id="company_logo", overwrite=True,
                    resource_type="image", format="png",
                )
                logo_input = resp.get("secure_url") or resp.get("url") or logo_input
                print(f"[comm-save-logo] base64 → Cloudinary: {logo_input}", flush=True)
            else:
                print("[comm-save-logo][WARN] Cloudinary no configurado — "
                      "guardando base64 (Gmail no lo verá). Setear CLOUDINARY_* en Railway.",
                      flush=True)
        except Exception as _e:
            print(f"[comm-save-logo][WARN] Falló upload Cloudinary: {_e} — "
                  "guardando data URL como fallback (no funciona en Gmail)", flush=True)

    conn = get_db()
    with conn.cursor() as cur:
        cur.execute(
            """INSERT INTO comm_client_config
               (id,company_name,reply_to,support_email,support_phone,
                tracking_url,logo_url,corp_color,email_cc,email_bcc,updated_by)
               VALUES (1,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
               ON DUPLICATE KEY UPDATE
                 company_name=VALUES(company_name),
                 reply_to=VALUES(reply_to),
                 support_email=VALUES(support_email),
                 support_phone=VALUES(support_phone),
                 tracking_url=VALUES(tracking_url),
                 logo_url=VALUES(logo_url),
                 corp_color=VALUES(corp_color),
                 email_cc=VALUES(email_cc),
                 email_bcc=VALUES(email_bcc),
                 updated_by=VALUES(updated_by)""",
            (
                (d.get("company_name") or "ILUS Sport & Health").strip(),
                (d.get("reply_to") or "").strip(),
                (d.get("support_email") or "").strip(),
                (d.get("support_phone") or "").strip(),
                (d.get("tracking_url") or "").strip(),
                logo_input,
                (d.get("corp_color") or "#CC0000").strip(),
                (d.get("email_cc") or "").strip(),
                (d.get("email_bcc") or "").strip(),
                current_username(),
            ),
        )
        cur.execute("DELETE FROM comm_client_config WHERE id <> 1")
    conn.commit()
    try: _invalidate_client_cfg_cache()
    except Exception: pass
    return jsonify({"ok": True, "client": _get_client_cfg()})


@app.route("/comunicaciones/whatsapp/env-vars", methods=["GET"])
@_require_superadmin
def comm_wa_env_vars():
    """Devuelve los valores ACTIVOS de las env vars Twilio en Railway.

    Útil cuando el admin rotó credenciales en Railway y la BD tiene valores
    viejos: el botón "Sincronizar con env vars" en /comunicaciones lo llama
    para mostrar los valores reales en el formulario antes de guardar.

    NOTA SEGURIDAD: este endpoint requiere superadmin. Aún así, NO retorna
    el `auth_token` completo — solo los primeros y últimos 4 chars para
    poder confirmar que se actualizó. El admin debe ingresar el token
    completo manualmente si quiere persistirlo en BD.
    """
    import os as _os_e
    sid  = (_os_e.environ.get("TWILIO_ACCOUNT_SID") or "").strip()
    tok  = (_os_e.environ.get("TWILIO_AUTH_TOKEN") or "").strip()
    frm  = (_os_e.environ.get("TWILIO_WHATSAPP_FROM") or "").strip()
    if frm and not frm.startswith("whatsapp:"):
        frm = f"whatsapp:{frm}"
    if not (sid or tok or frm):
        return jsonify({
            "ok": False,
            "error": "No hay env vars Twilio configuradas en Railway. "
                     "Define TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN y TWILIO_WHATSAPP_FROM."
        }), 404
    return jsonify({
        "ok": True,
        "account_sid": sid,
        "auth_token":  tok,
        "from_number": frm,
        "source":      "env",
    })


