@app.route("/comunicaciones/whatsapp/test", methods=["POST"])
@_require_superadmin
def comm_wa_test():
    d     = request.get_json(silent=True) or {}
    saved = _get_wa_cfg()
    sid   = (d.get("account_sid") or saved.get("account_sid") or "").strip()
    tok   = (d.get("auth_token")  or saved.get("auth_token")  or "").strip()
    frm   = (d.get("from_number") or saved.get("from_number") or "").strip()
    to    = (d.get("to") or "").strip()
    if not all([sid, tok, frm, to]):
        return jsonify({"error": "Completa: Account SID, Auth Token, From y destinatario"}), 400
    body = (f"✅ Prueba de WhatsApp — ILUS Comunicaciones\n"
            f"Enviado por: {current_username()}")
    body = (d.get("body") or "").strip() or body
    try:
        msg_sid = _send_whatsapp(sid, tok, frm, to, body)
        _comm_log_entry("whatsapp", to, "Prueba WA", "ok", msg_sid)
        return jsonify({"ok": True, "msg_sid": msg_sid})
    except Exception as exc:
        detail = str(exc)
        code = getattr(exc, "code", None) or getattr(exc, "status", None)
        more_info = getattr(exc, "more_info", "") or ""
        suggestions = []
        if "not installed" in detail.lower() or "twilio" in detail.lower() and "instal" in detail.lower():
            suggestions.append("Instala Twilio en el mismo Python que ejecuta la app y reinicia el servidor.")
        if str(code) in {"21211", "21614"} or "not a valid phone number" in detail.lower():
            suggestions.append("Revisa que el destinatario tenga formato internacional, por ejemplo +56912345678.")
        if str(code) in {"63015", "63016"} or "sandbox" in detail.lower():
            suggestions.append("En sandbox, el destinatario debe enviar primero el codigo join al numero +1 415 523 8886.")
        if str(code) in {"20003", "20404"} or "authenticate" in detail.lower() or "credentials" in detail.lower():
            suggestions.append("Revisa Account SID y Auth Token desde el Dashboard de Twilio.")
        if frm.startswith("whatsapp:+14155238886"):
            suggestions.append("Estas usando sandbox Twilio; confirma que el telefono destino ya se unio al sandbox.")
        _comm_log_entry("whatsapp", to, "Prueba WA", "error", detail)
        return jsonify({
            "error": detail,
            "code": code,
            "more_info": more_info,
            "suggestions": suggestions,
        }), 500


# Módulos válidos para plantillas — mantener sincronizado con el frontend
_COMM_MODULOS_VALIDOS = (
    "transporte",
    "retiros",
    "mantenciones",
    "comunicacion_interna",
    "general",
)


@app.route("/comunicaciones/templates", methods=["GET"])
@_require_superadmin
def comm_templates_get():
    """Devuelve plantillas agrupadas por estado.
    Filtra por ?modulo=transporte (default), retiros, mantenciones,
    comunicacion_interna o general."""
    modulo = (request.args.get("modulo") or "transporte").strip()
    if modulo not in _COMM_MODULOS_VALIDOS:
        modulo = "transporte"
    rows = mysql_fetchall(
        "SELECT * FROM comm_templates WHERE modulo=%s ORDER BY estado, canal",
        (modulo,),
    ) or []
    legacy_tokens = ("Dropit", "direccion_origen", "direccion_destino", "link_tracking", "nombre_conductor")
    if modulo == "transporte" and any(
        any(tok in ((r.get("asunto") or "") + " " + (r.get("cuerpo") or "")) for tok in legacy_tokens)
        for r in rows
    ):
        _comm_seed_default_templates(overwrite=True)
        rows = mysql_fetchall(
            "SELECT * FROM comm_templates WHERE modulo=%s ORDER BY estado, canal",
            (modulo,),
        ) or []
    data = {}
    for r in rows:
        est = r["estado"]
        if est not in data:
            data[est] = {}
        data[est][r["canal"]] = {
            "id":     r["id"],
            "asunto": r.get("asunto") or "",
            "cuerpo": r.get("cuerpo") or "",
            "activo": r.get("activo", 1),
        }
    return jsonify(data)


@app.route("/comunicaciones/templates/<estado>/<canal>", methods=["PUT"])
@_require_superadmin
def comm_template_save(estado, canal):
    """Guarda/actualiza una plantilla para estado + canal en un módulo dado.
    Body opcional: { modulo: 'transporte' | 'retiros' | 'mantenciones' |
                              'comunicacion_interna' | 'general' }"""
    if canal not in ("email", "whatsapp"):
        return jsonify({"error": "Canal inválido"}), 400
    d      = request.get_json(silent=True) or {}
    modulo = (d.get("modulo") or "transporte").strip()
    if modulo not in _COMM_MODULOS_VALIDOS:
        modulo = "transporte"
    asunto = d.get("asunto", "")
    cuerpo = d.get("cuerpo", "")
    user   = current_username()
    conn   = get_db()
    with conn.cursor() as cur:
        cur.execute(
            """INSERT INTO comm_templates (modulo, estado, canal, asunto, cuerpo, updated_by)
               VALUES (%s,%s,%s,%s,%s,%s)
               ON DUPLICATE KEY UPDATE
                 asunto=VALUES(asunto), cuerpo=VALUES(cuerpo), updated_by=VALUES(updated_by)""",
            (modulo, estado, canal, asunto, cuerpo, user)
        )
    conn.commit()
    # Audit log del cambio
    try:
        _audit(
            "comm_template_save",
            target_type="comm_template",
            target_id=f"{modulo}:{estado}:{canal}",
            details={"modulo": modulo, "estado": estado, "canal": canal,
                     "asunto_len": len(asunto or ""), "cuerpo_len": len(cuerpo or "")},
        )
    except Exception:
        pass
    return jsonify({"ok": True})


@app.route("/comunicaciones/templates/restaurar-todo", methods=["POST"])
@_require_superadmin
def comm_templates_restore_all():
    """Restaura todas las plantillas a la base oficial ILUS."""
    _comm_seed_default_templates(overwrite=True)
    return jsonify({"ok": True})


# ══════════════════════════════════════════════════════════════════════
#  LLAVE DE PASO POR MÓDULO — endpoints REST
#  Permite a admin/superadmin cerrar/abrir email + WhatsApp + SMS por
#  módulo. Útil para pruebas: cuando Daniel cierra la llave de un módulo,
#  los envíos quedan loggeados como 'bloqueado' pero NO salen.
# ══════════════════════════════════════════════════════════════════════

@app.route("/api/comunicaciones/killswitch", methods=["GET"])
def comm_killswitch_get():
    """Devuelve el estado de la llave de paso de TODOS los módulos.
    Visible para admin o superadmin."""
    if not g.user:
        return jsonify({"error": "Sin sesión"}), 401
    if not (g.permissions.get("admin") or g.permissions.get("superadmin")):
        return jsonify({"error": "Solo administradores"}), 403

    estado = _comm_killswitch_estado()
    # Etiquetas legibles para el UI
    labels = {
        "transporte":           "Transporte",
        "retiros":              "Retiros",
        "mantenciones":         "Mantenciones",
        "comunicacion_interna": "Comunicación interna",
        "general":              "General",
    }
    modulos = []
    for mod in _MODULOS_KILLSWITCH_VALIDOS:
        st = estado.get(mod, {}) or {}
        at = st.get("actualizado_at")
        at_iso = None
        try:
            if at is not None:
                at_iso = at.strftime("%Y-%m-%d %H:%M:%S") if hasattr(at, "strftime") else str(at)
        except Exception:
            at_iso = None
        modulos.append({
            "modulo":             mod,
            "label":              labels.get(mod, mod),
            "email_bloqueado":    bool(st.get("email_bloqueado")),
            "whatsapp_bloqueado": bool(st.get("whatsapp_bloqueado")),
            "sms_bloqueado":      bool(st.get("sms_bloqueado")),
            "motivo":             st.get("motivo") or "",
            "actualizado_por":    st.get("actualizado_por") or "",
            "actualizado_at":     at_iso,
        })
    # Banner global: ¿hay al menos uno bloqueado?
    hay_bloqueados = any(
        m["email_bloqueado"] or m["whatsapp_bloqueado"] or m["sms_bloqueado"]
        for m in modulos
    )
    return jsonify({
        "ok":               True,
        "modulos":          modulos,
        "hay_bloqueados":   hay_bloqueados,
    })


@app.route("/api/comunicaciones/killswitch/<modulo>", methods=["PUT"])
def comm_killswitch_set(modulo):
    """Actualiza la llave de paso de un módulo.

    Body JSON:
      { canal: 'email'|'whatsapp'|'sms'|'todos',
        bloqueado: true|false,
        motivo?: 'texto opcional' }

    Cada cambio queda en app_audit_log."""
    if not g.user:
        return jsonify({"error": "Sin sesión"}), 401
    if not (g.permissions.get("admin") or g.permissions.get("superadmin")):
        return jsonify({"error": "Solo administradores"}), 403

    modulo = (modulo or "").strip().lower()
    if modulo not in _MODULOS_KILLSWITCH_VALIDOS:
        return jsonify({"error": f"Módulo inválido: {modulo}"}), 400

    d         = request.get_json(silent=True) or {}
    canal     = (d.get("canal") or "").strip().lower()
    bloqueado = bool(d.get("bloqueado"))
    motivo    = (d.get("motivo") or "").strip()[:1000] or None
    user      = current_username() or "sistema"

    if canal not in ("email", "whatsapp", "sms", "todos"):
        return jsonify({"error": "canal debe ser email, whatsapp, sms o todos"}), 400

    # Resolver columnas a actualizar
    cols_to_set = []
    if canal == "todos":
        cols_to_set = ["email_bloqueado", "whatsapp_bloqueado", "sms_bloqueado"]
    else:
        cols_to_set = [{
            "email": "email_bloqueado",
            "whatsapp": "whatsapp_bloqueado",
            "sms": "sms_bloqueado",
        }[canal]]

    try:
        # UPSERT: si el módulo no tenía fila aún, la crea con valores 0
        existing = mysql_fetchone(
            "SELECT modulo, email_bloqueado, whatsapp_bloqueado, sms_bloqueado, motivo "
            "FROM comm_killswitch WHERE modulo=%s",
            (modulo,)
        )
        if not existing:
            mysql_execute(
                "INSERT IGNORE INTO comm_killswitch "
                "(modulo, email_bloqueado, whatsapp_bloqueado, sms_bloqueado, motivo, actualizado_por) "
                "VALUES (%s, 0, 0, 0, NULL, %s)",
                (modulo, user)
            )

        val = 1 if bloqueado else 0
        # Construir SET dinámico: solo columnas válidas (whitelist arriba)
        set_clauses = ", ".join([f"`{c}`=%s" for c in cols_to_set])
        params      = [val] * len(cols_to_set)
        # Motivo: si no se pasó, conserva el anterior (no lo borramos)
        if motivo is not None:
            set_clauses += ", motivo=%s"
            params.append(motivo)
        set_clauses += ", actualizado_por=%s"
        params.append(user)
        params.append(modulo)
        mysql_execute(
            f"UPDATE comm_killswitch SET {set_clauses} WHERE modulo=%s",
            tuple(params)
        )

        # Invalidar caché → próximo envío leerá BD fresca
        _comm_killswitch_invalidar()

        # Audit log
        try:
            _audit(
                "comm_killswitch_set",
                target_type="comm_killswitch",
                target_id=modulo,
                details={"modulo": modulo, "canal": canal,
                         "bloqueado": bloqueado, "motivo": motivo or ""},
            )
        except Exception: pass

        # Devolver estado actualizado del módulo
        fresh = _comm_killswitch_estado().get(modulo, {}) or {}
        return jsonify({
            "ok":      True,
            "modulo":  modulo,
            "estado": {
                "email_bloqueado":    bool(fresh.get("email_bloqueado")),
                "whatsapp_bloqueado": bool(fresh.get("whatsapp_bloqueado")),
                "sms_bloqueado":      bool(fresh.get("sms_bloqueado")),
                "motivo":             fresh.get("motivo") or "",
            },
        })
    except Exception as exc:
        print(f"[KILLSWITCH] Error al actualizar {modulo}/{canal}: {exc}")
        return jsonify({"error": "No se pudo actualizar la llave de paso."}), 500


# ══════════════════════════════════════════════════════════════════════
