@app.route("/comunicaciones/log")
@require_permission("admin")
def comm_email_log():
    """Redirige al tab Historial dentro de Comunicaciones (centralizado).

    Antes era una página separada. Ahora todo se concentra en la pestaña
    Historial de /comunicaciones para evitar duplicidad. Si vino con filtros
    en query, se preservan en el hash para que el JS los procese.
    """
    qs = []
    for k in ("evento", "estado", "limit"):
        v = request.args.get(k)
        if v: qs.append(f"{k}={v}")
    hash_part = "#tabLog"
    if qs:
        hash_part += "?" + "&".join(qs)
    return redirect(url_for("comm_index") + hash_part)


@app.route("/comunicaciones/log/<int:lid>/reintentar", methods=["POST"])
@require_permission("admin")
def comm_log_reintentar(lid):
    """Reintenta un email que falló."""
    row = mysql_fetchone("SELECT * FROM email_log WHERE id=%s",(lid,))
    if not row: return jsonify({"error":"Log no encontrado"}), 404
    # Reintento envuelto con la plantilla corporativa
    body = (
        f"<p>Reintento del envío original: <strong>{row['asunto']}</strong></p>"
        f"<p>Si crees que es un error, contacta al administrador.</p>"
    )
    html = _comm_render_email_document(row["asunto"], body, "Reintento")
    sent = _send_ilus_email(row["destinatario"], row["asunto"], html, evento="retry_"+(row.get("evento") or "manual"))
    return jsonify({"ok": bool(sent)})


# ══════════════════════════════════════════════════════════════
#  MÓDULO: MANTENCIONES
#  Acceso: superadmin + ejecutivo
# ══════════════════════════════════════════════════════════════

def _mant_required(view):
    """Decorador: requiere permiso 'mantenciones'.

    Si la petición viene de AJAX/wizard (X-Wizard, JSON o XMLHttpRequest),
    devuelve 403 JSON en lugar de redirect 302. Esto evita que el frontend
    reciba HTML cuando esperaba JSON y muestre un error genérico.

    FIX 2026-05-17 (Daniel): cuando un usuario intentaba abrir una OT y
    su rol no tenía el permiso `mantenciones`, lo redirigíamos a `index`
    que es el catálogo de productos. Eso confundía: parecía que abrir la
    OT "te llevaba a los productos". Ahora el redirect prioriza el
    `request.referrer` (vuelve a la página anterior con flash explicando)
    y solo cae a `index` si no hay referrer (acceso directo por URL).
    """
    @wraps(view)
    def wrapped(*args, **kwargs):
        perms = g.get("permissions") or {}
        if not (perms.get("mantenciones") or perms.get("superadmin")):
            # ¿Es una petición AJAX/JSON/Wizard?
            is_ajax = (
                request.headers.get("X-Wizard") == "1"
                or request.headers.get("X-Requested-With") == "XMLHttpRequest"
                or (request.headers.get("Accept") or "").startswith("application/json")
                or request.is_json
                or request.path.startswith("/mantenciones/api/")
            )
            if is_ajax:
                return jsonify({
                    "ok": False,
                    "error": "Tu usuario no tiene permiso para Mantenciones. "
                             "Pide al superadministrador que active 'mantenciones.ver' "
                             "en /admin/roles para tu rol.",
                    "error_codigo": "SIN_PERMISO_MANTENCIONES",
                }), 403
            flash(
                "No tienes permiso para abrir esta sección de Mantenciones. "
                "Pide al superadministrador que active 'mantenciones.ver' para tu rol.",
                "warning",
            )
            # Vuelve a la página anterior si vino de un link interno; sino al home.
            # Evita el efecto "abrir OT → caer en productos" que confundía a Daniel.
            ref = request.referrer or ""
            host_url = request.host_url.rstrip("/")
            if ref and ref.startswith(host_url) and "/mantenciones/" not in ref:
                return redirect(ref)
            return redirect(url_for("index"))
        return view(*args, **kwargs)
    return login_required(wrapped)


def _no_tecnico(view):
    """Decorador: bloquea el acceso a usuarios con role='tecnico'.

    Usado en endpoints de mantenciones que NO son para técnicos
    (ficha de cliente, listado de clientes, etc.). Los técnicos
    solo gestionan OTs asignadas a ellos.

    En AJAX devuelve 403 JSON. En GET normal redirige a su listado
    de OTs con un flash explicativo. Se debe aplicar DESPUÉS de
    @_mant_required (por convención del proyecto).
    """
    @wraps(view)
    def wrapped(*args, **kwargs):
        try:
            u = getattr(g, "user", None)
            role = (u["role"] if u else "") or ""
        except Exception:
            role = ""
        if role == "tecnico":
            is_ajax = (
                request.headers.get("X-Wizard") == "1"
                or request.headers.get("X-Requested-With") == "XMLHttpRequest"
                or (request.headers.get("Accept") or "").startswith("application/json")
                or request.is_json
                or request.path.startswith("/mantenciones/api/")
            )
            if is_ajax:
                return jsonify({
                    "ok": False,
                    "error": "Acceso restringido para técnicos. Gestiona tus OTs desde 'Órdenes de Trabajo'.",
                    "error_codigo": "TECNICO_SIN_ACCESO",
                }), 403
            flash("Como técnico, solo puedes ver las Órdenes de Trabajo asignadas a ti.", "warning")
            return redirect(url_for("mant_ots_list"))
        return view(*args, **kwargs)
    return wrapped


# ═════════════════════════════════════════════════════════════════════
# 🔐 MATRIZ DE PERMISOS POR ACCIÓN — OT (2026-05-18)
# ─────────────────────────────────────────────────────────────────────
# Daniel pidió que SOLAMENTE el técnico asignado pueda gestionar/ejecutar
# una OT (responder tareas, subir fotos, firmar como técnico, etc.). El
# ejecutivo que la creó (Aaron) NO debe poder ejecutarla — solo puede
# crearla, supervisarla y firmar como creador en la pantalla de
# aprobación. El superadministrador SIEMPRE puede hacer y deshacer todo,
# sin excepción.
#
# La matriz se aplica vía el helper `_puede_ot_accion(vid, accion, user)`
# y dos decoradores:
#
#   `_tecnico_owns_visita` (legacy name, mantenido por compat)
#       Endpoints de EJECUCIÓN: solo superadmin + técnico asignado/
#       colaborador. Todos los demás roles (admin, ejecutivo, editor,
#       etc.) son BLOQUEADOS.
#
#   `_ot_can_view` (nuevo, para endpoints de SOLO LECTURA)
#       superadmin + admin + ejecutivo + supervisor + creador + técnico
#       asignado/colaborador. Bloquea solo a tecnico/tecnico_externo que
#       NO tienen la OT asignada (no espiar OTs ajenas).
#
# Acciones reconocidas (claves de la matriz):
#   - 'ejecutar'      → responder tareas, fotos, GPS, firmar técnico,
#                        iniciar/cerrar OT, etc. SOLO técnico asignado +
#                        colaborador + superadmin.
#   - 'aprobar'       → aprobar/rechazar cierre. Supervisor (admin/
#                        ejecutivo) + superadmin + creador de la OT.
#   - 'firmar_creador' → firmar como supervisor/responsable que asignó.
#                        Solo el `created_by` user + superadmin + admin.
#   - 'ver'           → lectura simple. Técnico solo SUS OTs; admin/
#                        ejecutivo/supervisor/creador ven todo.
#   - 'metadata'      → editar metadata, eliminar. Solo admin/superadmin
#                        + creador (para corregir un error al crear).
#                        Técnico NO puede borrar/editar metadata aunque
#                        sea la asignada.
#
# REGLA ABSOLUTA: superadmin SIEMPRE pasa todas las verificaciones, sin
# excepción. Esto es petición textual y no negociable de Daniel.
# ═════════════════════════════════════════════════════════════════════

def _rol_familia(role):
    """Devuelve la 'familia' del rol normalizada para chequear permisos OT.

    Acepta variantes dinámicas creadas por el admin (ej: 'ejecutivo_sstt',
    'supervisor_servicio_tecnico', 'ejecutivo_servicio'). El comparador
    matchea por prefijo + por contains de tokens conocidos, así un rol
    como 'ejecutivo_sstt' cae en la familia 'ejecutivo' y un
    'supervisor_sstt' en 'supervisor'.

    Familias reconocidas (orden de prioridad — superadmin > admin >
    supervisor > ejecutivo > tecnico > otro):

      'superadmin' | 'admin' | 'supervisor' | 'ejecutivo' | 'tecnico' | ''
    """
    r = (role or "").strip().lower()
    if not r:
        return ""
    if r == "superadmin" or r.startswith("superadmin"):
        return "superadmin"
    if r == "admin" or r.startswith("admin_") or r.endswith("_admin"):
        return "admin"
    # supervisor_sstt, supervisor_servicio_tecnico, supervisor, etc.
    if r == "supervisor" or r.startswith("supervisor"):
        return "supervisor"
    # ejecutivo_sstt, ejecutivo_servicio_tecnico, ejecutivo_servicio,
    # ejecutivo, etc.
    if r == "ejecutivo" or r.startswith("ejecutivo"):
        return "ejecutivo"
    # tecnico_externo, tecnico_jr, tecnico, etc.
    if r == "tecnico" or r.startswith("tecnico"):
        return "tecnico"
    return r  # fallback: usar el slug tal cual


def _puede_ot_accion(vid, accion, user=None):
    """Devuelve True si `user` puede ejecutar la `accion` sobre la OT `vid`.

    Args:
      vid:    int o str ID de mant_visitas
      accion: 'ejecutar' | 'aprobar' | 'firmar_creador' | 'ver' | 'metadata'
              | 'configurar' | 'editar' | 'eliminar'
      user:   dict de g.user o None (en cuyo caso usa g.user actual)

    Returns:
      bool — True si pasa, False si denegado.

    Fail-closed: en cualquier error de BD devuelve False (denegar).

    ═══════════════════════════════════════════════════════════════════
    MATRIZ DE PERMISOS POR ROL (2026-05-22, Daniel — clarificación final):
    ─────────────┬──────────┬────────┬─────────┬─────────┬───────────┬───────
    Acción       │ superadm │ admin  │ supervi │ ejecuti │ tecnico   │ otro
    ─────────────┼──────────┼────────┼─────────┼─────────┼───────────┼───────
    ver          │   ✓      │   ✓    │   ✓     │ ✓ (sus) │ ✓ (asign) │  ✗
    crear OT     │   ✓      │   ✓    │   ✓     │   ✓     │   ✗       │  ✗
    configurar   │   ✓      │   ✓    │   ✓     │ ✓(cre)  │ ✓(asign)  │  ✗
    ejecutar     │   ✓      │   ✗    │   ✗     │   ✗     │ ✓(asign)  │  ✗
    metadata     │   ✓      │   ✓    │   ✗     │   ✗     │   ✗       │  ✗
    editar       │   ✓      │   ✓    │   ✗     │   ✗     │   ✗       │  ✗
    eliminar     │   ✓      │   ✗    │   ✗     │   ✗     │   ✗       │  ✗
    aprobar      │   ✓      │   ✓    │   ✓     │   ✓     │   ✗       │  ✗  ← ejecutivo firma
    firmar_creador│  ✓      │   ✓    │   ✓     │   ✓     │   ✗       │  ✗  ← como supervisor
    ─────────────┴──────────┴────────┴─────────┴─────────┴───────────┴───────

    Decisión final 2026-05-22 (Daniel):
      - El ejecutivo SSTT (Aaron) ES el supervisor en el flujo de 3 firmas
        (cliente + técnico + supervisor). Sin su firma la OT no cierra.
      - Sigue SIN poder editar metadata ni eliminar OTs. La firma es su
        compromiso de revisión, no de modificación.

    Responsabilidades por firma (procedimiento interno ILUS):
      Técnico        → "Presté el servicio sin detalles ni problemas."
      Cliente        → "Recibo conforme el trabajo realizado."
      Ejecutivo SSTT → "Reviso y certifico que la OT quedó bien gestionada."
    ═══════════════════════════════════════════════════════════════════
    """
    if user is None:
        user = getattr(g, "user", None) or {}
    role_raw = (user.get("role") or "").lower()
    role = _rol_familia(role_raw)   # 2026-05-18: normaliza ejecutivo_sstt → ejecutivo
    uid = user.get("id")
    username = user.get("username") or ""

    # ── REGLA ABSOLUTA: superadmin SIEMPRE pasa ────────────────────
    if role == "superadmin":
        print(f"[PERM] vid={vid} action={accion} role={role_raw}->{role} user={username} -> ALLOWED (superadmin)", flush=True)
        return True

    # Sin user_id válido → denegar (sesión rota)
    if not uid:
        print(f"[PERM] vid={vid} action={accion} role={role_raw} user={username} -> DENIED (sin uid)", flush=True)
        return False

    # PERF 2026-05-22: cache request-scoped del fetch de mant_visitas.
    # ANTES: mant_ot_ejecutar llama `_puede_ot_accion(vid, ver/ejecutar/
    # aprobar/configurar)` = 4 queries idénticas al `mant_visitas` por
    # cada page-load. AHORA: la primera ejecución guarda en `g._perm_visita_cache`
    # y las siguientes 3 reusan el dict. Reduce 3 queries × cada acción extra.
    # `g` se limpia automáticamente al fin del request (Flask teardown).
    try:
        _perm_cache = getattr(g, "_perm_visita_cache", None)
        if _perm_cache is None:
            _perm_cache = {}
            try:
                g._perm_visita_cache = _perm_cache
            except Exception:
                pass
        _cache_key = ("v", int(vid)) if vid is not None else ("v", None)
    except Exception:
        _perm_cache = {}
        _cache_key = ("v", vid)

    v = _perm_cache.get(_cache_key)
    if v is None:
        # Cargar campos clave de la OT una vez.
        # 2026-05-22 (Aaron Urbina): traemos también `created_by_user_id` (FK
        # estable) si la columna existe — es la fuente de verdad nueva. El
        # string `created_by` queda como fallback para compat con OTs viejas.
        try:
            # Intentamos con la columna nueva; si falla (DB pre-migración), reintento.
            try:
                v = mysql_fetchone(
                    "SELECT tecnico_user_id, created_by, created_by_user_id, "
                    "       firma_supervisor_user_id, estado, tipo "
                    "  FROM mant_visitas WHERE id=%s",
                    (vid,)
                )
            except Exception:
                v = mysql_fetchone(
                    "SELECT tecnico_user_id, created_by, "
                    "       firma_supervisor_user_id, estado, tipo "
                    "  FROM mant_visitas WHERE id=%s",
                    (vid,)
                )
        except Exception as e:
            print(f"[SECURITY] _puede_ot_accion BD error vid={vid}: {e}", flush=True)
            return False
        if not v:
            print(f"[PERM] vid={vid} action={accion} role={role_raw} user={username} -> DENIED (OT inexistente)", flush=True)
            _perm_cache[_cache_key] = False  # cachear "no existe" también
            return False
        _perm_cache[_cache_key] = v
    elif v is False:
        # Cachée previa indicó que la OT no existe.
        return False

    tecnico_uid = v.get("tecnico_user_id")
    creador_username = (v.get("created_by") or "").strip().lower()
    creador_uid = v.get("created_by_user_id")  # puede ser None

    # 🔒 FIX 2026-05-22 (brecha Aaron OT-2026-00008):
    # ANTES `es_creador` solo comparaba `created_by` (varchar) contra
    # `user.username`. Eso fallaba si created_by guardó el nombre legible
    # (ej. 'Aaron Urbina') y username es el email
    # (ej. 'urbinaaaron65@gmail.com').
    # AHORA: 3 chequeos en cascada (cualquiera vale):
    #   1. created_by_user_id == user.id  (FK estable, post-migración)
    #   2. created_by ILIKE user.username  (legacy email-style)
    #   3. created_by ILIKE user.nombre    (legacy nombre-style — caso Aaron)
    user_nombre = (user.get("nombre") or "").strip().lower()
    user_username = username.strip().lower()
    es_creador = False
    try:
        if creador_uid and int(creador_uid) == int(uid):
            es_creador = True
    except (TypeError, ValueError):
        pass
    if not es_creador and creador_username:
        if creador_username == user_username:
            es_creador = True
        elif user_nombre and creador_username == user_nombre:
            es_creador = True

    # ¿Es técnico asignado (principal o colaborador)?
    es_tecnico_asignado = False
    if tecnico_uid and int(tecnico_uid) == int(uid):
        es_tecnico_asignado = True
    else:
        # PERF 2026-05-22: cache request-scoped del colab check (mismo motivo).
        _colab_key = ("colab", int(vid), int(uid))
        if _colab_key in _perm_cache:
            es_tecnico_asignado = _perm_cache[_colab_key]
        else:
            try:
                colab = mysql_fetchone(
                    "SELECT 1 FROM mant_visita_tecnicos "
                    " WHERE visita_id=%s AND tecnico_user_id=%s LIMIT 1",
                    (vid, uid)
                )
                es_tecnico_asignado = bool(colab)
                _perm_cache[_colab_key] = es_tecnico_asignado
            except Exception as e:
                print(f"[SECURITY] error consultando colaboradores vid={vid}: {e}",
                      flush=True)

    # ── EJECUTAR ─────────────────────────────────────────────────
    # responder tareas, subir fotos, firmar técnico, iniciar/cerrar OT.
    # SOLO técnico asignado/colaborador + superadmin (ya retornado arriba).
    # 🔒 FIX 2026-05-22 (Daniel — brecha Aaron): aunque por error administrativo
    # el ejecutivo quede asignado como técnico (caso edge: alguien lo selecciona
    # en el dropdown sin filtrar), NO le permitimos ejecutar. El rol manda.
    # Solo familia 'tecnico' (tecnico, tecnico_externo, etc.) + superadmin
    # pueden ejecutar OTs físicamente. Defense in depth.
    if accion == "ejecutar":
        if role != "tecnico":
            print(f"[PERM] vid={vid} action=ejecutar role={role_raw}->{role} user={username} "
                  f"-> DENIED (solo familia 'tecnico' puede ejecutar; este rol levanta/supervisa)", flush=True)
            return False
        result = es_tecnico_asignado
        print(f"[PERM] vid={vid} action=ejecutar role={role_raw}->{role} user={username} "
              f"tecnico_uid={tecnico_uid} es_asignado={es_tecnico_asignado} -> "
              f"{'ALLOWED' if result else 'DENIED'}", flush=True)
        return result

    # ── CONFIGURAR ──────────────────────────────────────────────
    # FIX 2026-05-22 (OT 2026-00004 Vitacura): aplicar plantilla, agregar
    # tareas, asociar equipos, aplicar protocolo. Antes estas operaciones
    # estaban bajo `ejecutar` (solo técnico asignado), lo que dejaba al
    # ejecutivo/admin creador sin forma de "armar" la OT que él mismo
    # creó. Bug observable: Aaron creó OT preventiva, asignó a Lenin,
    # pero al no poder aplicar plantilla, la OT quedó vacía. Lenin la
    # abrió y vio "Sin máquinas en esta OT".
    #
    # Política nueva: pueden CONFIGURAR la OT (NO ejecutar tareas):
    #   - admin / supervisor (rol global con permiso de gestión)
    #   - ejecutivo creador de la OT
    #   - técnico asignado (compat: técnico siempre podía hacerlo)
    if accion == "configurar":
        if role in ("admin", "supervisor"):
            print(f"[PERM] vid={vid} action=configurar role={role_raw}->{role} user={username} -> ALLOWED (rol global)", flush=True)
            return True
        if role == "ejecutivo" and es_creador:
            print(f"[PERM] vid={vid} action=configurar role={role_raw}->{role} user={username} -> ALLOWED (ejecutivo creador)", flush=True)
            return True
        if es_tecnico_asignado:
            print(f"[PERM] vid={vid} action=configurar role={role_raw}->{role} user={username} -> ALLOWED (técnico asignado)", flush=True)
            return True
        print(f"[PERM] vid={vid} action=configurar role={role_raw}->{role} user={username} "
              f"created_by={creador_username} es_creador={es_creador} "
              f"es_tec_asignado={es_tecnico_asignado} -> DENIED", flush=True)
        return False

    # ── METADATA / EDITAR ───────────────────────────────────────
    # Editar campos generales (título, fecha, tipo, descripción, técnico,
    # estado, modalidad, prioridad, etc.). SOLO admin + superadmin.
    # 🔒 FIX 2026-05-22 (Daniel — brecha Aaron):
    # Antes `ejecutivo+creador` también podía editar. Daniel definió:
    #   "el ejecutivo NO edita NUNCA. Solo crea y supervisa visualmente.
    #    Si necesita corregir algo lo pide al admin."
    # 'editar' es alias semántico de 'metadata' (mismo permiso).
    if accion in ("metadata", "editar"):
        if role == "admin":
            print(f"[PERM] vid={vid} action={accion} role={role_raw}->{role} user={username} -> ALLOWED (admin)", flush=True)
            return True
        print(f"[PERM] vid={vid} action={accion} role={role_raw}->{role} user={username} "
              f"created_by={creador_username} es_creador={es_creador} -> DENIED", flush=True)
        return False

    # ── ELIMINAR ────────────────────────────────────────────────
    # 🔒 Solo superadmin. Ni siquiera admin (que sí puede editar) puede
    # borrar definitivamente. Para "cancelar" una OT mal creada, el admin
    # debe usar PUT estado='cancelada' (conserva historial). Esto matchea
    # la regla actual de `mant_visita_del` (línea 36422).
    if accion == "eliminar":
        # superadmin ya pasó por la regla absoluta arriba; aquí solo
        # llegamos si role != superadmin → DENIED.
        print(f"[PERM] vid={vid} action=eliminar role={role_raw}->{role} user={username} -> DENIED (solo superadmin)", flush=True)
        return False

    # ── CREAR (chequeo sin vid, ver `_puede_crear_ot()`) ───────
    # Esta rama existe para compat semántica si alguien llama con
    # accion='crear' sobre una OT ya existente; permitimos a admin,
    # supervisor y ejecutivo. NO valida vid (la OT ya existe).
    if accion == "crear":
        if role in ("admin", "supervisor", "ejecutivo"):
            return True
        return False

    # ── APROBAR ─────────────────────────────────────────────────
    # Aprobar/rechazar cierre = "tercera firma de supervisión formal".
    #
    # ✅ Daniel 22/05/2026 (clarificación post-deploy):
    #   El EJECUTIVO SSTT (Aaron) ES el supervisor en el flujo de 3 firmas.
    #   Él levanta la OT, asigna al técnico y FIRMA como tercer responsable
    #   cuando Lenin termina. Sin esa firma, la OT no cierra.
    #
    #   Responsabilidades por firma (procedimiento interno ILUS):
    #     - Técnico → "Declaro haber prestado el servicio sin detalles
    #                  ni problemas pendientes."
    #     - Cliente → "Recibo conforme el trabajo realizado y dejo
    #                  registro para evitar reclamos posteriores."
    #     - Ejecutivo SSTT → "Reviso y certifico que la orden de trabajo
    #                  quedó gestionada como corresponde."
    #
    #   Si hay 2+ ejecutivos SSTT, comparten esta atribución.
    #
    # Familia autorizada: admin · supervisor · ejecutivo (+ superadmin
    # ya pasó por la regla absoluta arriba).
    if accion == "aprobar":
        if role in ("admin", "supervisor", "ejecutivo"):
            print(f"[PERM] vid={vid} action=aprobar role={role_raw}->{role} user={username} -> ALLOWED (supervisor formal)", flush=True)
            return True
        print(f"[PERM] vid={vid} action=aprobar role={role_raw}->{role} user={username} "
              f"created_by={creador_username} es_creador={es_creador} -> DENIED", flush=True)
        return False

    # ── FIRMAR_CREADOR ──────────────────────────────────────────
    # Firmar como supervisor en el flujo de 3 firmas (cliente + técnico +
    # supervisor). Misma política que 'aprobar': el ejecutivo SSTT SÍ firma
    # — es su rol gestionar y certificar la OT.
    if accion == "firmar_creador":
        if role in ("admin", "supervisor", "ejecutivo"):
            print(f"[PERM] vid={vid} action=firmar_creador role={role_raw}->{role} user={username} -> ALLOWED (supervisor formal)", flush=True)
            return True
        print(f"[PERM] vid={vid} action=firmar_creador role={role_raw}->{role} user={username} "
              f"created_by={creador_username} es_creador={es_creador} -> DENIED", flush=True)
        return False

    # ── VER ────────────────────────────────────────────────────
    # Lectura: admin/supervisor (siempre), ejecutivo (SUS OTs: creó +
    # asignado), creador, técnico asignado/colaborador.
    # 🔒 FIX 2026-05-22 (Daniel): el ejecutivo NO ve TODAS las OTs (antes
    # sí podía). Ahora solo ve las que él creó o tiene asignadas, igual
    # que el filtro del listado.
    if accion == "ver":
        if role in ("admin", "supervisor"):
            return True
        if role == "ejecutivo":
            # Solo SUS OTs (creó + asignado)
            return es_creador or es_tecnico_asignado
        if es_creador:
            return True
        if es_tecnico_asignado:
            return True
        return False

    # Acción desconocida → denegar
    return False


def _ot_403_response(vid, role, uid, username, accion="ejecutar"):
    """Helper común para devolver 403 con audit trail. AJAX → JSON, GET → flash."""
    print(
        f"[SECURITY] {uid} ({username}) intento {accion} "
        f"vid={vid} sin permiso (role={role}, path={request.path})",
        flush=True
    )
    is_api = (
        request.is_json
        or request.path.startswith("/mantenciones/api/")
        or request.headers.get("X-Requested-With") == "XMLHttpRequest"
        or (request.headers.get("Accept") or "").startswith("application/json")
    )
    if is_api:
        if accion == "ejecutar":
            msg = "Solo el técnico asignado puede gestionar esta OT."
        elif accion in ("metadata", "editar"):
            msg = ("Solo admin/superadmin pueden editar esta OT. Como "
                   "ejecutivo puedes crear OTs pero no modificarlas — pide "
                   "el cambio al administrador.")
        elif accion == "eliminar":
            msg = ("Solo el superadministrador puede eliminar definitivamente "
                   "una OT. Para anularla usa estado='cancelada' (PUT).")
        elif accion == "configurar":
            msg = ("Solo el creador, administrador o técnico asignado "
                   "puede aplicar plantilla o agregar tareas a esta OT.")
        elif accion in ("aprobar", "firmar_creador"):
            msg = ("No tienes permiso para firmar el cierre de esta OT. "
                   "La firma como supervisor le corresponde al ejecutivo SSTT, "
                   "supervisor o administrador.")
        else:
            msg = "No tienes acceso a esa orden de trabajo."
        return jsonify({
            "ok": False,
            "error": msg,
            "error_codigo": "OT_SIN_PERMISO",
        }), 403
    flash("No tienes acceso a esa orden de trabajo.", "warning")
    return redirect(url_for("mant_ots_list"))


def _ot_can_configurar(view_func):
    """Decorador para endpoints que ARMAN la OT antes/durante de la
    ejecución: aplicar plantilla, aplicar protocolo, agregar tareas
    manuales, asociar equipos.

    🔧 FIX 2026-05-22 (OT 2026-00004 Vitacura, Daniel):
    Antes estos endpoints usaban `@_tecnico_owns_visita` (solo técnico
    asignado + superadmin). Eso dejaba al ejecutivo creador SIN forma
    de armar la OT que él mismo creó.

    Política nueva (delegada a `_puede_ot_accion(vid, 'configurar', u)`):
      - superadmin: siempre
      - admin / supervisor: cualquier OT
      - ejecutivo creador: SU OT
      - técnico asignado/colaborador: SU OT (compat)
      - resto: 403

    Espera `vid` como primer parámetro de URL.
    Aplicar SIEMPRE después de @_mant_required.
    """
    @wraps(view_func)
    def wrapped(vid, *args, **kwargs):
        u = getattr(g, "user", None) or {}
        if not _puede_ot_accion(vid, "configurar", u):
            return _ot_403_response(
                vid,
                (u.get("role") or "").lower(),
                u.get("id"),
                u.get("username"),
                accion="configurar",
            )
        return view_func(vid, *args, **kwargs)
    return wrapped


def _tecnico_owns_visita(view_func):
    """Decorador para endpoints de EJECUCIÓN de OT.

    🔐 SEGURIDAD 2026-05-18 (Daniel) — refuerzo crítico:
    Antes solo bloqueaba a roles tecnico/tecnico_externo. Eso permitía
    que Aaron (rol=ejecutivo) y otros pudieran ejecutar la OT de un
    técnico ajeno (responder tareas, subir fotos, firmar). Ahora:

    - SUPERADMIN: siempre pasa (regla absoluta de Daniel).
    - TÉCNICO ASIGNADO (principal o colaborador en mant_visita_tecnicos):
      pasa.
    - TODOS LOS DEMÁS ROLES (admin, ejecutivo, editor, lector, etc.):
      bloqueados con 403/redirect. No pueden ejecutar OTs ajenas.

    Si admin/ejecutivo necesita editar metadata o aprobar cierre, usar
    los endpoints específicos (PUT visita, aprobar-cierre, etc.) que
    aplican la matriz de permisos correspondiente.

    Espera que el view reciba `vid` como primer parámetro de URL.
    Aplicar SIEMPRE después de @_mant_required (convención del proyecto).

    Test cases:
    - Superadmin → cualquier OT → 200 OK
    - Técnico asignado a OT-X → /ot/X/ejecutar → 200 OK
    - Técnico no asignado a OT-X → /ot/X/ejecutar → 403/redirect
    - Aaron (ejecutivo, creador de OT-X asignada a Daniel) → POST tarea → 403
    - Aaron → GET /ot/X (ver ficha) → debe usar endpoint con _ot_can_view
    - Admin → POST tarea en OT ajena → 403 (admin no ejecuta OTs)
    """
    @wraps(view_func)
    def wrapped(vid, *args, **kwargs):
        u = getattr(g, "user", None) or {}
        if not _puede_ot_accion(vid, "ejecutar", u):
            return _ot_403_response(
                vid,
                (u.get("role") or "").lower(),
                u.get("id"),
                u.get("username"),
                accion="ejecutar",
            )
        return view_func(vid, *args, **kwargs)
    return wrapped


def _ot_can_view(view_func):
    """Decorador para endpoints de SOLO LECTURA (GET) de una OT.

    Permite el acceso a admin/ejecutivo/superadmin/creador/técnico
    asignado. Bloquea a técnico no asignado (no puede espiar OTs ajenas).

    Espera `vid` como primer parámetro de URL.
    """
    @wraps(view_func)
    def wrapped(vid, *args, **kwargs):
        u = getattr(g, "user", None) or {}
        if not _puede_ot_accion(vid, "ver", u):
            return _ot_403_response(
                vid,
                (u.get("role") or "").lower(),
                u.get("id"),
                u.get("username"),
                accion="ver",
            )
        return view_func(vid, *args, **kwargs)
    return wrapped


