@app.route("/mantenciones/clientes/nuevo", methods=["GET", "POST"])
@_mant_required
@_no_tecnico
def mant_cliente_nuevo():
    if request.method == "POST":
        d = request.form
        is_wizard = request.headers.get("X-Wizard") == "1"

        # ── VALIDACIONES de datos reales ─────────────────────────────────
        razon = (d.get("razon_social") or "").strip()
        if not razon:
            err = "La razón social es obligatoria."
            if is_wizard: return jsonify({"ok": False, "error": err}), 400
            flash(err, "danger")
            return render_template("mantenciones/cliente_form.html", cliente=None)
        if len(razon) > 200:
            err = "La razón social excede 200 caracteres."
            if is_wizard: return jsonify({"ok": False, "error": err}), 400
            flash(err, "danger")
            return render_template("mantenciones/cliente_form.html", cliente=None)

        # RUT (opcional, pero si viene debe ser válido + único)
        # rut_force=1 (form field o header) permite saltar la validación de DV
        # — útil para RUTs antiguos, dummy, extranjeros o casos donde el
        # ejecutivo está SEGURO que el RUT es correcto aunque módulo-11 falle.
        rut_input = (d.get("rut") or "").strip()
        rut_force = (d.get("rut_force") == "1") or (request.headers.get("X-RUT-Force") == "1")
        rut_norm = None
        if rut_input:
            ok, val_or_err = validar_rut(rut_input)
            if not ok and not rut_force:
                err = f"RUT inválido: {val_or_err}"
                # Devolvemos error_codigo para que el frontend pueda ofrecer
                # "guardar de todos modos" sin perder el resto del wizard.
                if is_wizard: return jsonify({
                    "ok": False,
                    "error": err,
                    "error_codigo": "RUT_DV_INVALIDO",
                    "rut_input": rut_input,
                }), 400
                flash(err, "danger")
                return render_template("mantenciones/cliente_form.html", cliente=None)
            # Si force=true y la validación falló, igual normalizar y guardar
            if not ok and rut_force:
                rut_norm = normalizar_rut(rut_input) or rut_input
            else:
                rut_norm = val_or_err
            # Check duplicado (UNIQUE index nos protege, pero damos error amigable antes)
            existing = mysql_fetchone(
                "SELECT id, razon_social FROM mant_clientes WHERE rut=%s LIMIT 1",
                (rut_norm,)
            )
            if existing:
                err = (f"Ya existe un cliente con ese RUT: "
                       f"«{existing.get('razon_social','')}» (ID {existing.get('id')}).")
                if is_wizard: return jsonify({"ok": False, "error": err,
                                              "duplicate_id": existing.get("id")}), 409
                flash(err, "warning")
                return redirect(url_for("mant_ficha", cid=existing.get("id")))

        # Contacto PRINCIPAL obligatorio (Daniel pidió 2026-05-17): el técnico
        # necesita saber con quién hablar al llegar al sitio. Nombre + teléfono
        # son obligatorios. Email queda opcional. Si viene del wizard / ERP que
        # no tiene contacto, el frontend ya pone los inputs como required pero
        # validamos también en backend por si llega un POST manipulado.
        contacto_nombre_v = (d.get("contacto_nombre") or "").strip()
        contacto_tel_v    = (d.get("contacto_tel") or "").strip()
        if not contacto_nombre_v:
            err = "El nombre del contacto es obligatorio."
            if is_wizard: return jsonify({"ok": False, "error": err, "field": "contacto_nombre"}), 400
            flash(err, "danger")
            return render_template("mantenciones/cliente_form.html", cliente=None)
        if not contacto_tel_v:
            err = "El teléfono del contacto es obligatorio."
            if is_wizard: return jsonify({"ok": False, "error": err, "field": "contacto_tel"}), 400
            flash(err, "danger")
            return render_template("mantenciones/cliente_form.html", cliente=None)

        # Emails (institucional + 2 contactos)
        # Modo tolerante: si el ERP devolvió basura (string sin @, espacios, etc.)
        # auto-limpiamos en vez de bloquear. Solo bloqueamos si el usuario tipeó
        # un email con formato inválido conscientemente.
        emails_to_check = [
            ("email_empresa",   d.get("email_empresa")),
            ("contacto_email",  d.get("contacto_email")),
            ("contacto2_email", d.get("contacto2_email")),
        ]
        emails_norm = {}
        for campo, val in emails_to_check:
            val_clean = (val or "").strip()
            # Si vino vacío o sin '@', tratar como vacío (vino del ERP corrupto)
            if not val_clean or "@" not in val_clean:
                emails_norm[campo] = None
                continue
            ok, val_or_err = validar_email(val_clean)
            if not ok:
                # Solo bloqueamos si tiene '@' pero formato corrupto
                err = f"Email inválido en '{campo}': {val_or_err}. Corrige o deja vacío."
                if is_wizard: return jsonify({"ok": False, "error": err}), 400
                flash(err, "danger")
                return render_template("mantenciones/cliente_form.html", cliente=None)
            emails_norm[campo] = val_or_err

        # Teléfonos (normalizados pero no rechazamos por formato — formato chileno es flexible)
        tel_empresa     = normalizar_telefono(d.get("tel_empresa"))
        tel_contacto    = normalizar_telefono(d.get("contacto_tel"))
        tel_contacto2   = normalizar_telefono(d.get("contacto2_tel"))

        conn = get_mysql()
        try:
            with conn.cursor() as cur:
                try:
                    # Parsear lat/lng del Google Places autocomplete (hidden inputs)
                    try: _lat = float(d.get("direccion_lat")) if d.get("direccion_lat") else None
                    except (TypeError, ValueError): _lat = None
                    try: _lng = float(d.get("direccion_lng")) if d.get("direccion_lng") else None
                    except (TypeError, ValueError): _lng = None
                    _placeid = (d.get("direccion_place_id") or "").strip()[:200] or None

                    cur.execute(
                        """INSERT INTO mant_clientes
                           (razon_social, rut,
                            email_empresa, tel_empresa,
                            contacto_nombre, contacto_cargo, contacto_tel, contacto_email,
                            contacto2_nombre, contacto2_cargo, contacto2_tel, contacto2_email,
                            direccion, direccion_lat, direccion_lng, direccion_place_id,
                            comuna, ciudad, region, giro,
                            notas, notas_confidenciales,
                            estado, created_by, updated_by)
                           VALUES (%s,%s, %s,%s,
                                   %s,%s,%s,%s,
                                   %s,%s,%s,%s,
                                   %s,%s,%s,%s,
                                   %s,%s,%s,%s,
                                   %s,%s,
                                   %s,%s,%s)""",
                        (razon, rut_norm,
                         emails_norm["email_empresa"], tel_empresa,
                         (d.get("contacto_nombre") or "").strip()[:200],
                         (d.get("contacto_cargo")  or "").strip()[:120],
                         tel_contacto, emails_norm["contacto_email"],
                         (d.get("contacto2_nombre") or "").strip()[:200],
                         (d.get("contacto2_cargo")  or "").strip()[:120],
                         tel_contacto2, emails_norm["contacto2_email"],
                         (d.get("direccion") or "").strip(),
                         _lat, _lng, _placeid,
                         (d.get("comuna")    or "").strip()[:100],
                         (d.get("ciudad")    or "").strip()[:100],
                         (d.get("region")    or "").strip()[:100],
                         (d.get("giro")      or "").strip()[:200],
                         (d.get("notas")     or "").strip(),
                         (d.get("notas_confidenciales") or "").strip(),
                         (d.get("estado") or "activo"),
                         current_username(), current_username())
                    )
                    cid = cur.lastrowid
                except Exception as e:
                    # Manejo amigable del error de UNIQUE rut (carrera con check anterior)
                    if "Duplicate entry" in str(e) and "uq_mc_rut" in str(e):
                        err = "Ya existe un cliente con ese RUT (revisar lista de clientes)."
                        if is_wizard: return jsonify({"ok": False, "error": err}), 409
                        flash(err, "warning")
                        return redirect(url_for("mant_clientes"))
                    raise
            conn.commit()
            _mant_log("cliente", cid, "creado", razon)
            if is_wizard:
                return jsonify({"ok": True, "id": cid})
            return redirect(url_for("mant_ficha", cid=cid))
        finally:
            conn.close()
    return render_template("mantenciones/cliente_form.html", cliente=None)


@app.route("/mantenciones/api/clientes/enriquecer")
@_mant_required
def mant_enriquecer_cliente():
    """
    Consulta /entidades del ERP por RUT exacto y devuelve datos normalizados.
    GET /mantenciones/api/clientes/enriquecer?rut=77.123.456-7
    Usa _normalize_phone_cl y _cmen_to_comuna para máxima calidad.

    PREFER_SQL=1 (default): consulta directo a MAEEN vía SQL Server.
    Fallback: REST /entidades.
    """
    rut = (request.args.get("rut") or "").strip()
    if not rut:
        return jsonify({"error": "RUT requerido"}), 400

    # Cuerpo del RUT (sin DV, sin puntos): "77.123.456-7" → "77123456"
    rut_clean = rut.replace(".", "").replace(" ", "").strip()
    rut_body  = rut_clean.split("-")[0] if "-" in rut_clean else rut_clean

    # ── Path SQL (primario cuando PREFER_SQL=1) ──
    _prefer_sql = (os.environ.get("ILUS_ERP_PREFER_SQL", "1").strip().lower()
                   in ("1", "true", "yes", "on"))
    if _prefer_sql:
        try:
            row = _random_sql_one(
                "SELECT TOP 1 "
                "       LTRIM(RTRIM(COALESCE(RTEN,      ''))) AS RTEN, "
                "       LTRIM(RTRIM(COALESCE(NOKOEN,    ''))) AS NOKOEN, "
                "       LTRIM(RTRIM(COALESCE(NOKOENAMP, ''))) AS NOKOENAMP, "
                "       LTRIM(RTRIM(COALESCE(EMAIL,     ''))) AS EMAIL, "
                "       LTRIM(RTRIM(COALESCE(FOEN,      ''))) AS FOEN, "
                "       LTRIM(RTRIM(COALESCE(FAEN,      ''))) AS FAEN, "
                "       LTRIM(RTRIM(COALESCE(DIEN,      ''))) AS DIEN, "
                "       LTRIM(RTRIM(COALESCE(CMEN,      ''))) AS CMEN, "
                "       LTRIM(RTRIM(COALESCE(CIEN,      ''))) AS CIEN, "
                "       LTRIM(RTRIM(COALESCE(GIEN,      ''))) AS GIEN, "
                "       LTRIM(RTRIM(COALESCE(OBEN,      ''))) AS OBEN "
                "  FROM MAEEN "
                " WHERE LTRIM(RTRIM(RTEN)) = %s",
                (rut_body,),
            )
            if row:
                cien = (row.get("CIEN") or "").strip()
                cmen = (row.get("CMEN") or "").strip()
                raw_tel = (row.get("FOEN") or row.get("FAEN") or "").strip()
                nombre_largo = (row.get("NOKOENAMP") or "").strip()
                nombre_corto = (row.get("NOKOEN") or "").strip()
                import erp_engine as _erpe_local
                return jsonify({
                    "encontrado":    True,
                    "razon_social":  _erpe_local.fix_yen_to_n(nombre_largo or nombre_corto).title(),
                    "rut":           (row.get("RTEN") or rut).strip(),
                    "email":         (row.get("EMAIL") or "").strip(),
                    "telefono":      _normalize_phone_cl(raw_tel),
                    "direccion":     _erpe_local.fix_yen_to_n(row.get("DIEN") or "").title(),
                    "comuna":        _cmen_to_comuna(cien, cmen),
                    "region":        _REGION_NOMBRES.get(str(cien).zfill(3), ""),
                    "giro":          (row.get("GIEN") or "").strip(),
                    "observaciones": _erpe_local.fix_yen_to_n(row.get("OBEN") or ""),
                    "cien":          cien,
                    "cmen":          cmen,
                    "fuente":        "sql_server",
                })
            # No encontrado en SQL → seguir al fallback REST por si REST tiene más
        except Exception as ex_sql:
            print(f"[mant-enriquecer-sql] error: {ex_sql} — cae a REST", flush=True)

    # ── Path REST (fallback) ──
    TOKEN = ERP_CONFIG.get("api_token", "")
    try:
        body = _erp_get("/entidades", {"rten": rut}, TOKEN, timeout=8)
        data = body.get("data") or []
        if not data:
            return jsonify({"encontrado": False, "rut": rut})
        e    = data[0]
        cien = (e.get("CIEN") or "").strip()
        cmen = (e.get("CMEN") or "").strip()
        raw_tel = (e.get("FOEN") or e.get("FAEN") or "").strip()
        region  = _REGION_NOMBRES.get(str(cien).zfill(3), "")
        return jsonify({
            "encontrado":    True,
            "razon_social":  (e.get("NOKOEN") or "").strip().title(),
            "rut":           (e.get("RTEN")   or rut).strip(),
            "email":         (e.get("EMAIL")  or e.get("EMAILCOMER") or "").strip(),
            "telefono":      _normalize_phone_cl(raw_tel),
            "direccion":     (e.get("DIEN")   or "").strip().title(),
            "comuna":        _cmen_to_comuna(cien, cmen),
            "region":        region,
            "giro":          (e.get("GIEN")   or "").strip(),
            "observaciones": (e.get("OBEN")   or "").strip(),
            "cien":          cien,
            "cmen":          cmen,
            "fuente":        "rest_api",
        })
    except Exception as ex:
        return jsonify({"error": str(ex), "encontrado": False}), 503


@app.route("/mantenciones/clientes/<int:cid>")
@_mant_required
@_no_tecnico
def mant_ficha(cid):
    try:
        return _mant_ficha_impl(cid)
    except Exception as _e_ficha:
        import traceback as _tb
        print(f"[ficha-cli] cid={cid} ERROR: {_e_ficha}\n{_tb.format_exc()}",
              flush=True)
        try:
            flash(
                f"No se pudo cargar la ficha del cliente #{cid}. "
                f"Reporta este código al admin: cid={cid}.",
                "danger")
        except Exception:
            pass
        return redirect(url_for("mant_clientes"))


def _mant_ficha_impl(cid):
    cliente   = mysql_fetchone("SELECT * FROM mant_clientes WHERE id=%s", (cid,))
    if not cliente:
        return redirect(url_for("mant_clientes"))
    # FIX 2026-05-18 — defensiva contra rows legacy con campos None.
    # El template ficha.html hace `cliente.estado.title()` directo en varios
    # lugares, así que un valor None reventaría el render. Forzamos
    # defaults sensatos antes de pasar al template.
    try:
        cliente = dict(cliente)
        if not (cliente.get("estado") or "").strip():
            cliente["estado"] = "activo"
        if not (cliente.get("razon_social") or "").strip():
            cliente["razon_social"] = f"Cliente #{cid}"
    except Exception:
        pass

    # ── Helper: normaliza datetime/date de MySQL a datetime.date ──────────
    def _d(val):
        """Convierte datetime o date a date para comparaciones seguras."""
        if val is None:
            return None
        return val.date() if hasattr(val, 'date') else val

    # ── Helper: normaliza hora de MySQL ──────────────────────────────────
    # MySQL devuelve columnas TIME como datetime.timedelta (¡NO time!).
    # El template hace .strftime('%H:%M') que rompe con timedelta.
    # Devolvemos siempre un string "HH:MM" o None.
    def _h(val):
        if val is None:
            return None
        # timedelta (caso típico MySQL TIME)
        if isinstance(val, timedelta):
            total = int(val.total_seconds())
            if total < 0:
                total = 0
            hh = (total // 3600) % 24
            mm = (total % 3600) // 60
            return f"{hh:02d}:{mm:02d}"
        # datetime.time u objeto con strftime
        if hasattr(val, 'strftime'):
            try:
                return val.strftime('%H:%M')
            except Exception:
                pass
        # String que ya viene como "08:00:00" o "08:00"
        s = str(val).strip()
        return s[:5] if s else None

    # ── Normaliza filas de DB para evitar mezcla datetime/date ───────────
    def _norm_maquina(row):
        r = dict(row)
        for k in ('doc_fecha', 'fecha_instalacion', 'created_at', 'updated_at'):
            if k in r:
                r[k] = _d(r[k])
        return r

    def _norm_contrato(row):
        r = dict(row)
        for k in ('fecha_inicio', 'fecha_vencimiento', 'ai_fecha',
                  'ai_vigencia_inicio', 'ai_vigencia_fin',
                  'created_at', 'updated_at'):
            if k in r:
                r[k] = _d(r[k])
        # FIX 2026-05-18 — defensiva: estado/nombre/nivel_riesgo nunca None.
        # El template usa .replace().title() directo sobre contratos[0].estado
        # y otros campos, así que un None hace 500.
        if r.get('estado') is None:
            r['estado'] = ''
        if r.get('nivel_riesgo') is None:
            r['nivel_riesgo'] = ''
        return r

    def _norm_visita(row):
        r = dict(row)
        r['fecha_programada'] = _d(r.get('fecha_programada'))
        if 'created_at' in r:
            r['created_at'] = _d(r['created_at'])
        # CRÍTICO: hora_inicio/hora_fin vienen como timedelta desde MySQL.
        # Sin esta normalización el template falla con
        # "datetime.timedelta has no attribute strftime"
        if 'hora_inicio' in r:
            r['hora_inicio'] = _h(r.get('hora_inicio'))
        if 'hora_fin' in r:
            r['hora_fin'] = _h(r.get('hora_fin'))
        # FIX 2026-05-18 — defensiva: tipo/estado/titulo nunca None.
        # El template usa .title() y .replace() directamente sobre estos
        # campos en varios sitios, así que si vienen None la ficha
        # explota. Forzar string vacío evita 500 silencioso.
        for _k in ('tipo', 'estado', 'titulo', 'tecnico'):
            if _k in r and r[_k] is None:
                r[_k] = ''
        return r

    # 2026-05-15: filtrar máquinas dadas de baja del listado principal de la ficha.
    # Las máquinas con estado='baja' siguen en BD pero NO se muestran aquí.
    # Para verlas/restaurarlas: GET /mantenciones/api/clientes/<cid>/maquinas-baja
    # CAMBIO 2026-05-26 (Daniel — filtro "mostrar bajas"): traemos TODOS
    # los equipos (activos + bajas) y el frontend oculta/muestra según el
    # toggle "Mostrar bajas". Las filas dadas de baja se marcan con
    # data-estado="baja" y CSS atenuado. Por default solo se ven activos.
    maquinas_raw  = mysql_fetchall(
        "SELECT * FROM mant_maquinas "
        " WHERE cliente_id=%s "
        " ORDER BY "
        "   CASE WHEN COALESCE(estado,'activo')='baja' THEN 1 ELSE 0 END ASC, "
        "   created_at DESC",
        (cid,)
    ) or []
    # SELECT * para máxima compatibilidad con el template (revertido del SELECT
    # explícito que causó error al perder alguna columna como monto_anual,
    # clausulas_custom, variables_extra, ai_editable, etc.)
    contratos_raw = mysql_fetchall(
        "SELECT * FROM mant_contratos WHERE cliente_id=%s ORDER BY created_at DESC",
        (cid,)
    ) or []
    # 2026-05-22 (Daniel — caso Vitacura/JDA): marcar contratos que tienen
    # algún adjunto válido en Cloudinary para que el botón "Ver PDF" del
    # template aparezca incluso cuando el contrato principal tiene
    # archivo_path/cloudinary_url en NULL (caso SEED de demo). El endpoint
    # mant_contrato_archivo hace fallback automático a estos adjuntos.
    try:
        _ct_ids = [int(r["id"]) for r in contratos_raw if r.get("id")]
        if _ct_ids:
            placeholders = ",".join(["%s"] * len(_ct_ids))
            _adj_disponibles = mysql_fetchall(
                f"SELECT DISTINCT contrato_id FROM mant_contrato_adjuntos "
                f"WHERE contrato_id IN ({placeholders}) "
                f"  AND cloudinary_url IS NOT NULL AND cloudinary_url <> '' "
                f"  AND tipo IN ('contrato','anexo','externo','otro')",
                tuple(_ct_ids)
            ) or []
            _ct_con_adj = {int(r["contrato_id"]) for r in _adj_disponibles}
            for _ct in contratos_raw:
                _ct["tiene_adjunto_visible"] = int(_ct.get("id") or 0) in _ct_con_adj
        else:
            for _ct in contratos_raw:
                _ct["tiene_adjunto_visible"] = False
    except Exception as _e_adj:
        print(f"[ficha contratos] tiene_adjunto_visible flag failed: {_e_adj}", flush=True)
        for _ct in contratos_raw:
            _ct["tiene_adjunto_visible"] = False

    # ── AUTO-SYNC CLOUDINARY 2026-05-26 (Daniel — "esto debe operar sí o sí") ──
    # Cuando se carga la ficha, lanzamos un thread en background que sube a
    # Cloudinary CUALQUIER contrato del cliente que tenga archivo en disco
    # pero NO esté en cloud. Esto hace que la auto-cura sea invisible para el
    # usuario: la próxima vez que abra el visor, el contrato estará en cloud
    # y se previsualizará al instante.
    #
    # Idempotente: si ya está en cloud, se salta. Si no hay archivo en disco
    # (Railway redeployó), no se puede recuperar — solo re-subiendo manualmente.
    try:
        _pending_sync = [
            ct for ct in contratos_raw
            if (ct.get("archivo_path") or "").strip()
            and not (ct.get("cloudinary_url") or "").strip()
        ]
        if _pending_sync and _CLD_READY:
            import threading as _th_sync

            def _sync_cliente_silent(_ctlist, _cid):
                """Sube en background los contratos del cliente que están en
                disco pero no en cloud. Errores se loguean, no se propagan."""
                for _ctp in _ctlist:
                    try:
                        _path = _ctp.get("archivo_path")
                        if not _path:
                            continue
                        _full = os.path.join(MANT_UPLOADS, _path)
                        if not os.path.exists(_full):
                            continue
                        with open(_full, "rb") as _fh:
                            _pid = f"contrato_{_cid}_{int(time.time())}_{_ctp['id']}_autosync"
                            _res = _cloud_upload_raw(_fh, _pid, folder="ilus/contratos")
                        mysql_execute(
                            "UPDATE mant_contratos "
                            "   SET cloudinary_url=%s, cloudinary_public_id=%s, "
                            "       cloudinary_uploaded_at=%s "
                            " WHERE id=%s AND (cloudinary_url IS NULL OR cloudinary_url='')",
                            (_res["url"], _res["public_id"], datetime.utcnow(), _ctp["id"])
                        )
                        print(f"[ficha autosync] ctid={_ctp['id']} → cloud OK",
                              flush=True)
                    except Exception as _e_si:
                        print(f"[ficha autosync] ctid={_ctp.get('id')} FAIL: {_e_si}",
                              flush=True)

            _th_sync.Thread(
                target=_sync_cliente_silent,
                args=(list(_pending_sync), cid),
                daemon=True
            ).start()
            print(f"[ficha autosync] cid={cid} lanzando sync silencioso de "
                  f"{len(_pending_sync)} contrato(s)", flush=True)
    except Exception as _e_autosync:
        # Nunca bloquear el render de la ficha por una falla en el sync
        print(f"[ficha autosync] no se pudo lanzar thread: {_e_autosync}",
              flush=True)

    # PERF: LIMIT 200 en visitas (stats 12m + tab visitas no requieren más)
    visitas_raw   = mysql_fetchall(
        "SELECT * FROM mant_visitas WHERE cliente_id=%s ORDER BY fecha_programada DESC LIMIT 200",
        (cid,)
    ) or []

    # PERF: logs sin subqueries correlacionadas. Recolectamos IDs primero.
    # Envuelto en try/except por defensivo: si algo falla, fallback a query original.
    logs = []
    try:
        ids_contratos = [int(r["id"]) for r in contratos_raw]
        ids_maquinas  = [int(r["id"]) for r in maquinas_raw]
        ids_visitas   = [int(r["id"]) for r in visitas_raw]
        try:
            _rep_rows = mysql_fetchall(
                "SELECT id FROM mant_reportes WHERE cliente_id=%s", (cid,)
            ) or []
        except Exception:
            _rep_rows = []
        ids_reportes  = [int(r["id"]) for r in _rep_rows]

        _log_clauses = ["(entidad='cliente' AND entidad_id=%s)"]
        _log_params  = [cid]
        if ids_contratos:
            _log_clauses.append(
                f"(entidad='contrato' AND entidad_id IN ({','.join(['%s']*len(ids_contratos))}))")
            _log_params.extend(ids_contratos)
        if ids_maquinas:
            _log_clauses.append(
                f"(entidad='maquina' AND entidad_id IN ({','.join(['%s']*len(ids_maquinas))}))")
            _log_params.extend(ids_maquinas)
        if ids_visitas:
            _log_clauses.append(
                f"(entidad='visita' AND entidad_id IN ({','.join(['%s']*len(ids_visitas))}))")
            _log_params.extend(ids_visitas)
        if ids_reportes:
            _log_clauses.append(
                f"(entidad='reporte' AND entidad_id IN ({','.join(['%s']*len(ids_reportes))}))")
            _log_params.extend(ids_reportes)
        logs = mysql_fetchall(
            f"""SELECT * FROM mant_logs
                WHERE {' OR '.join(_log_clauses)}
                ORDER BY created_at DESC LIMIT 50""",
            tuple(_log_params)
        ) or []
    except Exception as _e:
        # Fallback: query original con subqueries (más lenta pero garantizada)
        try:
            logs = mysql_fetchall(
                """SELECT * FROM mant_logs
                   WHERE (entidad='cliente' AND entidad_id=%s)
                      OR (entidad='contrato' AND entidad_id IN (SELECT id FROM mant_contratos WHERE cliente_id=%s))
                      OR (entidad='maquina'  AND entidad_id IN (SELECT id FROM mant_maquinas  WHERE cliente_id=%s))
                      OR (entidad='visita'   AND entidad_id IN (SELECT id FROM mant_visitas   WHERE cliente_id=%s))
                   ORDER BY created_at DESC LIMIT 50""",
                (cid, cid, cid, cid)
            ) or []
            print(f"[MANT][ficha] fallback logs query usado: {_e}")
        except Exception as _e2:
            print(f"[MANT][ficha] error CRÍTICO en logs: {_e2}")
            logs = []

    # Normalizar todas las fechas a datetime.date
    maquinas     = [_norm_maquina(r)  for r in maquinas_raw]
    contratos    = [_norm_contrato(r) for r in contratos_raw]
    visitas_full = [_norm_visita(r)   for r in visitas_raw]

    # ── 2026-05-21 (Daniel) — Última revisión por equipo ───────────────
    # Para cada máquina del cliente, traemos la última fila de
    # mant_visita_equipos. Lo pintamos en la tabla de equipos (badge
    # con estado: verificado / con cambios / saltado / falla).
    if maquinas:
        try:
            _ids_maq = [int(m["id"]) for m in maquinas]
            _ph = ",".join(["%s"] * len(_ids_maq))
            # Subquery: por cada maquina_id, traer la fila más reciente
            # de mant_visita_equipos (greatest-n-per-group con id como
            # desempate). Compatible con MySQL 5.7+ sin window functions.
            _rev_rows = mysql_fetchall(
                f"""
                SELECT ve.maquina_id, ve.visita_id, ve.estado_revision,
                       ve.razon_saltado, ve.observacion_tecnico,
                       ve.revisado_at, ve.revisado_por,
                       v.numero_ot, v.tipo AS visita_tipo,
                       v.fecha_programada
                  FROM mant_visita_equipos ve
                  JOIN mant_visitas v ON v.id = ve.visita_id
                  JOIN (
                       SELECT maquina_id, MAX(id) AS max_id
                         FROM mant_visita_equipos
                        WHERE maquina_id IN ({_ph})
                        GROUP BY maquina_id
                  ) lastrev ON lastrev.maquina_id = ve.maquina_id
                           AND lastrev.max_id = ve.id
                """,
                tuple(_ids_maq)
            ) or []
            _idx_rev = {}
            for _r in _rev_rows:
                _idx_rev[int(_r["maquina_id"])] = {
                    "estado_revision":     _r.get("estado_revision") or "verificado",
                    "razon_saltado":       _r.get("razon_saltado") or "",
                    "observacion":         _r.get("observacion_tecnico") or "",
                    "revisado_at":         _r.get("revisado_at"),
                    "revisado_por":        _r.get("revisado_por") or "",
                    "numero_ot":           _r.get("numero_ot") or "",
                    "visita_id":           _r.get("visita_id"),
                    "visita_tipo":         _r.get("visita_tipo") or "",
                    "fecha":               _r.get("fecha_programada"),
                }
            for _m in maquinas:
                _m["ultima_revision"] = _idx_rev.get(int(_m["id"]))
        except Exception as _e_ur:
            print(f"[MANT][ficha] ultima_revision load error: {_e_ur}", flush=True)

    # ── ESTADÍSTICAS PARA SIDEBAR / GRÁFICOS ──────────────────────────────
    hoy = datetime.now().date()
    fecha_corte_12m = hoy - timedelta(days=365)

    visitas_12m = [v for v in visitas_full if v.get("fecha_programada") and v["fecha_programada"] >= fecha_corte_12m]
    visitas_realizadas = [v for v in visitas_12m if v.get("estado") == "completada"]
    visitas_programadas_30d = [
        v for v in visitas_full
        if v.get("estado") == "programada"
        and v.get("fecha_programada")
        and hoy <= v["fecha_programada"] <= (hoy + timedelta(days=30))
    ]
    visitas_correctivas = [v for v in visitas_12m if v.get("tipo") == "correctiva"]

    total_programadas_12m  = len([v for v in visitas_12m if v.get("estado") in ("programada","completada","reagendada")])
    total_realizadas_12m   = len(visitas_realizadas)
    cumplimiento_pct       = round(100 * total_realizadas_12m / total_programadas_12m) if total_programadas_12m else 0

    # Mantenciones por mes (últimos 12 meses) — para barra
    import calendar
    months_es = ['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic']
    mant_por_mes = []
    for i in range(11, -1, -1):
        ref_year  = hoy.year
        ref_month = hoy.month - i
        while ref_month <= 0:
            ref_month += 12
            ref_year  -= 1
        cnt = sum(1 for v in visitas_12m
                  if v.get("fecha_programada")
                  and v["fecha_programada"].month == ref_month
                  and v["fecha_programada"].year  == ref_year
                  and v.get("estado") == "completada")
        mant_por_mes.append({
            "mes":   months_es[ref_month-1],
            "year":  ref_year,
            "count": cnt,
        })

    # Estado de equipos (donut)
    eq_activos      = len([m for m in maquinas if (m.get("estado") or "activo") == "activo"])
    eq_advertencia  = len([m for m in maquinas if m.get("estado") == "advertencia"])
    eq_inactivos    = len([m for m in maquinas if m.get("estado") == "inactivo"])
    eq_total        = max(1, len(maquinas))

    # Próxima visita
    prox_visita = next((v for v in visitas_full
                        if v.get("estado") == "programada"
                        and v.get("fecha_programada")
                        and v["fecha_programada"] >= hoy), None)
    # Última visita realizada
    ult_visita = next((v for v in visitas_full
                       if v.get("estado") == "completada"
                       and v.get("fecha_programada")
                       and v["fecha_programada"] <= hoy), None)
    dias_desde_ultima = (hoy - ult_visita["fecha_programada"]).days if ult_visita else None
    dias_hasta_prox   = (prox_visita["fecha_programada"] - hoy).days if prox_visita else None

    # Alertas inteligentes (calculadas server-side)
    alertas_smart = []
    # 1. Equipos con garantía próxima a vencer
    for m in maquinas:
        if m.get("doc_fecha"):
            try:
                dias_doc = (hoy - m["doc_fecha"]).days
                if 150 <= dias_doc <= 180:
                    alertas_smart.append({
                        "tipo": "warning",
                        "icon": "shield-exclamation",
                        "titulo": f"{m['nombre']} — Garantía próxima a vencer",
                        "detalle": f"Quedan {180 - dias_doc} días de garantía",
                    })
            except Exception:
                pass
    # 2. Contratos por vencer
    for ct in contratos:
        if ct.get("fecha_vencimiento") and not ct.get("es_indefinido"):
            try:
                dias_v = (ct["fecha_vencimiento"] - hoy).days
                if 0 < dias_v <= 60:
                    alertas_smart.append({
                        "tipo": "warning",
                        "icon": "file-earmark-text",
                        "titulo": f"Contrato vence en {dias_v} días",
                        "detalle": ct.get("nombre") or "Contrato sin nombre",
                    })
                elif dias_v <= 0:
                    alertas_smart.append({
                        "tipo": "danger",
                        "icon": "file-earmark-x",
                        "titulo": "Contrato VENCIDO",
                        "detalle": ct.get("nombre") or "Contrato sin nombre",
                    })
            except Exception:
                pass
    # 3. Mucho tiempo sin visita
    if dias_desde_ultima is not None and dias_desde_ultima > 90:
        alertas_smart.append({
            "tipo": "warning",
            "icon": "calendar-x",
            "titulo": f"Sin visita hace {dias_desde_ultima} días",
            "detalle": "Considera programar una mantención preventiva",
        })
    # 4. Próxima mantención cercana
    if dias_hasta_prox is not None and 0 <= dias_hasta_prox <= 7:
        # FIX 2026-05-18 — defensiva: .get("x","") devuelve None si la
        # clave existe con None. Usar `or ""` antes de .title() evita el
        # AttributeError típico de "NoneType has no attribute 'title'".
        _detalle_tipo = (prox_visita.get("tipo") or "").title()
        alertas_smart.append({
            "tipo": "info",
            "icon": "calendar-check",
            "titulo": f"Próxima visita en {dias_hasta_prox} día{'s' if dias_hasta_prox != 1 else ''}",
            "detalle": (prox_visita.get("titulo") or "") or _detalle_tipo or "Visita",
        })

    stats = {
        "realizadas_12m":          total_realizadas_12m,
        "programadas_30d":         len(visitas_programadas_30d),
        "incidencias_abiertas":    len([v for v in visitas_full if v.get("tipo") == "correctiva" and v.get("estado") == "programada"]),
        "cumplimiento_pct":        cumplimiento_pct,
        "mant_por_mes":            mant_por_mes,
        "max_mes":                 max((m["count"] for m in mant_por_mes), default=1) or 1,
        "eq_activos":              eq_activos,
        "eq_advertencia":          eq_advertencia,
        "eq_inactivos":            eq_inactivos,
        "eq_total":                len(maquinas),
        "eq_pct_activos":          round(100 * eq_activos / eq_total),
        "eq_pct_advertencia":      round(100 * eq_advertencia / eq_total),
        "eq_pct_inactivos":        round(100 * eq_inactivos / eq_total),
        "ult_visita_fecha":        ult_visita["fecha_programada"] if ult_visita else None,
        "ult_visita_dias":         dias_desde_ultima,
        "prox_visita_fecha":       prox_visita["fecha_programada"] if prox_visita else None,
        "prox_visita_dias":        dias_hasta_prox,
        "alertas_smart":           alertas_smart,
        "total_correctivas_12m":   len(visitas_correctivas),
    }

    # Normaliza logs: conserva datetime convertido a hora Chile (America/Santiago).
    # MySQL en cloud guarda en UTC; sin conversión la hora mostrada está mal.
    try:
        from zoneinfo import ZoneInfo
        _tz_scl = ZoneInfo("America/Santiago")
        _tz_utc = ZoneInfo("UTC")
    except Exception:
        _tz_scl = _tz_utc = None

    def _to_chile(dt):
        if dt is None or _tz_scl is None or not isinstance(dt, datetime):
            return dt
        if dt.tzinfo is None:
            dt = dt.replace(tzinfo=_tz_utc)
        return dt.astimezone(_tz_scl)

    def _norm_log(row):
        r = dict(row)
        r['created_at'] = _to_chile(r.get('created_at'))
        return r

    # Sucursales (información adicional opcional)
    try:
        sucursales = mysql_fetchall(
            "SELECT * FROM mant_sucursales WHERE cliente_id=%s AND activo=1 ORDER BY nombre",
            (cid,)
        )
        sucursales = [dict(s) for s in (sucursales or [])]
    except Exception:
        sucursales = []

    return render_template("mantenciones/ficha.html",
        cliente   = dict(cliente),
        maquinas  = maquinas,
        contratos = contratos,
        visitas   = visitas_full[:50],
        logs      = [_norm_log(r) for r in logs],
        hoy       = hoy,
        stats     = stats,
        sucursales = sucursales,
    )


@app.route("/mantenciones/api/clientes/<int:cid>", methods=["PUT"])
@_mant_required
def mant_cliente_update(cid):
    d = request.get_json(silent=True) or {}
    # Whitelist de campos editables. tipo_cliente agregado 2026-05-21 (Plan
    # fancy-cuddling-marble) — valida que sea uno de los 3 valores válidos.
    fields = ["razon_social","rut","email_empresa","tel_empresa","giro",
              "contacto_nombre","contacto_cargo","contacto_tel","contacto_email",
              "contacto2_nombre","contacto2_cargo","contacto2_tel","contacto2_email",
              "direccion","comuna","ciudad","region",
              "direccion_lat","direccion_lng","direccion_place_id",
              "notas","notas_confidenciales","estado","tipo_cliente"]
    # Validación dura del ENUM tipo_cliente — si llega valor distinto, lo descartamos
    # silenciosamente para no romper el UPDATE.
    if "tipo_cliente" in d:
        _tc = str(d.get("tipo_cliente") or "").strip().lower()
        if _tc not in ("mantencion", "arriendo", "leasing"):
            d.pop("tipo_cliente", None)
        else:
            d["tipo_cliente"] = _tc
    # Geo (Google Places): sanitizar lat/lng a float|None y place_id a str|None.
    # Las columnas son DECIMAL(10,7)/VARCHAR — un '' string rompería el UPDATE.
    if "direccion_lat" in d:
        try: d["direccion_lat"] = float(d["direccion_lat"]) if str(d.get("direccion_lat") or "").strip() else None
        except (TypeError, ValueError): d["direccion_lat"] = None
    if "direccion_lng" in d:
        try: d["direccion_lng"] = float(d["direccion_lng"]) if str(d.get("direccion_lng") or "").strip() else None
        except (TypeError, ValueError): d["direccion_lng"] = None
    if "direccion_place_id" in d:
        d["direccion_place_id"] = (str(d.get("direccion_place_id") or "").strip()[:200]) or None
    sets   = [f"{f}=%s" for f in fields if f in d]
    vals   = [d[f] for f in fields if f in d]
    if not sets:
        return jsonify({"error": "Sin campos"}), 400
    # Auditoría: quién actualizó
    sets.append("updated_by=%s")
    vals.append(current_username())
    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            cur.execute(f"UPDATE mant_clientes SET {','.join(sets)} WHERE id=%s",
                        vals + [cid])
        conn.commit()
        # Log especial si se cambió el estado: deja rastro claro de quién y a qué.
        # Esto evita "fichas perdidas" en el futuro porque se puede auditar.
        if "estado" in d:
            try:
                _mant_log("cliente", cid, f"estado_a_{d['estado']}",
                          f"Estado del cliente cambiado a '{d['estado']}' por {current_username()}")
            except Exception:
                pass
        _mant_log("cliente", cid, "editado")
        return jsonify({"ok": True})
    finally:
        conn.close()


# ══════════════════════════════════════════════════════════════════════
# RECUPERACIÓN DE FICHAS — buscar y restaurar clientes "perdidos"
#
# Caso de uso: un usuario marca un cliente como inactivo/suspendido por
# error y la ficha "desaparece" del listado (que filtra por estado='activo').
# Estos endpoints permiten encontrarlos y restaurarlos sin perder data.
# ══════════════════════════════════════════════════════════════════════

@app.route("/mantenciones/api/clientes/buscar-todos", methods=["GET"])
@_mant_required
def mant_clientes_buscar_todos():
    """Búsqueda global en mant_clientes SIN filtro de estado.
    Devuelve TODOS los clientes que matchean por nombre/RUT/email/giro/comuna,
    incluyendo los soft-archivados (estado != 'activo').

    Usado por el modal "Clientes ocultos" para recuperar fichas perdidas.
    """
    q = (request.args.get("q") or "").strip()
    incluir_activos = request.args.get("incluir_activos") == "1"

    where, params = [], []
    if not incluir_activos:
        # Por defecto solo mostramos los NO activos (la papelera real)
        where.append("c.estado <> 'activo'")
    if q:
        where.append(
            "(c.razon_social LIKE %s OR c.rut LIKE %s OR c.contacto_email LIKE %s "
            " OR c.email_empresa LIKE %s OR c.giro LIKE %s OR c.comuna LIKE %s)"
        )
        qp = f"%{q}%"; params += [qp]*6
    wstr = " WHERE " + " AND ".join(where) if where else ""

    rows = mysql_fetchall(
        f"""SELECT c.id, c.razon_social, c.rut, c.estado, c.giro, c.comuna,
                   c.contacto_nombre, c.contacto_email, c.contacto_tel,
                   c.created_at, c.updated_at, c.created_by, c.updated_by,
                   COALESCE(m_cnt.cnt, 0) AS maquinas_count,
                   COALESCE(ct_cnt.cnt, 0) AS contratos_count,
                   COALESCE(v_cnt.cnt, 0) AS visitas_count
              FROM mant_clientes c
              LEFT JOIN (SELECT cliente_id, COUNT(*) AS cnt FROM mant_maquinas GROUP BY cliente_id) m_cnt
                     ON m_cnt.cliente_id = c.id
              LEFT JOIN (SELECT cliente_id, COUNT(*) AS cnt FROM mant_contratos GROUP BY cliente_id) ct_cnt
                     ON ct_cnt.cliente_id = c.id
              LEFT JOIN (SELECT cliente_id, COUNT(*) AS cnt FROM mant_visitas GROUP BY cliente_id) v_cnt
                     ON v_cnt.cliente_id = c.id
              {wstr}
              ORDER BY c.razon_social
              LIMIT 200""",
        tuple(params)
    )

    result = []
    for r in rows:
        result.append({
            "id": r["id"],
            "razon_social": r.get("razon_social") or "",
            "rut": r.get("rut") or "",
            "estado": r.get("estado") or "",
            "giro": r.get("giro") or "",
            "comuna": r.get("comuna") or "",
            "contacto_nombre": r.get("contacto_nombre") or "",
            "contacto_email": r.get("contacto_email") or "",
            "contacto_tel": r.get("contacto_tel") or "",
            "created_at": str(r["created_at"])[:16] if r.get("created_at") else "",
            "updated_at": str(r["updated_at"])[:16] if r.get("updated_at") else "",
            "created_by": r.get("created_by") or "",
            "updated_by": r.get("updated_by") or "",
            "maquinas_count": int(r.get("maquinas_count") or 0),
            "contratos_count": int(r.get("contratos_count") or 0),
            "visitas_count": int(r.get("visitas_count") or 0),
            "url_ficha": url_for("mant_ficha", cid=r["id"]),
        })
    return jsonify({"ok": True, "clientes": result, "total": len(result)})


@app.route("/mantenciones/api/clientes/<int:cid>/restaurar", methods=["POST"])
@_mant_required
def mant_cliente_restaurar(cid):
    """Restaura un cliente al estado 'activo' (lo saca de la papelera).
    Audita la acción en mant_logs.
    """
    cliente = mysql_fetchone(
        "SELECT id, razon_social, estado FROM mant_clientes WHERE id=%s", (cid,)
    )
    if not cliente:
        return jsonify({"ok": False, "error": "Cliente no encontrado"}), 404
    if cliente["estado"] == "activo":
        return jsonify({"ok": True, "ya_activo": True,
                        "mensaje": f"{cliente['razon_social']} ya está activo"})

    estado_previo = cliente["estado"]
    mysql_execute(
        "UPDATE mant_clientes SET estado='activo', updated_by=%s WHERE id=%s",
        (current_username(), cid)
    )
    try:
        _mant_log("cliente", cid, "restaurado",
                  f"Restaurado de '{estado_previo}' a 'activo' por {current_username()}")
    except Exception:
        pass
    return jsonify({
        "ok": True,
        "cliente_id": cid,
        "razon_social": cliente["razon_social"],
        "estado_previo": estado_previo,
        "mensaje": f"✓ {cliente['razon_social']} restaurado correctamente",
    })


@app.route("/mantenciones/api/clientes/<int:cid>/cambiar-estado", methods=["POST"])
@_mant_required
def mant_cliente_cambiar_estado(cid):
    """Cambia el estado del cliente de forma explícita con auditoría completa.
    Body: { "estado": "activo|inactivo|suspendido|prospecto", "motivo": "..." }
    """
    d = request.get_json(silent=True) or {}
    estado_nuevo = (d.get("estado") or "").strip().lower()
    motivo = (d.get("motivo") or "").strip()[:500]
    if estado_nuevo not in ("activo", "inactivo", "suspendido", "prospecto"):
        return jsonify({"ok": False, "error": "Estado inválido"}), 400
    cliente = mysql_fetchone(
        "SELECT id, razon_social, estado FROM mant_clientes WHERE id=%s", (cid,)
    )
    if not cliente:
        return jsonify({"ok": False, "error": "Cliente no encontrado"}), 404
    if cliente["estado"] == estado_nuevo:
        return jsonify({"ok": True, "ya_en_estado": True})
    mysql_execute(
        "UPDATE mant_clientes SET estado=%s, updated_by=%s WHERE id=%s",
        (estado_nuevo, current_username(), cid)
    )
    try:
        _mant_log("cliente", cid, f"estado_a_{estado_nuevo}",
                  f"Cambiado de '{cliente['estado']}' a '{estado_nuevo}' por {current_username()}"
                  + (f" · Motivo: {motivo}" if motivo else ""))
    except Exception:
        pass
    return jsonify({"ok": True, "estado": estado_nuevo})


# ══════════════════════════════════════════════════════════════════
# DEDUPLICACIÓN DE CLIENTES (modelo Fracttal — datos limpios)
#
# Caso real: "MBJ SUAREZ CONUS SpA" apareció duplicado en producción
# porque mant_clientes.rut admite NULLs y el UNIQUE en rut no bloquea
# (NULL ≠ NULL en SQL). Estos endpoints permiten detectar y fusionar.
# ══════════════════════════════════════════════════════════════════

@app.route("/mantenciones/api/clientes/duplicados", methods=["GET"])
@_mant_required
def mant_clientes_duplicados():
    """Detecta clientes duplicados.
    Reglas de detección:
      - Por RUT (cuando RUT no es NULL ni vacío): mismo RUT = duplicado
      - Por nombre normalizado (cuando RUT está vacío): mismo nombre
        sin acentos ni espacios = duplicado probable.
    """
    # Duplicados por RUT
    rows_rut = mysql_fetchall(
        "SELECT rut, GROUP_CONCAT(id ORDER BY id) AS ids, "
        "       COUNT(*) AS cant, GROUP_CONCAT(razon_social SEPARATOR ' || ') AS razones "
        "  FROM mant_clientes "
        " WHERE rut IS NOT NULL AND rut <> '' "
        " GROUP BY rut "
        "HAVING COUNT(*) > 1 "
        " ORDER BY cant DESC"
    ) or []
    # Duplicados por nombre (sin RUT)
    rows_nombre = mysql_fetchall(
        "SELECT LOWER(REPLACE(REPLACE(razon_social,' ',''),'.','')) AS norm, "
        "       GROUP_CONCAT(id ORDER BY id) AS ids, "
        "       COUNT(*) AS cant, GROUP_CONCAT(razon_social SEPARATOR ' || ') AS razones "
        "  FROM mant_clientes "
        " WHERE (rut IS NULL OR rut = '') AND razon_social IS NOT NULL "
        " GROUP BY norm "
        "HAVING COUNT(*) > 1 "
        " ORDER BY cant DESC"
    ) or []

    def _expand(rows, criterio):
        out = []
        for r in rows:
            ids = [int(x) for x in (r.get("ids") or "").split(",") if x.strip().isdigit()]
            if len(ids) < 2: continue
            # Para cada id, traer info enriquecida (counts de máquinas, contratos, OTs)
            detalles = []
            for cid_ in ids:
                info = mysql_fetchone(
                    "SELECT c.id, c.razon_social, c.rut, c.estado, c.created_at, c.created_by, "
                    "       (SELECT COUNT(*) FROM mant_maquinas WHERE cliente_id=c.id AND COALESCE(estado,'activo')<>'baja') AS n_maq, "
                    "       (SELECT COUNT(*) FROM mant_contratos WHERE cliente_id=c.id) AS n_ct, "
                    "       (SELECT COUNT(*) FROM mant_visitas WHERE cliente_id=c.id) AS n_ot "
                    "  FROM mant_clientes c WHERE c.id=%s",
                    (cid_,)
                )
                if info:
                    detalles.append({
                        "id": info["id"],
                        "razon_social": info.get("razon_social"),
                        "rut": info.get("rut") or "",
                        "estado": info.get("estado"),
                        "created_at": str(info["created_at"])[:16] if info.get("created_at") else "",
                        "created_by": info.get("created_by") or "",
                        "n_maquinas": int(info.get("n_maq") or 0),
                        "n_contratos": int(info.get("n_ct") or 0),
                        "n_ots": int(info.get("n_ot") or 0),
                    })
            out.append({
                "criterio": criterio,
                "valor": r.get("rut") or r.get("norm"),
                "ids": ids,
                "cantidad": len(ids),
                "detalles": detalles,
            })
        return out

    grupos_rut = _expand(rows_rut, "rut")
    grupos_nombre = _expand(rows_nombre, "nombre")
    return jsonify({
        "ok": True,
        "duplicados_por_rut": grupos_rut,
        "duplicados_por_nombre": grupos_nombre,
        "total_grupos": len(grupos_rut) + len(grupos_nombre),
    })


@app.route("/mantenciones/api/clientes/<int:cid_keep>/fusionar/<int:cid_drop>", methods=["POST"])
@_mant_required
def mant_clientes_fusionar(cid_keep, cid_drop):
    """Fusiona dos clientes duplicados.

    cid_keep: el que se conserva (el "bueno", con datos limpios)
    cid_drop: el duplicado a eliminar. Sus máquinas, contratos, OTs,
              fotos, etc., se reasignan a cid_keep antes de soft-delete.

    Solo admin/superadmin. Audita la operación completa en mant_logs.
    """
    if not ((g.permissions or {}).get("admin") or (g.permissions or {}).get("superadmin")):
        return jsonify({"ok": False, "error": "Solo admin/superadmin puede fusionar."}), 403

    if cid_keep == cid_drop:
        return jsonify({"ok": False, "error": "No puedes fusionar un cliente consigo mismo."}), 400

    c_keep = mysql_fetchone("SELECT id, razon_social, rut FROM mant_clientes WHERE id=%s", (cid_keep,))
    c_drop = mysql_fetchone("SELECT id, razon_social, rut FROM mant_clientes WHERE id=%s", (cid_drop,))
    if not c_keep:
        return jsonify({"ok": False, "error": f"Cliente {cid_keep} no encontrado"}), 404
    if not c_drop:
        return jsonify({"ok": False, "error": f"Cliente {cid_drop} no encontrado"}), 404

    user = current_username()
    stats = {"maquinas": 0, "contratos": 0, "visitas": 0,
             "sucursales": 0, "contactos": 0, "documentos": 0, "fotos": 0,
             "levantamientos": 0, "logs": 0}

    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            # Reasignar TODAS las relaciones del duplicado al cliente bueno
            tablas_a_reasignar = [
                ("mant_maquinas",            "cliente_id", "maquinas"),
                ("mant_contratos",           "cliente_id", "contratos"),
                ("mant_visitas",             "cliente_id", "visitas"),
                ("mant_sucursales",          "cliente_id", "sucursales"),
                ("mant_contrato_adjuntos",   "cliente_id", "documentos"),
                ("mant_maquina_eventos",     "cliente_id", "logs"),
                ("mant_levantamientos",      "cliente_id", "levantamientos"),
                ("mant_reportes",            "cliente_id", "documentos"),
                ("mant_logs",                "entidad_id", None),  # logs con entidad='cliente'
            ]
            for tabla, col, key_stat in tablas_a_reasignar:
                try:
                    if tabla == "mant_logs":
                        cur.execute(
                            "UPDATE mant_logs SET entidad_id=%s "
                            "WHERE entidad='cliente' AND entidad_id=%s",
                            (cid_keep, cid_drop)
                        )
                    else:
                        cur.execute(
                            f"UPDATE {tabla} SET {col}=%s WHERE {col}=%s",
                            (cid_keep, cid_drop)
                        )
                    if key_stat:
                        stats[key_stat] = stats.get(key_stat, 0) + cur.rowcount
                except Exception as e_t:
                    print(f"[fusionar] tabla {tabla} falló: {e_t}", flush=True)

            # Soft-delete del duplicado en vez de hard-delete: deja rastro
            cur.execute(
                "UPDATE mant_clientes SET estado='inactivo', updated_by=%s, "
                "       notas=CONCAT(COALESCE(notas,''), %s) "
                " WHERE id=%s",
                (user, f"\n\n[FUSIONADO con cliente #{cid_keep} ({c_keep['razon_social']}) por {user} el "
                       f"{_now_chile_str('%Y-%m-%d %H:%M')}]", cid_drop)
            )
        conn.commit()

        _mant_log("cliente", cid_keep, "fusion_recibida",
                  f"Recibió datos de #{cid_drop} ({c_drop['razon_social']}) — "
                  f"{stats['maquinas']} eq · {stats['contratos']} ct · {stats['visitas']} ot")
        _mant_log("cliente", cid_drop, "fusionado_a",
                  f"Fusionado a #{cid_keep} ({c_keep['razon_social']}) por {user}")

        return jsonify({
            "ok": True,
            "cliente_conservado": {"id": cid_keep, "razon_social": c_keep['razon_social']},
            "cliente_fusionado": {"id": cid_drop, "razon_social": c_drop['razon_social']},
            "reasignaciones": stats,
            "mensaje": (
                f"Fusión exitosa. Todos los datos de '{c_drop['razon_social']}' (#{cid_drop}) "
                f"se reasignaron a '{c_keep['razon_social']}' (#{cid_keep}). "
                f"El duplicado quedó como inactivo (puede restaurarse desde Fichas Ocultas si fue un error)."
            ),
        })
    finally:
        conn.close()


@app.route("/mantenciones/api/clientes/<int:cid>", methods=["DELETE"])
@_mant_required
def mant_cliente_delete(cid):
    """Elimina un cliente y TODOS sus datos asociados.

    Triple protección:
      1. Solo SUPERADMIN puede ejecutar (NO admin general).
      2. Requiere confirm_text en el body que coincida con razón social o RUT.
      3. Auto-cleanup de huérfanos al final (defensa contra FK legacy).
    """
    # ★ Restricción estricta: SOLO superadmin puede borrar clientes.
    # Borrar arrastra contratos, visitas, máquinas y fotos en cascada — es
    # una operación delicada que debe quedar reservada al dueño del sistema.
    if not g.permissions.get("superadmin"):
        return jsonify({
            "error": "Solo el superadministrador puede eliminar clientes. "
                     "Esta acción borra contratos, visitas, máquinas y fotos en cascada."
        }), 403

    cliente = mysql_fetchone(
        "SELECT id, razon_social, rut FROM mant_clientes WHERE id=%s", (cid,)
    )
    if not cliente:
        return jsonify({"error":"Cliente no encontrado"}), 404

    d = request.get_json(silent=True) or {}
    confirm = (d.get("confirm_text") or "").strip().lower()
    rs = (cliente.get("razon_social") or "").strip().lower()
    rut = re.sub(r"[^0-9kK]","",(cliente.get("rut") or "")).lower()
    confirm_norm = re.sub(r"[^0-9kK]","",confirm) if confirm.replace(".","").replace("-","").replace("k","").isdigit() else confirm
    if confirm not in (rs, (cliente.get("rut") or "").lower()) and confirm_norm != rut:
        return jsonify({
            "error": f"Para confirmar, escribe exactamente la razón social o el RUT del cliente.",
            "expected_rs": cliente.get("razon_social"),
            "expected_rut": cliente.get("rut"),
        }), 400

    # Inventario de lo que se va a eliminar (para auditoría)
    counts = {}
    try:
        for tbl, label in [
            ("mant_maquinas","equipos"),
            ("mant_contratos","contratos"),
            ("mant_visitas","visitas"),
            ("mant_reportes","reportes"),
            ("mant_repuestos","repuestos"),
            ("mant_notificaciones","notificaciones"),
        ]:
            row = mysql_fetchone(f"SELECT COUNT(*) AS n FROM {tbl} WHERE cliente_id=%s",(cid,))
            counts[label] = (row or {}).get("n", 0)
    except Exception: pass

    # Recolectar IDs hijos para limpiar sus logs (mant_logs no tiene FK)
    ids_visitas    = [r["id"] for r in (mysql_fetchall(
        "SELECT id FROM mant_visitas WHERE cliente_id=%s", (cid,)) or [])]
    ids_maquinas   = [r["id"] for r in (mysql_fetchall(
        "SELECT id FROM mant_maquinas WHERE cliente_id=%s", (cid,)) or [])]
    ids_contratos  = [r["id"] for r in (mysql_fetchall(
        "SELECT id FROM mant_contratos WHERE cliente_id=%s", (cid,)) or [])]

    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            # Apagar FK checks por si quedan logs huérfanos o relaciones legacy
            cur.execute("SET FOREIGN_KEY_CHECKS = 0")
            try:
                # Borrar dependencias que NO tienen ON DELETE CASCADE explícito
                cur.execute("DELETE FROM mant_repuestos WHERE cliente_id=%s", (cid,))
                cur.execute("DELETE FROM mant_reportes WHERE cliente_id=%s", (cid,))
                cur.execute("DELETE FROM mant_notificaciones WHERE cliente_id=%s", (cid,))

                # Limpiar logs huérfanos de los hijos antes del DELETE en cascada
                cur.execute(
                    "DELETE FROM mant_logs WHERE entidad='cliente' AND entidad_id=%s",
                    (cid,)
                )
                if ids_visitas:
                    placeholders = ",".join(["%s"] * len(ids_visitas))
                    cur.execute(
                        f"DELETE FROM mant_logs WHERE entidad='visita' AND entidad_id IN ({placeholders})",
                        tuple(ids_visitas)
                    )
                if ids_maquinas:
                    placeholders = ",".join(["%s"] * len(ids_maquinas))
                    cur.execute(
                        f"DELETE FROM mant_logs WHERE entidad='maquina' AND entidad_id IN ({placeholders})",
                        tuple(ids_maquinas)
                    )
                    # mant_maquina_audit
                    try:
                        cur.execute(
                            f"DELETE FROM mant_maquina_audit WHERE maquina_id IN ({placeholders})",
                            tuple(ids_maquinas)
                        )
                    except Exception: pass
                if ids_contratos:
                    placeholders = ",".join(["%s"] * len(ids_contratos))
                    cur.execute(
                        f"DELETE FROM mant_logs WHERE entidad='contrato' AND entidad_id IN ({placeholders})",
                        tuple(ids_contratos)
                    )

                # mant_maquinas, mant_contratos, mant_visitas tienen ON DELETE CASCADE
                # → al borrar cliente, esos hijos se borran solos y a su vez
                # arrastran sus visitas_tareas, visitas_fotos, etc. también CASCADE.
                cur.execute("DELETE FROM mant_clientes WHERE id=%s", (cid,))

                # AUDIT: registrar la eliminación. Usamos 'cliente' (valor válido
                # del ENUM) con entidad_id=0 para indicar acción global sobre cliente.
                cur.execute(
                    "INSERT INTO mant_logs (entidad,entidad_id,accion,detalle,usuario) "
                    "VALUES ('cliente', 0, 'cliente_eliminado', %s, %s)",
                    (f"#{cid} {cliente.get('razon_social') or ''} (RUT {cliente.get('rut') or '—'}) "
                     f"— {counts}",
                     current_username())
                )

                # ── Auto-limpieza de huérfanos (defensa contra FK CASCADE que
                # no se aplicaron por datos legacy o estructura antigua) ──
                # Esto garantiza que tras borrar un cliente, NUNCA queden
                # contratos/visitas/máquinas/sucursales sin padre.
                for child_tbl in ("mant_contratos", "mant_visitas", "mant_maquinas",
                                  "mant_sucursales", "mant_reportes", "mant_repuestos",
                                  "mant_notificaciones"):
                    try:
                        cur.execute(f"""
                            DELETE FROM {child_tbl}
                            WHERE cliente_id IS NULL
                               OR cliente_id NOT IN (SELECT id FROM mant_clientes)
                        """)
                    except Exception: pass
            finally:
                try: cur.execute("SET FOREIGN_KEY_CHECKS = 1")
                except Exception: pass
        conn.commit()
        print(f"[MANT][DEL] cliente#{cid} '{cliente.get('razon_social')}' eliminado por {current_username()} — {counts}")
        return jsonify({
            "ok": True,
            "razon_social": cliente.get("razon_social"),
            "rut": cliente.get("rut"),
            "eliminado": counts,
        })
    except Exception as exc:
        try: conn.rollback()
        except Exception: pass
        return jsonify({"error": f"No se pudo eliminar: {exc}"}), 500
    finally:
        conn.close()


# ── MÁQUINAS ──────────────────────────────────────────────────────────

def _generar_serie_ilus(cid: int, sku: str = "", _intento: int = 0) -> str:
    """
    Genera un N° Serie único para un equipo físico cuando el fabricante no
    proporciona uno.

    Formato amigable: {RUT}-{SKU4}-{n}
      RUT  = RUT del cliente sin DV ni puntos (ej: 65206047)
      SKU4 = últimos 4 caracteres alfanuméricos del SKU del modelo
      n    = secuencial dentro del cliente para ese SKU

    Ejemplos:
      65206047-0905-1   (Trotadora ILUS, SKU 1027100905, primera unidad)
      65206047-0905-2   (segunda trotadora del mismo modelo)
      65206047-4640-1   (otro equipo, SKU termina en 4640)

    SEGURIDAD CONCURRENCIA: si dos workers leen 'usados' simultáneamente,
    podrían intentar la misma serie. La UNIQUE KEY uq_cliente_serie en
    mant_maquinas garantiza que el INSERT fallará. La función `mant_maquina_add`
    atrapa Duplicate entry y reintenta con _intento+1.

    Editable: el usuario puede reemplazar con el serial real del fabricante.
    """
    import random
    # Obtener RUT del cliente (sin DV, sin puntos)
    rut_clean = "00000000"
    try:
        row = mysql_fetchone("SELECT rut FROM mant_clientes WHERE id=%s", (cid,))
        if row and row.get("rut"):
            raw = str(row["rut"]).replace(".", "").replace(" ", "").replace("-", "").upper()
            rut_clean = raw[:-1] if len(raw) >= 8 else raw
    except Exception:
        pass

    # Últimos 4 chars alfanum del SKU
    sku_clean = "".join(c for c in (sku or "AUTO").upper() if c.isalnum())
    sku4 = sku_clean[-4:] if len(sku_clean) >= 4 else (sku_clean.rjust(4, "0") if sku_clean else "AUTO")
    base = f"{rut_clean}-{sku4}"
    rows = mysql_fetchall(
        "SELECT serie FROM mant_maquinas WHERE cliente_id=%s AND serie LIKE %s",
        (cid, f"{base}-%")
    )
    usados = set()
    for r in rows or []:
        suf = (r.get("serie") or "").rsplit("-", 1)[-1]
        try: usados.add(int(suf))
        except Exception: pass
    seq = 1
    while seq in usados:
        seq += 1
    # Si es reintento por colisión concurrente, agregar offset aleatorio para
    # evitar volver a chocar con el mismo número que otro worker eligió
    if _intento > 0:
        seq += random.randint(_intento, _intento * 10)
    return f"{base}-{seq}"


@app.route("/mantenciones/api/clientes/<int:cid>/maquinas", methods=["POST"])
@_mant_required
def mant_maquina_add(cid):
    """Agrega máquina(s) a la ficha del cliente.

    Nuevos parámetros (opcionales) para soportar carga desde documento ERP:
      split_to_rows: bool — si true y cantidad>1, crea N filas con cantidad=1
                            cada una (cada equipo con su propia serie).
                            Si false, crea 1 fila con cantidad=N (gestión grupal).
      validar_saldo: bool — si true, verifica que el saldo del documento
                            (cantidad_original - ya_asignadas) sea ≥ cantidad
                            solicitada. Default false.
      force:         bool — si true, ignora la validación de saldo (admin override).
                            Para casos donde el ERP devolvió mal la cantidad.
    """
    d = request.get_json(silent=True) or {}

    cantidad     = int(d.get("cantidad", 1) or 1)
    if cantidad < 1: cantidad = 1
    split_rows   = bool(d.get("split_to_rows", False))
    validar      = bool(d.get("validar_saldo", False))
    force        = bool(d.get("force", False))
    # SKU siempre en upper para que matchee con saldos y queries
    sku          = (d.get("sku","") or "").strip().upper()
    # 2026-05-27 (Daniel — auto-SKU para creación manual):
    # Si no viene SKU, generamos uno automático con formato "MAN-<cid>-<timestamp>"
    # (MAN = manual). El usuario lo puede editar después desde la ficha.
    if not sku and d.get("auto_sku"):
        sku = f"MAN-{cid}-{int(time.time())}"[:80].upper()
    # doc_origen NORMALIZADO al formato canónico 'TIDO NUDO' (sin leading zeros)
    # Esto garantiza que _asignados_por_sku encuentre el match en futuras consultas.
    doc_origen   = _doc_origen_normalizar((d.get("doc_origen","") or "").strip())

    # ── Validación de saldo (sólo si vienen los datos del documento ERP) ──
    if validar and not force and doc_origen and sku:
        try:
            # Extraer tido + nudo desde doc_origen (formato "TIDO NUDO" o "TIDO-NUDO")
            partes = doc_origen.replace("-", " ").split()
            if len(partes) >= 2:
                tido_d, nudo_d = partes[0], partes[1]
                # Cantidad original en el documento: viene en el body (front lo manda)
                qty_original = int(d.get("cantidad_original") or 0)
                if qty_original > 0:
                    asignados = _asignados_por_sku(tido_d, nudo_d)
                    ya_asig   = int(asignados.get(sku.upper(), 0))
                    saldo     = qty_original - ya_asig
                    if cantidad > saldo:
                        return jsonify({
                            "ok": False,
                            "error_codigo": "SALDO_INSUFICIENTE",
                            "error": (f"Saldo insuficiente para SKU {sku} en {doc_origen}. "
                                      f"Documento tenía {qty_original}, ya hay {ya_asig} asignadas, "
                                      f"sólo quedan {saldo} disponibles. "
                                      f"Estás intentando agregar {cantidad}."),
                            "saldo_disponible": saldo,
                            "cantidad_solicitada": cantidad,
                            "ya_asignadas": ya_asig,
                        }), 409  # 409 Conflict (estado actual de recurso)
        except Exception:
            pass  # si la validación misma falla, no bloqueamos

    def _insert_con_retry(cur, base_params, serie_inicial, max_intentos=5):
        """INSERT con retry si la UNIQUE (cliente_id, serie) está tomada
        por concurrencia. Devuelve (last_id, serie_efectiva)."""
        serie = serie_inicial
        for intento in range(max_intentos):
            try:
                cur.execute(
                    """INSERT INTO mant_maquinas
                       (cliente_id,sku,nombre,serie,doc_origen,doc_fecha,cantidad,notas,
                        ubicacion_cliente,estado_op,fecha_instalacion,
                        tag_1,tag_2,
                        justif_fecha_inst,justif_doc_mismatch,created_by)
                       VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)""",
                    base_params(serie)
                )
                return cur.lastrowid, serie
            except Exception as e:
                msg = str(e)
                # MySQL error 1062 = Duplicate entry. Regenerar serie y reintentar.
                if "1062" in msg or "Duplicate entry" in msg:
                    serie = _generar_serie_ilus(cid, sku, _intento=intento + 1)
                    continue
                raise
        # Si pasamos los 5 intentos sin éxito, devolver error claro
        raise Exception(f"No se pudo generar serie única tras {max_intentos} intentos para cliente {cid}, SKU {sku}")

    conn = get_mysql()
    creadas = []
    try:
        with conn.cursor() as cur:
            # Modo SPLIT: N filas con cantidad=1 (cada equipo con su propia serie)
            if split_rows and cantidad > 1:
                for _ in range(cantidad):
                    serie_nueva = _generar_serie_ilus(cid, sku)
                    def build(s, _r=d):
                        return (cid, sku, _r.get("nombre",""), s,
                                doc_origen, _r.get("doc_fecha") or None, 1,
                                _r.get("notas",""),
                                _r.get("ubicacion_cliente",""),
                                _r.get("estado_op","operativo"),
                                _r.get("fecha_instalacion") or None,
                                (_r.get("tag_1") or "").strip()[:120] or None,
                                (_r.get("tag_2") or "").strip()[:120] or None,
                                _r.get("justif_fecha_inst") or None,
                                _r.get("justif_doc_mismatch") or None,
                                current_username())
                    mid_new, serie_efectiva = _insert_con_retry(cur, build, serie_nueva)
                    creadas.append({"id": mid_new, "serie": serie_efectiva})
            else:
                # Modo CLÁSICO: 1 fila con cantidad=N
                serie = (d.get("serie") or "").strip()
                if not serie or serie.startswith("(auto"):
                    serie = _generar_serie_ilus(cid, sku)
                def build(s, _r=d, _q=cantidad):
                    return (cid, sku, _r.get("nombre",""), s,
                            doc_origen, _r.get("doc_fecha") or None, _q,
                            _r.get("notas",""),
                            _r.get("ubicacion_cliente",""),
                            _r.get("estado_op","operativo"),
                            _r.get("fecha_instalacion") or None,
                            (_r.get("tag_1") or "").strip()[:120] or None,
                            (_r.get("tag_2") or "").strip()[:120] or None,
                            _r.get("justif_fecha_inst") or None,
                            _r.get("justif_doc_mismatch") or None,
                            current_username())
                mid_new, serie_efectiva = _insert_con_retry(cur, build, serie)
                creadas.append({"id": mid_new, "serie": serie_efectiva})
        conn.commit()
        # 2026-05-27 (Daniel): UPDATE post-INSERT con campos nuevos opcionales.
        # Se hace por separado para no romper el INSERT principal si alguna
        # columna no existe en BDs viejas. Cada campo en try independiente.
        try:
            _campos_extra = {
                "familia_equipo":    (d.get("familia_equipo") or "").strip()[:30],
                "marca":             (d.get("marca") or "").strip()[:120],
                "modelo":            (d.get("modelo") or "").strip()[:120],
                "anio_fabricacion":  d.get("anio_fabricacion"),
                "ubicacion_sala":    (d.get("ubicacion_sala") or "").strip()[:200],
            }
            # Solo intentar UPDATE si al menos un campo extra tiene valor real
            _hay_extra = any(v for v in _campos_extra.values() if v not in (None, "", 0))
            if _hay_extra and creadas:
                _ids_creados = [c["id"] for c in creadas]
                for _id_eq in _ids_creados:
                    for _col, _val in _campos_extra.items():
                        if _val in (None, "", 0):
                            continue
                        try:
                            mysql_execute(
                                f"UPDATE mant_maquinas SET {_col}=%s WHERE id=%s",
                                (_val, _id_eq)
                            )
                        except Exception as _e_col:
                            # Columna no existe (BD vieja) → ignorar silencioso
                            print(f"[maquina_add] columna {_col} no existe: {_e_col}", flush=True)
                            break
        except Exception as _e_xt:
            print(f"[maquina_add] update campos extra falló: {_e_xt}", flush=True)
        # Log unificado
        for c in creadas:
            _mant_log("maquina", c["id"], "agregada", d.get("nombre",""))
        # Respuesta compatible con clientes existentes (1 fila → mismo shape antiguo)
        if len(creadas) == 1:
            return jsonify({"ok": True, "id": creadas[0]["id"], "serie": creadas[0]["serie"],
                            "sku": sku, "filas_creadas": 1})
        return jsonify({"ok": True, "filas_creadas": len(creadas), "items": creadas, "sku": sku})
    finally:
        conn.close()


@app.route("/mantenciones/api/maquinas/<int:mid>", methods=["DELETE"])
@_mant_required
def mant_maquina_del(mid):
    """SOFT-DELETE de máquina (cambio 2026-05-15).

    ANTES: hacía DELETE permanente → causó pérdida irreversible de datos
    en producción ("se borraron las máquinas y no se pueden recuperar").

    AHORA: marca estado='baja' (soft-delete). La máquina sale del listado
    activo pero sus datos, fotos, contratos asociados y registros de OT
    quedan intactos en la BD. Se puede restaurar con:
      POST /mantenciones/api/maquinas/<id>/restaurar

    Para HARD DELETE (destrucción real) solo superadmin vía endpoint
    dedicado /api/maquinas/<id>/destruir (requiere confirm_text).

    REFUERZO 2026-05-22 (Daniel): la ficha del cliente se trata como
    información confidencial. Eliminar un equipo (aun soft) sale del
    permiso de ejecutivo/admin y queda restringido a `superadmin`. Se
    exige un motivo ≥ 12 chars + confirm_text 'ELIMINAR' que registramos
    en `mant_logs` para auditoría completa.
    """
    # Restricción dura: solo superadmin puede eliminar equipos (regla
    # confidencialidad ficha cliente). Aarón / ejecutivo / técnico → 403.
    if not (g.permissions or {}).get("superadmin"):
        return jsonify({
            "ok": False,
            "error": "Acción restringida al superadministrador. "
                     "Razón: ficha confidencial.",
            "error_codigo": "REQUIERE_SUPERADMIN",
        }), 403

    m_info = mysql_fetchone(
        "SELECT cliente_id, nombre, sku, serie, estado FROM mant_maquinas WHERE id=%s", (mid,)
    )
    if not m_info:
        return jsonify({"ok": False, "error": "Máquina no encontrada"}), 404

    # Si ya está dada de baja, no hay nada que hacer (idempotente)
    if (m_info.get("estado") or "").lower() == "baja":
        return jsonify({"ok": True, "ya_de_baja": True})

    # Motivo + confirm_text obligatorios (auditoría confidencial)
    body = request.get_json(silent=True) or {}
    motivo = (body.get("motivo") or "").strip()
    confirm_text = (body.get("confirm_text") or "").strip().upper()
    if len(motivo) < 12:
        return jsonify({
            "ok": False,
            "error": "El motivo debe tener al menos 12 caracteres "
                     "(queda en auditoría para trazabilidad).",
            "error_codigo": "MOTIVO_INSUFICIENTE",
        }), 400
    if confirm_text != "ELIMINAR":
        return jsonify({
            "ok": False,
            "error": "Debes escribir exactamente 'ELIMINAR' para confirmar.",
            "error_codigo": "CONFIRM_TEXT_INVALIDO",
        }), 400

    user = current_username()
    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            # Soft-delete: cambiar estado a 'baja' + auditar
            cur.execute(
                "UPDATE mant_maquinas SET estado='baja', updated_by=%s WHERE id=%s",
                (user, mid)
            )
        conn.commit()
        detalle = (
            f"{m_info.get('nombre') or ''} "
            f"(SKU {m_info.get('sku') or '—'} · Serie {m_info.get('serie') or '—'}) "
            f"· estado: {m_info.get('estado')} → baja · por {user} "
            f"· motivo: {motivo[:300]}"
        )
        # Acción canónica para auditoría: maquina_eliminada_soft / equipo_eliminado_soft
        _mant_log("maquina", mid, "maquina_eliminada_soft", detalle)
        _mant_log("cliente", m_info.get("cliente_id"),
                  "equipo_eliminado_soft", detalle)
        # Mantengo el log legacy "dada_de_baja" por compatibilidad con
        # dashboards o queries que ya filtran por ese nombre.
        _mant_log("maquina", mid, "dada_de_baja", detalle)
        return jsonify({
            "ok": True,
            "soft_delete": True,
            "mensaje": "Equipo eliminado · auditoría registrada.",
        })
    finally:
        conn.close()


@app.route("/mantenciones/api/maquinas/<int:mid>/restaurar", methods=["POST"])
@_mant_required
def mant_maquina_restaurar(mid):
    """Restaura una máquina dada de baja (estado='baja' → 'activo').

    Restaurar NO es destructivo: lo permitimos a admin + superadmin
    (no a ejecutivo/técnico). Si en el futuro Daniel pide abrirlo a
    ejecutivo, basta con borrar el guard de rol.
    """
    _role = (g.user["role"] if g.user else "") or ""
    _is_super = bool((g.permissions or {}).get("superadmin"))
    if not (_is_super or _role == "admin"):
        return jsonify({
            "ok": False,
            "error": "Restaurar equipos está reservado a administradores.",
            "error_codigo": "REQUIERE_ADMIN",
        }), 403

    m_info = mysql_fetchone(
        "SELECT cliente_id, nombre, estado FROM mant_maquinas WHERE id=%s", (mid,)
    )
    if not m_info:
        return jsonify({"ok": False, "error": "Máquina no encontrada"}), 404
    if (m_info.get("estado") or "").lower() != "baja":
        return jsonify({"ok": True, "ya_activa": True})

    user = current_username()
    mysql_execute(
        "UPDATE mant_maquinas SET estado='activo', updated_by=%s WHERE id=%s",
        (user, mid)
    )
    _mant_log("maquina", mid, "restaurada", f"Restaurada por {user}")
    _mant_log("cliente", m_info.get("cliente_id"), "equipo_restaurado",
              f"{m_info.get('nombre') or ''} restaurado por {user}")
    return jsonify({"ok": True})


@app.route("/mantenciones/api/clientes/<int:cid>/maquinas-baja", methods=["GET"])
@_mant_required
def mant_maquinas_baja_listar(cid):
    """Lista las máquinas dadas de baja de un cliente (papelera de equipos)."""
    rows = mysql_fetchall(
        "SELECT id, nombre, sku, serie, doc_origen, doc_fecha, notas, "
        "       estado, updated_by, created_at "
        "  FROM mant_maquinas "
        " WHERE cliente_id=%s AND estado='baja' "
        " ORDER BY id DESC LIMIT 200",
        (cid,)
    ) or []
    out = []
    for r in rows:
        out.append({
            "id": r["id"],
            "nombre": r.get("nombre") or "",
            "sku": r.get("sku") or "",
            "serie": r.get("serie") or "",
            "doc_origen": r.get("doc_origen") or "",
            "doc_fecha": str(r["doc_fecha"]) if r.get("doc_fecha") else "",
            "notas": r.get("notas") or "",
            "dada_baja_por": r.get("updated_by") or "",
            "created_at": str(r["created_at"])[:16] if r.get("created_at") else "",
        })
    return jsonify({"ok": True, "maquinas_baja": out, "total": len(out)})


@app.route("/mantenciones/api/clientes/<int:cid>/equipos/baja-masiva", methods=["POST"])
@_mant_required
def mant_equipos_baja_masiva(cid):
    """Soft-delete masivo: marca como 'baja' todos los equipos activos de un cliente.
    Solo superadmin. Requiere confirm_text='BAJA TOTAL' en el body JSON.
    Registra audit-log ANTES de ejecutar el UPDATE (regla #5)."""
    if not (g.permissions or {}).get("superadmin"):
        return jsonify({"ok": False, "error": "Acción reservada para superadmin"}), 403

    body = request.get_json(silent=True) or {}
    if (body.get("confirm_text") or "").strip().upper() != "BAJA TOTAL":
        return jsonify({"ok": False, "error": "Confirmación incorrecta"}), 400

    # Verificar que el cliente existe
    cli = mysql_fetchone("SELECT id, razon_social FROM mant_clientes WHERE id=%s", (cid,))
    if not cli:
        return jsonify({"ok": False, "error": "Cliente no encontrado"}), 404

    # Contar equipos activos antes de actuar
    row = mysql_fetchone(
        "SELECT COUNT(*) AS n FROM mant_maquinas WHERE cliente_id=%s AND estado='activo'",
        (cid,)
    )
    n_activos = int(row["n"]) if row else 0

    if n_activos == 0:
        return jsonify({"ok": True, "n": 0, "msg": "No había equipos activos que dar de baja"})

    # ── AUDIT LOG antes del cambio (regla #5) ──────────────────────────────
    _mant_log(
        "cliente", cid,
        "baja_masiva_equipos",
        f"Baja masiva de {n_activos} equipo(s) activo(s) del cliente "
        f"'{cli.get('razon_social', cid)}' — superadmin"
    )

    # ── Soft-delete ────────────────────────────────────────────────────────
    # FIX 2026-05-26: sin updated_by (columna puede no existir en bd vieja).
    # La trazabilidad ya quedó en mant_logs via _mant_log más arriba.
    mysql_execute(
        "UPDATE mant_maquinas SET estado='baja' "
        " WHERE cliente_id=%s AND estado='activo'",
        (cid,)
    )

    return jsonify({"ok": True, "n": n_activos})


@app.route("/mantenciones/api/clientes/<int:cid>/equipos/baja-seleccion", methods=["POST"])
@_mant_required
def mant_equipos_baja_seleccion(cid):
    """Soft-delete SELECTIVO: marca como 'baja' una lista específica de
    equipos (no todos los del cliente). Solo superadmin.

    Body JSON: { "ids": [12, 34, 56] }

    Diferencia con baja-masiva (que baja TODOS los activos del cliente):
    este recibe una lista explícita de IDs seleccionados por checkbox en
    la UI. Permite al admin elegir granularmente qué equipos retirar
    (ej: 3 trotadoras viejas pero NO las nuevas).
    """
    if not (g.permissions or {}).get("superadmin"):
        return jsonify({"ok": False, "error": "Acción reservada para superadmin"}), 403

    body = request.get_json(silent=True) or {}
    try:
        ids = body.get("ids") or []
        # Validar y sanitizar IDs (solo enteros positivos)
        try:
            ids = [int(x) for x in ids if x and int(x) > 0]
        except (TypeError, ValueError):
            return jsonify({"ok": False, "error": "Lista de IDs inválida"}), 400
        if not ids:
            return jsonify({"ok": False, "error": "No se seleccionaron equipos"}), 400
        if len(ids) > 500:
            return jsonify({"ok": False, "error": "Máximo 500 equipos por operación"}), 400

        # OPTIMIZACION 2026-05-26: una sola query UPDATE con WHERE compuesto
        # (cliente_id + id IN + estado='activo'). El cliente_id en el WHERE
        # garantiza seguridad (no se pueden bajar equipos de otro cliente).
        # No hace SELECT previo: lo que MySQL no encuentre, simplemente no
        # se actualiza. Más rápido y atómico.
        #
        # FIX 2026-05-26: quitamos `updated_by` del UPDATE porque la columna
        # no siempre existe en BDs viejas (error 1054). La trazabilidad
        # queda en mant_logs vía _mant_log (audit_async más abajo).
        placeholders = ",".join(["%s"] * len(ids))
        params = tuple([cid] + ids)

        # Ejecutamos UPDATE y capturamos rowcount para saber cuántos se afectaron
        conn = get_mysql()
        n_a_bajar = 0
        try:
            with conn.cursor() as cur:
                cur.execute(
                    f"UPDATE mant_maquinas SET estado='baja' "
                    f" WHERE cliente_id=%s AND id IN ({placeholders}) "
                    f"   AND COALESCE(estado,'activo') <> 'baja'",
                    params
                )
                n_a_bajar = int(cur.rowcount or 0)
            conn.commit()
        finally:
            try: conn.close()
            except Exception: pass

        # Audit log en background (no bloqueante — evita que el frontend
        # vea "error de red" cuando solo era latencia del log).
        try:
            import threading as _th
            def _audit_async():
                try:
                    _mant_log(
                        "cliente", cid,
                        "baja_seleccion_equipos",
                        f"Baja selectiva de {n_a_bajar} de {len(ids)} equipo(s) "
                        f"seleccionados — superadmin {current_username()}"
                    )
                except Exception as _e_al:
                    print(f"[baja_seleccion audit] {_e_al}", flush=True)
            _th.Thread(target=_audit_async, daemon=True).start()
        except Exception:
            pass

        return jsonify({"ok": True, "n": n_a_bajar})

    except Exception as e:
        # Cualquier error inesperado → siempre devolvemos JSON (nunca crash silencioso)
        print(f"[baja_seleccion] EXCEPCION cid={cid} ids_count={len(body.get('ids',[]))} err={e}",
              flush=True)
        return jsonify({
            "ok": False,
            "error": f"Error al procesar la baja: {str(e)[:150]}",
        }), 500


@app.route("/mantenciones/api/maquinas/<int:mid>/destruir", methods=["DELETE"])
@_mant_required
def mant_maquina_destruir(mid):
    """HARD DELETE real de la máquina. Solo superadmin + confirm_text.
    Borra la máquina y sus fotos/eventos en cascada. Acción irreversible.

    REFUERZO 2026-05-22 (Daniel): además del confirm_text 'DESTRUIR' y
    el motivo (≥ 12 chars), registramos en `mant_logs` con la acción
    canónica 'maquina_eliminada_hard' + el detalle del equipo destruido.
    """
    # Guard: solo superadmin
    if not (g.permissions or {}).get("superadmin"):
        return jsonify({
            "ok": False,
            "error": "Acción restringida al superadministrador. "
                     "Razón: ficha confidencial.",
            "error_codigo": "REQUIERE_SUPERADMIN",
        }), 403

    m_info = mysql_fetchone(
        "SELECT cliente_id, nombre, sku, serie FROM mant_maquinas WHERE id=%s", (mid,)
    )
    if not m_info:
        return jsonify({"ok": False, "error": "Máquina no encontrada"}), 404

    body = request.get_json(silent=True) or {}
    confirm_text = (body.get("confirm_text") or "").strip().upper()
    motivo = (body.get("motivo") or "").strip()
    nombre_esperado = (m_info.get("nombre") or "").strip()

    if confirm_text != "DESTRUIR":
        return jsonify({
            "ok": False,
            "error": "Debes escribir exactamente 'DESTRUIR' para confirmar.",
            "error_codigo": "CONFIRM_TEXT_INVALIDO",
        }), 400
    if len(motivo) < 12:
        return jsonify({
            "ok": False,
            "error": "El motivo debe tener al menos 12 caracteres "
                     "(queda en auditoría para trazabilidad).",
            "error_codigo": "MOTIVO_INSUFICIENTE",
        }), 400

    user = current_username()
    detalle = (
        f"DESTRUIDA: {nombre_esperado} (SKU {m_info.get('sku') or '—'} · "
        f"Serie {m_info.get('serie') or '—'}) · por {user} "
        f"· motivo: {motivo[:300]}"
    )
    # Log ANTES de borrar (sino se pierde la referencia). Acción canónica
    # `maquina_eliminada_hard` + log legacy `destruida_permanente` por
    # compatibilidad.
    _mant_log("maquina", mid, "maquina_eliminada_hard", detalle)
    _mant_log("cliente", m_info.get("cliente_id"),
              "equipo_eliminado_hard", detalle)
    _mant_log("maquina", mid, "destruida_permanente", detalle)
    mysql_execute("DELETE FROM mant_maquinas WHERE id=%s", (mid,))
    return jsonify({"ok": True, "destruida": True})


@app.route("/mantenciones/api/maquinas/<int:mid>/serie", methods=["PUT"])
@_mant_required
def mant_maquina_actualizar_serie(mid):
    """
    Actualiza el N° serie de un equipo con auditoría completa.
    Cada cambio queda registrado en mant_maquina_audit:
      - valor anterior, valor nuevo, motivo, usuario, fecha

    Body JSON:
      serie:  str (nuevo valor — vacío vuelve a auto-generar)
      motivo: str (mín 5 chars, justificación del cambio)
    """
    d = request.get_json(silent=True) or {}
    serie_nueva_raw = (d.get("serie") or "").strip()[:120]
    motivo = (d.get("motivo") or "").strip()[:500]
    if len(motivo) < 5:
        return jsonify({"error": "El motivo debe tener al menos 5 caracteres"}), 400

    # Cargar equipo actual
    maq = mysql_fetchone(
        "SELECT id, cliente_id, sku, serie FROM mant_maquinas WHERE id=%s", (mid,)
    )
    if not maq:
        return jsonify({"error": "Equipo no encontrado"}), 404

    serie_anterior = maq.get("serie") or ""

    # Si quedó vacío → regenerar auto
    if not serie_nueva_raw:
        serie_nueva = _generar_serie_ilus(maq["cliente_id"], maq.get("sku", ""))
    else:
        serie_nueva = serie_nueva_raw

    if serie_nueva == serie_anterior:
        return jsonify({"ok": True, "sin_cambios": True, "serie": serie_nueva})

    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            # Actualizar el equipo
            cur.execute("UPDATE mant_maquinas SET serie=%s WHERE id=%s",
                        (serie_nueva, mid))
            # Registrar en auditoría dedicada
            cur.execute(
                """INSERT INTO mant_maquina_audit
                   (maquina_id, cliente_id, campo, valor_antes, valor_nuevo, motivo, usuario)
                   VALUES (%s,%s,'serie',%s,%s,%s,%s)""",
                (mid, maq["cliente_id"], serie_anterior, serie_nueva, motivo, current_username())
            )
        conn.commit()
        # También al log general para que aparezca en historial de la ficha
        _mant_log("maquina", mid, "serie_cambiada",
                  f"'{serie_anterior}' → '{serie_nueva}'. Motivo: {motivo}")
        return jsonify({
            "ok": True,
            "serie": serie_nueva,
            "serie_anterior": serie_anterior,
            "usuario": current_username(),
        })
    finally:
        conn.close()


@app.route("/mantenciones/api/maquinas/<int:mid>/audit", methods=["GET"])
@_mant_required
def mant_maquina_audit_list(mid):
    """Devuelve el historial de cambios sensibles de un equipo (serie, etc)."""
    rows = mysql_fetchall(
        "SELECT * FROM mant_maquina_audit WHERE maquina_id=%s ORDER BY fecha DESC LIMIT 50",
        (mid,)
    )
    # Convertir a hora Chile
    try:
        from zoneinfo import ZoneInfo
        tz_scl = ZoneInfo("America/Santiago")
        tz_utc = ZoneInfo("UTC")
        out = []
        for r in (rows or []):
            r = dict(r)
            f = r.get("fecha")
            if isinstance(f, datetime):
                if f.tzinfo is None: f = f.replace(tzinfo=tz_utc)
                r["fecha"] = f.astimezone(tz_scl).strftime("%d/%m/%Y %H:%M")
            out.append(r)
        return jsonify({"ok": True, "audit": out})
    except Exception:
        return jsonify({"ok": True, "audit": [dict(r) for r in (rows or [])]})


@app.route("/mantenciones/api/clientes/<int:cid>/visita-multi", methods=["POST"])
@_mant_required
def mant_visita_multi(cid):
    """
    Crea UNA sola visita asociada a N equipos del cliente.
    Caso de uso real: "el lunes voy a Vitacura a cambiar 4 trotadoras + revisar 2 bicis"
    → 1 visita técnica con 6 equipos involucrados, en lugar de 6 visitas separadas.

    Body JSON:
      maquina_ids: list[int]      — equipos a incluir
      tipo_visita: str             — garantia|correctiva|preventiva|inspeccion
      fecha_programada: 'YYYY-MM-DD'
      motivo: str (mín 8 chars)
      estado_nuevo: 'critico'|'en_mantencion'|'operativo'  (se aplica a todos)
      tecnico: str (opcional, nombre libre — DEPRECADO; usar tecnico_id)
      tecnico_id: int (opcional, FK a mant_tecnicos)
      titulo: str (opcional, generado si no viene)
      hora_inicio: 'HH:MM' (opcional)
      hora_fin: 'HH:MM' (opcional)
      costo: float (opcional, CLP)
      observaciones: str (opcional, hasta 1000 chars)
    """
    d = request.get_json(silent=True) or {}
    mids = d.get("maquina_ids") or []
    if not isinstance(mids, list) or not mids:
        return jsonify({"error": "Debes seleccionar al menos un equipo"}), 400
    try:
        mids = [int(m) for m in mids]
    except (TypeError, ValueError):
        return jsonify({"error": "IDs de equipo inválidos"}), 400

    motivo = (d.get("motivo") or "").strip()
    if len(motivo) < 8:
        return jsonify({"error": "El motivo debe tener al menos 8 caracteres"}), 400

    tipo_visita = d.get("tipo_visita") or "preventiva"
    if tipo_visita not in ("garantia","correctiva","preventiva","inspeccion"):
        tipo_visita = "preventiva"

    # GARANTÍA TRANSVERSAL (Daniel 2026-05-30): interruptor Aplica/No aplica,
    # independiente del tipo de visita. Si no llega el flag explícito, hacemos
    # un fallback compatible: tipo_visita 'garantia' → aplica garantía.
    _gar_aplica_mv = _parse_garantia_aplica(d.get("garantia_aplica"))
    if _gar_aplica_mv is None and tipo_visita == "garantia":
        _gar_aplica_mv = True
    _cobertura_mv, _ = _mapear_garantia_a_cobertura(_gar_aplica_mv, tipo_visita)
    # Defaults seguros si no se especifica garantía: servicio pagado pendiente.
    mv_modalidad      = _cobertura_mv.get("modalidad_cobro", "pagado")
    mv_cubierto_por   = _cobertura_mv.get("cubierto_por", "cliente")
    mv_estado_factur  = _cobertura_mv.get("estado_facturacion", "sin_cotizar")

    estado_nuevo = d.get("estado_nuevo") or "operativo"
    if estado_nuevo not in ("critico","en_mantencion","operativo"):
        estado_nuevo = "operativo"
    # Fecha por defecto: +48 horas. Solo el superadmin puede modificarla en frontend,
    # pero validamos también en backend que el campo no quede vacío.
    fecha_prog = d.get("fecha_programada") or (datetime.today().date() + timedelta(days=2)).isoformat()
    # Multi-técnico: aceptamos lista de IDs (1..10). Compatibilidad con tecnico_id único.
    tecnico_ids_raw = d.get("tecnico_ids") or []
    if not isinstance(tecnico_ids_raw, list):
        tecnico_ids_raw = []
    if not tecnico_ids_raw and d.get("tecnico_id"):
        tecnico_ids_raw = [d.get("tecnico_id")]
    tecnico_ids = []
    for x in tecnico_ids_raw:
        try:
            xi = int(x)
            if xi > 0:
                tecnico_ids.append(xi)
        except (TypeError, ValueError):
            pass
    tecnico_ids = list(dict.fromkeys(tecnico_ids))[:10]  # dedupe + máx 10

    # Resolver nombres y tarifas desde la tabla. El campo `tecnico` (texto libre)
    # se conserva por compatibilidad con visitas viejas — se usa nombre concatenado.
    tecnicos_data = []
    if tecnico_ids:
        placeholders_t = ",".join(["%s"] * len(tecnico_ids))
        rows_t = mysql_fetchall(
            f"SELECT id,nombre,tarifa_visita FROM mant_tecnicos WHERE id IN ({placeholders_t}) AND activo=1",
            tuple(tecnico_ids)
        ) or []
        tecnicos_data = [dict(r) for r in rows_t]
    tecnico_id     = tecnicos_data[0]["id"]     if tecnicos_data else None
    tecnico_nombre = (
        ", ".join(t["nombre"] for t in tecnicos_data)
        if tecnicos_data
        else ((d.get("tecnico") or "").strip()[:200] or None)
    )

    titulo_input = (d.get("titulo") or "").strip()[:200]

    # Hora inicio / fin — autocompleta ceros: '8' -> '08:00', '12' -> '12:00'
    hora_inicio = _normalize_hora(d.get("hora_inicio"))
    hora_fin    = _normalize_hora(d.get("hora_fin"))

    # Costo (CLP). Si el usuario no lo indica → cálculo automático:
    # tarifa_visita × cantidad de técnicos asignados (default $50.000 por técnico).
    costo = d.get("costo")
    try:
        costo = float(costo) if costo not in (None, "", 0, "0") else None
        if costo is not None and costo < 0:
            costo = None
    except (TypeError, ValueError):
        costo = None
    if costo is None and tecnicos_data:
        costo_auto = 0.0
        for t in tecnicos_data:
            tarifa = float(t.get("tarifa_visita") or 50000)
            costo_auto += tarifa
        costo = costo_auto if costo_auto > 0 else None

    observaciones = (d.get("observaciones") or "").strip()[:1000] or None

    # Repuestos asociados (lista de objetos con sku/descripcion/cantidad/costo_unitario/origen)
    repuestos_raw = d.get("repuestos") or []
    if not isinstance(repuestos_raw, list):
        repuestos_raw = []
    repuestos = []
    repuestos_total = 0.0
    for rp in repuestos_raw[:50]:  # max 50 por visita
        try:
            desc = (rp.get("descripcion") or "").strip()[:300]
            if not desc:
                continue
            cant = float(rp.get("cantidad") or 1) or 1.0
            cunit = float(rp.get("costo_unitario") or 0) or 0.0
            ctot = round(cant * cunit, 2)
            repuestos.append({
                "sku":            (rp.get("sku") or "").strip()[:80] or None,
                "producto_id":    int(rp["producto_id"]) if rp.get("producto_id") else None,
                "descripcion":    desc,
                "cantidad":       cant,
                "costo_unitario": cunit,
                "costo_total":    ctot,
                "origen":         rp.get("origen") if rp.get("origen") in ("manual","erp","catalogo") else "manual",
                "notas":          (rp.get("notas") or "").strip()[:500] or None,
            })
            repuestos_total += ctot
        except (TypeError, ValueError):
            continue
    # Si vinieron repuestos y el costo no fue indicado manualmente,
    # se SUMA al costo total de la visita
    if repuestos_total > 0 and costo is not None:
        costo += repuestos_total
    elif repuestos_total > 0 and costo is None:
        costo = repuestos_total

    # Generar número de OT correlativo
    numero_ot = _next_ot_number()

    # Cargar todos los equipos seleccionados (verificar que pertenecen al cliente)
    placeholders = ",".join(["%s"] * len(mids))
    rows = mysql_fetchall(
        f"SELECT id,nombre,sku,serie,cantidad,doc_origen FROM mant_maquinas "
        f"WHERE id IN ({placeholders}) AND cliente_id=%s",
        tuple(mids) + (cid,)
    )
    if not rows or len(rows) != len(mids):
        return jsonify({"error": "Algunos equipos no pertenecen a este cliente"}), 400

    # Construir título y descripción
    tipos_label = {
        "garantia":   "Cambio / Garantía",
        "correctiva": "Reparación correctiva",
        "preventiva": "Mantención preventiva",
        "inspeccion": "Inspección / Levantamiento",
    }
    titulo = titulo_input or f"{tipos_label[tipo_visita]} — {len(rows)} equipo(s)"

    detalle_equipos = "\n".join(
        f"  • {r['nombre']} (SKU {r.get('sku') or '—'}, Serie {r.get('serie') or '—'})"
        for r in rows
    )
    descripcion = (
        f"VISITA MULTI-EQUIPO — {tipos_label[tipo_visita]}\n"
        f"Equipos involucrados ({len(rows)}):\n{detalle_equipos}\n\n"
        f"Motivo:\n{motivo}\n"
    )

    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            # 1. Crear la visita única (con número de OT correlativo)
            # 2026-05-22 (Aaron Urbina): incluir created_by_user_id (FK).
            _u_mv = getattr(g, "user", None) or {}
            _cre_uid_mv = _u_mv.get("id")
            try:
                _cre_uid_mv = int(_cre_uid_mv) if _cre_uid_mv else None
            except (TypeError, ValueError):
                _cre_uid_mv = None
            try:
                cur.execute(
                    """INSERT INTO mant_visitas
                       (numero_ot,cliente_id,titulo,fecha_programada,hora_inicio,hora_fin,
                        tipo,estado,descripcion,observaciones,tecnico,tecnico_id,
                        costo,modalidad_cobro,cubierto_por,estado_facturacion,
                        created_by,created_by_user_id)
                       VALUES (%s,%s,%s,%s,%s,%s,%s,'programada',%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)""",
                    (numero_ot, cid, titulo, fecha_prog, hora_inicio, hora_fin,
                     tipo_visita, descripcion, observaciones, tecnico_nombre, tecnico_id,
                     costo, mv_modalidad, mv_cubierto_por, mv_estado_factur,
                     current_username(), _cre_uid_mv)
                )
            except Exception as _e_ins_mv:
                print(f"[visita-multi] INSERT con created_by_user_id falló ({_e_ins_mv}); reintentando legacy", flush=True)
                # Fallback (DB antigua sin created_by_user_id → tampoco tiene
                # cubierto_por/estado_facturacion, agregadas después). Set mínimo.
                cur.execute(
                    """INSERT INTO mant_visitas
                       (numero_ot,cliente_id,titulo,fecha_programada,hora_inicio,hora_fin,
                        tipo,estado,descripcion,observaciones,tecnico,tecnico_id,
                        costo,created_by)
                       VALUES (%s,%s,%s,%s,%s,%s,%s,'programada',%s,%s,%s,%s,%s,%s)""",
                    (numero_ot, cid, titulo, fecha_prog, hora_inicio, hora_fin,
                     tipo_visita, descripcion, observaciones, tecnico_nombre, tecnico_id,
                     costo, current_username())
                )
            vid = cur.lastrowid

            # 1.b Insertar técnicos asignados (N:N) si hay
            if tecnicos_data:
                for t in tecnicos_data:
                    cur.execute(
                        """INSERT INTO mant_visita_tecnicos (visita_id, tecnico_id, costo)
                           VALUES (%s, %s, %s)""",
                        (vid, t["id"], float(t.get("tarifa_visita") or 50000))
                    )

            # 1.c Insertar repuestos asociados a la visita
            for rp in repuestos:
                cur.execute(
                    """INSERT INTO mant_visita_repuestos
                       (visita_id, sku, producto_id, descripcion, cantidad,
                        costo_unitario, costo_total, origen, notas)
                       VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s)""",
                    (vid, rp["sku"], rp["producto_id"], rp["descripcion"],
                     rp["cantidad"], rp["costo_unitario"], rp["costo_total"],
                     rp["origen"], rp["notas"])
                )

            # 2. Cambiar estado de los equipos
            cur.execute(
                f"UPDATE mant_maquinas SET estado_op=%s WHERE id IN ({placeholders})",
                (estado_nuevo,) + tuple(mids)
            )
            # 3. Loguear en cada equipo (auditoría)
            for r in rows:
                cur.execute(
                    "INSERT INTO mant_logs (entidad,entidad_id,accion,detalle,usuario) "
                    "VALUES ('maquina',%s,'visita_multi',%s,%s)",
                    (r["id"],
                     f"Visita {vid} ({tipo_visita}) — fecha {fecha_prog}. {motivo[:120]}",
                     current_username())
                )
        conn.commit()
        _mant_log("cliente", cid, "visita_multi_creada",
                  f"Visita {vid}: {len(rows)} equipos, tipo {tipo_visita}, fecha {fecha_prog}")
        return jsonify({
            "ok": True,
            "visita_id": vid,
            "numero_ot": numero_ot,
            "equipos_afectados": len(rows),
            "tecnicos_asignados": len(tecnicos_data),
            "repuestos_count": len(repuestos),
            "repuestos_total": repuestos_total,
            "costo_calculado": costo,
            "fecha_programada": fecha_prog,
            "cliente_id": cid,
        })
    except Exception as e:
        try:
            conn.rollback()
        except Exception:
            pass
        return jsonify({"error": f"Error al crear la visita: {str(e)}"}), 500
    finally:
        conn.close()


