@app.route("/mantenciones/api/clientes/<int:cid>/sucursales", methods=["POST"])
@_mant_required
def mant_sucursal_add(cid):
    d = request.get_json(silent=True) or {}
    nombre = (d.get("nombre") or "").strip()[:200]
    if not nombre:
        return jsonify({"error": "El nombre de la sucursal es obligatorio"}), 400
    es_principal = 1 if d.get("es_principal") else 0
    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            # Si esta nueva va a ser principal, desmarcar las anteriores
            if es_principal:
                cur.execute(
                    "UPDATE mant_sucursales SET es_principal=0 WHERE cliente_id=%s AND es_principal=1",
                    (cid,)
                )
            cur.execute(
                """INSERT INTO mant_sucursales
                   (cliente_id,nombre,direccion,comuna,ciudad,region,
                    encargado_nombre,encargado_cargo,encargado_tel,encargado_email,
                    contacto2_nombre,contacto2_cargo,contacto2_tel,contacto2_email,
                    notas,es_principal,created_by)
                   VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)""",
                (cid, nombre,
                 (d.get("direccion") or "").strip()[:300] or None,
                 (d.get("comuna") or "").strip()[:100] or None,
                 (d.get("ciudad") or "").strip()[:100] or None,
                 (d.get("region") or "").strip()[:100] or None,
                 (d.get("encargado_nombre") or "").strip()[:200] or None,
                 (d.get("encargado_cargo") or "").strip()[:120] or None,
                 (d.get("encargado_tel") or "").strip()[:50] or None,
                 (d.get("encargado_email") or "").strip()[:200] or None,
                 (d.get("contacto2_nombre") or "").strip()[:200] or None,
                 (d.get("contacto2_cargo") or "").strip()[:120] or None,
                 (d.get("contacto2_tel") or "").strip()[:50] or None,
                 (d.get("contacto2_email") or "").strip()[:200] or None,
                 (d.get("notas") or "").strip() or None,
                 es_principal,
                 current_username())
            )
            sid = cur.lastrowid
        conn.commit()
        _mant_log("cliente", cid, "sucursal_agregada", nombre + (" (principal)" if es_principal else ""))
        return jsonify({"ok": True, "id": sid, "es_principal": bool(es_principal)})
    finally:
        conn.close()


@app.route("/mantenciones/api/sucursales/<int:sid>", methods=["PUT"])
@_mant_required
def mant_sucursal_update(sid):
    d = request.get_json(silent=True) or {}
    fields = ["nombre","direccion","comuna","ciudad","region",
              "encargado_nombre","encargado_cargo","encargado_tel","encargado_email",
              "contacto2_nombre","contacto2_cargo","contacto2_tel","contacto2_email",
              "notas"]
    sets, vals = [], []
    for f in fields:
        if f in d:
            v = (d[f] or "").strip() if isinstance(d[f], str) else d[f]
            sets.append(f"{f}=%s")
            vals.append(v if v else None)
    # Manejo de es_principal con lógica única (solo una principal por cliente)
    es_principal = d.get("es_principal")
    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            if es_principal is not None:
                ep = 1 if es_principal else 0
                if ep:
                    # Obtener el cliente_id de esta sucursal
                    row = mysql_fetchone("SELECT cliente_id FROM mant_sucursales WHERE id=%s", (sid,))
                    if row:
                        cur.execute(
                            "UPDATE mant_sucursales SET es_principal=0 WHERE cliente_id=%s AND id<>%s",
                            (row["cliente_id"], sid)
                        )
                sets.append("es_principal=%s")
                vals.append(ep)
            if not sets:
                return jsonify({"error": "Sin cambios"}), 400
            cur.execute(f"UPDATE mant_sucursales SET {','.join(sets)} WHERE id=%s",
                        vals + [sid])
        conn.commit()
        # Log con cliente_id y nombre de la sucursal
        suc_info = mysql_fetchone("SELECT cliente_id, nombre FROM mant_sucursales WHERE id=%s", (sid,))
        if suc_info:
            campos_mod = ", ".join([f.split("=")[0] for f in sets[:6]])
            _mant_log("cliente", suc_info["cliente_id"], "sucursal_actualizada",
                      f"{suc_info.get('nombre') or 'sucursal'} — campos: {campos_mod}")
        return jsonify({"ok": True})
    finally:
        conn.close()


@app.route("/mantenciones/api/sucursales/<int:sid>/marcar-principal", methods=["POST"])
@_mant_required
def mant_sucursal_marcar_principal(sid):
    """Marca una sucursal como principal (desmarca cualquier otra del mismo cliente)."""
    row = mysql_fetchone(
        "SELECT cliente_id, nombre FROM mant_sucursales WHERE id=%s AND activo=1",
        (sid,)
    )
    if not row:
        return jsonify({"error": "Sucursal no encontrada"}), 404
    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            cur.execute(
                "UPDATE mant_sucursales SET es_principal=0 WHERE cliente_id=%s",
                (row["cliente_id"],)
            )
            cur.execute(
                "UPDATE mant_sucursales SET es_principal=1 WHERE id=%s",
                (sid,)
            )
        conn.commit()
        _mant_log("cliente", row["cliente_id"], "sucursal_principal_cambiada", row["nombre"])
        return jsonify({"ok": True})
    finally:
        conn.close()


@app.route("/mantenciones/api/sucursales/<int:sid>", methods=["DELETE"])
@_mant_required
def mant_sucursal_del(sid):
    """Soft delete: marca activo=0 para preservar histórico."""
    suc_info = mysql_fetchone("SELECT cliente_id, nombre FROM mant_sucursales WHERE id=%s", (sid,))
    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            cur.execute("UPDATE mant_sucursales SET activo=0 WHERE id=%s", (sid,))
        conn.commit()
        if suc_info:
            _mant_log("cliente", suc_info["cliente_id"], "sucursal_eliminada", suc_info.get("nombre") or f"sucursal #{sid}")
        return jsonify({"ok": True})
    finally:
        conn.close()


# ── CONTRATOS ─────────────────────────────────────────────────────────

MANT_UPLOADS = os.path.join(UPLOADS_BASE, "mantenciones")
os.makedirs(MANT_UPLOADS, exist_ok=True)

# DECISIÓN 2026-05-14: estandarizamos a PDF para que el viewer sea
# universal (Chrome/Firefox/Edge renderan PDF inline sin viewers de
# terceros como Office Online). Los DOCX se rechazaban con mensaje claro
# y se le pedía al usuario que los exportara a PDF antes de subir.
# Esto evita el flujo "viewer no encuentra archivo" porque Cloudinary
# devuelve URL directa al PDF que el navegador renderiza inline.
ALLOWED_CONTRATO = {"pdf"}
ALLOWED_CONTRATO_LEGACY = {"pdf", "doc", "docx"}  # solo lectura — uploads existentes
# Tamaño máximo del archivo (Cloudinary free permite 100MB, mantenemos 25MB).
MAX_CONTRATO_BYTES = 25 * 1024 * 1024  # 25 MB


# ════════════════════════════════════════════════════════════════════════
# VALIDADOR + REPARADOR DE PDFs (2026-05-26 — Daniel: "que persista hasta
# que esté bien y si es posible repararlo seria genial")
#
# Cuando el usuario sube un contrato, validamos INMEDIATAMENTE:
#   1. Magic bytes — el archivo realmente empieza con %PDF-
#   2. Estructura — pdfplumber puede abrirlo y leer al menos 1 página
#   3. Si pdfplumber falla, intentamos REPARAR con pypdf (re-escribir el
#      stream desde cero — recupera muchos PDFs con cross-reference dañado,
#      objetos huérfanos, EOL incorrecto, etc.)
#   4. Si tampoco se puede reparar, retornamos error claro.
#
# Devuelve dict con:
#   ok:        bool
#   problema:  str (mensaje accionable para el usuario) o None
#   reparado:  bool (True si tuvimos que reescribir el PDF)
#   stream:    BytesIO con el contenido válido (original o reparado),
#              listo para subir a Cloudinary. None si falló.
#   n_pages:   int (cantidad de páginas detectadas)
# ════════════════════════════════════════════════════════════════════════
def _validar_y_reparar_pdf(file_obj, filename: str = "") -> dict:
    """Valida un PDF y trata de repararlo si está dañado."""
    import io

    try:
        file_obj.seek(0)
    except Exception:
        pass

    # 1. Magic bytes — primer chequeo barato
    try:
        head = file_obj.read(5)
        file_obj.seek(0)
    except Exception as e:
        return {
            "ok": False,
            "problema": ("No se pudo leer el archivo subido. "
                         "Inténtalo de nuevo o usa otro archivo."),
            "reparado": False, "stream": None, "n_pages": 0,
        }

    if head != b'%PDF-':
        return {
            "ok": False,
            "problema": ("El archivo tiene extensión .pdf pero su contenido "
                         "NO es un PDF real. Exporta el documento como PDF "
                         "desde el programa original (Word: Archivo → "
                         "Exportar → Crear PDF/XPS)."),
            "reparado": False, "stream": None, "n_pages": 0,
        }

    # 2. Leer todo el contenido en memoria
    try:
        content = file_obj.read()
        file_obj.seek(0)
    except Exception:
        return {
            "ok": False,
            "problema": "No se pudo leer el archivo. Inténtalo de nuevo.",
            "reparado": False, "stream": None, "n_pages": 0,
        }

    if len(content) < 512:
        return {
            "ok": False,
            "problema": ("El archivo PDF está incompleto (menos de 512 bytes). "
                         "Vuelve a subirlo — probablemente se cortó la subida."),
            "reparado": False, "stream": None, "n_pages": 0,
        }

    # 3. Intentar abrir con pdfplumber (el visor real del navegador hace algo
    #    similar; si pdfplumber lo abre, casi seguro el browser también).
    try:
        import pdfplumber
        with pdfplumber.open(io.BytesIO(content)) as pdf:
            n_pages = len(pdf.pages)
            if n_pages == 0:
                raise ValueError("PDF sin páginas")
            # Tocar la primera página para detectar corrupción profunda
            _ = pdf.pages[0]
        # OK — devolvemos el stream original
        return {
            "ok": True,
            "problema": None,
            "reparado": False,
            "stream": io.BytesIO(content),
            "n_pages": n_pages,
        }
    except Exception as e_open:
        problema_inicial = str(e_open)[:140]
        # 4. PDF dañado — intentar reparar con pypdf
        try:
            from pypdf import PdfReader, PdfWriter
            reader = PdfReader(io.BytesIO(content), strict=False)
            if len(reader.pages) == 0:
                raise ValueError("PDF sin páginas al reparar")
            writer = PdfWriter()
            for page in reader.pages:
                writer.add_page(page)
            output = io.BytesIO()
            writer.write(output)
            output.seek(0)

            # Verificar que el reparado es legible por pdfplumber
            content_rep = output.getvalue()
            with pdfplumber.open(io.BytesIO(content_rep)) as pdf_rep:
                n_rep = len(pdf_rep.pages)
                if n_rep == 0:
                    raise ValueError("Reparado quedó sin páginas")
                _ = pdf_rep.pages[0]

            print(f"[validar_pdf] {filename!r} REPARADO "
                  f"({len(content)} → {len(content_rep)} bytes, "
                  f"{n_rep} págs)", flush=True)
            return {
                "ok": True,
                "problema": None,
                "reparado": True,
                "stream": io.BytesIO(content_rep),
                "n_pages": n_rep,
            }
        except Exception as e_rep:
            print(f"[validar_pdf] {filename!r} no reparable: "
                  f"open_err={problema_inicial!r}; rep_err={str(e_rep)[:140]!r}",
                  flush=True)
            return {
                "ok": False,
                "problema": ("El PDF está dañado y el sistema no lo pudo "
                             "reparar automáticamente. Vuelve a exportarlo "
                             "desde el programa original (Word, Excel, "
                             "navegador, etc.) y súbelo de nuevo."),
                "reparado": False,
                "stream": None,
                "n_pages": 0,
            }


@app.route("/mantenciones/api/contratos/<int:ctid>", methods=["DELETE"])
@_mant_required
def mant_contrato_delete(ctid):
    """Elimina un contrato — SOLO superadmin.

    Borra archivo físico + análisis IA + adjuntos asociados.
    Esta acción es irreversible. Requiere doble confirmación en body:
      {"confirm": "ELIMINAR"}
    """
    # Solo superadmin
    if not g.permissions.get("superadmin"):
        return jsonify({
            "ok": False,
            "error": "Solo el superadministrador puede eliminar contratos. "
                     "Esta acción borra el archivo, el análisis IA y los adjuntos.",
            "error_codigo": "REQUIERE_SUPERADMIN",
        }), 403

    d = request.get_json(silent=True) or {}
    if (d.get("confirm") or "").strip().upper() != "ELIMINAR":
        return jsonify({
            "ok": False,
            "error": "Confirmación incorrecta. Envía {\"confirm\":\"ELIMINAR\"}",
        }), 400

    contrato = mysql_fetchone(
        "SELECT id, cliente_id, nombre, archivo_path FROM mant_contratos WHERE id=%s",
        (ctid,)
    )
    if not contrato:
        return jsonify({"ok": False, "error": "Contrato no encontrado"}), 404

    contrato = dict(contrato)
    cid       = contrato.get("cliente_id")
    nombre    = contrato.get("nombre") or "(sin nombre)"
    arch_path = contrato.get("archivo_path")

    # Borrar archivo físico (best-effort)
    archivos_borrados = 0
    if arch_path:
        try:
            full_path = os.path.join(MANT_UPLOADS, arch_path)
            if os.path.exists(full_path):
                os.remove(full_path)
                archivos_borrados += 1
        except Exception:
            pass

    # Borrar adjuntos físicos del contrato (best-effort)
    try:
        adjuntos = mysql_fetchall(
            "SELECT archivo_path FROM mant_adjuntos WHERE contrato_id=%s", (ctid,)
        ) or []
        for a in adjuntos:
            try:
                ap = a.get("archivo_path")
                if ap:
                    fp = os.path.join(MANT_UPLOADS, ap)
                    if os.path.exists(fp):
                        os.remove(fp)
                        archivos_borrados += 1
            except Exception: pass
    except Exception: pass

    # Borrar BD — CASCADE arrastra adjuntos, IA history, visitas SET NULL
    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            cur.execute("DELETE FROM mant_contratos WHERE id=%s", (ctid,))
        conn.commit()
        try:
            _mant_log("contrato", ctid, "eliminado",
                      f"Contrato #{ctid} '{nombre}' borrado por {current_username()}. "
                      f"{archivos_borrados} archivo(s) físicos eliminados.")
        except Exception: pass
        return jsonify({
            "ok": True,
            "mensaje": f"Contrato #{ctid} eliminado.",
            "archivos_borrados": archivos_borrados,
            "cliente_id": cid,
        })
    except Exception as e:
        return jsonify({"ok": False, "error": f"Error al eliminar: {e}"}), 500
    finally:
        conn.close()


# Tope de contratos simultáneos por cliente. Permite tener distintos
# contratos (mantención principal + anexos + adendas) sin saturar la ficha.
# Si necesitas más para un cliente puntual, cambiá este número o eliminá
# contratos viejos del cliente desde la UI.
MANT_CONTRATOS_MAX_POR_CLIENTE = 5


@app.route("/mantenciones/api/clientes/<int:cid>/contratos", methods=["POST"])
@_mant_required
def mant_contrato_subir(cid):
    """Sube un contrato PDF al cliente.

    DECISIÓN 2026-05-14 — estandarización a PDF:
      * Solo se aceptan archivos .pdf. DOCX/DOC se rechazan con instrucción
        de exportar a PDF (Word > Archivo > Guardar como > PDF).
      * Razón: el viewer del navegador renderiza PDF inline sin depender
        de Office Online Viewer (que falla si Cloudinary requiere auth
        o si el archivo no es público). Estandarización + UX consistente.

    Persistencia:
      * Cloudinary OBLIGATORIO (resource_type='raw', folder ilus/contratos).
      * Si Cloudinary no está disponible, se rechaza el upload (no se
        guarda nada efímero). Antes había fallback a filesystem pero ese
        archivo desaparece en cada deploy de Railway → causa "Archivo
        no encontrado" al previsualizar. Mejor fallar limpio.

    Antiduplicados (anti triple-click):
      * Verifica si en los últimos 30s ya se subió un archivo con el
        mismo nombre original para este cliente. Si sí, retorna 409 sin
        crear el segundo.

    Límite: máximo MANT_CONTRATOS_MAX_POR_CLIENTE contratos (default 5).
    """
    f = request.files.get("archivo")
    d = request.form
    if not f or not f.filename:
        return jsonify({"error": "Sin archivo"}), 400

    # Validación PDF-only
    ext = f.filename.rsplit(".", 1)[-1].lower() if "." in f.filename else ""
    if ext != "pdf":
        if ext in ("doc", "docx"):
            return jsonify({
                "error": (
                    "Solo se aceptan archivos PDF. "
                    "Abre el documento en Word → Archivo → Guardar como → PDF, "
                    "y vuelve a subirlo. Esto permite que se visualice correctamente "
                    "en cualquier navegador sin viewers externos."
                ),
                "error_codigo": "FORMATO_NO_PERMITIDO",
                "formato_detectado": ext,
            }), 400
        return jsonify({
            "error": "Tipo no permitido. Solo PDF.",
            "error_codigo": "FORMATO_NO_PERMITIDO",
            "formato_detectado": ext or "desconocido",
        }), 400

    # Validar tamaño máximo
    try:
        f.stream.seek(0, 2)  # ir al final
        size_bytes = f.stream.tell()
        f.stream.seek(0)
        if size_bytes > MAX_CONTRATO_BYTES:
            return jsonify({
                "error": f"Archivo demasiado grande ({size_bytes/1024/1024:.1f}MB). "
                         f"Máximo permitido: {MAX_CONTRATO_BYTES/1024/1024:.0f}MB.",
                "error_codigo": "ARCHIVO_GRANDE",
            }), 400
    except Exception:
        size_bytes = 0  # no crítico, sigue

    # Validar Cloudinary disponible (estandarización: sin Cloudinary, no se sube)
    if not _CLD_READY:
        return jsonify({
            "error": (
                "El almacenamiento de archivos no está disponible en este momento. "
                "Por favor contacta al administrador (Cloudinary no configurado)."
            ),
            "error_codigo": "ALMACENAMIENTO_NO_DISPONIBLE",
        }), 503

    # ── VALIDAR + REPARAR el PDF antes de hacer cualquier otra cosa ─────
    # Si el archivo está dañado, devolvemos error claro AHORA. El usuario
    # vuelve a subir otro y persistimos hasta que esté bien.
    _val = _validar_y_reparar_pdf(f.stream, f.filename or "")
    if not _val["ok"]:
        return jsonify({
            "error": _val["problema"],
            "error_codigo": "PDF_INVALIDO",
        }), 400
    _upload_stream = _val["stream"]
    _fue_reparado  = _val["reparado"]
    _n_pages_pdf   = _val.get("n_pages", 0)

    # Anti-duplicados v2: hash MD5 del contenido VALIDADO (post-reparación).
    # Más robusto que nombre, porque detecta también re-envíos del browser
    # por timeout/retry HTTP. Ventana 5 min.
    import hashlib
    try:
        _upload_stream.seek(0)
        _content = _upload_stream.read()
        archivo_hash = hashlib.md5(_content).hexdigest()
        _upload_stream.seek(0)
    except Exception as e_hash:
        archivo_hash = None
        print(f"[mant_contrato_subir] no se pudo calcular hash: {e_hash}", flush=True)

    if archivo_hash:
        try:
            dup_check = mysql_fetchone(
                "SELECT id FROM mant_contratos "
                "WHERE cliente_id=%s AND archivo_hash=%s "
                "  AND created_at >= DATE_SUB(NOW(), INTERVAL 5 MINUTE) "
                "LIMIT 1",
                (cid, archivo_hash)
            )
            if dup_check:
                return jsonify({
                    "error": (
                        "Este mismo archivo (mismo contenido) ya se subió en los "
                        "últimos 5 minutos. Si quieres subir uno nuevo, asegúrate "
                        "de que sea un archivo distinto. Recarga la página para ver "
                        "el contrato existente."
                    ),
                    "error_codigo": "DUPLICADO_RAPIDO",
                    "contrato_existente_id": dup_check["id"],
                }), 409
        except Exception as e_dup:
            # Si la columna archivo_hash no existe aún (DB sin migrar),
            # cae al check por nombre como fallback.
            print(f"[mant_contrato_subir] check duplicado hash falló: {e_dup}", flush=True)

    # Fallback: anti-duplicado por nombre (compat con DBs sin archivo_hash)
    try:
        dup_check_name = mysql_fetchone(
            "SELECT id FROM mant_contratos "
            "WHERE cliente_id=%s AND archivo_nombre=%s "
            "  AND created_at >= DATE_SUB(NOW(), INTERVAL 30 SECOND) "
            "LIMIT 1",
            (cid, f.filename)
        )
        if dup_check_name:
            return jsonify({
                "error": (
                    "Este mismo archivo ya se subió hace menos de 30 segundos. "
                    "Si es un error del navegador, recarga la página."
                ),
                "error_codigo": "DUPLICADO_RAPIDO",
                "contrato_existente_id": dup_check_name["id"],
            }), 409
    except Exception as e_dup2:
        print(f"[mant_contrato_subir] check duplicado nombre falló: {e_dup2}", flush=True)

    # Validar tope de N contratos por cliente
    try:
        cnt_row = mysql_fetchone(
            "SELECT COUNT(*) AS n FROM mant_contratos WHERE cliente_id=%s",
            (cid,)
        )
        n_actual = int((cnt_row or {}).get("n", 0))
        if n_actual >= MANT_CONTRATOS_MAX_POR_CLIENTE:
            return jsonify({
                "error": (
                    f"Este cliente ya tiene {n_actual} contratos cargados — el máximo "
                    f"es {MANT_CONTRATOS_MAX_POR_CLIENTE}. Elimina uno antes de subir el siguiente, "
                    f"o usa la pestaña 'Documentos' para subir como 'Anexo' o 'Documento externo'."
                ),
                "error_codigo": "LIMITE_CONTRATOS",
                "limite": MANT_CONTRATOS_MAX_POR_CLIENTE,
                "actual": n_actual,
            }), 400
    except Exception as e_cnt:
        print(f"[mant_contrato_subir] no se pudo verificar tope ({e_cnt})", flush=True)

    fname = secure_filename(f"{cid}_{int(time.time())}_{f.filename}")

    # ── Subir a Cloudinary como 'raw' (PDFs/ZIPs/DOCs) ─────────────────
    # ANTES: probamos resource_type='image' pensando que serviría PDFs
    # inline directamente. Cloudinary BLOQUEA por defecto la entrega de
    # PDFs en image/upload por seguridad (política post-enero 2021):
    # devolvía HTTP 401 al cargar la URL en el iframe.
    #
    # AHORA: subimos como 'raw' (/raw/upload/), que NO tiene esa
    # restricción. El endpoint /api/contratos/<id>/archivo hace PROXY
    # del PDF y le agrega Content-Type: application/pdf + inline para
    # que el navegador lo renderice en el iframe. Funciona en TODOS los
    # casos: contratos viejos, nuevos y los que quedaron rotos en
    # /image/upload/ entre commits.
    cloud_url = None
    cloud_pid = None
    cloud_uploaded_at = None
    try:
        _upload_stream.seek(0)
        public_id = f"contrato_{cid}_{int(time.time())}"
        cloud_result = _cloud_upload_raw(_upload_stream, public_id, folder="ilus/contratos")
        cloud_url = cloud_result["url"]
        cloud_pid = cloud_result["public_id"]
        cloud_uploaded_at = datetime.utcnow()
        print(f"[mant_contrato] Cloudinary OK (raw/pdf) cid={cid} url={cloud_url}", flush=True)
    except Exception as e_cld:
        print(f"[mant_contrato] Cloudinary FAIL cid={cid}: {e_cld}", flush=True)
        return jsonify({
            "error": (
                "No se pudo subir el archivo al almacenamiento persistente. "
                "Inténtalo de nuevo en unos segundos. Si el problema persiste, "
                "contacta al administrador."
            ),
            "error_codigo": "CLOUDINARY_FAIL",
            "detalle": str(e_cld)[:200],
        }), 502

    # Backup local opcional (no bloqueante) — usa el stream validado/reparado
    try:
        _upload_stream.seek(0)
        fpath = os.path.join(MANT_UPLOADS, fname)
        with open(fpath, "wb") as _fh_loc:
            _fh_loc.write(_upload_stream.read())
    except Exception as e_save:
        print(f"[mant_contrato] backup filesystem falló (no crítico): {e_save}", flush=True)

    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            # Intentar INSERT con archivo_hash (columna nueva post-migración)
            try:
                cur.execute(
                    """INSERT INTO mant_contratos
                       (cliente_id,nombre,archivo_nombre,archivo_path,archivo_tipo,
                        archivo_hash,
                        cloudinary_url,cloudinary_public_id,cloudinary_uploaded_at,
                        fecha_inicio,fecha_vencimiento,es_indefinido,
                        monto_mensual,monto_anual,frecuencia_meses,notas,created_by)
                       VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)""",
                    (cid, d.get("nombre","Contrato"), f.filename, fname, "pdf",
                     archivo_hash,
                     cloud_url, cloud_pid, cloud_uploaded_at,
                     d.get("fecha_inicio") or None, d.get("fecha_vencimiento") or None,
                     1 if d.get("es_indefinido") else 0,
                     float(d.get("monto_mensual",0) or 0),
                     float(d.get("monto_anual",0) or 0),
                     int(d.get("frecuencia_meses",0) or 0),
                     d.get("notas",""), current_username())
                )
            except Exception as e_insert_hash:
                # Fallback: si la columna archivo_hash no existe en esta DB
                # (instalación antigua sin migrar), insertar sin ella.
                print(f"[mant_contrato_subir] INSERT con hash falló ({e_insert_hash}), fallback sin hash", flush=True)
                cur.execute(
                    """INSERT INTO mant_contratos
                       (cliente_id,nombre,archivo_nombre,archivo_path,archivo_tipo,
                        cloudinary_url,cloudinary_public_id,cloudinary_uploaded_at,
                        fecha_inicio,fecha_vencimiento,es_indefinido,
                        monto_mensual,monto_anual,frecuencia_meses,notas,created_by)
                       VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)""",
                    (cid, d.get("nombre","Contrato"), f.filename, fname, "pdf",
                     cloud_url, cloud_pid, cloud_uploaded_at,
                     d.get("fecha_inicio") or None, d.get("fecha_vencimiento") or None,
                     1 if d.get("es_indefinido") else 0,
                     float(d.get("monto_mensual",0) or 0),
                     float(d.get("monto_anual",0) or 0),
                     int(d.get("frecuencia_meses",0) or 0),
                     d.get("notas",""), current_username())
                )
            ctid = cur.lastrowid
        conn.commit()
        _detalle_log = f"{f.filename} (Cloudinary raw · {size_bytes/1024:.0f}KB"
        if _fue_reparado:
            _detalle_log += " · PDF reparado automáticamente"
        _detalle_log += ")"
        _mant_log("contrato", ctid, "subido", _detalle_log)
        return jsonify({
            "ok": True, "id": ctid,
            "persistente": True,
            "storage": "cloudinary",
            "url": cloud_url,
            "size_kb": int(size_bytes / 1024) if size_bytes else 0,
            "reparado": _fue_reparado,
            "n_pages": _n_pages_pdf,
        })
    finally:
        conn.close()


@app.route("/mantenciones/api/contratos/<int:ctid>/check-archivo")
@_mant_required
def mant_contrato_check_archivo(ctid):
    """Verifica disponibilidad del archivo del contrato.

    FIX 2026-05-22 — Filesystem efímero de Railway:
      Antes solo verificaba existencia en disco. Ahora devuelve flags
      por canal de almacenamiento para que el frontend pueda mostrar
      el aviso correcto (re-subir, link a Cloudinary, etc.).

    Respuesta:
      {
        "existe":          true|false,            # ¿hay algo servible?
        "tiene_cloudinary":true|false,            # URL persistente registrada
        "tiene_disco":     true|false,            # copia local presente
        "estado": "ok" | "solo_cloudinary"
                | "solo_disco_efimero" | "perdido" | "sin_archivo",
        "sugerencia":      "texto operativo",
        "archivo_nombre":  "...",
        "razon":           legacy-string para compat con UI vieja
      }
    """
    ct = mysql_fetchone(
        "SELECT archivo_path, archivo_nombre, cloudinary_url "
        "  FROM mant_contratos WHERE id=%s",
        (ctid,)
    )
    if not ct:
        return jsonify({
            "existe": False, "tiene_cloudinary": False, "tiene_disco": False,
            "estado": "sin_archivo", "sugerencia": "",
            "error": "Contrato no encontrado",
        }), 404

    tiene_cloud = bool(ct.get("cloudinary_url"))
    archivo_path = ct.get("archivo_path") or ""
    tiene_disco = False
    if archivo_path:
        try:
            tiene_disco = os.path.exists(os.path.join(MANT_UPLOADS, archivo_path))
        except Exception:
            tiene_disco = False

    # Determinar estado y sugerencia para el usuario
    if tiene_cloud and tiene_disco:
        estado = "ok"
        sugerencia = "Archivo disponible (Cloudinary + disco)."
    elif tiene_cloud and not tiene_disco:
        estado = "solo_cloudinary"
        sugerencia = "Archivo disponible en Cloudinary (persistente)."
    elif (not tiene_cloud) and tiene_disco:
        estado = "solo_disco_efimero"
        sugerencia = ("El archivo está SOLO en disco (efímero). Re-súbelo para que "
                      "quede en Cloudinary y no se pierda en el próximo deploy.")
    elif (not tiene_cloud) and (not tiene_disco) and archivo_path:
        estado = "perdido"
        sugerencia = ("El archivo se perdió tras un deploy. Re-súbelo desde la ficha "
                      "para recuperarlo (Cloudinary lo guardará persistente).")
    else:
        estado = "sin_archivo"
        sugerencia = "Este contrato nunca tuvo archivo. Sube uno desde la ficha."

    # Compat con UI vieja que usaba razon=ok|borrado_filesystem_efimero|no_subido
    razon_legacy = {
        "ok": "ok",
        "solo_cloudinary": "ok",
        "solo_disco_efimero": "ok",
        "perdido": "borrado_filesystem_efimero",
        "sin_archivo": "no_subido",
    }[estado]

    return jsonify({
        "existe":          (tiene_cloud or tiene_disco),
        "tiene_cloudinary": tiene_cloud,
        "tiene_disco":      tiene_disco,
        "estado":           estado,
        "sugerencia":       sugerencia,
        "archivo_nombre":   ct.get("archivo_nombre") or "",
        "razon":            razon_legacy,
    })


@app.route("/mantenciones/api/contratos/<int:ctid>/re-subir", methods=["POST"])
@_mant_required
def mant_contrato_re_subir(ctid):
    """Re-sube el archivo físico de un contrato existente.

    Usado cuando el filesystem efímero de Railway borra el PDF tras un deploy.
    Solo superadmin (operación delicada — reemplaza el archivo).
    Conserva: nombre, fechas, montos, análisis IA. SOLO reemplaza el archivo.
    """
    if not g.permissions.get("superadmin"):
        return jsonify({
            "ok": False,
            "error": "Solo el superadministrador puede re-subir archivos de contrato.",
            "error_codigo": "REQUIERE_SUPERADMIN",
        }), 403

    ct = mysql_fetchone(
        "SELECT id, cliente_id, archivo_path, archivo_nombre, nombre, "
        "       cloudinary_public_id "
        "  FROM mant_contratos WHERE id=%s", (ctid,)
    )
    if not ct:
        return jsonify({"ok": False, "error": "Contrato no encontrado"}), 404

    f = request.files.get("archivo")
    if not f or not f.filename:
        return jsonify({"ok": False, "error": "Sin archivo adjunto"}), 400
    ext = f.filename.rsplit(".", 1)[-1].lower() if "." in f.filename else ""
    # Estandarización 2026-05-14: solo PDF. DOCX se rechaza con instrucción clara.
    if ext != "pdf":
        if ext in ("doc", "docx"):
            return jsonify({
                "ok": False,
                "error": ("Solo se aceptan archivos PDF. "
                          "Exporta el documento desde Word a PDF antes de subirlo."),
                "error_codigo": "FORMATO_NO_PERMITIDO",
            }), 400
        return jsonify({
            "ok": False,
            "error": f"Tipo '{ext or 'desconocido'}' no permitido. Solo PDF.",
            "error_codigo": "FORMATO_NO_PERMITIDO",
        }), 400

    # ── VALIDAR + REPARAR el PDF antes de tocar Cloudinary ──────────────
    # Si el archivo está dañado, fallamos LIMPIO sin destruir lo que ya había.
    # El usuario verá el problema y volverá a subir otro.
    _val = _validar_y_reparar_pdf(f.stream, f.filename or "")
    if not _val["ok"]:
        return jsonify({
            "ok": False,
            "error": _val["problema"],
            "error_codigo": "PDF_INVALIDO",
        }), 400

    # Stream a usar de aquí en adelante (puede ser el original o el reparado)
    _upload_stream = _val["stream"]
    _fue_reparado = _val["reparado"]
    _n_pages_pdf  = _val.get("n_pages", 0)

    # Borrar el archivo viejo si existe (cleanup local) — recién ahora que
    # sabemos que el nuevo es válido.
    if ct.get("archivo_path"):
        try:
            old_path = os.path.join(MANT_UPLOADS, ct["archivo_path"])
            if os.path.exists(old_path):
                os.remove(old_path)
        except Exception:
            pass
    # Borrar el archivo viejo de Cloudinary si tenía
    if ct.get("cloudinary_public_id"):
        try:
            _cloud_delete_raw(ct["cloudinary_public_id"])
        except Exception as e_del:
            print(f"[re-subir] no se pudo borrar cloud viejo: {e_del}", flush=True)

    fname = secure_filename(f"{ct['cliente_id']}_{int(time.time())}_{f.filename}")

    # ── 1. Cloudinary OBLIGATORIO (PERSISTENTE — sobrevive deploys) ──
    # FIX 2026-05-22: si Cloudinary no se puede usar, FALLAMOS LIMPIO.
    # Antes guardábamos en filesystem como "fallback" pero ese archivo
    # se pierde en el próximo deploy → re-subir era inútil. Mejor fallar
    # con mensaje claro que el admin pueda accionar.
    if not _CLD_READY:
        return jsonify({
            "ok": False,
            "error": ("El almacenamiento persistente no está disponible. "
                      "Cloudinary no está configurado — contacta al administrador."),
            "error_codigo": "ALMACENAMIENTO_NO_DISPONIBLE",
        }), 503

    cloud_url = None
    cloud_pid = None
    cloud_uploaded_at = None
    try:
        _upload_stream.seek(0)
        public_id = f"contrato_{ct['cliente_id']}_{int(time.time())}"
        cloud_result = _cloud_upload_raw(_upload_stream, public_id, folder="ilus/contratos")
        cloud_url = cloud_result["url"]
        cloud_pid = cloud_result["public_id"]
        cloud_uploaded_at = datetime.utcnow()
        print(f"[re-subir] Cloudinary OK ctid={ctid} url={cloud_url}", flush=True)
    except Exception as e_cld:
        print(f"[re-subir] Cloudinary FAIL ctid={ctid}: {e_cld}", flush=True)
        return jsonify({
            "ok": False,
            "error": ("No se pudo subir el archivo a Cloudinary. "
                      "Inténtalo de nuevo en unos segundos."),
            "error_codigo": "CLOUDINARY_FAIL",
            "detalle": str(e_cld)[:200],
        }), 502

    # ── 2. Backup local (no bloqueante) ──
    fpath = os.path.join(MANT_UPLOADS, fname)
    saved_local = False
    try:
        _upload_stream.seek(0)
        with open(fpath, "wb") as _fh_local:
            _fh_local.write(_upload_stream.read())
        saved_local = True
    except Exception as e_save:
        # Cloudinary ya está OK — el archivo está seguro. Backup local fall
        # solo afecta diagnóstico/analizar IA. No es bloqueante.
        print(f"[re-subir] filesystem save fail (Cloudinary OK): {e_save}", flush=True)

    tipo_archivo = "pdf" if ext == "pdf" else ("word" if ext in ("doc","docx") else "otro")
    try:
        mysql_execute(
            "UPDATE mant_contratos SET archivo_path=%s, archivo_nombre=%s, archivo_tipo=%s, "
            "       cloudinary_url=%s, cloudinary_public_id=%s, cloudinary_uploaded_at=%s "
            " WHERE id=%s",
            (fname if saved_local else None, f.filename, tipo_archivo,
             cloud_url, cloud_pid, cloud_uploaded_at, ctid)
        )
        try:
            _mant_log("contrato", ctid, "archivo_resubido",
                      f"Re-subido por {current_username()}: {f.filename} "
                      f"({'Cloudinary' if cloud_url else 'filesystem'})")
        except Exception: pass
        _msg = "Archivo re-subido correctamente."
        if _fue_reparado:
            _msg += (" El PDF estaba dañado y el sistema lo reparó "
                     "automáticamente antes de guardarlo.")
        return jsonify({
            "ok": True,
            "mensaje": _msg,
            "archivo_nombre": f.filename,
            "persistente": bool(cloud_url),
            "storage": "cloudinary" if cloud_url else "filesystem",
            "reparado": _fue_reparado,
            "n_pages": _n_pages_pdf,
        })
    except Exception as e:
        return jsonify({"ok": False, "error": f"Error al actualizar BD: {e}"}), 500


# ════════════════════════════════════════════════════════════════════════
# BACKFILL CLOUDINARY 2026-05-22
# Recorre todos los contratos con cloudinary_url IS NULL, busca el archivo
# en disco (si todavía está) y lo sube a Cloudinary. Idempotente: si un
# contrato ya tiene cloudinary_url, se salta.
#
# Útil para recuperar contratos que se subieron antes del fix Cloudinary
# y todavía tienen el archivo en disco (Railway aún no ha redeployado).
# ════════════════════════════════════════════════════════════════════════
@app.route("/mantenciones/api/contratos/backfill-cloudinary", methods=["POST"])
@_mant_required
def mant_contrato_backfill_cloudinary():
    """Sube a Cloudinary los contratos cuyo archivo está en disco pero
    cloudinary_url IS NULL. Solo admin/superadmin.

    Body opcional:
      { "dry_run": true }  → reporta sin subir nada
      { "limit":   N    }  → procesa solo N (default 200, max 500)

    Respuesta:
      {
        "ok": true,
        "total_candidatos": int,    # con cloudinary_url NULL
        "procesados": int,
        "subidos_ok": int,
        "ids_subidos": [int...],
        "perdidos": [{id, archivo_path}],   # archivo no en disco tampoco
        "errores":  [{id, error}],
        "dry_run": bool
      }
    """
    if not (g.permissions.get("admin") or g.permissions.get("superadmin")):
        return jsonify({"ok": False, "error": "Solo admin/superadmin."}), 403

    if not _CLD_READY:
        return jsonify({
            "ok": False,
            "error": "Cloudinary no configurado — no se puede hacer backfill.",
        }), 503

    d = request.get_json(silent=True) or {}
    dry_run = bool(d.get("dry_run", False))
    try:
        limit = int(d.get("limit", 200))
    except Exception:
        limit = 200
    limit = max(1, min(500, limit))

    # Candidatos: cloudinary_url vacía pero archivo_path declarado
    candidatos = mysql_fetchall(
        "SELECT id, cliente_id, archivo_path, archivo_nombre "
        "  FROM mant_contratos "
        " WHERE (cloudinary_url IS NULL OR cloudinary_url='') "
        "   AND archivo_path IS NOT NULL AND archivo_path != '' "
        " ORDER BY id ASC LIMIT %s",
        (limit,)
    )

    ids_subidos = []
    perdidos = []
    errores = []
    procesados = 0

    for ct in candidatos:
        procesados += 1
        ctid = ct["id"]
        archivo_path = ct["archivo_path"]
        full = os.path.join(MANT_UPLOADS, archivo_path)
        if not os.path.exists(full):
            perdidos.append({"id": ctid, "archivo_path": archivo_path})
            continue

        if dry_run:
            ids_subidos.append(ctid)  # potencial — se subiría
            continue

        try:
            with open(full, "rb") as fh:
                public_id = f"contrato_{ct['cliente_id']}_{int(time.time())}_bf"
                res = _cloud_upload_raw(fh, public_id, folder="ilus/contratos")
            mysql_execute(
                "UPDATE mant_contratos "
                "   SET cloudinary_url=%s, cloudinary_public_id=%s, "
                "       cloudinary_uploaded_at=%s "
                " WHERE id=%s AND (cloudinary_url IS NULL OR cloudinary_url='')",
                (res["url"], res["public_id"], datetime.utcnow(), ctid)
            )
            ids_subidos.append(ctid)
            try:
                _mant_log("contrato", ctid, "backfill_cloudinary",
                          f"Subido a Cloudinary por {current_username()}")
            except Exception:
                pass
            print(f"[backfill] ctid={ctid} → Cloudinary OK", flush=True)
        except Exception as e:
            errores.append({"id": ctid, "error": str(e)[:200]})
            print(f"[backfill] ctid={ctid} → ERROR {e}", flush=True)

    return jsonify({
        "ok": True,
        "total_candidatos": len(candidatos),
        "procesados":       procesados,
        "subidos_ok":       len(ids_subidos),
        "ids_subidos":      ids_subidos,
        "perdidos":         perdidos,
        "errores":          errores,
        "dry_run":          dry_run,
    })


@app.route("/mantenciones/api/contratos/<int:ctid>", methods=["PUT"])
@_mant_required
def mant_contrato_update(ctid):
    d = request.get_json(silent=True) or {}
    allowed = ["nombre","fecha_inicio","fecha_vencimiento","es_indefinido",
               "monto_mensual","monto_anual","frecuencia_meses","notas","estado"]
    sets = [f"{f}=%s" for f in allowed if f in d]
    vals = [d[f] for f in allowed if f in d]
    if not sets:
        return jsonify({"error": "Sin campos"}), 400
    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            cur.execute(f"UPDATE mant_contratos SET {','.join(sets)} WHERE id=%s",
                        vals + [ctid])
        conn.commit()
        # Log con campos modificados
        ct_info = mysql_fetchone("SELECT cliente_id, nombre FROM mant_contratos WHERE id=%s", (ctid,))
        campos_mod = ", ".join([f for f in allowed if f in d][:6])
        _mant_log("contrato", ctid, "actualizado", f"campos: {campos_mod}")
        if ct_info:
            _mant_log("cliente", ct_info["cliente_id"], "contrato_actualizado",
                      f"{ct_info.get('nombre') or ''} — {campos_mod}")
        return jsonify({"ok": True})
    finally:
        conn.close()


@app.route("/mantenciones/api/contratos/<int:ctid>/archivo")
@_mant_required
def mant_contrato_archivo(ctid):
    """Sirve el archivo del contrato.

    REFACTOR 2026-05-22 — Estrategia "Cloudinary-first":
      Antes el servidor PROXEABA el PDF de Cloudinary (descargaba el binario
      desde Cloudinary y se lo re-servía al cliente). Eso causaba 3 problemas
      en producción:
        - Si Cloudinary respondía con timeout o status != 200, el iframe
          quedaba en "Archivo no encontrado" y el usuario no podía hacer nada.
        - Doble ancho de banda en Railway (egress duplicado).
        - El stream se rompía con conexiones móviles intermitentes.
      Ahora REDIRECT 302 a Cloudinary y dejamos que el browser pida el PDF
      directo. Solo proxeamos como fallback de último recurso.

    Comportamiento por canal:
      1) Cloudinary URL existe → 302 a Cloudinary (con fl_inline/fl_attachment).
      2) Solo disco + archivo presente → sirve el binario Y dispara upload
         best-effort a Cloudinary para próxima visita (fire-and-forget).
      3) Ningún canal sirve → 404 amigable con instrucción de re-subir.

    Comportamiento por rol:
      - Usuario con permiso mantenciones → ve inline.
      - Superadmin → puede descargar con ?download=1.
    """
    from flask import send_from_directory, make_response, redirect as _redir
    ct = mysql_fetchone(
        "SELECT id, cliente_id, archivo_path, archivo_nombre, archivo_tipo, "
        "       cloudinary_url, cloudinary_public_id "
        "  FROM mant_contratos WHERE id=%s",
        (ctid,)
    )
    if not ct:
        return "Contrato no encontrado", 404

    # ── FALLBACK 2026-05-22 (Daniel — caso Vitacura/JDA) ──────────────
    # Contratos SEED del 21/05 vienen con archivo_path=NULL y cloudinary_url=NULL
    # PORQUE el archivo real está en mant_contrato_adjuntos (Cloudinary OK).
    # Si el contrato principal no tiene archivo propio, buscamos el primer
    # adjunto válido de tipo 'contrato' o 'anexo' con Cloudinary URL y lo
    # redirigimos directamente. Esto destraba todos los contratos huérfanos
    # sin tener que re-subir manualmente.
    if not (ct.get("archivo_path") or ct.get("cloudinary_url")):
        adj_fallback = mysql_fetchone(
            "SELECT cloudinary_url, archivo_nombre, mime_type "
            "  FROM mant_contrato_adjuntos "
            " WHERE contrato_id=%s "
            "   AND cloudinary_url IS NOT NULL AND cloudinary_url <> '' "
            "   AND tipo IN ('contrato','anexo','externo','otro') "
            " ORDER BY CASE tipo "
            "          WHEN 'contrato' THEN 1 WHEN 'anexo' THEN 2 "
            "          WHEN 'externo'  THEN 3 ELSE 4 END, id ASC "
            " LIMIT 1",
            (ctid,)
        )
        if adj_fallback and adj_fallback.get("cloudinary_url"):
            print(f"[mant_contrato_archivo] ctid={ctid} → FALLBACK adjunto "
                  f"({adj_fallback.get('archivo_nombre')})", flush=True)
            # Promovemos el adjunto al contrato principal para que el próximo
            # acceso sea directo (mejor performance + UI consistente).
            try:
                mysql_execute(
                    "UPDATE mant_contratos "
                    "   SET cloudinary_url=%s, archivo_nombre=%s "
                    " WHERE id=%s AND (cloudinary_url IS NULL OR cloudinary_url='')",
                    (adj_fallback["cloudinary_url"],
                     adj_fallback.get("archivo_nombre") or f"contrato_{ctid}.pdf",
                     ctid)
                )
            except Exception:
                pass
            # Cargar el ct con el dato fresco para que la lógica siguiente lo use
            ct["cloudinary_url"] = adj_fallback["cloudinary_url"]
            ct["archivo_nombre"] = adj_fallback.get("archivo_nombre") or ct.get("archivo_nombre")
        else:
            print(f"[mant_contrato_archivo] ctid={ctid} → SIN canales (ni disco ni cloud ni adjuntos)", flush=True)
            return "Archivo no encontrado", 404

    as_dl = request.args.get("download") == "1"
    use_office_viewer = request.args.get("viewer") == "office"
    # Descargar: SOLO superadmin (bloqueo server-side, no solo UI)
    if as_dl and not g.permissions.get("superadmin"):
        return ("Acceso restringido — solo el Superadministrador puede "
                "descargar archivos de contratos. Puedes visualizarlo en "
                "el navegador."), 403

    # Detectar extensión real (de cloudinary o filesystem)
    nombre = ct.get("archivo_nombre") or f"contrato_{ctid}.pdf"
    ext = nombre.rsplit(".", 1)[-1].lower() if "." in nombre else (
        (ct.get("archivo_path") or "").rsplit(".", 1)[-1].lower()
    )
    es_office = ext in ("doc", "docx", "xls", "xlsx", "ppt", "pptx")

    # ── PRIORIDAD 1a: Office Online Viewer (sólo DOCX/XLSX/PPT en Cloudinary)
    # El navegador NO renderiza DOCX nativamente. Office Online Viewer es un
    # servicio GRATIS de Microsoft que sí lo hace — requiere URL pública HTTPS
    # (Cloudinary cumple). Convierte al vuelo, sin que tengamos LibreOffice.
    if use_office_viewer and ct.get("cloudinary_url") and es_office:
        from urllib.parse import quote as _q
        viewer_url = (
            "https://view.officeapps.live.com/op/embed.aspx?src="
            + _q(ct["cloudinary_url"], safe="")
        )
        print(f"[mant_contrato_archivo] ctid={ctid} → Office Viewer redirect", flush=True)
        return _redir(viewer_url, code=302)

    # ── PRIORIDAD 1: Cloudinary (persistente entre deploys) ────────────
    # REFACTOR 2026-05-26 (Daniel — iframe en blanco):
    #   Antes hacíamos 302 a Cloudinary con fl_inline=true. PROBLEMA: cuando
    #   el recurso está como `raw` en Cloudinary (caso de PDFs subidos vía
    #   upload_raw), Cloudinary devuelve `Content-Disposition: attachment;
    #   filename="..."` ignorando fl_inline (esa flag solo aplica a recursos
    #   `image` y `auto`). Resultado: el browser ve el header attachment,
    #   descarga el PDF (aparece en la barra de descargas) y deja el iframe
    #   COMPLETAMENTE EN BLANCO. Exactamente el bug que Daniel reportó.
    #
    #   Solución: PROXEAR el binario reescribiendo los headers. Forzamos
    #   `Content-Disposition: inline` y `Content-Type: application/pdf` desde
    #   nuestro propio servidor — el browser obedece y renderiza en iframe.
    #
    #   Para DOWNLOADS sí seguimos redirigiendo (más eficiente, el CDN sirve
    #   directo, y como queremos descarga el header attachment es correcto).
    if ct.get("cloudinary_url"):
        cld_url = ct["cloudinary_url"]
        sep = "&" if "?" in cld_url else "?"

        if as_dl:
            # Download: redirect directo al CDN (header attachment es lo deseado)
            target = f"{cld_url}{sep}fl_attachment=true"
            print(f"[mant_contrato_archivo] ctid={ctid} → REDIRECT download "
                  f"(ext={ext})", flush=True)
            return _redir(target, code=302)

        # Preview inline: PROXY con headers reescritos
        try:
            import requests as _rq
            # Range header passthrough para que el browser pueda hacer
            # requests parciales de PDFs grandes (PDF.js los necesita).
            upstream_headers = {}
            if request.headers.get("Range"):
                upstream_headers["Range"] = request.headers["Range"]

            r_up = _rq.get(cld_url, headers=upstream_headers,
                           stream=True, timeout=30,
                           allow_redirects=True)

            if r_up.status_code not in (200, 206):
                print(f"[mant_contrato_archivo] ctid={ctid} Cloudinary "
                      f"status={r_up.status_code}, intentando fallback "
                      f"disco", flush=True)
                # No retornamos aquí — caemos al fallback de disco abajo
                r_up.close()
                raise RuntimeError(f"Cloudinary HTTP {r_up.status_code}")

            # Inferir Content-Type desde la extensión del nombre original
            # (Cloudinary a veces devuelve application/octet-stream).
            mime_inline = {
                "pdf":  "application/pdf",
                "jpg":  "image/jpeg",
                "jpeg": "image/jpeg",
                "png":  "image/png",
                "gif":  "image/gif",
                "webp": "image/webp",
                "doc":  "application/msword",
                "docx": "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
                "xls":  "application/vnd.ms-excel",
                "xlsx": "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
                "ppt":  "application/vnd.ms-powerpoint",
                "pptx": "application/vnd.openxmlformats-officedocument.presentationml.presentation",
            }
            ctype = mime_inline.get(ext) or r_up.headers.get("Content-Type") or "application/octet-stream"

            def _stream():
                try:
                    for chunk in r_up.iter_content(chunk_size=64 * 1024):
                        if chunk:
                            yield chunk
                finally:
                    r_up.close()

            from flask import Response as _Resp
            resp = _Resp(_stream(), status=r_up.status_code)
            resp.headers["Content-Type"] = ctype
            resp.headers["Content-Disposition"] = f'inline; filename="{nombre}"'
            # Passthrough de Content-Length y Accept-Ranges si vienen
            if r_up.headers.get("Content-Length"):
                resp.headers["Content-Length"] = r_up.headers["Content-Length"]
            if r_up.headers.get("Content-Range"):
                resp.headers["Content-Range"] = r_up.headers["Content-Range"]
            resp.headers["Accept-Ranges"] = r_up.headers.get("Accept-Ranges", "bytes")
            resp.headers["X-Frame-Options"] = "SAMEORIGIN"
            resp.headers["Content-Security-Policy"] = "frame-ancestors 'self'"
            # CACHE AGRESIVO 2026-05-26 (Daniel — saas de primera, velocidad):
            # Los PDFs de contratos son inmutables (Cloudinary genera public_id
            # único por subida). Cachear 24h en browser hace que segundas vistas
            # del mismo contrato sean instantáneas (0 ms egress de Railway).
            # ETag basado en public_id permite revalidación condicional.
            resp.headers["Cache-Control"] = "private, max-age=86400, immutable"
            _etag = ct.get("cloudinary_public_id") or f"ct-{ctid}"
            resp.headers["ETag"] = f'"{_etag}"'
            # Si el browser ya tiene esta versión, devuelve 304 (sin body)
            if request.headers.get("If-None-Match") == f'"{_etag}"':
                r_up.close()
                from flask import Response as _Resp2
                _resp304 = _Resp2(status=304)
                _resp304.headers["ETag"] = f'"{_etag}"'
                _resp304.headers["Cache-Control"] = "private, max-age=86400, immutable"
                print(f"[mant_contrato_archivo] ctid={ctid} → 304 (etag hit)",
                      flush=True)
                return _resp304
            print(f"[mant_contrato_archivo] ctid={ctid} → PROXY Cloudinary "
                  f"OK (ext={ext}, ctype={ctype}, status={r_up.status_code})",
                  flush=True)
            return resp
        except Exception as _e_proxy:
            print(f"[mant_contrato_archivo] ctid={ctid} → PROXY FALLO "
                  f"({_e_proxy}), intentando disco", flush=True)
            # Si el proxy falla, intentamos disco (sigue abajo). Si tampoco
            # hay disco, caerá al 404 amigable.

    # ── PRIORIDAD 2: Filesystem local (sin Cloudinary o tras fallo del proxy) ──
    # Si no tenemos archivo_path (solo había cloudinary y el proxy falló),
    # no hay nada que servir desde disco — caemos directo al 404 amigable.
    if not ct.get("archivo_path"):
        es_super = bool(g.permissions.get("superadmin"))
        nombre_visible = ct.get("archivo_nombre") or f"contrato_{ctid}"
        print(f"[mant_contrato_archivo] ctid={ctid} → SIN DISCO "
              f"(proxy Cloudinary falló y no hay archivo_path)", flush=True)
        return (
            f"Contrato no disponible — el CDN no respondió y no hay copia local. "
            f"{'Re-súbelo desde la ficha.' if es_super else 'Avisa al superadministrador.'}",
            503
        )

    # Verificar que el archivo existe en disco
    full_path = os.path.join(MANT_UPLOADS, ct["archivo_path"])
    if not os.path.exists(full_path):
        # IMPORTANTE: Railway usa filesystem efímero. Si hubo un deploy
        # desde la última subida, los archivos físicos se pierden (aunque
        # la BD aún tenga el archivo_path). El usuario debe re-subir.
        es_super = bool(g.permissions.get("superadmin"))
        nombre_visible = ct.get("archivo_nombre") or ct["archivo_path"]
        print(f"[mant_contrato_archivo] ctid={ctid} → PERDIDO "
              f"(disco={ct['archivo_path']} no existe, sin Cloudinary)", flush=True)
        accion = ("<p class='mb-2'><strong>Acción recomendada:</strong> "
                  "vuelve a la ficha del cliente y usa el botón "
                  "<strong>'Re-subir contrato'</strong>.</p>") if es_super else (
                 "<p class='mb-2'>Avisa al superadministrador para que "
                 "vuelva a subir el contrato.</p>")
        html = f"""
        <!doctype html><html><head><meta charset='utf-8'>
        <title>Contrato no disponible</title>
        <link rel='stylesheet' href='https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/css/bootstrap.min.css'>
        <link rel='stylesheet' href='https://cdn.jsdelivr.net/npm/bootstrap-icons@1.11.0/font/bootstrap-icons.css'>
        </head><body style='padding:40px;font-family:system-ui;background:#f3f4f6'>
          <div class='container' style='max-width:640px'>
          <div class='alert alert-warning' style='border-left:4px solid #dc2626;border-radius:10px'>
            <h5 style='font-weight:700;color:#0a0a0a'><i class='bi bi-exclamation-triangle-fill me-2' style='color:#dc2626'></i>Contrato no disponible</h5>
            <p class='mb-2'>El archivo se perdió tras un redeploy de Railway (filesystem efímero).
            Por eso Cloudinary es importante: persiste entre deploys.</p>
            <hr>
            <div class='small text-muted mb-3'>
              Archivo perdido: <code>{nombre_visible}</code><br>
              ID del contrato: <strong>#{ctid}</strong>
            </div>
            {accion}
          </div>
          <a href='javascript:window.close()' class='btn' style='background:#dc2626;color:#fff'>Cerrar</a>
          </div>
        </body></html>
        """
        return html, 404

    # Archivo en disco existe → servir + best-effort upload a Cloudinary async
    # FIX 2026-05-22: aprovechamos que el archivo está aquí AHORA para
    # subirlo a Cloudinary en background y que la próxima visita ya redirija.
    # Si Cloudinary falla, simplemente seguimos sirviendo desde disco esta vez.
    if _CLD_READY and ct.get("cliente_id"):
        try:
            import threading as _th
            def _backfill_async():
                try:
                    with open(full_path, "rb") as _fh:
                        public_id = f"contrato_{ct['cliente_id']}_{int(time.time())}_bf"
                        res = _cloud_upload_raw(_fh, public_id, folder="ilus/contratos")
                    mysql_execute(
                        "UPDATE mant_contratos "
                        "   SET cloudinary_url=%s, cloudinary_public_id=%s, "
                        "       cloudinary_uploaded_at=%s "
                        " WHERE id=%s AND (cloudinary_url IS NULL OR cloudinary_url='')",
                        (res["url"], res["public_id"], datetime.utcnow(), ctid)
                    )
                    print(f"[mant_contrato_archivo] backfill cloud OK ctid={ctid} url={res['url']}", flush=True)
                except Exception as e_bf:
                    print(f"[mant_contrato_archivo] backfill cloud FAIL ctid={ctid}: {e_bf}", flush=True)
            _th.Thread(target=_backfill_async, daemon=True).start()
        except Exception as e_th:
            print(f"[mant_contrato_archivo] no se pudo lanzar thread backfill: {e_th}", flush=True)

    # Servir el archivo
    resp = make_response(send_from_directory(
        MANT_UPLOADS, ct["archivo_path"],
        as_attachment=as_dl,
        download_name=ct["archivo_nombre"] if as_dl else None,
    ))

    # Headers explícitos para garantizar visualización inline en iframe
    if as_dl:
        resp.headers["Content-Disposition"] = f'attachment; filename="{nombre}"'
    else:
        resp.headers["Content-Disposition"] = f'inline; filename="{nombre}"'

    # Tipo MIME explícito según extensión
    mime_map = {
        "pdf":  "application/pdf",
        "doc":  "application/msword",
        "docx": "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
    }
    if ext in mime_map:
        resp.headers["Content-Type"] = mime_map[ext]

    resp.headers["X-Frame-Options"] = "SAMEORIGIN"
    resp.headers["Content-Security-Policy"] = "frame-ancestors 'self'"
    resp.headers["Cache-Control"] = "private, max-age=60"
    print(f"[mant_contrato_archivo] ctid={ctid} → DISCO (ext={ext})", flush=True)
    return resp


# ══════════════════════════════════════════════════════════════════════
# CLAUDE AI — HELPER UNIFICADO + ENDPOINTS DE MANTENCIONES
#
# Centraliza la llamada a Claude para que todo el módulo use el mismo
# modelo, manejo de errores y logging.
#
# Modelo: usamos un alias estable que funciona bien para JSON estructurado
#          y razonamiento técnico (analisis de equipos, contratos, etc.)
# ══════════════════════════════════════════════════════════════════════

# Modelo principal de Claude para mantenciones. Si cambia el modelo, sólo
# se edita aquí. Fallbacks si el principal falla.
_CLAUDE_MODELS_FALLBACK = [
    "claude-opus-4-5",
    "claude-sonnet-4-5",
    "claude-sonnet-4-6",   # reemplazo de claude-3-5-sonnet (retirado 28/10/2025)
]

# ─── ROUTING POR TIER 2026-05-26 (Daniel — ahorro -60% costo IA) ──────
# Cada llamada a _claude_call() puede elegir un tier según la complejidad:
#   'haiku'  → clasificaciones cortas, completar campos (rápido + barato)
#   'sonnet' → fichas técnicas, análisis medios (balance)
#   'opus'   → razonamiento profundo, plan-mejora (caro pero potente)
# Cuando no se pasa tier, se mantiene el comportamiento histórico (opus
# por default) para no romper callers existentes.
_CLAUDE_MODELS_BY_TIER = {
    "haiku": [
        "claude-haiku-4-5",
        "claude-sonnet-4-6",   # último recurso (reemplaza 3-5-sonnet retirado)
    ],
    "sonnet": [
        "claude-sonnet-4-5",
        "claude-sonnet-4-6",   # reemplaza claude-3-5-sonnet (retirado)
        "claude-opus-4-5",
    ],
    "opus": [
        "claude-opus-4-5",
        "claude-sonnet-4-5",
        "claude-sonnet-4-6",   # reemplaza claude-3-5-sonnet (retirado)
    ],
}

# Precios aproximados por 1M tokens (USD) — Anthropic 2025
# Solo para estimación de costo en mant_ia_logs.
_CLAUDE_PRICES_PER_MTOK = {
    # Modelo: (input, output)
    "claude-opus-4-5":            (15.0, 75.0),
    "claude-opus-4-7":            (15.0, 75.0),
    "claude-opus-4-8":            (15.0, 75.0),
    "claude-sonnet-4-5":          (3.0,  15.0),
    "claude-sonnet-4-6":          (3.0,  15.0),
    "claude-3-5-sonnet-20241022": (3.0,  15.0),   # retirado — mantener para lookup de logs históricos
    "claude-haiku-4-5":           (1.0,  5.0),
    "claude-3-5-haiku-20241022":  (0.80, 4.0),    # retirado — mantener para lookup de logs históricos
}


def _ia_estimar_costo_usd(modelo: str, tokens_in: int, tokens_out: int) -> float:
    """Estima costo USD de una llamada Claude segun el modelo."""
    if not modelo or modelo not in _CLAUDE_PRICES_PER_MTOK:
        return 0.0
    p_in, p_out = _CLAUDE_PRICES_PER_MTOK[modelo]
    return round(((tokens_in or 0) * p_in + (tokens_out or 0) * p_out) / 1_000_000, 5)


def _ia_log(endpoint: str, *, entidad_tipo=None, entidad_id=None, modelo=None,
            tier=None, tokens_in=0, tokens_out=0, elapsed_ms=0,
            cache_hit=False, ok=True, error_msg=None):
    """Registra una llamada a Claude en mant_ia_logs. Best-effort: si la
    tabla no existe aún (migración no corrió), no rompe el caller."""
    try:
        costo = _ia_estimar_costo_usd(modelo, tokens_in, tokens_out)
        mysql_execute(
            "INSERT INTO mant_ia_logs (endpoint, entidad_tipo, entidad_id, "
            " modelo, tier_solicitado, tokens_in, tokens_out, costo_usd, "
            " elapsed_ms, cache_hit, ok, error_msg, usuario) "
            "VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)",
            (endpoint[:80], entidad_tipo, entidad_id, (modelo or "")[:60],
             (tier or "")[:10] or None,
             int(tokens_in or 0), int(tokens_out or 0), costo,
             int(elapsed_ms or 0), 1 if cache_hit else 0,
             1 if ok else 0, (error_msg or "")[:255] or None,
             current_username())
        )
    except Exception as _e:
        print(f"[_ia_log] no se pudo loguear ({endpoint}): {_e}", flush=True)


# ═════════════════════════════════════════════════════════════════════
# JOBS IA ASÍNCRONOS 2026-05-26 (Daniel — UX premium)
# Permite ejecutar llamadas Claude largas sin bloquear al usuario.
# El POST original devuelve job_id en <300ms; un thread daemon ejecuta
# el análisis; el frontend polea GET /api/ai/jobs/<id> cada 2s para ver
# avance. Cuando termina, descarga el resultado del job.
# ═════════════════════════════════════════════════════════════════════
def _ia_job_crear(endpoint: str, entidad_tipo=None, entidad_id=None) -> int:
    """Crea un job en estado pending y devuelve su id."""
    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            cur.execute(
                "INSERT INTO mant_ia_jobs (endpoint, entidad_tipo, entidad_id, "
                " estado, paso_actual, creado_por) "
                "VALUES (%s,%s,%s,'pending','Esperando turno…',%s)",
                (endpoint[:80], entidad_tipo, entidad_id, current_username())
            )
            jid = cur.lastrowid
        conn.commit()
        return int(jid)
    finally:
        conn.close()


def _ia_job_update(job_id: int, *, estado=None, paso=None, progreso=None,
                   resultado=None, error=None):
    """Actualiza el estado de un job IA. Best-effort, no levanta excepciones."""
    sets, vals = [], []
    if estado is not None:
        sets.append("estado=%s"); vals.append(estado)
        if estado == "running":
            sets.append("started_at=NOW()")
        elif estado in ("done", "error"):
            sets.append("finished_at=NOW()")
    if paso is not None:
        sets.append("paso_actual=%s"); vals.append(paso[:120])
    if progreso is not None:
        sets.append("progreso_pct=%s"); vals.append(max(0, min(100, int(progreso))))
    if resultado is not None:
        sets.append("resultado_json=%s")
        vals.append(json.dumps(resultado, ensure_ascii=False) if not isinstance(resultado, str) else resultado)
    if error is not None:
        sets.append("error_msg=%s"); vals.append(error[:500])
    if not sets:
        return
    vals.append(job_id)
    try:
        mysql_execute(f"UPDATE mant_ia_jobs SET {', '.join(sets)} WHERE id=%s", tuple(vals))
    except Exception as _e:
        print(f"[_ia_job_update] job={job_id} fail: {_e}", flush=True)


def _ia_job_lanzar(endpoint: str, fn, *, entidad_tipo=None, entidad_id=None,
                   etapas=None):
    """Ejecuta `fn(job_actualizar)` en un daemon thread. Crea el job ANTES
    de devolver, así el caller obtiene job_id en <300ms.

    `fn` debe ser una función que recibe un callback:
        def fn(reportar_paso):
            reportar_paso('Etapa 1', 25)
            ...
            return {"clave": "valor"}     # o levanta Exception si falla

    `etapas` (opcional): lista de strings — mensajes preset para usar.

    Returns: job_id (int)
    """
    job_id = _ia_job_crear(endpoint, entidad_tipo, entidad_id)

    def _runner():
        def _reportar(paso, pct):
            _ia_job_update(job_id, estado="running", paso=paso, progreso=pct)
        try:
            _ia_job_update(job_id, estado="running",
                           paso=(etapas[0] if etapas else "Procesando…"),
                           progreso=5)
            resultado = fn(_reportar)
            _ia_job_update(job_id, estado="done",
                           paso="Listo", progreso=100,
                           resultado=resultado)
        except Exception as e:
            print(f"[_ia_job_lanzar] job={job_id} ERROR: {e}", flush=True)
            _ia_job_update(job_id, estado="error",
                           paso="Error", progreso=100,
                           error=str(e)[:500])

    import threading as _th
    _th.Thread(target=_runner, daemon=True).start()
    return job_id


def _coerce_json_from_llm(raw):
    """Extrae un objeto/array JSON de una respuesta de LLM de forma tolerante.

    Los modelos suelen "ensuciar" el JSON de formas predecibles; este helper
    las absorbe todas:
      - lo envuelven en un fence markdown  ```json ... ```
      - agregan prosa antes o después del bloque
      - dejan comas colgantes  (",}"  o  ",]")  que rompen json.loads

    Devuelve el objeto Python ya parseado, o lanza ValueError si NO hay JSON
    recuperable (respuesta vacía o truncada a la mitad por max_tokens).
    """
    if not raw or not str(raw).strip():
        raise ValueError("respuesta vacía")
    s = str(raw).strip()
    # 1) Si viene dentro de un bloque ```...``` nos quedamos con su contenido.
    _fence = re.search(r"```(?:json)?\s*(.+?)\s*```", s, re.DOTALL | re.IGNORECASE)
    if _fence:
        s = _fence.group(1).strip()
    # 2) Intento directo.
    try:
        return json.loads(s)
    except Exception:
        pass
    # 3) Recortar al primer {…última } (o [ … ]) y reintentar, quitando además
    #    comas colgantes (",}" / ",]") que invalidan el JSON.
    for _op, _cl in (("{", "}"), ("[", "]")):
        _i, _j = s.find(_op), s.rfind(_cl)
        if 0 <= _i < _j:
            _frag = s[_i:_j + 1]
            for _cand in (_frag, re.sub(r",\s*([}\]])", r"\1", _frag)):
                try:
                    return json.loads(_cand)
                except Exception:
                    continue
    raise ValueError("no parseable")


def _claude_call(prompt_usuario, prompt_sistema, max_tokens=1500,
                 expect_json=True, model=None, temperature=0.2,
                 attachments=None, tier=None,
                 log_endpoint=None, log_entidad_tipo=None, log_entidad_id=None):
    """Llama a Claude API. Retorna (data, error) — data es dict si expect_json.

    - Maneja la limpieza de bloques ```json ... ```
    - Reintenta con modelos fallback si el principal no existe
    - Logs detallados para diagnóstico
    - attachments: lista opcional de dicts tipo
        {"type":"document","source":{...}} para PDFs escaneados, o
        {"type":"image","source":{...}} para imágenes.
        Si está presente, se concatenan al content del primer message.
    - tier (opcional): 'haiku' | 'sonnet' | 'opus' — selecciona la cadena
        de fallback apropiada. Si se omite, usa _CLAUDE_MODELS_FALLBACK
        (comportamiento histórico para no romper callers existentes).
        `model` explícito tiene prioridad sobre `tier`.
    - log_endpoint (opcional): nombre del endpoint para registrar en
        mant_ia_logs. Si no se pasa, intenta inferirlo de request.endpoint.
    - log_entidad_tipo, log_entidad_id (opcional): para correlacionar
        la llamada con la entidad afectada (cliente/contrato/máquina).
    """
    _start_ts = time.time()
    _endpoint_inferido = log_endpoint
    if not _endpoint_inferido:
        try:
            _endpoint_inferido = request.endpoint or "ai_unknown"
        except Exception:
            _endpoint_inferido = "ai_background"

    ai_key = _get_ai_key()
    if not ai_key:
        _ia_log(_endpoint_inferido, entidad_tipo=log_entidad_tipo,
                entidad_id=log_entidad_id, tier=tier, ok=False,
                error_msg="API key no configurada",
                elapsed_ms=int((time.time() - _start_ts) * 1000))
        return None, "ANTHROPIC_API_KEY no configurada. Agregala en Railway → Variables."

    try:
        import anthropic as _anthropic
    except ImportError:
        _ia_log(_endpoint_inferido, entidad_tipo=log_entidad_tipo,
                entidad_id=log_entidad_id, tier=tier, ok=False,
                error_msg="lib anthropic no instalada",
                elapsed_ms=int((time.time() - _start_ts) * 1000))
        return None, "Librería anthropic no instalada. Agregar al requirements.txt"

    # Resolución del modelo:
    #   1) Si viene `model` explícito → solo ese.
    #   2) Si viene `tier` → cadena del tier.
    #   3) Si no viene nada → fallback histórico (opus default).
    if model:
        models_to_try = [model]
    elif tier and tier in _CLAUDE_MODELS_BY_TIER:
        models_to_try = _CLAUDE_MODELS_BY_TIER[tier]
    else:
        models_to_try = _CLAUDE_MODELS_FALLBACK
    last_err = None
    client = _anthropic.Anthropic(api_key=ai_key)

    # Si hay attachments, construir content como lista (texto + adjuntos)
    if attachments:
        content_blocks = list(attachments) + [{"type": "text", "text": prompt_usuario}]
    else:
        content_blocks = prompt_usuario

    for m in models_to_try:
        try:
            msg = client.messages.create(
                model=m,
                max_tokens=max_tokens,
                temperature=temperature,
                system=prompt_sistema,
                messages=[{"role": "user", "content": content_blocks}]
            )
            raw = msg.content[0].text.strip()
            # Captura tokens usados (la SDK devuelve usage.input_tokens/output_tokens)
            _tok_in = getattr(msg.usage, "input_tokens", 0) if hasattr(msg, "usage") else 0
            _tok_out = getattr(msg.usage, "output_tokens", 0) if hasattr(msg, "usage") else 0
            _elapsed = int((time.time() - _start_ts) * 1000)

            if not expect_json:
                _ia_log(_endpoint_inferido, entidad_tipo=log_entidad_tipo,
                        entidad_id=log_entidad_id, modelo=m, tier=tier,
                        tokens_in=_tok_in, tokens_out=_tok_out,
                        elapsed_ms=_elapsed, ok=True)
                return raw, None
            # Parseo tolerante: absorbe fences ```json, prosa alrededor y comas
            # colgantes (ver _coerce_json_from_llm).
            try:
                _parsed = _coerce_json_from_llm(raw)
                _ia_log(_endpoint_inferido, entidad_tipo=log_entidad_tipo,
                        entidad_id=log_entidad_id, modelo=m, tier=tier,
                        tokens_in=_tok_in, tokens_out=_tok_out,
                        elapsed_ms=_elapsed, ok=True)
                return _parsed, None
            except Exception:
                # Distinguir el truncamiento (respuesta cortada por max_tokens)
                # de un JSON realmente malformado o vacío: el mensaje cambia para
                # que el usuario sepa qué hacer.
                _stop = getattr(msg, "stop_reason", None)
                if _stop == "max_tokens":
                    last_err = ("La IA generó una respuesta más larga que el límite "
                                "y se cortó a la mitad. Reintenta; si el documento es "
                                "muy extenso, divídelo o súbelo más corto.")
                elif not (raw or "").strip():
                    last_err = ("La IA devolvió una respuesta vacía. "
                                "Reintenta en unos segundos.")
                else:
                    last_err = f"Respuesta no parseable como JSON: {raw[:200]}"
        except Exception as e:
            err_str = str(e)
            last_err = err_str
            # Si es error de modelo, intentar el siguiente
            if "model" in err_str.lower() or "not_found" in err_str.lower():
                continue
            # Otros errores (auth, rate limit, etc.) → cortar acá
            _ia_log(_endpoint_inferido, entidad_tipo=log_entidad_tipo,
                    entidad_id=log_entidad_id, modelo=m, tier=tier,
                    elapsed_ms=int((time.time() - _start_ts) * 1000),
                    ok=False, error_msg=err_str[:255])
            return None, f"Error Claude API: {err_str}"

    _ia_log(_endpoint_inferido, entidad_tipo=log_entidad_tipo,
            entidad_id=log_entidad_id, tier=tier,
            elapsed_ms=int((time.time() - _start_ts) * 1000),
            ok=False, error_msg=(last_err or "todos los modelos fallaron")[:255])
    return None, last_err or "Todos los modelos fallaron"


@app.route("/mantenciones/api/ai/health", methods=["GET"])
@_mant_required
def mant_ai_health():
    """Diagnóstico: verifica si la IA está configurada y responde correctamente.
    Útil para que el técnico/admin vea por qué la IA no funciona."""
    status = {
        "key_configurada": bool(_get_ai_key()),
        "anthropic_lib": False,
        "modelo_funciona": False,
        "modelo_usado": None,
        "error": None,
    }
    try:
        import anthropic as _anthropic
        status["anthropic_lib"] = True
    except ImportError:
        status["error"] = "Librería anthropic NO instalada. Agregar a requirements.txt"
        return jsonify(status)

    if not status["key_configurada"]:
        status["error"] = "ANTHROPIC_API_KEY no configurada en Railway"
        return jsonify(status)

    # Test ping a Claude con prompt mínimo
    data, err = _claude_call(
        prompt_usuario="Devuelve EXACTAMENTE este JSON: {\"ok\":true,\"test\":\"ping\"}",
        prompt_sistema="Eres un servicio de health check. Responde SOLO el JSON pedido.",
        max_tokens=50, expect_json=True
    )
    if err:
        status["error"] = err
    elif data and data.get("ok"):
        status["modelo_funciona"] = True
        # Inferir cuál modelo respondió (intentamos el principal primero)
        status["modelo_usado"] = _CLAUDE_MODELS_FALLBACK[0]
    else:
        status["error"] = f"Respuesta inesperada: {data}"

    return jsonify(status)


# ══════════════════════════════════════════════════════════════════════
# IA — JOBS ASÍNCRONOS (2026-05-26 Daniel — UX premium)
# Endpoint de polling para el frontend. Permite mostrar barra de progreso
# mientras Claude trabaja en background.
# ══════════════════════════════════════════════════════════════════════
@app.route("/mantenciones/api/ai/jobs/<int:job_id>", methods=["GET"])
@_mant_required
def mant_ai_job_status(job_id):
    """Devuelve el estado actual de un job IA. Frontend polea cada 2s.

    Respuesta:
      {
        "ok": true,
        "id": 123,
        "estado": "pending" | "running" | "done" | "error",
        "paso_actual": "Leyendo contrato…",
        "progreso_pct": 45,
        "resultado": {...} | null,   # solo cuando estado=done
        "error_msg": null | str,
        "elapsed_ms": 4530           # cuánto lleva corriendo
      }
    """
    j = mysql_fetchone(
        "SELECT id, endpoint, entidad_tipo, entidad_id, estado, paso_actual, "
        "       progreso_pct, resultado_json, error_msg, creado_por, "
        "       created_at, started_at, finished_at "
        "  FROM mant_ia_jobs WHERE id=%s", (job_id,)
    )
    if not j:
        return jsonify({"ok": False, "error": "Job no encontrado"}), 404

    # Solo el creador o un superadmin/admin puede ver el job
    es_super = bool((g.permissions or {}).get("superadmin") or (g.permissions or {}).get("admin"))
    if not es_super and j.get("creado_por") != current_username():
        return jsonify({"ok": False, "error": "Sin permiso"}), 403

    resultado = None
    if j.get("estado") == "done" and j.get("resultado_json"):
        try:
            resultado = json.loads(j["resultado_json"])
        except Exception:
            resultado = j["resultado_json"]  # texto crudo

    # Calcular elapsed_ms desde started_at (o created_at si aún pending)
    elapsed_ms = 0
    try:
        from datetime import datetime as _dt
        ref = j.get("started_at") or j.get("created_at")
        if ref:
            elapsed_ms = int((_dt.utcnow() - ref).total_seconds() * 1000)
    except Exception:
        pass

    return jsonify({
        "ok": True,
        "id": j["id"],
        "endpoint": j.get("endpoint"),
        "entidad_tipo": j.get("entidad_tipo"),
        "entidad_id": j.get("entidad_id"),
        "estado": j["estado"],
        "paso_actual": j.get("paso_actual") or "",
        "progreso_pct": int(j.get("progreso_pct") or 0),
        "resultado": resultado,
        "error_msg": j.get("error_msg"),
        "elapsed_ms": elapsed_ms,
    })


# ══════════════════════════════════════════════════════════════════════
# IA — MÉTRICAS DE CONSUMO (2026-05-26 Daniel)
# Endpoint para que el superadmin vea cuánto se gasta en IA cada mes.
# ══════════════════════════════════════════════════════════════════════
@app.route("/mantenciones/api/ai/metricas", methods=["GET"])
@_mant_required
def mant_ai_metricas():
    """Devuelve métricas de consumo IA del último mes (o periodo elegido).

    Query params:
      ?dias=30      → ventana (default 30)
      ?endpoint=X   → filtrar por endpoint específico

    Respuesta:
      {
        ok: true,
        periodo_dias: 30,
        totales: {llamadas, costo_usd, tokens_in, tokens_out, errores, cache_hits},
        por_endpoint: [{endpoint, llamadas, costo_usd, avg_ms}, ...],
        por_dia: [{dia, llamadas, costo_usd}, ...]
      }
    """
    if not (g.permissions or {}).get("superadmin"):
        return jsonify({"ok": False, "error": "Solo superadmin"}), 403

    try:
        dias = max(1, min(365, int(request.args.get("dias", 30))))
    except Exception:
        dias = 30
    ep_filter = (request.args.get("endpoint") or "").strip()[:80] or None

    where = ["created_at >= DATE_SUB(NOW(), INTERVAL %s DAY)"]
    params = [dias]
    if ep_filter:
        where.append("endpoint = %s")
        params.append(ep_filter)
    where_sql = " AND ".join(where)

    # Totales
    try:
        row = mysql_fetchone(
            f"SELECT COUNT(*) AS n, "
            f"       COALESCE(SUM(costo_usd),0) AS costo, "
            f"       COALESCE(SUM(tokens_in),0)  AS toks_in, "
            f"       COALESCE(SUM(tokens_out),0) AS toks_out, "
            f"       COALESCE(SUM(CASE WHEN ok=0 THEN 1 ELSE 0 END),0) AS errores, "
            f"       COALESCE(SUM(cache_hit),0) AS cache_hits "
            f"  FROM mant_ia_logs WHERE {where_sql}",
            tuple(params)
        ) or {}
    except Exception as e:
        return jsonify({
            "ok": False,
            "error": "La tabla mant_ia_logs aún no se ha creado o está vacía. "
                     "Después de la próxima llamada IA aparecerán métricas. "
                     "Detalle: " + str(e)[:150]
        }), 200

    # Por endpoint
    por_ep = mysql_fetchall(
        f"SELECT endpoint, COUNT(*) AS n, "
        f"       COALESCE(SUM(costo_usd),0) AS costo, "
        f"       COALESCE(AVG(elapsed_ms),0) AS avg_ms "
        f"  FROM mant_ia_logs WHERE {where_sql} "
        f" GROUP BY endpoint ORDER BY costo DESC LIMIT 20",
        tuple(params)
    ) or []

    # Por día
    por_dia = mysql_fetchall(
        f"SELECT DATE(created_at) AS dia, COUNT(*) AS n, "
        f"       COALESCE(SUM(costo_usd),0) AS costo "
        f"  FROM mant_ia_logs WHERE {where_sql} "
        f" GROUP BY DATE(created_at) ORDER BY dia ASC",
        tuple(params)
    ) or []

    return jsonify({
        "ok": True,
        "periodo_dias": dias,
        "totales": {
            "llamadas":   int(row.get("n", 0) or 0),
            "costo_usd":  float(row.get("costo", 0) or 0),
            "tokens_in":  int(row.get("toks_in", 0) or 0),
            "tokens_out": int(row.get("toks_out", 0) or 0),
            "errores":    int(row.get("errores", 0) or 0),
            "cache_hits": int(row.get("cache_hits", 0) or 0),
        },
        "por_endpoint": [
            {"endpoint": r["endpoint"],
             "llamadas": int(r["n"]),
             "costo_usd": float(r["costo"]),
             "avg_ms": int(r["avg_ms"])}
            for r in por_ep
        ],
        "por_dia": [
            {"dia": str(r["dia"]),
             "llamadas": int(r["n"]),
             "costo_usd": float(r["costo"])}
            for r in por_dia
        ],
    })


# ══════════════════════════════════════════════════════════════════════
# IA — ALERTAS PROACTIVAS DIARIAS (disparo manual)
# El cron diario ya invoca _ia_alertas_resumir_diario() en el slot de
# las 06:00 CL. Este endpoint permite disparo manual on-demand para
# testing o uso bajo demanda. Solo superadmin.
# ══════════════════════════════════════════════════════════════════════
@app.route("/mantenciones/api/ia/alertas-diarias-run", methods=["POST"])
@_mant_required
def mant_ia_alertas_diarias_manual():
    """Disparo manual del resumen IA diario."""
