# ══════════════════════════════════════════════════════════════════════
# IA — COMPLETAR FICHA DE MÁQUINA
#
# Toma una máquina con datos parciales (SKU, nombre, serie) y usa Claude
# para sugerir/completar: marca, modelo, especificaciones técnicas,
# ubicación recomendada, tag de zona, vida útil estimada, riesgos típicos.
# ══════════════════════════════════════════════════════════════════════

@app.route("/mantenciones/api/maquinas/<int:mid>/ai-completar", methods=["POST"])
@_mant_required
def mant_maquina_ai_completar(mid):
    """Usa Claude para completar la ficha técnica de una máquina."""
    maq = mysql_fetchone(
        "SELECT m.*, c.razon_social, c.comuna "
        "  FROM mant_maquinas m "
        "  LEFT JOIN mant_clientes c ON c.id=m.cliente_id "
        " WHERE m.id=%s", (mid,)
    )
    if not maq:
        return jsonify({"ok": False, "error": "Máquina no encontrada"}), 404

    sistema = """Eres un ingeniero experto en equipos de fitness comercial (ILUS Fitness, Chile).
Tu trabajo es identificar y completar la ficha técnica de una máquina basándote en datos parciales.
Responde SIEMPRE en JSON con esta estructura EXACTA, sin texto adicional:
{
  "marca_estimada": "marca probable (ej: Life Fitness, Precor, Matrix, Technogym, BH, Sportek)",
  "modelo_estimado": "modelo si se puede inferir del SKU",
  "categoria": "cardio|fuerza|funcional|accesorio|libre",
  "subcategoria": "treadmill|elliptical|bike_spinning|bike_recumbent|stairmaster|rower|smith|multipower|mancuernas|barra|cable_cruzado|otro",
  "voltaje_recomendado": "220V|380V|N/A",
  "potencia_kw_estimada": número_o_null,
  "peso_kg_estimado": número_o_null,
  "vida_util_anos": número_entero,
  "puntos_inspeccion_pm": [
    "ítem 1 de inspección preventiva mensual/anual",
    "ítem 2",
    "..."
  ],
  "riesgos_tipicos": ["riesgo 1", "riesgo 2"],
  "repuestos_consumo_frecuente": ["repuesto 1", "repuesto 2"],
  "frecuencia_pm_sugerida_meses": número_entero,
  "ubicacion_recomendada": "ej: sala cardio, sala pesas, zona libre",
  "confianza": 0-100,
  "notas": "observaciones libres para el técnico"
}
Sé preciso. Si no se puede inferir un campo con razonable certeza, devuelve null o lista vacía.
"""

    usuario = f"""Completa la ficha técnica de esta máquina:

SKU: {maq.get('sku') or '(no informado)'}
Nombre/Descripción: {maq.get('nombre') or '(no informado)'}
N° Serie: {maq.get('serie') or '(no informado)'}
Tag 1 actual: {maq.get('tag_1') or '(no informado)'}
Tag 2 actual: {maq.get('tag_2') or '(no informado)'}
Cliente: {maq.get('razon_social') or '(no informado)'} ({maq.get('comuna') or 'comuna sin dato'})
Cantidad: {maq.get('cantidad') or 1}

Devuelve el JSON completo."""

    data, err = _claude_call(usuario, sistema, max_tokens=1200, expect_json=True)
    if err:
        return jsonify({"ok": False, "error": err}), 503
    if not data:
        return jsonify({"ok": False, "error": "Sin respuesta"}), 503

    # Aplicar sugerencias seguras a la máquina (sin pisar lo que el usuario ya editó)
    updates = {}
    if not maq.get("nombre") or maq.get("nombre") == "":
        if data.get("marca_estimada") and data.get("modelo_estimado"):
            updates["nombre"] = f"{data['marca_estimada']} {data['modelo_estimado']}"[:400]
    if not maq.get("tag_1"):
        if data.get("ubicacion_recomendada"):
            updates["tag_1"] = data["ubicacion_recomendada"][:120]
    if not maq.get("tag_2"):
        if data.get("categoria"):
            cat_sub = data.get("categoria")
            if data.get("subcategoria"):
                cat_sub += f" / {data['subcategoria']}"
            updates["tag_2"] = cat_sub[:120]

    if updates:
        try:
            sets = ", ".join(f"{k}=%s" for k in updates.keys())
            vals = list(updates.values()) + [mid]
            mysql_execute(f"UPDATE mant_maquinas SET {sets} WHERE id=%s", tuple(vals))
        except Exception:
            pass

    return jsonify({
        "ok": True,
        "ai": data,
        "aplicado": updates,
        "mensaje": ("Sugerencias generadas. Aplicadas a campos vacíos."
                    if updates else "Sugerencias generadas. La ficha ya estaba completa.")
    })


# ══════════════════════════════════════════════════════════════════════
# IA — ANÁLISIS ECONÓMICO Y OPERATIVO DEL CLIENTE
#
# Analiza el cliente con todos sus datos: contratos, visitas, máquinas,
# notas. Devuelve: MRR estimado, salud financiera, oportunidades,
# riesgos operativos, próximas acciones recomendadas.
# ══════════════════════════════════════════════════════════════════════

@app.route("/mantenciones/api/clientes/<int:cid>/ai-analisis", methods=["POST"])
@_mant_required
def mant_cliente_ai_analisis(cid):
    """Análisis integral del cliente con Claude: economía + ops + recomendaciones.

    Throttle inteligente (2026-05-22):
      - Si han pasado < THROTTLE días Y no hay cambios significativos →
        devuelve el plan en caché SIN llamar a Claude (cached=true).
      - Si ?force=1 (o body {"force":true}) el usuario fuerza regeneración
        (esto sólo es aceptable si elegibilidad dice puede_generar=True).
      - El gating "deberías regenerar?" debe ocurrir en el cliente vía
        GET /api/clientes/<cid>/ia/elegibilidad ANTES de POSTear acá.
    """
    cliente = mysql_fetchone("SELECT * FROM mant_clientes WHERE id=%s", (cid,))
    if not cliente:
        return jsonify({"ok": False, "error": "Cliente no encontrado"}), 404
    cliente = dict(cliente)

    # ── THROTTLE: si cache vigente y no fuerza → no gastar tokens ──
    body = request.get_json(silent=True) or {}
    force_flag = (
        request.args.get("force", "0") in ("1", "true", "yes")
        or bool(body.get("force"))
    )
    elig = _mant_ia_cliente_eligibilidad(cid)

    if elig.get("motivo") == "cache_vigente" and not force_flag:
        # Devolver el plan anterior (no llamar a Claude)
        try:
            row = mysql_fetchone(
                "SELECT plan_json, generado_at FROM mant_ia_planes "
                " WHERE id=%s LIMIT 1",
                (elig.get("plan_actual_id"),)
            )
            pj = (row or {}).get("plan_json") or "{}"
            data_cache = json.loads(pj) if isinstance(pj, str) else (pj or {})
        except Exception:
            data_cache = {}
        try:
            _mant_log("cliente", cid, "ai_analisis_cache",
                      f"Cache vigente ({elig.get('dias_desde_ultimo')}d) — "
                      f"no se consultó a Claude")
        except Exception:
            pass
        return jsonify({
            "ok": True,
            "cached": True,
            "ai": data_cache,
            "elegibilidad": elig,
            "mensaje": (
                f"Sin cambios relevantes desde hace "
                f"{elig.get('dias_desde_ultimo')} día(s) — análisis vigente. "
                f"Esto evita gastar tokens innecesariamente."
            ),
            "contexto": {
                "n_contratos": (elig.get("snapshot_actual") or {}).get("n_contratos", 0),
                "n_visitas":   (elig.get("snapshot_actual") or {}).get("n_visitas", 0),
                "n_maquinas":  (elig.get("snapshot_actual") or {}).get("n_equipos", 0),
            },
        })

    # Si motivo='cambios_detectados' y NO force → devolver 409 para que el
    # frontend confirme con el usuario antes de gastar tokens.
    if (elig.get("motivo") == "cambios_detectados"
            and not force_flag):
        return jsonify({
            "ok": False,
            "needs_confirmation": True,
            "elegibilidad": elig,
            "mensaje": (
                f"Hay {elig.get('n_cambios')} cambio(s) desde el último "
                f"análisis ({elig.get('dias_desde_ultimo')}d). Confirma si "
                f"deseas regenerar (costará ~{elig.get('costo_estimado_tokens')} "
                f"tokens) o si prefieres dejar la sugerencia para más tarde."
            ),
        }), 409

    # Recopilar contexto: contratos, visitas, máquinas
    contratos = [dict(r) for r in (mysql_fetchall(
        "SELECT id, fecha_inicio, fecha_vencimiento, monto_mensual, estado, "
        "       frecuencia_meses, ai_tipo_contrato "
        "  FROM mant_contratos WHERE cliente_id=%s "
        " ORDER BY created_at DESC", (cid,)) or [])]

    visitas = [dict(r) for r in (mysql_fetchall(
        "SELECT id, tipo, estado, fecha_programada, fecha_realizada, costo "
        "  FROM mant_visitas WHERE cliente_id=%s "
        " ORDER BY fecha_programada DESC LIMIT 30", (cid,)) or [])]

    maquinas = [dict(r) for r in (mysql_fetchall(
        "SELECT id, nombre, sku, serie, estado, estado_op, fecha_instalacion "
        "  FROM mant_maquinas WHERE cliente_id=%s "
        " ORDER BY nombre LIMIT 100", (cid,)) or [])]

    # Resumen de números clave
    n_visitas_done = sum(1 for v in visitas if (v.get("estado") or "") == "completada")
    n_visitas_prog = sum(1 for v in visitas if (v.get("estado") or "") == "programada")
    mrr_total = sum(float(c.get("monto_mensual") or 0)
                    for c in contratos if (c.get("estado") or "") in ("vigente","indefinido"))
    costo_promedio_visita = (
        sum(float(v.get("costo") or 0) for v in visitas if v.get("estado")=="completada")
        / max(n_visitas_done, 1)
    )

    sistema = """Eres un analista senior de cuentas para una empresa de servicio técnico
de equipos fitness (ILUS Fitness, Chile). Tu trabajo es analizar la relación con un cliente
y dar insights accionables al ejecutivo SSTT (Servicio Técnico).

Considera:
- MRR (Monthly Recurring Revenue) y tendencia
- Frecuencia de visitas vs lo contratado
- Estado del parque de equipos (vida útil, mantenimiento, riesgos)
- Oportunidades de venta cruzada (repuestos, upgrade contrato, equipos nuevos)
- Riesgos de churn / contrato por vencer / impago

Responde SIEMPRE en JSON con esta estructura EXACTA:
{
  "salud_cuenta": "excelente|buena|regular|riesgo|critica",
  "score_general": 0-100,
  "mrr_estimado_clp": número,
  "valor_anual_estimado_clp": número,
  "rentabilidad_estimada": "alta|media|baja|negativa",
  "fortalezas": ["fortaleza 1","fortaleza 2","..."],
  "debilidades": ["debilidad 1","debilidad 2","..."],
  "oportunidades_venta": [
    {"titulo":"oportunidad 1","valor_estimado_clp":número,"plazo":"corto|medio|largo"}
  ],
  "riesgos_inmediatos": ["riesgo 1","riesgo 2"],
  "proximas_acciones": [
    {"accion":"qué hacer","prioridad":"alta|media|baja","plazo_dias":número}
  ],
  "frecuencia_visitas_recomendada_meses": número_entero,
  "alerta_contrato": "sin contrato|contrato vencido|por vencer|vigente OK",
  "resumen_ejecutivo": "2-3 oraciones para reporte gerencial"
}
Sé específico con cifras en CLP (pesos chilenos). No inventes datos del cliente — si
faltan, dilo en los riesgos."""

    usuario = f"""Analiza esta cuenta de ILUS Fitness:

CLIENTE: {cliente.get('razon_social') or '(sin nombre)'}
  RUT: {cliente.get('rut') or '(sin RUT)'}
  Comuna: {cliente.get('comuna') or '(sin comuna)'}
  Giro: {cliente.get('giro') or '(sin giro)'}
  Estado: {cliente.get('estado')}
  Notas: {cliente.get('notas') or '(sin notas)'}
  Notas confidenciales: {cliente.get('notas_confidenciales') or '(no hay)'}

CONTRATOS ({len(contratos)}):
{json.dumps(contratos, ensure_ascii=False, default=str)[:1500]}

VISITAS recientes ({len(visitas)} — {n_visitas_done} completadas, {n_visitas_prog} programadas):
{json.dumps(visitas[:15], ensure_ascii=False, default=str)[:1500]}

EQUIPOS ({len(maquinas)}):
{json.dumps(maquinas[:20], ensure_ascii=False, default=str)[:1500]}

NÚMEROS CALCULADOS:
  MRR vigente: ${int(mrr_total):,}
  Visitas completadas: {n_visitas_done}
  Costo promedio por visita: ${int(costo_promedio_visita):,}

Devuelve SOLO el JSON solicitado."""

    data, err = _claude_call(usuario, sistema, max_tokens=2000, expect_json=True)
    if err:
        return jsonify({"ok": False, "error": err}), 503
    if not data:
        return jsonify({"ok": False, "error": "Sin respuesta de IA"}), 503

    # Guardar resumen ejecutivo en notas_confidenciales (opcional)
    try:
        analisis_resumido = (
            f"[Análisis IA · {datetime.now().strftime('%Y-%m-%d %H:%M')} · "
            f"{current_username()}] "
            f"{data.get('resumen_ejecutivo','')[:500]}"
        )
        # Append (no pisar). Si excede 5000 char, truncar.
        nota_actual = (cliente.get("notas_confidenciales") or "")[:4000]
        nueva = (analisis_resumido + "\n\n" + nota_actual).strip()[:5000]
        mysql_execute(
            "UPDATE mant_clientes SET notas_confidenciales=%s, updated_by=%s WHERE id=%s",
            (nueva, current_username(), cid)
        )
    except Exception:
        pass

    # Persistir plan IA en mant_ia_planes con snapshot ACTUAL (para que el
    # próximo throttle pueda comparar). Idempotente: si falla, no rompe el endpoint.
    nuevo_plan_id = None
    try:
        snap = _mant_cliente_snapshot_actual(cid)
        conn = get_db()
        with conn.cursor() as cur:
            cur.execute(
                "INSERT INTO mant_ia_planes "
                "  (cliente_id, generado_por, plan_json, "
                "   snapshot_n_visitas, snapshot_n_contratos, snapshot_n_garantias, "
                "   snapshot_ultima_visita) "
                "VALUES (%s,%s,%s,%s,%s,%s,%s)",
                (
                    cid, current_username(),
                    json.dumps(data, ensure_ascii=False, default=str),
                    snap.get("n_visitas"), snap.get("n_contratos"),
                    snap.get("n_garantias"), snap.get("ultima_visita"),
                )
            )
            nuevo_plan_id = cur.lastrowid
        conn.commit()
    except Exception as _e_ia:
        print(f"[mant-ia] no se pudo guardar plan: {_e_ia}", flush=True)

    # Si había una sugerencia "ia_regenerar" pendiente para este cliente,
    # resolverla como aceptada (la acción se ejecutó).
    try:
        row = mysql_fetchone(
            "SELECT id FROM mant_sugerencias_evidencia "
            " WHERE cliente_id=%s AND tipo_sugerencia='ia_regenerar' "
            "   AND resolucion='pendiente' "
            " ORDER BY sugerida_at DESC LIMIT 1",
            (cid,)
        )
        if row and row.get("id"):
            _sugerencia_resolver(
                row["id"], 'aceptada',
                motivo=f"Regenerado vía análisis IA (plan #{nuevo_plan_id})",
            )
    except Exception:
        pass

    # Log de auditoría
    try:
        _mant_log("cliente", cid, "ai_analisis",
                  f"Score: {data.get('score_general')} · "
                  f"Salud: {data.get('salud_cuenta')} · "
                  f"plan_id={nuevo_plan_id}")
    except Exception: pass

    return jsonify({
        "ok": True,
        "cached": False,
        "ai": data,
        "plan_id": nuevo_plan_id,
        "elegibilidad": elig,
        "contexto": {
            "n_contratos": len(contratos),
            "n_visitas": len(visitas),
            "n_maquinas": len(maquinas),
            "mrr_total": mrr_total,
        }
    })


# ══════════════════════════════════════════════════════════════════════
# IA — ELEGIBILIDAD para regenerar análisis del cliente
# Devuelve si el cliente puede/debe regenerar el análisis IA SIN gastar
# tokens. Frontend lo consume antes de POSTear para mostrar modal claro.
# ══════════════════════════════════════════════════════════════════════

# ── Cache TTL 10min de elegibilidad IA (Daniel 2026-05-26 audit) ──
# DevTools: endpoint tarda ~4.5s. Hace múltiples queries para detectar
# cambios desde la última generación. Como esos cambios ocurren con
# frecuencia DIARIA (no por segundo), cachear 10 min es seguro y quita
# 4.5s de la apertura de ficha cliente.
_IA_ELIG_CACHE = {}  # cid -> (data, ts)
_IA_ELIG_LOCK  = threading.Lock()
_IA_ELIG_TTL   = 600  # 10 min


def _ia_elig_cache_invalidar(cid=None):
    """Invalida cache de elegibilidad. Llamar tras regenerar análisis IA."""
    with _IA_ELIG_LOCK:
        if cid is None:
            _IA_ELIG_CACHE.clear()
        else:
            _IA_ELIG_CACHE.pop(int(cid), None)


@app.route("/mantenciones/api/clientes/<int:cid>/ia/elegibilidad",
           methods=["GET"])
@_mant_required
def mant_cliente_ia_elegibilidad(cid):
    """Verifica si conviene regenerar el análisis IA para este cliente.
    Cacheado 10 min (audit DevTools: era 4.5s por llamada)."""
    # Cache hit
    _now = time.time()
    with _IA_ELIG_LOCK:
        entry = _IA_ELIG_CACHE.get(cid)
    if entry and (_now - entry[1]) < _IA_ELIG_TTL:
        return jsonify(entry[0])

    cliente = mysql_fetchone(
        "SELECT id, razon_social FROM mant_clientes WHERE id=%s", (cid,)
    )
    if not cliente:
        return jsonify({"ok": False, "error": "Cliente no encontrado"}), 404
    elig = _mant_ia_cliente_eligibilidad(cid)
    data = {
        "ok": True,
        "cliente": {"id": cliente["id"],
                    "razon_social": cliente.get("razon_social")},
        **elig,
        "_cached_ttl": _IA_ELIG_TTL,
    }
    with _IA_ELIG_LOCK:
        _IA_ELIG_CACHE[cid] = (data, _now)
    return jsonify(data)


@app.route("/mantenciones/api/clientes/<int:cid>/ia/diferir",
           methods=["POST"])
@_mant_required
def mant_cliente_ia_diferir(cid):
    """El usuario decide NO regenerar ahora, pero quiere dejar la
    evidencia de que se le sugirió. Crea sugerencia tipo='ia_regenerar'
    para revisión posterior (cumple el principio "queda huella")."""
    cliente = mysql_fetchone(
        "SELECT id, razon_social FROM mant_clientes WHERE id=%s", (cid,)
    )
    if not cliente:
        return jsonify({"ok": False, "error": "Cliente no encontrado"}), 404
    cliente = dict(cliente)

    elig = _mant_ia_cliente_eligibilidad(cid)
    if elig.get("motivo") == "cache_vigente":
        return jsonify({
            "ok": False,
            "error": "El cache aún está vigente, no es necesario diferir."
        }), 400

    body = request.get_json(silent=True) or {}
    nota = (body.get("nota") or "").strip()

    titulo = (f"Regenerar análisis IA: {cliente.get('razon_social','')}"
              f" ({elig.get('n_cambios')} cambio(s))")
    cuerpo = (
        f"Hay cambios desde el último análisis IA "
        f"({elig.get('dias_desde_ultimo')}d). El usuario eligió diferir."
        + (f"\n\nNota del usuario: {nota}" if nota else "")
        + f"\n\nCambios detectados ({elig.get('n_cambios')}):"
    )
    for c in elig.get("cambios") or []:
        cuerpo += f"\n  · {c.get('campo')}: {c.get('antes')} → {c.get('ahora')}"

    sid = _sugerencia_crear(
        cliente_id=cid,
        tipo="ia_regenerar",
        titulo=titulo,
        cuerpo=cuerpo,
        url_accion=f"/mantenciones/clientes/{cid}",
        origen="usuario",
        entidad="cliente",
        entidad_id=cid,
        metadata={
            "elegibilidad": elig,
            "nota_usuario": nota,
        },
        notificar=True,
        prioridad='baja',
    )
    if not sid:
        return jsonify({"ok": False,
                        "error": "No se pudo crear sugerencia"}), 500

    try:
        _mant_log("cliente", cid, "ia_diferida",
                  f"sugerencia_id={sid} cambios={elig.get('n_cambios')}")
    except Exception:
        pass

    return jsonify({"ok": True, "sugerencia_id": sid})


# ══════════════════════════════════════════════════════════════════════
# IA — COMPLETAR FICHA DEL CLIENTE (cuando faltan datos)
#
# Usa el nombre/RUT y lo que ya hay en la ficha para sugerir campos
# faltantes: giro probable, comuna probable según dirección, contacto
# típico, observaciones operativas.
# ══════════════════════════════════════════════════════════════════════

@app.route("/mantenciones/api/clientes/<int:cid>/ai-completar-ficha", methods=["POST"])
@_mant_required
def mant_cliente_ai_completar(cid):
    """Sugiere completar campos faltantes de la ficha del cliente."""
    cliente = mysql_fetchone("SELECT * FROM mant_clientes WHERE id=%s", (cid,))
    if not cliente:
        return jsonify({"ok": False, "error": "Cliente no encontrado"}), 404
    cliente = dict(cliente)

    sistema = """Eres un asistente de back-office de ILUS Fitness, empresa de servicio
técnico de equipos fitness en Chile. Tu trabajo es completar la ficha de un cliente
basándote en lo que ya hay. Solo sugieres — NO inventes datos que no se puedan deducir
de la información disponible.

Devuelve SIEMPRE este JSON, con null donde no haya base para sugerir:
{
  "giro_sugerido": "ej. Gimnasio comercial | Centro deportivo municipal | Hotel | Club",
  "tipo_cliente": "premium|estandar|emergente|institucional",
  "comuna_estimada_segun_direccion": "comuna probable o null",
  "region_estimada": "región probable o null",
  "observaciones_operativas": "ej. exige facturación a 30 días, ventana de servicio sólo en madrugada, etc.",
  "campos_faltantes_criticos": ["lista de campos que urgen completar"],
  "preguntas_para_ejecutivo": ["pregunta 1","pregunta 2"],
  "confianza": 0-100
}"""

    usuario = f"""Analiza esta ficha de cliente y sugiere campos faltantes:

Razón social: {cliente.get('razon_social') or '(VACÍO)'}
RUT: {cliente.get('rut') or '(VACÍO)'}
Giro actual: {cliente.get('giro') or '(VACÍO)'}
Dirección: {cliente.get('direccion') or '(VACÍO)'}
Comuna: {cliente.get('comuna') or '(VACÍO)'}
Ciudad: {cliente.get('ciudad') or '(VACÍO)'}
Región: {cliente.get('region') or '(VACÍO)'}
Email empresa: {cliente.get('email_empresa') or '(VACÍO)'}
Teléfono empresa: {cliente.get('tel_empresa') or '(VACÍO)'}
Contacto principal: {cliente.get('contacto_nombre') or '(VACÍO)'} ({cliente.get('contacto_cargo') or 'sin cargo'})
Notas: {cliente.get('notas') or '(VACÍO)'}

Devuelve SOLO el JSON."""

    data, err = _claude_call(usuario, sistema, max_tokens=900, expect_json=True)
    if err:
        return jsonify({"ok": False, "error": err}), 503
    if not data:
        return jsonify({"ok": False, "error": "Sin respuesta"}), 503

    # Aplicar SOLO a campos vacíos (no pisar lo que el usuario ya editó)
    updates = {}
    if not cliente.get("giro") and data.get("giro_sugerido"):
        updates["giro"] = data["giro_sugerido"][:200]
    if not cliente.get("comuna") and data.get("comuna_estimada_segun_direccion"):
        updates["comuna"] = data["comuna_estimada_segun_direccion"][:100]
    if not cliente.get("region") and data.get("region_estimada"):
        updates["region"] = data["region_estimada"][:100]

    if updates:
        try:
            sets = ", ".join(f"{k}=%s" for k in updates.keys())
            vals = list(updates.values()) + [current_username(), cid]
            mysql_execute(
                f"UPDATE mant_clientes SET {sets}, updated_by=%s WHERE id=%s",
                tuple(vals)
            )
        except Exception: pass

    return jsonify({"ok": True, "ai": data, "aplicado": updates})


# ── ANÁLISIS IA DE CONTRATO ───────────────────────────────────────────

@app.route("/mantenciones/api/contratos/<int:ctid>/analizar", methods=["POST"])
@_mant_required
def mant_contrato_analizar(ctid):
    """
    Llama a Claude API para analizar el contrato de mantención.
    Extrae: puntos críticos, frecuencia sugerida, alertas, score.
    """
    ct = mysql_fetchone("SELECT ct.*, cl.razon_social FROM mant_contratos ct "
                        "JOIN mant_clientes cl ON cl.id=ct.cliente_id "
                        "WHERE ct.id=%s", (ctid,))
    if not ct:
        return jsonify({"error": "Contrato no encontrado"}), 404

    # Leer texto del contrato si es PDF
    texto_contrato = ""
    pdf_b64_paginas = []   # base64 de las primeras N páginas (fallback visión)
    es_escaneado = False
    fpath = os.path.join(MANT_UPLOADS, ct["archivo_path"] or "")
    if os.path.exists(fpath):
        ext = ct["archivo_path"].rsplit(".", 1)[-1].lower()
        if ext == "pdf":
            try:
                import pdfplumber
                with pdfplumber.open(fpath) as pdf:
                    texto_contrato = "\n".join(
                        p.extract_text() or "" for p in pdf.pages[:15]
                    )
            except Exception:
                pass
            # QW5: si el texto extraído está vacío o casi vacío, es un PDF
            # escaneado (imagen). Caemos a Claude visión: enviamos el PDF
            # como base64 + Claude lo procesa visualmente.
            if len(texto_contrato.strip()) < 50:
                es_escaneado = True
                try:
                    import base64
                    with open(fpath, "rb") as f:
                        pdf_bytes = f.read()
                    # Claude soporta PDFs directamente (hasta ~30MB).
                    # Si el archivo es muy grande, lo skippeamos.
                    if len(pdf_bytes) < 30 * 1024 * 1024:
                        pdf_b64_paginas.append({
                            "type": "document",
                            "source": {
                                "type": "base64",
                                "media_type": "application/pdf",
                                "data": base64.standard_b64encode(pdf_bytes).decode("utf-8"),
                            }
                        })
                except Exception:
                    pass
        elif ext in ("doc", "docx"):
            try:
                import docx
                doc = docx.Document(fpath)
                texto_contrato = "\n".join(p.text for p in doc.paragraphs)
            except Exception:
                pass

    # ══════════════════════════════════════════════════════════════════
    # PRE-CHECK IA: ¿es realmente un contrato de servicio?
    # Validador rápido (Haiku-tier) que evita gastar Sonnet/Opus analizando
    # listas de productos, facturas u otros documentos que NO son contratos.
    # ══════════════════════════════════════════════════════════════════
    tipo_doc_detectado = None
    razon_deteccion = None
    if texto_contrato and len(texto_contrato.strip()) > 100:
        precheck_sistema = (
            "Eres un clasificador de documentos. Recibes el texto de un archivo "
            "y debes decidir si es un CONTRATO DE SERVICIO/MANTENCIÓN. "
            "Responde SIEMPRE en JSON: "
            '{"tipo":"contrato_servicio|lista_productos|factura|cotizacion|'
            'guia_despacho|reporte_tecnico|otro","confianza":0-100,"razon":"frase corta"}'
        )
        precheck_usuario = (
            f"Clasifica este documento (extracto):\n\n{texto_contrato[:2500]}\n\n"
            "¿Es un contrato de servicio/mantención? Responde el JSON."
        )
        precheck, precheck_err = _claude_call(
            precheck_usuario, precheck_sistema,
            max_tokens=200, expect_json=True, temperature=0.1
        )
        if precheck and isinstance(precheck, dict):
            tipo_doc_detectado = precheck.get("tipo")
            razon_deteccion = precheck.get("razon")
            confianza = int(precheck.get("confianza") or 0)
            # Daniel 30/05/2026: NUNCA rechazar. La IA analiza CUALQUIER documento
            # contractual (compraventa, leasing, servicio, garantía, comodato…) y
            # entrega el análisis gerencial igual. El tipo detectado solo se informa
            # al prompt (para contextualizar) y al usuario; jamás bloquea el análisis.

    # Datos del contrato para enriquecer el prompt
    datos_extra = (
        f"Cliente: {ct['razon_social']}\n"
        f"Fecha inicio: {ct['fecha_inicio']}\n"
        f"Fecha vencimiento: {ct['fecha_vencimiento']}\n"
        f"Monto mensual: ${ct['monto_mensual']}\n"
        f"Frecuencia declarada: {ct['frecuencia_meses']} meses\n"
        + (f"NOTA: PDF escaneado (imagen) — analizado visualmente.\n" if es_escaneado else "")
        + (f"NOTA: tipo detectado por IA = {tipo_doc_detectado} (puede no ser un contrato típico)\n"
           if tipo_doc_detectado and tipo_doc_detectado != "contrato_servicio" else "")
    )
    if not texto_contrato:
        texto_contrato = "(Texto no extraíble — análisis visual del PDF)" if es_escaneado else "(Texto no extraíble — análisis basado en metadatos)"

    prompt_sistema = """Actúas como un COMITÉ DE EXPERTOS de ILUS Fitness (Chile) analizando
un contrato para la GERENCIA. Combinas 4 roles a la vez:
  - ABOGADO corporativo: detectas cláusulas débiles/ausentes y REDACTAS mejoras concretas.
  - ESPECIALISTA EN SERVICIO TÉCNICO: equipos de fitness (treadmills, bikes, elípticas, fuerza).
  - ANALISTA COMERCIAL: propones cómo subir el ingreso sin perder al cliente.
  - ANALISTA FINANCIERO: cuantificas la EXPOSICIÓN (cuánto podemos perder) y la rentabilidad.

OBJETIVO DE NEGOCIO (crítico): ILUS debe GANAR dinero y estar BLINDADO. El mayor riesgo que
preocupa a la gerencia: clientes que usan el contrato SOLO para exigir/cobrar GARANTÍAS, pero
contratan las mantenciones PAGAS con TERCEROS. Eso nos expone (cubrimos garantías sin ingreso
por servicio). Tu análisis DEBE evidenciar esta y otras exposiciones y proponer blindaje:
por ejemplo, condicionar la garantía a que TODA mantención se haga con ILUS (si la hace un
tercero, se anula la garantía) y obligar mantención periódica exclusiva con ILUS.

Analiza el documento SEA DEL TIPO QUE SEA (servicio, compraventa, leasing, comodato, garantía).
Nunca te niegues a analizar. Responde SIEMPRE en JSON VÁLIDO con ESTA estructura EXACTA
(sin texto fuera del JSON):
{
  "tipo_contrato": "Servicio|Compraventa|Leasing|Comodato|Garantia|Mixto|Otro",
  "resumen": "2-4 oraciones en tono gerencial: qué es y qué significa para ILUS",
  "score": 0-100,
  "nivel_riesgo": "alto|medio|bajo",
  "vigencia_inicio": "YYYY-MM-DD o null",
  "vigencia_fin": "YYYY-MM-DD o null",
  "es_indefinido": true_o_false,
  "frecuencia_sugerida_meses": numero_entero,
  "sla_horas": numero_entero_o_null,
  "incluye_mant_gratis": true_o_false,
  "incluye_repuestos": true_o_false,
  "cobertura_descripcion": "qué cubre y qué NO cubre el contrato",
  "costo_mensual": numero_o_null,
  "costo_por_mant": numero_o_null,
  "costo_total": numero_o_null,
  "clausulas_criticas": ["cláusula textual riesgosa o ausente", "..."],
  "puntos_criticos": ["hallazgo clave", "..."],
  "alertas": ["alerta accionable", "..."],
  "mejoras_prioritarias": ["mejora 1", "mejora 2", "mejora 3"],
  "exposicion": {
    "nivel": "alto|medio|bajo",
    "resumen": "en plata: a qué nos expone este contrato hoy",
    "escenarios": [
      {"riesgo": "ej: garantía sin mantención con ILUS", "impacto": "costo/efecto concreto",
       "probabilidad": "alta|media|baja", "mitigacion": "qué cláusula o acción lo evita"}
    ]
  },
  "analisis_garantia": {
    "cubre_garantia": true_o_false,
    "condicionada_a_mantencion_ilus": true_o_false,
    "riesgo_terceros": "riesgo de que hagan mantenciones pagas con terceros y nos dejen solo la garantía",
    "recomendacion": "cómo condicionar la garantía a mantención exclusiva con ILUS"
  },
  "clausulas_sugeridas": [
    {"titulo": "nombre de la cláusula", "texto": "REDACCIÓN jurídica lista para pegar en el contrato",
     "justificacion": "qué riesgo cubre / cuánto blinda a ILUS"}
  ],
  "propuestas_comerciales": [
    {"titulo": "propuesta para subir ingreso", "descripcion": "cómo, sin perder al cliente",
     "impacto_ingreso": "estimación CLP o cualitativo", "prioridad": "alta|media|baja"}
  ],
  "rentabilidad": {
    "mrr_estimado_clp": numero_o_null,
    "margen_estimado": "alto|medio|bajo|negativo + breve por qué",
    "oportunidad_ingreso_clp": numero_o_null
  }
}
Sé concreto y chileno (CLP, RUT, equipos fitness). Las clausulas_sugeridas deben ser texto
jurídico REAL listo para usar, enfocadas en: (1) mantención periódica OBLIGATORIA con ILUS,
(2) garantía CONDICIONADA a esa mantención exclusiva, (3) cobro de toda visita/OT fuera de
cobertura. Detecta SLA, penalidades y cláusulas de exclusión que perjudiquen a ILUS."""

    if es_escaneado and pdf_b64_paginas:
        prompt_usuario = f"""Analiza este contrato de mantención. El PDF adjunto
es ESCANEADO (imagen), no texto extraíble. Léelo visualmente.

METADATOS:
{datos_extra}

(El texto del contrato está en el PDF adjunto — léelo visualmente)

Devuelve SOLO el JSON, sin texto adicional."""
    else:
        prompt_usuario = f"""Analiza este contrato de mantención:

METADATOS:
{datos_extra}

TEXTO DEL CONTRATO:
{texto_contrato[:6000]}

Devuelve SOLO el JSON, sin texto adicional."""

    # Llamada unificada con fallback de modelos. Si el PDF es escaneado,
    # mandamos el PDF como attachment para que Claude lo procese visualmente.
    # max_tokens alto (8000): el esquema pedido es grande (cláusulas jurídicas
    # completas + propuestas + escenarios de exposición). Con 4000 la respuesta
    # se truncaba a la mitad → "Respuesta no parseable como JSON". (Daniel 30/05/2026)
    resultado, err = _claude_call(
        prompt_usuario, prompt_sistema,
        max_tokens=8000, expect_json=True,
        attachments=pdf_b64_paginas if es_escaneado else None
    )
    if err:
        return jsonify({"error": f"Error IA: {err}"}), 503
    if not resultado:
        return jsonify({"error": "Sin respuesta de IA"}), 503

    # Guardar resultado en DB (estructura expandida + trazabilidad de usuario)
    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            cur.execute(
                """UPDATE mant_contratos SET
                   ai_analizado=1, ai_fecha=%s, ai_usuario=%s,
                   ai_analisis_json=%s,
                   ai_resumen=%s,
                   ai_puntos_criticos=%s, ai_alertas=%s, ai_mejoras=%s,
                   ai_clausulas=%s, ai_cobertura=%s, ai_tipo_contrato=%s,
                   ai_frecuencia_sug=%s, ai_score=%s,
                   ai_vigencia_inicio=%s, ai_vigencia_fin=%s,
                   nivel_riesgo=%s,
                   sla_horas=%s,
                   incluye_mant_gratis=%s, incluye_repuestos=%s,
                   costo_por_mant=%s, costo_total=%s,
                   frecuencia_meses=COALESCE(NULLIF(frecuencia_meses,0),%s),
                   es_indefinido=COALESCE(NULLIF(es_indefinido,0),%s),
                   monto_mensual=COALESCE(NULLIF(monto_mensual,0),%s)
                   WHERE id=%s""",
                (datetime.now(),
                 current_username(),
                 json.dumps(resultado, ensure_ascii=False),
                 resultado.get("resumen",""),
                 json.dumps(resultado.get("puntos_criticos",[]),    ensure_ascii=False),
                 json.dumps(resultado.get("alertas",[]),            ensure_ascii=False),
                 json.dumps(resultado.get("mejoras_prioritarias",[]),ensure_ascii=False),
                 json.dumps(resultado.get("clausulas_criticas",[]), ensure_ascii=False),
                 resultado.get("cobertura_descripcion",""),
                 resultado.get("tipo_contrato",""),
                 resultado.get("frecuencia_sugerida_meses"),
                 resultado.get("score"),
                 resultado.get("vigencia_inicio") or None,
                 resultado.get("vigencia_fin") or None,
                 resultado.get("nivel_riesgo","medio"),
                 resultado.get("sla_horas") or None,
                 1 if resultado.get("incluye_mant_gratis") else 0,
                 1 if resultado.get("incluye_repuestos") else 0,
                 resultado.get("costo_por_mant") or None,
                 resultado.get("costo_total") or None,
                 resultado.get("frecuencia_sugerida_meses"),
                 1 if resultado.get("es_indefinido") else 0,
                 resultado.get("costo_mensual") or None,
                 ctid)
            )
        conn.commit()
        _mant_log("contrato", ctid, "analizado_ia",
                  f"score={resultado.get('score')} riesgo={resultado.get('nivel_riesgo')}"
                  + (f" · tipo_doc={tipo_doc_detectado}" if tipo_doc_detectado else ""))
        return jsonify({
            "ok": True,
            "resultado": resultado,
            "tipo_doc_detectado": tipo_doc_detectado,
            "razon_deteccion": razon_deteccion,
        })
    except Exception as db_err:
        conn.rollback()
        print(f"[MANT] ERROR guardando análisis contrato {ctid}: {db_err}")
        return jsonify({"error": f"IA OK pero error guardando: {db_err}"}), 500
    finally:
        conn.close()


# ── GESTIÓN CONTRATO — cláusulas y variables personalizadas ──────────

@app.route("/mantenciones/api/contratos/<int:ctid>/clausulas", methods=["PUT"])
@_mant_required
def mant_contrato_clausulas(ctid):
    """Guarda cláusulas personalizadas y variables adicionales del contrato."""
    d = request.get_json(silent=True) or {}
    clausulas = d.get("clausulas", [])   # lista de {titulo, texto, tipo}
    variables = d.get("variables", {})   # dict campo→valor
    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            # Actualizar también campos directos si vienen
            extra_sets, extra_vals = [], []
            for campo in ("sla_horas", "frecuencia_meses", "monto_mensual",
                          "monto_anual", "notas", "nivel_riesgo"):
                if campo in variables:
                    extra_sets.append(f"{campo}=%s")
                    extra_vals.append(variables.pop(campo) or None)
            sets = ["clausulas_custom=%s", "variables_extra=%s"] + extra_sets
            vals = [
                json.dumps(clausulas, ensure_ascii=False),
                json.dumps(variables, ensure_ascii=False),
            ] + extra_vals + [ctid]
            cur.execute(
                f"UPDATE mant_contratos SET {','.join(sets)} WHERE id=%s", vals
            )
        conn.commit()
        _mant_log("contrato", ctid, "clausulas_actualizadas",
                  f"{len(clausulas)} cláusulas, {len(variables)} variables")
        return jsonify({"ok": True})
    except Exception as e:
        conn.rollback()
        return jsonify({"error": str(e)}), 500
    finally:
        conn.close()


@app.route("/mantenciones/api/contratos/<int:ctid>/clausulas", methods=["GET"])
@_mant_required
def mant_contrato_clausulas_get(ctid):
    """Devuelve cláusulas personalizadas y variables de un contrato."""
    ct = mysql_fetchone(
        "SELECT clausulas_custom, variables_extra, sla_horas, frecuencia_meses, "
        "monto_mensual, monto_anual, notas, nivel_riesgo FROM mant_contratos WHERE id=%s",
        (ctid,)
    )
    if not ct:
        return jsonify({"error": "No encontrado"}), 404
    return jsonify({
        "clausulas": json.loads(ct.get("clausulas_custom") or "[]"),
        "variables": json.loads(ct.get("variables_extra") or "{}"),
        "campos": {
            "sla_horas": ct.get("sla_horas"),
            "frecuencia_meses": ct.get("frecuencia_meses"),
            "monto_mensual": ct.get("monto_mensual"),
            "monto_anual": ct.get("monto_anual"),
            "notas": ct.get("notas",""),
            "nivel_riesgo": ct.get("nivel_riesgo","medio"),
        }
    })


# ══════════════════════════════════════════════════════════════════════
# DRILL-DOWN POR DÍA — Calendario con métricas
#
# Modal "click en un día" del calendario para ver el detalle completo:
#  - Lista de visitas del día
#  - Duración planificada vs real
#  - Heatmap por técnico
#  - Resumen: total, completadas, overrun promedio
# ══════════════════════════════════════════════════════════════════════

@app.route("/mantenciones/api/calendario/dia/<string:fecha>", methods=["GET"])
@_mant_required
def mant_calendario_dia_drill(fecha):
    """Devuelve el detalle de un día específico (todas las visitas + métricas).

    Path param: fecha en formato YYYY-MM-DD
    """
    import re as _re
    if not _re.match(r"^\d{4}-\d{2}-\d{2}$", fecha):
        return jsonify({"ok": False, "error": "Formato fecha inválido (use YYYY-MM-DD)"}), 400

    try:
        # 🔐 SEGURIDAD 2026-05-22 (Aaron Urbina — brecha calendario-listado):
        # Aplicar filtro por rol coherente con `mant_ots_list` y
        # `mant_visitas_api`. Si el rol no puede ver la OT en el listado,
        # tampoco debe verla como visita del día.
        _u = getattr(g, "user", None) or {}
        _role_raw = (_u.get("role") or "").lower()
        _role_fam = _rol_familia(_role_raw)
        _uid = _u.get("id")
        _extra_where = ""
        _extra_params = []
        if _role_fam in ("admin", "superadmin", "supervisor"):
            pass
        elif _role_fam == "ejecutivo":
            username_actual = (_u.get("username") or "").strip()
            nombre_actual = (_u.get("nombre") or "").strip()
            _has_cbu = False
            try:
                _col_check = mysql_fetchone(
                    "SELECT COUNT(*) AS n FROM INFORMATION_SCHEMA.COLUMNS "
                    " WHERE TABLE_SCHEMA = DATABASE() "
                    "   AND TABLE_NAME = 'mant_visitas' "
                    "   AND COLUMN_NAME = 'created_by_user_id'"
                )
                _has_cbu = bool((_col_check or {}).get("n"))
            except Exception:
                _has_cbu = False
            clauses = []
            if _has_cbu and _uid:
                clauses.append("v.created_by_user_id=%s")
                _extra_params.append(int(_uid))
            if username_actual:
                clauses.append("LOWER(TRIM(v.created_by))=LOWER(TRIM(%s))")
                _extra_params.append(username_actual)
            if nombre_actual and nombre_actual.lower() != username_actual.lower():
                clauses.append("LOWER(TRIM(v.created_by))=LOWER(TRIM(%s))")
                _extra_params.append(nombre_actual)
            if _uid:
                clauses.append("v.tecnico_user_id=%s")
                _extra_params.append(int(_uid))
                clauses.append(
                    "v.id IN (SELECT visita_id FROM mant_visita_tecnicos "
                    "         WHERE tecnico_user_id=%s)"
                )
                _extra_params.append(int(_uid))
            if clauses:
                _extra_where = " AND (" + " OR ".join(clauses) + ") "
            else:
                _extra_where = " AND 1=0 "
        elif _role_fam == "tecnico":
            if _uid:
                _extra_where = (
                    " AND (v.tecnico_user_id=%s OR EXISTS("
                    "  SELECT 1 FROM mant_visita_tecnicos vt "
                    "   WHERE vt.visita_id=v.id AND vt.tecnico_user_id=%s)) "
                )
                _extra_params.extend([int(_uid), int(_uid)])
            else:
                _extra_where = " AND 1=0 "
        else:
            _extra_where = " AND 1=0 "

        # Visitas del día con sus técnicos
        visitas = mysql_fetchall(
            "SELECT v.id, v.numero_ot, v.cliente_id, v.titulo, v.tipo, v.estado, "
            "       v.fecha_programada, v.hora_inicio, v.hora_fin, "
            "       v.hora_real_inicio, v.hora_real_fin, "
            "       v.duracion_planificada_min, v.duracion_real_min, "
            "       v.pausada_total_min, v.costo, v.costo_real, "
            "       v.satisfaccion_estrellas, "
            "       c.razon_social AS cliente_nombre, c.comuna, "
            "       t.id AS tecnico_id, t.nombre AS tecnico_nombre, "
            "       (SELECT COUNT(*) FROM mant_visita_tareas WHERE visita_id=v.id) AS n_tareas, "
            "       (SELECT COUNT(*) FROM mant_visita_tareas WHERE visita_id=v.id AND completada=1) AS n_completas "
            "  FROM mant_visitas v "
            "  JOIN mant_clientes c ON c.id=v.cliente_id "
            "  LEFT JOIN mant_tecnicos t ON t.id=v.tecnico_id "
            f" WHERE v.fecha_programada=%s {_extra_where} "
            " ORDER BY v.hora_inicio, v.id",
            (fecha, *_extra_params)
        ) or []
        visitas = [dict(v) for v in visitas]

        # Calcular delta y overrun por visita
        for v in visitas:
            plan = v.get("duracion_planificada_min")
            real = v.get("duracion_real_min")
            if plan is None and v.get("hora_inicio") and v.get("hora_fin"):
                # Calcular plan desde hora_inicio/hora_fin si no está
                try:
                    from datetime import timedelta as _td
                    hi = v["hora_inicio"]
                    hf = v["hora_fin"]
                    # MySQL puede devolver como timedelta
                    if isinstance(hi, _td) and isinstance(hf, _td):
                        plan = int((hf - hi).total_seconds() // 60)
                        v["duracion_planificada_min"] = plan
                except Exception: pass
            if plan and real:
                v["delta_min"] = real - plan
                v["overrun_pct"] = round((real - plan) * 100.0 / plan, 1)
            else:
                v["delta_min"] = None
                v["overrun_pct"] = None

        # KPIs del día
        n_total = len(visitas)
        n_completadas = sum(1 for v in visitas if v.get("estado") == "completada")
        n_canceladas = sum(1 for v in visitas if v.get("estado") == "cancelada")
        n_en_curso = sum(1 for v in visitas if v.get("estado") in ("en_curso","programada") and v.get("hora_real_inicio"))
        n_pendientes = n_total - n_completadas - n_canceladas - n_en_curso

        # Duración total planificada vs real
        dur_plan_total = sum(v.get("duracion_planificada_min") or 0 for v in visitas)
        dur_real_total = sum(v.get("duracion_real_min") or 0 for v in visitas if v.get("duracion_real_min"))
        overrun_global = None
        if dur_plan_total > 0 and dur_real_total > 0:
            overrun_global = round((dur_real_total - dur_plan_total) * 100.0 / dur_plan_total, 1)

        # Agrupar por técnico (para heatmap)
        tecnicos_dia = {}
        for v in visitas:
            tid = v.get("tecnico_id")
            tname = v.get("tecnico_nombre") or "Sin asignar"
            if tid not in tecnicos_dia:
                tecnicos_dia[tid] = {
                    "id": tid, "nombre": tname,
                    "visitas": [], "n_visitas": 0,
                    "dur_plan_min": 0, "dur_real_min": 0,
                }
            tecnicos_dia[tid]["visitas"].append({
                "id": v["id"], "numero_ot": v.get("numero_ot"),
                "hora_inicio": str(v.get("hora_inicio") or ""),
                "hora_fin": str(v.get("hora_fin") or ""),
                "estado": v.get("estado"),
                "overrun_pct": v.get("overrun_pct"),
            })
            tecnicos_dia[tid]["n_visitas"] += 1
            tecnicos_dia[tid]["dur_plan_min"] += v.get("duracion_planificada_min") or 0
            tecnicos_dia[tid]["dur_real_min"] += v.get("duracion_real_min") or 0

        return jsonify({
            "ok": True,
            "fecha": fecha,
            "visitas": visitas,
            "kpis": {
                "total": n_total,
                "completadas": n_completadas,
                "canceladas": n_canceladas,
                "en_curso": n_en_curso,
                "pendientes": n_pendientes,
                "dur_plan_min_total": dur_plan_total,
                "dur_real_min_total": dur_real_total,
                "overrun_pct_global": overrun_global,
            },
            "tecnicos": list(tecnicos_dia.values()),
        })
    except Exception as e:
        return jsonify({"ok": False, "error": f"Error al consultar: {e}"}), 500


# ══════════════════════════════════════════════════════════════════════
# CRONÓMETRO POR TAREA — start / pause / resume / complete
#
# Cada acción del usuario inserta una fila en mant_tarea_tiempo y
# actualiza el estado de la tarea (mant_visita_tareas.estado_trabajo).
# Cuando se completa la PRIMERA tarea o la ÚLTIMA, también se ajustan
# hora_real_inicio / hora_real_fin de la visita.
#
# Endpoints:
#   POST /mantenciones/api/tareas/<tid>/cronometro
#        body: {accion: iniciar|pausar|reanudar|completar, nota?, geo?}
#   GET  /mantenciones/api/tareas/<tid>/cronometro
#        → estado actual + eventos recientes
#   GET  /mantenciones/api/visitas/<vid>/cronometro-resumen
#        → tiempo agregado de toda la visita
# ══════════════════════════════════════════════════════════════════════

def _crono_seg_desde_ultimo(tarea_id):
    """Devuelve los segundos transcurridos desde el último 'iniciar' o
    'reanudar' (sin pausar/completar posterior). 0 si no hay segmento abierto.
    """
    row = mysql_fetchone(
        "SELECT `timestamp` FROM mant_tarea_tiempo "
        " WHERE tarea_id=%s AND accion IN ('iniciar','reanudar') "
        " ORDER BY id DESC LIMIT 1",
        (tarea_id,)
    )
    if not row or not row.get("timestamp"):
        return 0
    try:
        from datetime import datetime as _dt
        ts = row["timestamp"]
        if isinstance(ts, str):
            ts = _dt.fromisoformat(ts)
        return max(0, int((_dt.now() - ts).total_seconds()))
    except Exception:
        return 0


def _crono_total_seg(tarea_id):
    """Suma todos los segmentos cerrados (pausar/completar) de la tarea."""
    row = mysql_fetchone(
        "SELECT COALESCE(SUM(duracion_segmento_seg),0) AS total "
        "  FROM mant_tarea_tiempo "
        " WHERE tarea_id=%s AND duracion_segmento_seg IS NOT NULL",
        (tarea_id,)
    )
    return int((row or {}).get("total") or 0)


@app.route("/mantenciones/api/tareas/<int:tid>/cronometro", methods=["POST"])
@_mant_required
def mant_tarea_cronometro(tid):
    """Iniciar / pausar / reanudar / completar tarea.

    Body JSON: {accion: 'iniciar'|'pausar'|'reanudar'|'completar', nota?, geo?}
    """
    d = request.get_json(silent=True) or {}
    accion = (d.get("accion") or "").strip().lower()
    if accion not in ("iniciar", "pausar", "reanudar", "completar"):
        return jsonify({"ok": False, "error": "Acción inválida"}), 400

    nota = (d.get("nota") or "").strip()[:300] or None
    geo  = (d.get("geo")  or "").strip()[:50]  or None
    user = current_username()

    # Tarea actual
    tarea = mysql_fetchone(
        "SELECT t.id, t.visita_id, t.titulo, t.completada, t.estado_trabajo, "
        "       t.pausada_acumulado_seg, t.iniciado_at "
        "  FROM mant_visita_tareas t WHERE t.id=%s",
        (tid,)
    )
    if not tarea:
        return jsonify({"ok": False, "error": "Tarea no encontrada"}), 404
    tarea = dict(tarea)
    vid   = tarea["visita_id"]

    # 🔐 SEGURIDAD (2026-05-17): si es técnico/tecnico_externo, validar
    # ownership por la visita asociada a la tarea (endpoint usa <tid>, no <vid>).
    u_curr = getattr(g, "user", None) or {}
    role_curr = (u_curr.get("role") or "").lower()
    if role_curr in ("tecnico", "tecnico_externo"):
        uid_curr = u_curr.get("id")
        ok_owner = None
        if uid_curr:
            ok_owner = mysql_fetchone(
                "SELECT 1 AS x FROM mant_visitas "
                " WHERE id=%s AND tecnico_user_id=%s "
                "UNION ALL "
                "SELECT 1 FROM mant_visita_tecnicos "
                " WHERE visita_id=%s AND tecnico_user_id=%s "
                "LIMIT 1",
                (vid, uid_curr, vid, uid_curr)
            )
        if not ok_owner:
            print(
                f"[SECURITY] {uid_curr} ({u_curr.get('username')}) intento "
                f"cronometro tid={tid} (vid={vid}) sin asignacion (role={role_curr})",
                flush=True
            )
            return jsonify({"ok": False, "error": "No estás asignado a esta OT"}), 403

    estado_actual = tarea.get("estado_trabajo") or "pendiente"

    # Validaciones de transición
    if accion == "iniciar" and estado_actual not in ("pendiente", "pausada"):
        return jsonify({"ok": False, "error": f"No se puede iniciar (estado actual: {estado_actual})"}), 409
    if accion == "pausar" and estado_actual != "en_curso":
        return jsonify({"ok": False, "error": "Solo se puede pausar una tarea en curso"}), 409
    if accion == "reanudar" and estado_actual != "pausada":
        return jsonify({"ok": False, "error": "Solo se puede reanudar una tarea pausada"}), 409
    if accion == "completar" and estado_actual == "completada":
        return jsonify({"ok": False, "error": "La tarea ya está completada"}), 409

    # Tecnico (intentar deducir desde visita)
    tecnico_id = None
    try:
        trow = mysql_fetchone(
            "SELECT tecnico_id FROM mant_visita_tecnicos WHERE visita_id=%s LIMIT 1",
            (vid,)
        )
        if trow and trow.get("tecnico_id"):
            tecnico_id = int(trow["tecnico_id"])
        else:
            vrow = mysql_fetchone("SELECT tecnico_id FROM mant_visitas WHERE id=%s", (vid,))
            if vrow and vrow.get("tecnico_id"):
                tecnico_id = int(vrow["tecnico_id"])
    except Exception:
        pass

    # Calcular segundos del segmento actual cuando se cierra
    seg_segmento = None
    if accion in ("pausar", "completar"):
        seg_segmento = _crono_seg_desde_ultimo(tid)

    # Insertar evento
    mysql_execute(
        "INSERT INTO mant_tarea_tiempo (tarea_id, visita_id, tecnico_id, accion, "
        "                               duracion_segmento_seg, nota, geo, creado_por) "
        "VALUES (%s,%s,%s,%s,%s,%s,%s,%s)",
        (tid, vid, tecnico_id, accion, seg_segmento, nota, geo, user)
    )

    # Actualizar tarea según acción
    if accion == "iniciar":
        # Marcar iniciado_at sólo la primera vez
        if not tarea.get("iniciado_at"):
            mysql_execute(
                "UPDATE mant_visita_tareas SET estado_trabajo='en_curso', "
                "       iniciado_at=NOW() WHERE id=%s",
                (tid,)
            )
        else:
            mysql_execute(
                "UPDATE mant_visita_tareas SET estado_trabajo='en_curso' WHERE id=%s",
                (tid,)
            )
        # ¿Primera tarea de la visita en iniciarse?  → marcar hora_real_inicio
        try:
            otras_iniciadas = mysql_fetchone(
                "SELECT COUNT(*) AS n FROM mant_visita_tareas "
                " WHERE visita_id=%s AND iniciado_at IS NOT NULL AND id<>%s",
                (vid, tid)
            )
            visita_row = mysql_fetchone(
                "SELECT hora_real_inicio FROM mant_visitas WHERE id=%s", (vid,)
            )
            if (otras_iniciadas or {}).get("n", 0) == 0 and not (visita_row or {}).get("hora_real_inicio"):
                mysql_execute(
                    "UPDATE mant_visitas SET hora_real_inicio=NOW(), "
                    "       estado=CASE WHEN estado='programada' THEN 'en_curso' ELSE estado END "
                    " WHERE id=%s",
                    (vid,)
                )
        except Exception:
            pass

    elif accion == "pausar":
        mysql_execute(
            "UPDATE mant_visita_tareas "
            "   SET estado_trabajo='pausada', "
            "       pausada_acumulado_seg = COALESCE(pausada_acumulado_seg,0) + %s "
            " WHERE id=%s",
            (seg_segmento or 0, tid)
        )

    elif accion == "reanudar":
        mysql_execute(
            "UPDATE mant_visita_tareas SET estado_trabajo='en_curso' WHERE id=%s",
            (tid,)
        )

    elif accion == "completar":
        # Sumar duración total acumulada (segmentos cerrados) en minutos
        total_seg = _crono_total_seg(tid)
        # Sumar el segmento que recién cerramos (si la tarea estaba en_curso)
        if estado_actual == "en_curso" and seg_segmento:
            total_seg += seg_segmento
        duracion_min = max(1, round(total_seg / 60.0)) if total_seg else None
        mysql_execute(
            "UPDATE mant_visita_tareas "
            "   SET estado_trabajo='completada', "
            "       completada=1, "
            "       completada_at=NOW(), "
            "       completada_por=%s, "
            "       duracion_min=COALESCE(%s, duracion_min) "
            " WHERE id=%s",
            (user, duracion_min, tid)
        )

        # ¿Todas las tareas de la visita completadas? → cerrar visita
        try:
            stats = mysql_fetchone(
                "SELECT COUNT(*) AS total, "
                "       SUM(CASE WHEN completada=1 THEN 1 ELSE 0 END) AS completas "
                "  FROM mant_visita_tareas WHERE visita_id=%s",
                (vid,)
            ) or {}
            if stats.get("total") and stats.get("total") == stats.get("completas"):
                # Calcular duracion_real_min desde hora_real_inicio
                vis = mysql_fetchone(
                    "SELECT hora_real_inicio FROM mant_visitas WHERE id=%s", (vid,)
                )
                dur_real = None
                if vis and vis.get("hora_real_inicio"):
                    try:
                        from datetime import datetime as _dt
                        hi = vis["hora_real_inicio"]
                        if isinstance(hi, str):
                            hi = _dt.fromisoformat(hi)
                        dur_real = max(1, int((_dt.now() - hi).total_seconds() / 60))
                    except Exception:
                        pass
                mysql_execute(
                    "UPDATE mant_visitas "
                    "   SET hora_real_fin=NOW(), "
                    "       duracion_real_min=COALESCE(%s, duracion_real_min) "
                    " WHERE id=%s",
                    (dur_real, vid)
                )
        except Exception:
            pass

    # Log
    try:
        mysql_execute(
            "INSERT INTO mant_logs (entidad, entidad_id, accion, detalle, usuario) "
            "VALUES ('tarea', %s, %s, %s, %s)",
            (tid, f"cronometro_{accion}", tarea.get("titulo") or f"tid={tid}", user)
        )
    except Exception:
        pass

    # Estado actualizado para devolver al frontend
    tarea_upd = mysql_fetchone(
        "SELECT id, estado_trabajo, iniciado_at, completada, completada_at, "
        "       duracion_min, duracion_estimada_min, pausada_acumulado_seg "
        "  FROM mant_visita_tareas WHERE id=%s",
        (tid,)
    ) or {}
    return jsonify({
        "ok": True,
        "accion": accion,
        "tarea": {
            "id": tid,
            "estado_trabajo": (tarea_upd or {}).get("estado_trabajo"),
            "iniciado_at": str((tarea_upd or {}).get("iniciado_at") or "") or None,
            "completada": bool((tarea_upd or {}).get("completada")),
            "completada_at": str((tarea_upd or {}).get("completada_at") or "") or None,
            "duracion_min": (tarea_upd or {}).get("duracion_min"),
            "duracion_estimada_min": (tarea_upd or {}).get("duracion_estimada_min"),
            "pausada_acumulado_seg": (tarea_upd or {}).get("pausada_acumulado_seg"),
        },
        "duracion_segmento_seg": seg_segmento,
        "duracion_total_seg": _crono_total_seg(tid),
    })


@app.route("/mantenciones/api/tareas/<int:tid>/cronometro", methods=["GET"])
@_mant_required
def mant_tarea_cronometro_get(tid):
    """Devuelve estado actual del cronómetro + últimos 20 eventos."""
    tarea = mysql_fetchone(
        "SELECT id, visita_id, titulo, completada, estado_trabajo, "
        "       iniciado_at, completada_at, duracion_min, duracion_estimada_min, "
        "       pausada_acumulado_seg "
        "  FROM mant_visita_tareas WHERE id=%s",
        (tid,)
    )
    if not tarea:
        return jsonify({"ok": False, "error": "Tarea no encontrada"}), 404

    # 🔐 SEGURIDAD (2026-05-17): tarea pertenece a una visita — verificar
    # ownership si el actor es técnico/tecnico_externo (endpoint sin <vid>).
    vid_chk = dict(tarea).get("visita_id")
    u_curr = getattr(g, "user", None) or {}
    role_curr = (u_curr.get("role") or "").lower()
    if role_curr in ("tecnico", "tecnico_externo") and vid_chk:
        uid_curr = u_curr.get("id")
        ok_owner = None
        if uid_curr:
            ok_owner = mysql_fetchone(
                "SELECT 1 AS x FROM mant_visitas "
                " WHERE id=%s AND tecnico_user_id=%s "
                "UNION ALL "
                "SELECT 1 FROM mant_visita_tecnicos "
                " WHERE visita_id=%s AND tecnico_user_id=%s "
                "LIMIT 1",
                (vid_chk, uid_curr, vid_chk, uid_curr)
            )
        if not ok_owner:
            print(
                f"[SECURITY] {uid_curr} ({u_curr.get('username')}) intento "
                f"cronometro_get tid={tid} (vid={vid_chk}) sin asignacion",
                flush=True
            )
            return jsonify({"ok": False, "error": "No estás asignado a esta OT"}), 403

    eventos = mysql_fetchall(
        "SELECT id, accion, `timestamp`, duracion_segmento_seg, nota, creado_por "
        "  FROM mant_tarea_tiempo WHERE tarea_id=%s ORDER BY id DESC LIMIT 20",
        (tid,)
    ) or []
    seg_abierto = 0
    if (dict(tarea).get("estado_trabajo")) == "en_curso":
        seg_abierto = _crono_seg_desde_ultimo(tid)
    return jsonify({
        "ok": True,
        "tarea": {
            **dict(tarea),
            "iniciado_at": str(dict(tarea).get("iniciado_at") or "") or None,
            "completada_at": str(dict(tarea).get("completada_at") or "") or None,
        },
        "eventos": [
            {
                "id": e["id"], "accion": e["accion"],
                "timestamp": str(e.get("timestamp") or ""),
                "duracion_segmento_seg": e.get("duracion_segmento_seg"),
                "nota": e.get("nota"),
                "creado_por": e.get("creado_por"),
            } for e in eventos
        ],
        "duracion_total_seg": _crono_total_seg(tid),
        "segmento_abierto_seg": seg_abierto,
    })


@app.route("/mantenciones/api/visitas/<int:vid>/cronometro-resumen", methods=["GET"])
@_mant_required
@_ot_can_view
def mant_visita_cronometro_resumen(vid):
    """Resumen de tiempo de toda la visita (todas las tareas)."""
    visita = mysql_fetchone(
        "SELECT id, numero_ot, hora_real_inicio, hora_real_fin, "
        "       duracion_real_min, duracion_planificada_min, pausada_total_min "
        "  FROM mant_visitas WHERE id=%s",
        (vid,)
    )
    if not visita:
        return jsonify({"ok": False, "error": "Visita no encontrada"}), 404
    tareas = mysql_fetchall(
        "SELECT id, titulo, estado_trabajo, iniciado_at, completada_at, "
        "       duracion_min, duracion_estimada_min, pausada_acumulado_seg, "
        "       completada "
        "  FROM mant_visita_tareas WHERE visita_id=%s ORDER BY orden, id",
        (vid,)
    ) or []
    tareas = [dict(t) for t in tareas]
    # Sumar todas las duraciones reales
    real_total_min = 0
    estimado_total_min = 0
    for t in tareas:
        if t.get("duracion_min"):
            real_total_min += int(t["duracion_min"])
        elif t.get("estado_trabajo") == "en_curso":
            # Tiempo vivo: sumar todos los segmentos cerrados + segmento abierto
            real_total_min += round((_crono_total_seg(t["id"]) + _crono_seg_desde_ultimo(t["id"])) / 60.0)
        if t.get("duracion_estimada_min"):
            estimado_total_min += int(t["duracion_estimada_min"])

    return jsonify({
        "ok": True,
        "visita": {
            "id": visita["id"],
            "numero_ot": visita.get("numero_ot"),
            "hora_real_inicio": str(visita.get("hora_real_inicio") or "") or None,
            "hora_real_fin": str(visita.get("hora_real_fin") or "") or None,
            "duracion_real_min": visita.get("duracion_real_min"),
            "duracion_planificada_min": visita.get("duracion_planificada_min"),
        },
        "tareas_resumen": {
            "n_total": len(tareas),
            "n_completadas": sum(1 for t in tareas if t.get("completada")),
            "n_en_curso":    sum(1 for t in tareas if t.get("estado_trabajo") == "en_curso"),
            "n_pausadas":    sum(1 for t in tareas if t.get("estado_trabajo") == "pausada"),
            "real_min_total": real_total_min,
            "estimado_min_total": estimado_total_min,
        },
        "tareas": [
            {
                "id": t["id"], "titulo": t.get("titulo"),
                "estado_trabajo": t.get("estado_trabajo"),
                "duracion_min": t.get("duracion_min"),
                "duracion_estimada_min": t.get("duracion_estimada_min"),
                "completada": bool(t.get("completada")),
            } for t in tareas
        ],
    })


# ══════════════════════════════════════════════════════════════════════
# FLUJO DE OT: programada → en_curso → completada (con 3 firmas)
#
# Reglas:
#   - INICIAR (programada → en_curso): solo el técnico asignado
#     (visita.tecnico_user_id) o un admin/supervisor.
#   - FIRMAR: 3 firmas obligatorias para cerrar.
#       firma_cliente   → cualquier usuario puede capturar (el cliente firma
#                         en el dispositivo del técnico).
#       firma_tecnico   → solo el usuario cuyo id == visita.tecnico_user_id.
#       firma_supervisor→ solo el usuario cuyo id == visita.created_by_id
#                         (quien asignó la OT) o un admin/superadmin.
#   - CERRAR: requiere las 3 firmas presentes. Si falta alguna → 400.
# ══════════════════════════════════════════════════════════════════════

def _ot_es_admin_o_super():
    """True si el usuario actual puede actuar como supervisor de cualquier OT."""
    if not g.permissions:
        return False
    return bool(g.permissions.get("superadmin") or g.permissions.get("admin"))


def _ot_visita_basic(vid):
    """Lee la OT con campos necesarios para validar permisos de acción."""
    return mysql_fetchone(
        "SELECT id, estado, tecnico_user_id, created_by, "
        "       firma_cliente_url, firma_tecnico_url, firma_supervisor_url "
        "  FROM mant_visitas WHERE id=%s",
        (vid,)
    )


@app.route("/mantenciones/api/visitas/<int:vid>/iniciar", methods=["POST"])
@_mant_required
@_tecnico_owns_visita
def mant_visita_iniciar(vid):
    """Cambia el estado de 'programada' a 'en_curso'. Solo el técnico asignado
    (o un admin/supervisor) puede iniciar el trabajo. Setea hora_real_inicio
    si todavía no estaba."""
    v = _ot_visita_basic(vid)
    if not v:
        return jsonify({"ok": False, "error": "OT no encontrada"}), 404
    if v["estado"] not in ("programada",):
        return jsonify({"ok": False, "error": f"La OT ya está en estado '{v['estado']}'. Solo se puede iniciar desde 'programada'."}), 400
    uid = (g.user or {}).get("id")
    if not uid:
        return jsonify({"ok": False, "error": "Sesión inválida"}), 401
    # 🔐 2026-05-18 — La verificación de "técnico asignado o superadmin"
    # ya la hace el decorador @_tecnico_owns_visita (strict). Acá solo
    # validamos coherencia adicional (ej. hay técnico asignado de verdad).
    asignado = v.get("tecnico_user_id")
    if not asignado:
        # Permitir si es superadmin (puede iniciar OTs sin asignar)
        _u = getattr(g, "user", None) or {}
        if (_u.get("role") or "").lower() != "superadmin":
            return jsonify({"ok": False, "error": "Esta OT no tiene técnico asignado todavía. Pide al supervisor que asigne uno."}), 400
    mysql_execute(
        "UPDATE mant_visitas "
        "   SET estado='en_curso', "
        "       hora_real_inicio=COALESCE(hora_real_inicio, NOW()) "
        " WHERE id=%s",
        (vid,)
    )
    try:
        mysql_execute(
            "INSERT INTO mant_logs (entidad, entidad_id, accion, detalle, usuario) "
            "VALUES ('visita', %s, 'iniciada', %s, %s)",
            (vid, "OT pasada a en_curso", current_username())
        )
    except Exception:
        pass
    return jsonify({"ok": True, "estado": "en_curso"})


@app.route("/mantenciones/api/visitas/<int:vid>/firmar", methods=["POST"])
@_mant_required
def mant_visita_firmar(vid):
    """Guarda una de las 3 firmas (cliente / tecnico / supervisor).
    Body: {"tipo": "cliente"|"tecnico"|"supervisor",
           "firma": "data:image/png;base64,...",
           "nombre": "Juan Pérez"  // solo para cliente }

    🔐 SEGURIDAD 2026-05-18: no se aplica decorador genérico porque cada
    `tipo` de firma tiene su propia regla de quién puede hacerla:
      - cliente   → técnico asignado + superadmin (el técnico captura la
                    firma del cliente en su dispositivo).
      - tecnico   → solo el técnico asignado + superadmin.
      - supervisor→ admin/superadmin + creador de la OT.
    Las validaciones por-tipo están más abajo. Aquí filtramos por la
    acción genérica 'ver' (cualquiera con vista válida puede ENTRAR al
    endpoint, pero recibe 403 si el tipo no le corresponde).
    """
    if not _puede_ot_accion(vid, "ver"):
        u = getattr(g, "user", None) or {}
        return _ot_403_response(
            vid, (u.get("role") or "").lower(),
            u.get("id"), u.get("username"), accion="ver",
        )
    v = _ot_visita_basic(vid)
    if not v:
        return jsonify({"ok": False, "error": "OT no encontrada"}), 404
    d = request.get_json(silent=True) or {}
    tipo = (d.get("tipo") or "").strip().lower()
    firma = (d.get("firma") or "").strip()
    if tipo not in ("cliente", "tecnico", "supervisor"):
        return jsonify({"ok": False, "error": "tipo debe ser cliente|tecnico|supervisor"}), 400
    if not firma or not firma.startswith("data:image/"):
        return jsonify({"ok": False, "error": "firma vacía o formato inválido (debe ser data URL de imagen)"}), 400
    uid = (g.user or {}).get("id")
    if not uid:
        return jsonify({"ok": False, "error": "Sesión inválida"}), 401

    # Validaciones de identidad por tipo de firma (matriz 2026-05-18)
    if tipo == "tecnico":
        # Solo técnico asignado + superadmin (acción 'ejecutar').
        if not _puede_ot_accion(vid, "ejecutar"):
            return jsonify({"ok": False, "error": "Solo el técnico asignado puede firmar como técnico."}), 403
    elif tipo == "supervisor":
        # admin/superadmin + creador de la OT (acción 'firmar_creador').
        if not _puede_ot_accion(vid, "firmar_creador"):
            return jsonify({"ok": False, "error": "Solo el supervisor que asignó esta OT (o un admin) puede firmar."}), 403
    elif tipo == "cliente":
        # El cliente firma en el dispositivo del técnico → solo el técnico
        # asignado + superadmin pueden capturarla. Antes no se validaba y
        # cualquier rol con permiso 'mantenciones' podía falsificar la firma
        # del cliente desde otra sesión (IDOR).
        if not _puede_ot_accion(vid, "ejecutar"):
            return jsonify({"ok": False, "error": "Solo el técnico asignado puede capturar la firma del cliente."}), 403

    nombre = (d.get("nombre") or "").strip()[:200] or None
    # 2026-05-18 — Si no llegó `nombre`, usar el display name del firmante
    # (excepto cliente, donde el campo es responsabilidad del operador en sitio).
    _u_sig = getattr(g, "user", None) or {}
    _default_nom = (_u_sig.get("nombre") or _u_sig.get("username") or "")[:200] or None

    if tipo == "cliente":
        mysql_execute(
            "UPDATE mant_visitas SET firma_cliente_url=%s, firma_cliente_nombre=%s, "
            "       firma_cliente_at=NOW() WHERE id=%s",
            (firma, nombre, vid)
        )
    elif tipo == "tecnico":
        mysql_execute(
            "UPDATE mant_visitas SET firma_tecnico_url=%s, firma_tecnico_user_id=%s, "
            "       firma_tecnico_nombre=%s, firma_tecnico_at=NOW() WHERE id=%s",
            (firma, uid, (nombre or _default_nom), vid)
        )
    else:  # supervisor
        mysql_execute(
            "UPDATE mant_visitas SET firma_supervisor_url=%s, firma_supervisor_user_id=%s, "
            "       firma_supervisor_nombre=%s, firma_supervisor_at=NOW() WHERE id=%s",
            (firma, uid, (nombre or _default_nom), vid)
        )

    try:
        mysql_execute(
            "INSERT INTO mant_logs (entidad, entidad_id, accion, detalle, usuario) "
            "VALUES ('visita', %s, 'firma', %s, %s)",
            (vid, f"Firma capturada — tipo={tipo}", current_username())
        )
    except Exception:
        pass
    return jsonify({"ok": True, "tipo": tipo})


# ══════════════════════════════════════════════════════════════════════
# CIERRE DE OT — captura causa raíz, satisfacción y comentario
# Requiere: las 3 firmas (cliente, técnico, supervisor) presentes.
# ══════════════════════════════════════════════════════════════════════

def _ot_validar_cierre(vid):
    """FASE 5 — Validación de cierre auditable de OT con 4 reglas que el
    usuario aprobó. Devuelve dict con resultado:
      {"puede_cerrar": bool, "razones": [list de razones bloqueantes]}

    Reglas (todas obligatorias salvo que la OT sea de tipo levantamiento
    que tiene sus propias reglas más laxas):
      R1. Checklist 100% completado (todas las tareas con estado_trabajo='completada')
      R2. Diagnóstico obligatorio (mant_visitas.diagnostico no vacío, mín 20 chars)
      R3. Foto obligatoria por cada tarea con requiere_foto=1 (debe tener ≥1 foto)
      R4. Las 3 firmas presentes (cliente, técnico, supervisor)

    Las OT tipo 'levantamiento' eximen R2 (diagnóstico autogenerado al cerrar).
    """
    v = mysql_fetchone(
        "SELECT id, tipo, estado, diagnostico, levantamiento_id, "
        "       firma_cliente_url, firma_tecnico_url, firma_supervisor_url "
        "  FROM mant_visitas WHERE id=%s",
        (vid,)
    )
    if not v:
        return {"puede_cerrar": False, "razones": ["OT no encontrada"]}

    razones = []
    # FIX 2026-05-22 (Daniel — caso Vitacura OT 161/162/163): tratamos como
    # "levantamiento" (reglas de cierre más laxas: sin diagnóstico, sin
    # checklist obligatorio) TANTO las OT tipo='levantamiento' COMO las
    # que tienen levantamiento_id poblado (creadas desde el modal del
    # cliente con dropdown distinto a 'levantamiento'). En ambos casos el
    # foco es capturar datos del equipo (fotos, marca/modelo/serie), no
    # ejecutar un checklist clínico.
    es_levantamiento = (
        (v.get("tipo") or "").lower() == "levantamiento"
        or bool(v.get("levantamiento_id"))
    )

    # ── 2026-05-21 (Daniel) — Trazabilidad por equipo ──────────────────
    # Si la OT es tipo 'levantamiento', el técnico puede SALTAR equipos
    # (con razón + observación). Las tareas de un equipo saltado NO
    # bloquean el cierre. Tampoco bloquean las del equipo marcado como
    # 'falla_detectada' (ya quedó registrada la incidencia).
    # Equipos saltados/con falla por visita: set de maquina_id excluidos
    # del check de "tareas completas".
    excluir_maquinas = set()
    try:
        rows_excl = mysql_fetchall(
            "SELECT maquina_id, estado_revision FROM mant_visita_equipos "
            " WHERE visita_id=%s "
            "   AND estado_revision IN ('saltado','falla_detectada')",
            (vid,)
        ) or []
        for r in rows_excl:
            if r.get("maquina_id"):
                excluir_maquinas.add(int(r["maquina_id"]))
    except Exception:
        # Tabla nueva — si aún no se creó, no excluimos nada (comp. atrás).
        excluir_maquinas = set()

    # R1 — Checklist 100% completado (excluyendo tareas de equipos saltados/con falla)
    if excluir_maquinas:
        _ph = ",".join(["%s"] * len(excluir_maquinas))
        chk_row = mysql_fetchone(
            "SELECT COUNT(*) AS total, "
            " SUM(CASE WHEN estado_trabajo='completada' OR completada=1 THEN 1 ELSE 0 END) AS done "
            f"FROM mant_visita_tareas WHERE visita_id=%s "
            f"  AND (maquina_id IS NULL OR maquina_id NOT IN ({_ph}))",
            (vid, *list(excluir_maquinas))
        ) or {}
    else:
        chk_row = mysql_fetchone(
            "SELECT COUNT(*) AS total, "
            " SUM(CASE WHEN estado_trabajo='completada' OR completada=1 THEN 1 ELSE 0 END) AS done "
            "FROM mant_visita_tareas WHERE visita_id=%s",
            (vid,)
        ) or {}
    total = int(chk_row.get("total") or 0)
    done = int(chk_row.get("done") or 0)
    # FIX 2026-05-21: si es un levantamiento, NO exigimos tareas explícitas.
    # El audit trail por equipo lo lleva mant_visita_equipos
    # (verificado/saltado/con_cambios/falla). Para preventivas/correctivas
    # sí se sigue exigiendo checklist para no perder control de calidad.
    if total == 0 and not excluir_maquinas and not es_levantamiento:
        razones.append("La OT no tiene tareas asignadas — agrega un checklist antes de cerrar.")
    elif done < total:
        razones.append(
            f"Checklist incompleto: {done}/{total} tareas completadas. "
            f"Faltan {total - done} por marcar."
        )

    # R2 — Diagnóstico obligatorio (excepto levantamiento)
    if not es_levantamiento:
        diag = (v.get("diagnostico") or "").strip()
        if len(diag) < 20:
            razones.append(
                "Diagnóstico obligatorio: debe explicar qué se hizo (mínimo 20 caracteres)."
            )

    # R3 — Foto obligatoria por tarea con requiere_foto=1 (excluyendo saltados)
    if excluir_maquinas:
        _ph = ",".join(["%s"] * len(excluir_maquinas))
        tareas_sin_foto = mysql_fetchall(
            "SELECT t.id, t.titulo "
            "FROM mant_visita_tareas t "
            "LEFT JOIN mant_visita_fotos f ON f.tarea_id=t.id "
            f"WHERE t.visita_id=%s AND t.requiere_foto=1 "
            f"  AND (t.maquina_id IS NULL OR t.maquina_id NOT IN ({_ph})) "
            "GROUP BY t.id, t.titulo "
            "HAVING COUNT(f.id) = 0",
            (vid, *list(excluir_maquinas))
        ) or []
    else:
        tareas_sin_foto = mysql_fetchall(
            "SELECT t.id, t.titulo "
            "FROM mant_visita_tareas t "
            "LEFT JOIN mant_visita_fotos f ON f.tarea_id=t.id "
            "WHERE t.visita_id=%s AND t.requiere_foto=1 "
            "GROUP BY t.id, t.titulo "
            "HAVING COUNT(f.id) = 0",
            (vid,)
        ) or []
    if tareas_sin_foto:
        nombres = [t.get("titulo") or f"#{t['id']}" for t in tareas_sin_foto[:5]]
        suf = "" if len(tareas_sin_foto) <= 5 else f" y {len(tareas_sin_foto)-5} más"
        razones.append(
            f"Falta foto en {len(tareas_sin_foto)} tarea(s): {', '.join(nombres)}{suf}"
        )

    # R4 — Las 3 firmas
    if not v.get("firma_cliente_url"):    razones.append("Falta firma del cliente.")
    if not v.get("firma_tecnico_url"):    razones.append("Falta firma del técnico.")
    if not v.get("firma_supervisor_url"): razones.append("Falta firma del supervisor.")

    return {
        "puede_cerrar": len(razones) == 0,
        "razones": razones,
        "total_tareas": total,
        "tareas_completadas": done,
        "tareas_sin_foto": len(tareas_sin_foto),
        "tiene_diagnostico": bool((v.get("diagnostico") or "").strip()),
        "firmas_ok": all([v.get("firma_cliente_url"), v.get("firma_tecnico_url"), v.get("firma_supervisor_url")]),
        "equipos_excluidos": len(excluir_maquinas),
    }


@app.route("/mantenciones/api/visitas/<int:vid>/validacion-cierre", methods=["GET"])
@_mant_required
@_ot_can_view
def mant_visita_validacion_cierre(vid):
    """Endpoint que devuelve si la OT cumple las 4 reglas de cierre.
    El frontend lo llama para mostrar el estado del cierre antes de
    intentar cerrar — feedback inmediato al técnico."""
    return jsonify({"ok": True, **_ot_validar_cierre(vid)})


@app.route("/mantenciones/api/visitas/<int:vid>/cerrar", methods=["POST"])
@_mant_required
@_tecnico_owns_visita
def mant_visita_cerrar(vid):
    """Cierra la visita aplicando las 4 reglas de cierre auditable (FASE 5).
    Bloquea cierre si falta alguna:
      R1. Checklist 100% completado
      R2. Diagnóstico (mín 20 chars, excepto levantamientos)
      R3. Foto en tareas requiere_foto=1
      R4. Las 3 firmas (cliente, técnico, supervisor)
    """
    v = _ot_visita_basic(vid)
    if not v:
        return jsonify({"ok": False, "error": "OT no encontrada"}), 404

    d = request.get_json(silent=True) or {}

    # Si llega un diagnóstico en este request, guardarlo ANTES de validar
    # (para que el técnico pueda cerrar en un solo paso con el modal)
    diag_nuevo = (d.get("diagnostico") or "").strip()
    if diag_nuevo:
        mysql_execute(
            "UPDATE mant_visitas SET diagnostico=%s WHERE id=%s",
            (diag_nuevo[:5000], vid)
        )

    # Aplicar las 4 reglas de cierre auditable
    validacion = _ot_validar_cierre(vid)
    if not validacion["puede_cerrar"]:
        return jsonify({
            "ok": False,
            "error": "No se puede cerrar la OT — faltan requisitos:",
            "error_codigo": "CIERRE_BLOQUEADO",
            "razones": validacion["razones"],
            "validacion": validacion,
        }), 400

    causa = (d.get("causa_raiz") or "").strip().lower() or None
    if causa and causa not in ("desgaste","mal_uso","falta_mantencion","defecto_fabrica","accidente","otro"):
        causa = "otro"
    estrellas = d.get("satisfaccion_estrellas")
    try:
        estrellas = int(estrellas) if estrellas not in (None, "") else None
        if estrellas is not None and (estrellas < 1 or estrellas > 5):
            estrellas = max(1, min(5, estrellas))
    except (TypeError, ValueError):
        estrellas = None
    comentario = (d.get("comentario") or "").strip()[:1000] or None
    user = current_username()
    mysql_execute(
        "UPDATE mant_visitas "
        "   SET estado='cerrada', "
        "       cerrada_at=NOW(), "
        "       cerrada_por=%s, "
        "       causa_raiz=COALESCE(%s, causa_raiz), "
        "       satisfaccion_estrellas=COALESCE(%s, satisfaccion_estrellas), "
        "       satisfaccion_comentario=COALESCE(%s, satisfaccion_comentario), "
        "       hora_real_fin=COALESCE(hora_real_fin, NOW()) "
        " WHERE id=%s",
        (user, causa, estrellas, comentario, vid)
    )
    try:
        mysql_execute(
            "INSERT INTO mant_logs (entidad, entidad_id, accion, detalle, usuario) "
            "VALUES ('visita', %s, 'cerrada', %s, %s)",
            (vid,
             f"OT cerrada (auditable) — causa: {causa or '—'} · "
             f"estrellas: {estrellas or '—'} · "
             f"{validacion['tareas_completadas']}/{validacion['total_tareas']} tareas · "
             f"firmas: {'OK' if validacion['firmas_ok'] else 'INCOMPLETO'}",
             user)
        )
    except Exception:
        pass
    # ── 2026-05-21 (Daniel) — Trazabilidad por equipo ──────────────────
    # Al cerrar la OT, todo equipo que esté en mant_visita_tareas pero
    # que NO tenga fila en mant_visita_equipos se inserta como
    # 'verificado' (default). Esto deja audit trail aunque el técnico
    # haya cerrado sin tocar nada en ese equipo.
    try:
        mysql_execute(
            "INSERT IGNORE INTO mant_visita_equipos "
            "  (visita_id, maquina_id, estado_revision, revisado_at, revisado_por) "
            "SELECT DISTINCT vt.visita_id, vt.maquina_id, 'verificado', NOW(), %s "
            "  FROM mant_visita_tareas vt "
            " WHERE vt.visita_id=%s AND vt.maquina_id IS NOT NULL",
            (user, vid)
        )
    except Exception as _e_vme:
        print(f"[ot_cerrar] mant_visita_equipos autofill error: {_e_vme}", flush=True)

    # ── Promoción levantamiento → ficha de equipo (async, no bloquea) ──
    # Aplica cuando la visita es tipo='levantamiento' O tiene levantamiento_id
    # poblado (caso Vitacura — preventiva creada desde modal del cliente).
    # El wrapper interno (_promover_levantamiento_a_maquina) hace el filtro
    # fino y descarta silenciosamente si no corresponde.
    _promover_levantamiento_async(vid, usuario=user)
    return jsonify({
        "ok": True,
        "estado": "cerrada",
        "validacion": validacion,
        "mensaje": "OT cerrada exitosamente con auditoría completa.",
    })


# ══════════════════════════════════════════════════════════════════════
# TRAZABILIDAD POR EQUIPO EN VISITA (2026-05-21 Daniel)
# Permite que el técnico SALTE un equipo durante el levantamiento sin
# completar sus tareas, marque "con cambios" o "falla detectada", o
# deje una observación libre. Cada decisión queda con audit trail.
# ══════════════════════════════════════════════════════════════════════

# Razones válidas para saltar un equipo. Cualquier otra cae como 'otro'.
_RAZONES_SALTADO_VALIDAS = (
    "no_encontrado", "dado_de_baja", "danado_inaccesible",
    "cliente_lo_quito", "otro",
    # 2026-05-31 (Fase 3 — cobertura de tareas): causales ampliadas. Una tarea/
    # equipo no ejecutado debe quedar con una causal clara + observación
    # obligatoria (ya exigida, mín. 5 chars). No se borran las antiguas (compat).
    "sin_acceso", "cliente_no_permite", "equipo_en_uso", "sin_energia",
    "requiere_repuesto", "reagendar", "no_aplica",
)

# Estados válidos para el campo estado_revision.
_ESTADOS_REVISION_VALIDOS = (
    "verificado", "con_cambios", "saltado", "falla_detectada"
)


def _ot_visita_equipo_link_ok(vid, mid):
    """Valida que el equipo `mid` pertenezca realmente a la visita `vid`
    (ya sea via mant_visita_tareas o mant_visita_equipos previo). Evita
    que un técnico marque equipos ajenos a su OT (IDOR)."""
    try:
        r = mysql_fetchone(
            "SELECT 1 FROM mant_visita_tareas "
            " WHERE visita_id=%s AND maquina_id=%s LIMIT 1",
            (vid, mid)
        )
        if r:
            return True
        # Fallback: ya estaba registrado en mant_visita_equipos
        r2 = mysql_fetchone(
            "SELECT 1 FROM mant_visita_equipos "
            " WHERE visita_id=%s AND maquina_id=%s LIMIT 1",
            (vid, mid)
        )
        return bool(r2)
    except Exception:
        return False


@app.route(
    "/mantenciones/api/visitas/<int:vid>/equipos/<int:mid>/saltar",
    methods=["POST"]
)
@_mant_required
@_tecnico_owns_visita
def mant_visita_equipo_saltar(vid, mid):
    """El técnico salta un equipo durante la OT: registra razón +
    observación obligatoria (mín 5 chars). Idempotente vía upsert.
    """
    if not _ot_visita_equipo_link_ok(vid, mid):
        return jsonify({"ok": False, "error": "Equipo no pertenece a esta OT"}), 404

    d = request.get_json(silent=True) or {}
    razon_raw = (d.get("razon") or "").strip().lower()
    razon = razon_raw if razon_raw in _RAZONES_SALTADO_VALIDAS else "otro"
    obs = (d.get("observacion") or "").strip()
    if len(obs) < 5:
        return jsonify({
            "ok": False,
            "error": "La observación es obligatoria (mínimo 5 caracteres)."
        }), 400
    obs = obs[:2000]  # cap razonable

    user = current_username()
    try:
        mysql_execute(
            "INSERT INTO mant_visita_equipos "
            "  (visita_id, maquina_id, estado_revision, razon_saltado, "
            "   observacion_tecnico, revisado_at, revisado_por) "
            "VALUES (%s, %s, 'saltado', %s, %s, NOW(), %s) "
            "ON DUPLICATE KEY UPDATE "
            "  estado_revision='saltado', "
            "  razon_saltado=VALUES(razon_saltado), "
            "  observacion_tecnico=VALUES(observacion_tecnico), "
            "  revisado_at=NOW(), "
            "  revisado_por=VALUES(revisado_por)",
            (vid, mid, razon, obs, user)
        )
    except Exception as e:
        print(f"[visita_equipo_saltar] error vid={vid} mid={mid}: {e}", flush=True)
        return jsonify({"ok": False, "error": "No se pudo guardar el saltado"}), 500

    # Audit log
    try:
        _mant_log(
            "visita", vid, "equipo_saltado",
            f"Equipo #{mid} saltado por {user} — razón: {razon} · {obs[:150]}"
        )
    except Exception:
        pass

    return jsonify({
        "ok": True,
        "visita_id": vid,
        "maquina_id": mid,
        "estado_revision": "saltado",
        "razon": razon,
        "observacion": obs,
        "revisado_por": user,
    })


@app.route(
    "/mantenciones/api/visitas/<int:vid>/equipos/<int:mid>/marcar",
    methods=["POST"]
)
@_mant_required
@_tecnico_owns_visita
def mant_visita_equipo_marcar(vid, mid):
    """Cambia el estado de revisión del equipo en la visita sin requerir
    completar tareas. Estados: verificado | con_cambios | saltado |
    falla_detectada. Si es 'falla_detectada' o 'saltado', exige
    observación mín 5 chars.
    """
    if not _ot_visita_equipo_link_ok(vid, mid):
        return jsonify({"ok": False, "error": "Equipo no pertenece a esta OT"}), 404

    d = request.get_json(silent=True) or {}
    estado = (d.get("estado_revision") or "").strip().lower()
    if estado not in _ESTADOS_REVISION_VALIDOS:
        return jsonify({
            "ok": False,
            "error": f"estado_revision inválido (debe ser uno de: "
                     f"{', '.join(_ESTADOS_REVISION_VALIDOS)})"
        }), 400

    obs = (d.get("observacion") or "").strip()[:2000]
    razon_raw = (d.get("razon") or "").strip().lower()
    razon = razon_raw if razon_raw in _RAZONES_SALTADO_VALIDAS else None

    # Obs obligatoria para estados problemáticos
    if estado in ("saltado", "falla_detectada") and len(obs) < 5:
        return jsonify({
            "ok": False,
            "error": "La observación es obligatoria para este estado (mín 5 caracteres)."
        }), 400

    user = current_username()
    try:
        mysql_execute(
            "INSERT INTO mant_visita_equipos "
            "  (visita_id, maquina_id, estado_revision, razon_saltado, "
            "   observacion_tecnico, revisado_at, revisado_por) "
            "VALUES (%s, %s, %s, %s, %s, NOW(), %s) "
            "ON DUPLICATE KEY UPDATE "
            "  estado_revision=VALUES(estado_revision), "
            "  razon_saltado=VALUES(razon_saltado), "
            "  observacion_tecnico=COALESCE(VALUES(observacion_tecnico), observacion_tecnico), "
            "  revisado_at=NOW(), "
            "  revisado_por=VALUES(revisado_por)",
            (vid, mid, estado, razon, (obs or None), user)
        )
    except Exception as e:
        print(f"[visita_equipo_marcar] error vid={vid} mid={mid}: {e}", flush=True)
        return jsonify({"ok": False, "error": "No se pudo guardar el estado"}), 500

    try:
        _mant_log(
            "visita", vid, "equipo_estado_revision",
            f"Equipo #{mid} → {estado} por {user}"
            + (f" · razón={razon}" if razon else "")
            + (f" · {obs[:120]}" if obs else "")
        )
    except Exception:
        pass

    return jsonify({
        "ok": True,
        "visita_id": vid,
        "maquina_id": mid,
        "estado_revision": estado,
        "razon": razon,
        "observacion": obs or None,
        "revisado_por": user,
    })


@app.route(
    "/mantenciones/api/visitas/<int:vid>/equipos/<int:mid>/observacion",
    methods=["POST"]
)
@_mant_required
@_tecnico_owns_visita
def mant_visita_equipo_observacion(vid, mid):
    """Guarda observación libre del técnico sobre este equipo en esta
    visita, sin cambiar el estado_revision (queda como esté, default
    'verificado'). Pensado para el textarea siempre visible en
    ot_ejecutar.html con auto-save al perder foco.
    """
    if not _ot_visita_equipo_link_ok(vid, mid):
        return jsonify({"ok": False, "error": "Equipo no pertenece a esta OT"}), 404

    d = request.get_json(silent=True) or {}
    obs = (d.get("observacion") or "").strip()[:2000]
    user = current_username()
    try:
        # Si ya existe, solo actualiza observacion (preserva estado_revision).
        # Si no, inserta como 'verificado' con la observación.
        mysql_execute(
            "INSERT INTO mant_visita_equipos "
            "  (visita_id, maquina_id, estado_revision, "
            "   observacion_tecnico, revisado_at, revisado_por) "
            "VALUES (%s, %s, 'verificado', %s, NOW(), %s) "
            "ON DUPLICATE KEY UPDATE "
            "  observacion_tecnico=VALUES(observacion_tecnico), "
            "  revisado_at=NOW(), "
            "  revisado_por=VALUES(revisado_por)",
            (vid, mid, (obs or None), user)
        )
    except Exception as e:
        print(f"[visita_equipo_observacion] error vid={vid} mid={mid}: {e}", flush=True)
        return jsonify({"ok": False, "error": "No se pudo guardar la observación"}), 500

    # No logueamos cada keystroke; solo si la observación es nueva o se vació.
    return jsonify({
        "ok": True,
        "visita_id": vid,
        "maquina_id": mid,
        "observacion": obs or "",
        "revisado_por": user,
    })


@app.route(
    "/mantenciones/api/visitas/<int:vid>/equipos-estado",
    methods=["GET"]
)
@_mant_required
@_ot_can_view
def mant_visita_equipos_estado(vid):
    """Devuelve el estado de revisión de cada equipo en la visita.
    Usado por ot_ejecutar.html para pintar los badges al cargar.
    """
    rows = mysql_fetchall(
        "SELECT maquina_id, estado_revision, razon_saltado, "
        "       observacion_tecnico, revisado_at, revisado_por "
        "  FROM mant_visita_equipos WHERE visita_id=%s",
        (vid,)
    ) or []
    out = {}
    for r in rows:
        out[str(r["maquina_id"])] = {
            "estado_revision":      r.get("estado_revision") or "verificado",
            "razon_saltado":        r.get("razon_saltado") or "",
            "observacion_tecnico":  r.get("observacion_tecnico") or "",
            "revisado_at":          str(r["revisado_at"])[:19] if r.get("revisado_at") else "",
            "revisado_por":         r.get("revisado_por") or "",
        }
    return jsonify({"ok": True, "equipos": out})


@app.route(
    "/mantenciones/api/maquinas/<int:mid>/revisiones",
    methods=["GET"]
)
@_mant_required
def mant_maquina_revisiones(mid):
    """Devuelve TODAS las revisiones que ha tenido este equipo en visitas
    (timeline cronológico). Usado por el modal de ficha técnica del equipo
    (tab "Revisiones"). Incluye cambios de serial detectados en el
    audit log para enriquecer el historial.
    """
    # Permisos: técnico solo ve si la máquina está en una OT asignada.
    u = getattr(g, "user", None) or {}
    role_u = (u.get("role") or "").lower()
    if role_u in ("tecnico", "tecnico_externo"):
        uid = u.get("id")
        autorizado = mysql_fetchone(
            "SELECT 1 FROM mant_visita_tareas vt "
            "  JOIN mant_visitas v ON v.id = vt.visita_id "
            " WHERE vt.maquina_id=%s "
            "   AND (v.tecnico_user_id=%s "
            "        OR v.id IN (SELECT visita_id FROM mant_visita_tecnicos "
            "                    WHERE tecnico_user_id=%s)) "
            " LIMIT 1",
            (mid, uid, uid)
        )
        if not autorizado:
            return jsonify({"ok": False, "error": "Equipo no asignado a tus OTs"}), 403

    # Datos de cada revisión, joineando con la visita y técnico.
    rows = mysql_fetchall(
        "SELECT ve.id, ve.visita_id, ve.estado_revision, ve.razon_saltado, "
        "       ve.observacion_tecnico, ve.revisado_at, ve.revisado_por, "
        "       v.numero_ot, v.tipo AS visita_tipo, v.fecha_programada, "
        "       v.estado AS visita_estado, "
        "       (SELECT COUNT(*) FROM mant_visita_fotos f "
        "          WHERE f.visita_id=v.id AND f.maquina_id=%s) AS fotos_count "
        "  FROM mant_visita_equipos ve "
        "  JOIN mant_visitas v ON v.id = ve.visita_id "
        " WHERE ve.maquina_id=%s "
        " ORDER BY COALESCE(ve.revisado_at, v.fecha_programada) DESC, ve.id DESC "
        " LIMIT 100",
        (mid, mid)
    ) or []

    timeline = []
    counters = {
        "total": 0, "verificado": 0, "con_cambios": 0,
        "saltado": 0, "falla_detectada": 0,
    }
    for r in rows:
        estado = (r.get("estado_revision") or "verificado").lower()
        counters["total"] += 1
        counters[estado] = counters.get(estado, 0) + 1
        timeline.append({
            "visita_id":     r["visita_id"],
            "numero_ot":     r.get("numero_ot") or f"VS-{r['visita_id']:05d}",
            "tipo_visita":   r.get("visita_tipo") or "",
            "estado_visita": r.get("visita_estado") or "",
            "fecha":         str(r["fecha_programada"])[:10] if r.get("fecha_programada") else "",
            "revisado_at":   str(r["revisado_at"])[:16] if r.get("revisado_at") else "",
            "revisado_por":  r.get("revisado_por") or "",
            "estado_revision": estado,
            "razon_saltado": r.get("razon_saltado") or "",
            "observacion":   r.get("observacion_tecnico") or "",
            "fotos_count":   int(r.get("fotos_count") or 0),
            "url_ot":        f"/mantenciones/ot/{r['visita_id']}",
        })

    # Última revisión = primer elemento del timeline (mayor fecha)
    ultima = timeline[0] if timeline else None

    return jsonify({
        "ok": True,
        "maquina_id": mid,
        "ultima_revision": ultima,
        "contadores": counters,
        "timeline": timeline,
    })


# ── VISITAS / AGENDA ──────────────────────────────────────────────────

@app.route("/mantenciones/api/visitas", methods=["GET"])
@_mant_required
def mant_visitas_api():
    """
    Devuelve visitas enriquecidas para el calendario inteligente.
    Cada evento incluye: cliente, dirección, técnicos N:N, horario, costo,
    modalidad_cobro y prioridad (FASE 8).

    Filtros opcionales:
      start, end, cliente_id, tecnico_id  (existentes)
      modalidad_cobro  (FASE 8: pagado|garantia|sin_costo|interno)
      prioridad        (FASE 8: baja|media|alta|urgente)
      tipo             (FASE 8: tipo OT específico)
      estado           (FASE 8: filtrar por estado)
    """
    desde = request.args.get("start", "")
    hasta = request.args.get("end", "")
    cid   = request.args.get("cliente_id")
    tid   = request.args.get("tecnico_id")
    mod   = (request.args.get("modalidad_cobro") or "").strip().lower()
    pri   = (request.args.get("prioridad") or "").strip().lower()
    tipo_f = (request.args.get("tipo") or "").strip().lower()
    estado_f = (request.args.get("estado") or "").strip().lower()
    where, params = [], []
    # 🔐 SEGURIDAD (2026-05-17 / refuerzo 2026-05-22 Aaron Urbina):
    # Filtramos el calendario por rol con el MISMO criterio que el listado
    # (`mant_ots_list`). Si el rol no puede ver una OT en el listado,
    # tampoco debe verla como evento en el calendario.
    #
    # BRECHA detectada 2026-05-22 (Daniel): el calendario mostraba TODAS
    # las OTs incluso a ejecutivos, mientras el listado las filtraba. Aaron
    # entraba a OTs ajenas vía calendario aunque no aparecían en su lista.
    # Esto era un IDOR de lectura.
    #
    # Reglas (coherentes con _puede_ot_accion('ver') y mant_ots_list):
    #  - admin / supervisor / superadmin → ven TODO (sin filtro)
    #  - ejecutivo → solo creadas por él (created_by_user_id, created_by
    #    por username y por nombre) O asignadas a él (tecnico_user_id,
    #    colaborador en mant_visita_tecnicos)
    #  - tecnico / tecnico_externo → solo asignadas (principal o colab.)
    #  - resto (lector/editor/etc.) → nada (1=0) — el decorador
    #    @_mant_required ya las debería bloquear; cinturón + tirantes.
    u = getattr(g, "user", None) or {}
    role_raw = (u.get("role") or "").lower()
    role_fam = _rol_familia(role_raw)
    uid = u.get("id")
    if role_fam in ("admin", "superadmin", "supervisor"):
        pass  # Sin filtro de rol — ven todo
    elif role_fam == "ejecutivo":
        # Mismo criterio que el listado en mant_ots_list
        username_actual = (u.get("username") or "").strip()
        nombre_actual = (u.get("nombre") or "").strip()
        # Detectar columna `created_by_user_id` (post-migración)
        _has_cbu = False
        try:
            _col_check = mysql_fetchone(
                "SELECT COUNT(*) AS n FROM INFORMATION_SCHEMA.COLUMNS "
                " WHERE TABLE_SCHEMA = DATABASE() "
                "   AND TABLE_NAME = 'mant_visitas' "
                "   AND COLUMN_NAME = 'created_by_user_id'"
            )
            _has_cbu = bool((_col_check or {}).get("n"))
        except Exception:
            _has_cbu = False
        clauses = []
        if _has_cbu and uid:
            clauses.append("v.created_by_user_id=%s")
            params.append(int(uid))
        if username_actual:
            clauses.append("LOWER(TRIM(v.created_by))=LOWER(TRIM(%s))")
            params.append(username_actual)
        if nombre_actual and nombre_actual.lower() != username_actual.lower():
            clauses.append("LOWER(TRIM(v.created_by))=LOWER(TRIM(%s))")
            params.append(nombre_actual)
        if uid:
            clauses.append("v.tecnico_user_id=%s")
            params.append(int(uid))
            clauses.append(
                "v.id IN (SELECT visita_id FROM mant_visita_tecnicos "
                "         WHERE tecnico_user_id=%s)"
            )
            params.append(int(uid))
        if clauses:
            where.append("(" + " OR ".join(clauses) + ")")
        else:
            where.append("1=0")
    elif role_fam == "tecnico":
        if uid:
            where.append(
                "(v.tecnico_user_id=%s OR EXISTS("
                "  SELECT 1 FROM mant_visita_tecnicos vt "
                "   WHERE vt.visita_id=v.id AND vt.tecnico_user_id=%s))"
            )
            params.extend([int(uid), int(uid)])
        else:
            # Sin uid no puede ver nada
            where.append("1=0")
    else:
        # Rol desconocido — denegar lectura (defense in depth)
        where.append("1=0")
    if desde: where.append("v.fecha_programada >= %s"); params.append(desde[:10])
    if hasta: where.append("v.fecha_programada <= %s"); params.append(hasta[:10])
    if cid:   where.append("v.cliente_id=%s"); params.append(int(cid))
    if tid:   where.append(
        "v.id IN (SELECT visita_id FROM mant_visita_tecnicos WHERE tecnico_id=%s)"
    ); params.append(int(tid))
    # FASE 8: filtros nuevos (validados contra ENUMs)
    if mod in ("pagado", "garantia", "sin_costo", "interno"):
        where.append("v.modalidad_cobro=%s"); params.append(mod)
    if pri in ("baja", "media", "alta", "urgente"):
        where.append("v.prioridad=%s"); params.append(pri)
    if tipo_f:
        where.append("v.tipo=%s"); params.append(tipo_f)
    if estado_f:
        where.append("v.estado=%s"); params.append(estado_f)

    sql = ("""SELECT v.*, c.razon_social, c.direccion, c.comuna, c.region
                FROM mant_visitas v
                JOIN mant_clientes c ON c.id=v.cliente_id""")
    if where:
        sql += " WHERE " + " AND ".join(where)
    sql += " ORDER BY v.fecha_programada, v.hora_inicio LIMIT 500"
    rows = mysql_fetchall(sql, tuple(params)) or []
    rows = [dict(r) for r in rows]

    # Cargar técnicos N:N de todas las visitas en una sola query
    tecs_por_visita = {}
    if rows:
        vids = [r["id"] for r in rows]
        ph = ",".join(["%s"] * len(vids))
        tec_rows = mysql_fetchall(
            f"""SELECT vt.visita_id, t.id, t.nombre, t.especialidad, t.nivel,
                       t.es_externo, t.foto_url
                  FROM mant_visita_tecnicos vt
                  JOIN mant_tecnicos t ON t.id=vt.tecnico_id
                 WHERE vt.visita_id IN ({ph})
                 ORDER BY t.nombre""",
            tuple(vids)
        ) or []
        for tr in tec_rows:
            tecs_por_visita.setdefault(tr["visita_id"], []).append({
                "id":           tr["id"],
                "nombre":       tr["nombre"],
                "especialidad": tr["especialidad"],
                "nivel":        tr["nivel"],
                "es_externo":   bool(tr.get("es_externo")),
                "foto_url":     tr.get("foto_url"),
            })

    # Colores por TIPO (mantención preventiva, correctiva, etc.) — FASE 8 expandido
    TIPO_COLOR = {
        "preventiva":     "#16a34a",  # verde
        "correctiva":     "#dc2626",  # rojo
        "garantia":       "#2563eb",  # azul (tipo legacy)
        "inspeccion":     "#f59e0b",  # ámbar
        "levantamiento":  "#7c2d12",  # marrón rojizo
        "instalacion":    "#0891b2",  # cyan
        "visita_tecnica": "#6366f1",  # índigo
        "visita_correctiva": "#be123c",  # rojo oscuro
        "cambio_equipo":  "#9333ea",  # violeta
        "desinstalacion": "#737373",  # gris
        "capacitacion":   "#ca8a04",  # mostaza
        "repuesto":       "#0d9488",  # teal
        "revision_interna": "#475569",  # slate
    }
    EST_BORDER = {
        "creada":              "#94a3b8",
        "programada":          "#0f172a",
        "asignada":            "#3b82f6",
        "en_curso":            "#f59e0b",
        "en_ejecucion":        "#f59e0b",
        "pendiente_info":      "#a855f7",
        "pendiente_repuesto":  "#ec4899",
        "pendiente_aprobacion":"#fb7185",
        "completada":          "#166534",
        "cerrada":             "#15803d",
        "cancelada":           "#9ca3af",
        "anulada":             "#6b7280",
        "reagendada":          "#7c3aed",
    }
    # FASE 8: colores por MODALIDAD DE COBRO (banda lateral del evento)
    MODALIDAD_COLOR = {
        "pagado":    "#16a34a",  # verde — ingreso confirmado
        "garantia":  "#dc2626",  # rojo — atención costo cubierto
        "sin_costo": "#9ca3af",  # gris — operación gratuita
        "interno":   "#7c3aed",  # violeta — operación ILUS
    }
    # FASE 8: prioridad — borde grueso colorido
    PRIORIDAD_COLOR = {
        "baja":    "#10b981",
        "media":   "#3b82f6",
        "alta":    "#f59e0b",
        "urgente": "#dc2626",
    }

    events = []
    for r in rows:
        tecs = tecs_por_visita.get(r["id"], [])
        # Si no hay técnicos N:N pero sí hay tecnico_id legacy, fallback
        if not tecs and r.get("tecnico_id"):
            t_legacy = mysql_fetchone(
                "SELECT id,nombre,especialidad,nivel,es_externo,foto_url FROM mant_tecnicos WHERE id=%s",
                (r["tecnico_id"],)
            )
            if t_legacy:
                tecs = [dict(t_legacy)]
        # Para visitas viejas con solo el campo texto `tecnico`
        elif not tecs and r.get("tecnico"):
            tecs = [{"id": None, "nombre": r["tecnico"], "especialidad": None,
                     "nivel": None, "es_externo": False, "foto_url": None}]

        # Helper para serializar hora (puede venir como timedelta o string)
        def _h(v):
            if v is None: return None
            if hasattr(v, "total_seconds"):
                t = int(v.total_seconds())
                return f"{t//3600:02d}:{(t%3600)//60:02d}"
            s = str(v)
            return s[:5] if len(s) >= 5 else s

        events.append({
            "id":          r["id"],
            "title":       r["titulo"] or (r.get("tipo","").capitalize() + " programada"),
            "fecha":       str(r["fecha_programada"]) if r["fecha_programada"] else None,
            "hora_inicio": _h(r.get("hora_inicio")),
            "hora_fin":    _h(r.get("hora_fin")),
            "tipo":        r.get("tipo"),
            "estado":      r.get("estado"),
            "descripcion": (r.get("descripcion") or "")[:300],
            "costo":       float(r.get("costo") or 0),
            "cliente": {
                "id":           r["cliente_id"],
                "razon_social": r["razon_social"],
                "direccion":    r.get("direccion") or "",
                "comuna":       r.get("comuna") or "",
                "region":       r.get("region") or "",
            },
            "tecnicos":    tecs,
            "n_tecnicos":  len(tecs),
            # FASE 8: campos nuevos en payload
            "modalidad_cobro": r.get("modalidad_cobro") or "pagado",
            "prioridad":       r.get("prioridad") or "media",
            "numero_ot":       r.get("numero_ot") or "",
            "levantamiento_id":r.get("levantamiento_id"),
            "color_tipo":      TIPO_COLOR.get(r.get("tipo"), "#6b7280"),
            "color_borde":     EST_BORDER.get(r.get("estado"), "#0f172a"),
            "color_modalidad": MODALIDAD_COLOR.get(r.get("modalidad_cobro") or "pagado", "#9ca3af"),
            "color_prioridad": PRIORIDAD_COLOR.get(r.get("prioridad") or "media", "#3b82f6"),
        })
    return jsonify(events)


# ══════════════════════════════════════════════════════════════════════
# MANTENCIONES HISTÓRICAS — backdating + cálculo de próxima visita
#
# Caso de uso: el cliente migra al sistema con historial. Hay que registrar
# visitas que YA ocurrieron (estado=completada, fecha_realizada anterior)
# y el sistema sugiere automáticamente la PRÓXIMA según la frecuencia
# del contrato.
#
# Ejemplo:
#   - Contrato: cada 3 meses
#   - Última mantención hecha: 2025-12-15
#   - Hoy: 2026-05-11
#   - Sugerencia: próxima = 2025-12-15 + 3 meses = 2026-03-15
#                 (ya pasó → marcar VENCIDA y proponer hoy + 7 días)
#                 si no había vencido → proponer la fecha calculada
# ══════════════════════════════════════════════════════════════════════

def _sugerir_proxima_visita(ultima_fecha, frecuencia_meses=None, contrato_id=None):
    """Calcula la próxima visita ideal.
    Si la próxima ya pasó, sugiere fecha de catch-up (hoy + 7 días).
    Devuelve dict con detalles."""
    from datetime import date, datetime, timedelta
    import calendar as _cal

    # Normalizar última fecha a date
    if isinstance(ultima_fecha, datetime):
        ultima_d = ultima_fecha.date()
    elif isinstance(ultima_fecha, date):
        ultima_d = ultima_fecha
    elif isinstance(ultima_fecha, str):
        try: ultima_d = datetime.strptime(ultima_fecha[:10], "%Y-%m-%d").date()
        except Exception: return None
    else:
        return None

    # Obtener frecuencia del contrato si no vino
    if not frecuencia_meses and contrato_id:
        try:
            row = mysql_fetchone(
                "SELECT frecuencia_meses, ai_frecuencia_sug FROM mant_contratos WHERE id=%s",
                (contrato_id,)
            )
            if row:
                frecuencia_meses = row.get("frecuencia_meses") or row.get("ai_frecuencia_sug") or 0
        except Exception:
            pass

    if not frecuencia_meses or frecuencia_meses <= 0:
        return {
            "proxima_ideal": None,
            "sin_frecuencia": True,
            "mensaje": "El contrato no tiene frecuencia definida — asigna una para que el sistema sugiera próximas visitas.",
        }

    # Sumar N meses a la última fecha
    año = ultima_d.year
    mes = ultima_d.month + int(frecuencia_meses)
    while mes > 12:
        mes -= 12
        año += 1
    # Ajustar día si el mes destino tiene menos días (ej: 31 enero + 1 mes = 28/29 feb)
    dia_max = _cal.monthrange(año, mes)[1]
    dia = min(ultima_d.day, dia_max)
    proxima_ideal = date(año, mes, dia)
    hoy = date.today()
    dias_vencimiento = (proxima_ideal - hoy).days

    estado = "futura"
    fecha_sugerida = proxima_ideal
    if dias_vencimiento < 0:
        estado = "vencida"
        # Catch-up: hoy + 7 días (ventana razonable)
        fecha_sugerida = hoy + timedelta(days=7)
    elif dias_vencimiento <= 15:
        estado = "proxima"

    return {
        "ultima_fecha": ultima_d.isoformat(),
        "frecuencia_meses": int(frecuencia_meses),
        "proxima_ideal": proxima_ideal.isoformat(),
        "fecha_sugerida": fecha_sugerida.isoformat(),
        "dias_vencimiento": dias_vencimiento,
        "estado": estado,  # vencida | proxima | futura
        "mensaje": (
            f"Última mantención: {ultima_d.strftime('%d/%m/%Y')} · "
            f"Frecuencia: cada {int(frecuencia_meses)} mes(es) · "
            + (f"Próxima IDEAL era {proxima_ideal.strftime('%d/%m/%Y')} "
               f"(VENCIDA hace {-dias_vencimiento} días) → "
               f"sugerencia: {fecha_sugerida.strftime('%d/%m/%Y')}"
               if estado == "vencida"
               else f"Próxima: {fecha_sugerida.strftime('%d/%m/%Y')}"
                    + (f" (en {dias_vencimiento} días)" if dias_vencimiento > 0 else " (HOY)"))
        ),
    }


@app.route("/mantenciones/api/clientes/<int:cid>/sugerir-proxima", methods=["GET"])
@_mant_required
def mant_sugerir_proxima(cid):
    """Devuelve la próxima visita sugerida basada en la última mantención
    completada del cliente + frecuencia del contrato más reciente.

    Útil para mostrar al usuario antes de crear una visita futura."""
    # Última visita completada del cliente
    ultima = mysql_fetchone(
        "SELECT fecha_realizada, fecha_programada, contrato_id "
        "  FROM mant_visitas "
        " WHERE cliente_id=%s AND estado='completada' "
        " ORDER BY COALESCE(fecha_realizada, fecha_programada) DESC LIMIT 1",
        (cid,)
    )

    # Frecuencia del contrato vigente más reciente
    contrato = mysql_fetchone(
        "SELECT id, frecuencia_meses, ai_frecuencia_sug "
        "  FROM mant_contratos "
        " WHERE cliente_id=%s AND estado IN ('vigente','indefinido') "
        " ORDER BY created_at DESC LIMIT 1",
        (cid,)
    )

    if not ultima:
        # Sin historial → sugerir hoy + 7 días como fecha tentativa
        from datetime import date, timedelta
        return jsonify({
            "ok": True,
            "sin_historial": True,
            "fecha_sugerida": (date.today() + timedelta(days=7)).isoformat(),
            "mensaje": "Sin historial previo — sugerencia: comenzar dentro de 7 días.",
            "frecuencia_meses": (contrato.get("frecuencia_meses") if contrato else None),
        })

    freq = None
    if contrato:
        freq = contrato.get("frecuencia_meses") or contrato.get("ai_frecuencia_sug")
    ultima_fecha = ultima.get("fecha_realizada") or ultima.get("fecha_programada")

    sug = _sugerir_proxima_visita(ultima_fecha, freq, ultima.get("contrato_id"))
    if not sug:
        return jsonify({"ok": False, "error": "No se pudo calcular"}), 500
    sug["ok"] = True
    return jsonify(sug)


@app.route("/mantenciones/api/clientes/<int:cid>/visita-historica", methods=["POST"])
@_mant_required
def mant_visita_historica(cid):
    """Registra una mantención que YA ocurrió (backdating) y calcula próxima.

    Body JSON:
      fecha_realizada: 'YYYY-MM-DD' (obligatoria, fecha del pasado)
      tipo: 'preventiva' | 'correctiva' | 'garantia' | 'inspeccion'
      tecnico: string
      titulo: string opcional
      observaciones: string opcional
      costo: número opcional
      contrato_id: int opcional (si no, usa el vigente más reciente)
      crear_proxima: bool — si true, además crea automáticamente la próxima
                            visita programada en la fecha sugerida
    """
    d = request.get_json(silent=True) or {}
    from datetime import date, datetime

    fecha_real_str = (d.get("fecha_realizada") or "").strip()
    if not fecha_real_str:
        return jsonify({"ok": False, "error": "fecha_realizada requerida"}), 400
    try:
        fecha_real = datetime.strptime(fecha_real_str[:10], "%Y-%m-%d").date()
    except Exception:
        return jsonify({"ok": False, "error": "fecha_realizada con formato inválido (usa YYYY-MM-DD)"}), 400

    if fecha_real > date.today():
        return jsonify({
            "ok": False,
            "error": "La fecha realizada no puede ser futura. Usa el módulo de programar visita."
        }), 400

    # Verificar cliente
    cliente = mysql_fetchone("SELECT id FROM mant_clientes WHERE id=%s", (cid,))
    if not cliente:
        return jsonify({"ok": False, "error": "Cliente no encontrado"}), 404

    # Contrato (opcional — toma el vigente si no viene)
    contrato_id = d.get("contrato_id")
    if not contrato_id:
        ct = mysql_fetchone(
            "SELECT id FROM mant_contratos "
            "WHERE cliente_id=%s AND estado IN ('vigente','indefinido') "
            "ORDER BY created_at DESC LIMIT 1", (cid,)
        )
        if ct:
            contrato_id = ct.get("id")

    titulo = (d.get("titulo") or "Mantención histórica").strip()[:200]
    tipo = (d.get("tipo") or "preventiva").strip().lower()
    if tipo not in ("preventiva", "correctiva", "garantia", "inspeccion"):
        tipo = "preventiva"
    tecnico = (d.get("tecnico") or "").strip()[:200]
    observ  = (d.get("observaciones") or "").strip()
    costo   = float(d.get("costo") or 0)

    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            cur.execute(
                """INSERT INTO mant_visitas
                   (cliente_id, contrato_id, titulo, fecha_programada, fecha_realizada,
                    tipo, estado, tecnico, observaciones, costo, created_by)
                   VALUES (%s,%s,%s,%s,%s,%s,'completada',%s,%s,%s,%s)""",
                (cid, contrato_id, titulo, fecha_real, fecha_real,
                 tipo, tecnico, observ, costo, current_username())
            )
            vid_historica = cur.lastrowid
        conn.commit()
        try:
            _mant_log("visita", vid_historica, "registrada_historica",
                      f"Mantención de {fecha_real.strftime('%d/%m/%Y')} retroactiva")
        except Exception: pass
    finally:
        conn.close()

    # ─── Calcular próxima sugerida ───
    freq = None
    if contrato_id:
        ctr = mysql_fetchone(
            "SELECT frecuencia_meses, ai_frecuencia_sug FROM mant_contratos WHERE id=%s",
            (contrato_id,)
        )
        if ctr:
            freq = ctr.get("frecuencia_meses") or ctr.get("ai_frecuencia_sug")

    sugerencia = _sugerir_proxima_visita(fecha_real, freq, contrato_id) or {}

    # ─── Si se pidió, crear automáticamente la próxima ───
    proxima_creada = None
    if d.get("crear_proxima") and sugerencia.get("fecha_sugerida"):
        try:
            conn2 = get_mysql()
            with conn2.cursor() as cur:
                cur.execute(
                    """INSERT INTO mant_visitas
                       (cliente_id, contrato_id, titulo, fecha_programada,
                        tipo, estado, created_by)
                       VALUES (%s,%s,%s,%s,%s,'programada',%s)""",
                    (cid, contrato_id,
                     f"Mantención preventiva (sugerida por sistema)",
                     sugerencia["fecha_sugerida"], tipo, current_username())
                )
                proxima_creada = cur.lastrowid
            conn2.commit()
            conn2.close()
            try:
                _mant_log("visita", proxima_creada, "programada_auto",
                          f"Generada por sistema tras mantención histórica {vid_historica}")
            except Exception: pass
        except Exception as e:
            print(f"[mant_visita_historica] error creando próxima: {e}")

    return jsonify({
        "ok": True,
        "visita_historica_id": vid_historica,
        "proxima_creada_id": proxima_creada,
        "sugerencia": sugerencia,
        "mensaje": (f"Mantención del {fecha_real.strftime('%d/%m/%Y')} registrada. "
                    + (sugerencia.get("mensaje","") if sugerencia else "")),
    })


