@app.route("/mantenciones/api/notif-interna", methods=["GET"])
@_mant_required
def mant_notif_interna_list():
    """Lista notificaciones internas del usuario actual.

    Query params:
        leidas: 0|1 (default 0 = solo no leídas)
        limit:  int (default 50, max 200)
        archivadas: 0|1 (default 0)

    Si el usuario es admin/superadmin, ve también las broadcast (destino IS NULL).
    """
    perms = g.get("permissions") or {}
    es_admin = bool(perms.get("admin") or perms.get("superadmin"))
    user_id = None
    try:
        user_id = (g.user or {}).get("id") if hasattr(g, "user") else None
    except Exception:
        user_id = None

    leidas      = request.args.get("leidas", "0").strip()
    archivadas  = request.args.get("archivadas", "0").strip()
    limit       = min(200, int(request.args.get("limit") or 50))

    sql = (
        "SELECT n.id, n.tipo, n.prioridad, n.titulo, "
        "       COALESCE(n.cuerpo, n.mensaje) AS cuerpo, "
        "       n.url_accion, n.leida_at, n.archivada_at, n.created_at, "
        "       n.cliente_id, n.visita_id, "
        "       c.razon_social "
        "FROM mant_notificaciones n "
        "LEFT JOIN mant_clientes c ON c.id = n.cliente_id "
        "WHERE 1=1 "
    )
    params = []
    # Filtro destino
    if es_admin:
        # Admin ve todas (las suyas + broadcast + cualquiera)
        pass
    elif user_id:
        sql += " AND (n.destino_user_id=%s OR n.destino_user_id IS NULL) "
        params.append(user_id)
    else:
        sql += " AND n.destino_user_id IS NULL "
    # Filtro leídas
    if leidas != "1":
        sql += " AND n.leida_at IS NULL "
    # Filtro archivadas
    if archivadas != "1":
        sql += " AND n.archivada_at IS NULL "

    sql += (
        " ORDER BY "
        "   CASE n.prioridad WHEN 'urgente' THEN 1 WHEN 'alta' THEN 2 "
        "                    WHEN 'media' THEN 3 ELSE 4 END, "
        "   n.created_at DESC "
        " LIMIT %s "
    )
    params.append(limit)

    rows = mysql_fetchall(sql, tuple(params)) or []
    out = []
    for r in rows:
        d = dict(r)
        for k in ("created_at", "leida_at", "archivada_at"):
            if d.get(k):
                d[k] = str(d[k])[:19]
        out.append(d)
    return jsonify({"ok": True, "notificaciones": out, "total": len(out)})


@app.route("/mantenciones/api/notif-interna/<int:nid>/leida", methods=["POST"])
@_mant_required
def mant_notif_interna_leida(nid):
    """Marca una notificación como leída."""
    try:
        mysql_execute(
            "UPDATE mant_notificaciones SET leida_at=NOW(), "
            "  estado=CASE WHEN estado='pendiente' THEN 'leida' ELSE estado END "
            "WHERE id=%s AND leida_at IS NULL",
            (nid,)
        )
        return jsonify({"ok": True})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 500


@app.route("/mantenciones/api/notif-interna/<int:nid>/archivar", methods=["POST"])
@_mant_required
def mant_notif_interna_archivar(nid):
    """Archiva una notificación (no aparece más en la campana)."""
    try:
        mysql_execute(
            "UPDATE mant_notificaciones SET archivada_at=NOW(), "
            "  leida_at=COALESCE(leida_at, NOW()) "
            "WHERE id=%s",
            (nid,)
        )
        return jsonify({"ok": True})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 500


# ── CACHE en memoria del contador de notificaciones por usuario ──
# 2026-05-26 (Daniel — audit DevTools: 840ms × 5 llamadas/página = 4.2s).
# La query agrega COUNT + SUM filtrando por destino_user_id NULL OR igual.
# Resultado: cache TTL 45s por (es_admin, user_id). Quita 4 de 5 queries.
# Llamar _mant_notif_cache_invalidar(user_id) tras INSERT/UPDATE de notif.
_MANT_NOTIF_CONT_CACHE = {}   # key -> (data_dict, ts)
_MANT_NOTIF_CONT_LOCK  = threading.Lock()
_MANT_NOTIF_CONT_TTL   = 45   # segundos


def _mant_notif_cache_invalidar(user_id=None):
    """Invalida cache cuando se modifica una notificación. Si user_id es
    None, invalida todo (caso: notificación broadcast). Llamar tras
    INSERT/UPDATE/DELETE en mant_notificaciones."""
    with _MANT_NOTIF_CONT_LOCK:
        if user_id is None:
            _MANT_NOTIF_CONT_CACHE.clear()
        else:
            for k in list(_MANT_NOTIF_CONT_CACHE.keys()):
                # k es tupla (es_admin, user_id_o_None) — invalidamos
                # tanto la del usuario específico como las admin
                if k[0] or k[1] == user_id:
                    _MANT_NOTIF_CONT_CACHE.pop(k, None)


@app.route("/mantenciones/api/notif-interna/contador", methods=["GET"])
@_mant_required
def mant_notif_interna_contador():
    """Devuelve {no_leidas, urgentes} para el badge de la campana.
    Cacheado 45s por usuario (DevTools audit: era 840ms x 5/página = 4.2s).
    """
    perms = g.get("permissions") or {}
    es_admin = bool(perms.get("admin") or perms.get("superadmin"))
    user_id = None
    try:
        user_id = (g.user or {}).get("id") if hasattr(g, "user") else None
    except Exception:
        user_id = None

    # ── CACHE HIT ───────────────────────────────────────────────────
    cache_key = (es_admin, user_id)
    _now = time.time()
    with _MANT_NOTIF_CONT_LOCK:
        entry = _MANT_NOTIF_CONT_CACHE.get(cache_key)
    if entry and (_now - entry[1]) < _MANT_NOTIF_CONT_TTL:
        return jsonify(entry[0])

    # ── CACHE MISS — Query original ────────────────────────────────
    sql = (
        "SELECT "
        "  COUNT(*) AS no_leidas, "
        "  SUM(CASE WHEN prioridad IN ('alta','urgente') THEN 1 ELSE 0 END) AS urgentes "
        "FROM mant_notificaciones "
        "WHERE leida_at IS NULL AND archivada_at IS NULL "
    )
    params = []
    if not es_admin and user_id:
        sql += " AND (destino_user_id=%s OR destino_user_id IS NULL) "
        params.append(user_id)
    elif not es_admin and not user_id:
        sql += " AND destino_user_id IS NULL "
    try:
        row = mysql_fetchone(sql, tuple(params)) or {}
        data = {
            "ok": True,
            "no_leidas": int(row.get("no_leidas") or 0),
            "urgentes":  int(row.get("urgentes") or 0),
            "_cached_ttl": _MANT_NOTIF_CONT_TTL,
        }
        # Guardar en cache
        with _MANT_NOTIF_CONT_LOCK:
            _MANT_NOTIF_CONT_CACHE[cache_key] = (data, _now)
        return jsonify(data)
    except Exception as e:
        return jsonify({"ok": False, "no_leidas": 0, "urgentes": 0,
                        "error": str(e)}), 200


# ═════════════════════════════════════════════════════════════════════
# SUGERENCIAS CON EVIDENCIA — endpoints
# Lista, contador, aceptar, rechazar, ignorar. El sistema NUNCA actúa
# solo — cada acción la confirma el usuario. Resoluciones quedan en
# mant_sugerencias_evidencia para auditoría.
# ═════════════════════════════════════════════════════════════════════

@app.route("/mantenciones/api/sugerencias", methods=["GET"])
@_mant_required
def mant_sugerencias_list():
    """Lista sugerencias filtradas.

    Query params:
        cliente_id (int|None)  - filtro por cliente
        estado (str|None)      - 'pendiente'|'aceptada'|'rechazada'|
                                 'ignorada'|'expirada' (default 'pendiente')
        tipo (str|None)        - filtro por tipo_sugerencia
        origen (str|None)      - filtro por origen ('cron','ia','usuario','sistema')
        limit (int)            - default 100, max 500
    """
    cliente_id = request.args.get("cliente_id")
    estado = (request.args.get("estado") or "pendiente").strip().lower()
    tipo = (request.args.get("tipo") or "").strip()
    origen = (request.args.get("origen") or "").strip().lower()
    try:
        limit = min(500, max(1, int(request.args.get("limit") or 100)))
    except Exception:
        limit = 100

    sql = (
        "SELECT s.id, s.cliente_id, s.entidad, s.entidad_id, "
        "       s.tipo_sugerencia, s.origen, s.titulo, s.cuerpo, "
        "       s.url_accion, s.sugerida_at, s.resolucion, "
        "       s.resolucion_at, s.resolucion_por, s.resolucion_motivo, "
        "       s.metadata_json, c.razon_social "
        "  FROM mant_sugerencias_evidencia s "
        "  LEFT JOIN mant_clientes c ON c.id = s.cliente_id "
        " WHERE 1=1 "
    )
    params = []
    if estado and estado != "todas":
        sql += " AND s.resolucion=%s "
        params.append(estado)
    if cliente_id:
        try:
            sql += " AND s.cliente_id=%s "
            params.append(int(cliente_id))
        except Exception:
            pass
    if tipo:
        sql += " AND s.tipo_sugerencia=%s "
        params.append(tipo)
    if origen and origen in ('cron', 'ia', 'usuario', 'sistema'):
        sql += " AND s.origen=%s "
        params.append(origen)

    sql += (
        " ORDER BY "
        "   CASE s.resolucion WHEN 'pendiente' THEN 0 ELSE 1 END, "
        "   s.sugerida_at DESC "
        " LIMIT %s"
    )
    params.append(limit)

    rows = mysql_fetchall(sql, tuple(params)) or []
    out = []
    for r in rows:
        d = dict(r)
        for k in ("sugerida_at", "resolucion_at"):
            if d.get(k):
                d[k] = str(d[k])[:19]
        out.append(d)
    return jsonify({"ok": True, "sugerencias": out, "total": len(out)})


