# ─────────────────────────────────────────────────────────────────
# REGLAS DE NEGOCIO — modelo Fracttal Fase 1
# ─────────────────────────────────────────────────────────────────

# Modalidades de cobro válidas (deben coincidir con el ENUM de mant_visitas.modalidad_cobro)
_OT_MODALIDADES = ("pagado", "garantia", "sin_costo", "interno")

# Prioridades válidas
_OT_PRIORIDADES = ("baja", "media", "alta", "urgente")

# Tipos de OT que NO pueden ser cobrados por garantía (regla ILUS).
# El levantamiento fotográfico es un registro inicial del activo: no genera
# costo ni garantía. Si llega garantia → se fuerza a sin_costo.
_OT_TIPOS_SIN_GARANTIA = ("levantamiento",)


def _normalizar_modalidad_cobro(tipo, modalidad_raw):
    """Aplica reglas de negocio a la modalidad de cobro de una OT.

    Args:
        tipo: tipo de OT (levantamiento, preventiva, correctiva, etc.)
        modalidad_raw: valor crudo desde el request (puede ser None o inválido)

    Returns:
        Tupla (modalidad_normalizada, warning_msg_or_None)
    """
    m = (modalidad_raw or "").strip().lower()
    if m not in _OT_MODALIDADES:
        m = "pagado"  # default seguro
    # Regla ILUS: levantamiento NUNCA puede ser garantía
    if tipo in _OT_TIPOS_SIN_GARANTIA and m == "garantia":
        return ("sin_costo",
                "Levantamiento fotográfico no admite modalidad 'garantía'. "
                "Convertido a 'sin_costo'.")
    return (m, None)


def _parse_garantia_aplica(raw):
    """Interpreta el flag transversal `garantia_aplica` del request.

    Acepta bool, int o string (json o form). Devuelve True/False/None:
      - True   → el servicio está cubierto por garantía (no se cobra)
      - False  → es un servicio PAGO (debe ligarse a factura para cerrar)
      - None   → el campo no vino en el body (no tocar el estado actual)
    """
    if raw is None:
        return None
    if isinstance(raw, bool):
        return raw
    if isinstance(raw, (int, float)):
        return bool(raw)
    s = str(raw).strip().lower()
    if s in ("1", "true", "si", "sí", "yes", "aplica", "on"):
        return True
    if s in ("0", "false", "no", "no_aplica", "off", ""):
        return False
    return None


def _mapear_garantia_a_cobertura(garantia_aplica, tipo):
    """Mapeo CANÓNICO garantía → (cubierto_por, modalidad_cobro, estado_facturacion).

    Modelo Daniel (2026-05-30): la garantía es un interruptor transversal,
    independiente del TIPO de servicio (mantención/correctiva/inspección…).

      - APLICA (True)  → cubierto_por='garantia', modalidad_cobro='garantia',
                         estado_facturacion='no_aplica' (no se cobra, cerrable).
      - NO APLICA (False) → cubierto_por='cliente', modalidad_cobro='pagado',
                         estado_facturacion='sin_cotizar' (PENDIENTE DE FACTURAR
                         hasta ligar una factura del ERP).

    Regla dura: tipo='levantamiento' NUNCA puede ir a garantía. Si llega
    APLICA con ese tipo, se degrada a servicio PAGO (consistente con
    _normalizar_modalidad_cobro) y se devuelve un warning.

    Devuelve (dict_de_campos, warning_or_None). El dict solo trae las
    columnas a setear; el caller decide cómo aplicarlas (INSERT o UPDATE).
    """
    tipo_l = (tipo or "").strip().lower()
    if garantia_aplica is None:
        return ({}, None)
    if garantia_aplica:
        if tipo_l in _OT_TIPOS_SIN_GARANTIA:
            # Levantamiento no admite garantía → cae a PAGO pendiente.
            return ({
                "cubierto_por": "cliente",
                "modalidad_cobro": "pagado",
                "estado_facturacion": "sin_cotizar",
            }, "El levantamiento no admite garantía. Quedó como servicio pagado "
               "(pendiente de facturar).")
        return ({
            "cubierto_por": "garantia",
            "modalidad_cobro": "garantia",
            "estado_facturacion": "no_aplica",
        }, None)
    # NO APLICA → servicio pagado pendiente de facturar.
    return ({
        "cubierto_por": "cliente",
        "modalidad_cobro": "pagado",
        "estado_facturacion": "sin_cotizar",
    }, None)


@app.route("/mantenciones/api/visitas", methods=["POST"])
@_mant_required
def mant_visita_crear():
    """Crea una OT. Acepta tecnico_user_id (FK a app_users con role='tecnico')
    como alternativa al campo de texto legacy 'tecnico'."""
    d = request.get_json(silent=True) or {}
    if not d.get("cliente_id") or not d.get("fecha_programada"):
        return jsonify({"error": "cliente_id y fecha_programada requeridos"}), 400

    # Resolver técnico asignado (preferir tecnico_user_id, sino el texto legacy)
    # COMPAT: la API /api/tecnicos ahora devuelve app_users.id en el campo `id`.
    # Si el frontend manda `tecnico_id` (legacy), lo interpretamos como user_id
    # cuando no llegue `tecnico_user_id` explícito y haya match en app_users.
    tecnico_user_id = d.get("tecnico_user_id")
    if not tecnico_user_id and d.get("tecnico_id"):
        # Migración silenciosa: el dropdown manda el id de app_users
        tecnico_user_id = d.get("tecnico_id")
        d["tecnico_id"] = None
    tecnico_txt = d.get("tecnico", "") or ""
    if tecnico_user_id:
        try:
            tecnico_user_id = int(tecnico_user_id)
            # Si no viene texto, lo rellenamos desde app_users.nombre
            if not tecnico_txt:
                u = mysql_fetchone(
                    "SELECT COALESCE(nombre, username) AS nm FROM app_users "
                    "WHERE id=%s AND role='tecnico' AND active=1",
                    (tecnico_user_id,)
                )
                if u:
                    tecnico_txt = u["nm"]
                else:
                    # No es un técnico válido — descartar
                    tecnico_user_id = None
        except (TypeError, ValueError):
            tecnico_user_id = None

    # FASE 1 — modalidad de cobro + prioridad (con validación de regla)
    tipo_ot = (d.get("tipo") or "preventiva").lower()
    modalidad, warn_mod = _normalizar_modalidad_cobro(tipo_ot, d.get("modalidad_cobro"))
    prioridad = (d.get("prioridad") or "media").lower()
    if prioridad not in _OT_PRIORIDADES:
        prioridad = "media"

    # GARANTÍA TRANSVERSAL (Daniel 2026-05-30): interruptor Aplica/No aplica
    # independiente del tipo. Si llega `garantia_aplica`, MANDA sobre cualquier
    # modalidad_cobro suelta que pudiera venir del frontend legacy.
    cubierto_por_ins = "contrato"   # default histórico de la columna
    estado_factur_ins = "sin_cotizar"
    gar_aplica = _parse_garantia_aplica(d.get("garantia_aplica"))
    cobertura_map, warn_gar = _mapear_garantia_a_cobertura(gar_aplica, tipo_ot)
    if cobertura_map:
        modalidad = cobertura_map["modalidad_cobro"]
        cubierto_por_ins = cobertura_map["cubierto_por"]
        estado_factur_ins = cobertura_map["estado_facturacion"]
        if warn_gar:
            warn_mod = warn_gar

    # 2026-05-22 (Aaron Urbina) — capturamos el user_id del creador como
    # FUENTE DE VERDAD para el filtro del listado. `created_by` queda como
    # texto display (puede ser email o nombre, según current_username()),
    # pero `created_by_user_id` es FK estable a app_users.id que NO depende
    # del formato del string.
    _u_creator = getattr(g, "user", None) or {}
    creador_user_id = _u_creator.get("id")
    try:
        creador_user_id = int(creador_user_id) if creador_user_id else None
    except (TypeError, ValueError):
        creador_user_id = None

    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            # INSERT con created_by_user_id. Si la migración aún no corrió en
            # esta instancia, hacemos fallback al INSERT legacy sin la columna.
            try:
                cur.execute(
                    """INSERT INTO mant_visitas
                       (cliente_id,contrato_id,titulo,fecha_programada,hora_inicio,hora_fin,
                        tecnico,tecnico_user_id,tipo,estado,descripcion,costo,
                        modalidad_cobro,cubierto_por,estado_facturacion,
                        prioridad,created_by,created_by_user_id)
                       VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)""",
                    (d["cliente_id"], d.get("contrato_id") or None,
                     d.get("titulo","Mantención"), d["fecha_programada"],
                     d.get("hora_inicio") or None, d.get("hora_fin") or None,
                     tecnico_txt, tecnico_user_id,
                     tipo_ot,
                     d.get("estado","programada"), d.get("descripcion",""),
                     float(d.get("costo",0) or 0),
                     modalidad, cubierto_por_ins, estado_factur_ins,
                     prioridad, current_username(), creador_user_id)
                )
            except Exception as _e_ins_full:
                # Fallback (DB sin la migración nueva todavía). Este path solo se
                # alcanza en una DB tan antigua que ni siquiera tiene
                # `created_by_user_id` — que se agregó ANTES que cubierto_por/
                # estado_facturacion. Por eso aquí volvemos al set mínimo de
                # columnas históricas (sin garantía): si las nuevas tampoco
                # existen, este INSERT igual funciona y la OT queda creada.
                print(f"[crear-ot] INSERT con created_by_user_id falló ({_e_ins_full}); reintentando sin la columna", flush=True)
                cur.execute(
                    """INSERT INTO mant_visitas
                       (cliente_id,contrato_id,titulo,fecha_programada,hora_inicio,hora_fin,
                        tecnico,tecnico_user_id,tipo,estado,descripcion,costo,
                        modalidad_cobro,prioridad,created_by)
                       VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)""",
                    (d["cliente_id"], d.get("contrato_id") or None,
                     d.get("titulo","Mantención"), d["fecha_programada"],
                     d.get("hora_inicio") or None, d.get("hora_fin") or None,
                     tecnico_txt, tecnico_user_id,
                     tipo_ot,
                     d.get("estado","programada"), d.get("descripcion",""),
                     float(d.get("costo",0) or 0),
                     modalidad, prioridad, current_username())
                )
            vid = cur.lastrowid
        conn.commit()
        _mant_log("visita", vid, "creada",
                  f"{d.get('titulo','')} · tipo={tipo_ot} · modalidad={modalidad}"
                  + (f" · garantía={'aplica' if cubierto_por_ins=='garantia' else 'no aplica'}"
                     if gar_aplica is not None else "")
                  + (f" · ⚠ {warn_mod}" if warn_mod else ""))
        # 2026-05-22 (Daniel) — si la OT se creó CON técnico ya asignado,
        # disparamos la notificación interna (campana) + el helper WA/SMS
        # legacy (silencioso si Twilio off). Best-effort, no bloquea.
        if tecnico_user_id:
            try: _notificar_ot_asignada_interna(vid, tecnico_user_id, motivo="asignada")
            except Exception as _e_nai: print(f"[crear-ot notif] {_e_nai}", flush=True)
            try: _notificar_ot_asignada(vid)
            except Exception as _e_naw: print(f"[crear-ot wa] {_e_naw}", flush=True)
        # 2026-05-22 (OT 2026-00004 Vitacura) — Opcionalmente acepta
        # maquina_ids y plantilla_id en el mismo POST para que el
        # ejecutivo no tenga que aplicar plantilla en un segundo paso
        # (y olvidarlo, dejando la OT huérfana al técnico). Best-effort:
        # si la asociación falla, la OT igual queda creada y el creador
        # puede ir al panel "Configurar OT" después.
        maq_ids_inicial = []
        for m in (d.get("maquina_ids") or []):
            try: maq_ids_inicial.append(int(m))
            except (TypeError, ValueError): continue
        plant_id_inicial = None
        try:
            if d.get("plantilla_id"):
                plant_id_inicial = int(d["plantilla_id"])
        except (TypeError, ValueError):
            plant_id_inicial = None
        n_tareas_creadas = 0
        if maq_ids_inicial and plant_id_inicial:
            try:
                items_p = mysql_fetchall(
                    "SELECT * FROM mant_tarea_plantilla_items "
                    " WHERE plantilla_id=%s ORDER BY orden, id",
                    (plant_id_inicial,)
                ) or []
                if items_p:
                    conn2 = get_mysql()
                    try:
                        with conn2.cursor() as cur2:
                            ph = ",".join(["%s"] * len(maq_ids_inicial))
                            cur2.execute(
                                f"SELECT id, nombre, serie FROM mant_maquinas "
                                f"WHERE id IN ({ph}) AND cliente_id=%s",
                                tuple(maq_ids_inicial) + (d["cliente_id"],)
                            )
                            m_rows = cur2.fetchall() or []
                            m_idx = {r["id"]: r for r in m_rows}
                            orden = 0
                            for mid in maq_ids_inicial:
                                if mid not in m_idx:
                                    continue
                                m_row = m_idx[mid]
                                for it in items_p:
                                    orden += 1
                                    sufijo = m_row["nombre"]
                                    if m_row.get("serie"):
                                        sufijo += f" (S/N: {m_row['serie']})"
                                    titulo = f"{it['titulo']} — {sufijo}"[:300]
                                    tr = it.get("tipo_respuesta") or "check"
                                    cur2.execute(
                                        "INSERT INTO mant_visita_tareas "
                                        "(visita_id, plantilla_id, orden, titulo, "
                                        " descripcion, tipo, maquina_id, tipo_respuesta, "
                                        " obligatoria, requiere_foto, unidad, rango_min, "
                                        " rango_max, opciones_lista_json, estado_trabajo, "
                                        " created_by) "
                                        "VALUES (%s,%s,%s,%s,%s,'otro',%s,%s,%s,%s,"
                                        "        %s,%s,%s,%s,'pendiente',%s)",
                                        (vid, plant_id_inicial, orden, titulo,
                                         it.get("descripcion"), mid, tr,
                                         it.get("obligatoria") or 0,
                                         it.get("requiere_foto") or 0,
                                         it.get("unidad"), it.get("rango_min"),
                                         it.get("rango_max"),
                                         it.get("opciones_lista_json"),
                                         current_username())
                                    )
                                    n_tareas_creadas += 1
                        conn2.commit()
                        try:
                            _mant_log(
                                "visita", vid, "plantilla_inicial",
                                f"{n_tareas_creadas} tarea(s) creadas al crear OT "
                                f"(plantilla_id={plant_id_inicial}, "
                                f"máquinas={len(maq_ids_inicial)})"
                            )
                        except Exception: pass
                    finally:
                        conn2.close()
            except Exception as _e_plant:
                print(f"[crear-ot] aplicar plantilla inicial falló: {_e_plant}",
                      flush=True)
        resp = {"ok": True, "id": vid, "modalidad_cobro": modalidad}
        if warn_mod:
            resp["warning"] = warn_mod
        if n_tareas_creadas:
            resp["tareas_creadas"] = n_tareas_creadas
        return jsonify(resp)
    finally:
        conn.close()


@app.route("/mantenciones/api/visitas/<int:vid>", methods=["PUT"])
@_mant_required
@_ot_can_metadata
def mant_visita_update(vid):
    d = request.get_json(silent=True) or {}
    # COMPAT: el dropdown legacy puede mandar `tecnico_id` esperando que sea
    # mant_tecnicos. Tras la migración, /api/tecnicos devuelve app_users.id.
    # Migramos silenciosamente para no romper el frontend.
    if "tecnico_id" in d and d["tecnico_id"] and "tecnico_user_id" not in d:
        d["tecnico_user_id"] = d["tecnico_id"]
        d["tecnico_id"] = None

    # FASE 1 — validar modalidad_cobro contra la regla "levantamiento != garantia".
    # Se evalúa con el tipo nuevo (si llega en el body) o el tipo actual de la BD.
    warn_mod_upd = None
    gar_aplica_upd = _parse_garantia_aplica(d.get("garantia_aplica"))
    # tipo_final se reusa para validar modalidad y mapear garantía. Solo
    # consultamos la BD cuando alguno de esos casos aplica (edits que solo
    # tocan técnico/fecha no pagan la query extra).
    tipo_final = ""
    if "modalidad_cobro" in d or "tipo" in d or gar_aplica_upd is not None:
        _tipo_actual = None
        if "tipo" not in d:
            _row_tipo = mysql_fetchone("SELECT tipo FROM mant_visitas WHERE id=%s", (vid,))
            _tipo_actual = (_row_tipo or {}).get("tipo")
        tipo_final = (d.get("tipo") or _tipo_actual or "").lower()
    if "modalidad_cobro" in d:
        mod_norm, warn_mod_upd = _normalizar_modalidad_cobro(tipo_final, d.get("modalidad_cobro"))
        d["modalidad_cobro"] = mod_norm

    # GARANTÍA TRANSVERSAL (Daniel 2026-05-30): el interruptor Aplica/No aplica
    # MANDA sobre modalidad_cobro suelta. Mapea a cubierto_por/modalidad_cobro/
    # estado_facturacion según el modelo canónico.
    if gar_aplica_upd is not None:
        cobertura_upd, warn_gar_upd = _mapear_garantia_a_cobertura(gar_aplica_upd, tipo_final)
        if cobertura_upd:
            d["cubierto_por"]   = cobertura_upd["cubierto_por"]
            d["modalidad_cobro"] = cobertura_upd["modalidad_cobro"]
            # No degradar el pipeline si ya hay una factura ligada: un servicio
            # ya 'facturado' marcado como "no aplica garantía" sigue facturado.
            _ef_actual = mysql_fetchone(
                "SELECT estado_facturacion FROM mant_visitas WHERE id=%s", (vid,))
            _ef_now = (_ef_actual or {}).get("estado_facturacion")
            if not (gar_aplica_upd is False and _ef_now == "facturado"):
                d["estado_facturacion"] = cobertura_upd["estado_facturacion"]
            if warn_gar_upd:
                warn_mod_upd = warn_gar_upd
    # Validar prioridad si llega
    if "prioridad" in d:
        p = (d.get("prioridad") or "").lower()
        d["prioridad"] = p if p in _OT_PRIORIDADES else "media"

    allowed = ["titulo","fecha_programada","fecha_realizada","hora_inicio","hora_fin",
               "tecnico","tecnico_user_id","tipo","estado","descripcion","observaciones",
               "costo","contrato_id",
               # FASE 1 — modelo Fracttal
               "modalidad_cobro","prioridad","diagnostico",
               # Garantía transversal (mapeada desde garantia_aplica)
               "cubierto_por","estado_facturacion"]
    # tecnico_user_id: si llega, validar que sea un app_users con role='tecnico'
    if "tecnico_user_id" in d and d["tecnico_user_id"]:
        try:
            tuid = int(d["tecnico_user_id"])
            u = mysql_fetchone(
                "SELECT 1 FROM app_users WHERE id=%s AND role='tecnico' AND active=1",
                (tuid,)
            )
            if not u:
                d["tecnico_user_id"] = None
            else:
                d["tecnico_user_id"] = tuid
        except (TypeError, ValueError):
            d["tecnico_user_id"] = None
    sets = [f"{f}=%s" for f in allowed if f in d]
    vals = [d[f] for f in allowed if f in d]
    if not sets:
        return jsonify({"error": "Sin campos"}), 400
    # 2026-05-22 (Daniel) — capturamos el técnico ANTES del UPDATE para
    # saber si cambió y notificar al nuevo técnico vía campana interna.
    tecnico_prev = None
    if "tecnico_user_id" in d:
        try:
            _prev = mysql_fetchone(
                "SELECT tecnico_user_id FROM mant_visitas WHERE id=%s", (vid,)
            )
            tecnico_prev = (_prev or {}).get("tecnico_user_id")
        except Exception:
            tecnico_prev = None
    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            cur.execute(f"UPDATE mant_visitas SET {','.join(sets)} WHERE id=%s",
                        vals + [vid])
        conn.commit()
        _mant_log("visita", vid, "actualizada",
                  f"⚠ {warn_mod_upd}" if warn_mod_upd else "")
        # Si el técnico cambió (o se asignó por primera vez), notificar.
        tecnico_nuevo = d.get("tecnico_user_id")
        try:
            if tecnico_nuevo and (not tecnico_prev or int(tecnico_prev) != int(tecnico_nuevo)):
                motivo = "reasignada" if tecnico_prev else "asignada"
                try: _notificar_ot_asignada_interna(vid, tecnico_nuevo, motivo=motivo)
                except Exception as _e_nai: print(f"[upd-ot notif] {_e_nai}", flush=True)
                try: _notificar_ot_asignada(vid)
                except Exception as _e_naw: print(f"[upd-ot wa] {_e_naw}", flush=True)
        except Exception as _e_chk:
            print(f"[upd-ot check tecnico] {_e_chk}", flush=True)
        resp = {"ok": True}
        if warn_mod_upd:
            resp["warning"] = warn_mod_upd
        return jsonify(resp)
    finally:
        conn.close()


@app.route("/mantenciones/api/visitas/<int:vid>", methods=["DELETE"])
@_mant_required
@_ot_can_eliminar
def mant_visita_del(vid):
    # 🔐 SEGURIDAD 2026-05-22 (Daniel): el DELETE de OT es STRICT.
    # Solo superadmin puede eliminar definitivamente (validado por
    # @_ot_can_eliminar → matriz `_puede_ot_accion('eliminar')`).
    # Admin puede EDITAR (PUT) pero NO eliminar; ejecutivo no puede
    # ninguna de las dos. Si quieren cancelar una OT mal creada, deben
    # usar PUT estado='cancelada' (conserva historial).
    # Mantenemos chequeo defensivo redundante (defense in depth):
    _u = getattr(g, "user", None) or {}
    _role = (_u.get("role") or "").lower()
    if _role != "superadmin":
        print(
            f"[SECURITY] {_u.get('id')} ({_u.get('username')}) intento DELETE "
            f"vid={vid} sin permiso (role={_role})",
            flush=True
        )
        return jsonify({
            "ok": False,
            "error": "Solo el superadministrador puede eliminar una OT. "
                     "Si necesitas cancelarla, usa el botón 'Cancelar OT' "
                     "que cambia el estado pero conserva el historial.",
            "error_codigo": "OT_DELETE_RESTRINGIDO",
        }), 403
    # Capturar info ANTES de borrar para el log y para encontrar levantamiento asociado
    v_info = mysql_fetchone(
        "SELECT cliente_id, numero_ot, titulo, fecha_programada, levantamiento_id "
        "  FROM mant_visitas WHERE id=%s", (vid,)
    )
    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            # Sincronizar: si la OT tiene un levantamiento asociado, marcarlo cancelado
            # (antes quedaba huérfano y bloqueaba la creación de nuevos levantamientos).
            if v_info and v_info.get("levantamiento_id"):
                try:
                    cur.execute(
                        "UPDATE mant_levantamientos "
                        "   SET estado='cancelado', fecha_cierre=NOW() "
                        " WHERE id=%s AND estado IN ('borrador','en_curso')",
                        (v_info["levantamiento_id"],)
                    )
                except Exception as _e_sync:
                    print(f"[visita_del] sync levantamiento falló: {_e_sync}", flush=True)
            cur.execute("DELETE FROM mant_visitas WHERE id=%s", (vid,))
        conn.commit()
        if v_info:
            ot = v_info.get("numero_ot") or f"V-{vid}"
            _mant_log("visita", vid, "eliminada", f"{ot} — {v_info.get('titulo') or ''}")
            _mant_log("cliente", v_info.get("cliente_id"), "visita_eliminada", f"{ot}")
        return jsonify({"ok": True})
    finally:
        conn.close()


# ══════════════════════════════════════════════════════════════════════
# MÓDULO TICKETS — sistema de solicitudes/incidencias del cliente
#
# Paralelo a OT/visitas. Útil para tracking de:
#   - Cambios de equipos (ej: 4 trotadoras Deportes Bitácora)
#   - Fallas urgentes reportadas por el cliente
#   - Consultas/cotizaciones
#   - Garantías
#
# Un ticket puede vincularse a una OT/visita cuando requiere terreno.
# ══════════════════════════════════════════════════════════════════════

def _next_ticket_number():
    """Genera el próximo N° ticket. Formato: TKT-YYYY-NNNNN"""
    year = datetime.now().year
    prefix = f"TKT-{year}-"
    last = mysql_fetchone(
        "SELECT numero_ticket FROM mant_tickets "
        "WHERE numero_ticket LIKE %s ORDER BY id DESC LIMIT 1",
        (f"{prefix}%",)
    )
    next_n = 1
    if last and last.get("numero_ticket"):
        try:
            seq = last["numero_ticket"].split("-")[-1]
            next_n = int(seq) + 1
        except Exception:
            next_n = 1
    return f"{prefix}{next_n:05d}"


def _ticket_log(ticket_id, tipo, contenido, usuario=None, metadata=None, es_interno=True):
    """Agrega entrada a la bitácora del ticket."""
    try:
        mysql_execute(
            "INSERT INTO mant_ticket_bitacora "
            "(ticket_id, tipo, contenido, metadata, usuario, es_interno) "
            "VALUES (%s,%s,%s,%s,%s,%s)",
            (ticket_id, tipo, contenido,
             json.dumps(metadata) if metadata else None,
             usuario or current_username(),
             1 if es_interno else 0)
        )
    except Exception as e:
        print(f"[ticket_log] error: {e}")


@app.route("/mantenciones/api/tickets", methods=["GET"])
@_mant_required
def mant_tickets_list_api():
    """Lista tickets con filtros opcionales (estado, prioridad, cliente, tipo, q)."""
    where = ["1=1"]
    params = []
    estado = (request.args.get("estado") or "").strip().lower()
    prio   = (request.args.get("prioridad") or "").strip().lower()
    tipo   = (request.args.get("tipo") or "").strip().lower()
    cid    = request.args.get("cliente_id")
    q      = (request.args.get("q") or "").strip()
    if estado in ("abierto","en_proceso","esperando_cliente","esperando_repuesto","resuelto","cerrado","cancelado"):
        where.append("t.estado=%s"); params.append(estado)
    if prio in ("baja","media","alta","urgente"):
        where.append("t.prioridad=%s"); params.append(prio)
    if tipo in ("cambio","garantia","falla","consulta","cotizacion","presupuesto","seguimiento","otro"):
        where.append("t.tipo=%s"); params.append(tipo)
    if cid:
        try:
            params.append(int(cid))
            where.append("t.cliente_id=%s")
        except (TypeError, ValueError): pass
    if q:
        where.append("(t.titulo LIKE %s OR t.descripcion LIKE %s OR t.numero_ticket LIKE %s OR c.razon_social LIKE %s)")
        like = f"%{q}%"
        params.extend([like, like, like, like])

    sql = (
        "SELECT t.id, t.numero_ticket, t.titulo, t.tipo, t.prioridad, t.estado, "
        "       t.cliente_id, c.razon_social, c.rut AS cliente_rut, "
        "       t.solicitante, t.asignado_a, t.tecnico_id, "
        "       mt.nombre AS tecnico_nombre, "
        "       t.fecha_limite, t.visita_id, "
        "       t.created_by, t.created_at, t.cerrado_at, "
        "       (SELECT COUNT(*) FROM mant_ticket_equipos WHERE ticket_id=t.id) AS n_equipos, "
        "       (SELECT COUNT(*) FROM mant_ticket_bitacora WHERE ticket_id=t.id) AS n_eventos "
        "  FROM mant_tickets t "
        "  JOIN mant_clientes c ON c.id=t.cliente_id "
        "  LEFT JOIN mant_tecnicos mt ON mt.id=t.tecnico_id "
        f" WHERE {' AND '.join(where)} "
        " ORDER BY "
        "   CASE t.estado WHEN 'abierto' THEN 1 WHEN 'en_proceso' THEN 2 "
        "                  WHEN 'esperando_cliente' THEN 3 WHEN 'esperando_repuesto' THEN 4 "
        "                  WHEN 'resuelto' THEN 5 WHEN 'cerrado' THEN 6 ELSE 7 END, "
        "   CASE t.prioridad WHEN 'urgente' THEN 1 WHEN 'alta' THEN 2 WHEN 'media' THEN 3 ELSE 4 END, "
        "   t.created_at DESC "
        " LIMIT 300"
    )
    try:
        rows = mysql_fetchall(sql, tuple(params)) or []
    except Exception as e:
        return jsonify({"ok": False, "error": f"Error consulta: {e}"}), 500

    # KPIs
    try:
        kpis = mysql_fetchone(
            "SELECT "
            " COUNT(*) AS total, "
            " SUM(CASE WHEN estado IN ('abierto','en_proceso') THEN 1 ELSE 0 END) AS activos, "
            " SUM(CASE WHEN prioridad='urgente' AND estado NOT IN ('cerrado','cancelado') THEN 1 ELSE 0 END) AS urgentes, "
            " SUM(CASE WHEN fecha_limite < CURDATE() AND estado NOT IN ('cerrado','cancelado','resuelto') THEN 1 ELSE 0 END) AS vencidos "
            "FROM mant_tickets"
        ) or {}
    except Exception:
        kpis = {}

    return jsonify({
        "ok": True,
        "tickets": [dict(r) for r in rows],
        "kpis": dict(kpis),
        "total": len(rows),
    })


@app.route("/mantenciones/api/tickets", methods=["POST"])
@_mant_required
def mant_ticket_create():
    """Crea un ticket nuevo.

    Body JSON:
      cliente_id, titulo (obligatorios)
      descripcion, tipo, prioridad, canal_origen, solicitante,
      solicitante_tel, solicitante_email, asignado_a, tecnico_id,
      fecha_limite, notas_internas
      equipos_ids: [int] — máquinas afectadas
    """
    d = request.get_json(silent=True) or {}
    if not d.get("cliente_id") or not (d.get("titulo") or "").strip():
        return jsonify({"ok": False, "error": "cliente_id y titulo son obligatorios"}), 400

    cliente = mysql_fetchone("SELECT id FROM mant_clientes WHERE id=%s", (d["cliente_id"],))
    if not cliente:
        return jsonify({"ok": False, "error": "Cliente no encontrado"}), 404

    numero = _next_ticket_number()
    user = current_username() or "sistema"

    tipo = (d.get("tipo") or "consulta").lower()
    if tipo not in ("cambio","garantia","falla","consulta","cotizacion","presupuesto","seguimiento","otro"):
        tipo = "consulta"
    prio = (d.get("prioridad") or "media").lower()
    if prio not in ("baja","media","alta","urgente"): prio = "media"
    canal = (d.get("canal_origen") or "sistema").lower()
    if canal not in ("email","whatsapp","telefono","presencial","sistema","otro"):
        canal = "sistema"

    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            cur.execute(
                """INSERT INTO mant_tickets
                   (numero_ticket, cliente_id, titulo, descripcion, tipo, prioridad,
                    canal_origen, solicitante, solicitante_tel, solicitante_email,
                    asignado_a, tecnico_id, fecha_limite, notas_internas, created_by)
                   VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)""",
                (numero, d["cliente_id"], d["titulo"].strip()[:300],
                 (d.get("descripcion") or "").strip()[:5000],
                 tipo, prio, canal,
                 (d.get("solicitante") or "").strip()[:200],
                 (d.get("solicitante_tel") or "").strip()[:50],
                 (d.get("solicitante_email") or "").strip()[:200],
                 (d.get("asignado_a") or "").strip()[:190] or user,
                 int(d["tecnico_id"]) if d.get("tecnico_id") else None,
                 d.get("fecha_limite") or None,
                 (d.get("notas_internas") or "").strip()[:5000],
                 user)
            )
            ticket_id = cur.lastrowid
            # Equipos asociados
            equipos_ids = d.get("equipos_ids") or []
            for mid in equipos_ids:
                try:
                    cur.execute(
                        "INSERT IGNORE INTO mant_ticket_equipos (ticket_id, maquina_id, cantidad) "
                        "VALUES (%s,%s,1)",
                        (ticket_id, int(mid))
                    )
                except Exception: pass
        conn.commit()
        # Log en bitácora
        _ticket_log(ticket_id, "creacion",
                    f"Ticket {numero} creado por {user} — tipo: {tipo} · prioridad: {prio}"
                    + (f" · {len(equipos_ids)} equipo(s)" if equipos_ids else ""))
        # Log general
        try:
            _mant_log("cliente", d["cliente_id"], "ticket_creado", f"{numero}: {d['titulo']}")
        except Exception: pass
        return jsonify({"ok": True, "id": ticket_id, "numero_ticket": numero})
    finally:
        conn.close()


@app.route("/mantenciones/api/tickets/<int:tid>", methods=["GET"])
@_mant_required
def mant_ticket_get_api(tid):
    """Devuelve detalle del ticket + equipos + bitácora."""
    t = mysql_fetchone(
        "SELECT t.*, c.razon_social, c.rut AS cliente_rut, c.contacto_nombre, "
        "       c.contacto_tel, c.contacto_email, "
        "       mt.nombre AS tecnico_nombre, mt.telefono AS tecnico_tel "
        "  FROM mant_tickets t "
        "  JOIN mant_clientes c ON c.id=t.cliente_id "
        "  LEFT JOIN mant_tecnicos mt ON mt.id=t.tecnico_id "
        " WHERE t.id=%s", (tid,)
    )
    if not t:
        return jsonify({"ok": False, "error": "Ticket no encontrado"}), 404
    equipos = mysql_fetchall(
        "SELECT te.cantidad, te.notas, m.id AS maquina_id, m.nombre, m.sku, m.serie, m.estado_op "
        "  FROM mant_ticket_equipos te "
        "  JOIN mant_maquinas m ON m.id=te.maquina_id "
        " WHERE te.ticket_id=%s ORDER BY m.nombre", (tid,)
    ) or []
    bitacora = mysql_fetchall(
        "SELECT * FROM mant_ticket_bitacora WHERE ticket_id=%s ORDER BY created_at DESC LIMIT 100",
        (tid,)
    ) or []
    return jsonify({
        "ok": True,
        "ticket": dict(t),
        "equipos": [dict(r) for r in equipos],
        "bitacora": [dict(r) for r in bitacora],
    })


@app.route("/mantenciones/api/tickets/<int:tid>", methods=["PATCH"])
@_mant_required
def mant_ticket_update(tid):
    """Actualiza campos del ticket. Loguea cambios sensibles en bitácora."""
    d = request.get_json(silent=True) or {}
    t_old = mysql_fetchone("SELECT * FROM mant_tickets WHERE id=%s", (tid,))
    if not t_old:
        return jsonify({"ok": False, "error": "Ticket no encontrado"}), 404
    allowed = ["titulo","descripcion","tipo","prioridad","estado","canal_origen",
               "solicitante","solicitante_tel","solicitante_email","asignado_a",
               "tecnico_id","fecha_limite","notas_internas","visita_id"]
    sets, vals, eventos = [], [], []
    user = current_username() or "sistema"
    for f in allowed:
        if f in d:
            sets.append(f"{f}=%s")
            vals.append(d[f] if d[f] not in ("",) else None)
            # Trackear cambios sensibles
            if t_old.get(f) != d[f] and f in ("estado","prioridad","asignado_a","tecnico_id"):
                eventos.append((f, t_old.get(f), d[f]))
    if not sets:
        return jsonify({"ok": False, "error": "Sin cambios"}), 400

    # Si pasa a cerrado/resuelto, setear cerrado_at/cerrado_por
    nuevo_estado = d.get("estado")
    if nuevo_estado in ("cerrado", "resuelto") and t_old.get("estado") not in ("cerrado", "resuelto"):
        sets.append("cerrado_at=NOW()");
        sets.append("cerrado_por=%s"); vals.append(user)

    try:
        mysql_execute(
            f"UPDATE mant_tickets SET {','.join(sets)} WHERE id=%s",
            tuple(vals) + (tid,)
        )
    except Exception as e:
        return jsonify({"ok": False, "error": f"Error: {e}"}), 500

    # Bitácora de cambios
    for campo, antes, nuevo in eventos:
        _ticket_log(tid, "cambio_estado" if campo == "estado" else "asignacion",
                    f"{campo}: '{antes or '—'}' → '{nuevo or '—'}'",
                    metadata={"campo": campo, "antes": antes, "nuevo": str(nuevo)})
    return jsonify({"ok": True})


