# ═════════════════════════════════════════════════════════════════════
# OT — LISTADO GLOBAL DE ÓRDENES DE TRABAJO
# Vista pro: todas las OTs con filtros (estado, técnico, cliente, rango)
# ═════════════════════════════════════════════════════════════════════

@app.route("/mantenciones/ots")
@_mant_required
def mant_ots_list():
    """Listado global de Órdenes de Trabajo (visitas) con filtros.

    🔐 SEGURIDAD 2026-05-18 (Daniel) — filtro por rol:
      - tecnico / tecnico_externo: SIEMPRE `solo_mias` (no puede ver
        ajenas — refuerzo doble; cualquier intento se ignora server-side).
      - ejecutivo (ej. Aaron): por DEFAULT ve SOLO las OTs que él CREÓ
        (`created_by = self.username`). Puede pasar `?todas=1` para ver
        el resto del módulo (consultivo, sin ejecutar).
      - admin / superadmin: ve TODAS por default. Puede usar `?solo_mias=1`
        para filtrar SOLO sus asignadas (raramente útil para ellos).
      - Otros roles (editor, lector, vendedor) → no llegan acá porque el
        decorador @_mant_required ya los bloquea por permisos.
    """
    estado     = (request.args.get("estado") or "").strip().lower()
    tipo       = (request.args.get("tipo") or "").strip().lower()
    tecnico_id = request.args.get("tecnico_id")
    cliente_id = request.args.get("cliente_id")
    q          = (request.args.get("q") or "").strip()
    solo_mias  = request.args.get("solo_mias") == "1"
    ver_todas  = request.args.get("todas") == "1"

    # ── Lógica por rol (matriz 2026-05-18) ──────────────────────────
    # FIX 2026-05-18 (Aaron Urbina): normalizamos vía `_rol_familia` para que
    # variantes dinámicas (ejecutivo_sstt, tecnico_externo, etc.) caigan en
    # la familia correcta.
    user = getattr(g, "user", None) or {}
    role_l = (user.get("role") or "").lower()
    role_fam = _rol_familia(role_l)
    es_tecnico   = (role_fam == "tecnico")
    es_ejecutivo = (role_fam == "ejecutivo")
    # Técnico: forzar solo_mias siempre (refuerzo IDOR — antes intentaba
    # manipular ?solo_mias=0 para ver ajenas).
    if es_tecnico:
        solo_mias = True

    where = ["1=1"]
    params = []

    # ── EJECUTIVO (Aaron) — filtrar a sus OTs (creadas + asignadas) por DEFAULT ──
    # Daniel: "el ejecutivo NO ejecuta — solo crea/supervisa". Por
    # default mostramos las OTs que él mismo creó (created_by =
    # username/nombre) **O las que tiene asignadas como técnico**.
    # Puede pasar ?todas=1 para ver el resto del módulo (útil para
    # coordinar), pero igualmente no puede ejecutarlas si no es responsable.
    #
    # FIX 2026-05-22 (Aaron Urbina ejecutivo_sstt — brecha listado vacío):
    # `created_by` es un VARCHAR que históricamente guardó lo que devolvió
    # `current_username()` — a veces el email (`username`), a veces el
    # nombre legible. Si los formatos no coinciden, el match LOWER(TRIM())
    # falla y el listado queda VACÍO aunque el calendario sí muestre la OT
    # (ya pasó con Aaron: created_by='Aaron Urbina' (nombre)
    # vs username='urbinaaaron65@gmail.com').
    # Solución defensiva: comparamos contra TODAS las identidades posibles
    # (username, nombre legible) Y además contra el nuevo `created_by_user_id`
    # (FK estable). Si la columna nueva existe → match exacto por id.
    if es_ejecutivo and not ver_todas and not solo_mias:
        username_actual = (user.get("username") or "").strip()
        nombre_actual = (user.get("nombre") or "").strip()
        user_id_actual = user.get("id")
        # Detectar si la columna `created_by_user_id` ya fue migrada.
        # Hacemos un SELECT cheap a INFORMATION_SCHEMA — si falla por
        # cualquier motivo, caemos al match legacy (solo string).
        _has_created_by_user_id = False
        try:
            _col_check = mysql_fetchone(
                "SELECT COUNT(*) AS n FROM INFORMATION_SCHEMA.COLUMNS "
                " WHERE TABLE_SCHEMA = DATABASE() "
                "   AND TABLE_NAME = 'mant_visitas' "
                "   AND COLUMN_NAME = 'created_by_user_id'"
            )
            _has_created_by_user_id = bool((_col_check or {}).get("n"))
        except Exception:
            _has_created_by_user_id = False

        clauses = []
        # Match por FK estable (preferido — no depende del formato del string).
        if _has_created_by_user_id and user_id_actual:
            clauses.append("v.created_by_user_id=%s")
            params.append(int(user_id_actual))
        # Match legacy contra `created_by` por username (email) — compat con
        # OTs creadas antes de la migración del FK.
        if username_actual:
            clauses.append("LOWER(TRIM(v.created_by))=LOWER(TRIM(%s))")
            params.append(username_actual)
        # Match legacy contra `created_by` por nombre legible — para OTs donde
        # el string guardó el nombre en vez del email (caso Aaron OT-2026-00008,
        # created_by='Aaron Urbina' vs username='urbinaaaron65@gmail.com').
        if nombre_actual and nombre_actual.lower() != username_actual.lower():
            clauses.append("LOWER(TRIM(v.created_by))=LOWER(TRIM(%s))")
            params.append(nombre_actual)
        # Match como técnico asignado (principal o colaborador).
        if user_id_actual:
            clauses.append("v.tecnico_user_id=%s")
            params.append(int(user_id_actual))
            clauses.append(
                "v.id IN (SELECT visita_id FROM mant_visita_tecnicos "
                "         WHERE tecnico_user_id=%s)"
            )
            params.append(int(user_id_actual))
        if clauses:
            where.append("(" + " OR ".join(clauses) + ")")

    # Filtro "mis OTs": muestra TODAS las OTs donde el usuario aparece como
    # técnico, sea como principal (v.tecnico_user_id) o como colaborador en
    # mant_visita_tecnicos.tecnico_user_id (multi-técnico Fracttal).
    # Fallback legacy: si el usuario tiene email match en mant_tecnicos,
    # también ve OTs apuntadas a ese técnico legacy (compat con OTs viejas).
    if solo_mias and user:
        try:
            uid = user.get("id")
            me_tec = mysql_fetchone(
                "SELECT id FROM mant_tecnicos WHERE LOWER(TRIM(email))=LOWER(TRIM(%s)) "
                "AND COALESCE(activo,1)=1 LIMIT 1",
                (user.get("username") or user.get("correo") or user.get("email") or "",)
            ) if (user.get("username") or user.get("correo") or user.get("email")) else None

            if uid:
                # Match principal (v.tecnico_user_id) OR multi-técnico
                # (mant_visita_tecnicos.tecnico_user_id) OR legacy (mant_tecnicos)
                if me_tec:
                    where.append(
                        "(v.tecnico_user_id=%s "
                        " OR v.id IN (SELECT visita_id FROM mant_visita_tecnicos "
                        "             WHERE tecnico_user_id=%s) "
                        " OR v.tecnico_id=%s)"
                    )
                    params.extend([int(uid), int(uid), int(me_tec["id"])])
                else:
                    where.append(
                        "(v.tecnico_user_id=%s "
                        " OR v.id IN (SELECT visita_id FROM mant_visita_tecnicos "
                        "             WHERE tecnico_user_id=%s))"
                    )
                    params.extend([int(uid), int(uid)])
            elif me_tec:
                where.append("v.tecnico_id=%s")
                params.append(int(me_tec["id"]))
            else:
                # No tiene id de usuario ni técnico legacy → no muestra nada
                where.append("1=0")
            # Por defecto, técnico solo ve OTs activas (no cerradas históricas)
            if (uid or me_tec) and not estado:
                where.append("v.estado IN ('programada','en_curso','reagendada')")
        except Exception as e_tec:
            print(f"[mant_ots_list solo_mias] error: {e_tec}", flush=True)

    if estado in ("programada", "completada", "cancelada", "reagendada", "en_curso"):
        where.append("v.estado=%s")
        params.append(estado)
    if tipo in ("preventiva", "correctiva", "garantia", "inspeccion", "levantamiento", "instalacion"):
        where.append("v.tipo=%s")
        params.append(tipo)
    if tecnico_id:
        try:
            params.append(int(tecnico_id))
            where.append("v.tecnico_id=%s")
        except (TypeError, ValueError):
            pass
    if cliente_id:
        try:
            params.append(int(cliente_id))
            where.append("v.cliente_id=%s")
        except (TypeError, ValueError):
            pass
    if q:
        where.append("(c.razon_social LIKE %s OR v.titulo LIKE %s OR v.numero_ot LIKE %s)")
        like = f"%{q}%"
        params.extend([like, like, like])

    ots = []
    kpis = {"total": 0, "programadas": 0, "completadas": 0, "atrasadas": 0}
    tecnicos = []
    fatal_error = None
    try:
        # ── PERF: en vez de 3 subqueries correlacionadas POR fila (~600 queries
        # con LIMIT 200), usamos LEFT JOIN a derivadas agregadas. Total: 1 query.
        sql = (
            "SELECT v.id, v.numero_ot, v.tipo, v.estado, v.titulo, v.descripcion, "
            "       v.fecha_programada, v.hora_inicio, v.hora_fin, v.costo, "
            "       v.cliente_id, c.razon_social, c.comuna AS cli_comuna, "
            "       v.tecnico_id, t.nombre AS tecnico_nombre, "
            "       v.created_by, "
            "       COALESCE(tar.n_tareas, 0)    AS n_tareas, "
            "       COALESCE(tar.n_completas, 0) AS n_completas, "
            "       COALESCE(fot.n_fotos, 0)     AS n_fotos "
            "  FROM mant_visitas v "
            "  JOIN mant_clientes c ON c.id=v.cliente_id "
            "  LEFT JOIN mant_tecnicos t ON t.id=v.tecnico_id "
            "  LEFT JOIN ( "
            "       SELECT visita_id, "
            "              COUNT(*) AS n_tareas, "
            "              SUM(CASE WHEN completada=1 THEN 1 ELSE 0 END) AS n_completas "
            "         FROM mant_visita_tareas "
            "       GROUP BY visita_id"
            "  ) tar ON tar.visita_id = v.id "
            "  LEFT JOIN ( "
            "       SELECT visita_id, COUNT(*) AS n_fotos "
            "         FROM mant_visita_fotos "
            "       GROUP BY visita_id"
            "  ) fot ON fot.visita_id = v.id "
            f" WHERE {' AND '.join(where)} "
            " ORDER BY v.fecha_programada DESC, v.id DESC "
            " LIMIT 200"
        )
        ots = mysql_fetchall(sql, tuple(params)) or []
        ots = [dict(o) for o in ots]
        # Normalizar campos no-JSON-safe (date/time/Decimal) para el JSON
        # de la vista (Kanban/Cards lo consumen client-side).
        for o in ots:
            for k in ('fecha_programada','hora_inicio','hora_fin'):
                if o.get(k) is not None:
                    o[k] = str(o[k])
            if o.get('costo') is not None:
                try: o['costo'] = float(o['costo'])
                except Exception: o['costo'] = None
    except Exception as e:
        # Fallback simple si subqueries fallan (ej. tablas no migradas aún)
        try:
            ots = mysql_fetchall(
                "SELECT v.id, v.numero_ot, v.tipo, v.estado, v.titulo, v.descripcion, "
                "       v.fecha_programada, v.hora_inicio, v.hora_fin, v.costo, "
                "       v.cliente_id, c.razon_social, c.comuna AS cli_comuna, "
                "       v.tecnico_id, v.tecnico AS tecnico_nombre, "
                "       v.created_by, "
                "       0 AS n_tareas, 0 AS n_completas, 0 AS n_fotos "
                "  FROM mant_visitas v "
                "  JOIN mant_clientes c ON c.id=v.cliente_id "
                f" WHERE {' AND '.join(where)} "
                " ORDER BY v.fecha_programada DESC, v.id DESC LIMIT 200",
                tuple(params)
            ) or []
            ots = [dict(o) for o in ots]
            for o in ots:
                for k in ('fecha_programada','hora_inicio','hora_fin'):
                    if o.get(k) is not None:
                        o[k] = str(o[k])
                if o.get('costo') is not None:
                    try: o['costo'] = float(o['costo'])
                    except Exception: o['costo'] = None
        except Exception as e2:
            fatal_error = f"{e} / fallback: {e2}"
            ots = []

    # KPIs respetan el MISMO filtro que la tabla — para que el técnico vea
    # SUS contadores (no los globales del sistema). Antes había un BUG donde
    # mostraba "1 TOTAL" pero la lista filtrada decía 0 (KPI no filtrado).
    try:
        # Reutilizamos el `where` ya construido (incluye solo_mias para tec).
        kpis_sql = (
            "SELECT "
            " COUNT(*) AS total, "
            " SUM(CASE WHEN v.estado='programada' THEN 1 ELSE 0 END) AS programadas, "
            " SUM(CASE WHEN v.estado='completada' THEN 1 ELSE 0 END) AS completadas, "
            " SUM(CASE WHEN v.estado='programada' AND v.fecha_programada < CURDATE() THEN 1 ELSE 0 END) AS atrasadas "
            "FROM mant_visitas v "
            "JOIN mant_clientes c ON c.id=v.cliente_id "
            f"WHERE {' AND '.join(where)}"
        )
        kpis = mysql_fetchone(kpis_sql, tuple(params)) or kpis
    except Exception as e_kpi:
        print(f"[mant_ots_list kpis] error: {e_kpi}", flush=True)

    try:
        tecnicos = mysql_fetchall(
            "SELECT id, nombre FROM mant_tecnicos WHERE estado='activo' ORDER BY nombre"
        ) or []
        tecnicos = [dict(t) for t in tecnicos]
    except Exception:
        tecnicos = []

    # ── 2026-05-18 (Aaron Urbina fix) ─────────────────────────────
    # Inyectar `puede_aprobar` por OT y un flag global `puede_aprobar_global`
    # para el template. ANTES el template usaba `permissions.admin or
    # permissions.superadmin` literal → ejecutivo_sstt (rol dinámico) no
    # tenía permissions.admin=True, así que el botón "Revisar" jamás
    # aparecía aunque la matriz `_puede_ot_accion('aprobar')` sí lo
    # permitía. Ahora el flag se calcula server-side con la matriz
    # unificada y el template solo lo lee.
    #
    # Por performance NO recalculamos por OT (sería N+1 queries a
    # mant_visitas + mant_visita_tecnicos). En su lugar inferimos:
    #   - si es admin/superadmin/supervisor/ejecutivo (familia) → True
    #     para CUALQUIER OT (matchea la matriz exactamente).
    #   - si NO, fallback al check del creador (created_by ==
    #     user.username, case insensitive + trim).
    # El backend de aprobar-cierre revalida con `_puede_ot_accion`,
    # así que aunque alguien fuerce el botón, el server bloquea.
    puede_aprobar_global = _is_aprobador(user)
    _username_lower = (user.get("username") or "").strip().lower()
    _n_aprob = 0
    _n_pendientes = 0
    for _o in ots:
        if puede_aprobar_global:
            _o["puede_aprobar"] = True
        else:
            _created_by = (_o.get("created_by") or "").strip().lower()
            _o["puede_aprobar"] = bool(_created_by) and _created_by == _username_lower
        if _o.get("puede_aprobar"):
            _n_aprob += 1
        if (_o.get("estado") or "") == "pendiente_aprobacion":
            _n_pendientes += 1

    # 🔍 Log para diagnóstico (Daniel pidió poder ver en Railway logs por qué
    # aparece o no el botón "Revisar" para Aaron). Se emite SIEMPRE.
    print(
        f"[ots_list] user={user.get('username')} role={role_l}->{role_fam} "
        f"mostrando={len(ots)} pendientes_aprobacion={_n_pendientes} "
        f"con_puede_aprobar={_n_aprob} puede_aprobar_global={puede_aprobar_global} "
        f"es_tecnico={es_tecnico} es_ejecutivo={es_ejecutivo} "
        f"solo_mias={solo_mias} ver_todas={ver_todas}",
        flush=True
    )

    return render_template(
        "mantenciones/ots_list.html",
        ots=ots,
        kpis=kpis,
        tecnicos=tecnicos,
        fatal_error=fatal_error,
        filtros={
            "estado": estado, "tipo": tipo,
            "tecnico_id": tecnico_id, "cliente_id": cliente_id, "q": q,
        },
        # 🔐 2026-05-18 — Flags de rol para el template (ocultar botones
        # de "Eliminar" / "Editar" que el rol no debería ver).
        es_tecnico=es_tecnico,
        es_ejecutivo=es_ejecutivo,
        ver_todas=ver_todas,
        solo_mias_activo=solo_mias,
        # 2026-05-18 (Aaron Urbina) — Permisos de aprobación inyectados
        # desde la matriz para que el template no use comparaciones de
        # rol literal que no soportan variantes dinámicas (ejecutivo_sstt).
        puede_aprobar_global=puede_aprobar_global,
    )


