# PLANTILLAS DE CHECKLIST — UI
# ═════════════════════════════════════════════════════════════════════

@app.route("/mantenciones/plantillas")
@_mant_required
def mant_plantillas_page():
    """Página de gestión de plantillas de checklist."""
    return render_template("mantenciones/plantillas.html")


# ═════════════════════════════════════════════════════════════════════
# PLANTILLAS DE CHECKLIST (modelo Fracttal)
#
# Una plantilla es un conjunto reusable de items (preguntas/campos).
# Cada item tiene un tipo de respuesta entre 9 posibles:
#   check         → casilla simple (tarea tradicional, valor implícito completada)
#   texto         → texto libre
#   sino          → enum: si / no / na
#   numero        → numérico con unidad y rango opcional
#   verificacion  → tricolor aprobado/alerta/falla (modelo Fracttal)
#   gps           → captura coordenadas del dispositivo
#   lista         → dropdown con opciones predefinidas (JSON)
#   fecha_hora    → datetime picker
#   foto          → tarea que requiere subir foto al completar
#
# Al aplicar una plantilla a una OT, sus items se CLONAN como
# mant_visita_tareas. La plantilla puede editarse después sin afectar
# OTs ya creadas (snapshot lógico).
# ═════════════════════════════════════════════════════════════════════

# Tipos de respuesta permitidos (cualquier valor fuera de esta lista se rechaza)
_TAREA_TIPOS_RESPUESTA = (
    "check", "texto", "sino", "numero", "verificacion",
    "gps", "lista", "fecha_hora", "foto",
)
_PLANT_TIPO_VISITA = (
    "preventiva", "correctiva", "garantia", "levantamiento",
    "inspeccion", "instalacion", "otro",
)


def _validar_item_plantilla(d):
    """Normaliza y valida un item de plantilla. Devuelve dict listo para INSERT
    o (None, error_str)."""
    titulo = (d.get("titulo") or "").strip()[:300]
    if not titulo:
        return None, "Título requerido"
    tipo = (d.get("tipo_respuesta") or "check").strip().lower()
    if tipo not in _TAREA_TIPOS_RESPUESTA:
        return None, f"tipo_respuesta inválido: {tipo}"
    opciones = None
    if tipo == "lista":
        ops_raw = d.get("opciones_lista") or d.get("opciones_lista_json") or []
        if isinstance(ops_raw, str):
            try:
                ops_raw = json.loads(ops_raw)
            except Exception:
                ops_raw = [s.strip() for s in ops_raw.split("\n") if s.strip()]
        if not isinstance(ops_raw, list) or not ops_raw:
            return None, "Tipo 'lista' requiere al menos una opción"
        opciones = json.dumps([str(x).strip()[:200] for x in ops_raw if str(x).strip()],
                              ensure_ascii=False)
    rmin = d.get("rango_min")
    rmax = d.get("rango_max")
    try: rmin = float(rmin) if rmin not in (None, "") else None
    except Exception: rmin = None
    try: rmax = float(rmax) if rmax not in (None, "") else None
    except Exception: rmax = None
    return {
        "orden":        int(d.get("orden") or 0),
        "titulo":       titulo,
        "descripcion":  (d.get("descripcion") or "").strip()[:2000] or None,
        "tipo_respuesta": tipo,
        "obligatoria":  1 if d.get("obligatoria") else 0,
        "requiere_foto":1 if d.get("requiere_foto") else 0,
        "unidad":       (d.get("unidad") or "").strip()[:30] or None,
        "rango_min":    rmin,
        "rango_max":    rmax,
        "opciones_lista_json": opciones,
    }, None


@app.route("/mantenciones/api/plantillas", methods=["GET"])
@_mant_required
def mant_plantillas_listar():
    """Lista plantillas con filtros (FASE 3 — selector inteligente):
        ?activa=1
        ?tipo_visita=preventiva|correctiva|garantia|...
        ?familia_checklist=instalacion|preventiva|correctivo|...
        ?familia_activo=cardio|trotadoras|todas|...
        ?q=texto
    """
    where, params = [], []
    if request.args.get("activa") == "1":
        where.append("activa=1")
    tv = (request.args.get("tipo_visita") or "").strip().lower()
    if tv in _PLANT_TIPO_VISITA:
        where.append("tipo_visita=%s"); params.append(tv)
    # FASE 3: filtros nuevos
    fchk = (request.args.get("familia_checklist") or "").strip().lower()
    _FAM_CHK_OK = ("instalacion","preventiva","correctivo","desinstalacion",
                   "capacitacion","registro_productos","operacional_interno",
                   "rendiciones","otro")
    if fchk in _FAM_CHK_OK:
        where.append("familia_checklist=%s"); params.append(fchk)
    fact = (request.args.get("familia_activo") or "").strip().lower()
    _FAM_ACT_OK = ("cardio","selectorizado","carga_libre","racks_estructuras",
                   "bancos","accesorios","bicicletas","trotadoras","otros","todas")
    if fact in _FAM_ACT_OK:
        # Buscar plantillas para esa familia O las que aplican a 'todas'
        where.append("(familia_activo=%s OR familia_activo='todas')")
        params.append(fact)
    q = (request.args.get("q") or "").strip()
    if q:
        where.append("(nombre LIKE %s OR descripcion LIKE %s)")
        params += [f"%{q}%", f"%{q}%"]
    wstr = (" WHERE " + " AND ".join(where)) if where else ""
    rows = mysql_fetchall(
        f"""SELECT p.*, COALESCE(it.cnt, 0) AS items_count
              FROM mant_tarea_plantillas p
              LEFT JOIN (SELECT plantilla_id, COUNT(*) AS cnt
                           FROM mant_tarea_plantilla_items
                          GROUP BY plantilla_id) it ON it.plantilla_id = p.id
              {wstr}
             ORDER BY p.activa DESC, p.es_sistema DESC, p.nombre""",
        tuple(params)
    ) or []
    return jsonify({
        "ok": True,
        "plantillas": [{
            "id": r["id"], "nombre": r["nombre"],
            "descripcion": r.get("descripcion") or "",
            "tipo_visita": r.get("tipo_visita") or "otro",
            "familia_checklist": r.get("familia_checklist") or "otro",
            "familia_activo": r.get("familia_activo") or "todas",
            "tiempo_estimado_min": r.get("tiempo_estimado_min"),
            "activa": bool(r.get("activa")),
            "es_sistema": bool(r.get("es_sistema")),
            "items_count": int(r.get("items_count") or 0),
            "created_by": r.get("created_by") or "",
            "created_at": str(r["created_at"])[:16] if r.get("created_at") else "",
        } for r in rows],
        "total": len(rows),
    })


@app.route("/mantenciones/api/plantillas/<int:pid>", methods=["GET"])
@_mant_required
def mant_plantilla_detalle(pid):
    """Devuelve plantilla + sus items."""
    plant = mysql_fetchone("SELECT * FROM mant_tarea_plantillas WHERE id=%s", (pid,))
    if not plant:
        return jsonify({"ok": False, "error": "Plantilla no encontrada"}), 404
    items = mysql_fetchall(
        "SELECT * FROM mant_tarea_plantilla_items "
        " WHERE plantilla_id=%s ORDER BY orden, id",
        (pid,)
    ) or []
    out_items = []
    for it in items:
        opciones = []
        if it.get("opciones_lista_json"):
            try: opciones = json.loads(it["opciones_lista_json"])
            except Exception: opciones = []
        out_items.append({
            "id": it["id"], "orden": it.get("orden") or 0,
            "titulo": it["titulo"], "descripcion": it.get("descripcion") or "",
            "tipo_respuesta": it.get("tipo_respuesta") or "check",
            "obligatoria": bool(it.get("obligatoria")),
            "requiere_foto": bool(it.get("requiere_foto")),
            "unidad": it.get("unidad") or "",
            "rango_min": float(it["rango_min"]) if it.get("rango_min") is not None else None,
            "rango_max": float(it["rango_max"]) if it.get("rango_max") is not None else None,
            "opciones_lista": opciones,
        })
    return jsonify({
        "ok": True,
        "plantilla": {
            "id": plant["id"], "nombre": plant["nombre"],
            "descripcion": plant.get("descripcion") or "",
            "tipo_visita": plant.get("tipo_visita") or "otro",
            "tiempo_estimado_min": plant.get("tiempo_estimado_min"),
            "activa": bool(plant.get("activa")),
            "es_sistema": bool(plant.get("es_sistema")),
            "created_by": plant.get("created_by") or "",
            "created_at": str(plant["created_at"])[:16] if plant.get("created_at") else "",
        },
        "items": out_items,
    })


@app.route("/mantenciones/api/plantillas", methods=["POST"])
@_mant_required
def mant_plantilla_crear():
    """Crea una plantilla con sus items en un solo POST.
    Body: { nombre, descripcion, tipo_visita, tiempo_estimado_min, items: [...] }
    """
    d = request.get_json(silent=True) or {}
    nombre = (d.get("nombre") or "").strip()[:200]
    if not nombre:
        return jsonify({"ok": False, "error": "Nombre requerido"}), 400
    tv = (d.get("tipo_visita") or "preventiva").lower()
    if tv not in _PLANT_TIPO_VISITA:
        tv = "otro"
    desc = (d.get("descripcion") or "").strip()[:2000]
    tiempo = d.get("tiempo_estimado_min")
    try: tiempo = int(tiempo) if tiempo not in (None, "") else None
    except Exception: tiempo = None

    items_in = d.get("items") or []
    items_norm = []
    for idx, raw in enumerate(items_in):
        norm, err = _validar_item_plantilla(raw)
        if err:
            return jsonify({"ok": False, "error": f"Item #{idx+1}: {err}"}), 400
        if norm.get("orden") in (0, None):
            norm["orden"] = idx + 1
        items_norm.append(norm)

    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            cur.execute(
                "INSERT INTO mant_tarea_plantillas "
                "(nombre, descripcion, tipo_visita, tiempo_estimado_min, activa, es_sistema, created_by) "
                "VALUES (%s,%s,%s,%s,1,0,%s)",
                (nombre, desc, tv, tiempo, current_username())
            )
            pid = cur.lastrowid
            for it in items_norm:
                cur.execute(
                    "INSERT INTO mant_tarea_plantilla_items "
                    "(plantilla_id, orden, titulo, descripcion, tipo_respuesta, "
                    " obligatoria, requiere_foto, unidad, rango_min, rango_max, opciones_lista_json) "
                    "VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)",
                    (pid, it["orden"], it["titulo"], it["descripcion"], it["tipo_respuesta"],
                     it["obligatoria"], it["requiere_foto"], it["unidad"],
                     it["rango_min"], it["rango_max"], it["opciones_lista_json"])
                )
        conn.commit()
        try:
            _mant_log("plantilla", pid, "creada", f"{nombre} ({len(items_norm)} items)")
        except Exception: pass
        return jsonify({"ok": True, "id": pid, "items_count": len(items_norm)})
    finally:
        conn.close()


@app.route("/mantenciones/api/plantillas/<int:pid>", methods=["PUT"])
@_mant_required
def mant_plantilla_actualizar(pid):
    """Actualiza la plantilla (header) y REEMPLAZA todos los items.
    Las OTs ya creadas con esta plantilla NO se ven afectadas (snapshot lógico).
    """
    plant = mysql_fetchone("SELECT id, es_sistema FROM mant_tarea_plantillas WHERE id=%s", (pid,))
    if not plant:
        return jsonify({"ok": False, "error": "Plantilla no encontrada"}), 404
    d = request.get_json(silent=True) or {}
    nombre = (d.get("nombre") or "").strip()[:200]
    if not nombre:
        return jsonify({"ok": False, "error": "Nombre requerido"}), 400
    tv = (d.get("tipo_visita") or "preventiva").lower()
    if tv not in _PLANT_TIPO_VISITA:
        tv = "otro"
    desc = (d.get("descripcion") or "").strip()[:2000]
    tiempo = d.get("tiempo_estimado_min")
    try: tiempo = int(tiempo) if tiempo not in (None, "") else None
    except Exception: tiempo = None
    activa = 1 if d.get("activa", True) else 0

    items_in = d.get("items") or []
    items_norm = []
    for idx, raw in enumerate(items_in):
        norm, err = _validar_item_plantilla(raw)
        if err:
            return jsonify({"ok": False, "error": f"Item #{idx+1}: {err}"}), 400
        if norm.get("orden") in (0, None):
            norm["orden"] = idx + 1
        items_norm.append(norm)

    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            cur.execute(
                "UPDATE mant_tarea_plantillas SET "
                " nombre=%s, descripcion=%s, tipo_visita=%s, "
                " tiempo_estimado_min=%s, activa=%s "
                "WHERE id=%s",
                (nombre, desc, tv, tiempo, activa, pid)
            )
            cur.execute("DELETE FROM mant_tarea_plantilla_items WHERE plantilla_id=%s", (pid,))
            for it in items_norm:
                cur.execute(
                    "INSERT INTO mant_tarea_plantilla_items "
                    "(plantilla_id, orden, titulo, descripcion, tipo_respuesta, "
                    " obligatoria, requiere_foto, unidad, rango_min, rango_max, opciones_lista_json) "
                    "VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)",
                    (pid, it["orden"], it["titulo"], it["descripcion"], it["tipo_respuesta"],
                     it["obligatoria"], it["requiere_foto"], it["unidad"],
                     it["rango_min"], it["rango_max"], it["opciones_lista_json"])
                )
        conn.commit()
        try:
            _mant_log("plantilla", pid, "actualizada", f"{nombre} ({len(items_norm)} items)")
        except Exception: pass
        return jsonify({"ok": True, "id": pid, "items_count": len(items_norm)})
    finally:
        conn.close()


@app.route("/mantenciones/api/plantillas/<int:pid>", methods=["DELETE"])
@_mant_required
def mant_plantilla_eliminar(pid):
    """Borra (soft) una plantilla. Las del sistema no se pueden borrar; solo
    desactivarse (activa=0)."""
    plant = mysql_fetchone("SELECT id, es_sistema, nombre FROM mant_tarea_plantillas WHERE id=%s", (pid,))
    if not plant:
        return jsonify({"ok": False, "error": "Plantilla no encontrada"}), 404
    if plant.get("es_sistema"):
        # Desactivar en vez de borrar
        mysql_execute("UPDATE mant_tarea_plantillas SET activa=0 WHERE id=%s", (pid,))
        try: _mant_log("plantilla", pid, "desactivada", plant["nombre"])
        except Exception: pass
        return jsonify({"ok": True, "desactivada": True})
    mysql_execute("DELETE FROM mant_tarea_plantillas WHERE id=%s", (pid,))
    try: _mant_log("plantilla", pid, "eliminada", plant["nombre"])
    except Exception: pass
    return jsonify({"ok": True})


@app.route("/mantenciones/api/visitas/<int:vid>/aplicar-plantilla", methods=["POST"])
@_mant_required
@_ot_can_configurar
def mant_visita_aplicar_plantilla(vid):
    """Aplica una plantilla a una OT: clona sus items como mant_visita_tareas.
    Body: { plantilla_id, maquina_ids?: [int,...]  // opcional: si viene,
            crea una copia de las tareas por cada máquina (útil para
            levantamiento fotográfico de N equipos) }
    """
    v = mysql_fetchone(
        "SELECT id, estado, cliente_id FROM mant_visitas WHERE id=%s", (vid,)
    )
    if not v:
        return jsonify({"ok": False, "error": "OT no encontrada"}), 404
    d = request.get_json(silent=True) or {}
    pid = d.get("plantilla_id")
    try: pid = int(pid)
    except (TypeError, ValueError):
        return jsonify({"ok": False, "error": "plantilla_id inválido"}), 400
    plant = mysql_fetchone(
        "SELECT id, nombre, activa FROM mant_tarea_plantillas WHERE id=%s", (pid,)
    )
    if not plant or not plant.get("activa"):
        return jsonify({"ok": False, "error": "Plantilla no encontrada o inactiva"}), 404

    items = mysql_fetchall(
        "SELECT * FROM mant_tarea_plantilla_items "
        " WHERE plantilla_id=%s ORDER BY orden, id",
        (pid,)
    ) or []
    if not items:
        return jsonify({"ok": False, "error": "Plantilla sin items"}), 400

    # Determinar máquinas objetivo (opcional)
    maquina_ids = d.get("maquina_ids") or []
    if maquina_ids:
        try: maquina_ids = [int(m) for m in maquina_ids]
        except Exception:
            return jsonify({"ok": False, "error": "maquina_ids inválido"}), 400

    # ── FIX 2026-05-22 (OT 2026-00004 Vitacura) — autoexpansión ─────
    # Bug observable: Aaron aplicaba plantilla SIN marcar máquinas →
    # tareas se insertaban con maquina_id=NULL → la vista del técnico
    # (mant_ot_ejecutar) filtra `vt.maquina_id IS NOT NULL` → Lenin
    # veía "Sin máquinas en esta OT" aunque la plantilla SÍ se aplicó.
    #
    # Política nueva: si el usuario no marca máquinas, autoexpandir a
    # TODAS las activas del cliente. Esto matchea el comportamiento
    # esperado del wizard `lev_crear` (que sí aplica plantilla por
    # equipo). El caller puede pasar explícitamente maquina_ids=[]
    # ¿imposible? — si es lista vacía, llegamos acá igual. Para conservar
    # el modo "tareas sueltas sin máquina" (uso anterior), aceptamos un
    # flag explícito `sin_maquina=True` en el body.
    sin_maquina = bool(d.get("sin_maquina"))
    if not maquina_ids and not sin_maquina:
        try:
            cliente_id_ot = v.get("cliente_id")
            if cliente_id_ot:
                rows_m = mysql_fetchall(
                    "SELECT id FROM mant_maquinas "
                    " WHERE cliente_id=%s "
                    "   AND COALESCE(estado,'activo') != 'baja' "
                    " ORDER BY nombre",
                    (cliente_id_ot,)
                ) or []
                maquina_ids = [int(r["id"]) for r in rows_m]
                if maquina_ids:
                    print(
                        f"[aplicar-plantilla] autoexpand vid={vid} sin maquina_ids → "
                        f"{len(maquina_ids)} máquina(s) del cliente {cliente_id_ot}",
                        flush=True,
                    )
        except Exception as _e_auto:
            print(f"[aplicar-plantilla] autoexpand error: {_e_auto}", flush=True)
            maquina_ids = []

    # Calcular orden inicial (siguiente al último existente)
    last_row = mysql_fetchone(
        "SELECT COALESCE(MAX(orden), 0) AS mx FROM mant_visita_tareas WHERE visita_id=%s",
        (vid,)
    )
    next_orden = int((last_row or {}).get("mx") or 0)

    conn = get_mysql()
    n_creadas = 0
    # ── FIX REVIEWER B1 — Pre-fetch UNA SOLA query de máquinas (anti N+1) ──
    # Antes: por cada (máquina × item) un fetchone separado. Con 10 items × 5
    # máquinas = 50 queries. Ahora: 1 query y dict en memoria.
    maquinas_idx = {}
    if maquina_ids:
        placeholders = ",".join(["%s"] * len(maquina_ids))
        m_rows = mysql_fetchall(
            f"SELECT id, nombre, serie FROM mant_maquinas WHERE id IN ({placeholders})",
            tuple(maquina_ids)
        ) or []
        for mr in m_rows:
            maquinas_idx[mr["id"]] = mr
    n_skipped = 0  # contador de máquinas saltadas por dedup
    try:
        with conn.cursor() as cur:
            targets = maquina_ids if maquina_ids else [None]
            for mid in targets:
                # BUG FIX 2026-05-17 — DEDUP por (visita, plantilla, máquina).
                # Si ya existen tareas de esta plantilla en esta máquina, NO
                # se duplican. Evita el caso de aplicar la misma plantilla
                # "Levantamiento fotográfico" dos veces (manual o por hook).
                cur.execute(
                    "SELECT COUNT(*) AS n FROM mant_visita_tareas "
                    " WHERE visita_id=%s AND plantilla_id=%s "
                    "   AND ((maquina_id=%s) OR (maquina_id IS NULL AND %s IS NULL))",
                    (vid, pid, mid, mid)
                )
                _dup = cur.fetchone() or {}
                if (_dup.get("n") or 0) > 0:
                    n_skipped += 1
                    print(f"[aplicar-plantilla] DEDUP — plantilla {pid} ya aplicada "
                          f"a máquina {mid} en visita {vid}, skip", flush=True)
                    continue
                for it in items:
                    next_orden += 1
                    # Si tenemos máquina específica y la tarea es foto/levantamiento,
                    # prefijar el título con el nombre del equipo para que el técnico
                    # sepa de qué equipo se trata.
                    titulo = it["titulo"]
                    if mid:
                        m_row = maquinas_idx.get(mid)
                        if m_row:
                            sufijo = m_row["nombre"]
                            if m_row.get("serie"):
                                sufijo += f" (S/N: {m_row['serie']})"
                            titulo = f"{titulo} — {sufijo}"
                    # FIX 2026-05-17: bug GPS heredado de plantillas.
                    # 1) plantilla_id se preservaba como NULL → no había trazabilidad
                    #    de origen y el frontend no podía agrupar las tareas.
                    # 2) it["tipo_respuesta"] (sin .get) podía ser NULL en plantillas
                    #    legacy → el JS default `|| 'check'` convertía GPS → check
                    #    silenciosamente. Ahora usamos .get() + COALESCE explícito.
                    tr = it.get("tipo_respuesta") or "check"
                    # Si el título contiene "GPS"/"ubicación" y tipo_respuesta no
                    # estaba seteado, asumir GPS. Heurística ESTRICTA para no
                    # producir falsos positivos en "Capturar peso", "Captura firma".
                    if not it.get("tipo_respuesta"):
                        ttl = (it.get("titulo") or "").lower()
                        if ("gps" in ttl or "ubicación" in ttl or "ubicacion" in ttl
                            or "capturar gps" in ttl or "captura ubicaci" in ttl
                            or "danos tu ubicaci" in ttl):
                            tr = "gps"
                    cur.execute(
                        "INSERT INTO mant_visita_tareas "
                        "(visita_id, plantilla_id, orden, titulo, descripcion, tipo, "
                        " maquina_id, tipo_respuesta, obligatoria, requiere_foto, "
                        " unidad, rango_min, rango_max, opciones_lista_json, "
                        " estado_trabajo, created_by) "
                        "VALUES (%s,%s,%s,%s,%s,'otro',%s,%s,%s,%s,%s,%s,%s,%s,'pendiente',%s)",
                        (vid, pid, next_orden, titulo[:300], it.get("descripcion"),
                         mid, tr,
                         it.get("obligatoria") or 0, it.get("requiere_foto") or 0,
                         it.get("unidad"), it.get("rango_min"), it.get("rango_max"),
                         it.get("opciones_lista_json"), current_username())
                    )
                    n_creadas += 1
        conn.commit()
        try:
            _mant_log("visita", vid, "plantilla_aplicada",
                      f"Plantilla '{plant['nombre']}' → {n_creadas} tarea(s)"
                      + (f" · dedup {n_skipped} máquina(s)" if n_skipped else ""))
        except Exception: pass
        return jsonify({
            "ok": True, "creadas": n_creadas, "plantilla": plant["nombre"],
            "skipped_dedup": n_skipped,
        })
    finally:
        conn.close()


@app.route("/mantenciones/api/visitas/<int:vid>/tareas/<int:tid>/responder", methods=["POST"])
@_mant_required
@_tecnico_owns_visita
def mant_tarea_responder(vid, tid):
    """Guarda la respuesta a una tarea de checklist según su tipo_respuesta.
    Body acepta cualquiera de:
      { valor_texto, valor_numero, valor_sino, valor_verificacion,
        valor_lista, valor_fecha_hora, valor_gps_lat, valor_gps_lng,
        valor_gps_accuracy, observaciones }
    El backend valida solo el campo correspondiente al tipo_respuesta de la tarea.
    Si la tarea es obligatoria y el valor está vacío, devuelve error.
    """
    tarea = mysql_fetchone(
        "SELECT id, visita_id, tipo_respuesta, obligatoria, requiere_foto, "
        "       rango_min, rango_max, opciones_lista_json "
        "  FROM mant_visita_tareas WHERE id=%s AND visita_id=%s",
        (tid, vid)
    )
    if not tarea:
        return jsonify({"ok": False, "error": "Tarea no encontrada"}), 404
    d = request.get_json(silent=True) or {}
    tipo = (tarea.get("tipo_respuesta") or "check").lower()

    sets, vals = [], []

    if tipo == "check":
        # Tarea simple: solo marcar completada
        pass
    elif tipo == "texto":
        v = (d.get("valor_texto") or "").strip()
        if not v and tarea.get("obligatoria"):
            return jsonify({"ok": False, "error": "Respuesta obligatoria"}), 400
        sets.append("valor_texto=%s"); vals.append(v or None)
    elif tipo == "numero":
        raw = d.get("valor_numero")
        if raw in (None, ""):
            if tarea.get("obligatoria"):
                return jsonify({"ok": False, "error": "Respuesta numérica obligatoria"}), 400
            v = None
        else:
            try: v = float(raw)
            except Exception:
                return jsonify({"ok": False, "error": "Valor numérico inválido"}), 400
            # Validar rango si existe
            rmin = tarea.get("rango_min")
            rmax = tarea.get("rango_max")
            if rmin is not None and v < float(rmin):
                return jsonify({"ok": False, "error": f"Valor menor al rango mínimo ({rmin})"}), 400
            if rmax is not None and v > float(rmax):
                return jsonify({"ok": False, "error": f"Valor mayor al rango máximo ({rmax})"}), 400
        sets.append("valor_numero=%s"); vals.append(v)
    elif tipo == "sino":
        v = (d.get("valor_sino") or "").strip().lower()
        if v not in ("si", "no", "na", ""):
            return jsonify({"ok": False, "error": "valor_sino debe ser si|no|na"}), 400
        if not v and tarea.get("obligatoria"):
            return jsonify({"ok": False, "error": "Respuesta obligatoria"}), 400
        sets.append("valor_sino=%s"); vals.append(v or None)
    elif tipo == "verificacion":
        v = (d.get("valor_verificacion") or "").strip().lower()
        if v not in ("aprobado", "alerta", "falla", ""):
            return jsonify({"ok": False, "error": "valor_verificacion debe ser aprobado|alerta|falla"}), 400
        if not v and tarea.get("obligatoria"):
            return jsonify({"ok": False, "error": "Respuesta obligatoria"}), 400
        sets.append("valor_verificacion=%s"); vals.append(v or None)
    elif tipo == "lista":
        v = (d.get("valor_lista") or "").strip()
        opciones = []
        if tarea.get("opciones_lista_json"):
            try: opciones = json.loads(tarea["opciones_lista_json"])
            except Exception: opciones = []
        if v and opciones and v not in opciones:
            return jsonify({"ok": False, "error": "Opción no válida"}), 400
        if not v and tarea.get("obligatoria"):
            return jsonify({"ok": False, "error": "Respuesta obligatoria"}), 400
        sets.append("valor_lista=%s"); vals.append(v or None)
    elif tipo == "fecha_hora":
        v = (d.get("valor_fecha_hora") or "").strip()
        if not v and tarea.get("obligatoria"):
            return jsonify({"ok": False, "error": "Respuesta obligatoria"}), 400
        if v:
            # Normalizar formato esperado: YYYY-MM-DD HH:MM o YYYY-MM-DDTHH:MM
            v = v.replace("T", " ")[:19]
        sets.append("valor_fecha_hora=%s"); vals.append(v or None)
    elif tipo == "gps":
        lat = d.get("valor_gps_lat")
        lng = d.get("valor_gps_lng")
        acc = d.get("valor_gps_accuracy")
        try: lat = float(lat) if lat not in (None, "") else None
        except Exception: lat = None
        try: lng = float(lng) if lng not in (None, "") else None
        except Exception: lng = None
        try: acc = float(acc) if acc not in (None, "") else None
        except Exception: acc = None
        if (lat is None or lng is None) and tarea.get("obligatoria"):
            return jsonify({"ok": False, "error": "Coordenadas GPS obligatorias"}), 400
        sets.append("valor_gps_lat=%s"); vals.append(lat)
        sets.append("valor_gps_lng=%s"); vals.append(lng)
        sets.append("valor_gps_accuracy=%s"); vals.append(acc)
    elif tipo == "foto":
        # La foto se sube por el endpoint /fotos. Aquí solo marcamos
        # completada; el frontend valida que haya al menos 1 foto si requiere_foto.
        pass

    # Observaciones libres (opcional para cualquier tipo)
    if "observaciones" in d:
        sets.append("observaciones=%s")
        vals.append((d.get("observaciones") or "").strip()[:2000] or None)

    # Marcar completada
    sets.append("completada=1")
    sets.append("completada_at=NOW()")
    sets.append("completada_por=%s")
    vals.append(current_username())
    sets.append("estado_trabajo='completada'")

    if sets:
        sql = f"UPDATE mant_visita_tareas SET {', '.join(sets)} WHERE id=%s"
        mysql_execute(sql, tuple(vals) + (tid,))
    try:
        _mant_log("visita_tarea", tid, "respondida",
                  f"Tipo {tipo} respondido por {current_username()}")
    except Exception: pass
    return jsonify({"ok": True, "tarea_id": tid, "tipo": tipo})


# ═════════════════════════════════════════════════════════════════════
# OT — PÁGINA FICHA (ficha completa con tabs)
# ═════════════════════════════════════════════════════════════════════

@app.route("/mantenciones/ot/<int:vid>")
@_mant_required
@_ot_can_view
def mant_ot_ficha(vid):
    """Ficha de OT — TODOS los roles van al modo drill-down de ejecución.

    Daniel pidió (2026-05-17) que admin/superadmin también vea la misma
    vista de drill-down (máquina → plantilla → tarea) que ve el técnico,
    sin las tabs viejas (Fotos/Repuestos/Bitácora) que confundían.
    Si admin necesita editar metadata de la OT, sigue teniendo los
    botones "Editar" y "Eliminar" en /mantenciones/ots.
    Para acceder a la ficha vieja (legacy), usar ?legacy=1 en la URL.
    """
    if request.args.get("legacy") != "1":
        return redirect(url_for("mant_ot_ejecutar", vid=vid))
    # NOTA: la columna real en mant_clientes es contacto_tel (no contacto_telefono).
    # Se mantiene el alias cli_contacto_tel para que el template no cambie.
    # tecnico_principal viene preferentemente de app_users (v.tecnico_user_id, nuevo)
    # y como fallback de mant_tecnicos (v.tecnico_id, legacy).
    visita = mysql_fetchone(
        "SELECT v.*, c.razon_social, c.direccion AS cli_direccion, "
        "       c.comuna AS cli_comuna, c.email_empresa AS cli_email, "
        "       c.tel_empresa AS cli_tel, c.contacto_nombre AS cli_contacto, "
        "       c.contacto_tel AS cli_contacto_tel, "
        "       ct.nombre AS contrato_nombre, "
        "       COALESCE(u.nombre, u.username, t.nombre) AS tecnico_principal, "
        "       COALESCE(u.phone, t.telefono) AS tecnico_tel, "
        "       COALESCE(u.username, t.email) AS tecnico_email, "
        "       COALESCE(u.foto_url, t.foto_url) AS tecnico_foto "
        "  FROM mant_visitas v "
        "  JOIN mant_clientes c ON c.id=v.cliente_id "
        "  LEFT JOIN mant_contratos ct ON ct.id=v.contrato_id "
        "  LEFT JOIN mant_tecnicos t ON t.id=v.tecnico_id "
        "  LEFT JOIN app_users   u ON u.id=v.tecnico_user_id "
        " WHERE v.id=%s",
        (vid,)
    )
    if not visita:
        flash("OT no encontrada.", "danger")
        return redirect(url_for("mant_index"))

    visita = dict(visita)

    # Técnicos adicionales asignados (N:N)
    tecnicos = mysql_fetchall(
        "SELECT vt.rol, vt.horas, vt.costo, t.id, t.nombre, t.telefono, "
        "       t.email, t.foto_url, t.especialidad, t.nivel "
        "  FROM mant_visita_tecnicos vt "
        "  JOIN mant_tecnicos t ON t.id=vt.tecnico_id "
        " WHERE vt.visita_id=%s ORDER BY (vt.rol='lider') DESC, t.nombre",
        (vid,)
    ) or []
    tecnicos = [dict(t) for t in tecnicos]

    # Máquinas del cliente (para asignar a tareas)
    maquinas = mysql_fetchall(
        "SELECT id, nombre, serie, sku FROM mant_maquinas "
        " WHERE cliente_id=%s ORDER BY nombre",
        (visita["cliente_id"],)
    ) or []
    maquinas = [dict(m) for m in maquinas]

    # Tareas con stats
    tareas_stats = mysql_fetchone(
        "SELECT COUNT(*) AS total, "
        "       SUM(CASE WHEN completada=1 THEN 1 ELSE 0 END) AS completas "
        "  FROM mant_visita_tareas WHERE visita_id=%s",
        (vid,)
    ) or {"total": 0, "completas": 0}

    fotos_count = mysql_fetchone(
        "SELECT COUNT(*) AS n FROM mant_visita_fotos WHERE visita_id=%s",
        (vid,)
    ) or {"n": 0}

    # 2026-05-18 — Backend evalúa permisos para mostrar el panel de firmas
    # (creador/admin/ejecutivo_sstt/supervisor pueden firmar como aprobador).
    _u_ficha = getattr(g, "user", None) or {}
    _role_ficha = (_u_ficha.get("role") or "").lower()
    puede_aprobar_flag = _puede_ot_accion(vid, "aprobar", _u_ficha)
    _creator_username = (visita.get("created_by") or "").strip().lower()
    es_creador_flag = bool(_creator_username) and (
        _creator_username == (_u_ficha.get("username") or "").strip().lower()
    )
    es_superadmin_flag = (_rol_familia(_role_ficha) == "superadmin")

    return render_template(
        "mantenciones/ot_ficha.html",
        visita=visita,
        tecnicos=tecnicos,
        maquinas=maquinas,
        stats={
            "total_tareas":    tareas_stats.get("total", 0),
            "completas":       tareas_stats.get("completas", 0) or 0,
            "fotos":           fotos_count.get("n", 0),
        },
        puede_aprobar=puede_aprobar_flag,
        es_creador=es_creador_flag,
        es_superadmin=es_superadmin_flag,
    )


# ═════════════════════════════════════════════════════════════════════
# OT — MODO TÉCNICO (vista simplificada mobile-first)
# El técnico solo ve los equipos asignados, sus tareas (plantilla)
# y los gestiona uno a uno. No puede asignar más técnicos ni cambiar
# metadata de la OT. Al terminar firma y la OT pasa a "pendiente
# revisión" para que el supervisor la apruebe/cierre.
# ═════════════════════════════════════════════════════════════════════

@app.route("/mantenciones/ot/<int:vid>/ejecutar")
@_mant_required
def mant_ot_ejecutar(vid):
    """Vista simplificada de ejecución de OT (modo técnico)."""
    # NOTE 2026-05-17 (cliente_default GPS): traemos c.direccion_lat/lng
    # como fallback para cuando v.direccion_lat/lng vienen NULL (OTs viejas
    # creadas antes de que mant_visitas tuviera esas columnas, o OTs donde
    # no se sobrescribió la dirección a nivel OT). Esto le permite al
    # frontend (DESTINO_LAT/LNG) y al endpoint de respuesta GPS usar la
    # dirección ya parametrizada del cliente cuando el GPS del dispositivo
    # del técnico no funciona (default 'cliente_default').
    visita = mysql_fetchone(
        "SELECT v.*, c.razon_social, c.rut AS cli_rut, "
        "       c.direccion AS cli_direccion, "
        "       c.direccion_lat AS cli_direccion_lat, "
        "       c.direccion_lng AS cli_direccion_lng, "
        "       c.comuna AS cli_comuna, c.contacto_nombre AS cli_contacto, "
        "       c.contacto_tel AS cli_contacto_tel, "
        "       COALESCE(u.nombre, u.username) AS tecnico_principal "
        "  FROM mant_visitas v "
        "  JOIN mant_clientes c ON c.id=v.cliente_id "
        "  LEFT JOIN app_users u ON u.id=v.tecnico_user_id "
        " WHERE v.id=%s",
        (vid,)
    )
    if not visita:
        flash("OT no encontrada.", "danger")
        return redirect(url_for("mant_ots_list"))
    visita = dict(visita)

    # 🔐 SEGURIDAD 2026-05-18 / refuerzo 2026-05-22 (Daniel — brecha Aaron):
    # Matriz unificada de permisos. Permite VER la página a:
    #   - superadmin / admin / supervisor (siempre)
    #   - ejecutivo (SOLO SUS OTs: creó O asignado/colaborador)
    #   - creador de la OT (cualquier rol)
    #   - técnico asignado/colaborador
    # Bloquea a:
    #   - técnico/tecnico_externo que NO la tienen asignada
    #   - ejecutivo en OTs ajenas (no creadas ni asignadas a él)
    #   - cualquier otro rol
    # Las acciones de ejecución (botones que llaman a /api/visitas/.../tareas)
    # están protegidas a nivel API con `_tecnico_owns_visita` strict.
    u = getattr(g, "user", None) or {}
    if not _puede_ot_accion(vid, "ver", u):
        print(
            f"[SECURITY] {u.get('id')} ({u.get('username')}) intento ver OT "
            f"vid={vid} sin permiso (role={(u.get('role') or '').lower()})",
            flush=True
        )
        flash("Esta OT no está asignada a ti.", "warning")
        return redirect(url_for("mant_ots_list"))
    role_u = (u.get("role") or "").lower()
    # Flag para el template: indica si puede o no ejecutar (modificar) tareas.
    # Si es solo viewer (admin/ejecutivo no asignado), se ocultan los botones.
    puede_ejecutar_flag = _puede_ot_accion(vid, "ejecutar", u)
    # 2026-05-18 — Flags para el template: evaluamos el permiso de aprobar
    # SIEMPRE en backend (la matriz reconoce ejecutivo_sstt, supervisor_sstt,
    # etc.). El template usa estos booleans directos en vez de re-evaluar
    # con strings literales que no soportan variantes dinámicas.
    puede_aprobar_flag = _puede_ot_accion(vid, "aprobar", u)
    # 2026-05-22 (OT 2026-00004 Vitacura) — Flag para mostrar el panel
    # "Configurar OT" cuando la OT está vacía. Permite al ejecutivo
    # creador / admin arreglar OTs huérfanas (sin equipos/plantilla)
    # sin tener que ir a la vista legacy a mano.
    puede_configurar_flag = _puede_ot_accion(vid, "configurar", u)
    # Comparar created_by (varchar username) con el username del user actual,
    # case insensitive y trim, igual que en `_puede_ot_accion`.
    _creator_username = (visita.get("created_by") or "").strip().lower()
    es_creador_flag = bool(_creator_username) and (
        _creator_username == (u.get("username") or "").strip().lower()
    )
    es_superadmin_flag = (_rol_familia(role_u) == "superadmin")

    # ════════════════════════════════════════════════════════════════
    # FIX 2026-05-22 22:00 (caso OT 2026-00004 Vitacura — Daniel):
    # Si la OT viene desde un levantamiento (levantamiento_id NOT NULL)
    # y mant_visita_equipos está vacío, sincronizamos los items del
    # levantamiento → mant_visita_equipos con INSERT IGNORE (idempotente
    # vía UNIQUE KEY uq_visita_maquina). Esto reconstruye la asociación
    # equipo↔OT para OTs creadas por el wizard de levantamiento que NO
    # populó la tabla intermedia. Es seguro correr cada vez que se abre
    # la OT: si ya están sincronizados, no hace nada.
    # ════════════════════════════════════════════════════════════════
    _lev_id = visita.get("levantamiento_id")
    if _lev_id:
        try:
            # PERF 2026-05-31 (ot_performance): este sync reconstruye la
            # asociación equipo↔OT y solo hace falta UNA vez (cuando la OT aún
            # no tiene equipos). Antes corría un INSERT IGNORE + commit en CADA
            # apertura de la OT — una escritura inútil en el hot path del
            # técnico. Ahora se evita con un COUNT barato: si ya hay equipos
            # sincronizados, NO se vuelve a escribir (la apertura queda de solo
            # lectura). Caso orphan (count=0) sigue reconstruyéndose igual.
            _ya_sync = mysql_fetchone(
                "SELECT COUNT(*) AS n FROM mant_visita_equipos WHERE visita_id=%s",
                (vid,)
            ) or {}
            _lev_items = [] if int(_ya_sync.get("n") or 0) > 0 else (mysql_fetchall(
                "SELECT maquina_id FROM mant_levantamiento_items "
                " WHERE levantamiento_id=%s AND maquina_id IS NOT NULL",
                (_lev_id,)
            ) or [])
            if _lev_items:
                # INSERT IGNORE por UNIQUE KEY uq_visita_maquina (visita_id, maquina_id)
                _rows = [(vid, int(it["maquina_id"]),
                          "verificado", current_username() or "sistema")
                         for it in _lev_items]
                conn_li = get_mysql()
                try:
                    with conn_li.cursor() as cur_li:
                        cur_li.executemany(
                            "INSERT IGNORE INTO mant_visita_equipos "
                            "  (visita_id, maquina_id, estado_revision, revisado_por) "
                            "VALUES (%s,%s,%s,%s)",
                            _rows
                        )
                    conn_li.commit()
                finally:
                    conn_li.close()
        except Exception as _e_lev_sync:
            print(f"[ot_ejecutar] sync levantamiento→equipos vid={vid} "
                  f"lev_id={_lev_id} error: {_e_lev_sync}", flush=True)

    # ════════════════════════════════════════════════════════════════
    # FIX 2026-05-22 (Daniel — caso Vitacura OT 161/162/163):
    # SAFETY-NET para OTs EXISTENTES huérfanas creadas antes del fix
    # en `lev_crear_o_listar`. Si la OT viene de un levantamiento
    # (levantamiento_id NOT NULL) y NO tiene ninguna tarea en
    # mant_visita_tareas, generamos UN fallback "📷 Documentar" por
    # cada equipo del levantamiento. Esto desbloquea al técnico
    # (Lenin) que abre la OT y la encuentra sin checklist: AHORA verá
    # 4 cards (una por equipo) con su tarea base de captura de fotos.
    # Idempotente: solo inserta si COUNT==0.
    # ════════════════════════════════════════════════════════════════
    if _lev_id:
        try:
            _has_tareas = mysql_fetchone(
                "SELECT COUNT(*) AS n FROM mant_visita_tareas WHERE visita_id=%s",
                (vid,)
            ) or {}
            if int(_has_tareas.get("n") or 0) == 0:
                _maqs_lev = mysql_fetchall(
                    "SELECT li.maquina_id, m.nombre "
                    "  FROM mant_levantamiento_items li "
                    "  LEFT JOIN mant_maquinas m ON m.id=li.maquina_id "
                    " WHERE li.levantamiento_id=%s AND li.maquina_id IS NOT NULL "
                    " ORDER BY li.id",
                    (_lev_id,)
                ) or []
                if _maqs_lev:
                    _conn_tfb = get_mysql()
                    try:
                        with _conn_tfb.cursor() as _cur_tfb:
                            for _idx_t, _m in enumerate(_maqs_lev, 1):
                                _cur_tfb.execute(
                                    "INSERT INTO mant_visita_tareas "
                                    "(visita_id, orden, titulo, descripcion, "
                                    " maquina_id, tipo, tipo_respuesta, "
                                    " obligatoria, requiere_foto, estado_trabajo, "
                                    " created_by) "
                                    "VALUES (%s,%s,%s,%s,%s,"
                                    "        'levantamiento','foto',1,1,'pendiente',%s)",
                                    (vid, _idx_t,
                                     f"📷 Documentar: {(_m.get('nombre') or 'equipo')[:240]}",
                                     "Capturar fotos generales del equipo + N° serie + "
                                     "placa + datos técnicos.",
                                     _m["maquina_id"],
                                     current_username() or 'sistema')
                                )
                        _conn_tfb.commit()
                        print(f"[ot_ejecutar] safety-net tareas vid={vid} "
                              f"lev_id={_lev_id}: {len(_maqs_lev)} tarea(s) "
                              f"📷 Documentar creadas (OT huérfana).", flush=True)
                        try:
                            _mant_log(
                                "visita", vid, "tareas_safety_net",
                                f"{len(_maqs_lev)} tarea(s) 📷 Documentar creadas "
                                f"automáticamente para destrabar OT huérfana "
                                f"(lev_id={_lev_id})"
                            )
                        except Exception:
                            pass
                    finally:
                        _conn_tfb.close()
        except Exception as _e_tsn:
            print(f"[ot_ejecutar] safety-net tareas vid={vid} error: {_e_tsn}",
                  flush=True)

    # Equipos involucrados en la OT — vienen de mant_visita_tareas distintas máquinas
    # FIX 2026-05-16: filtrar equipos dados de baja (soft-delete).
    # FIX 2026-05-22 (Daniel): si la plantilla todavía no se aplicó (Aaron creó
    # la OT con equipos pero el técnico aún no tiene tareas), agregamos también
    # los equipos listados en mant_visita_equipos (audit trail). Esto evita que
    # Lenin vea pantalla en blanco cuando la OT está armada pero sin checklist.
    equipos = mysql_fetchall(
        "SELECT DISTINCT m.id, m.nombre, m.sku, m.serie, m.foto_url, "
        "       m.marca, m.modelo, m.anio_fabricacion, m.voltaje, "
        "       m.ubicacion_sala, m.estado_capturado, m.tiene_dano, "
        "       m.observaciones, m.ultima_intervencion, m.visitas_count "
        "  FROM mant_visita_tareas vt "
        "  JOIN mant_maquinas m ON m.id=vt.maquina_id "
        " WHERE vt.visita_id=%s AND vt.maquina_id IS NOT NULL "
        "   AND COALESCE(m.estado,'activo') != 'baja' "
        " UNION "
        "SELECT DISTINCT m.id, m.nombre, m.sku, m.serie, m.foto_url, "
        "       m.marca, m.modelo, m.anio_fabricacion, m.voltaje, "
        "       m.ubicacion_sala, m.estado_capturado, m.tiene_dano, "
        "       m.observaciones, m.ultima_intervencion, m.visitas_count "
        "  FROM mant_visita_equipos ve "
        "  JOIN mant_maquinas m ON m.id=ve.maquina_id "
        " WHERE ve.visita_id=%s AND ve.maquina_id IS NOT NULL "
        "   AND COALESCE(m.estado,'activo') != 'baja' "
        " ORDER BY nombre",
        (vid, vid)
    ) or []
    equipos = [dict(e) for e in equipos]

    # 2026-05-22 (OT 2026-00004 Vitacura) — Detección de OT vacía /
    # huérfana. Si hay tareas pero todas tienen maquina_id NULL, no
    # aparecen equipos en la vista. Pasamos un flag al template para
    # que ofrezca al creador/admin un banner para arreglarla.
    _huerf_info = mysql_fetchone(
        "SELECT "
        "  COUNT(*) AS n_total, "
        "  SUM(CASE WHEN maquina_id IS NULL THEN 1 ELSE 0 END) AS n_huerfanas "
        "  FROM mant_visita_tareas WHERE visita_id=%s",
        (vid,)
    ) or {"n_total": 0, "n_huerfanas": 0}
    _tareas_total_v = int(_huerf_info.get("n_total") or 0)
    _tareas_huerf_v = int(_huerf_info.get("n_huerfanas") or 0)
    ot_necesita_config = (
        len(equipos) == 0 and (_tareas_total_v == 0 or _tareas_huerf_v > 0)
    )

    # Tareas con info de plantilla origen + valor_json para tipos avanzados.
    # Incluye `version` y datos del lock para sincronizar concurrencia
    # multitécnico (Parte 3 — anti-duplicación).
    tareas = mysql_fetchall(
        "SELECT t.id, t.maquina_id, t.plantilla_id, t.orden, t.titulo, t.descripcion, "
        "       t.tipo, t.tipo_respuesta, t.obligatoria, t.requiere_foto, "
        "       t.unidad, t.rango_min, t.rango_max, t.opciones_lista_json, "
        "       t.completada, t.completada_at, t.observaciones, t.valor_json, "
        "       t.version, t.locked_by_user_id, t.locked_at, "
        "       COALESCE(p.nombre, 'Gestión de tareas') AS plantilla_nombre, "
        "       COALESCE(p.tipo_visita, t.tipo, 'otro') AS plantilla_tipo "
        "  FROM mant_visita_tareas t "
        "  LEFT JOIN mant_tarea_plantillas p ON p.id = t.plantilla_id "
        " WHERE t.visita_id=%s "
        " ORDER BY t.maquina_id, t.plantilla_id, t.orden, t.id",
        (vid,)
    ) or []
    tareas = [dict(t) for t in tareas]
    # Normalizar `version` y `locked_at` para JSON
    for _t in tareas:
        _t["version"] = int(_t.get("version") or 0)
        if _t.get("locked_at"):
            _t["locked_at"] = str(_t["locked_at"])[:19]

    # ════════════════════════════════════════════════════════════════
    # Agrupar por (maquina_id, plantilla_id) — UNA card por equipo×plantilla.
    # Si una máquina tiene 3 plantillas, aparece 3 veces en grupos.
    # ════════════════════════════════════════════════════════════════
    grupos = []  # lista de {maquina_id, plantilla_id, plantilla_nombre, tareas[], stats{}}
    grupo_idx = {}  # (mid, pid) → index en grupos
    for t in tareas:
        mid = t.get("maquina_id") or 0
        pid = t.get("plantilla_id") or 0  # 0 = sin plantilla (manual/legacy)
        key = (mid, pid)
        if key not in grupo_idx:
            grupo_idx[key] = len(grupos)
            grupos.append({
                "maquina_id":       mid,
                "plantilla_id":     pid,
                "plantilla_nombre": t.get("plantilla_nombre") or "Tareas manuales",
                "plantilla_tipo":   t.get("plantilla_tipo") or "otro",
                "tareas":           [],
            })
        grupos[grupo_idx[key]]["tareas"].append(t)
    # Calcular stats por grupo
    # CRÍTICO: usamos `grp` (no `g`) porque `g` es el contexto global de Flask
    # (flask.g) y reutilizarlo como variable de loop lo convierte en LOCAL en
    # toda la función — causa UnboundLocalError al acceder g.user antes del loop.
    for grp in grupos:
        grp["total"] = len(grp["tareas"])
        grp["completas"] = sum(1 for t in grp["tareas"] if t.get("completada"))
        grp["progreso"] = round((grp["completas"] / grp["total"]) * 100) if grp["total"] else 0
        grp["bloqueado"] = (grp["completas"] == grp["total"] and grp["total"] > 0)

    # Compat: el viejo tareas_por_eq sigue existiendo (legacy templates)
    tareas_por_eq = {}
    for t in tareas:
        mid = t.get("maquina_id") or 0
        tareas_por_eq.setdefault(mid, []).append(t)

    # ════════════════════════════════════════════════════════════════
    # ESTRUCTURA DRILL-DOWN (vista nueva 2026-05-17):
    # plantillas_por_maquina[mid] = [
    #   {plantilla_id, plantilla_nombre, plantilla_tipo, total, completas, progreso, bloqueado, tareas: [...]}
    # ]
    # Estructura jerárquica para que el técnico navegue:
    #   máquina → plantilla → tarea
    # ════════════════════════════════════════════════════════════════
    plantillas_por_maquina = {}
    for grp in grupos:
        mid = grp["maquina_id"]
        plantillas_por_maquina.setdefault(mid, []).append(grp)

    # Stats por máquina (suma de todas sus plantillas)
    stats_por_maquina = {}
    for mid, pls in plantillas_por_maquina.items():
        total = sum(p["total"] for p in pls)
        comp = sum(p["completas"] for p in pls)
        stats_por_maquina[mid] = {
            "total": total,
            "completas": comp,
            "progreso": round((comp / total) * 100) if total else 0,
            "bloqueada": (comp == total and total > 0),
            "n_plantillas": len(pls),
        }

    # Fotos por máquina (FIX 2026-05-17: la columna timestamp se llama
    # `tomada_at` no `created_at`. Tampoco hay `cloudinary_url` en el
    # CREATE TABLE original — se agregó vía migración idempotente).
    fotos = mysql_fetchall(
        "SELECT id, tarea_id, archivo_path, cloudinary_url, tipo_foto, tomada_at "
        "  FROM mant_visita_fotos WHERE visita_id=%s ORDER BY tomada_at",
        (vid,)
    ) or []
    fotos = [dict(f) for f in fotos]
    # Normalizar URL preferida (Cloudinary > local)
    for f in fotos:
        f["url"] = f.get("cloudinary_url") or (
            f"/static/uploads/mantenciones/{f['archivo_path']}"
            if f.get("archivo_path") else ""
        )

    # ════════════════════════════════════════════════════════════════
    # FIX 2026-05-17 — Keys stringificadas para JSON.
    # Python dict con keys INT al pasar por |tojson en Jinja se serializa
    # con keys STRING (estándar JSON). En JS al hacer dict[5] (int de
    # onclick(5)) se obtiene undefined porque la key real es "5".
    # Convertimos las keys a STRING acá para que JS las encuentre.
    # ════════════════════════════════════════════════════════════════
    equipos_idx = {str(e["id"]): e for e in equipos}
    plantillas_por_maquina = {str(k): v for k, v in plantillas_por_maquina.items()}
    stats_por_maquina = {str(k): v for k, v in stats_por_maquina.items()}

    # Datos para concurrencia multitécnico (Parte 3): id del user actual
    # (filtrar locks propios en frontend) y flag is_admin (override del lock).
    _user_id_actual = u.get("id") or 0
    _perms = g.get("permissions") or {}
    _is_admin_lock = bool(_perms.get("superadmin") or _perms.get("admin"))

    # ── 2026-05-21 (Daniel) — Trazabilidad por equipo ──────────────────
    # Cargamos el estado de revisión actual de cada equipo en esta visita
    # para que el técnico vea badges al cargar la página. Keys stringified
    # para que coincidan con String(eq.id) usado en JS.
    equipos_estado_revision = {}
    try:
        _rows_ve = mysql_fetchall(
            "SELECT maquina_id, estado_revision, razon_saltado, "
            "       observacion_tecnico, revisado_at, revisado_por "
            "  FROM mant_visita_equipos WHERE visita_id=%s",
            (vid,)
        ) or []
        for _r in _rows_ve:
            equipos_estado_revision[str(_r["maquina_id"])] = {
                "estado_revision":     _r.get("estado_revision") or "verificado",
                "razon_saltado":       _r.get("razon_saltado") or "",
                "observacion_tecnico": _r.get("observacion_tecnico") or "",
                "revisado_at":         str(_r["revisado_at"])[:19] if _r.get("revisado_at") else "",
                "revisado_por":        _r.get("revisado_por") or "",
            }
    except Exception as _e_ve:
        print(f"[ot_ejecutar] equipos_estado_revision load error: {_e_ve}", flush=True)

    return render_template(
        "mantenciones/ot_ejecutar.html",
        visita=visita,
        equipos=equipos,
        equipos_idx=equipos_idx,
        tareas_por_eq=tareas_por_eq,
        grupos=grupos,
        plantillas_por_maquina=plantillas_por_maquina,
        stats_por_maquina=stats_por_maquina,
        equipos_estado_revision=equipos_estado_revision,
        fotos=fotos,
        current_user_id=_user_id_actual,
        is_admin_lock=_is_admin_lock,
        # 🔐 2026-05-18 — Si el usuario solo puede VER (admin/ejecutivo no
        # asignado, creador no técnico), el template oculta botones de
        # acción y muestra la OT en "modo lectura".
        puede_ejecutar=puede_ejecutar_flag,
        es_solo_lectura=(not puede_ejecutar_flag),
        # 2026-05-18 (Aaron Urbina fix) — Backend evalúa el permiso para
        # aprobar usando `_puede_ot_accion`, que normaliza ejecutivo_sstt
        # / supervisor_sstt / etc. El template usa este flag directo.
        puede_aprobar=puede_aprobar_flag,
        es_creador=es_creador_flag,
        es_superadmin=es_superadmin_flag,
        # 2026-05-22 (OT 2026-00004 Vitacura) — flags para el panel
        # "Configurar OT": solo aparece al creador/admin/supervisor y
        # cuando la OT no tiene equipos asociados (huérfana).
        puede_configurar=puede_configurar_flag,
        ot_necesita_config=ot_necesita_config,
        tareas_huerfanas=_tareas_huerf_v,
    )


@app.route("/mantenciones/api/visitas/<int:vid>/equipo/<int:mid>/datos", methods=["PATCH"])
@_mant_required
@_tecnico_owns_visita
def mant_ot_equipo_datos(vid, mid):
    """Actualiza los datos del equipo en el contexto de la OT.

    Comportamiento (2026-05-22 Daniel — captura de ficha desde ot_ejecutar):
      1) Actualiza `mant_maquinas` con los campos editables (estrategia:
         escribir solo lo que viene en el payload — NO pisa con NULL).
      2) ESPEJA los mismos valores en `mant_levantamiento_items` (si la OT
         tiene levantamiento_id; si no, lo CREA en modo borrador para que
         Lenin pueda capturar incluso en OT preventiva sin levantamiento).
         Esto permite que `_promover_levantamiento_a_maquina` los vuelva a
         leer al cerrar la OT y los reaplique idempotente.
      3) Si cambia serie/marca/modelo (datos críticos), registra en
         `mant_maquina_audit` con valor antes/después + usuario + motivo.
      4) Si `completado=true`, también marca `mant_visita_equipos`
         estado_revision='con_cambios' (queda registrado quién capturó).

    Performance: <500ms (UPDATE simple + INSERT mant_levantamiento_items
    si no existe, opcional). Idempotente: vuelve a llamarse y solo aplica
    delta.
    """
    d = request.get_json(silent=True) or {}

    # Campos string permitidos en mant_maquinas (clave → max_length).
    # 2026-05-22 — agregamos varios campos que antes solo vivían en
    # mant_levantamiento_items. El espejo asegura coherencia.
    permitidos_str = {
        "serie": 100, "marca": 120, "modelo": 120,
        "voltaje": 40, "ubicacion_sala": 200,
        "estado_capturado": 40, "observaciones": 5000,
    }
    estados_validos = (
        "operativo", "advertencia", "fuera_servicio",
        "en_reparacion", "dado_baja", "no_encontrado"
    )

    # ── Capturar valores ANTES del update para auditoría de campos críticos ──
    valores_antes = {}
    try:
        _antes = mysql_fetchone(
            "SELECT serie, marca, modelo, cliente_id FROM mant_maquinas WHERE id=%s",
            (mid,)
        )
        if _antes:
            valores_antes = dict(_antes)
    except Exception:
        valores_antes = {}

    sets, vals = [], []
    for k, maxlen in permitidos_str.items():
        if k in d:
            v = (str(d.get(k) or "").strip())[:maxlen] or None
            # estado_capturado se valida contra ENUM (ignoramos valores inválidos)
            if k == "estado_capturado" and v and v not in estados_validos:
                continue
            sets.append(f"{k}=%s"); vals.append(v)
    # Numéricos / booleanos
    if "anio_fabricacion" in d:
        try: v = int(d["anio_fabricacion"]) if d["anio_fabricacion"] not in (None, "") else None
        except Exception: v = None
        sets.append("anio_fabricacion=%s"); vals.append(v)
    if "tiene_dano" in d:
        sets.append("tiene_dano=%s"); vals.append(1 if d["tiene_dano"] else 0)
    if "ultima_intervencion" in d:
        v = d["ultima_intervencion"]
        sets.append("ultima_intervencion=%s"); vals.append(v if v else None)
    # 2026-05-22 — campo que también vive en mant_levantamiento_items.
    # En mant_maquinas no existe `fecha_documento` — solo espejamos al item.
    if not sets:
        return jsonify({"ok": False, "error": "Sin campos"}), 400
    # Siempre actualizamos last_visita_id para trazabilidad
    sets.append("last_visita_id=%s"); vals.append(vid)
    vals.append(mid)
    try:
        mysql_execute(f"UPDATE mant_maquinas SET {','.join(sets)} WHERE id=%s", tuple(vals))

        # ── ESPEJO en mant_levantamiento_items (2026-05-22 Daniel) ────
        # Esto es lo que `_promover_levantamiento_a_maquina` vuelve a leer
        # al cerrar la OT. Sin este espejo, los datos solo vivirían en
        # mant_maquinas y se perdería trazabilidad por OT.
        try:
            _mirror_ot_equipo_a_levantamiento(vid, mid, d)
        except Exception as _e_mir:
            print(f"[mant_ot_equipo_datos] espejo levantamiento_items vid={vid} "
                  f"mid={mid}: {_e_mir}", flush=True)

        # ── Si el técnico marca como "completado" o cambia datos, marcamos
        #    también el estado_revision del equipo en la visita para que
        #    sea visible en la lista de equipos. ────────────────────────
        try:
            user_for_rev = current_username() or "técnico"
            estado_rev = "con_cambios" if d.get("completado") else None
            if estado_rev:
                mysql_execute(
                    "INSERT INTO mant_visita_equipos "
                    "  (visita_id, maquina_id, estado_revision, revisado_at, revisado_por) "
                    "VALUES (%s, %s, %s, NOW(), %s) "
                    "ON DUPLICATE KEY UPDATE "
                    "  estado_revision=VALUES(estado_revision), "
                    "  revisado_at=NOW(), "
                    "  revisado_por=VALUES(revisado_por)",
                    (vid, mid, estado_rev, user_for_rev[:190])
                )
        except Exception as _e_rev:
            print(f"[mant_ot_equipo_datos] mant_visita_equipos vid={vid} "
                  f"mid={mid}: {_e_rev}", flush=True)

        # ── Audit log de cambios sensibles ──
        # Solo escribimos en mant_maquina_audit cuando cambia un campo CRÍTICO
        # (serie / marca / modelo). Para no inflar la tabla con cada edición.
        try:
            v_obs = mysql_fetchone(
                "SELECT cliente_id, tipo, levantamiento_id FROM mant_visitas WHERE id=%s", (vid,)
            ) or {}
            # FIX 2026-05-22 (Daniel): el motivo "Levantamiento OT #X" también
            # aplica cuando la OT es de otro tipo pero está vinculada a un
            # levantamiento (mant_visitas.levantamiento_id NOT NULL). Permite
            # trazabilidad consistente en mant_maquina_audit para los 2 flujos
            # que generan herencia a la ficha.
            es_lev = (
                (v_obs.get("tipo") or "").lower() == "levantamiento"
                or bool(v_obs.get("levantamiento_id"))
            )
            user = current_username()
            motivo_base = (f"Levantamiento OT #{vid}" if es_lev
                           else f"Edición desde OT #{vid}")
            for campo in ("serie", "marca", "modelo"):
                if campo not in d:
                    continue
                nuevo = (str(d.get(campo) or "").strip())[:120] or None
                antes = (valores_antes.get(campo) or "") or None
                if (antes or "") == (nuevo or ""):
                    continue
                try:
                    mysql_execute(
                        "INSERT INTO mant_maquina_audit "
                        "(maquina_id, cliente_id, campo, valor_antes, valor_nuevo, "
                        " motivo, usuario) "
                        "VALUES (%s,%s,%s,%s,%s,%s,%s)",
                        (mid, valores_antes.get("cliente_id") or v_obs.get("cliente_id"),
                         campo, antes, nuevo, motivo_base, (user or "")[:190])
                    )
                except Exception as _e_aud:
                    print(f"[mant_ot_equipo_datos] audit {campo} fallo: {_e_aud}",
                          flush=True)
        except Exception:
            pass
        return jsonify({"ok": True})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 500


def _ensure_levantamiento_para_visita(vid):
    """Garantiza que la visita `vid` tenga `levantamiento_id`. Idempotente.

    2026-05-22 (Daniel) — Caso edge: Aaron crea una OT preventiva SIN
    levantamiento, pero Lenin necesita capturar ficha de los equipos
    (porque vienen vacíos). Este helper crea el levantamiento bajo demanda
    para que `_promover_levantamiento_a_maquina` pueda leerlo al cerrar.

    Solo crea levantamiento para tipos que tienen sentido (preventiva,
    levantamiento, instalacion, inspeccion). Para correctivas o garantías
    devuelve None — el técnico no está "levantando ficha", solo reparando.

    Returns: int → levantamiento_id (o None si no aplica / no se pudo crear).
    """
    v = mysql_fetchone(
        "SELECT id, cliente_id, levantamiento_id, tipo, fecha_programada, "
        "       tecnico_user_id, tecnico, numero_ot "
        "  FROM mant_visitas WHERE id=%s",
        (vid,)
    )
    if not v:
        return None
    lev_id = v.get("levantamiento_id")
    if lev_id:
        return lev_id
    # Solo crear para tipos que capturan ficha. Correctiva/garantía NO.
    tipo_v = (v.get("tipo") or "").lower()
    if tipo_v not in ("preventiva", "levantamiento", "instalacion", "inspeccion"):
        return None
    cid = v.get("cliente_id")
    if not cid:
        return None
    try:
        titulo = f"Ficha técnica OT {v.get('numero_ot') or vid}"
        mysql_execute(
            "INSERT INTO mant_levantamientos "
            "  (cliente_id, tecnico, fecha_inicio, estado, titulo, created_by, visita_id) "
            "VALUES (%s, %s, NOW(), 'en_curso', %s, %s, %s)",
            (cid, (v.get("tecnico") or current_username() or "técnico")[:190],
             titulo[:200],
             (current_username() or "sistema")[:190],
             vid)
        )
        row = mysql_fetchone("SELECT LAST_INSERT_ID() AS id")
        lev_id = (row or {}).get("id")
        if not lev_id:
            return None
        mysql_execute(
            "UPDATE mant_visitas SET levantamiento_id=%s WHERE id=%s",
            (lev_id, vid)
        )
        try:
            _mant_log("visita", vid, "levantamiento_creado_auto",
                      f"Levantamiento #{lev_id} creado al capturar ficha de equipos")
        except Exception:
            pass
        return lev_id
    except Exception as e:
        print(f"[_ensure_levantamiento_para_visita] vid={vid}: {e}", flush=True)
        return None


def _mirror_ot_equipo_a_levantamiento(vid, mid, payload):
    """Refleja en `mant_levantamiento_items` los campos editables que el
    técnico cambia desde la vista de ejecución (mant_ot_equipo_datos).

    Idempotente: si ya existe el item, hace UPDATE solo de las claves que
    vienen en el payload. Si no existe, INSERTA con snapshots básicos
    (nombre_snap/sku_snap/serie_snap) tomados de mant_maquinas.

    Crea el levantamiento si la OT no lo tenía (ver
    `_ensure_levantamiento_para_visita`).
    """
    lev_id = _ensure_levantamiento_para_visita(vid)
    if not lev_id:
        return
    # ¿Ya existe item para esta máquina en este levantamiento?
    row = mysql_fetchone(
        "SELECT id FROM mant_levantamiento_items "
        " WHERE levantamiento_id=%s AND maquina_id=%s LIMIT 1",
        (lev_id, mid)
    )
    estados_validos = (
        "operativo", "advertencia", "fuera_servicio",
        "en_reparacion", "dado_baja", "no_encontrado"
    )
    # Construir SET map con solo lo que viene en el payload
    set_map = {}
    for k in ("estado_capturado", "marca", "modelo", "voltaje",
              "observaciones"):
        if k in payload:
            v = (str(payload.get(k) or "").strip()) or None
            if k == "estado_capturado" and v and v not in estados_validos:
                continue
            # Truncar para columnas con maxlen
            if k == "marca": v = (v or "")[:120] or None
            if k == "modelo": v = (v or "")[:120] or None
            if k == "voltaje": v = (v or "")[:20] or None
            set_map[k] = v
    if "anio_fabricacion" in payload:
        try:
            set_map["anio_fabricacion"] = int(payload["anio_fabricacion"]) \
                if payload["anio_fabricacion"] not in (None, "") else None
        except Exception:
            pass
    if "ubicacion_sala" in payload:
        # En mant_levantamiento_items la columna se llama `ubicacion`
        set_map["ubicacion"] = (str(payload["ubicacion_sala"] or "").strip())[:200] or None
    if "ultima_intervencion" in payload:
        v = payload["ultima_intervencion"]
        set_map["ultima_intervencion"] = v if v else None
    if "fecha_documento" in payload:
        v = payload["fecha_documento"]
        set_map["fecha_documento"] = v if v else None
    if "completado" in payload:
        set_map["completado"] = 1 if payload["completado"] else 0
    if "anomalias" in payload:
        set_map["anomalias"] = (str(payload["anomalias"] or "").strip()) or None
    if not set_map:
        return
    if row and row.get("id"):
        # UPDATE existente
        sets = []
        vals = []
        for k, v in set_map.items():
            sets.append(f"{k}=%s"); vals.append(v)
        vals.append(row["id"])
        mysql_execute(
            f"UPDATE mant_levantamiento_items SET {','.join(sets)} WHERE id=%s",
            tuple(vals)
        )
    else:
        # INSERT nuevo — snapshot inicial desde mant_maquinas
        snap = mysql_fetchone(
            "SELECT nombre, sku, serie FROM mant_maquinas WHERE id=%s",
            (mid,)
        ) or {}
        cols = ["levantamiento_id", "maquina_id",
                "nombre_snap", "sku_snap", "serie_snap"]
        vals = [lev_id, mid,
                (snap.get("nombre") or "")[:300] or None,
                (snap.get("sku") or "")[:120] or None,
                (snap.get("serie") or "")[:120] or None]
        for k, v in set_map.items():
            cols.append(k); vals.append(v)
        placeholders = ",".join(["%s"] * len(vals))
        mysql_execute(
            f"INSERT INTO mant_levantamiento_items ({','.join(cols)}) "
            f"VALUES ({placeholders})",
            tuple(vals)
        )
        # Recalcular total_equipos del levantamiento
        try:
            mysql_execute(
                "UPDATE mant_levantamientos SET total_equipos = "
                "(SELECT COUNT(*) FROM mant_levantamiento_items WHERE levantamiento_id=%s) "
                "WHERE id=%s",
                (lev_id, lev_id)
            )
        except Exception:
            pass


@app.route("/mantenciones/api/visitas/<int:vid>/equipo/<int:mid>/foto", methods=["POST"])
@_mant_required
@_tecnico_owns_visita
def mant_ot_equipo_foto(vid, mid):
    """Sube una foto del equipo en el contexto de una OT.

    2026-05-22 (Daniel) — Refactor para soportar GALERÍA por equipo:

      Modo 'principal' (default si no había foto previa):
        - Sube a Cloudinary con public_id estable maquina_<mid>.
        - Actualiza `mant_maquinas.foto_url` (ficha permanente).
        - Si la máquina ya tenía foto y NO es admin con force=1, degradamos
          silenciosamente a modo 'detalle' (no rechazamos el upload).

      Modo 'detalle' (siempre permitido al técnico):
        - Public_id ÚNICO (timestamp) → no pisa fotos anteriores.
        - NO toca `mant_maquinas.foto_url`.

    En AMBOS modos:
      - INSERT en `mant_visita_fotos` (evidencia de la OT).
      - Si la OT tiene levantamiento_id (o se crea al vuelo vía
        `_ensure_levantamiento_para_visita`), también INSERTA en
        `mant_levantamiento_fotos` → promoción a `mant_maquina_fotos`
        al cerrar la OT.

    Body multipart:
      - foto / file:  archivo (jpg/png/webp, máx 8MB)
      - tipo_foto:    'principal'|'detalle'|'serie'|'placa'|'dano'|'general'
      - descripcion:  str opcional (≤300)
      - force:        '1' → solo admin → reemplaza foto principal
    """
    f = request.files.get("foto") or request.files.get("file")
    if not f or not f.filename:
        return jsonify({"ok": False, "error": "Sin archivo"}), 400

    # Tamaño 8MB
    f.stream.seek(0, 2); size = f.stream.tell(); f.stream.seek(0)
    if size > 8 * 1024 * 1024:
        return jsonify({"ok": False, "error": "Archivo demasiado grande (máx 8MB)"}), 400
    # Validar tipo MIME — helper compartido
    try:
        _ext_ok, _err_val = _validate_uploaded_image(f, label=f.filename or "foto")
        if _err_val:
            return jsonify({"ok": False, "error": _err_val}), 400
    except Exception:
        pass

    tipos_validos = ("principal", "detalle", "serie", "placa",
                     "dano", "general", "antes", "despues")
    tipo_foto_solicitado = (request.form.get("tipo_foto") or "principal").strip().lower()
    if tipo_foto_solicitado not in tipos_validos:
        tipo_foto_solicitado = "principal"
    descripcion = (request.form.get("descripcion") or "").strip()[:300]
    force = (request.form.get("force") or "").strip() == "1"

    # Permisos
    es_admin = False
    try:
        perms = g.get("permissions") or {}
        es_admin = bool(perms.get("superadmin") or perms.get("admin"))
    except Exception:
        es_admin = False

    eq_existente = mysql_fetchone(
        "SELECT foto_url, cliente_id FROM mant_maquinas WHERE id=%s", (mid,)
    ) or {}
    foto_actual = (eq_existente.get("foto_url") or "").strip()

    # ¿Es principal? Depende de si ya hay foto y de permisos.
    es_principal = (tipo_foto_solicitado == "principal")
    if es_principal and foto_actual and not (es_admin and force):
        # Hay foto previa y no es admin con force → degradar a 'detalle'
        es_principal = False
    tipo_foto_final = "principal" if es_principal else (
        "detalle" if tipo_foto_solicitado == "principal" else tipo_foto_solicitado
    )

    try:
        import cloudinary, cloudinary.uploader
        if es_principal:
            public_id = f"maquina_{mid}"
            overwrite = True
            folder = "ilus/maquinas"
        else:
            public_id = f"maquina_{mid}_v{vid}_{int(time.time())}"
            overwrite = False
            folder = f"ilus/visitas/v{vid}"
        f.stream.seek(0)
        result = cloudinary.uploader.upload(
            f,
            folder=folder,
            public_id=public_id,
            overwrite=overwrite,
            resource_type="image",
            transformation=[
                {"width": 1600, "height": 1600, "crop": "limit"},
                {"quality": "auto:good", "fetch_format": "auto"},
            ],
        )
        url = result.get("secure_url")
        cld_public_id = result.get("public_id")
        bytes_size = result.get("bytes") or 0
        if not url:
            return jsonify({"ok": False, "error": "Cloudinary no devolvió URL"}), 500

        user = current_username() or "técnico"

        # 1) Si principal → actualizar mant_maquinas.foto_url
        if es_principal:
            mysql_execute(
                "UPDATE mant_maquinas SET foto_url=%s, last_visita_id=%s WHERE id=%s",
                (url, vid, mid)
            )

        # 2) Registrar evidencia en mant_visita_fotos
        try:
            mysql_execute(
                "INSERT INTO mant_visita_fotos "
                "(visita_id, tarea_id, maquina_id, archivo_path, cloudinary_url, "
                " archivo_nombre, tipo_foto, descripcion, tomada_por, file_size_kb) "
                "VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)",
                (vid, None, mid, "", url,
                 (f.filename or "")[:300],
                 ("levantamiento" if tipo_foto_final == "principal" else tipo_foto_final),
                 descripcion or None,
                 user[:190], (bytes_size // 1024))
            )
        except Exception as _e_vf:
            print(f"[mant_ot_equipo_foto] INSERT mant_visita_fotos vid={vid} "
                  f"mid={mid}: {_e_vf}", flush=True)

        # 3) Si la OT tiene/puede tener levantamiento → guardar en
        #    mant_levantamiento_fotos para promoción al cerrar.
        lev_id = _ensure_levantamiento_para_visita(vid)
        if lev_id:
            try:
                item_row = mysql_fetchone(
                    "SELECT id FROM mant_levantamiento_items "
                    " WHERE levantamiento_id=%s AND maquina_id=%s LIMIT 1",
                    (lev_id, mid)
                )
                if not item_row:
                    snap = mysql_fetchone(
                        "SELECT nombre, sku, serie FROM mant_maquinas WHERE id=%s",
                        (mid,)
                    ) or {}
                    mysql_execute(
                        "INSERT INTO mant_levantamiento_items "
                        "  (levantamiento_id, maquina_id, nombre_snap, sku_snap, serie_snap) "
                        "VALUES (%s, %s, %s, %s, %s)",
                        (lev_id, mid,
                         (snap.get("nombre") or "")[:300] or None,
                         (snap.get("sku") or "")[:120] or None,
                         (snap.get("serie") or "")[:120] or None)
                    )
                    item_row = mysql_fetchone(
                        "SELECT id FROM mant_levantamiento_items "
                        " WHERE levantamiento_id=%s AND maquina_id=%s LIMIT 1",
                        (lev_id, mid)
                    )
                if item_row and item_row.get("id"):
                    mysql_execute(
                        "INSERT INTO mant_levantamiento_fotos "
                        "(item_id, levantamiento_id, maquina_id, cloudinary_url, "
                        " cloudinary_public_id, tipo_foto, descripcion, bytes, "
                        " tomada_por) "
                        "VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s)",
                        (item_row["id"], lev_id, mid, url, cld_public_id,
                         (tipo_foto_final if tipo_foto_final != "principal" else "general")[:60],
                         (descripcion or "")[:300] or None,
                         int(bytes_size), user[:190])
                    )
                    try:
                        mysql_execute(
                            "UPDATE mant_levantamiento_items SET n_fotos = "
                            "  (SELECT COUNT(*) FROM mant_levantamiento_fotos "
                            "    WHERE item_id=%s) "
                            "WHERE id=%s",
                            (item_row["id"], item_row["id"])
                        )
                    except Exception:
                        pass
            except Exception as _e_lf:
                print(f"[mant_ot_equipo_foto] mant_levantamiento_fotos lev={lev_id} "
                      f"mid={mid}: {_e_lf}", flush=True)

        # 4) Audit log
        try:
            accion = ("foto_principal_subida" if es_principal
                      else f"foto_{tipo_foto_final}_subida")
            _mant_log("maquina", mid, accion,
                      f"OT #{vid} · {user} · {tipo_foto_final}")
        except Exception:
            pass

        return jsonify({
            "ok": True, "url": url,
            "tipo_foto": tipo_foto_final, "es_principal": es_principal,
            "degradado": (tipo_foto_solicitado == "principal" and not es_principal),
        })
    except Exception as e:
        print(f"[mant_ot_equipo_foto] err vid={vid} mid={mid}: {e}", flush=True)
        return jsonify({"ok": False, "error": str(e)}), 500


@app.route("/mantenciones/api/visitas/<int:vid>/equipo/<int:mid>/fotos", methods=["GET"])
@_mant_required
@_ot_can_view
def mant_ot_equipo_fotos_list(vid, mid):
    """Devuelve las fotos del equipo `mid` en el contexto de la OT `vid`,
    combinando mant_visita_fotos (de la OT) + mant_maquina_fotos (galería
    permanente previa). Útil para que el técnico vea histórico + las que
    está capturando ahora.

    2026-05-22 (Daniel) — UI de captura muestra miniaturas + galería.
    """
    out_fotos = []
    # Fotos de esta OT (recientes primero)
    try:
        rows = mysql_fetchall(
            "SELECT id, cloudinary_url, archivo_path, tipo_foto, descripcion, "
            "       tomada_por, tomada_at "
            "  FROM mant_visita_fotos "
            " WHERE visita_id=%s AND maquina_id=%s "
            " ORDER BY tomada_at DESC, id DESC",
            (vid, mid)
        ) or []
        for r in rows:
            url = r.get("cloudinary_url") or (
                f"/static/uploads/mantenciones/{r['archivo_path']}"
                if r.get("archivo_path") else ""
            )
            if not url:
                continue
            out_fotos.append({
                "id": r["id"],
                "url": url,
                "tipo_foto": r.get("tipo_foto") or "general",
                "descripcion": r.get("descripcion") or "",
                "tomada_por": r.get("tomada_por") or "",
                "fecha": str(r["tomada_at"])[:16] if r.get("tomada_at") else "",
                "fuente": "ot",
            })
    except Exception as _e_vf:
        print(f"[mant_ot_equipo_fotos_list] mant_visita_fotos: {_e_vf}", flush=True)

    # Fotos previas de la ficha del equipo (galería permanente, limit 30)
    try:
        rows = mysql_fetchall(
            "SELECT id, cloudinary_url, archivo_path, tipo_foto, descripcion, "
            "       tomada_por, tomada_at, visita_origen "
            "  FROM mant_maquina_fotos "
            " WHERE maquina_id=%s "
            " ORDER BY tomada_at DESC LIMIT 30",
            (mid,)
        ) or []
        for r in rows:
            url = r.get("cloudinary_url") or (
                f"/static/uploads/mantenciones/{r['archivo_path']}"
                if r.get("archivo_path") else ""
            )
            if not url:
                continue
            out_fotos.append({
                "id": r["id"],
                "url": url,
                "tipo_foto": r.get("tipo_foto") or "general",
                "descripcion": r.get("descripcion") or "",
                "tomada_por": r.get("tomada_por") or "",
                "fecha": str(r["tomada_at"])[:16] if r.get("tomada_at") else "",
                "fuente": "ficha",
                "visita_origen": r.get("visita_origen"),
            })
    except Exception as _e_mf:
        print(f"[mant_ot_equipo_fotos_list] mant_maquina_fotos: {_e_mf}", flush=True)

    foto_principal = ""
    try:
        r = mysql_fetchone("SELECT foto_url FROM mant_maquinas WHERE id=%s", (mid,))
        foto_principal = (r or {}).get("foto_url") or ""
    except Exception:
        pass

    return jsonify({
        "ok": True,
        "visita_id": vid,
        "maquina_id": mid,
        "foto_principal": foto_principal,
        "fotos": out_fotos,
    })


# ═════════════════════════════════════════════════════════════════════
# 2026-05-17 — Foto principal del equipo (admin/superadmin override).
# Daniel: "Igual el super administrador puede subir y cambiar y borrar
# la foto de la ficha del producto."
#
# Estos endpoints van por la FICHA del equipo (no por una OT). El admin
# elige libremente cuál foto queda como principal, incluso si la máquina
# ya tenía una previa (el técnico no puede hacerlo, ver endpoint arriba).
# ═════════════════════════════════════════════════════════════════════

@app.route("/mantenciones/api/maquinas/<int:mid>/foto", methods=["POST"])
@_mant_required
def mant_maquina_foto_admin_upload(mid):
    """Sube/reemplaza la foto principal del equipo. SOLO admin/superadmin."""
    perms = g.get("permissions") or {}
    if not (perms.get("superadmin") or perms.get("admin")):
        return jsonify({
            "ok": False,
            "error": "Solo administradores pueden gestionar la foto principal del equipo.",
        }), 403
    eq = mysql_fetchone("SELECT id, foto_url, cliente_id FROM mant_maquinas WHERE id=%s", (mid,))
    if not eq:
        return jsonify({"ok": False, "error": "Equipo no encontrado"}), 404
    f = request.files.get("foto") or request.files.get("file")
    if not f:
        return jsonify({"ok": False, "error": "Sin archivo"}), 400
    # Validar imagen + tamaño
    ext, err = _validate_uploaded_image(f, label=f.filename or "foto")
    if err:
        return jsonify({"ok": False, "error": err}), 400
    f.stream.seek(0, 2); size = f.stream.tell(); f.stream.seek(0)
    if size > 8 * 1024 * 1024:
        return jsonify({"ok": False, "error": "Archivo demasiado grande (máx 8MB)"}), 400
    try:
        import cloudinary, cloudinary.uploader
        result = cloudinary.uploader.upload(
            f,
            folder="ilus/maquinas",
            public_id=f"maquina_{mid}",
            overwrite=True,
            resource_type="image",
            transformation=[
                {"width": 1200, "height": 1200, "crop": "limit"},
                {"quality": "auto", "fetch_format": "auto"},
            ],
        )
        url = result.get("secure_url")
        if not url:
            return jsonify({"ok": False, "error": "Cloudinary no devolvió URL"}), 500
        antes = (eq.get("foto_url") or "").strip()
        mysql_execute(
            "UPDATE mant_maquinas SET foto_url=%s WHERE id=%s",
            (url, mid)
        )
        # Audit log + evento en timeline del equipo
        accion = "foto_reemplazada_admin" if antes else "foto_subida_admin"
        try:
            _mant_log("maquina", mid, accion,
                      f"Admin {current_username() or 'sistema'} "
                      f"{'reemplazó' if antes else 'subió'} foto principal")
        except Exception:
            pass
        try:
            mysql_execute(
                "INSERT INTO mant_maquina_eventos "
                "(maquina_id, tipo, descripcion, created_by) "
                "VALUES (%s, 'foto_agregada', %s, %s)",
                (mid,
                 f"{'Reemplazada' if antes else 'Subida'} foto principal por administrador",
                 (current_username() or 'admin')[:190])
            )
        except Exception:
            pass
        return jsonify({"ok": True, "foto_url": url, "url": url})
    except Exception as e:
        print(f"[mant_maquina_foto_admin_upload] err mid={mid}: {e}", flush=True)
        return jsonify({"ok": False, "error": "No se pudo subir la foto"}), 500


@app.route("/mantenciones/api/maquinas/<int:mid>/foto", methods=["DELETE"])
@_mant_required
def mant_maquina_foto_admin_delete(mid):
    """Borra la foto principal del equipo. SOLO admin/superadmin."""
    perms = g.get("permissions") or {}
    if not (perms.get("superadmin") or perms.get("admin")):
        return jsonify({
            "ok": False,
            "error": "Solo administradores pueden borrar la foto principal del equipo.",
        }), 403
    eq = mysql_fetchone("SELECT id, foto_url FROM mant_maquinas WHERE id=%s", (mid,))
    if not eq:
        return jsonify({"ok": False, "error": "Equipo no encontrado"}), 404
    if not (eq.get("foto_url") or "").strip():
        return jsonify({"ok": False, "error": "Este equipo no tiene foto principal"}), 400
    try:
        mysql_execute(
            "UPDATE mant_maquinas SET foto_url=NULL WHERE id=%s",
            (mid,)
        )
        try:
            _mant_log("maquina", mid, "foto_borrada_admin",
                      f"Admin {current_username() or 'sistema'} borró foto principal")
        except Exception:
            pass
        try:
            mysql_execute(
                "INSERT INTO mant_maquina_eventos "
                "(maquina_id, tipo, descripcion, created_by) "
                "VALUES (%s, 'otro', %s, %s)",
                (mid,
                 "Foto principal borrada por administrador",
                 (current_username() or 'admin')[:190])
            )
        except Exception:
            pass
        return jsonify({"ok": True})
    except Exception as e:
        print(f"[mant_maquina_foto_admin_delete] err mid={mid}: {e}", flush=True)
        return jsonify({"ok": False, "error": "No se pudo borrar la foto"}), 500


@app.route("/mantenciones/api/visitas/<int:vid>/exec-gps", methods=["POST"])
@_mant_required
@_tecnico_owns_visita
def mant_ot_exec_gps(vid):
    """Registra la geolocalización del técnico al INICIAR la ejecución.
    Sirve para auditar que ejecutó la OT desde la dirección del cliente."""
    d = request.get_json(silent=True) or {}
    try:
        lat = float(d.get("lat")) if d.get("lat") is not None else None
        lng = float(d.get("lng")) if d.get("lng") is not None else None
    except (TypeError, ValueError):
        return jsonify({"ok": False, "error": "lat/lng inválido"}), 400
    if lat is None or lng is None:
        return jsonify({"ok": False, "error": "Faltan coordenadas"}), 400
    direccion = (d.get("direccion") or "").strip()[:400] or None
    try:
        # Solo guardamos la PRIMERA vez (no sobreescribir si ya tiene)
        v = mysql_fetchone("SELECT exec_gps_lat FROM mant_visitas WHERE id=%s", (vid,))
        if v and v.get("exec_gps_lat") is None:
            mysql_execute(
                "UPDATE mant_visitas "
                "   SET exec_gps_lat=%s, exec_gps_lng=%s, "
                "       exec_gps_at=NOW(), exec_gps_direccion=%s "
                " WHERE id=%s",
                (lat, lng, direccion, vid)
            )
        return jsonify({"ok": True, "lat": lat, "lng": lng, "direccion": direccion})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 500


def _ot_firmante_cliente(vid):
    """Última identidad del firmante cliente (mant_ot_signatures) para mostrar
    su RUT/cargo en el PDF y el detalle de la OT. Devuelve {} si no hay firma."""
    try:
        r = mysql_fetchone(
            "SELECT signer_rut, signer_role FROM mant_ot_signatures "
            "WHERE ot_id=%s ORDER BY id DESC LIMIT 1", (vid,)
        )
        return dict(r) if r else {}
    except Exception:
        return {}


@app.route("/mantenciones/api/visitas/<int:vid>/firmar-revision", methods=["POST"])
@_mant_required
@_tecnico_owns_visita
def mant_ot_firmar_revision(vid):
    """El técnico firma la OT y la pasa a estado 'pendiente_revision'.
    El supervisor luego deberá aprobarla y cerrarla.

    Acepta:
      - firma_tecnico (data URL base64 o URL Cloudinary)
      - firma_tecnico_nombre (string)
      - firma_cliente (data URL)
      - firma_cliente_nombre
    """
    d = request.get_json(silent=True) or {}
    firma_tec = (d.get("firma_tecnico") or "").strip()
    nombre_tec = (d.get("firma_tecnico_nombre") or "").strip()[:200] or None
    firma_cli = (d.get("firma_cliente") or "").strip()
    nombre_cli = (d.get("firma_cliente_nombre") or "").strip()[:200] or None
    # ── Identidad del firmante cliente (Fase 2 — Daniel 2026-05-31) ──
    rut_cli    = (d.get("firma_cliente_rut") or "").strip()
    cargo_cli  = (d.get("firma_cliente_cargo") or "").strip()[:120] or None
    tel_cli    = (d.get("firma_cliente_tel") or "").strip()[:40] or None
    email_cli  = (d.get("firma_cliente_email") or "").strip()[:190] or None
    sug_nombre = (d.get("firma_cliente_sugerido_nombre") or "").strip()[:200] or None
    sug_rut    = (d.get("firma_cliente_sugerido_rut") or "").strip()[:20] or None

    if not firma_tec:
        return jsonify({"ok": False, "error": "Falta la firma del técnico"}), 400

    # Si el cliente firma, exigimos la identidad del firmante REAL: nombre +
    # RUT chileno válido. NO se asume el contacto principal (puede recibir otra
    # persona: encargado, conserjería, administración, etc.).
    rut_cli_norm = None
    if firma_cli:
        if not nombre_cli:
            return jsonify({"ok": False,
                            "error": "Falta el NOMBRE de quien firma por el cliente.",
                            "error_codigo": "FIRMANTE_SIN_NOMBRE"}), 400
        _ok_rut, _rut_res = validar_rut(rut_cli)
        if not _ok_rut:
            return jsonify({"ok": False,
                            "error": f"RUT del firmante inválido: {_rut_res}",
                            "error_codigo": "FIRMANTE_RUT_INVALIDO"}), 400
        rut_cli_norm = _formato_rut_chile(_rut_res) or _rut_res

    try:
        # ── Gate de cierre (Fase 10) ──────────────────────────────────────
        # Una tarea obligatoria está CUBIERTA si se completó O si su equipo fue
        # omitido con causal (estado_revision='saltado'). Así el técnico que SÍ
        # justificó no queda bloqueado. Devolvemos QUÉ FALTA por equipo para que
        # el frontend muestre el panel "No puedes cerrar todavía".
        faltan_rows = mysql_fetchall(
            "SELECT t.maquina_id, "
            "       COALESCE(m.nombre, CONCAT('Equipo #', t.maquina_id)) AS nombre, "
            "       COUNT(*) AS n "
            "  FROM mant_visita_tareas t "
            "  LEFT JOIN mant_maquinas m ON m.id = t.maquina_id "
            " WHERE t.visita_id=%s AND t.obligatoria=1 AND COALESCE(t.completada,0)=0 "
            "   AND NOT EXISTS (SELECT 1 FROM mant_visita_equipos e "
            "                    WHERE e.visita_id=t.visita_id AND e.maquina_id=t.maquina_id "
            "                      AND e.estado_revision='saltado') "
            " GROUP BY t.maquina_id, m.nombre "
            " ORDER BY nombre",
            (vid,)
        ) or []
        if faltan_rows:
            faltantes = [f"{r['nombre']}: {int(r['n'])} tarea(s) obligatoria(s) sin cubrir"
                         for r in faltan_rows]
            total_pend = sum(int(r["n"]) for r in faltan_rows)
            return jsonify({
                "ok": False,
                "error": (f"No puedes cerrar esta OT todavía: quedan {total_pend} "
                          "tarea(s) obligatoria(s) sin completar ni justificar."),
                "error_codigo": "TAREAS_PENDIENTES",
                "faltantes": faltantes,
            }), 400

        u = getattr(g, "user", None) or {}
        uid = u.get("id")

        # ── BUG FIX 2026-05-17 — Subir firmas a Cloudinary ──
        # Las firmas son data URLs base64 de ~100-500KB. La columna TEXT
        # legacy las truncaba (error 1406). Ahora subimos a Cloudinary
        # y guardamos solo la URL pública (corta). Si Cloudinary falla,
        # _subir_firma_cloudinary devuelve el data URL original como
        # fallback — la columna ahora es LONGTEXT y lo soporta.
        firma_tec_url = _subir_firma_cloudinary(firma_tec, vid, "tecnico")
        firma_cli_url = _subir_firma_cloudinary(firma_cli, vid, "cliente") if firma_cli else None

        # 2026-05-18 — Estampar el nombre del técnico al firmar. Si el form
        # no lo manda, default al display name del user (nombre o username).
        if not nombre_tec:
            nombre_tec = (u.get("nombre") or u.get("username") or "Técnico")[:200]

        mysql_execute(
            "UPDATE mant_visitas SET "
            "  firma_tecnico_url=%s, firma_tecnico_user_id=%s, "
            "  firma_tecnico_nombre=%s, firma_tecnico_at=NOW(), "
            "  firma_cliente_url=%s, firma_cliente_nombre=%s, firma_cliente_at=NOW(), "
            "  estado='pendiente_aprobacion' "
            " WHERE id=%s",
            (firma_tec_url, uid, nombre_tec, firma_cli_url, nombre_cli, vid)
        )
        # ── Registro de identidad del firmante cliente (Fase 2) ──────────
        # Persistimos quién firmó realmente (nombre + RUT validado) + el
        # contacto sugerido (para auditar si cambió) + trazabilidad.
        if firma_cli:
            try:
                _ua = (request.headers.get("User-Agent") or "")[:400]
                _ip = ((request.headers.get("X-Forwarded-For") or "").split(",")[0].strip()
                       or request.remote_addr or "")[:64]
                mysql_execute(
                    "INSERT INTO mant_ot_signatures "
                    "(ot_id, suggested_contact_name, suggested_contact_rut, "
                    " signer_name, signer_rut, signer_role, signer_phone, signer_email, "
                    " signature_url, signed_by_technician_id, ip, user_agent) "
                    "VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)",
                    (vid, sug_nombre, sug_rut, nombre_cli, rut_cli_norm, cargo_cli,
                     tel_cli, email_cli, firma_cli_url, uid, _ip, _ua)
                )
            except Exception as _e_sig:
                print(f"[firma-signer] no se guardó identidad firmante vid={vid}: {_e_sig}", flush=True)
        # Marcar levantamiento como cerrado si la OT tenía uno
        v_info = mysql_fetchone(
            "SELECT levantamiento_id FROM mant_visitas WHERE id=%s", (vid,)
        )
        if v_info and v_info.get("levantamiento_id"):
            mysql_execute(
                "UPDATE mant_levantamientos SET estado='cerrado', fecha_cierre=NOW() "
                " WHERE id=%s AND estado IN ('borrador','en_curso')",
                (v_info["levantamiento_id"],)
            )
        _mant_log("visita", vid, "firmada_tecnico",
                  f"{nombre_tec or ''} → pendiente_aprobacion")
        # ── Notificación al creador + supervisores ──────────────────
        # Best-effort, dispara en hilo. Si email/WA están deshabilitados
        # por kill-switch global, los helpers lo manejan internamente
        # (no rompe el flujo del técnico).
        try:
            _notificar_ot_pendiente_aprobacion_async(vid, request.host_url)
        except Exception as e_n:
            print(f"[notif-pend-aprob] fail vid={vid}: {e_n}", flush=True)
        return jsonify({"ok": True, "estado": "pendiente_aprobacion"})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 500


# ═════════════════════════════════════════════════════════════════════
# NOTIFICACIÓN: OT pasa a 'pendiente_aprobacion' → avisar al creador
# (y supervisores/admin) para que entren a firmar la aprobación final.
# Email + WhatsApp best-effort, en hilo daemon. Respeta kill-switches.
# ═════════════════════════════════════════════════════════════════════

def _notificar_ot_pendiente_aprobacion_async(vid, host_url=""):
    """Dispara hilo daemon que envía email + WhatsApp al `created_by` y
    a los supervisores/admin que tengan email o teléfono cargado, con
    un link directo a la OT para firmar como aprobador.

    NO bloquea la respuesta del endpoint. Si hay errores, los loguea pero
    nunca falla la firma del técnico.
    """
    import threading as _th_p
    base = (host_url or "").rstrip("/")

    def _bg():
        try:
            v = mysql_fetchone(
                "SELECT v.id, v.numero_ot, v.fecha_programada, v.created_by, "
                "       v.tecnico_user_id, c.razon_social, "
                "       COALESCE(ut.nombre, ut.username, v.tecnico) AS tecnico_nombre "
                "  FROM mant_visitas v "
                "  JOIN mant_clientes c ON c.id = v.cliente_id "
                "  LEFT JOIN app_users ut ON ut.id = v.tecnico_user_id "
                " WHERE v.id=%s",
                (vid,)
            )
            if not v:
                return
            numero_ot = v.get("numero_ot") or f"OT #{vid}"
            razon = v.get("razon_social") or "Cliente"
            tecnico = v.get("tecnico_nombre") or "el técnico"
            creador_username = (v.get("created_by") or "").strip()

            # ── Destinatarios: creador + admins + supervisores + ejecutivos ──
            # Cada uno se notifica solo una vez (dedupe por user id).
            destinos = []  # lista de dicts {id, username, nombre, phone, kind}
            seen_ids = set()

            def _add(user_dict, kind):
                if not user_dict:
                    return
                uid = user_dict.get("id")
                if not uid or uid in seen_ids:
                    return
                seen_ids.add(uid)
                destinos.append({
                    "id":       uid,
                    "username": (user_dict.get("username") or "").strip(),
                    "nombre":   (user_dict.get("nombre") or user_dict.get("username") or "").strip(),
                    "phone":    (user_dict.get("phone") or "").strip(),
                    "kind":     kind,
                })

            # 1) Creador de la OT (prioridad)
            if creador_username:
                try:
                    row = mysql_fetchone(
                        f"SELECT id, username, nombre, phone FROM `{AUTH_TABLE}` "
                        f" WHERE username=%s AND active=1 LIMIT 1",
                        (creador_username,)
                    )
                    _add(row, "creador")
                except Exception as _e:
                    print(f"[notif-pend] err buscando creador {creador_username}: {_e}",
                          flush=True)

            # 2) Supervisores + admins + superadmin (todos los que pueden aprobar)
            try:
                supers = mysql_fetchall(
                    f"SELECT id, username, nombre, phone, role FROM `{AUTH_TABLE}` "
                    f" WHERE active=1 AND role IN ('superadmin','admin','supervisor') "
                    f" ORDER BY role, nombre"
                ) or []
                for r in supers:
                    _add(r, r.get("role") or "supervisor")
            except Exception as _e:
                print(f"[notif-pend] err buscando supervisores: {_e}", flush=True)

            if not destinos:
                print(f"[notif-pend-aprob] sin destinatarios vid={vid}", flush=True)
                return

            # Link a la OT (el aprobador entra desde computador y firma)
            link_ot = (f"{base}/mantenciones/ot/{vid}/ejecutar"
                       if base else f"/mantenciones/ot/{vid}/ejecutar")

            # 2026-05-22 (Daniel) — NOTIFICACIÓN INTERNA (campana del header)
            # Para cada destino con user_id, dejamos fila en mant_notificaciones.
            # Idempotente: si ya hay una abierta de tipo='ot_pendiente_aprobacion'
            # con la misma (visita_id, destino_user_id), no inserta otra.
            try:
                titulo_interno = f"{numero_ot} esperando tu firma de aprobación"
                cuerpo_interno = (
                    f"El técnico {tecnico} firmó la OT y la dejó lista. "
                    f"Cliente: {razon}. Entra a firmar como aprobador."
                )
                for d_dest in destinos:
                    if not d_dest.get("id"):
                        continue
                    try:
                        _mant_notificar(
                            destino_user_id=int(d_dest["id"]),
                            tipo="ot_pendiente_aprobacion",
                            titulo=titulo_interno,
                            cuerpo=cuerpo_interno,
                            url_accion=f"/mantenciones/ot/{vid}/ejecutar",
                            prioridad="alta",
                            visita_id=vid,
                        )
                    except Exception as _e_ni:
                        print(f"[notif-pend][interna] vid={vid} dest={d_dest.get('id')}: {_e_ni}",
                              flush=True)
            except Exception as _e_ni_outer:
                print(f"[notif-pend][interna] vid={vid} outer: {_e_ni_outer}", flush=True)

            # 2026-05-21: subject + WA usan marca editable desde /comunicaciones
            subject = _brand_subject(f"{numero_ot} esperando tu firma de aprobación")
            wa_template = (
                _brand_wa_prefix(f"{numero_ot} esperando tu firma") +
                f"Hola {{nombre}}, el técnico {tecnico} terminó la OT "
                f"{numero_ot} para el cliente {razon}.\n\n"
                f"Firma como aprobador para cerrarla:\n{link_ot}"
            )

            # WhatsApp: sólo si está habilitado por env var Y configurado
            # en Twilio. Email vía Resend NO depende de este flag —
            # siempre se intenta y es el canal principal del flujo.
            wa = _get_wa_cfg()
            wa_ok = (_canal_activo("whatsapp") and
                     bool(wa.get("account_sid") and wa.get("auth_token")
                          and wa.get("from_number")))

            for d_dest in destinos:
                nombre_d = d_dest["nombre"] or "equipo ILUS"
                # En el sistema ILUS muchos usernames SON correos
                # (ej: daniel.aguilar@sphs.cl). Para email usamos username
                # si tiene formato de correo, sino lo saltamos.
                username = d_dest["username"]
                is_email = bool(username and "@" in username
                                and "." in username.split("@")[-1])
                email_ok = False
                if is_email:
                    try:
                        # Usamos el template ILUS oficial (header negro + logo + CTA rojo)
                        cuerpo = _ilus_email_html(
                            titulo="OT esperando tu firma",
                            subtitulo=f"{numero_ot} · {razon}",
                            saludo=nombre_d,
                            parrafos=[
                                f"El técnico <strong>{tecnico}</strong> terminó la OT "
                                f"<strong>{numero_ot}</strong> y firmó como ejecutor.",
                                "Necesita tu firma como aprobador para cerrarla.",
                            ],
                            btn_primario_txt="Firmar y cerrar la OT",
                            btn_primario_url=link_ot,
                            info_lineas=[
                                ("", "Cliente", razon),
                                ("", "Técnico", tecnico),
                                ("", "OT", numero_ot),
                            ],
                        )
                        email_ok = _send_ilus_email(
                            username, subject, cuerpo,
                            evento="ot_pendiente_aprobacion",
                            modulo="mantenciones",
                        )
                    except Exception as e_e:
                        print(f"[notif-pend][email] vid={vid} dest={username}: {e_e}",
                              flush=True)
                # WhatsApp si tiene phone cargado Y canal activo Y Twilio configurado
                phone = d_dest["phone"]
                if wa_ok and phone:
                    try:
                        _send_whatsapp(
                            wa["account_sid"], wa["auth_token"], wa["from_number"],
                            phone, wa_template.replace("{nombre}", nombre_d),
                            modulo="mantenciones",
                        )
                    except Exception as e_w:
                        print(f"[notif-pend][wa] vid={vid} dest={phone}: {e_w}",
                              flush=True)
                # Si no logramos enviar nada para este destino, log explícito
                # para que Daniel pueda rastrear sin que se rompa el flujo
                if not (email_ok or (wa_ok and phone)):
                    print(f"[notify-fail] vid={vid} dest={username or phone or 'sin-contacto'} "
                          f"reason=sin_canal_activo "
                          f"(canales: email={_canal_activo('email')} wa={_canal_activo('whatsapp')})",
                          flush=True)
        except Exception as e_outer:
            print(f"[notif-pend-aprob] outer fail vid={vid}: {e_outer}",
                  flush=True)

    try:
        _th_p.Thread(target=_bg, daemon=True,
                     name=f"notif-pend-aprob-{vid}").start()
    except Exception as e:
        print(f"[notif-pend-aprob] no se pudo iniciar hilo vid={vid}: {e}",
              flush=True)


# ═════════════════════════════════════════════════════════════════════
# F7 — INICIAR RUTA (Google Maps / Waze)
# ═════════════════════════════════════════════════════════════════════

@app.route("/mantenciones/api/visitas/<int:vid>/iniciar-ruta", methods=["POST"])
@_mant_required
@_tecnico_owns_visita
def mant_ot_iniciar_ruta(vid):
    """Registra que el técnico inició la navegación hacia la dirección
    del cliente. Guarda timestamp + ubicación de origen + app elegida
    (google|waze|saltado).

    Si elige 'saltado', solo se registra que decidió no usar nav.
    """
    d = request.get_json(silent=True) or {}
    app_sel = (d.get("app") or "").strip().lower()
    if app_sel not in ("google", "waze", "saltado"):
        return jsonify({"ok": False, "error": "app inválida (google|waze|saltado)"}), 400
    try:
        lat = float(d.get("lat")) if d.get("lat") is not None else None
        lng = float(d.get("lng")) if d.get("lng") is not None else None
    except (TypeError, ValueError):
        lat, lng = None, None
    try:
        # Solo registrar la PRIMERA vez (no sobreescribir)
        v = mysql_fetchone("SELECT ruta_iniciada_at FROM mant_visitas WHERE id=%s", (vid,))
        if v and v.get("ruta_iniciada_at") is None:
            mysql_execute(
                "UPDATE mant_visitas SET "
                "  ruta_iniciada_at=NOW(), "
                "  ruta_origen_lat=%s, ruta_origen_lng=%s, ruta_app=%s "
                " WHERE id=%s",
                (lat, lng, app_sel, vid)
            )
            try: _mant_log("visita", vid, "ruta_iniciada", f"app={app_sel} origen=({lat},{lng})")
            except Exception: pass
        return jsonify({"ok": True, "app": app_sel})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 500


# ═════════════════════════════════════════════════════════════════════
# F6 — SUPERVISOR APRUEBA / RECHAZA OT FIRMADA
# Estado: pendiente_aprobacion → cerrada (aprobada) o programada (rechazada)
# ═════════════════════════════════════════════════════════════════════

def _is_supervisor_user():
    """True si el usuario actual puede aprobar OTs como supervisor.

    🔒 FIX 2026-05-22 (Daniel — clarificación rol ejecutivo SSTT):
    El EJECUTIVO de servicio técnico (rol ejecutivo_sstt — ej. Aaron Urbina)
    SÍ es supervisor en el flujo de cierre. Es quien gestiona la OT, la
    levanta, la asigna al técnico Y firma como tercer responsable cuando
    Lenin termina el trabajo. Sin la firma del ejecutivo la OT no cierra.

    Responsabilidades en la firma (procedimiento interno ILUS):
      - Técnico: declara haber prestado el servicio sin detalles.
      - Cliente: recibe conforme el trabajo realizado.
      - Ejecutivo SSTT: revisa y certifica que la OT quedó bien gestionada.

    Si hay 2+ ejecutivos SSTT (caso futuro), ambos comparten esta atribución.
    """
    try:
        perms = g.get("permissions") or {}
        if perms.get("superadmin") or perms.get("admin"):
            return True
        u = getattr(g, "user", None) or {}
        fam = _rol_familia(u.get("role") or "")
        if fam in ("supervisor", "admin", "superadmin", "ejecutivo"):
            return True
    except Exception:
        pass
    return False


def _is_aprobador(user=None):
    """True si el usuario puede aprobar/firmar OTs como tercer responsable.

    Familia autorizada: superadmin · admin · supervisor · ejecutivo.

    Wrapper canónico para chequeos de "¿puede ver botón Revisar?" en
    contextos donde NO tenemos vid (ej. listado global). Para chequeos
    por OT específica usar `_puede_ot_accion(vid, "aprobar", user)`.

    🔒 FIX 2026-05-22 (Daniel — clarificación):
    El EJECUTIVO SSTT (Aaron) SÍ firma como supervisor de la OT. Eso forma
    parte del compromiso de su rol: gestiona la OT y certifica que el
    trabajo del técnico quedó bien hecho. Coherente con
    `_puede_ot_accion('aprobar')` y `_is_supervisor_user()`.
    """
    u = user or getattr(g, "user", None) or {}
    fam = _rol_familia((u.get("role") or "").lower())
    return fam in ("superadmin", "admin", "supervisor", "ejecutivo")


@app.route("/mantenciones/api/visitas/<int:vid>/aprobar-cierre", methods=["POST"])
@_mant_required
def mant_ot_aprobar_cierre(vid):
    """Supervisor aprueba la OT firmada por el técnico → estado 'cerrada'.
    Guarda firma_supervisor + comentario + timestamp + user_id.

    🔐 SEGURIDAD 2026-05-22 (Daniel — clarificación rol ejecutivo):
    El ejecutivo SSTT (Aaron) SÍ firma como supervisor de la OT. Es parte
    del compromiso de su rol gestor — revisar y certificar que el trabajo
    del técnico quedó bien hecho. Familia autorizada: superadmin · admin ·
    supervisor · ejecutivo. Esa firma cierra el flujo: cliente recibe
    conforme + técnico declara servicio prestado + ejecutivo certifica.
    """
    if not _puede_ot_accion(vid, "aprobar"):
        _u = getattr(g, "user", None) or {}
        print(
            f"[SECURITY] {_u.get('id')} ({_u.get('username')}) intento aprobar "
            f"vid={vid} sin permiso (role={(_u.get('role') or '').lower()})",
            flush=True
        )
        return jsonify({
            "ok": False,
            "error": "No tienes permiso para firmar el cierre de esta OT. "
                     "Solo el ejecutivo SSTT, supervisor o administrador "
                     "pueden aprobar.",
        }), 403
    d = request.get_json(silent=True) or {}
    firma_sup = (d.get("firma_supervisor") or "").strip()
    comentario = (d.get("comentario") or "").strip()[:1000] or None
    # FIX 2026-05-18 — Capturar el nombre del firmante. Si el form no lo
    # manda, usamos el display name del usuario actual (nombre o username).
    firma_sup_nombre = (d.get("firma_supervisor_nombre") or "").strip()[:200]
    # Validar estado actual
    v = mysql_fetchone("SELECT estado FROM mant_visitas WHERE id=%s", (vid,))
    if not v:
        return jsonify({"ok": False, "error": "OT no encontrada"}), 404
    if v.get("estado") not in ("pendiente_aprobacion", "completada"):
        return jsonify({
            "ok": False,
            "error": f"La OT no está en estado pendiente_aprobacion (actual: {v.get('estado')})",
        }), 400
    try:
        u = getattr(g, "user", None) or {}
        uid = u.get("id")
        # Default: nombre del usuario actual (Aaron Urbina, Daniel Aguilar, etc.)
        if not firma_sup_nombre:
            firma_sup_nombre = (u.get("nombre") or u.get("username") or "Aprobador")[:200]
        # ── BUG FIX 2026-05-17 — Subir firma supervisor a Cloudinary ──
        # Misma lógica que firmar-revision: data URL → URL pública corta.
        firma_sup_url = _subir_firma_cloudinary(firma_sup, vid, "supervisor") if firma_sup else None
        mysql_execute(
            "UPDATE mant_visitas SET "
            "  estado='cerrada', cerrada_at=NOW(), cerrada_por=%s, "
            "  firma_supervisor_url=%s, firma_supervisor_user_id=%s, "
            "  firma_supervisor_nombre=%s, firma_supervisor_at=NOW() "
            " WHERE id=%s",
            (current_username() or 'supervisor', firma_sup_url, uid, firma_sup_nombre, vid)
        )
        try: _mant_log("visita", vid, "aprobada_supervisor",
                       f"{current_username()}{' · ' + comentario if comentario else ''}")
        except Exception: pass
        # ── Promoción levantamiento → ficha de equipo (async, no bloquea) ──
        # Aplica si la OT es tipo='levantamiento' O si tiene levantamiento_id
        # poblado (caso Vitacura 2026-05-22 — Aaron creó preventiva desde el
        # modal del cliente, que igual genera levantamiento_id). Los datos
        # capturados (fotos, marca/modelo/serie/estado) se promueven a la
        # ficha del equipo (mant_maquinas) + historial cronológico. El
        # wrapper interno (_promover_levantamiento_a_maquina) hace el filtro
        # fino: solo promueve si tipo='levantamiento' o levantamiento_id NOT NULL.
        _promover_levantamiento_async(vid, usuario=current_username())
        # 2026-05-22 (Daniel) — Notificar al técnico (campana) y opcionalmente
        # al cliente por email (env MANT_NOTIF_CLIENTE_EMAIL_ENABLED).
        try:
            _notificar_cierre_ot_async(vid, resultado="aprobada",
                                       motivo=comentario, host_url=request.host_url)
        except Exception as _e_nca:
            print(f"[aprobar-cierre notif] {_e_nca}", flush=True)
        return jsonify({"ok": True, "estado": "cerrada"})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 500


@app.route("/mantenciones/api/visitas/<int:vid>/rechazar-cierre", methods=["POST"])
@_mant_required
def mant_ot_rechazar_cierre(vid):
    """Supervisor rechaza la OT → vuelve a 'programada' para que técnico
    corrija. Limpia firma_tecnico (debe firmar de nuevo).

    🔐 SEGURIDAD 2026-05-22 (Daniel — clarificación final):
    El supervisor formal de la OT incluye al ejecutivo SSTT (Aaron). Si
    revisa el trabajo del técnico y detecta algo que corregir, también
    puede rechazar — es parte de su rol gestor. Familia autorizada:
    superadmin · admin · supervisor · ejecutivo.
    """
    if not _puede_ot_accion(vid, "aprobar"):
        _u = getattr(g, "user", None) or {}
        print(
            f"[SECURITY] {_u.get('id')} ({_u.get('username')}) intento rechazar "
            f"vid={vid} sin permiso (role={(_u.get('role') or '').lower()})",
            flush=True
        )
        return jsonify({
            "ok": False,
            "error": "No tienes permiso para rechazar el cierre de esta OT. "
                     "El rechazo le corresponde al ejecutivo SSTT, "
                     "supervisor o administrador.",
        }), 403
    d = request.get_json(silent=True) or {}
    motivo = (d.get("motivo") or "").strip()[:1000]
    if not motivo:
        return jsonify({"ok": False, "error": "Indica el motivo del rechazo"}), 400
    v = mysql_fetchone("SELECT estado FROM mant_visitas WHERE id=%s", (vid,))
    if not v:
        return jsonify({"ok": False, "error": "OT no encontrada"}), 404
    if v.get("estado") != "pendiente_aprobacion":
        return jsonify({
            "ok": False,
            "error": f"Solo se pueden rechazar OTs pendientes (actual: {v.get('estado')})",
        }), 400
    try:
        mysql_execute(
            "UPDATE mant_visitas SET "
            "  estado='programada', "
            "  firma_tecnico_url=NULL, firma_tecnico_user_id=NULL, firma_tecnico_at=NULL "
            " WHERE id=%s",
            (vid,)
        )
        try: _mant_log("visita", vid, "rechazada_supervisor",
                       f"{current_username()} · motivo: {motivo}")
        except Exception: pass
        # 2026-05-22 (Daniel) — Notificar al técnico (campana) que la OT
        # fue rechazada y debe corregir + refirmar.
        try:
            _notificar_cierre_ot_async(vid, resultado="rechazada",
                                       motivo=motivo, host_url=request.host_url)
        except Exception as _e_ncr:
            print(f"[rechazar-cierre notif] {_e_ncr}", flush=True)
        return jsonify({"ok": True, "estado": "programada", "motivo": motivo})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 500


# ═════════════════════════════════════════════════════════════════════
# Tarea: respuesta avanzada (tipo_respuesta != check)
# ═════════════════════════════════════════════════════════════════════

@app.route("/mantenciones/api/visitas/<int:vid>/tareas/<int:tid>/respuesta", methods=["POST"])
@_mant_required
@_tecnico_owns_visita
def mant_visita_tarea_respuesta(vid, tid):
    """Guarda la respuesta capturada por el técnico para una tarea con
    tipo_respuesta avanzado (texto, numero, sino, verificacion, lista,
    fecha_hora, gps). El valor se serializa como JSON en mant_visita_tareas.valor_json.

    Body JSON:
      { "valor": <según tipo> }
        - texto: "..."
        - numero: 12.5
        - sino: "si"|"no"|"na"
        - verificacion: "aprobado"|"alerta"|"falla"
        - lista: "opcion_seleccionada"
        - fecha_hora: "2026-05-17T14:30"
        - gps: {"lat": ..., "lng": ...}
    Auto-completa la tarea si el valor es válido.
    """
    d = request.get_json(silent=True) or {}
    valor = d.get("valor")
    # Leer la tarea para conocer su tipo + version + lock-holder
    tar = mysql_fetchone(
        "SELECT id, tipo_respuesta, obligatoria, rango_min, rango_max, valor_json, "
        "       version, locked_by_user_id, locked_at "
        "  FROM mant_visita_tareas WHERE id=%s AND visita_id=%s",
        (tid, vid)
    )
    if not tar:
        return jsonify({"ok": False, "error": "Tarea no encontrada"}), 404
    # ── Version check (concurrencia multitécnico) ──
    # Si el frontend envía version y NO coincide, otro técnico ya modificó
    # la tarea desde que el front la cargó. El front debe recargar.
    # admin/supervisor bypass (pueden sobreescribir cambios).
    if "version" in d and not _is_supervisor_user():
        try:
            v_front = int(d.get("version"))
            v_db = int(tar.get("version") or 0)
            if v_front != v_db:
                return jsonify({
                    "ok": False,
                    "error": "Otro técnico modificó esta tarea. Refresca para ver los cambios.",
                    "error_codigo": "VERSION_CONFLICT",
                    "version_db": v_db,
                }), 409
        except (TypeError, ValueError):
            pass  # version inválida → seguir sin check
    # FIX 2026-05-17 (GPS DEFINITIVO): normalizar tipo_respuesta
    # Tareas heredadas de plantillas viejas pueden tener tipo='GPS' (mayúsculas)
    # o con espacios. Antes el strict equality fallaba y devolvía 400.
    tipo_raw = tar.get("tipo_respuesta") or "check"
    tipo = str(tipo_raw).strip().lower() or "check"

    # ── FIX 2026-05-17 (GPS DEFINITIVO): detector de payload GPS extra ──
    # Si el frontend manda {_gps_extra: {lat, lng, ...}} = quiere ADJUNTAR
    # ubicación a una tarea que no es de tipo GPS. La mergeamos al valor_json
    # existente sin pisar el valor principal y completamos como antes.
    if isinstance(valor, dict) and isinstance(valor.get("_gps_extra"), dict):
        try:
            gps_lat = float(valor["_gps_extra"].get("lat")) if valor["_gps_extra"].get("lat") is not None else None
            gps_lng = float(valor["_gps_extra"].get("lng")) if valor["_gps_extra"].get("lng") is not None else None
        except (TypeError, ValueError):
            return jsonify({"ok": False, "error": "Coordenadas inválidas en _gps_extra"}), 400
        if gps_lat is None or gps_lng is None:
            return jsonify({"ok": False, "error": "Faltan lat/lng en _gps_extra"}), 400
        # POLÍTICA 2026-05-17: solo GPS real, sin IP/manual, accuracy<=500m
        _src_x = str(valor["_gps_extra"].get("source") or "").strip().lower()[:20]
        if _src_x and _src_x in ("ip", "manual"):
            return jsonify({"ok": False,
                "error": "Solo GPS real. IP/manual deshabilitados por auditoría."}), 403
        _acc_x = None
        if valor["_gps_extra"].get("accuracy") is not None:
            try:
                _acc_x = float(valor["_gps_extra"]["accuracy"])
                if _acc_x > 500:
                    return jsonify({"ok": False,
                        "error": f"Precisión GPS muy baja (±{int(_acc_x)}m)."}), 400
            except (TypeError, ValueError):
                _acc_x = None
        # Mergeamos sobre el valor_json existente (preservando lo que el técnico ya respondió)
        try:
            existente = {}
            if tar.get("valor_json"):
                try:
                    existente = json.loads(tar["valor_json"]) if isinstance(tar["valor_json"], str) else dict(tar["valor_json"])
                except Exception:
                    existente = {}
            existente["_gps_extra"] = {
                "lat": gps_lat, "lng": gps_lng,
                "accuracy": _acc_x,
                "source": "gps",   # forzado tras validación
                "dir": str(valor["_gps_extra"].get("dir") or "")[:400] or None,
                "at": datetime.now().isoformat(timespec="seconds"),
            }
            mysql_execute(
                "UPDATE mant_visita_tareas SET valor_json=%s "
                " WHERE id=%s AND visita_id=%s",
                (json.dumps(existente, ensure_ascii=False), tid, vid)
            )
            return jsonify({
                "ok": True,
                "completada": bool(existente.get("completada") or False),
                "warning": None,
                "valor_norm": existente,
                "msg": "GPS adjunto guardado",
            })
        except Exception as e:
            print(f"[tarea_respuesta _gps_extra] err: {e}", flush=True)
            return jsonify({"ok": False, "error": "No se pudo guardar el GPS adjunto"}), 500

    # ── FIX 2026-05-17 (GPS DEFINITIVO): auto-promote a GPS ──
    # Si el payload trae lat/lng pero la tarea NO es de tipo GPS (porque
    # se heredó mal o cambió), igual aceptamos y guardamos como GPS.
    # Sin esto, una tarea con tipo_respuesta=NULL nunca podría guardar GPS.
    if isinstance(valor, dict) and valor.get("lat") is not None and valor.get("lng") is not None:
        try:
            test_lat = float(valor.get("lat"))
            test_lng = float(valor.get("lng"))
            if tipo != "gps":
                tipo = "gps"  # promote
        except (TypeError, ValueError):
            pass  # cae al validador normal abajo

    # Validar el valor según tipo
    valor_norm = None
    error = None
    completar = True
    if tipo == "texto":
        # 2026-05-18 (Mejora UX): aplicamos umbral mínimo de caracteres para
        # marcar la tarea como gestionada (completada=1). Si el técnico escribió
        # menos del mínimo, persistimos el valor pero NO marcamos completada
        # — así no pierde lo escrito y puede seguir editando.
        #   - obligatoria → 10 caracteres mínimo
        #   - opcional    → 3 caracteres mínimo
        v = (str(valor or "")).strip()[:2000]
        valor_norm = {"texto": v}
        _min_chars = 10 if tar.get("obligatoria") else 3
        if len(v) < _min_chars:
            completar = False
    elif tipo == "numero":
        try:
            n = float(valor) if valor not in (None, "") else None
        except (TypeError, ValueError):
            return jsonify({"ok": False, "error": "Valor numérico inválido"}), 400
        if n is None:
            completar = False
            valor_norm = {"numero": None}
        else:
            valor_norm = {"numero": n}
            # Validar rango si aplica
            rmin = tar.get("rango_min")
            rmax = tar.get("rango_max")
            if rmin is not None and n < float(rmin):
                error = f"Fuera de rango: mínimo {rmin}"
            if rmax is not None and n > float(rmax):
                error = f"Fuera de rango: máximo {rmax}"
    elif tipo == "sino":
        v = str(valor or "").lower()
        if v not in ("si", "sí", "no", "na", "n/a"):
            return jsonify({"ok": False, "error": "Valor inválido (si|no|na)"}), 400
        if v == "sí": v = "si"
        if v == "n/a": v = "na"
        valor_norm = {"valor": v}
    elif tipo == "verificacion":
        v = str(valor or "").lower()
        if v not in ("aprobado", "alerta", "falla"):
            return jsonify({"ok": False, "error": "Valor inválido"}), 400
        valor_norm = {"valor": v}
    elif tipo == "lista":
        v = str(valor or "").strip()[:200]
        if not v:
            return jsonify({"ok": False, "error": "Seleccioná una opción"}), 400
        valor_norm = {"opcion": v}
    elif tipo == "fecha_hora":
        v = str(valor or "").strip()[:30]
        valor_norm = {"fecha": v or None}
        if tar.get("obligatoria") and not v:
            completar = False
    elif tipo == "gps":
        # ═══════════════════════════════════════════════════════════
        # POLÍTICA 2026-05-17 (Daniel) — Solo GPS REAL del dispositivo.
        # Se RECHAZAN entries con source='ip' o source='manual' porque
        # vulneran la auditoría (el técnico podría falsear su posición).
        # Solo se aceptan: 'gps', 'gps_high', 'gps_low', 'watch'.
        # Adicionalmente: si accuracy > 500m la captura se rechaza por
        # impresión sospechosa.
        # ═══════════════════════════════════════════════════════════
        try:
            lat = float(valor.get("lat")) if isinstance(valor, dict) and valor.get("lat") is not None else None
            lng = float(valor.get("lng")) if isinstance(valor, dict) and valor.get("lng") is not None else None
        except (TypeError, ValueError):
            return jsonify({"ok": False, "error": "Coordenadas inválidas"}), 400
        if lat is None or lng is None:
            return jsonify({"ok": False, "error": "Faltan lat/lng"}), 400
        # Validar source — rechazar IP y manual
        src_raw = ""
        if isinstance(valor, dict):
            src_raw = str(valor.get("source") or "").strip().lower()[:20]
        if src_raw and src_raw in ("ip", "manual"):
            return jsonify({
                "ok": False,
                "error": "Solo se acepta GPS real del dispositivo. " +
                         "IP y manual están deshabilitados por política de auditoría."
            }), 403
        # Validar accuracy — rechazar imprecisiones absurdas (>500m sugiere wifi/IP)
        acc = None
        if isinstance(valor, dict) and valor.get("accuracy") is not None:
            try:
                acc = float(valor["accuracy"])
                if acc > 500:
                    return jsonify({
                        "ok": False,
                        "error": f"Precisión GPS muy baja (±{int(acc)}m). " +
                                 "Salí al aire libre y reintentá."
                    }), 400
            except (TypeError, ValueError):
                acc = None
        valor_norm = {"lat": lat, "lng": lng}
        if acc is not None:
            valor_norm["accuracy"] = acc
        # source siempre se normaliza a 'gps' (rechazamos otros arriba)
        valor_norm["source"] = "gps"
    else:
        return jsonify({"ok": False, "error": f"Tipo no soportado por este endpoint: {tipo}"}), 400

    try:
        user = current_username() or 'sistema'
        sets = ["valor_json=%s"]
        vals = [json.dumps(valor_norm, ensure_ascii=False)]
        if completar:
            sets += ["completada=1", "completada_at=%s", "completada_por=%s"]
            vals += [datetime.now(), user]
        else:
            sets += ["completada=0", "completada_at=NULL", "completada_por=NULL"]
        # ── Auto-unlock + bump version (concurrencia multitécnico) ──
        # Liberar el lock al guardar la respuesta para que otros técnicos
        # puedan responder otras tareas. Incrementar version para que
        # ediciones concurrentes detecten el cambio.
        sets += ["locked_by_user_id=NULL", "locked_at=NULL",
                 "version=COALESCE(version,0)+1"]
        vals.append(tid); vals.append(vid)
        mysql_execute(
            f"UPDATE mant_visita_tareas SET {', '.join(sets)} "
            f" WHERE id=%s AND visita_id=%s",
            tuple(vals)
        )
        # Releer version actualizada para devolver al frontend
        v_new = mysql_fetchone(
            "SELECT version FROM mant_visita_tareas WHERE id=%s", (tid,)
        )
        return jsonify({
            "ok": True,
            "completada": completar,
            "warning": error,
            "valor_norm": valor_norm,
            "version": int((v_new or {}).get("version") or 0),
        })
    except Exception as e:
        # No filtrar el SQL al cliente — log interno + mensaje genérico
        print(f"[tarea_respuesta] err: {e}", flush=True)
        return jsonify({"ok": False, "error": "No se pudo guardar la respuesta"}), 500


# ═════════════════════════════════════════════════════════════════════
# 2026-05-17 — LOCK OPTIMISTA POR TAREA (concurrencia multitécnico)
# Daniel: "¿Cómo nos garantiza que un técnico no va a borrar una ficha
# que otro esté abordando?"
#
# Flujo:
#   1. Técnico abre una tarea → POST /lock — marca locked_by_user_id + locked_at
#   2. Otros técnicos ven badge "🔒 Siendo gestionada por X" y NO pueden
#      editar/responder hasta que se libere.
#   3. Al guardar respuesta (POST /respuesta) → auto-unlock + bump version.
#   4. TTL del lock: 10 minutos. Si el técnico se desconecta sin guardar,
#      el lock expira y otro puede tomarla.
#   5. Admin/supervisor SIEMPRE puede sobrescribir el lock (override).
# ═════════════════════════════════════════════════════════════════════

# TTL del lock en minutos (configurable)
_TAREA_LOCK_TTL_MIN = 10


@app.route("/mantenciones/api/visitas/<int:vid>/tareas/<int:tid>/lock", methods=["POST"])
@_mant_required
@_tecnico_owns_visita
def mant_visita_tarea_lock(vid, tid):
    """Toma el lock de una tarea para que el técnico actual la responda.

    Reglas:
      - Si la tarea NO está locked, o el lock expiró (>TTL), o yo mismo soy
        el lock-holder → OK, marca con mi user_id y NOW().
      - Si está locked por otro y el lock es reciente → 423 Locked.
      - Admin/supervisor SIEMPRE puede sobrescribir.

    Returns:
      200 OK: {ok, locked_by, locked_at, version, expires_in_seg}
      423 Locked: {ok:false, error, locked_by_nombre, locked_at, expires_in_seg}
      404 si tarea no existe.
    """
    u = getattr(g, "user", None) or {}
    uid = u.get("id")
    if not uid:
        return jsonify({"ok": False, "error": "Sesión inválida"}), 401
    tar = mysql_fetchone(
        "SELECT id, locked_by_user_id, locked_at, version "
        "  FROM mant_visita_tareas WHERE id=%s AND visita_id=%s",
        (tid, vid)
    )
    if not tar:
        return jsonify({"ok": False, "error": "Tarea no encontrada"}), 404

    es_supervisor = _is_supervisor_user()
    holder_uid = tar.get("locked_by_user_id")
    locked_at = tar.get("locked_at")
    ahora = datetime.now()
    lock_vivo = False
    expires_in = 0
    if holder_uid and locked_at:
        try:
            edad_seg = (ahora - locked_at).total_seconds()
            ttl_seg = _TAREA_LOCK_TTL_MIN * 60
            if edad_seg < ttl_seg:
                lock_vivo = True
                expires_in = int(ttl_seg - edad_seg)
        except Exception:
            lock_vivo = False

    # Si está locked por OTRO y el lock está vivo → 423 (salvo supervisor)
    if lock_vivo and holder_uid != uid and not es_supervisor:
        holder = mysql_fetchone(
            "SELECT COALESCE(nombre, username) AS nom FROM app_users WHERE id=%s",
            (holder_uid,)
        )
        nombre = (holder or {}).get("nom") or f"Técnico #{holder_uid}"
        # Minutos relativos desde que tomó el lock
        try:
            min_relat = int((ahora - locked_at).total_seconds() // 60)
        except Exception:
            min_relat = 0
        return jsonify({
            "ok": False,
            "error": (
                f"Esta tarea está siendo respondida por {nombre} "
                f"hace {min_relat} min. Espera o coordínate con él."
            ),
            "error_codigo": "TAREA_BLOQUEADA",
            "locked_by_user_id": holder_uid,
            "locked_by_nombre": nombre,
            "locked_at": str(locked_at)[:16],
            "expires_in_seg": expires_in,
        }), 423

    # Tomar el lock (o renovarlo si yo ya era el holder)
    try:
        mysql_execute(
            "UPDATE mant_visita_tareas "
            "   SET locked_by_user_id=%s, locked_at=NOW() "
            " WHERE id=%s AND visita_id=%s",
            (uid, tid, vid)
        )
        return jsonify({
            "ok": True,
            "locked_by_user_id": uid,
            "locked_by_nombre": current_username() or "Yo",
            "version": int(tar.get("version") or 0),
            "expires_in_seg": _TAREA_LOCK_TTL_MIN * 60,
        })
    except Exception as e:
        print(f"[tarea_lock] err vid={vid} tid={tid}: {e}", flush=True)
        return jsonify({"ok": False, "error": "No se pudo tomar el lock"}), 500


@app.route("/mantenciones/api/visitas/<int:vid>/tareas/<int:tid>/lock", methods=["DELETE"])
@_mant_required
@_tecnico_owns_visita
def mant_visita_tarea_unlock(vid, tid):
    """Libera el lock de una tarea (cuando el técnico cancela o se va sin
    guardar). Solo el dueño del lock, admin o supervisor pueden liberar."""
    u = getattr(g, "user", None) or {}
    uid = u.get("id")
    tar = mysql_fetchone(
        "SELECT locked_by_user_id FROM mant_visita_tareas "
        " WHERE id=%s AND visita_id=%s",
        (tid, vid)
    )
    if not tar:
        return jsonify({"ok": False, "error": "Tarea no encontrada"}), 404
    holder = tar.get("locked_by_user_id")
    if holder and holder != uid and not _is_supervisor_user():
        return jsonify({
            "ok": False,
            "error": "Solo el técnico que tomó el lock o un supervisor puede liberarlo.",
        }), 403
    try:
        mysql_execute(
            "UPDATE mant_visita_tareas "
            "   SET locked_by_user_id=NULL, locked_at=NULL "
            " WHERE id=%s AND visita_id=%s",
            (tid, vid)
        )
        return jsonify({"ok": True})
    except Exception as e:
        print(f"[tarea_unlock] err vid={vid} tid={tid}: {e}", flush=True)
        return jsonify({"ok": False, "error": "No se pudo liberar el lock"}), 500


@app.route("/mantenciones/api/visitas/<int:vid>/tareas/locks", methods=["GET"])
@_mant_required
@_ot_can_view
def mant_visita_tareas_locks(vid):
    """Lista las tareas bloqueadas de una OT con el lock-holder.

    Útil para que el frontend pinte los badges 'siendo gestionada por X'
    sin tener que pedir lock individual. Solo devuelve locks vivos
    (dentro del TTL). El dueño NO ve sus propios locks en la respuesta
    (filtrado en frontend para no mostrar candado en sus tareas).
    """
    rows = mysql_fetchall(
        "SELECT t.id, t.locked_by_user_id, t.locked_at, "
        "       COALESCE(u.nombre, u.username) AS locked_by_nombre, "
        "       t.version "
        "  FROM mant_visita_tareas t "
        "  LEFT JOIN app_users u ON u.id = t.locked_by_user_id "
        " WHERE t.visita_id=%s "
        "   AND t.locked_by_user_id IS NOT NULL "
        "   AND t.locked_at >= (NOW() - INTERVAL %s MINUTE)",
        (vid, _TAREA_LOCK_TTL_MIN)
    ) or []
    out = []
    for r in rows:
        out.append({
            "tarea_id": r["id"],
            "locked_by_user_id": r["locked_by_user_id"],
            "locked_by_nombre": r.get("locked_by_nombre") or f"Técnico #{r['locked_by_user_id']}",
            "locked_at": str(r["locked_at"])[:16] if r.get("locked_at") else None,
            "version": int(r.get("version") or 0),
        })
    return jsonify({"ok": True, "locks": out})


# ═════════════════════════════════════════════════════════════════════
# Seguimiento de ruta en tiempo real
# Técnico envía pings periódicos (cada 30s) cuando está en ruta.
# Admin consume vista /mantenciones/seguimiento con mapa embebido.
# ═════════════════════════════════════════════════════════════════════

@app.route("/mantenciones/api/visitas/<int:vid>/ping-ruta", methods=["POST"])
@_mant_required
@_tecnico_owns_visita
def mant_visita_ping_ruta(vid):
    """Recibe ping del técnico con su lat/lng actual mientras está en
    ruta o ejecutando la OT. Se guarda en mant_ruta_pings (tabla circular,
    limitada a últimos 500 pings por visita para no inflar)."""
    d = request.get_json(silent=True) or {}
    try:
        lat = float(d.get("lat"))
        lng = float(d.get("lng"))
    except (TypeError, ValueError):
        return jsonify({"ok": False, "error": "lat/lng inválido"}), 400
    try:
        speed = float(d.get("speed")) if d.get("speed") is not None else None
    except (TypeError, ValueError):
        speed = None
    try:
        acc = float(d.get("accuracy")) if d.get("accuracy") is not None else None
    except (TypeError, ValueError):
        acc = None
    u = getattr(g, "user", None) or {}
    uid = u.get("id")
    try:
        mysql_execute(
            "INSERT INTO mant_ruta_pings "
            "(visita_id, user_id, lat, lng, velocidad, accuracy) "
            "VALUES (%s, %s, %s, %s, %s, %s)",
            (vid, uid, lat, lng, speed, acc)
        )
        return jsonify({"ok": True})
    except Exception as e:
        print(f"[ping_ruta] err: {e}", flush=True)
        return jsonify({"ok": False, "error": "No se pudo registrar el ping"}), 500


@app.route("/mantenciones/api/seguimiento/activos", methods=["GET"])
@_mant_required
def mant_seguimiento_activos():
    """Lista técnicos con OT en curso (en ruta o ejecutando), con su
    último ping. Para la vista admin de seguimiento en tiempo real.
    Solo para admin/supervisor — los técnicos no pueden ver la
    ubicación de otros técnicos."""
    if not _is_supervisor_user():
        return jsonify({"ok": False, "error": "Solo supervisor"}), 403
    try:
        # OTs hoy/recientes con técnico asignado y en estado activo
        rows = mysql_fetchall(
            "SELECT v.id AS visita_id, v.numero_ot, v.estado, v.titulo, "
            "       v.direccion_visita, v.direccion_lat, v.direccion_lng, "
            "       v.ruta_iniciada_at, v.ruta_app, "
            "       c.razon_social, "
            "       u.id AS user_id, COALESCE(u.nombre, u.username) AS tecnico_nombre, "
            "       u.foto_url AS tecnico_foto, "
            "       (SELECT lat FROM mant_ruta_pings p "
            "         WHERE p.visita_id = v.id ORDER BY p.created_at DESC LIMIT 1) AS last_lat, "
            "       (SELECT lng FROM mant_ruta_pings p "
            "         WHERE p.visita_id = v.id ORDER BY p.created_at DESC LIMIT 1) AS last_lng, "
            "       (SELECT created_at FROM mant_ruta_pings p "
            "         WHERE p.visita_id = v.id ORDER BY p.created_at DESC LIMIT 1) AS last_ping_at "
            "  FROM mant_visitas v "
            "  JOIN mant_clientes c ON c.id = v.cliente_id "
            "  LEFT JOIN app_users u ON u.id = v.tecnico_user_id "
            " WHERE v.estado IN ('programada','en_curso','en_ejecucion') "
            "   AND (v.fecha_programada >= CURDATE() - INTERVAL 1 DAY OR v.ruta_iniciada_at IS NOT NULL) "
            "   AND v.tecnico_user_id IS NOT NULL "
            " ORDER BY v.fecha_programada DESC LIMIT 50",
            ()
        ) or []
        out = []
        for r in rows:
            d = dict(r)
            for k in ("ruta_iniciada_at", "last_ping_at"):
                if d.get(k):
                    d[k] = str(d[k])[:19]
            for k in ("last_lat", "last_lng", "direccion_lat", "direccion_lng"):
                if d.get(k) is not None:
                    d[k] = float(d[k])
            # Estado visual:
            #  - en_ruta: tiene last_ping reciente Y no llegó al destino
            #  - en_sitio: GPS exec o último ping cerca de la dirección destino
            #  - sin_ruta: nunca inició
            if d.get("ruta_iniciada_at") and d.get("last_ping_at"):
                d["estado_visual"] = "en_ruta"
            elif d.get("ruta_iniciada_at"):
                d["estado_visual"] = "iniciado"
            else:
                d["estado_visual"] = "sin_ruta"
            out.append(d)
        return jsonify({"ok": True, "activos": out, "total": len(out)})
    except Exception as e:
        print(f"[seguimiento] err: {e}", flush=True)
        return jsonify({"ok": False, "error": "No se pudo obtener activos"}), 500


@app.route("/mantenciones/seguimiento")
@_mant_required
def mant_seguimiento_vista():
    """Vista admin con mapa de Google embebido + lista de técnicos activos."""
    if not _is_supervisor_user():
        flash("Solo supervisor/admin puede ver el seguimiento.", "warning")
        return redirect(url_for("mant_ots_list"))
    return render_template("mantenciones/seguimiento.html")


# ═════════════════════════════════════════════════════════════════════
# PDF — Reporte completo de OT con firmas y fotos
# ═════════════════════════════════════════════════════════════════════

@app.route("/mantenciones/api/visitas/<int:vid>/pdf")
@_mant_required
@_ot_can_view
def mant_visita_pdf(vid):
    """Genera un PDF completo de la OT con:
    - Header ILUS + número OT + estado
    - Datos cliente + dirección visita
    - Datos programación (fecha, hora, GPS)
    - Lista equipos con foto + datos técnicos + estado + observaciones
    - Tareas agrupadas por (equipo × plantilla) con respuestas
    - Fotos del levantamiento embebidas
    - Firmas técnico + cliente + supervisor

    Usa Playwright (_pw_pdf). Si no está disponible, devuelve 503.
    """
    visita = mysql_fetchone(
        "SELECT v.*, c.razon_social, c.rut AS cli_rut, "
        "       c.direccion AS cli_direccion, c.comuna AS cli_comuna, "
        "       c.contacto_nombre AS cli_contacto, c.contacto_tel AS cli_contacto_tel, "
        "       COALESCE(u.nombre, u.username) AS tecnico_principal, "
        "       u.username AS tecnico_email "
        "  FROM mant_visitas v "
        "  JOIN mant_clientes c ON c.id = v.cliente_id "
        "  LEFT JOIN app_users u ON u.id = v.tecnico_user_id "
        " WHERE v.id=%s",
        (vid,)
    )
    if not visita:
        return jsonify({"ok": False, "error": "OT no encontrada"}), 404
    visita = dict(visita)

    # ── Validación 2026-05-18 (Daniel): el PDF requiere las 3 firmas ──
    # Solo permitimos generar el PDF cuando la OT está cerrada con las
    # 3 firmas presentes (cliente + técnico + supervisor/aprobador).
    # Si falta alguna, devolvemos 409 con el detalle de qué falta.
    estado = (visita.get("estado") or "").lower()
    razones_pdf = []
    if estado != "cerrada":
        razones_pdf.append(
            f"La OT debe estar cerrada para descargar el PDF (estado actual: {estado or '—'})."
        )
    if not visita.get("firma_cliente_url"):
        razones_pdf.append("Falta firma del cliente.")
    if not visita.get("firma_tecnico_url"):
        razones_pdf.append("Falta firma del técnico.")
    if not visita.get("firma_supervisor_url"):
        razones_pdf.append("Falta firma del aprobador.")
    if razones_pdf:
        # Si es petición browser (no AJAX), redirigir con flash a la OT
        is_ajax = (
            request.headers.get("X-Requested-With") == "XMLHttpRequest"
            or (request.headers.get("Accept") or "").startswith("application/json")
        )
        if not is_ajax:
            flash(
                "PDF disponible solo cuando la OT está cerrada con las 3 firmas. "
                + " ".join(razones_pdf),
                "warning",
            )
            return redirect(url_for("mant_ot_ejecutar", vid=vid))
        return jsonify({
            "ok": False,
            "error": "Faltan requisitos para generar el PDF",
            "razones": razones_pdf,
        }), 409

    # Equipos
    equipos = mysql_fetchall(
        "SELECT DISTINCT m.id, m.nombre, m.sku, m.serie, m.foto_url, "
        "       m.marca, m.modelo, m.anio_fabricacion, m.voltaje, "
        "       m.ubicacion_sala, m.estado_capturado, m.tiene_dano, "
        "       m.observaciones "
        "  FROM mant_visita_tareas vt "
        "  JOIN mant_maquinas m ON m.id = vt.maquina_id "
        " WHERE vt.visita_id=%s AND vt.maquina_id IS NOT NULL "
        " ORDER BY m.nombre",
        (vid,)
    ) or []
    equipos = [dict(e) for e in equipos]

    # Tareas + plantilla
    tareas = mysql_fetchall(
        "SELECT t.id, t.maquina_id, t.plantilla_id, t.orden, t.titulo, "
        "       t.tipo, t.tipo_respuesta, t.obligatoria, t.requiere_foto, "
        "       t.unidad, t.completada, t.completada_at, t.observaciones, "
        "       t.valor_json, "
        "       COALESCE(p.nombre, 'Gestión de tareas') AS plantilla_nombre "
        "  FROM mant_visita_tareas t "
        "  LEFT JOIN mant_tarea_plantillas p ON p.id = t.plantilla_id "
        " WHERE t.visita_id=%s "
        " ORDER BY t.maquina_id, t.plantilla_id, t.orden, t.id",
        (vid,)
    ) or []
    tareas = [dict(t) for t in tareas]
    for t in tareas:
        if t.get("valor_json"):
            try: t["valor"] = json.loads(t["valor_json"])
            except Exception: t["valor"] = None

    # Agrupar por (mid, pid)
    grupos = []
    grupo_idx = {}
    for t in tareas:
        mid = t.get("maquina_id") or 0
        pid = t.get("plantilla_id") or 0
        key = (mid, pid)
        if key not in grupo_idx:
            grupo_idx[key] = len(grupos)
            grupos.append({
                "maquina_id": mid, "plantilla_id": pid,
                "plantilla_nombre": t.get("plantilla_nombre") or "Tareas manuales",
                "tareas": [],
            })
        grupos[grupo_idx[key]]["tareas"].append(t)
    eq_idx = {e["id"]: e for e in equipos}

    # Fotos (PDF) — usar columna real `tomada_at`
    fotos = mysql_fetchall(
        "SELECT id, tarea_id, archivo_path, cloudinary_url, tipo_foto, tomada_at "
        "  FROM mant_visita_fotos WHERE visita_id=%s ORDER BY tomada_at",
        (vid,)
    ) or []
    fotos_dict = []
    for f in fotos:
        d = dict(f)
        url = d.get("cloudinary_url") or (
            f"/static/uploads/mantenciones/{d['archivo_path']}"
            if d.get("archivo_path") else ""
        )
        if not url:
            continue
        d["url"] = url
        fotos_dict.append(d)

    # Logo ILUS — usa el base64 pre-encodeado si existe
    logo_b64 = ""
    try:
        logo_path = os.path.join(app.static_folder, "logo_pdf.txt")
        if os.path.exists(logo_path):
            with open(logo_path, "r", encoding="utf-8") as f:
                logo_b64 = f.read().strip()
    except Exception: pass

    # Render HTML
    html = render_template(
        "mantenciones/ot_pdf.html",
        visita=visita,
        firmante_cliente=_ot_firmante_cliente(vid),
        equipos=equipos,
        eq_idx=eq_idx,
        grupos=grupos,
        fotos=fotos_dict,
        logo_b64=logo_b64,
        generated_at=_now_chile_str('%d/%m/%Y %H:%M'),
    )

    # PDF
    try:
        pdf_bytes = _pw_pdf(
            html, page_format="A4", margin={
                "top": "15mm", "bottom": "15mm",
                "left": "12mm", "right": "12mm",
            },
            wait_fn="document.images.length === 0 || [...document.images].every(i=>i.complete)",
        )
    except PDFEngineUnavailable:
        return jsonify({
            "ok": False,
            "error": "Generador PDF no disponible. Avisá al admin.",
        }), 503
    except Exception as e:
        print(f"[ot_pdf] err: {e}", flush=True)
        return jsonify({"ok": False, "error": "No se pudo generar el PDF"}), 500

    fname = f"OT_{visita.get('numero_ot') or vid}.pdf"
    return send_file(
        io.BytesIO(pdf_bytes), mimetype="application/pdf",
        as_attachment=False, download_name=fname,
    )


# ═════════════════════════════════════════════════════════════════════
# PDF DINÁMICO — Reporte HTML imprimible de OT cerrada
# ─────────────────────────────────────────────────────────────────────
# Endpoint dependency-free: renderiza un HTML+CSS @media print que el
# usuario imprime con "Guardar como PDF" desde el navegador. No requiere
# Playwright / wkhtmltopdf / WeasyPrint — cero dependencias nativas.
#
# REGLAS de negocio (pedido Daniel 2026-05-17):
#   - Solo se genera si la OT está estado='cerrada'.
#   - Las 3 firmas deben existir:
#       * firma_cliente_url       (cliente que recibe la conformidad)
#       * firma_tecnico_url       (técnico ejecutor)
#       * firma_supervisor_url    (responsable/supervisor que aprobó)
#   - El "Validado Por" (firma supervisor) es DINÁMICO: se busca por
#     firma_supervisor_user_id en app_users y se muestra el nombre real
#     de quien aprobó la OT (no hardcodeado a Aarón ni nadie).
#   - Si alguna firma falta → redirige a la OT con flash error y mensaje
#     claro de qué le falta.
# ═════════════════════════════════════════════════════════════════════

@app.route("/mantenciones/ot/<int:vid>/pdf")
@_mant_required
@_ot_can_view
def mant_ot_pdf_render(vid):
    """Renderiza el HTML imprimible de la OT cerrada (Guardar como PDF).

    Query params:
      - ?print=1 → dispara window.print() automáticamente al cargar.
    """
    visita = mysql_fetchone(
        "SELECT v.*, c.razon_social, c.rut AS cli_rut, "
        "       c.direccion AS cli_direccion, c.comuna AS cli_comuna, "
        "       c.contacto_nombre AS cli_contacto, "
        "       c.contacto_tel AS cli_contacto_tel, "
        "       c.contacto_email AS cli_email, "
        "       COALESCE(u.nombre, u.username) AS tecnico_principal, "
        "       u.username AS tecnico_email, "
        "       COALESCE(us.nombre, us.username) AS responsable_nombre, "
        "       us.username AS responsable_email "
        "  FROM mant_visitas v "
        "  JOIN mant_clientes c ON c.id = v.cliente_id "
        "  LEFT JOIN app_users u  ON u.id  = v.tecnico_user_id "
        "  LEFT JOIN app_users us ON us.id = v.firma_supervisor_user_id "
        " WHERE v.id=%s",
        (vid,)
    )
    if not visita:
        flash("OT no encontrada.", "danger")
        return redirect(url_for("mant_index"))
    visita = dict(visita)

    # ── Validación: OT cerrada con las 3 firmas ──────────────────────
    razones = []
    estado = (visita.get("estado") or "").lower()
    if estado != "cerrada":
        razones.append(f"La OT debe estar en estado 'cerrada' (actual: {estado or '—'}).")
    if not visita.get("firma_cliente_url"):
        razones.append("Falta firma del cliente.")
    if not visita.get("firma_tecnico_url"):
        razones.append("Falta firma del técnico.")
    if not visita.get("firma_supervisor_url"):
        razones.append("Falta firma del responsable/supervisor.")

    if razones:
        flash(
            "PDF disponible solo cuando la OT está cerrada con las 3 firmas. "
            + " ".join(razones),
            "warning"
        )
        return redirect(url_for("mant_ot_ejecutar", vid=vid))

    # ── Equipos (distinct via tareas) ────────────────────────────────
    equipos = mysql_fetchall(
        "SELECT DISTINCT m.id, m.nombre, m.sku, m.serie, m.foto_url, "
        "       m.marca, m.modelo, m.anio_fabricacion, m.voltaje, "
        "       m.ubicacion_sala, m.estado_capturado, m.observaciones "
        "  FROM mant_visita_tareas vt "
        "  JOIN mant_maquinas m ON m.id = vt.maquina_id "
        " WHERE vt.visita_id=%s AND vt.maquina_id IS NOT NULL "
        "   AND COALESCE(m.estado,'activo') != 'baja' "
        " ORDER BY m.nombre",
        (vid,)
    ) or []
    equipos = [dict(e) for e in equipos]

    # ── Técnicos extras (legacy mant_visita_tecnicos) ────────────────
    tecnicos_extra_rows = mysql_fetchall(
        "SELECT COALESCE(u.nombre, u.username, t.nombre) AS nombre "
        "  FROM mant_visita_tecnicos vt "
        "  LEFT JOIN mant_tecnicos t ON t.id = vt.tecnico_id "
        "  LEFT JOIN app_users u    ON u.id = vt.tecnico_user_id "
        " WHERE vt.visita_id=%s "
        "   AND (u.id IS NULL OR u.id != %s)",
        (vid, visita.get("tecnico_user_id") or 0)
    ) or []
    tecnicos_extra = [dict(t) for t in tecnicos_extra_rows if t.get("nombre")]

    # ── Tareas (checklist técnico detallado) ─────────────────────────
    tareas = mysql_fetchall(
        "SELECT t.id, t.maquina_id, t.plantilla_id, t.orden, t.titulo, "
        "       t.tipo, t.tipo_respuesta, t.obligatoria, t.requiere_foto, "
        "       t.unidad, t.rango_min, t.rango_max, "
        "       t.completada, t.completada_at, t.observaciones, "
        "       t.valor_texto, t.valor_numero, t.valor_sino, "
        "       t.valor_verificacion, t.valor_lista, t.valor_fecha_hora, "
        "       t.valor_gps_lat, t.valor_gps_lng, "
        "       m.nombre AS maquina_nombre, "
        "       (SELECT COUNT(*) FROM mant_visita_fotos f WHERE f.tarea_id = t.id) AS n_fotos "
        "  FROM mant_visita_tareas t "
        "  LEFT JOIN mant_maquinas m ON m.id = t.maquina_id "
        " WHERE t.visita_id=%s "
        " ORDER BY t.maquina_id, t.plantilla_id, t.orden, t.id",
        (vid,)
    ) or []
    tareas = [dict(t) for t in tareas]

    # ── Fotos (con URL resuelta) ─────────────────────────────────────
    fotos_raw = mysql_fetchall(
        "SELECT id, tarea_id, maquina_id, archivo_path, cloudinary_url, "
        "       tipo_foto, tomada_at "
        "  FROM mant_visita_fotos WHERE visita_id=%s ORDER BY tomada_at",
        (vid,)
    ) or []
    fotos = []
    for f in fotos_raw:
        d = dict(f)
        url = d.get("cloudinary_url") or (
            f"/static/uploads/mantenciones/{d['archivo_path']}"
            if d.get("archivo_path") else ""
        )
        if not url:
            continue
        d["url"] = url
        fotos.append(d)

    # ── Index fotos por equipo (primeras 3 por máquina) ──────────────
    eq_fotos_idx = {}
    for f in fotos:
        mid = f.get("maquina_id")
        if not mid:
            continue
        eq_fotos_idx.setdefault(mid, []).append(f)

    # ── Fotos generales (sin máquina asociada o tipo=general) ────────
    fotos_generales = [
        f for f in fotos
        if not f.get("maquina_id") or (f.get("tipo_foto") or "") == "general"
    ]
    if not fotos_generales:
        fotos_generales = fotos  # fallback

    # ── Checklist resumen por equipo (primeras 5 tareas) ─────────────
    eq_check_resumen = {}
    for t in tareas:
        mid = t.get("maquina_id")
        if not mid:
            continue
        eq_check_resumen.setdefault(mid, []).append({
            "titulo": t.get("titulo") or "",
            "ok": bool(t.get("completada")),
        })

    # ── Tareas formateadas para tabla detallada ──────────────────────
    def _fmt_resultado(t):
        """Devuelve (texto, clase) para la pill de resultado."""
        tr = (t.get("tipo_respuesta") or "check").lower()
        if tr == "verificacion":
            v = (t.get("valor_verificacion") or "").lower()
            if v == "aprobado": return ("OK", "ok")
            if v == "alerta":   return ("ALERTA", "warn")
            if v == "falla":    return ("FALLA", "err")
            return ("—", "ok")
        if tr == "sino":
            v = (t.get("valor_sino") or "").lower()
            if v == "si":  return ("SÍ", "ok")
            if v == "no":  return ("NO", "err")
            if v == "na":  return ("N/A", "txt")
            return ("—", "txt")
        if tr == "numero":
            num = t.get("valor_numero")
            if num is None: return ("—", "txt")
            try:
                num_f = float(num)
                txt = f"{num_f:g}"
            except Exception:
                txt = str(num)
            unidad = t.get("unidad") or ""
            return (f"{txt} {unidad}".strip(), "ok")
        if tr == "lista":
            return ((t.get("valor_lista") or "—"), "txt")
        if tr == "fecha_hora":
            v = t.get("valor_fecha_hora")
            return ((v.strftime('%d/%m %H:%M') if v else "—"), "txt")
        if tr == "gps":
            la = t.get("valor_gps_lat"); ln = t.get("valor_gps_lng")
            if la is None or ln is None: return ("—", "txt")
            try:
                return (f"{float(la):.4f}, {float(ln):.4f}", "ok")
            except Exception:
                return ("GPS OK", "ok")
        if tr == "texto":
            v = (t.get("valor_texto") or "").strip()
            return ((v[:18] + "…" if len(v) > 18 else v) or "—", "txt")
        # check / foto / default
        return (("OK" if t.get("completada") else "—"), ("ok" if t.get("completada") else "txt"))

    # Cliente comuna para "Ubicación"
    cli_ubic_short = (visita.get("cli_comuna") or "—").strip()

    tareas_chk = []
    for t in tareas:
        res_txt, res_cls = _fmt_resultado(t)
        ca = t.get("completada_at")
        try:
            ca_str = ca.strftime('%Y-%m-%d %H:%M') if ca else ""
        except Exception:
            ca_str = str(ca) if ca else ""
        tareas_chk.append({
            "id":               t.get("id"),
            "titulo":           t.get("titulo") or "",
            "tipo_respuesta":   t.get("tipo_respuesta") or "check",
            "resultado_str":    res_txt,
            "resultado_clase":  res_cls,
            "tiene_foto":       (t.get("n_fotos") or 0) > 0,
            "completada_at_str": ca_str,
            "ubicacion_str":    cli_ubic_short,
            "maquina_nombre":   t.get("maquina_nombre") or "",
        })

    # ── Paginar equipos: 2 por página (cards grandes) ────────────────
    # Página 1: 2 equipos (los primeros). Páginas siguientes: 3 c/u.
    paginas_equipos = []
    if equipos:
        if len(equipos) <= 2:
            paginas_equipos = [equipos]
        else:
            paginas_equipos.append(equipos[:2])
            resto = equipos[2:]
            while resto:
                paginas_equipos.append(resto[:3])
                resto = resto[3:]
    else:
        paginas_equipos = [[]]

    # ── Logo ILUS (base64 pre-encoded si existe) ─────────────────────
    logo_b64 = ""
    try:
        logo_path = os.path.join(app.static_folder, "logo_pdf.txt")
        if os.path.exists(logo_path):
            with open(logo_path, "r", encoding="utf-8") as f:
                logo_b64 = f.read().strip()
    except Exception:
        pass

    return render_template(
        "mantenciones/ot_pdf.html",
        visita=visita,
        firmante_cliente=_ot_firmante_cliente(vid),
        equipos=equipos,
        tecnicos_extra=tecnicos_extra,
        tareas=tareas,
        tareas_chk=tareas_chk,
        fotos=fotos,
        fotos_generales=fotos_generales,
        eq_fotos_idx=eq_fotos_idx,
        eq_check_resumen=eq_check_resumen,
        paginas_equipos=paginas_equipos,
        logo_b64=logo_b64,
        generated_at=_now_chile_str('%d/%m/%Y %H:%M'),
    )


# ═════════════════════════════════════════════════════════════════════
# OT — TAREAS DENTRO DE UNA VISITA
# Checklist que el técnico ejecuta paso a paso. Cada tarea puede estar
# asociada a una máquina específica (mant_maquinas) para trazabilidad.
# ═════════════════════════════════════════════════════════════════════

@app.route("/mantenciones/api/visitas/<int:vid>/tareas", methods=["GET"])
@_mant_required
@_ot_can_view
def mant_visita_tareas_get(vid):
    """Lista las tareas de una OT con su estado y métricas de cronómetro."""
    rows = mysql_fetchall(
        "SELECT t.id, t.orden, t.titulo, t.descripcion, t.tipo, t.cantidad, "
        "       t.completada, t.completada_at, t.completada_por, t.observaciones, "
        "       t.maquina_id, m.nombre AS maquina_nombre, m.serie AS maquina_serie, "
        "       t.estado_trabajo, t.iniciado_at, t.duracion_min, "
        "       t.duracion_estimada_min, t.pausada_acumulado_seg "
        "  FROM mant_visita_tareas t "
        "  LEFT JOIN mant_maquinas m ON m.id=t.maquina_id "
        " WHERE t.visita_id=%s ORDER BY t.orden ASC, t.id ASC",
        (vid,)
    ) or []
    result = []
    for r in rows:
        d = dict(r)
        # Si está en curso, calcular segundos abiertos para UI live
        if d.get("estado_trabajo") == "en_curso":
            d["segmento_abierto_seg"] = _crono_seg_desde_ultimo(d["id"])
            d["duracion_total_seg"]   = _crono_total_seg(d["id"])
        # Serializar fechas
        if d.get("iniciado_at") is not None:
            d["iniciado_at"] = str(d["iniciado_at"])
        if d.get("completada_at") is not None:
            d["completada_at"] = str(d["completada_at"])
        result.append(d)
    return jsonify(result)


@app.route("/mantenciones/api/visitas/<int:vid>/tareas/nueva", methods=["POST"])
@_mant_required
@_ot_can_configurar
def mant_visita_tarea_nueva(vid):
    """Crea una tarea dentro de la OT. Acepta JSON o form-data."""
    d = request.get_json(silent=True) or request.form
    titulo = (d.get("titulo") or "").strip()[:300]
    if not titulo:
        return jsonify({"ok": False, "error": "Título requerido"}), 400
    descripcion = (d.get("descripcion") or "").strip()
    tipo = (d.get("tipo") or "otro").strip().lower()
    if tipo not in ("inspeccion", "cambio", "reparacion", "limpieza",
                    "levantamiento", "instalacion", "garantia", "otro"):
        tipo = "otro"
    maquina_id = d.get("maquina_id")
    try:
        maquina_id = int(maquina_id) if maquina_id else None
    except (TypeError, ValueError):
        maquina_id = None
    cantidad = int(d.get("cantidad") or 1)
    # Determinar orden = max + 1
    row = mysql_fetchone(
        "SELECT COALESCE(MAX(orden),0)+1 AS nx FROM mant_visita_tareas WHERE visita_id=%s",
        (vid,)
    )
    orden = (row or {}).get("nx", 1)
    nid = mysql_execute(
        "INSERT INTO mant_visita_tareas "
        "(visita_id, orden, titulo, descripcion, tipo, maquina_id, cantidad, created_by) "
        "VALUES (%s,%s,%s,%s,%s,%s,%s,%s)",
        (vid, orden, titulo, descripcion, tipo, maquina_id, cantidad, current_username())
    )
    try:
        mysql_execute(
            "INSERT INTO mant_logs (entidad, entidad_id, accion, detalle, usuario) "
            "VALUES ('visita', %s, 'tarea_agregada', %s, %s)",
            (vid, f"Tarea: {titulo}", current_username())
        )
    except Exception:
        pass
    return jsonify({"ok": True, "id": nid, "orden": orden})


@app.route("/mantenciones/api/visitas/<int:vid>/tareas/<int:tid>", methods=["POST", "PATCH", "DELETE"])
@_mant_required
@_tecnico_owns_visita
def mant_visita_tarea_update(vid, tid):
    """Actualiza, completa o elimina una tarea."""
    if request.method == "DELETE":
        mysql_execute("DELETE FROM mant_visita_tareas WHERE id=%s AND visita_id=%s", (tid, vid))
        return jsonify({"ok": True, "deleted": True})

    d = request.get_json(silent=True) or request.form
    action = (d.get("action") or "").strip().lower()
    user = current_username()

    if action == "toggle":
        # Cambiar estado completada
        row = mysql_fetchone(
            "SELECT completada, version FROM mant_visita_tareas "
            " WHERE id=%s AND visita_id=%s",
            (tid, vid)
        )
        if not row:
            return jsonify({"ok": False, "error": "Tarea no encontrada"}), 404
        new_state = 0 if row["completada"] else 1
        mysql_execute(
            "UPDATE mant_visita_tareas "
            "   SET completada=%s, "
            "       completada_at=%s, "
            "       completada_por=%s, "
            "       locked_by_user_id=NULL, "
            "       locked_at=NULL, "
            "       version=COALESCE(version,0)+1 "
            " WHERE id=%s AND visita_id=%s",
            (
                new_state,
                datetime.now() if new_state else None,
                user if new_state else None,
                tid, vid
            )
        )
        try:
            mysql_execute(
                "INSERT INTO mant_logs (entidad, entidad_id, accion, detalle, usuario) "
                "VALUES ('visita', %s, %s, %s, %s)",
                (vid,
                 "tarea_completada" if new_state else "tarea_reabierta",
                 f"Tarea ID {tid}",
                 user)
            )
        except Exception:
            pass
        return jsonify({"ok": True, "completada": bool(new_state),
                        "version": int(row.get("version") or 0) + 1})

    # Update genérico
    fields = []
    vals = []
    for f in ("titulo", "descripcion", "tipo", "observaciones"):
        if f in d:
            fields.append(f"{f}=%s")
            vals.append((d.get(f) or "").strip()[:500])
    for f in ("cantidad", "orden", "maquina_id"):
        if f in d:
            try:
                fields.append(f"{f}=%s")
                vals.append(int(d.get(f)) if d.get(f) else None)
            except (TypeError, ValueError):
                continue
    # Soporte para `completada` directo (modo técnico — vista ejecutar):
    # se setea junto con completada_at y completada_por.
    if "completada" in d:
        try:
            new_c = 1 if (int(d.get("completada") or 0)) else 0
        except Exception:
            new_c = 1 if d.get("completada") else 0
        fields.append("completada=%s"); vals.append(new_c)
        fields.append("completada_at=%s"); vals.append(datetime.now() if new_c else None)
        fields.append("completada_por=%s"); vals.append(user if new_c else None)
    if not fields:
        return jsonify({"ok": False, "error": "Nada para actualizar"}), 400
    # Bump version + libera lock (concurrencia multitécnico)
    fields.append("version=COALESCE(version,0)+1")
    fields.append("locked_by_user_id=NULL")
    fields.append("locked_at=NULL")
    vals.extend([tid, vid])
    mysql_execute(
        f"UPDATE mant_visita_tareas SET {', '.join(fields)} WHERE id=%s AND visita_id=%s",
        tuple(vals)
    )
    return jsonify({"ok": True})


# ═════════════════════════════════════════════════════════════════════
# OT — PROTOCOLOS RÁPIDOS (generadores de checklist 1-click)
# Crean en lote N tareas estándar sobre una OT existente.
#
# Protocolos disponibles:
#   · levantamiento     → 1 tarea por máquina del cliente (fotos + serie)
#   · cambio_garantia   → 1 tarea cambio por máquina seleccionada
#   · inspeccion_pm     → checklist estándar preventivo (8 ítems)
#   · instalacion_pm    → checklist de instalación nueva
# ═════════════════════════════════════════════════════════════════════

@app.route("/mantenciones/api/visitas/<int:vid>/protocolo/<protocolo>", methods=["POST"])
@_mant_required
@_ot_can_configurar
def mant_visita_protocolo(vid, protocolo):
    """Aplica un protocolo a la OT: genera N tareas estándar.

    POST JSON:
      maquinas_ids: [int]  (opcional, p/ cambio_garantia restringe a IDs específicos)
      reset:        bool   (default false; si true borra tareas existentes antes)
    """
    visita = mysql_fetchone(
        "SELECT id, cliente_id, tipo FROM mant_visitas WHERE id=%s", (vid,)
    )
    if not visita:
        return jsonify({"ok": False, "error": "OT no encontrada"}), 404

    visita = dict(visita)
    cliente_id = visita["cliente_id"]
    d = request.get_json(silent=True) or {}
    reset = bool(d.get("reset"))
    maquinas_ids = d.get("maquinas_ids") or []
    user = current_username()

    # Validar protocolo
    if protocolo not in ("levantamiento", "cambio_garantia", "inspeccion_pm", "instalacion_pm"):
        return jsonify({"ok": False, "error": "Protocolo desconocido"}), 400

    # Obtener máquinas del cliente
    if maquinas_ids:
        placeholders = ",".join(["%s"] * len(maquinas_ids))
        maquinas = mysql_fetchall(
            f"SELECT id, nombre, serie, sku FROM mant_maquinas "
            f"WHERE cliente_id=%s AND id IN ({placeholders})",
            tuple([cliente_id] + [int(x) for x in maquinas_ids])
        ) or []
    else:
        maquinas = mysql_fetchall(
            "SELECT id, nombre, serie, sku FROM mant_maquinas "
            "WHERE cliente_id=%s ORDER BY nombre",
            (cliente_id,)
        ) or []
    maquinas = [dict(m) for m in maquinas]

    # Si reset, borrar tareas existentes
    if reset:
        mysql_execute("DELETE FROM mant_visita_tareas WHERE visita_id=%s", (vid,))

    # Orden inicial = max(orden) + 1
    last_orden = mysql_fetchone(
        "SELECT COALESCE(MAX(orden),0) AS n FROM mant_visita_tareas WHERE visita_id=%s",
        (vid,)
    ) or {"n": 0}
    orden_base = int(last_orden.get("n", 0)) + 1

    creadas = 0

    # ─── PROTOCOLO 1: LEVANTAMIENTO FOTOGRÁFICO COMPLETO ──────────────
    # Para cada máquina del cliente: 1 tarea con checklist visual
    # ──────────────────────────────────────────────────────────────────
    if protocolo == "levantamiento":
        if not maquinas:
            return jsonify({
                "ok": False,
                "error": "El cliente no tiene máquinas registradas. Agrega máquinas desde la ficha del cliente."
            }), 400
        for i, m in enumerate(maquinas):
            mant_titulo = f"📸 Levantamiento: {m['nombre'] or 'Máquina'}"
            if m.get("serie"):
                mant_titulo += f" (S/N: {m['serie']})"
            descripcion = (
                "Protocolo de levantamiento fotográfico:\n"
                "  1) Foto general del equipo (frontal y lateral)\n"
                "  2) Foto de la placa / número de serie legible\n"
                "  3) Foto de la marca y modelo\n"
                "  4) Detalle de cualquier daño visible (si aplica)\n"
                "  5) Foto del equipo instalado / ubicado en sala"
            )
            mysql_execute(
                "INSERT INTO mant_visita_tareas "
                "(visita_id, orden, titulo, descripcion, tipo, maquina_id, cantidad, created_by) "
                "VALUES (%s,%s,%s,%s,'levantamiento',%s,1,%s)",
                (vid, orden_base + i, mant_titulo[:300], descripcion, m["id"], user)
            )
            creadas += 1

    # ─── PROTOCOLO 2: CAMBIO POR GARANTÍA ─────────────────────────────
    # Para cada máquina seleccionada: 1 tarea de cambio con checklist
    # ──────────────────────────────────────────────────────────────────
    elif protocolo == "cambio_garantia":
        if not maquinas:
            return jsonify({
                "ok": False,
                "error": "Selecciona al menos una máquina a cambiar."
            }), 400
        for i, m in enumerate(maquinas):
            mant_titulo = f"🔄 Cambio por garantía: {m['nombre'] or 'Máquina'}"
            if m.get("serie"):
                mant_titulo += f" (S/N saliente: {m['serie']})"
            descripcion = (
                "Protocolo de cambio por garantía:\n"
                "  1) Foto del equipo SALIENTE antes del retiro\n"
                "  2) Foto de la placa / N° serie del equipo saliente\n"
                "  3) Foto de la falla / motivo de garantía (si aplica)\n"
                "  4) Foto del equipo NUEVO (entrante) con su serie\n"
                "  5) Foto del equipo instalado y funcionando\n"
                "  6) Registrar N° de serie nuevo en el sistema (campo abajo)\n"
                "  7) Firma / conformidad del cliente"
            )
            mysql_execute(
                "INSERT INTO mant_visita_tareas "
                "(visita_id, orden, titulo, descripcion, tipo, maquina_id, cantidad, created_by) "
                "VALUES (%s,%s,%s,%s,'cambio',%s,1,%s)",
                (vid, orden_base + i, mant_titulo[:300], descripcion, m["id"], user)
            )
            creadas += 1

    # ─── PROTOCOLO 3: INSPECCIÓN PREVENTIVA ───────────────────────────
    elif protocolo == "inspeccion_pm":
        items = [
            ("inspeccion", "🔍 Inspección visual general del equipo", None),
            ("limpieza",   "🧹 Limpieza profunda de componentes", None),
            ("inspeccion", "🔋 Verificar tensión y voltaje", None),
            ("inspeccion", "⚙️ Lubricación de partes móviles", None),
            ("inspeccion", "🔌 Verificar conexiones eléctricas y aislantes", None),
            ("inspeccion", "📊 Test de funcionamiento bajo carga", None),
            ("inspeccion", "🩺 Diagnóstico de software / firmware (si aplica)", None),
            ("inspeccion", "📋 Registrar lecturas y observaciones finales", None),
        ]
        for i, (tipo, titulo, mid) in enumerate(items):
            mysql_execute(
                "INSERT INTO mant_visita_tareas "
                "(visita_id, orden, titulo, tipo, maquina_id, cantidad, created_by) "
                "VALUES (%s,%s,%s,%s,%s,1,%s)",
                (vid, orden_base + i, titulo[:300], tipo, mid, user)
            )
            creadas += 1

    # ─── PROTOCOLO 4: INSTALACIÓN NUEVA ───────────────────────────────
    elif protocolo == "instalacion_pm":
        items = [
            "📦 Verificar embalaje y accesorios completos",
            "🧰 Armado / ensamble del equipo",
            "📍 Ubicación y nivelación en sala",
            "🔌 Conexión eléctrica y verificación de toma",
            "⚡ Encendido inicial y test de funciones básicas",
            "📊 Configuración de software / firmware",
            "👤 Capacitación al cliente sobre uso básico",
            "📸 Foto del equipo instalado funcionando",
            "✍️ Firma de conformidad del cliente",
        ]
        for i, t in enumerate(items):
            mysql_execute(
                "INSERT INTO mant_visita_tareas "
                "(visita_id, orden, titulo, tipo, cantidad, created_by) "
                "VALUES (%s,%s,%s,'instalacion',1,%s)",
                (vid, orden_base + i, t[:300], user)
            )
            creadas += 1

    # Log de auditoría
    try:
        mysql_execute(
            "INSERT INTO mant_logs (entidad, entidad_id, accion, detalle, usuario) "
            "VALUES ('visita', %s, %s, %s, %s)",
            (vid, "protocolo_aplicado", f"{protocolo} → {creadas} tareas", user)
        )
    except Exception:
        pass

    return jsonify({
        "ok": True,
        "protocolo": protocolo,
        "tareas_creadas": creadas,
        "maquinas_afectadas": len(maquinas) if protocolo in ("levantamiento", "cambio_garantia") else 0,
    })


# ═════════════════════════════════════════════════════════════════════
# OT — FOTOS DE LA VISITA (galería con multi-upload)
# ═════════════════════════════════════════════════════════════════════

MANT_FOTOS_DIR = os.path.join(UPLOADS_BASE, "mantenciones")
os.makedirs(MANT_FOTOS_DIR, exist_ok=True)


@app.route("/mantenciones/api/visitas/<int:vid>/fotos", methods=["GET"])
@_mant_required
@_ot_can_view
def mant_visita_fotos_get(vid):
    """Lista las fotos de una OT."""
    rows = mysql_fetchall(
        "SELECT id, archivo_path, archivo_nombre, tipo_foto, descripcion, "
        "       tarea_id, maquina_id, tomada_por, tomada_at, file_size_kb "
        "  FROM mant_visita_fotos "
        " WHERE visita_id=%s ORDER BY tomada_at DESC, id DESC",
        (vid,)
    ) or []
    out = []
    for r in rows:
        rd = dict(r)
        # tomada_at puede ser datetime → string ISO
        if rd.get("tomada_at"):
            rd["tomada_at_iso"] = rd["tomada_at"].isoformat() if hasattr(rd["tomada_at"], "isoformat") else str(rd["tomada_at"])
        out.append(rd)
    return jsonify(out)


@app.route("/mantenciones/api/visitas/<int:vid>/fotos/subir", methods=["POST"])
@_mant_required
@_tecnico_owns_visita
def mant_visita_fotos_subir(vid):
    """Sube una o varias fotos a la OT.

    PERSISTENCIA ROBUSTA (2026-05-17): primero intenta Cloudinary
    (persistente, sobrevive deploys) y cae a filesystem solo si
    Cloudinary falla. Soporta nombres de campo `fotos` (plural, legacy)
    y `foto` (singular, frontend nuevo) — ambos funcionan.
    Devuelve la URL del primer archivo como `url` para que el frontend
    la muestre inline.
    """
    import traceback as _tb  # logging detallado para Railway
    # Aceptar AMBOS nombres de campo (foto / fotos / imagenes) para que
    # el frontend no se rompa según cómo arme el FormData.
    files = (request.files.getlist("foto")
             or request.files.getlist("fotos")
             or request.files.getlist("imagenes"))
    if not files or all(not f.filename for f in files):
        print(f"[fotos_subir vid={vid}] SIN ARCHIVOS — form keys: {list(request.form.keys())} "
              f"files keys: {list(request.files.keys())}", flush=True)
        return jsonify({"ok": False, "error": "No se envió ningún archivo (campo esperado: foto o fotos)"}), 400

    tipo_foto    = (request.form.get("tipo_foto") or "general").strip().lower()
    if tipo_foto not in ("antes", "durante", "despues", "serie", "falla",
                          "reparacion", "general", "levantamiento"):
        tipo_foto = "general"
    descripcion  = (request.form.get("descripcion") or "").strip()[:500]
    tarea_id     = request.form.get("tarea_id")
    maquina_id   = request.form.get("maquina_id")
    try:
        tarea_id = int(tarea_id) if tarea_id else None
    except (TypeError, ValueError):
        tarea_id = None
    try:
        maquina_id = int(maquina_id) if maquina_id else None
    except (TypeError, ValueError):
        maquina_id = None

    # Log entrada — útil en Railway logs
    print(f"[fotos_subir vid={vid}] iniciando: {len(files)} archivo(s), "
          f"tarea_id={tarea_id} maquina_id={maquina_id} tipo={tipo_foto} "
          f"primer_nombre={files[0].filename if files else 'N/A'} "
          f"mime={files[0].mimetype if files else 'N/A'}", flush=True)

    saved = 0
    errors = []
    first_url = None  # devolvemos al frontend para mostrar inline
    user = current_username()
    # ¿Cloudinary disponible?
    cloud_ok = False
    try:
        import cloudinary, cloudinary.uploader  # noqa
        cloud_ok = bool(CLOUDINARY_CONFIG.get("cloud_name") and CLOUDINARY_CONFIG.get("api_key"))
    except ImportError:
        cloud_ok = False
    if not cloud_ok:
        print(f"[fotos_subir vid={vid}] AVISO: Cloudinary no disponible "
              f"(cloud_name={bool(CLOUDINARY_CONFIG.get('cloud_name'))} "
              f"api_key={bool(CLOUDINARY_CONFIG.get('api_key'))}). "
              f"Solo filesystem (NO persiste entre deploys).", flush=True)

    for i, f in enumerate(files):
        if not f or not f.filename:
            continue
        ext, err = _validate_uploaded_image(f, label=f.filename)
        if err:
            print(f"[fotos_subir vid={vid}] validación FAIL: {err}", flush=True)
            errors.append(err)
            continue
        cld_url = None
        archivo_path = None
        size_kb = 0

        # ── INTENTO 1: Cloudinary (persistente) ──────────────────────
        if cloud_ok:
            try:
                import cloudinary.uploader
                f.stream.seek(0)
                result = cloudinary.uploader.upload(
                    f,
                    folder=f"ilus/visitas/v{vid}",
                    public_id=f"v{vid}_t{tarea_id or 0}_m{maquina_id or 0}_{int(time.time())}_{i}",
                    resource_type="image",
                    transformation=[
                        {"width": 1600, "height": 1600, "crop": "limit"},
                        {"quality": "auto:good", "fetch_format": "auto"},
                    ],
                )
                cld_url = result.get("secure_url")
                size_kb = (result.get("bytes") or 0) // 1024
                print(f"[fotos_subir vid={vid}] Cloudinary OK ({size_kb} KB): {cld_url}", flush=True)
            except Exception as e_cld:
                print(f"[fotos_subir vid={vid}] Cloudinary FAIL para "
                      f"{f.filename!r}: {e_cld}\n{_tb.format_exc()}", flush=True)
                errors.append(f"Cloudinary: {str(e_cld)[:100]}")
                # Continúa al fallback filesystem

        # ── INTENTO 2: Filesystem fallback (efímero en Railway) ─────
        if not cld_url:
            try:
                f.stream.seek(0)
                visita_dir = os.path.join(MANT_FOTOS_DIR, f"v{vid}")
                os.makedirs(visita_dir, exist_ok=True)
                fname = f"v{vid}_{int(time.time())}_{i}_{secure_filename(f.filename)}"
                fpath = os.path.join(visita_dir, fname)
                f.save(fpath)
                size_kb = os.path.getsize(fpath) // 1024
                archivo_path = f"uploads/mantenciones/v{vid}/{fname}"
                print(f"[fotos_subir vid={vid}] Filesystem OK ({size_kb} KB): {archivo_path}", flush=True)
            except Exception as e_fs:
                print(f"[fotos_subir vid={vid}] Filesystem FAIL para "
                      f"{f.filename!r}: {e_fs}\n{_tb.format_exc()}", flush=True)
                errors.append(f"Filesystem fallback falló para {f.filename}: {e_fs}")
                continue

        try:
            # FIX 2026-05-17: si Cloudinary funcionó (cld_url) pero NO hay
            # filesystem path, archivo_path queda NULL. La columna era NOT NULL
            # → error 1048. Migración ALTER ya está aplicada, pero por
            # defensiva pasamos string vacío si no hay path real.
            ap = archivo_path or ""
            mysql_execute(
                "INSERT INTO mant_visita_fotos "
                "(visita_id, tarea_id, maquina_id, archivo_path, cloudinary_url, "
                " archivo_nombre, tipo_foto, descripcion, tomada_por, file_size_kb) "
                "VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)",
                (
                    vid, tarea_id, maquina_id,
                    ap, cld_url,
                    f.filename[:300],
                    tipo_foto, descripcion or None, user, size_kb
                )
            )
            saved += 1
            if first_url is None:
                first_url = cld_url or (f"/static/{archivo_path}" if archivo_path else None)
        except Exception as e:
            print(f"[fotos_subir vid={vid}] INSERT BD FAIL para "
                  f"{f.filename!r}: {e}\n{_tb.format_exc()}", flush=True)
            errors.append(f"Error BD {f.filename}: {str(e)[:200]}")
    try:
        if saved:
            mysql_execute(
                "INSERT INTO mant_logs (entidad, entidad_id, accion, detalle, usuario) "
                "VALUES ('visita', %s, 'fotos_subidas', %s, %s)",
                (vid, f"{saved} foto(s) tipo={tipo_foto}", user)
            )
    except Exception:
        pass
    # Si NO se guardó NINGUNA foto, devolver ok:false con detalles
    if saved == 0:
        print(f"[fotos_subir vid={vid}] RESULTADO: 0 fotos guardadas. errores={errors[:3]}", flush=True)
        return jsonify({
            "ok": False,
            "error": "No se pudo guardar ninguna foto. " + (errors[0] if errors else "Causa desconocida."),
            "errors": errors[:3],
        }), 500
    print(f"[fotos_subir vid={vid}] RESULTADO: {saved} guardadas, "
          f"{len(errors)} errores, persistente={bool(first_url and first_url.startswith('https://'))}",
          flush=True)
    return jsonify({
        "ok": True,
        "saved": saved,
        "url": first_url,        # para que el frontend muestre inline
        "errors": errors[:3],
        "persistente": bool(first_url and first_url.startswith("https://")),
    })


@app.route("/mantenciones/api/visitas/<int:vid>/adjuntos", methods=["GET"])
@_mant_required
@_ot_can_view
def mant_visita_adjuntos_list(vid):
    """Lista de adjuntos (PDFs, videos, documentos) de una OT.
    Distintos de fotos (que tienen su propia tabla mant_visita_fotos)."""
    rows = mysql_fetchall(
        "SELECT id, tipo, archivo_path, cloudinary_url, archivo_nombre, "
        "       file_size_kb, mime_type, descripcion, subido_por, created_at "
        "  FROM mant_visita_adjuntos WHERE visita_id=%s "
        " ORDER BY created_at DESC",
        (vid,)
    ) or []
    out = []
    for r in rows:
        d = dict(r)
        d["url"] = d.get("cloudinary_url") or (
            f"/static/{d['archivo_path']}" if d.get("archivo_path") else ""
        )
        if d.get("created_at"):
            d["created_at"] = str(d["created_at"])[:16]
        out.append(d)
    return jsonify({"ok": True, "adjuntos": out, "total": len(out)})


@app.route("/mantenciones/api/visitas/<int:vid>/adjuntos", methods=["POST"])
@_mant_required
@_tecnico_owns_visita
def mant_visita_adjuntos_upload(vid):
    """Sube un adjunto a la OT — PDF, video, documento. Persistente
    en Cloudinary (resource_type según el tipo). Fallback filesystem
    si Cloudinary falla."""
    f = request.files.get("archivo") or request.files.get("file") or request.files.get("foto")
    if not f or not f.filename:
        return jsonify({"ok": False, "error": "No se envió archivo (campo 'archivo')"}), 400

    descripcion = (request.form.get("descripcion") or "").strip()[:1000] or None
    tipo_hint   = (request.form.get("tipo") or "").strip().lower()

    # Detectar tipo desde mime_type / extensión
    mime = (f.mimetype or "").lower()
    ext = ""
    if "." in f.filename:
        ext = f.filename.rsplit(".", 1)[1].lower()
    if tipo_hint in ("foto","pdf","video","documento","audio","otro"):
        tipo = tipo_hint
    elif mime.startswith("image/"):
        tipo = "foto"
    elif mime.startswith("video/") or ext in ("mp4","mov","avi","webm","mkv"):
        tipo = "video"
    elif mime == "application/pdf" or ext == "pdf":
        tipo = "pdf"
    elif mime.startswith("audio/"):
        tipo = "audio"
    elif ext in ("doc","docx","xls","xlsx","ppt","pptx","txt","csv"):
        tipo = "documento"
    else:
        tipo = "otro"

    # Tamaño máximo según tipo
    f.stream.seek(0, 2); size_bytes = f.stream.tell(); f.stream.seek(0)
    MAX = {
        "foto": 15 * 1024 * 1024,        # 15 MB
        "pdf": 30 * 1024 * 1024,         # 30 MB
        "video": 100 * 1024 * 1024,      # 100 MB
        "documento": 25 * 1024 * 1024,   # 25 MB
        "audio": 30 * 1024 * 1024,
        "otro": 25 * 1024 * 1024,
    }.get(tipo, 25 * 1024 * 1024)
    if size_bytes > MAX:
        return jsonify({
            "ok": False,
            "error": f"Archivo demasiado grande ({size_bytes // (1024*1024)} MB). "
                     f"Máximo para {tipo}: {MAX // (1024*1024)} MB."
        }), 413

    user = current_username()
    cloud_url = None
    cloud_public_id = None
    archivo_path = None

    # Subir a Cloudinary según tipo
    try:
        import cloudinary, cloudinary.uploader  # noqa
        cloud_ok = bool(CLOUDINARY_CONFIG.get("cloud_name") and CLOUDINARY_CONFIG.get("api_key"))
    except ImportError:
        cloud_ok = False

    if cloud_ok:
        try:
            import cloudinary.uploader
            f.stream.seek(0)
            # resource_type según el tipo
            if tipo == "video":
                rt = "video"
            elif tipo == "foto":
                rt = "image"
            else:
                rt = "raw"  # PDF, docs, etc.
            result = cloudinary.uploader.upload(
                f,
                folder=f"ilus/visitas/v{vid}/adjuntos",
                public_id=f"v{vid}_{tipo}_{int(time.time())}",
                resource_type=rt,
                # Transformaciones solo para imagen
                **({"transformation": [
                    {"width": 1600, "height": 1600, "crop": "limit"},
                    {"quality": "auto:good", "fetch_format": "auto"},
                ]} if rt == "image" else {})
            )
            cloud_url = result.get("secure_url")
            cloud_public_id = result.get("public_id")
        except Exception as e_cld:
            print(f"[adjuntos_upload] Cloudinary falló: {e_cld}", flush=True)

    # Fallback filesystem si Cloudinary no funcionó
    if not cloud_url:
        try:
            f.stream.seek(0)
            adj_dir = os.path.join(MANT_FOTOS_DIR, f"v{vid}", "adjuntos")
            os.makedirs(adj_dir, exist_ok=True)
            fname = f"adj_v{vid}_{int(time.time())}_{secure_filename(f.filename)}"
            fpath = os.path.join(adj_dir, fname)
            f.save(fpath)
            archivo_path = f"uploads/mantenciones/v{vid}/adjuntos/{fname}"
        except Exception as e_fs:
            return jsonify({"ok": False, "error": f"Error guardando: {e_fs}"}), 500

    try:
        mysql_execute(
            "INSERT INTO mant_visita_adjuntos "
            "(visita_id, tipo, archivo_path, cloudinary_url, cloudinary_public_id, "
            " archivo_nombre, file_size_kb, mime_type, descripcion, subido_por) "
            "VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)",
            (vid, tipo, archivo_path, cloud_url, cloud_public_id,
             f.filename[:300], size_bytes // 1024, mime[:100],
             descripcion, user)
        )
        _mant_log("visita", vid, "adjunto_subido", f"{tipo}: {f.filename}")
        return jsonify({
            "ok": True,
            "tipo": tipo,
            "url": cloud_url or (f"/static/{archivo_path}" if archivo_path else None),
            "nombre": f.filename,
            "size_kb": size_bytes // 1024,
            "persistente": bool(cloud_url),
        })
    except Exception as e:
        print(f"[adjuntos_upload] DB error: {e}", flush=True)
        return jsonify({"ok": False, "error": "Error guardando en BD"}), 500


@app.route("/mantenciones/api/visitas/<int:vid>/adjuntos/<int:aid>", methods=["DELETE"])
@_mant_required
@_tecnico_owns_visita
def mant_visita_adjunto_delete(vid, aid):
    """Elimina un adjunto de la OT (Cloudinary + BD)."""
    row = mysql_fetchone(
        "SELECT cloudinary_public_id, archivo_path FROM mant_visita_adjuntos "
        " WHERE id=%s AND visita_id=%s",
        (aid, vid)
    )
    if not row:
        return jsonify({"ok": False, "error": "Adjunto no encontrado"}), 404
    # Borrar de Cloudinary si tiene public_id
    if row.get("cloudinary_public_id"):
        try:
            import cloudinary, cloudinary.uploader
            cloudinary.uploader.destroy(row["cloudinary_public_id"], invalidate=True)
        except Exception as e:
            print(f"[adjunto_del] cloudinary destroy falló: {e}", flush=True)
    # Borrar filesystem si está
    if row.get("archivo_path"):
        try:
            fpath = os.path.join(app.static_folder, row["archivo_path"].replace("/static/", ""))
            if os.path.exists(fpath): os.remove(fpath)
        except Exception: pass
    mysql_execute("DELETE FROM mant_visita_adjuntos WHERE id=%s AND visita_id=%s", (aid, vid))
    _mant_log("visita", vid, "adjunto_eliminado", f"adj #{aid}")
    return jsonify({"ok": True})


@app.route("/mantenciones/api/visitas/<int:vid>/fotos/<int:fid>", methods=["DELETE"])
@_mant_required
@_tecnico_owns_visita
def mant_visita_foto_delete(vid, fid):
    """Elimina una foto de la OT (archivo + registro)."""
    row = mysql_fetchone(
        "SELECT archivo_path FROM mant_visita_fotos WHERE id=%s AND visita_id=%s",
        (fid, vid)
    )
    if row and row.get("archivo_path"):
        try:
            fp = os.path.join(
                os.path.dirname(os.path.abspath(__file__)),
                "static", row["archivo_path"]
            )
            if os.path.exists(fp):
                os.remove(fp)
        except Exception:
            pass
    mysql_execute("DELETE FROM mant_visita_fotos WHERE id=%s AND visita_id=%s", (fid, vid))
    return jsonify({"ok": True, "deleted": True})


# ═════════════════════════════════════════════════════════════════════
# GALERÍA POR MÁQUINA (inventario fotográfico permanente)
# ═════════════════════════════════════════════════════════════════════

def _maquina_tecnico_owns(mid):
    """Helper: True si el usuario actual NO es técnico/tecnico_externo
    (admin/superadmin/ejecutivo pasan), o si lo es y tiene al menos una
    visita asignada que involucra esta máquina. False ⇒ denegar.

    Una máquina "involucra" al técnico si:
    - tiene una tarea en una visita asignada al técnico (principal o N:N)
    """
    u = getattr(g, "user", None) or {}
    role = (u.get("role") or "").lower()
    if role not in ("tecnico", "tecnico_externo"):
        return True
    uid = u.get("id")
    if not uid:
        return False
    try:
        ok = mysql_fetchone(
            "SELECT 1 AS x FROM mant_visita_tareas vt "
            "  JOIN mant_visitas v ON v.id=vt.visita_id "
            " WHERE vt.maquina_id=%s "
            "   AND (v.tecnico_user_id=%s "
            "        OR EXISTS(SELECT 1 FROM mant_visita_tecnicos vtc "
            "                   WHERE vtc.visita_id=v.id "
            "                     AND vtc.tecnico_user_id=%s)) "
            " LIMIT 1",
            (mid, uid, uid)
        )
        return bool(ok)
    except Exception as e_chk:
        print(f"[SECURITY] Error validando maquina mid={mid} uid={uid}: {e_chk}", flush=True)
        return False


@app.route("/mantenciones/api/maquinas/<int:mid>/fotos", methods=["GET"])
@_mant_required
def mant_maquina_fotos_get(mid):
    # 🔐 SEGURIDAD: técnico solo ve fotos de máquinas que está atendiendo
    if not _maquina_tecnico_owns(mid):
        u = getattr(g, "user", None) or {}
        print(
            f"[SECURITY] {u.get('id')} ({u.get('username')}) intento ver fotos "
            f"maquina mid={mid} sin OT asignada",
            flush=True
        )
        return jsonify({"ok": False, "error": "No tienes acceso a esta máquina"}), 403
    rows = mysql_fetchall(
        "SELECT id, archivo_path, archivo_nombre, tipo_foto, descripcion, "
        "       es_principal, visita_origen, tomada_por, tomada_at "
        "  FROM mant_maquina_fotos WHERE maquina_id=%s "
        "ORDER BY es_principal DESC, tomada_at DESC",
        (mid,)
    ) or []
    return jsonify([dict(r) for r in rows])


@app.route("/mantenciones/api/maquinas/<int:mid>/fotos/subir", methods=["POST"])
@_mant_required
def mant_maquina_fotos_subir(mid):
    # 🔐 SEGURIDAD: técnico solo sube fotos a máquinas que está atendiendo
    if not _maquina_tecnico_owns(mid):
        u = getattr(g, "user", None) or {}
        print(
            f"[SECURITY] {u.get('id')} ({u.get('username')}) intento subir foto "
            f"a maquina mid={mid} sin OT asignada",
            flush=True
        )
        return jsonify({"ok": False, "error": "No tienes acceso a esta máquina"}), 403
    files = request.files.getlist("fotos") or request.files.getlist("imagenes")
    if not files or all(not f.filename for f in files):
        return jsonify({"ok": False, "error": "No se envió ningún archivo"}), 400
    tipo_foto = (request.form.get("tipo_foto") or "principal").strip().lower()
    if tipo_foto not in ("principal", "serie", "marca", "detalle",
                          "instalada", "daño", "antes_reparacion", "despues_reparacion"):
        tipo_foto = "principal"
    descripcion = (request.form.get("descripcion") or "").strip()[:500]
    user = current_username()

    saved = 0
    errors = []
    for i, f in enumerate(files):
        if not f or not f.filename:
            continue
        ext, err = _validate_uploaded_image(f, label=f.filename)
        if err:
            errors.append(err)
            continue
        mq_dir = os.path.join(MANT_FOTOS_DIR, f"m{mid}")
        os.makedirs(mq_dir, exist_ok=True)
        fname = f"m{mid}_{int(time.time())}_{i}_{secure_filename(f.filename)}"
        fpath = os.path.join(mq_dir, fname)
        try:
            f.save(fpath)
        except Exception as e:
            errors.append(f"Error guardando {f.filename}: {e}")
            continue
        try:
            mysql_execute(
                "INSERT INTO mant_maquina_fotos "
                "(maquina_id, archivo_path, archivo_nombre, tipo_foto, descripcion, tomada_por) "
                "VALUES (%s,%s,%s,%s,%s,%s)",
                (
                    mid,
                    f"uploads/mantenciones/m{mid}/{fname}",
                    f.filename[:300],
                    tipo_foto, descripcion or None, user
                )
            )
            saved += 1
        except Exception as e:
            errors.append(f"Error BD {f.filename}: {e}")
    return jsonify({"ok": True, "saved": saved, "errors": errors[:3]})


# ── REPUESTOS DE UNA VISITA ──────────────────────────────────────────

@app.route("/mantenciones/api/visitas/<int:vid>/repuestos", methods=["GET"])
@_mant_required
@_ot_can_view
def mant_visita_repuestos_get(vid):
    rows = mysql_fetchall(
        "SELECT id, sku, producto_id, descripcion, cantidad, "
        "       costo_unitario, costo_total, origen, notas "
        "  FROM mant_visita_repuestos "
        " WHERE visita_id=%s ORDER BY id",
        (vid,)
    ) or []
    return jsonify([dict(r) for r in rows])


@app.route("/mantenciones/api/productos-search", methods=["GET"])
@_mant_required
def mant_productos_search():
    """
    Buscador de productos del catálogo local (para repuestos).
    Busca por SKU o nombre.
    """
    q = (request.args.get("q") or "").strip()
    if len(q) < 2:
        return jsonify([])
    like = f"%{q}%"
    # Tabla 'products' es el catálogo de etiquetas/productos local
    rows = mysql_fetchall(
        "SELECT sku, nombre, marca, precio_venta "
        "  FROM products "
        " WHERE sku LIKE %s OR nombre LIKE %s "
        " ORDER BY sku LIMIT 15",
        (like, like)
    ) or []
    return jsonify([dict(r) for r in rows])


# ── ENVÍO DE EMAIL: visita agendada (con OT) ─────────────────────────

@app.route("/mantenciones/api/visitas/<int:vid>/enviar-email", methods=["POST"])
@_mant_required
@_tecnico_owns_visita
def mant_visita_enviar_email(vid):
    """
    Envía un email al cliente notificando que se agendó la visita,
    incluyendo el número de OT, fecha, técnicos y costo.
    Body JSON opcional:
      destinatario: email (si no se pasa, usa contacto_email del cliente)
    """
    d = request.get_json(silent=True) or {}
    v = mysql_fetchone(
        """SELECT v.*, c.razon_social, c.contacto_email, c.contacto_nombre,
                  c.direccion, c.comuna, c.region
             FROM mant_visitas v
             JOIN mant_clientes c ON c.id=v.cliente_id
            WHERE v.id=%s""",
        (vid,)
    )
    if not v:
        return jsonify({"error": "Visita no encontrada"}), 404

    destinatario = (d.get("destinatario") or v.get("contacto_email") or "").strip()
    if not destinatario:
        return jsonify({"error": "El cliente no tiene email registrado. Indica un destinatario."}), 400

    # Cargar técnicos asignados
    tecs = mysql_fetchall(
        """SELECT t.nombre, t.especialidad
             FROM mant_visita_tecnicos vt
             JOIN mant_tecnicos t ON t.id=vt.tecnico_id
            WHERE vt.visita_id=%s""",
        (vid,)
    ) or []
    # Repuestos
    reps = mysql_fetchall(
        "SELECT descripcion, cantidad, costo_total FROM mant_visita_repuestos WHERE visita_id=%s",
        (vid,)
    ) or []

    ot   = v.get("numero_ot") or f"V-{vid:05d}"
    fecha_str = v["fecha_programada"].strftime("%d/%m/%Y") if v.get("fecha_programada") else "—"
    horario = ""
    if v.get("hora_inicio"):
        h_ini = str(v["hora_inicio"])[:5]
        h_fin = str(v["hora_fin"])[:5] if v.get("hora_fin") else ""
        horario = f"{h_ini}{(' – ' + h_fin) if h_fin else ''}"
    tipo_label = {
        "preventiva":"Mantención preventiva",
        "correctiva":"Reparación correctiva",
        "garantia":"Cambio / Garantía",
        "inspeccion":"Inspección"
    }.get(v.get("tipo"), v.get("tipo") or "Visita")
    tecs_html = ", ".join(t["nombre"] for t in tecs) if tecs else (v.get("tecnico") or "Por asignar")
    reps_html = ""
    if reps:
        reps_html = "<h3 style='margin:18px 0 6px;font-size:14px;color:#0f172a'>Repuestos asociados</h3><ul style='font-size:13px;color:#374151'>"
        for rp in reps:
            reps_html += f"<li>{rp['descripcion']} × {rp['cantidad']} — ${int(rp['costo_total'] or 0):,}</li>".replace(",", ".")
        reps_html += "</ul>"
    costo_html = ""
    if v.get("costo"):
        costo_html = f"<p style='font-size:14px'><strong>Costo estimado:</strong> ${int(v['costo']):,} CLP</p>".replace(",", ".")

    saludo = f"Estimado/a {v.get('contacto_nombre') or v['razon_social']}"
    body = f"""
    <p style="font-size:14px;color:#374151">{saludo},</p>
    <p style="font-size:14px;color:#374151">
      Le informamos que se ha programado una visita técnica en sus dependencias:
    </p>
    <table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:13.5px">
      <tr><td style="padding:7px 10px;background:#f9fafb;font-weight:600">N° de Orden</td>
          <td style="padding:7px 10px;font-family:monospace;color:#dc2626;font-weight:700">{ot}</td></tr>
      <tr><td style="padding:7px 10px;background:#f9fafb;font-weight:600">Tipo</td>
          <td style="padding:7px 10px">{tipo_label}</td></tr>
      <tr><td style="padding:7px 10px;background:#f9fafb;font-weight:600">Fecha</td>
          <td style="padding:7px 10px"><strong>{fecha_str}</strong>{(' · ' + horario) if horario else ''}</td></tr>
      <tr><td style="padding:7px 10px;background:#f9fafb;font-weight:600">Técnico(s)</td>
          <td style="padding:7px 10px">{tecs_html}</td></tr>
      {('<tr><td style="padding:7px 10px;background:#f9fafb;font-weight:600">Dirección</td><td style="padding:7px 10px">' + (v.get('direccion') or '') + ', ' + (v.get('comuna') or '') + '</td></tr>') if v.get('direccion') else ''}
    </table>
    {costo_html}
    {reps_html}
    <p style="font-size:13px;color:#6b7280;margin-top:18px">
      Si necesita reagendar o cancelar la visita, por favor responda este correo
      o comuníquese con su ejecutivo asignado.
    </p>
    """
    asunto = f"Visita técnica programada — {ot} ({fecha_str})"
    html = _comm_render_email_document(asunto, body, subtitle=f"OT {ot}")
    ok = _send_ilus_email(destinatario, asunto, html,
                          evento="visita_agendada", modulo="mantenciones")

    if ok:
        _mant_log("visita", vid, "email_enviado", f"a {destinatario} — OT {ot}")
        return jsonify({"ok": True, "destinatario": destinatario})
    return jsonify({"error": "No se pudo enviar el email. Revisa la configuración SMTP."}), 500


