# ══════════════════════════════════════════════════════════════════
# FASE 9 — Analytics extendido (modelo Fracttal)
# 5 endpoints nuevos que complementan /api/analytics/data existente:
#   1. /repuestos     → costo + cantidad por modalidad / cliente / mes
#   2. /familias      → incidencias por familia de equipo
#   3. /modalidad     → desglose visitas pagadas vs garantía + costos
#   4. /pendientes    → OT pendientes por estado + días en backlog
#   5. /activos       → equipos en garantía vs vencida por cliente
# Todos retornan JSON con formato { ok: bool, ...datos }
# ══════════════════════════════════════════════════════════════════

@app.route("/mantenciones/api/analytics/repuestos", methods=["GET"])
@_mant_required
def mant_analytics_repuestos():
    """KPIs de repuestos: costo total, top clientes, desglose por modalidad,
    series por mes (últimos 12 meses).
    """
    try:
        # Totales globales últimos 90 días
        totales = mysql_fetchone(
            "SELECT COUNT(*) AS n_repuestos, "
            "       COALESCE(SUM(r.costo_total),0) AS costo_total, "
            "       COALESCE(SUM(CASE WHEN r.modalidad_repuesto='pagado' THEN r.costo_total ELSE 0 END),0) AS costo_pagado, "
            "       COALESCE(SUM(CASE WHEN r.modalidad_repuesto='garantia' THEN r.costo_total ELSE 0 END),0) AS costo_garantia, "
            "       COALESCE(SUM(CASE WHEN r.modalidad_repuesto='sin_costo' THEN r.costo_total ELSE 0 END),0) AS costo_sin_costo "
            "  FROM mant_visita_repuestos r "
            "  JOIN mant_visitas v ON v.id=r.visita_id "
            " WHERE v.fecha_programada >= DATE_SUB(CURDATE(), INTERVAL 90 DAY)"
        ) or {}
        # Top 10 clientes por costo de repuestos (últimos 90 días)
        top_clientes = mysql_fetchall(
            "SELECT c.id, c.razon_social, COUNT(r.id) AS n_repuestos, "
            "       COALESCE(SUM(r.costo_total),0) AS total "
            "  FROM mant_visita_repuestos r "
            "  JOIN mant_visitas v ON v.id=r.visita_id "
            "  JOIN mant_clientes c ON c.id=v.cliente_id "
            " WHERE v.fecha_programada >= DATE_SUB(CURDATE(), INTERVAL 90 DAY) "
            " GROUP BY c.id "
            " ORDER BY total DESC LIMIT 10"
        ) or []
        # Serie mensual últimos 12 meses
        serie = mysql_fetchall(
            "SELECT DATE_FORMAT(v.fecha_programada, '%%Y-%%m') AS mes, "
            "       COUNT(r.id) AS n, COALESCE(SUM(r.costo_total),0) AS total "
            "  FROM mant_visita_repuestos r "
            "  JOIN mant_visitas v ON v.id=r.visita_id "
            " WHERE v.fecha_programada >= DATE_SUB(CURDATE(), INTERVAL 12 MONTH) "
            " GROUP BY mes ORDER BY mes"
        ) or []
        return jsonify({
            "ok": True,
            "totales": {k: float(v) if k.startswith("costo") else int(v or 0)
                        for k, v in (totales or {}).items()},
            "top_clientes": [{
                "id": r["id"], "razon_social": r["razon_social"],
                "n_repuestos": int(r["n_repuestos"] or 0),
                "total": float(r["total"] or 0),
            } for r in top_clientes],
            "serie_mensual": [{
                "mes": r["mes"], "n": int(r["n"] or 0),
                "total": float(r["total"] or 0),
            } for r in serie],
        })
    except Exception as e:
        print(f"[analytics/repuestos] {e}", flush=True)
        return jsonify({"ok": False, "error": str(e)}), 500


@app.route("/mantenciones/api/analytics/familias", methods=["GET"])
@_mant_required
def mant_analytics_familias():
    """Incidencias por familia de equipo: cuáles familias tienen más
    intervenciones, más tiempo invertido, más costo de repuestos.
    """
    try:
        # OT por familia (últimos 180 días)
        rows = mysql_fetchall(
            "SELECT COALESCE(m.familia_equipo,'otros') AS familia, "
            "       COUNT(DISTINCT v.id) AS n_ot, "
            "       COALESCE(SUM(v.duracion_real_min),0) AS minutos, "
            "       COALESCE(SUM(r.costo_total),0) AS costo_rep "
            "  FROM mant_visitas v "
            "  JOIN mant_visita_tareas t ON t.visita_id=v.id "
            "  JOIN mant_maquinas m ON m.id=t.maquina_id "
            "  LEFT JOIN mant_visita_repuestos r ON r.visita_id=v.id AND r.maquina_id=m.id "
            " WHERE v.fecha_programada >= DATE_SUB(CURDATE(), INTERVAL 180 DAY) "
            " GROUP BY familia "
            " ORDER BY n_ot DESC"
        ) or []
        FAM_LBL = {
            "cardio":"Cardio","selectorizado":"Selectorizado","carga_libre":"Carga libre",
            "racks_estructuras":"Racks/Estructuras","bancos":"Bancos","accesorios":"Accesorios",
            "bicicletas":"Bicicletas","trotadoras":"Trotadoras","otros":"Otros",
        }
        return jsonify({
            "ok": True,
            "familias": [{
                "familia": r["familia"],
                "familia_label": FAM_LBL.get(r["familia"], r["familia"]),
                "n_ot": int(r["n_ot"] or 0),
                "horas": round((r["minutos"] or 0) / 60, 1),
                "costo_repuestos": float(r["costo_rep"] or 0),
            } for r in rows],
        })
    except Exception as e:
        print(f"[analytics/familias] {e}", flush=True)
        return jsonify({"ok": False, "error": str(e)}), 500


@app.route("/mantenciones/api/analytics/modalidad", methods=["GET"])
@_mant_required
def mant_analytics_modalidad():
    """Desglose de OTs por modalidad de cobro: cuántas, costos, % del total."""
    try:
        rows = mysql_fetchall(
            "SELECT COALESCE(modalidad_cobro,'pagado') AS modalidad, "
            "       COUNT(*) AS n, "
            "       COALESCE(SUM(costo),0) AS costo_visitas, "
            "       COALESCE(AVG(duracion_real_min),0) AS dur_prom "
            "  FROM mant_visitas "
            " WHERE fecha_programada >= DATE_SUB(CURDATE(), INTERVAL 180 DAY) "
            " GROUP BY modalidad "
            " ORDER BY n DESC"
        ) or []
        total_n = sum(r["n"] or 0 for r in rows) or 1
        MOD_LBL = {
            "pagado":"Pagado","garantia":"Garantía",
            "sin_costo":"Sin costo","interno":"Interno",
        }
        MOD_COLOR = {
            "pagado":"#16a34a","garantia":"#dc2626",
            "sin_costo":"#9ca3af","interno":"#7c3aed",
        }
        return jsonify({
            "ok": True,
            "modalidades": [{
                "modalidad": r["modalidad"],
                "label": MOD_LBL.get(r["modalidad"], r["modalidad"]),
                "color": MOD_COLOR.get(r["modalidad"], "#6b7280"),
                "n": int(r["n"] or 0),
                "pct": round((int(r["n"] or 0) * 100.0) / total_n, 1),
                "costo_visitas": float(r["costo_visitas"] or 0),
                "duracion_promedio_min": round(float(r["dur_prom"] or 0), 1),
            } for r in rows],
            "total_ot": total_n,
        })
    except Exception as e:
        print(f"[analytics/modalidad] {e}", flush=True)
        return jsonify({"ok": False, "error": str(e)}), 500


@app.route("/mantenciones/api/analytics/pendientes", methods=["GET"])
@_mant_required
def mant_analytics_pendientes():
    """OTs pendientes desglosadas por estado, con días en backlog (oldest first)."""
    from datetime import date as _date
    try:
        estados_pendientes = (
            "creada","programada","asignada","en_curso","en_ejecucion",
            "pendiente_info","pendiente_repuesto","pendiente_aprobacion"
        )
        ph = ",".join(["%s"]*len(estados_pendientes))
        rows = mysql_fetchall(
            f"SELECT estado, COUNT(*) AS n, "
            f"       MIN(fecha_programada) AS oldest, MAX(fecha_programada) AS newest, "
            f"       COALESCE(AVG(DATEDIFF(CURDATE(), fecha_programada)),0) AS dias_prom "
            f"  FROM mant_visitas "
            f" WHERE estado IN ({ph}) "
            f" GROUP BY estado "
            f" ORDER BY n DESC",
            estados_pendientes
        ) or []
        # OTs urgentes (prioridad alta/urgente + estados pendientes)
        urgentes = mysql_fetchall(
            f"SELECT v.id, v.numero_ot, v.titulo, v.fecha_programada, "
            f"       v.prioridad, v.estado, c.razon_social "
            f"  FROM mant_visitas v "
            f"  JOIN mant_clientes c ON c.id=v.cliente_id "
            f" WHERE v.estado IN ({ph}) "
            f"   AND v.prioridad IN ('alta','urgente') "
            f" ORDER BY (v.prioridad='urgente') DESC, v.fecha_programada ASC "
            f" LIMIT 20",
            estados_pendientes
        ) or []
        return jsonify({
            "ok": True,
            "por_estado": [{
                "estado": r["estado"],
                "n": int(r["n"] or 0),
                "dias_promedio": round(float(r["dias_prom"] or 0), 1),
                "oldest": str(r["oldest"])[:10] if r.get("oldest") else "",
                "newest": str(r["newest"])[:10] if r.get("newest") else "",
            } for r in rows],
            "urgentes": [{
                "id": r["id"], "numero_ot": r.get("numero_ot") or "",
                "titulo": r.get("titulo") or "",
                "cliente": r.get("razon_social") or "",
                "fecha": str(r["fecha_programada"])[:10] if r.get("fecha_programada") else "",
                "prioridad": r.get("prioridad"),
                "estado": r.get("estado"),
                "dias_atras": (_date.today() - r["fecha_programada"]).days if r.get("fecha_programada") else None,
            } for r in urgentes],
            "total_pendientes": sum(r["n"] or 0 for r in rows),
        })
    except Exception as e:
        print(f"[analytics/pendientes] {e}", flush=True)
        return jsonify({"ok": False, "error": str(e)}), 500


@app.route("/mantenciones/api/analytics/activos-registro", methods=["GET"])
@_mant_required
def mant_analytics_activos():
    """Análisis del parque de activos: por familia, garantía vigente vs vencida,
    activos sin OT en últimos 6 meses."""
    try:
        # Conteos generales
        gen = mysql_fetchone(
            "SELECT COUNT(*) AS total, "
            "       SUM(CASE WHEN COALESCE(estado,'activo')='activo' THEN 1 ELSE 0 END) AS activos, "
            "       SUM(CASE WHEN estado='baja' THEN 1 ELSE 0 END) AS baja, "
            "       SUM(CASE WHEN fecha_fin_garantia IS NOT NULL "
            "                AND fecha_fin_garantia >= CURDATE() THEN 1 ELSE 0 END) AS en_garantia, "
            "       SUM(CASE WHEN fecha_fin_garantia IS NOT NULL "
            "                AND fecha_fin_garantia < CURDATE() THEN 1 ELSE 0 END) AS garantia_vencida "
            "FROM mant_maquinas"
        ) or {}
        # Por familia
        por_familia = mysql_fetchall(
            "SELECT COALESCE(familia_equipo,'otros') AS familia, COUNT(*) AS n "
            "  FROM mant_maquinas "
            " WHERE COALESCE(estado,'activo') <> 'baja' "
            " GROUP BY familia ORDER BY n DESC"
        ) or []
        # Activos sin OT en últimos 6 meses (huérfanos)
        huerfanos = mysql_fetchall(
            "SELECT m.id, m.nombre, m.serie, c.razon_social "
            "  FROM mant_maquinas m "
            "  JOIN mant_clientes c ON c.id=m.cliente_id "
            " WHERE COALESCE(m.estado,'activo') <> 'baja' "
            "   AND NOT EXISTS ( "
            "     SELECT 1 FROM mant_visita_tareas t "
            "      JOIN mant_visitas v ON v.id=t.visita_id "
            "     WHERE t.maquina_id=m.id "
            "       AND v.fecha_programada >= DATE_SUB(CURDATE(), INTERVAL 6 MONTH) "
            "   ) "
            " ORDER BY c.razon_social, m.nombre "
            " LIMIT 50"
        ) or []
        return jsonify({
            "ok": True,
            "totales": {k: int(v or 0) for k, v in (gen or {}).items()},
            "por_familia": [{
                "familia": r["familia"], "n": int(r["n"] or 0),
            } for r in por_familia],
            "huerfanos_6m": [{
                "id": r["id"], "nombre": r.get("nombre") or "",
                "serie": r.get("serie") or "",
                "cliente": r.get("razon_social") or "",
            } for r in huerfanos],
            "huerfanos_count": len(huerfanos),
        })
    except Exception as e:
        print(f"[analytics/activos] {e}", flush=True)
        return jsonify({"ok": False, "error": str(e)}), 500


@app.route("/mantenciones/api/analytics/data", methods=["GET"])
@_mant_required
def mant_analytics_data():
    """Devuelve todos los KPIs y series para el dashboard analytics."""
    try:
        # ── 1. KPIs grandes (30 días)
        row = mysql_fetchone(
            "SELECT AVG(duracion_real_min) AS tmr "
            "  FROM mant_visitas "
            " WHERE estado='completada' "
            "   AND duracion_real_min IS NOT NULL "
            "   AND COALESCE(fecha_realizada, fecha_programada) >= DATE_SUB(CURDATE(), INTERVAL 30 DAY)",
            ()
        ) or {}
        tmr_min = float(row.get("tmr") or 0)

        sla_row = mysql_fetchone(
            "SELECT "
            "  COUNT(*) AS total, "
            "  SUM(CASE WHEN fecha_realizada IS NOT NULL "
            "           AND fecha_realizada <= DATE_ADD(fecha_programada, INTERVAL 1 DAY) "
            "           THEN 1 ELSE 0 END) AS dentro_sla "
            "  FROM mant_visitas "
            " WHERE estado='completada' "
            "   AND fecha_programada >= DATE_SUB(CURDATE(), INTERVAL 30 DAY)",
            ()
        ) or {}
        sla_total = int(sla_row.get("total") or 0)
        sla_ok    = int(sla_row.get("dentro_sla") or 0)
        sla_pct   = round(sla_ok * 100.0 / sla_total, 1) if sla_total > 0 else None

        over_row = mysql_fetchone(
            "SELECT AVG( (duracion_real_min - duracion_planificada_min) * 100.0 "
            "           / NULLIF(duracion_planificada_min,0) ) AS overrun "
            "  FROM mant_visitas "
            " WHERE estado='completada' "
            "   AND duracion_real_min IS NOT NULL "
            "   AND duracion_planificada_min IS NOT NULL "
            "   AND COALESCE(fecha_realizada, fecha_programada) >= DATE_SUB(CURDATE(), INTERVAL 30 DAY)",
            ()
        ) or {}
        overrun_pct = round(float(over_row.get("overrun") or 0), 1)

        gar_row = mysql_fetchone(
            "SELECT "
            "  COUNT(*) AS total, "
            "  SUM(CASE WHEN tipo='garantia' THEN 1 ELSE 0 END) AS garantias "
            "  FROM mant_visitas "
            " WHERE fecha_programada >= DATE_SUB(CURDATE(), INTERVAL 30 DAY)",
            ()
        ) or {}
        gar_total = int(gar_row.get("total") or 0)
        gar_n     = int(gar_row.get("garantias") or 0)
        gar_pct   = round(gar_n * 100.0 / gar_total, 1) if gar_total > 0 else None

        # ── 2. Top 10 máquinas con más fallas (90 días)
        top_maquinas = mysql_fetchall(
            "SELECT m.id, m.nombre, m.serie, m.sku, "
            "       c.razon_social AS cliente_nombre, "
            "       COUNT(t.id) AS n_tareas "
            "  FROM mant_visita_tareas t "
            "  JOIN mant_maquinas m ON m.id = t.maquina_id "
            "  LEFT JOIN mant_clientes c ON c.id = m.cliente_id "
            " WHERE t.created_at >= DATE_SUB(NOW(), INTERVAL 90 DAY) "
            "   AND t.maquina_id IS NOT NULL "
            " GROUP BY m.id "
            " ORDER BY n_tareas DESC, m.nombre "
            " LIMIT 10",
            ()
        ) or []
        top_maquinas = [dict(r) for r in top_maquinas]

        # ── 3. Top técnicos por eficiencia (más alto = mejor; plan/real)
        tec_rows = mysql_fetchall(
            "SELECT t.id, t.nombre, t.especialidad, t.nivel, t.es_externo, "
            "       COUNT(v.id) AS n_visitas, "
            "       AVG( v.duracion_planificada_min * 1.0 "
            "            / NULLIF(v.duracion_real_min, 0) ) AS eficiencia, "
            "       SUM(v.duracion_real_min) AS min_total_real "
            "  FROM mant_visitas v "
            "  JOIN mant_tecnicos t ON t.id = v.tecnico_id "
            " WHERE v.estado = 'completada' "
            "   AND v.duracion_real_min IS NOT NULL AND v.duracion_real_min > 0 "
            "   AND v.duracion_planificada_min IS NOT NULL "
            "   AND COALESCE(v.fecha_realizada, v.fecha_programada) >= DATE_SUB(CURDATE(), INTERVAL 60 DAY) "
            " GROUP BY t.id "
            "HAVING n_visitas >= 1 "
            " ORDER BY eficiencia DESC "
            " LIMIT 5",
            ()
        ) or []
        top_tecnicos = []
        for r in tec_rows:
            d = dict(r)
            ef = float(d.get("eficiencia") or 0)
            d["eficiencia_pct"] = round(ef * 100.0, 1)
            top_tecnicos.append(d)

        # ── 4. Heatmap semanal (cantidad OTs por día de semana, últimos 30 días)
        # MySQL DAYOFWEEK: 1=Domingo, 2=Lunes ... 7=Sábado
        heat = mysql_fetchall(
            "SELECT DAYOFWEEK(fecha_programada) AS dow, COUNT(*) AS n "
            "  FROM mant_visitas "
            " WHERE fecha_programada >= DATE_SUB(CURDATE(), INTERVAL 30 DAY) "
            " GROUP BY dow",
            ()
        ) or []
        # Reordenamos a LU MA MI JU VI SA DO (1..7)
        dow_map = {int(r["dow"]): int(r["n"]) for r in heat}
        # Convertir MySQL DOW (1=Dom) → nuestro orden (1=Lun ... 7=Dom)
        heatmap = []
        for nombre_dia, mysql_dow in [
            ("Lu", 2), ("Ma", 3), ("Mi", 4),
            ("Ju", 5), ("Vi", 6), ("Sa", 7), ("Do", 1),
        ]:
            heatmap.append({"dia": nombre_dia, "n": dow_map.get(mysql_dow, 0)})

        # ── 5. Proyección próxima semana
        # Capacidad: 8 horas/día × 5 días × N técnicos activos
        n_tec_row = mysql_fetchone(
            "SELECT COUNT(*) AS n FROM mant_tecnicos WHERE activo=1", ()
        ) or {}
        n_tec_activos = int(n_tec_row.get("n") or 0)
        capacidad_horas = n_tec_activos * 8 * 5  # 5 días hábiles

        prox_row = mysql_fetchone(
            "SELECT COUNT(*) AS n, "
            "       COALESCE(SUM(duracion_planificada_min),0) AS min_total "
            "  FROM mant_visitas "
            " WHERE fecha_programada BETWEEN CURDATE() AND DATE_ADD(CURDATE(), INTERVAL 7 DAY) "
            "   AND estado IN ('programada','en_curso','reagendada')",
            ()
        ) or {}
        prox_visitas = int(prox_row.get("n") or 0)
        prox_horas   = round(float(prox_row.get("min_total") or 0) / 60.0, 1)
        ocup_pct = round((prox_horas * 100.0 / capacidad_horas), 1) if capacidad_horas else None

        # ── 6. Totales globales para contexto
        glob_row = mysql_fetchone(
            "SELECT COUNT(*) AS total, "
            "       SUM(CASE WHEN estado='completada' THEN 1 ELSE 0 END) AS completadas, "
            "       SUM(CASE WHEN estado='cancelada'  THEN 1 ELSE 0 END) AS canceladas "
            "  FROM mant_visitas "
            " WHERE fecha_programada >= DATE_SUB(CURDATE(), INTERVAL 30 DAY)",
            ()
        ) or {}

        return jsonify({
            "ok": True,
            "kpis": {
                "tmr_min":      round(tmr_min, 1) if tmr_min else None,
                "tmr_label":    f"{int(tmr_min//60)}h {int(tmr_min%60)}min" if tmr_min >= 60 else (f"{int(tmr_min)} min" if tmr_min else "—"),
                "sla_pct":      sla_pct,
                "sla_total":    sla_total,
                "sla_ok":       sla_ok,
                "overrun_pct":  overrun_pct,
                "garantias_pct": gar_pct,
                "garantias_n":   gar_n,
                "total_30d":     int(glob_row.get("total") or 0),
                "completadas_30d": int(glob_row.get("completadas") or 0),
                "canceladas_30d":  int(glob_row.get("canceladas") or 0),
            },
            "top_maquinas":  top_maquinas,
            "top_tecnicos":  top_tecnicos,
            "heatmap":       heatmap,
            "proyeccion": {
                "n_tecnicos_activos": n_tec_activos,
                "capacidad_horas":    capacidad_horas,
                "prox_visitas":       prox_visitas,
                "prox_horas":         prox_horas,
                "ocupacion_pct":      ocup_pct,
            },
        })
    except Exception as e:
        return jsonify({"ok": False, "error": f"Error: {e}"}), 500


# ── ANÁLISIS ECONÓMICO ────────────────────────────────────────────────

@app.route("/mantenciones/analisis")
@_mant_required
def mant_analisis():
    # Ingresos por contrato (12 meses)
    ingresos_mes = mysql_fetchall(
        """SELECT YEAR(fecha_inicio) AS anio, MONTH(fecha_inicio) AS mes,
                  COALESCE(SUM(monto_mensual),0) AS total_mensual,
                  COUNT(*) AS n_contratos
           FROM mant_contratos
           WHERE estado IN ('vigente','indefinido')
             AND fecha_inicio >= DATE_SUB(NOW(), INTERVAL 12 MONTH)
           GROUP BY anio, mes ORDER BY anio, mes""",
        ()
    )
    # Proyección próximos 6 meses
    activos_total = mysql_fetchone(
        "SELECT COALESCE(SUM(monto_mensual),0) AS mrr FROM mant_contratos "
        "WHERE estado IN ('vigente','indefinido')", ()
    ) or {}
    mrr = float(activos_total.get("mrr", 0))

    # Visitas por mes (últimos 6)
    visitas_mes = mysql_fetchall(
        """SELECT YEAR(fecha_programada) AS anio, MONTH(fecha_programada) AS mes,
                  COUNT(*) AS total,
                  SUM(estado='completada') AS completadas,
                  COALESCE(SUM(costo),0) AS ingresos_visitas
           FROM mant_visitas
           WHERE fecha_programada >= DATE_SUB(NOW(), INTERVAL 6 MONTH)
           GROUP BY anio, mes ORDER BY anio, mes""",
        ()
    )
    # Top clientes por valor
    top_clientes = mysql_fetchall(
        """SELECT c.razon_social,
                  COALESCE(SUM(ct.monto_mensual),0) AS mrr,
                  COUNT(ct.id) AS n_contratos,
                  COUNT(v.id) AS n_visitas
           FROM mant_clientes c
           LEFT JOIN mant_contratos ct ON ct.cliente_id=c.id
                     AND ct.estado IN ('vigente','indefinido')
           LEFT JOIN mant_visitas v ON v.cliente_id=c.id
           WHERE c.estado='activo'
           GROUP BY c.id ORDER BY mrr DESC LIMIT 10""",
        ()
    )
    # Contratos por vencer
    por_vencer = mysql_fetchall(
        """SELECT ct.*, cl.razon_social,
                  DATEDIFF(ct.fecha_vencimiento, CURDATE()) AS dias_restantes
           FROM mant_contratos ct
           JOIN mant_clientes cl ON cl.id=ct.cliente_id
           WHERE ct.estado IN ('por_vencer','vigente')
             AND ct.fecha_vencimiento IS NOT NULL
             AND ct.es_indefinido=0
           ORDER BY ct.fecha_vencimiento LIMIT 15""",
        ()
    )

    return render_template("mantenciones/analisis.html",
        ingresos_mes = [dict(r) for r in ingresos_mes],
        mrr          = mrr,
        visitas_mes  = [dict(r) for r in visitas_mes],
        top_clientes = [dict(r) for r in top_clientes],
        por_vencer   = [dict(r) for r in por_vencer],
    )


# Cache global de UF — la UF cambia 1 vez al día, no tiene sentido pegarle
# a mindicador.cl en cada request (~200-600ms por hit).
_UF_CACHE = {"ts": 0, "uf": None, "fecha": None, "error": None}
_UF_CACHE_TTL = 3600  # 1 hora


@app.route("/api/uf-actual")
def api_uf_actual():
    """Devuelve el valor actual de la UF desde mindicador.cl (cacheado 1h)."""
    now = time.time()
    if _UF_CACHE["uf"] is not None and (now - _UF_CACHE["ts"]) < _UF_CACHE_TTL:
        return jsonify({"uf": _UF_CACHE["uf"], "fecha": _UF_CACHE["fecha"],
                        "ok": True, "cached": True})
    try:
        import urllib.request as _ur
        req = _ur.Request(
            "https://mindicador.cl/api/uf",
            headers={"User-Agent": "ILUSApp/1.0"}
        )
        with _ur.urlopen(req, timeout=6) as resp:
            data = json.loads(resp.read().decode("utf-8"))
        uf_val = float(data["serie"][0]["valor"])
        fecha  = data["serie"][0]["fecha"][:10]
        _UF_CACHE.update({"ts": now, "uf": uf_val, "fecha": fecha, "error": None})
        return jsonify({"uf": uf_val, "fecha": fecha, "ok": True})
    except Exception as e:
        # Si tenemos un valor cacheado aunque sea viejo, devolverlo en lugar de error
        if _UF_CACHE["uf"] is not None:
            return jsonify({"uf": _UF_CACHE["uf"], "fecha": _UF_CACHE["fecha"],
                            "ok": True, "cached": True, "stale": True})
        return jsonify({"uf": None, "error": str(e), "ok": False})


# ── BÚSQUEDA PRODUCTOS ERP ───────────────────────────────────────────

@app.route("/mantenciones/api/productos/buscar")
@_mant_required
def mant_productos_buscar():
    """
    Typeahead de productos ERP por SKU o descripción.

    PREFER_SQL=1 (default): consulta MAEPR directo en SQL Server (rápido,
    confiable, no depende del REST API).
    Fallback REST si SQL devuelve None o falla.

    Devuelve [{sku, nombre, tipo}].
    """
    q = request.args.get("q", "").strip()
    if len(q) < 2:
        return jsonify([])

    resultados = []
    seen = set()

    # ── Path SQL (primario cuando PREFER_SQL=1) ──
    _prefer_sql = (os.environ.get("ILUS_ERP_PREFER_SQL", "1").strip().lower()
                   in ("1", "true", "yes", "on"))
    if _prefer_sql:
        try:
            q_like = f"%{q}%"
            rows = _random_sql_query(
                "SELECT TOP 25 "
                "       LTRIM(RTRIM(COALESCE(KOPR,   ''))) AS KOPR, "
                "       LTRIM(RTRIM(COALESCE(NOKOPR, ''))) AS NOKOPR, "
                "       LTRIM(RTRIM(COALESCE(KOPRTE, ''))) AS KOPRTE "
                "  FROM MAEPR "
                " WHERE (UPPER(LTRIM(RTRIM(KOPR)))   LIKE UPPER(%s) "
                "        OR UPPER(LTRIM(RTRIM(NOKOPR))) LIKE UPPER(%s)) "
                " ORDER BY KOPR",
                (q_like, q_like),
                max_rows=25,
            ) or []
            for r in rows:
                sku    = (r.get("KOPR")   or "").strip().upper()
                nombre = (r.get("NOKOPR") or "").strip()
                tipo   = (r.get("KOPRTE") or "").strip()
                if not sku or sku in seen:
                    continue
                resultados.append({"sku": sku, "nombre": nombre, "tipo": tipo})
                seen.add(sku)
            if resultados:
                return jsonify(resultados)
            # Si SQL no devolvió nada, dejamos seguir al REST por si tiene match
        except Exception as ex_sql:
            print(f"[mant-productos-buscar-sql] error: {ex_sql} — cae a REST", flush=True)

    # ── Path REST (fallback) ──
    TOKEN = ERP_CONFIG.get("api_token", "")
    try:
        body = _erp_get(
            "/productos",
            {"search": q, "empresa": "01", "fields": "KOPR,NOKOPR,NOKOTI", "visible": "true"},
            TOKEN, timeout=8,
        )
        for p in (body.get("data") or []):
            sku    = (p.get("KOPR")   or "").strip().upper()
            nombre = (p.get("NOKOPR") or "").strip()
            tipo   = (p.get("NOKOTI") or p.get("TIPO") or "").strip()
            if not sku or sku in seen:
                continue
            resultados.append({"sku": sku, "nombre": nombre, "tipo": tipo})
            seen.add(sku)
            if len(resultados) >= 25:
                break
    except Exception:
        pass  # Si REST falla devolvemos lista vacía (mejor que 500)
    return jsonify(resultados)


# ── BÚSQUEDA DOCUMENTO ERP (como cubicador) ───────────────────────────

@app.route("/mantenciones/api/documento")
@_mant_required
def mant_documento_erp():
    """
    Busca un documento ERP por tipo + número usando la REST API (igual que cubicador).
    Devuelve header y líneas de productos.
    GET ?tido=FCV&nudo=12345
    """
    tido = request.args.get("tido", "").strip().upper()
    nudo = request.args.get("nudo", "").strip()
    if not tido or not nudo:
        return jsonify({"error": "Ingresa tipo y número de documento"}), 400

    # GDP = Guía Despacho Provisional (despachos parciales). El ERP usa GDP para
    # documentos en estado "Parc" antes de facturación final. Incluido para
    # importar equipos desde guías de despacho provisorias.
    TIDOS_VALIDOS = set(ERP_TIDOS_DOCUMENTOS_CLIENTE)
    if tido not in TIDOS_VALIDOS:
        return jsonify({"error": f"Tipo '{tido}' no válido. Usa: {', '.join(sorted(TIDOS_VALIDOS))}"}), 400

    try:
        header, lineas = _cubicador_fetch(tido, nudo)
    except ConnectionError as ce:
        return jsonify({"error": str(ce)}), 503
    except Exception as e:
        return jsonify({"error": f"Error al consultar ERP: {e}"}), 500

    if not header:
        return jsonify({"error": f"Documento {tido} {nudo} no encontrado en el ERP"}), 404

    # Formatear líneas para el wizard
    # NOTA: _cubicador_fetch devuelve el campo "descripcion_erp" (no "descripcion")
    _ZZ_SKUS = {"ZZENVIO","ZZINGREPUESTO","ZZSERVTEC","ZZRETIRO","ZZINSTALACION","ZZINGARREQUIP"}
    items = []
    filtradas = 0
    total_lineas = len(lineas)
    for l in lineas:
        sku  = (l.get("sku") or l.get("KOPRCT") or "").strip().upper()
        nom  = (l.get("descripcion_erp") or l.get("descripcion") or l.get("nombre") or l.get("NOKOPR") or "").strip()
        qty  = int(float(l.get("cantidad") or l.get("qty") or 1))
        if not nom and not sku:
            filtradas += 1
            continue
        # Excluir SKUs de servicio/flete (ya marcados con es_zz por _cubicador_fetch)
        if l.get("es_zz") or sku.upper() in _ZZ_SKUS:
            filtradas += 1
            continue
        items.append({"sku": sku, "nombre": nom or sku, "cantidad": max(qty, 1)})

    debug = request.args.get("debug") == "1"
    resp = {
        "ok":           True,
        "tido":         header.get("tido", tido),
        "nudo":         header.get("nudo_display", nudo),
        "fecha":        header.get("fecha",""),
        "cliente":      header.get("cliente_nombre",""),
        "rut":          header.get("cliente_rut",""),
        "direccion":    header.get("direccion",""),
        "comuna":       header.get("comuna",""),
        "items":        items,
        "total_lineas": total_lineas,
        "filtradas":    filtradas,
    }
    if debug:
        resp["raw_lineas"] = [{
            "sku":   l.get("sku") or l.get("KOPRCT",""),
            "desc":  l.get("descripcion_erp") or l.get("descripcion",""),
            "qty":   l.get("cantidad",0),
            "es_zz": l.get("es_zz",False),
            "keys":  list(l.keys())[:12],
        } for l in lineas[:20]]
    return jsonify(resp)


# ══════════════════════════════════════════════════════════════════════
# CONTROL DE SALDO POR DOCUMENTO ERP
#
# Para evitar duplicar productos: cuando un cliente compra una factura
# con 4 trotadoras, el sistema debe saber cuántas YA fueron asignadas
# a fichas de mantención. Si quedan 0 → no permitir importar más.
# ══════════════════════════════════════════════════════════════════════

def _doc_origen_key(tido, nudo):
    """Construye la clave CANÓNICA con que se guarda doc_origen en mant_maquinas.
    Siempre: 'TIDO_UPPER NUDO_SIN_LEADING_ZEROS'.
    Ej: '00012345' → '12345' → 'FCV 12345'
    """
    tido_n = (tido or "").strip().upper()
    nudo_raw = str(nudo or "").strip()
    # Quitar leading zeros (ERPs guardan 00012345, usuarios tipean 12345)
    nudo_n = nudo_raw.lstrip("0") or nudo_raw or "0"
    return f"{tido_n} {nudo_n}"


def _doc_origen_normalizar(doc_origen):
    """Normaliza cualquier doc_origen al formato canónico 'TIDO NUDO'.
    Acepta 'FCV-12345', 'FCV12345', 'fcv 00012345', etc.
    Si no logra parsear, devuelve el original sin cambios.
    """
    if not doc_origen:
        return doc_origen
    s = str(doc_origen).strip().upper()
    # Separador típico: espacio, guión o pegado (TIDO siempre 2-4 letras)
    import re as _re
    m = _re.match(r"^([A-Z]{2,4})[\s\-_]*([0-9]+)$", s)
    if not m:
        return s   # devolver tal cual si no parseó
    tido, nudo = m.group(1), m.group(2)
    nudo_clean = nudo.lstrip("0") or nudo
    return f"{tido} {nudo_clean}"


def _asignados_por_sku(tido, nudo):
    """Suma cantidad ya asignada de cada SKU para un documento ERP dado.
    Devuelve: {sku_upper: total_asignado}

    Búsqueda ULTRA-TOLERANTE: matchea cualquier formato de doc_origen que
    contenga el nudo (con/sin espacio, guión, leading zeros, may/min).
    """
    tido_n = (tido or "").strip().upper()
    nudo_n = str(nudo or "").strip().lstrip("0") or str(nudo or "").strip() or "0"
    nudo_raw = str(nudo or "").strip()

    # Patrón canónico de match: doc_origen tiene el TIDO y el NUDO sin separador
    # (LIKE flexible que ignora espacios, guiones, leading zeros).
    rows = mysql_fetchall(
        """
        SELECT UPPER(TRIM(sku)) AS sku, COALESCE(SUM(cantidad),0) AS total
          FROM mant_maquinas
         WHERE UPPER(REPLACE(REPLACE(REPLACE(doc_origen,' ',''),'-',''),'_',''))
               LIKE %s
           AND sku IS NOT NULL AND TRIM(sku) <> ''
        GROUP BY UPPER(TRIM(sku))
        """,
        (f"%{tido_n}%{nudo_n}%",)
    ) or []

    out = {}
    for r in rows:
        out[(r["sku"] or "").strip().upper()] = int(r["total"] or 0)
    return out


def _maquinas_de_doc(tido, nudo, limit=20):
    """Devuelve las máquinas existentes con doc_origen que matchea (diagnóstico)."""
    tido_n = (tido or "").strip().upper()
    nudo_n = str(nudo or "").strip().lstrip("0") or str(nudo or "").strip() or "0"
    rows = mysql_fetchall(
        f"""
        SELECT m.id, m.cliente_id, m.sku, m.serie, m.cantidad, m.doc_origen, m.created_at,
               c.razon_social
          FROM mant_maquinas m
          LEFT JOIN mant_clientes c ON c.id = m.cliente_id
         WHERE UPPER(REPLACE(REPLACE(REPLACE(m.doc_origen,' ',''),'-',''),'_',''))
               LIKE %s
         ORDER BY m.created_at DESC
         LIMIT {int(limit)}
        """,
        (f"%{tido_n}%{nudo_n}%",)
    ) or []
    return [dict(r) for r in rows]


@app.route("/mantenciones/api/erp/saldo-debug", methods=["GET"])
@_mant_required
def mant_saldo_debug():
    """Diagnóstico: muestra qué máquinas en BD están asociadas al doc dado.
    Útil cuando el saldo 'no se descuenta' — permite ver si el doc_origen
    guardado matchea con el que se busca.
    GET /mantenciones/api/erp/saldo-debug?tido=FCV&nudo=12345
    """
    tido = (request.args.get("tido") or "").strip().upper()
    nudo = (request.args.get("nudo") or "").strip()
    if not tido or not nudo:
        return jsonify({"error": "tido + nudo requeridos"}), 400

    asignados   = _asignados_por_sku(tido, nudo)
    maquinas    = _maquinas_de_doc(tido, nudo, limit=50)
    doc_canon   = _doc_origen_key(tido, nudo)
    nudo_clean  = nudo.lstrip("0") or nudo

    return jsonify({
        "ok": True,
        "buscando": {
            "tido": tido,
            "nudo_input": nudo,
            "nudo_normalizado": nudo_clean,
            "doc_canonico": doc_canon,
        },
        "asignados_por_sku": asignados,
        "total_maquinas_match": len(maquinas),
        "maquinas_match": maquinas,
        "explicacion": (
            "Si 'asignados_por_sku' está vacío pero 'maquinas_match' tiene "
            "entradas, el SKU no matcheó (revisar mayúsculas o trim). "
            "Si ambos están vacíos, no hay máquinas guardadas con este doc — "
            "puede que doc_origen tenga un formato diferente."
        ),
    })


@app.route("/mantenciones/api/erp/documento-saldos", methods=["GET"])
@_mant_required
def mant_documento_erp_saldos():
    """Igual que /mantenciones/api/erp/documento PERO enriquecido con saldos.

    Para cada línea del documento agrega:
      cantidad_original:  lo que dice la factura
      cantidad_asignada:  cuánto ya está en mant_maquinas (ANY cliente)
      saldo_disponible:   cantidad_original - cantidad_asignada
      ya_completo:        bool — saldo == 0
    """
    tido = request.args.get("tido", "").strip().upper()
    nudo = request.args.get("nudo", "").strip()
    if not tido or not nudo:
        return jsonify({"error": "Ingresa tipo y número de documento"}), 400

    TIDOS_VALIDOS = set(ERP_TIDOS_DOCUMENTOS_CLIENTE)
    if tido not in TIDOS_VALIDOS:
        return jsonify({"error": f"Tipo '{tido}' no válido. Usa: {', '.join(sorted(TIDOS_VALIDOS))}"}), 400

    try:
        header, lineas = _cubicador_fetch(tido, nudo)
    except ConnectionError as ce:
        return jsonify({"error": str(ce)}), 503
    except Exception as e:
        return jsonify({"error": f"Error al consultar ERP: {e}"}), 500

    if not header:
        return jsonify({"error": f"Documento {tido} {nudo} no encontrado"}), 404

    _ZZ_SKUS = {"ZZENVIO","ZZINGREPUESTO","ZZSERVTEC","ZZRETIRO","ZZINSTALACION","ZZINGARREQUIP"}

    # Mapa de asignaciones existentes
    asignados = _asignados_por_sku(tido, nudo)

    items = []
    total_lineas = len(lineas)
    filtradas = 0
    doc_completo = True  # se vuelve False si hay aunque sea 1 línea con saldo
    total_disponible = 0

    for l in lineas:
        sku  = (l.get("sku") or l.get("KOPRCT") or "").strip().upper()
        nom  = (l.get("descripcion_erp") or l.get("descripcion") or l.get("nombre") or l.get("NOKOPR") or "").strip()
        qty_orig = int(float(l.get("cantidad") or l.get("qty") or 1))
        if not nom and not sku:
            filtradas += 1
            continue
        if l.get("es_zz") or sku.upper() in _ZZ_SKUS:
            filtradas += 1
            continue

        ya_asig = int(asignados.get(sku, 0))
        saldo   = max(qty_orig - ya_asig, 0)
        if saldo > 0:
            doc_completo = False
            total_disponible += saldo

        # Buscar dónde está asignado (para mostrar "ya en cliente X")
        asignaciones_existentes = []
        if ya_asig > 0:
            try:
                aexist = mysql_fetchall(
                    "SELECT m.id, m.cliente_id, m.cantidad, m.serie, "
                    "       c.razon_social "
                    "  FROM mant_maquinas m "
                    "  LEFT JOIN mant_clientes c ON c.id=m.cliente_id "
                    " WHERE UPPER(m.sku)=%s AND m.doc_origen LIKE %s "
                    " ORDER BY m.created_at DESC LIMIT 5",
                    (sku, f"%{nudo}%")
                ) or []
                asignaciones_existentes = [{
                    "maquina_id":   int(r["id"]),
                    "cliente_id":   int(r["cliente_id"]) if r.get("cliente_id") else None,
                    "razon_social": r.get("razon_social") or "",
                    "cantidad":     int(r["cantidad"] or 0),
                    "serie":        r.get("serie") or "",
                } for r in aexist]
            except Exception:
                pass

        items.append({
            "sku": sku,
            "nombre": nom or sku,
            "cantidad_original":   qty_orig,
            "cantidad_asignada":   ya_asig,
            "saldo_disponible":    saldo,
            "ya_completo":         saldo == 0,
            "asignaciones":        asignaciones_existentes,
        })

    return jsonify({
        "ok":               True,
        "tido":             header.get("tido", tido),
        "nudo":             header.get("nudo_display", nudo),
        "fecha":            header.get("fecha",""),
        "cliente":          header.get("cliente_nombre",""),
        "rut":              header.get("cliente_rut",""),
        "direccion":        header.get("direccion",""),
        "comuna":           header.get("comuna",""),
        "items":            items,
        "total_lineas":     total_lineas,
        "filtradas":        filtradas,
        "doc_completo":     doc_completo,
        "total_disponible": total_disponible,
        "doc_origen_key":   _doc_origen_key(tido, nudo),
    })


# ── BÚSQUEDA ERP ─────────────────────────────────────────────────────

def _rut_norm(raw: str) -> str:
    """Normaliza RUT: quita puntos, espacios y guión. Devuelve solo dígitos + DV opcional."""
    if not raw:
        return ""
    return raw.replace(".", "").replace(" ", "").replace("-", "").upper()


def _ruts_equivalentes(rut_a: str, rut_b: str) -> bool:
    """True si dos RUT son el mismo (comparando sin puntos/DV)."""
    a = _rut_norm(rut_a)
    b = _rut_norm(rut_b)
    if not a or not b:
        return False
    # Comparar sin DV (último carácter)
    a_sin = a[:-1] if len(a) > 1 else a
    b_sin = b[:-1] if len(b) > 1 else b
    return a_sin == b_sin or a == b


@app.route("/mantenciones/api/clientes/<int:cid>/equipos-import-mismatch", methods=["POST"])
@_mant_required
def mant_equipos_import_mismatch(cid):
    """
    Registra en mant_logs cuando el usuario importa equipos de un documento ERP
    cuyo RUT NO coincide con el de la ficha de cliente. Pide motivo justificado.
    """
    d = (request.get_json(silent=True) or {})
    motivo  = (d.get("motivo")  or "").strip()
    rut_doc = (d.get("rut_doc") or "").strip()
    tido    = (d.get("tido")    or "").strip()
    nudo    = (d.get("nudo")    or "").strip()
    if len(motivo) < 8:
        return jsonify({"error": "El motivo debe tener al menos 8 caracteres."}), 400
    detalle = f"Documento {tido} {nudo} (RUT cliente doc: {rut_doc}) — Motivo: {motivo}"
    _mant_log("cliente", cid, "import_rut_mismatch", detalle)
    return jsonify({"ok": True})


# TIDOs válidos para listar como "documentos del cliente" (todos los G* + ventas)
# COV=Cotización, FCV=Factura, BLV=Boleta, NVI=Nota Interna, NVV=Nota Venta,
# GDV=Guía Despacho Venta, GDP=Guía Despacho Provisional, GTR=Guía Traslado,
# GRD=Guía Retiro/Devolución, FCO=Factura Compra
_RANDOM_TIDOS_VENTA = ('FCV','BLV','NVI','NVV','GDV','GDP','GTR','GRD','FCO','COV')


@app.route("/mantenciones/api/buscar-erp-sql", methods=["POST"])
@_mant_required
def mant_buscar_erp_sql():
    """
    Búsqueda inteligente de documentos en Random ERP via SQL Server directo.

    Detecta automáticamente el tipo de búsqueda según lo que escribió el usuario:
      - Solo dígitos 7-9 chars  → RUT (busca todos los docs del cliente)
      - Solo dígitos 1-6 chars  → Número de documento (busca por NUDO)
      - Texto                   → Razón social (LIKE en NOKOEN)

    Maneja prefijos VD/WEB que se almacenan como NVV con NUDO prefijado.
    """
    d = request.get_json(silent=True) or {}
    q = (d.get("q") or "").strip()
    if len(q) < 3:
        return jsonify({"error": "Mínimo 3 caracteres"}), 400

    pool = _random_sql_pool()
    if pool is None:
        return jsonify({
            "error": "Conexión a Random ERP no configurada. Pídele al admin que setee RANDOM_SQL_* en Railway.",
            "documentos": [], "sin_conexion": True
        }), 200

    # Normalizar query. El ERP guarda el RUT base (MAEEN.RTEN / ENDO) SIN dígito
    # verificador, así que para RUT buscamos por el CUERPO. Aceptamos RUT con DV
    # numérico o K. Daniel 30/05/2026: '77.017.350-K' debe encontrar lo mismo
    # que '77017350' (antes la K rompía la detección y caía a búsqueda por nombre).
    q_clean   = q.replace(".", "").replace(" ", "").replace("-", "").upper()
    is_digits = q_clean.isdigit()
    rut_base  = _rut_cuerpo(q)            # cuerpo sin DV, ej '77017350'
    # Parece RUT si el cuerpo es numérico y: tiene >=7 dígitos, o trae DV (guión/K).
    parece_rut = rut_base.isdigit() and (
        len(rut_base) >= 7 or (len(rut_base) >= 6 and ("-" in q or q_clean.endswith("K"))))
    tidos_in  = "','".join(_RANDOM_TIDOS_VENTA)

    docs = []
    modo = ""
    try:
        # ── Modo 1: RUT (busca todos los docs del cliente por su CUERPO) ──
        if parece_rut:
            modo = "rut"
            docs = _random_sql_query(f"""
                SELECT TOP 100
                    e.IDMAEEDO, e.TIDO, e.NUDO, e.ENDO,
                    e.FEEMDO, e.VANEDO, e.VAIVDO, e.VABRDO,
                    e.ESPGDO, e.ESDO,
                    en.NOKOEN AS razon_social,
                    en.RTEN   AS rut
                FROM MAEEDO e
                LEFT JOIN MAEEN en ON LTRIM(RTRIM(en.RTEN)) =
                      LEFT(LTRIM(RTRIM(e.ENDO)),
                           CHARINDEX('-', LTRIM(RTRIM(e.ENDO)) + '-') - 1)
                WHERE (e.ENDO LIKE %s OR e.ENDO LIKE %s)
                  AND e.TIDO IN ('{tidos_in}')
                ORDER BY e.FEEMDO DESC
            """, (f"{rut_base}%", f"{rut_base}-%")) or []

        # ── Modo 2: Número de documento (1-6 dígitos) ──────────
        if not docs and is_digits and 1 <= len(q_clean) <= 7:
            modo = "numero"
            # NUDO en MAEEDO se guarda con padding de ceros (10 chars) o con prefijo VD/WEB
            nudo_padded = q_clean.zfill(10)
            nudo_vd     = f"VD{q_clean.zfill(8)}"
            nudo_web    = f"WEB{q_clean.zfill(7)}"
            docs = _random_sql_query(f"""
                SELECT TOP 50
                    e.IDMAEEDO, e.TIDO, e.NUDO, e.ENDO,
                    e.FEEMDO, e.VANEDO, e.VAIVDO, e.VABRDO,
                    e.ESPGDO, e.ESDO,
                    en.NOKOEN AS razon_social,
                    en.RTEN   AS rut
                FROM MAEEDO e
                LEFT JOIN MAEEN en ON LTRIM(RTRIM(en.RTEN)) =
                      LEFT(LTRIM(RTRIM(e.ENDO)),
                           CHARINDEX('-', LTRIM(RTRIM(e.ENDO)) + '-') - 1)
                WHERE e.NUDO IN (%s, %s, %s)
                  AND e.TIDO IN ('{tidos_in}')
                ORDER BY e.FEEMDO DESC
            """, (nudo_padded, nudo_vd, nudo_web)) or []

        # ── Modo 3: Razón social (texto) ───────────────────────
        # Estrategia 2-pasos para evitar JOIN calculado lento:
        #   3a) Buscar primero los RUTs en MAEEN (tabla chica, índice por NOKOEN)
        #   3b) Luego traer documentos por ENDO IN (rut1-N, rut2-N, ...)
        if not docs and not is_digits:
            modo = "nombre"
            q_like = f"%{q.upper()}%"
            # 3a) RUTs que coinciden con el nombre buscado
            ruts = _random_sql_query("""
                SELECT TOP 20 LTRIM(RTRIM(RTEN)) AS rut, LTRIM(RTRIM(NOKOEN)) AS razon
                FROM MAEEN
                WHERE UPPER(NOKOEN) LIKE %s AND TIEN IN ('C','A')
            """, (q_like,)) or []
            if ruts:
                # 3b) Construir IN(...) seguro (los valores vienen de MAEEN, no del usuario)
                rut_map = {r['rut']: r['razon'] for r in ruts}
                # ENDO en MAEEDO incluye DV (formato 65206047-N), generamos patrones LIKE
                like_clauses = " OR ".join(["e.ENDO LIKE %s"] * len(rut_map))
                params = tuple(f"{rut}%" for rut in rut_map.keys())
                docs_raw = _random_sql_query(f"""
                    SELECT TOP 50
                        e.IDMAEEDO, e.TIDO, e.NUDO, e.ENDO,
                        e.FEEMDO, e.VANEDO, e.VAIVDO, e.VABRDO,
                        e.ESPGDO, e.ESDO
                    FROM MAEEDO e
                    WHERE ({like_clauses})
                      AND e.TIDO IN ('{tidos_in}')
                    ORDER BY e.FEEMDO DESC
                """, params) or []
                # Enriquecer con razón social mapeada por prefijo de RUT
                for r in docs_raw:
                    endo = (r.get("ENDO") or "").strip()
                    rut_clean = endo.split("-")[0] if "-" in endo else endo
                    r["rut"] = rut_clean
                    r["razon_social"] = rut_map.get(rut_clean, "")
                docs = docs_raw
    except PermissionError as pe:
        return jsonify({"error": f"Bloqueado por seguridad: {pe}"}), 403

    # Formatear respuesta
    out = []
    for r in docs:
        nudo_raw = (r.get("NUDO") or "").strip()
        tido_raw = (r.get("TIDO") or "").strip()
        # Detectar prefijo VD/WEB en NUDO (esos se guardan como TIDO=NVV)
        tido_display = tido_raw
        if tido_raw == "NVV" and nudo_raw.startswith("VD"):
            tido_display = "VD"
            nudo_display = nudo_raw[2:].lstrip("0") or "0"
        elif tido_raw == "NVV" and nudo_raw.startswith("WEB"):
            tido_display = "WEB"
            nudo_display = nudo_raw[3:].lstrip("0") or "0"
        else:
            nudo_display = nudo_raw.lstrip("0") or "0"

        fe = r.get("FEEMDO")
        out.append({
            "idmaeedo":     r.get("IDMAEEDO"),
            "tido":         tido_raw,                  # tido real para fetch detalle
            "nudo":         nudo_raw,                  # nudo real para fetch detalle
            "tido_display": tido_display,              # para mostrar al usuario
            "nudo_display": nudo_display,
            "rut":          (r.get("rut")  or r.get("ENDO") or "").strip(),
            "razon_social": (r.get("razon_social") or "").strip().title(),
            "fecha":        fe.strftime("%d/%m/%Y") if fe else "",
            "fecha_iso":    fe.strftime("%Y-%m-%d") if fe else "",
            "valor_neto":   float(r.get("VANEDO") or 0),
            "valor_total":  float(r.get("VABRDO") or 0),
            "estado_pago":  (r.get("ESPGDO") or "").strip(),
        })

    return jsonify({
        "ok": True,
        "modo": modo,
        "documentos": out,
        "count": len(out),
        "query": q,
    })


@app.route("/mantenciones/api/clientes/<int:cid>/documentos-erp")
@_mant_required
def mant_documentos_por_rut(cid):
    """Busca docs del cliente en ERP.

    Estrategia robusta:
      1. Intenta SQL directo a Random (rápido pero NO funciona desde Railway)
      2. Si falla → fallback a REST API (probando RUT en distintas variantes)
      3. Si RUT no encuentra nada → buscar por NOMBRE (razon_social) con LIKE
      4. Devolver agregado por documento
    """
    cliente = mysql_fetchone("SELECT rut, razon_social FROM mant_clientes WHERE id=%s", (cid,))
    if not cliente or not cliente.get("rut"):
        # Si no hay RUT pero sí razón social, intentar por nombre via REST
        if cliente and cliente.get("razon_social"):
            return _docs_erp_por_nombre_rest(cliente["razon_social"], cid)
        return jsonify({"sin_rut": True, "documentos": []})

    rut = cliente["rut"].strip()

    # ── Normalización: extraer solo dígitos + K ─────────────────────────
    rut_digits = re.sub(r"[^0-9kK]", "", rut).upper()   # ej: "760087564"
    dv         = rut_digits[-1] if len(rut_digits) > 1 else ""
    cuerpo     = rut_digits[:-1] if len(rut_digits) > 1 else rut_digits  # sin DV

    # ── Formatos que el ERP podría estar usando (basado en observación) ──
    # El ERP típicamente almacena RUTs sin puntos, y frecuentemente sin DV.
    candidatos = set(filter(None, [
        cuerpo,                       # 76008756   ← más común en ERP
        rut_digits,                   # 760087564  (con DV pegado)
        f"{cuerpo}-{dv}" if dv else None,  # 76008756-4
        f"{cuerpo}-{dv.lower()}" if dv else None,  # 76008756-k (minúscula)
        rut.strip(),                  # tal como está guardado en nuestro sistema
    ]))
    placeholders = ",".join(["%s"] * len(candidatos))
    params_rut   = list(candidatos)

    # ── PRIMARIO: SQL Server vía _random_sql_query ─────────────────────
    # FIX 2026-05-19: el ERP Random es SQL Server (cloud.random.cl:8058,
    # vía pymssql). La tabla HEBDOC no existe en su schema — la lógica
    # queda en MAEEDO/MAEDDO/MAEEN. Si el SQL falla (timeouts, conexión)
    # caemos a la REST API como antes (es lo que funciona desde Railway).
    tidos_list   = list(ERP_TIDOS_DOCUMENTOS_CLIENTE)
    tidos_in_p   = ",".join(["%s"] * len(tidos_list))

    # Para JOIN con MAEEN.RTEN: extraer base sin DV del ENDO.
    # Patrones a probar por ENDO: por cada candidato, "candidato%" cubre
    # "65206047", "65206047-1", "65206047-K", etc.
    endo_like_clauses = " OR ".join(["e.ENDO LIKE %s"] * len(candidatos))
    endo_like_params  = tuple(f"{c}%" for c in candidatos)

    sql_docs = f"""
        SELECT TOP 500
               LTRIM(RTRIM(COALESCE(en.NOKOENAMP, en.NOKOEN, ''))) AS razon_social,
               LTRIM(RTRIM(COALESCE(e.ENDO, ''))) AS rut,
               LTRIM(RTRIM(COALESCE(e.TIDO, ''))) AS tipo_doc,
               LTRIM(RTRIM(COALESCE(e.NUDO, ''))) AS num_doc,
               e.FEEMDO                            AS fecha,
               LTRIM(RTRIM(COALESCE(l.KOPRCT, ''))) AS sku,
               LTRIM(RTRIM(COALESCE(l.NOKOPR, ''))) AS producto,
               COALESCE(l.CAPRCO1, 0)              AS cantidad
          FROM MAEEDO e
          LEFT JOIN MAEDDO l ON l.IDMAEEDO = e.IDMAEEDO
          LEFT JOIN MAEEN en ON LTRIM(RTRIM(en.RTEN)) =
                CASE
                  WHEN CHARINDEX('-', e.ENDO) > 0
                    THEN LTRIM(RTRIM(SUBSTRING(e.ENDO, 1, CHARINDEX('-', e.ENDO) - 1)))
                  ELSE LTRIM(RTRIM(COALESCE(e.ENDO, '')))
                END
         WHERE LTRIM(RTRIM(COALESCE(e.TIDO, ''))) IN ({tidos_in_p})
           AND ({endo_like_clauses})
           AND (e.ESDO IS NULL OR LTRIM(RTRIM(e.ESDO)) <> 'NULO')
         ORDER BY e.FEEMDO DESC
    """

    rows = None
    sql_error = None
    try:
        rows = _random_sql_query(
            sql_docs,
            tuple(tidos_list) + endo_like_params,
            max_rows=2000,
        )
    except PermissionError as pe:
        sql_error = f"seguridad SQL: {pe}"
        print(f"[mant-docs-por-rut-sql] bloqueado por seguridad: {pe}", flush=True)
        rows = None
    except Exception as e:
        sql_error = str(e)
        print(f"[mant-docs-por-rut-sql] error: {e}", flush=True)
        rows = None

    # Si SQL devolvió None (pool sin configurar / error de conexión / excepción)
    # caemos a la REST API graceful — esa funciona desde Railway.
    if rows is None:
        return _docs_erp_por_rut_rest(rut, cliente.get("razon_social"), cid)

    try:
        docs = {}
        for r in rows:
            tipo_doc = (r.get("tipo_doc") or "").strip()
            num_doc  = (r.get("num_doc")  or "").strip()
            if not tipo_doc or not num_doc:
                continue
            key = f"{tipo_doc}|{num_doc}"
            if key not in docs:
                fe = r.get("fecha")
                docs[key] = {
                    "razon_social": (r.get("razon_social") or "").strip(),
                    "rut":          (r.get("rut")          or "").strip(),
                    "tipo_doc":     tipo_doc,
                    "num_doc":      num_doc.lstrip("0") or num_doc,
                    "num_doc_raw":  num_doc,
                    "fecha":        str(fe)[:10] if fe else "",
                    "lineas":       []
                }
            nom = (r.get("producto") or "").strip()
            sku = (r.get("sku")      or "").strip().upper()
            if nom or sku:
                try:
                    qty = int(float(r.get("cantidad") or 1))
                except Exception:
                    qty = 1
                docs[key]["lineas"].append({
                    "sku":      sku,
                    "nombre":   nom or sku,
                    "cantidad": qty,
                })

        # Conteo por tipo de documento — diagnóstico visual al usuario
        conteo_por_tipo = {}
        for doc in docs.values():
            t = doc["tipo_doc"]
            conteo_por_tipo[t] = conteo_por_tipo.get(t, 0) + 1

        return jsonify({
            "ok":            True,
            "rut":           rut,
            "cliente":       cliente["razon_social"],
            "documentos":    list(docs.values()),
            "total":         len(docs),
            "conteo_por_tipo": conteo_por_tipo,
            "tipos_buscados": list(ERP_TIDOS_DOCUMENTOS_CLIENTE),
            "filas_erp":     len(rows),
            "fuente":        "sql_server",
        })
    except Exception as e:
        print(f"[mant-docs-por-rut-sql] post-process error: {e}", flush=True)
        # Cualquier error procesando filas → caer a REST API
        return _docs_erp_por_rut_rest(rut, cliente.get("razon_social"), cid)


