# ══════════════════════════════════════════════════════════════════════
#  FINANZAS DEL CLIENTE — agregados de ingresos/costos/margen
# ══════════════════════════════════════════════════════════════════════

@app.route("/mantenciones/api/clientes/<int:cid>/finanzas")
@_mant_required
def mant_cliente_finanzas(cid):
    """Devuelve agregados financieros del cliente para los últimos N meses."""
    meses = int(request.args.get("meses") or 12)
    if meses <= 0:
        fecha_corte = "1900-01-01"
    else:
        fecha_corte = (datetime.now().date() - timedelta(days=meses*31)).isoformat()

    # Repuestos
    rep_rows = mysql_fetchall(
        "SELECT tipo, cantidad, costo_unitario, precio_venta, fecha "
        "FROM mant_repuestos WHERE cliente_id=%s AND (fecha IS NULL OR fecha >= %s)",
        (cid, fecha_corte)
    )
    rep_venta_total = 0
    rep_costo_total = 0
    garantia_costo  = 0
    for r in rep_rows:
        c = float(r["cantidad"] or 0)
        cu = float(r["costo_unitario"] or 0)
        pv = float(r["precio_venta"] or 0)
        if r["tipo"] == "venta":
            rep_venta_total += pv * c
            rep_costo_total += cu * c
        elif r["tipo"] == "garantia":
            garantia_costo += cu * c
        else:  # reposicion / consumo
            rep_costo_total += cu * c

    # Visitas con costo
    visitas = mysql_fetchall(
        "SELECT tipo, estado, costo, fecha_programada FROM mant_visitas "
        "WHERE cliente_id=%s AND fecha_programada >= %s",
        (cid, fecha_corte)
    )
    visitas_costo = sum(float(v["costo"] or 0) for v in visitas if v.get("costo"))
    visitas_count = len([v for v in visitas if v.get("estado")=="completada"])

    # Contrato — estimación lineal (monto_mensual × meses_vigentes)
    contrato_estimado = 0
    contratos = mysql_fetchall(
        "SELECT monto_mensual, fecha_inicio, fecha_vencimiento, es_indefinido "
        "FROM mant_contratos WHERE cliente_id=%s AND estado='vigente'", (cid,)
    )
    hoy = datetime.now().date()
    for ct in contratos:
        m = float(ct["monto_mensual"] or 0)
        if m <= 0: continue
        fi = ct.get("fecha_inicio") or hoy
        if isinstance(fi, datetime): fi = fi.date()
        meses_vigentes = max(0, min(meses or 12, ((hoy.year - fi.year)*12 + hoy.month - fi.month)))
        contrato_estimado += m * meses_vigentes

    ingresos_total = rep_venta_total + visitas_costo + contrato_estimado
    costos_total   = rep_costo_total + garantia_costo
    margen         = ingresos_total - costos_total
    ticket_prom    = (ingresos_total / visitas_count) if visitas_count else 0

    # Por mes (últimos 12)
    months_es = ['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic']
    por_mes = []
    for i in range(11,-1,-1):
        ref_year, ref_month = hoy.year, hoy.month - i
        while ref_month <= 0: ref_month += 12; ref_year -= 1
        ingreso_mes = 0
        for r in rep_rows:
            if r.get("fecha") and r["tipo"]=="venta":
                fr = r["fecha"]
                if isinstance(fr, datetime): fr = fr.date()
                if fr.year == ref_year and fr.month == ref_month:
                    ingreso_mes += float(r["precio_venta"] or 0) * float(r["cantidad"] or 0)
        for v in visitas:
            if v.get("fecha_programada") and v.get("estado")=="completada":
                fv = v["fecha_programada"]
                if isinstance(fv, datetime): fv = fv.date()
                if fv.year == ref_year and fv.month == ref_month:
                    ingreso_mes += float(v["costo"] or 0)
        por_mes.append({"label": months_es[ref_month-1], "year": ref_year, "ingreso": round(ingreso_mes,2)})

    return jsonify({
        "ingresos_total":  round(ingresos_total, 2),
        "costos_total":    round(costos_total, 2),
        "margen":          round(margen, 2),
        "garantia_costo":  round(garantia_costo, 2),
        "visitas_count":   visitas_count,
        "ticket_promedio": round(ticket_prom, 2),
        "repuestos_venta": round(rep_venta_total, 2),
        "visitas_costo":   round(visitas_costo, 2),
        "contrato_estimado": round(contrato_estimado, 2),
        "por_mes":         por_mes,
    })


# ══════════════════════════════════════════════════════════════════════
#  DOCUMENTOS DEL CLIENTE — listado unificado de adjuntos
# ══════════════════════════════════════════════════════════════════════

@app.route("/mantenciones/api/clientes/<int:cid>/documentos")
@_mant_required
def mant_cliente_documentos(cid):
    """Devuelve TODOS los documentos asociados al cliente (multi-fuente).

    SEGURIDAD 2026-05-26: solo superadmin puede ver botón de descarga o
    eliminar. Otros roles (ejecutivo, técnico) reciben deletable=false y
    downloadable=false. El flag se respeta en frontend; además, los
    endpoints destructivos validan server-side.
    """
    items = []
    es_super = bool((g.permissions or {}).get("superadmin"))

    # 1. Adjuntos (contratos + multi-archivo + externos + anexos)
    rows = mysql_fetchall(
        "SELECT id,tipo,subtipo_externo,nombre,archivo_nombre,mime_type,tamaño_bytes,"
        "       cloudinary_url,cloudinary_public_id,created_by,created_at "
        "  FROM mant_contrato_adjuntos WHERE cliente_id=%s", (cid,)
    )
    for r in rows:
        # URL: SIEMPRE usar nuestro proxy (fuerza inline + valida superadmin
        # en download). NO exponer la URL directa de Cloudinary.
        url = f"/mantenciones/api/adjuntos/{r['id']}/archivo"
        fuente_label = "Adjunto"
        if r.get("tipo") == "externo":
            fuente_label = "Doc. Externo"
            if r.get("subtipo_externo"):
                fuente_label += f" · {r['subtipo_externo'].replace('_',' ').title()}"
        elif r.get("tipo") == "anexo":
            fuente_label = "Anexo Contrato"
        # Mime hint para que el visor decida estrategia rápido
        _arch_nombre = r.get("archivo_nombre") or ""
        _ext = _arch_nombre.rsplit(".", 1)[-1].lower() if "." in _arch_nombre else ""
        _mime_hint = {
            "pdf": "application/pdf",
            "jpg": "image/jpeg", "jpeg": "image/jpeg",
            "png": "image/png", "gif": "image/gif", "webp": "image/webp",
            "docx": "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
            "doc": "application/msword",
            "xlsx": "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
            "xls": "application/vnd.ms-excel",
        }.get(_ext, r.get("mime_type") or "")
        _archivo_tipo = {
            "pdf": "pdf",
            "jpg": "imagen", "jpeg": "imagen", "png": "imagen",
            "gif": "imagen", "webp": "imagen",
            "docx": "docx", "doc": "doc",
            "xlsx": "xlsx", "xls": "xls",
        }.get(_ext, "")
        items.append({
            "kind":   "adjunto",
            "id":     r["id"],
            "tipo":   r["tipo"],
            "subtipo_externo": r.get("subtipo_externo"),
            "nombre": r["nombre"] or r.get("archivo_nombre"),
            "url":    url,
            "mime_type":    _mime_hint,
            "archivo_tipo": _archivo_tipo,
            "size_kb": round((r.get("tamaño_bytes") or 0)/1024) if r.get("tamaño_bytes") else None,
            "created_by": r.get("created_by"),
            "created_at": str(r["created_at"])[:16] if r.get("created_at") else "",
            "fuente": fuente_label,
            "persistente": bool(r.get("cloudinary_url")),
            "deletable":    es_super,   # solo superadmin
            "downloadable": es_super,   # solo superadmin
            "has_cloud":    bool(r.get("cloudinary_url")),
        })

    # 2. Reportes con HTML guardado
    rep_rows = mysql_fetchall(
        "SELECT id, ticket_num, asunto, html_path, html_generated_at, created_by "
        "FROM mant_reportes WHERE cliente_id=%s AND html_path IS NOT NULL", (cid,)
    )
    for r in rep_rows:
        items.append({
            "kind":   "reporte_html",
            "id":     r["id"],
            "tipo":   "reporte",
            "nombre": f"Informe {r.get('ticket_num') or r['id']} — {r.get('asunto') or 'Sin asunto'}",
            "url":    f"/static/{r['html_path']}",
            "mime_type": "text/html",
            "archivo_tipo": "html",
            "size_kb": None,
            "created_by": r.get("created_by"),
            "created_at": str(r["html_generated_at"])[:16] if r.get("html_generated_at") else "",
            "fuente": "Reporte (HTML)",
            "deletable":    False,
            "downloadable": es_super,
            "has_cloud":    False,
        })

    # 3. Contratos — archivo principal de cada contrato del cliente.
    #    FIX 2026-05-13: antes solo se listaban contratos que tenían archivo
    #    (archivo_path o cloudinary_url). Ahora listamos TODOS para que el tab
    #    "Documentos" sea espejo completo del tab "Contratos". Si un contrato
    #    no tiene archivo, lo mostramos igualmente con un flag `sin_archivo`
    #    para que el frontend pueda renderizar un placeholder informativo
    #    en vez de un link roto.
    # FIX 2026-05-14: la columna es fecha_vencimiento (no vencimiento).
    # El typo previo causaba HTTP 500 al cargar el tab Documentos.
    ct_rows = mysql_fetchall(
        "SELECT id,nombre,archivo_nombre,archivo_path,archivo_tipo,"
        "       cloudinary_url,cloudinary_public_id,estado,fecha_vencimiento,"
        "       created_by,created_at "
        "  FROM mant_contratos WHERE cliente_id=%s "
        " ORDER BY created_at DESC", (cid,)
    )
    for r in ct_rows:
        tiene_archivo = bool(r.get("archivo_path") or r.get("cloudinary_url"))
        # Nombre: priorizar el dado por el usuario, luego archivo, luego ID
        nm = r.get("nombre") or r.get("archivo_nombre") or f"Contrato #{r['id']}"
        # Estado opcional como sufijo
        if r.get("estado"):
            estado_lbl = r["estado"].replace("_", " ").title()
            if estado_lbl not in nm:
                nm = f"{nm} ({estado_lbl})"
        # Hint MIME para el viewer del frontend.
        # Como la URL es /api/contratos/X/archivo (sin extensión visible),
        # el frontend no puede detectar tipo desde la URL. Por eso le
        # pasamos `mime_type` explícito basado en archivo_tipo de la BD.
        _tipo_archivo_bd = (r.get("archivo_tipo") or "").lower()
        if _tipo_archivo_bd == "pdf":
            _mime = "application/pdf"
        elif _tipo_archivo_bd in ("word", "doc", "docx"):
            _mime = "application/vnd.openxmlformats-officedocument.wordprocessingml.document"
        else:
            _mime = ""
        items.append({
            "kind":   "contrato_principal",
            "id":     r["id"],
            "tipo":   "contrato",
            "nombre": nm,
            # Si tiene archivo: usar endpoint /contratos/<id>/archivo (proxy inline).
            # Si NO tiene: url null + flag sin_archivo para que el frontend muestre placeholder.
            "url":    (f"/mantenciones/api/contratos/{r['id']}/archivo" if tiene_archivo else None),
            "mime_type": _mime,
            "archivo_tipo": _tipo_archivo_bd,  # hint para el visor del frontend
            "size_kb": None,
            "created_by": r.get("created_by"),
            "created_at": str(r["created_at"])[:16] if r.get("created_at") else "",
            "fuente": "Contrato principal",
            "persistente": bool(r.get("cloudinary_url")),
            "deletable":    es_super,
            "downloadable": es_super,
            "has_cloud":    bool(r.get("cloudinary_url")),
            "sin_archivo": (not tiene_archivo),
        })

    # Ordenar por created_at desc
    items.sort(key=lambda x: x.get("created_at",""), reverse=True)
    return jsonify(items)


@app.route("/mantenciones/api/clientes/<int:cid>/evidencias", methods=["GET"])
@_mant_required
def mant_cliente_evidencias(cid):
    """FASE 6 — Tab "Evidencias" de la ficha del cliente.
    Devuelve todas las fotos del cliente unificadas en timeline:
    - mant_visita_fotos (evidencia de OTs ejecutadas)
    - mant_maquina_fotos (galería permanente de equipos)
    - mant_levantamiento_fotos (levantamientos fotográficos)

    Cada foto incluye: url Cloudinary, tipo, descripción, fecha, usuario,
    equipo al que pertenece (si aplica), origen (OT/levantamiento/galería).

    Filtros opcionales:
      ?origen=ot|levantamiento|galeria
      ?maquina_id=N (solo fotos de ese equipo)
    """
    origen = (request.args.get("origen") or "").strip().lower()
    maquina_id = request.args.get("maquina_id")
    try: maquina_id = int(maquina_id) if maquina_id else None
    except Exception: maquina_id = None

    fotos = []

    # 1. Fotos de visitas/OT
    if not origen or origen == "ot":
        rows_vf = mysql_fetchall(
            "SELECT vf.id, vf.archivo_path, vf.cloudinary_url, vf.tipo_foto, "
            "       vf.descripcion, vf.tomada_por, vf.tomada_at, "
            "       vf.visita_id, vf.maquina_id, "
            "       v.numero_ot, v.titulo AS visita_titulo, v.tipo AS visita_tipo, "
            "       v.estado AS visita_estado, "
            "       m.nombre AS maquina_nombre, m.serie AS maquina_serie "
            "  FROM mant_visita_fotos vf "
            "  JOIN mant_visitas v ON v.id = vf.visita_id "
            "  LEFT JOIN mant_maquinas m ON m.id = vf.maquina_id "
            " WHERE v.cliente_id=%s "
            + (" AND vf.maquina_id=%s" if maquina_id else "")
            + " ORDER BY vf.tomada_at DESC LIMIT 500",
            ((cid, maquina_id) if maquina_id else (cid,))
        ) or []
        for r in rows_vf:
            url = r.get("cloudinary_url") or (f"/static/uploads/mantenciones/{r['archivo_path']}" if r.get("archivo_path") else "")
            if not url: continue
            fotos.append({
                "id": r["id"],
                "url": url,
                "tipo_foto": r.get("tipo_foto") or "general",
                "descripcion": r.get("descripcion") or "",
                "tomada_por": r.get("tomada_por") or "",
                "fecha": str(r["tomada_at"])[:16] if r.get("tomada_at") else "",
                "origen": "ot",
                "origen_label": f"OT {r.get('numero_ot') or '#'+str(r['visita_id'])}",
                "origen_url": f"/mantenciones/ot/{r['visita_id']}",
                "visita_titulo": r.get("visita_titulo") or "",
                "visita_tipo": r.get("visita_tipo") or "",
                "visita_estado": r.get("visita_estado") or "",
                "maquina_id": r.get("maquina_id"),
                "maquina_nombre": r.get("maquina_nombre") or "",
                "maquina_serie": r.get("maquina_serie") or "",
                "persistente": bool(r.get("cloudinary_url")),
            })

    # 2. Fotos de máquinas (galería permanente)
    if not origen or origen == "galeria":
        sql_mf = (
            "SELECT mf.id, mf.archivo_path, mf.cloudinary_url, mf.tipo_foto, "
            "       mf.descripcion, mf.tomada_por, mf.created_at, "
            "       mf.maquina_id, mf.levantamiento_id, "
            "       m.nombre AS maquina_nombre, m.serie AS maquina_serie "
            "  FROM mant_maquina_fotos mf "
            "  JOIN mant_maquinas m ON m.id = mf.maquina_id "
            " WHERE m.cliente_id=%s "
        )
        params_mf = [cid]
        if maquina_id:
            sql_mf += " AND mf.maquina_id=%s "
            params_mf.append(maquina_id)
        sql_mf += " ORDER BY mf.created_at DESC LIMIT 500"
        rows_mf = mysql_fetchall(sql_mf, tuple(params_mf)) or []
        for r in rows_mf:
            url = r.get("cloudinary_url") or (f"/static/uploads/mantenciones/{r['archivo_path']}" if r.get("archivo_path") else "")
            if not url: continue
            fotos.append({
                "id": r["id"],
                "url": url,
                "tipo_foto": r.get("tipo_foto") or "general",
                "descripcion": r.get("descripcion") or "",
                "tomada_por": r.get("tomada_por") or "",
                "fecha": str(r["created_at"])[:16] if r.get("created_at") else "",
                "origen": "galeria" if not r.get("levantamiento_id") else "levantamiento",
                "origen_label": (
                    f"Levantamiento #{r['levantamiento_id']}" if r.get("levantamiento_id")
                    else "Galería del equipo"
                ),
                "origen_url": (
                    f"/mantenciones/clientes/{cid}?lev={r['levantamiento_id']}"
                    if r.get("levantamiento_id") else f"/mantenciones/clientes/{cid}"
                ),
                "maquina_id": r.get("maquina_id"),
                "maquina_nombre": r.get("maquina_nombre") or "",
                "maquina_serie": r.get("maquina_serie") or "",
                "persistente": bool(r.get("cloudinary_url")),
            })

    # Ordenar timeline cronológico desc
    fotos.sort(key=lambda x: x.get("fecha", ""), reverse=True)

    # Estadísticas para badges en UI
    total = len(fotos)
    por_origen = {}
    por_maquina = {}
    for f_ in fotos:
        por_origen[f_["origen"]] = por_origen.get(f_["origen"], 0) + 1
        if f_.get("maquina_id"):
            mid = f_["maquina_id"]
            por_maquina[mid] = por_maquina.get(mid, 0) + 1

    return jsonify({
        "ok": True,
        "fotos": fotos[:500],  # límite duro
        "total": total,
        "por_origen": por_origen,
        "por_maquina": por_maquina,
    })


@app.route("/mantenciones/api/clientes/<int:cid>/documentos", methods=["POST"])
@_mant_required
def mant_cliente_documento_subir(cid):
    """Sube un documento suelto al cliente como adjunto general.

    Form fields:
      archivo:         file (requerido)
      tipo:            'contrato'|'imagen'|'reporte'|'otro'|'externo'|'anexo' (opcional)
      subtipo_externo: si tipo='externo'→'visita_externa'|'ot_externa'|'otro'
                       si tipo='anexo'→'anexo_contrato'
      nombre:          nombre legible (sino usa filename)

    Storage: Cloudinary primero (persistente), filesystem como fallback.
    """
    f = request.files.get("archivo")
    if not f or not f.filename: return jsonify({"error":"Sin archivo"}), 400
    ext = f.filename.rsplit(".",1)[-1].lower() if "." in f.filename else ""
    if ext not in ALLOWED_ADJUNTO: return jsonify({"error":"Tipo no permitido"}), 400

    # Tipo explícito desde form
    tipo_form = (request.form.get("tipo") or "").strip().lower()
    if tipo_form in ("contrato","imagen","solicitud","cotizacion","reporte","otro","externo","anexo"):
        tipo = tipo_form
    else:
        tipo = ALLOWED_ADJUNTO_TIPOS.get(ext, "otro")
    subtipo_externo = (request.form.get("subtipo_externo") or "").strip()[:80] or None

    fname = secure_filename(f"cli{cid}_{int(time.time())}_{f.filename}")

    # ── Cloudinary primero ───────────────────────────────────────────
    cloud_url = None
    cloud_pid = None
    if _CLD_READY:
        try:
            f.stream.seek(0)
            folder = f"ilus/contratos/adjuntos/{tipo}"
            public_id = f"cli_{cid}_{int(time.time())}"
            res = _cloud_upload_raw(f.stream, public_id, folder=folder)
            cloud_url = res["url"]
            cloud_pid = res["public_id"]
            print(f"[mant_documento] Cloudinary OK cid={cid} tipo={tipo}", flush=True)
        except Exception as e_cld:
            print(f"[mant_documento] Cloudinary FAIL cid={cid}: {e_cld}", flush=True)

    # ── Filesystem fallback ──────────────────────────────────────────
    try:
        f.stream.seek(0)
    except Exception:
        pass
    fpath = os.path.join(MANT_UPLOADS, fname)
    size = 0
    try:
        f.save(fpath)
        size = os.path.getsize(fpath)
    except Exception as e_save:
        if not cloud_url:
            return jsonify({"error": f"No se pudo guardar: {e_save}"}), 500

    nombre = (request.form.get("nombre") or f.filename)[:300]

    # Crear contrato dummy si no existe (para satisfacer FK)
    ct = mysql_fetchone("SELECT id FROM mant_contratos WHERE cliente_id=%s ORDER BY id LIMIT 1", (cid,))
    if not ct:
        conn = get_mysql()
        with conn.cursor() as cur:
            cur.execute(
                "INSERT INTO mant_contratos (cliente_id,nombre,estado,es_indefinido,created_by) "
                "VALUES (%s,'Contenedor de documentos','indefinido',1,%s)",
                (cid, current_username())
            )
            ct_id = cur.lastrowid
        conn.commit(); conn.close()
    else:
        ct_id = ct["id"]

    mysql_execute(
        "INSERT INTO mant_contrato_adjuntos "
        "(contrato_id,cliente_id,tipo,subtipo_externo,nombre,archivo_nombre,archivo_path,"
        " cloudinary_url,cloudinary_public_id,mime_type,tamaño_bytes,created_by) "
        "VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)",
        (ct_id, cid, tipo, subtipo_externo, nombre, fname, fname,
         cloud_url, cloud_pid, f.mimetype or '', size, current_username())
    )
    _mant_log("documento", cid, "subir", f"{tipo} · {nombre}")
    return jsonify({
        "ok": True,
        "tipo": tipo,
        "subtipo_externo": subtipo_externo,
        "persistente": bool(cloud_url),
        "storage": "cloudinary" if cloud_url else "filesystem"
    })


@app.route("/mantenciones/api/documentos/<kind>/<int:did>", methods=["DELETE"])
@_mant_required
def mant_documento_del(kind, did):
    if kind == "adjunto":
        adj = mysql_fetchone(
            "SELECT archivo_nombre, nombre, cliente_id FROM mant_contrato_adjuntos WHERE id=%s",
            (did,)
        )
        if adj:
            try:
                fp = os.path.join(MANT_UPLOADS, adj["archivo_nombre"])
                if os.path.exists(fp): os.remove(fp)
            except Exception: pass
            mysql_execute("DELETE FROM mant_contrato_adjuntos WHERE id=%s",(did,))
            if adj.get("cliente_id"):
                _mant_log("cliente", adj["cliente_id"], "documento_eliminado",
                          adj.get("nombre") or f"adjunto #{did}")
            return jsonify({"ok":True})
    return jsonify({"error":"Tipo no eliminable o no encontrado"}), 400


# ══════════════════════════════════════════════════════════════════════
#  EMAIL MANUAL — enviar email arbitrario al cliente con trazabilidad
# ══════════════════════════════════════════════════════════════════════

@app.route("/mantenciones/api/clientes/<int:cid>/email-manual", methods=["POST"])
@_mant_required
def mant_email_manual(cid):
    d = request.get_json(silent=True) or {}
    destinatario = (d.get("destinatario") or "").strip()
    asunto       = (d.get("asunto") or "").strip()
    mensaje      = (d.get("mensaje") or "").strip()
    if not (destinatario and asunto and mensaje):
        return jsonify({"error":"Completa destinatario, asunto y mensaje"}), 400
    if "@" not in destinatario:
        return jsonify({"error":"Email no válido"}), 400

    cliente = mysql_fetchone("SELECT razon_social FROM mant_clientes WHERE id=%s",(cid,))
    if not cliente: return jsonify({"error":"Cliente no encontrado"}), 404

    # Envolver SIEMPRE con la plantilla corporativa (formato del preview)
    body = (
        f"<p>{mensaje.replace(chr(10), '<br>')}</p>"
        f"<hr style='border:none;border-top:1px solid #e5e7eb;margin:18px 0'>"
        f"<p style='font-size:.78rem;color:#9ca3af'>Enviado por {current_username()}</p>"
    )
    html = _comm_render_email_document(asunto, body, cliente.get("razon_social",""))

    sent = False; err = None
    try:
        sent = _send_ilus_email(destinatario, asunto, html,
                                evento="mant_sla_manual", modulo="mantenciones")
    except Exception as exc: err = str(exc)

    # Registrar en notificaciones
    try:
        mysql_execute(
            "INSERT INTO mant_notificaciones "
            "(cliente_id,entidad,entidad_id,tipo,titulo,mensaje,canal,estado,destinatario,fecha_envio,created_by) "
            "VALUES (%s,'cliente',%s,'sla',%s,%s,'email',%s,%s,NOW(),%s)",
            (cid, cid, asunto, mensaje[:1000],
             'enviada' if sent else 'fallida', destinatario, current_username())
        )
    except Exception: pass
    _mant_log("cliente", cid, "email_manual",
              f"to={destinatario} ok={sent} err={err or '-'}")
    return jsonify({"ok": bool(sent), "error": err})


# ── NOTIFICACIONES ────────────────────────────────────────────────────

@app.route("/mantenciones/api/notificaciones")
@_mant_required
def mant_notif_list():
    """Lista notificaciones (todas o filtradas por cliente)."""
    cid    = request.args.get("cliente_id")
    estado = request.args.get("estado","")
    sql    = ("SELECT n.*,c.razon_social FROM mant_notificaciones n "
              "LEFT JOIN mant_clientes c ON c.id=n.cliente_id WHERE 1=1")
    params = []
    if cid:    sql += " AND n.cliente_id=%s"; params.append(int(cid))
    if estado: sql += " AND n.estado=%s";    params.append(estado)
    sql += " ORDER BY n.created_at DESC LIMIT 100"
    rows = mysql_fetchall(sql, tuple(params))
    def _fmt(r):
        d = dict(r)
        d["created_at"] = str(d["created_at"])[:16] if d.get("created_at") else ""
        return d
    return jsonify([_fmt(r) for r in rows])


@app.route("/mantenciones/api/notificaciones", methods=["POST"])
@_mant_required
def mant_notif_crear():
    """Crea una notificación manualmente."""
    d = request.get_json(silent=True) or {}
    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            cur.execute(
                """INSERT INTO mant_notificaciones
                   (cliente_id,entidad,entidad_id,tipo,titulo,mensaje,canal,
                    destinatario,estado,created_by)
                   VALUES (%s,%s,%s,%s,%s,%s,%s,%s,'pendiente',%s)""",
                (d.get("cliente_id"), d.get("entidad","cliente"),
                 d.get("entidad_id"), d.get("tipo","otro"),
                 d.get("titulo",""), d.get("mensaje",""),
                 d.get("canal","sistema"), d.get("destinatario",""),
                 current_username())
            )
            nid = cur.lastrowid
        conn.commit()
        return jsonify({"ok":True,"id":nid})
    finally:
        conn.close()


@app.route("/mantenciones/api/notificaciones/<int:nid>", methods=["PUT"])
@_mant_required
def mant_notif_update(nid):
    """Cambia estado de una notificación (leida, ignorada, enviada)."""
    d = request.get_json(silent=True) or {}
    estado = d.get("estado","leida")
    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            extra = ", fecha_lectura=%s" if estado in ("leida","ignorada") else ""
            vals  = ([datetime.now()] if extra else []) + [estado, nid]
            cur.execute(
                f"UPDATE mant_notificaciones SET estado=%s{extra} WHERE id=%s",
                [estado] + ([datetime.now()] if extra else []) + [nid]
            )
        conn.commit()
        return jsonify({"ok":True})
    finally:
        conn.close()


@app.route("/mantenciones/api/notificaciones/<int:nid>/enviar", methods=["POST"])
@_mant_required
def mant_notif_enviar(nid):
    """Envía la notificación por email usando Resend."""
    notif = mysql_fetchone(
        "SELECT n.*,c.contacto_email,c.razon_social FROM mant_notificaciones n "
        "LEFT JOIN mant_clientes c ON c.id=n.cliente_id WHERE n.id=%s", (nid,)
    )
    if not notif: return jsonify({"error":"No encontrado"}), 404

    destinatario = notif.get("destinatario") or notif.get("contacto_email","")
    if not destinatario:
        return jsonify({"error":"Sin email destinatario"}), 400

    html_body = f"""
    <div style="font-family:sans-serif;max-width:600px;margin:auto">
      <div style="background:#CC0000;padding:20px;text-align:center">
        <h2 style="color:#fff;margin:0">ILUS Sport & Health</h2>
      </div>
      <div style="padding:24px;background:#f9f9f9">
        <h3 style="color:#111">{notif['titulo']}</h3>
        <p style="color:#374151;line-height:1.6">{notif['mensaje']}</p>
        <p style="color:#6b7280;font-size:.85rem">
          Cliente: <strong>{notif.get('razon_social','')}</strong>
        </p>
      </div>
      <div style="padding:12px;text-align:center;color:#9ca3af;font-size:.78rem">
        ILUS Sport & Health Solution SPA · Sistema de Mantenciones
      </div>
    </div>"""

    try:
        # Pasa por el wrapper para respetar kill switch global + llave por módulo
        resultado = _send_ilus_email(
            destinatario,
            f"[ILUS Mantenciones] {notif['titulo']}",
            html_body,
            evento="mant_notificacion", modulo="mantenciones",
        )
        conn = get_mysql()
        try:
            with conn.cursor() as cur:
                cur.execute(
                    "UPDATE mant_notificaciones SET estado='enviada',fecha_envio=%s WHERE id=%s",
                    (datetime.now(), nid)
                )
            conn.commit()
        finally:
            conn.close()
        return jsonify({"ok":True})
    except Exception as e:
        return jsonify({"error":str(e)}), 500


@app.route("/mantenciones/notificaciones")
@_mant_required
def mant_notificaciones_centro():
    """Centro de notificaciones global."""
    notifs = mysql_fetchall(
        "SELECT n.*,c.razon_social FROM mant_notificaciones n "
        "LEFT JOIN mant_clientes c ON c.id=n.cliente_id "
        "ORDER BY n.created_at DESC LIMIT 200"
    )
    pendientes = sum(1 for n in notifs if n.get("estado")=="pendiente")
    return render_template("mantenciones/notificaciones.html",
                           notifs=[dict(n) for n in notifs],
                           pendientes=pendientes)


# ════════════════════════════════════════════════════════════════════
#  LEVANTAMIENTOS FOTOGRÁFICOS DE EQUIPOS
#  ─────────────────────────────────────────────────────────────────
#  Sesión donde un técnico documenta visualmente los equipos del cliente.
#  NO es una OT/visita — es PRE-VENTA / inventario inicial.
#  Storage de fotos: Cloudinary siempre (persistente, mobile-friendly).
# ════════════════════════════════════════════════════════════════════

def _lev_estado_label(estado):
    return {
        'operativo':       '🟢 Operativo',
        'advertencia':     '🟡 Advertencia',
        'fuera_servicio':  '🔴 Fuera de servicio',
        'en_reparacion':   '🔵 En reparación',
        'dado_baja':       '⚪ Dado de baja',
        'no_encontrado':   '⚫ No encontrado',
    }.get(estado, estado)


def _lev_registrar_evento(maquina_id, cliente_id, tipo, descripcion,
                          ref_tabla=None, ref_id=None, metadata=None):
    """Helper: registra un evento en la timeline del equipo."""
    if not maquina_id:
        return
    try:
        meta_json = json.dumps(metadata) if metadata else None
        mysql_execute(
            "INSERT INTO mant_maquina_eventos "
            "(maquina_id, cliente_id, tipo, descripcion, referencia_tabla, "
            " referencia_id, metadata_json, created_by) "
            "VALUES (%s,%s,%s,%s,%s,%s,%s,%s)",
            (maquina_id, cliente_id, tipo, descripcion[:400],
             ref_tabla, ref_id, meta_json, current_username() or 'sistema')
        )
    except Exception as e:
        print(f"[lev_evento] no se pudo registrar: {e}", flush=True)


@app.route("/mantenciones/api/clientes/<int:cid>/levantamiento-abierto")
@_mant_required
def mant_lev_abierto(cid):
    """¿Hay un levantamiento abierto (borrador/en_curso) para este cliente?"""
    row = mysql_fetchone(
        "SELECT id, estado, fecha_inicio, titulo, total_equipos, total_fotos, tecnico "
        "  FROM mant_levantamientos "
        " WHERE cliente_id=%s AND estado IN ('borrador','en_curso') "
        " ORDER BY fecha_inicio DESC LIMIT 1",
        (cid,)
    )
    return jsonify({"ok": True, "levantamiento": dict(row) if row else None})


@app.route("/mantenciones/api/clientes/<int:cid>/levantamientos", methods=["GET", "POST"])
@_mant_required
def mant_lev_crear_o_listar(cid):
    """GET: listar levantamientos del cliente.
       POST: crear uno nuevo (si no hay abierto)."""
    if request.method == "GET":
        rows = mysql_fetchall(
            "SELECT id, fecha_inicio, fecha_cierre, estado, titulo, "
            "       total_equipos, total_fotos, tecnico, created_by "
            "  FROM mant_levantamientos WHERE cliente_id=%s "
            " ORDER BY fecha_inicio DESC",
            (cid,)
        ) or []
        for r in rows:
            for k in ('fecha_inicio', 'fecha_cierre'):
                if r.get(k):
                    r[k] = str(r[k])[:16]
        return jsonify({"ok": True, "levantamientos": rows})

    # POST: crear nuevo
    data = request.get_json(silent=True) or {}

    # ─── Auto-cancelar levantamientos huérfanos del mismo cliente ──
    # 2026-05-16: ya NO bloqueamos cuando hay un levantamiento abierto.
    # Cada acción crea una OT nueva (el admin gestiona desde Órdenes de
    # Trabajo, no continúa levantamientos antiguos).
    # Si quedaron levantamientos abiertos huérfanos (porque su OT
    # asociada fue eliminada o cancelada), los marcamos como cancelados
    # para mantener la BD consistente.
    try:
        huerfanos = mysql_fetchall(
            "SELECT l.id "
            "  FROM mant_levantamientos l "
            "  LEFT JOIN mant_visitas v ON v.id = l.visita_id "
            " WHERE l.cliente_id=%s "
            "   AND l.estado IN ('borrador','en_curso') "
            "   AND (v.id IS NULL OR v.estado IN ('cancelada','anulada'))",
            (cid,)
        ) or []
        if huerfanos:
            ids = [int(r["id"]) for r in huerfanos]
            ph = ",".join(["%s"] * len(ids))
            mysql_execute(
                f"UPDATE mant_levantamientos SET estado='cancelado', "
                f"        fecha_cierre=NOW() "
                f" WHERE id IN ({ph})",
                tuple(ids)
            )
            print(f"[lev_crear] {len(ids)} levantamiento(s) huérfano(s) auto-cancelados: {ids}", flush=True)
    except Exception as e_huer:
        print(f"[lev_crear] limpieza huérfanos falló: {e_huer}", flush=True)

    # ─── Datos básicos ────────────────────────────────────────────
    titulo = (data.get("titulo") or "").strip()[:200] or f"Levantamiento {_now_chile_str('%d/%m/%Y')}"
    notas = (data.get("notas") or "").strip()
    equipo_ids = data.get("equipo_ids") or []
    if not equipo_ids:
        return jsonify({
            "ok": False,
            "error": "Debes seleccionar al menos 1 equipo para el levantamiento.",
            "error_codigo": "SIN_EQUIPOS",
        }), 400

    # ─── Fecha y hora programadas (FASE 2026-05-16) ───────────────
    # fecha_programada: YYYY-MM-DD (default: hoy)
    # hora_inicio:      HH:MM (opcional)
    # hora_fin:         HH:MM (opcional)
    # fecha_fin:        YYYY-MM-DD (opcional, si dura varios días)
    fecha_prog = (data.get("fecha_programada") or "").strip()[:10]
    if not fecha_prog:
        fecha_prog = _now_chile_str('%Y-%m-%d')
    hora_ini = (data.get("hora_inicio") or "").strip()[:5] or None
    hora_fin = (data.get("hora_fin") or "").strip()[:5] or None
    fecha_fin = (data.get("fecha_fin") or "").strip()[:10] or None

    # ─── Multi-técnico ────────────────────────────────────────────
    # tecnico_ids: lista de IDs de app_users con rol=tecnico (preferido)
    # Compat: tecnico_id (singular) → se convierte a lista [tecnico_id]
    tecnico_ids = data.get("tecnico_ids") or []
    if not tecnico_ids and data.get("tecnico_id"):
        tecnico_ids = [data.get("tecnico_id")]
    # Sanear: solo enteros válidos
    tecnico_ids_clean = []
    for tid in tecnico_ids:
        try: tecnico_ids_clean.append(int(tid))
        except Exception: pass
    tecnico_ids = tecnico_ids_clean
    # Técnico principal (primero de la lista) — para la columna legacy mant_visitas.tecnico_user_id
    tecnico_principal = tecnico_ids[0] if tecnico_ids else None

    # ─── Tipo de OT (FASE 2 — modal generalizado 2026-05-16) ──────
    # Valores permitidos: deben coincidir con el ENUM mant_visitas.tipo
    tipos_ok = ("levantamiento", "instalacion", "preventiva", "correctiva",
                "visita_tecnica", "inspeccion", "garantia", "cambio_equipo",
                "desinstalacion", "capacitacion", "repuesto", "revision_interna",
                "visita_correctiva")
    tipo_ot = (data.get("tipo_ot") or "levantamiento").strip().lower()
    if tipo_ot not in tipos_ok:
        tipo_ot = "levantamiento"

    # ─── Flag opcional: ¿aplica garantía? ──────────────────────────
    # Garantía no es un tipo (cubre múltiples tipos), es una modalidad
    # de cobro. NO aplica a levantamiento (siempre sin_costo).
    aplica_garantia = bool(data.get("aplica_garantia")) and tipo_ot != 'levantamiento'

    # ─── Dirección de la visita (Google Places autocomplete) ───────
    # Editable por el usuario (puede ser distinta a la dirección
    # registrada del cliente). Guarda lat/lng para guiar al técnico
    # en el modo ejecución (Google Maps).
    direccion_visita = (data.get("direccion_visita") or "").strip()[:400] or None
    try:
        direccion_lat = float(data.get("direccion_lat")) if data.get("direccion_lat") is not None else None
        direccion_lng = float(data.get("direccion_lng")) if data.get("direccion_lng") is not None else None
    except (TypeError, ValueError):
        direccion_lat = None
        direccion_lng = None
    direccion_place_id = (data.get("direccion_place_id") or "").strip()[:200] or None

    # ─── Contacto / contraparte en sitio ───────────────────────────
    # El admin elige quién recibe al técnico. Puede ser el principal del
    # cliente, secundario, encargado de sucursal, o ingresarlo manual.
    contacto_nombre = (data.get("contacto_nombre") or "").strip()[:200] or None
    contacto_cargo  = (data.get("contacto_cargo")  or "").strip()[:120] or None
    contacto_tel    = (data.get("contacto_tel")    or "").strip()[:50]  or None
    contacto_email  = (data.get("contacto_email")  or "").strip()[:200] or None
    contacto_origen = (data.get("contacto_origen") or "").strip()[:40]  or None

    # ─── Acceso y logística del sitio (calidad OT) ─────────────────
    # Datos que el técnico necesita SABER ANTES de llegar:
    #  - Si hay ascensor (equipos pesados se suben por ahí, sino escalera).
    #  - Si hay estacionamiento (puede ir en auto/camioneta).
    #  - Piso/nivel del local.
    #  - Notas (códigos de portón, timbre, contacto seguridad, etc.).
    # acceso_ascensor / acceso_estacionamiento: TINYINT(1) — 0=No, 1=Sí,
    # NULL=No informado (legacy).
    def _tribool(val):
        """Convierte true/false/null/"si"/"no"/"1"/"0" a 1/0/None."""
        if val is None or val == "":
            return None
        if isinstance(val, bool):
            return 1 if val else 0
        s = str(val).strip().lower()
        if s in ("1", "true", "si", "sí", "yes", "y"):
            return 1
        if s in ("0", "false", "no", "n"):
            return 0
        return None
    acceso_ascensor        = _tribool(data.get("acceso_ascensor"))
    acceso_estacionamiento = _tribool(data.get("acceso_estacionamiento"))
    acceso_piso            = (data.get("acceso_piso")  or "").strip()[:50] or None
    acceso_notas           = (data.get("acceso_notas") or "").strip()[:2000] or None

    # ─── Multi-plantilla por equipo (plantillas_por_equipo) ───────
    # Estructura: { "<maquina_id>": [plantilla_id, plantilla_id, ...] }
    # Si llega, además de la plantilla estándar del tipo, aplica estas
    # plantillas extra SOLO al equipo indicado.
    plantillas_por_equipo_raw = data.get("plantillas_por_equipo") or {}
    plantillas_por_equipo = {}
    if isinstance(plantillas_por_equipo_raw, dict):
        for mid_str, plist in plantillas_por_equipo_raw.items():
            try:
                mid_int = int(mid_str)
                ids_int = [int(p) for p in (plist or []) if p]
                if ids_int:
                    plantillas_por_equipo[mid_int] = ids_int
            except (TypeError, ValueError):
                continue
    # Resolver nombre del técnico principal (para mant_levantamientos.tecnico VARCHAR)
    tecnico_nombre = ""
    if tecnico_principal:
        u = mysql_fetchone(
            "SELECT COALESCE(nombre, username) AS nm FROM app_users WHERE id=%s",
            (tecnico_principal,)
        )
        if u: tecnico_nombre = u["nm"]
    if not tecnico_nombre:
        tecnico_nombre = current_username() or ""

    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            cur.execute(
                "INSERT INTO mant_levantamientos "
                "(cliente_id, tecnico, titulo, notas, estado, created_by) "
                "VALUES (%s,%s,%s,%s,'en_curso',%s)",
                (cid, tecnico_nombre[:190], titulo, notas,
                 current_username() or 'sistema')
            )
            lev_id = cur.lastrowid

            # ─── Items del levantamiento (1 por equipo) ────────────
            ph = ",".join(["%s"] * len(equipo_ids))
            cur.execute(
                f"SELECT id, nombre, sku, serie, doc_fecha FROM mant_maquinas "
                f"WHERE id IN ({ph}) AND cliente_id=%s",
                tuple(list(equipo_ids) + [cid])
            )
            maquinas = cur.fetchall() or []
            n_items = 0
            for m in maquinas:
                cur.execute(
                    "INSERT INTO mant_levantamiento_items "
                    "(levantamiento_id, maquina_id, nombre_snap, sku_snap, serie_snap, "
                    " fecha_documento) "
                    "VALUES (%s,%s,%s,%s,%s,%s)",
                    (lev_id, m["id"], m.get("nombre"), m.get("sku"), m.get("serie"),
                     m.get("doc_fecha"))
                )
                n_items += 1
            cur.execute(
                "UPDATE mant_levantamientos SET total_equipos=%s WHERE id=%s",
                (n_items, lev_id)
            )

            # ══════════════════════════════════════════════════════════
            # CREAR OT (mant_visitas) ESPEJO con fecha/hora/multi-técnico
            # ══════════════════════════════════════════════════════════
            try:
                numero_ot = _next_ot_number()
            except Exception:
                numero_ot = f"LEV-{int(time.time())}"
            visita_id = None
            try:
                # Prefijo del título según tipo (para identificar visualmente)
                tipo_prefix = {
                    'levantamiento':  '[LEV]',
                    'instalacion':    '[INST]',
                    'preventiva':     '[PM]',
                    'correctiva':     '[CM]',
                    'visita_tecnica': '[VT]',
                    'inspeccion':     '[INSP]',
                    'garantia':       '[GAR]',
                }.get(tipo_ot, '[OT]')
                # Sufijo si aplica garantía (visible en el título)
                if aplica_garantia:
                    tipo_prefix = tipo_prefix + ' 🛡️'
                # Modalidad: levantamiento sin costo; garantia si flag activo; otros pagado
                if tipo_ot == 'levantamiento':
                    modalidad = 'sin_costo'
                elif aplica_garantia:
                    modalidad = 'garantia'
                else:
                    modalidad = 'pagado'
                # 2026-05-22 (Aaron Urbina): created_by_user_id FK estable a
                # app_users.id como fuente de verdad del creador. Si la
                # migración no corrió aún, fallback al INSERT legacy.
                _u_cre_lev = getattr(g, "user", None) or {}
                _cre_uid_lev = _u_cre_lev.get("id")
                try:
                    _cre_uid_lev = int(_cre_uid_lev) if _cre_uid_lev else None
                except (TypeError, ValueError):
                    _cre_uid_lev = None
                try:
                    cur.execute(
                        "INSERT INTO mant_visitas "
                        "(numero_ot, cliente_id, titulo, fecha_programada, "
                        " fecha_realizada, hora_inicio, hora_fin, "
                        " tipo, estado, modalidad_cobro, prioridad, "
                        " descripcion, tecnico_user_id, levantamiento_id, created_by, created_by_user_id, "
                        " direccion_visita, direccion_lat, direccion_lng, direccion_place_id, "
                        " contacto_nombre, contacto_cargo, contacto_tel, contacto_email, contacto_origen, "
                        " acceso_ascensor, acceso_estacionamiento, acceso_piso, acceso_notas) "
                        "VALUES (%s,%s,%s,%s,%s,%s,%s,"
                        " %s,'programada',%s,'media',"
                        " %s,%s,%s,%s,%s,"
                        " %s,%s,%s,%s,"
                        " %s,%s,%s,%s,%s,"
                        " %s,%s,%s,%s)",
                        (numero_ot, cid, f"{tipo_prefix} {titulo}"[:200],
                         fecha_prog, fecha_fin, hora_ini, hora_fin,
                         tipo_ot, modalidad,
                         f"OT tipo {tipo_ot} con {n_items} equipo(s). "
                         f"{'Multi-técnico (' + str(len(tecnico_ids)) + ' asignados)' if len(tecnico_ids) > 1 else ''}",
                         tecnico_principal, lev_id, current_username(), _cre_uid_lev,
                         direccion_visita, direccion_lat, direccion_lng, direccion_place_id,
                         contacto_nombre, contacto_cargo, contacto_tel, contacto_email, contacto_origen,
                         acceso_ascensor, acceso_estacionamiento, acceso_piso, acceso_notas)
                    )
                except Exception as _e_ins_lev:
                    print(f"[lev_crear] INSERT con created_by_user_id falló ({_e_ins_lev}); reintentando sin la columna", flush=True)
                    cur.execute(
                        "INSERT INTO mant_visitas "
                        "(numero_ot, cliente_id, titulo, fecha_programada, "
                        " fecha_realizada, hora_inicio, hora_fin, "
                        " tipo, estado, modalidad_cobro, prioridad, "
                        " descripcion, tecnico_user_id, levantamiento_id, created_by, "
                        " direccion_visita, direccion_lat, direccion_lng, direccion_place_id, "
                        " contacto_nombre, contacto_cargo, contacto_tel, contacto_email, contacto_origen, "
                        " acceso_ascensor, acceso_estacionamiento, acceso_piso, acceso_notas) "
                        "VALUES (%s,%s,%s,%s,%s,%s,%s,"
                        " %s,'programada',%s,'media',"
                        " %s,%s,%s,%s,"
                        " %s,%s,%s,%s,"
                        " %s,%s,%s,%s,%s,"
                        " %s,%s,%s,%s)",
                        (numero_ot, cid, f"{tipo_prefix} {titulo}"[:200],
                         fecha_prog, fecha_fin, hora_ini, hora_fin,
                         tipo_ot, modalidad,
                         f"OT tipo {tipo_ot} con {n_items} equipo(s). "
                         f"{'Multi-técnico (' + str(len(tecnico_ids)) + ' asignados)' if len(tecnico_ids) > 1 else ''}",
                         tecnico_principal, lev_id, current_username(),
                         direccion_visita, direccion_lat, direccion_lng, direccion_place_id,
                         contacto_nombre, contacto_cargo, contacto_tel, contacto_email, contacto_origen,
                         acceso_ascensor, acceso_estacionamiento, acceso_piso, acceso_notas)
                    )
                visita_id = cur.lastrowid
                cur.execute(
                    "UPDATE mant_levantamientos SET visita_id=%s WHERE id=%s",
                    (visita_id, lev_id)
                )

                # ─── Multi-técnico: registrar TODOS en mant_visita_tecnicos ─
                # Esto permite que cada técnico vea la OT en "Mis OTs" y
                # que cualquiera de ellos pueda tomar equipos disponibles
                # de forma colaborativa.
                # 2026-05-16: ahora usamos tecnico_user_id (FK a app_users.id)
                # como fuente de verdad. La columna legacy tecnico_id queda
                # NULL (la tabla mant_tecnicos legacy ya no es fuente).
                if len(tecnico_ids) > 0:
                    for tuid in tecnico_ids:
                        try:
                            cur.execute(
                                "INSERT IGNORE INTO mant_visita_tecnicos "
                                "(visita_id, tecnico_id, tecnico_user_id, rol) "
                                "VALUES (%s, NULL, %s, %s)",
                                (visita_id, tuid,
                                 'lider' if tuid == tecnico_principal else 'tecnico')
                            )
                        except Exception as _e_n:
                            print(f"[lev_crear] mant_visita_tecnicos insert falló para uid={tuid}: {_e_n}", flush=True)

                # ─── BUG FIX 2026-05-17 — "Gestión de tareas" duplicada ──
                # Antes: SIEMPRE se insertaba 1 tarea "📷 Documentar:" por
                # equipo SIN plantilla_id, que aparecía como "Gestión de tareas"
                # en la UI del técnico (fallback de COALESCE(p.nombre)).
                # Esto convivía con las plantillas que se aplicaban después
                # → duplicación visible.
                #
                # Ahora: SOLO se inserta este fallback legacy si NO se va a
                # aplicar ninguna plantilla (ni la estándar del tipo ni las
                # extra). Si se aplican plantillas, ellas ya generan las
                # tareas con plantilla_id y aparecen agrupadas correctamente.
                # Esta validación es defensiva — si no hay match de plantilla
                # estándar y plantillas_por_equipo está vacío, queda esta
                # tarea para que el técnico tenga AL MENOS qué hacer.
                _tiene_plantillas = bool(plantillas_por_equipo)
                if not _tiene_plantillas:
                    # Chequear si hay plantilla estándar para el tipo
                    try:
                        _nombre_test = {
                            'levantamiento':  'Levantamiento fotográfico estándar',
                            'instalacion':    'Instalación estándar',
                            'preventiva':     'Mantención preventiva estándar',
                            'correctiva':     'Mantención correctiva estándar',
                            'visita_tecnica': 'Visita técnica estándar',
                            'inspeccion':     'Inspección estándar',
                            'garantia':       'Garantía estándar',
                        }.get(tipo_ot)
                        if _nombre_test:
                            _check_p = mysql_fetchone(
                                "SELECT id FROM mant_tarea_plantillas "
                                "WHERE nombre=%s AND COALESCE(activa,1)=1 LIMIT 1",
                                (_nombre_test,)
                            )
                            if _check_p: _tiene_plantillas = True
                        if not _tiene_plantillas:
                            _check_p2 = mysql_fetchone(
                                "SELECT id FROM mant_tarea_plantillas "
                                "WHERE tipo_visita=%s AND COALESCE(activa,1)=1 LIMIT 1",
                                (tipo_ot,)
                            )
                            if _check_p2: _tiene_plantillas = True
                    except Exception:
                        pass
                # Solo crear el fallback "📷 Documentar" si NO hay plantillas
                # que se vayan a aplicar (evita duplicación con plantillas).
                if not _tiene_plantillas:
                    for idx, m in enumerate(maquinas, 1):
                        cur.execute(
                            "INSERT INTO mant_visita_tareas "
                            "(visita_id, orden, titulo, descripcion, maquina_id, "
                            " tipo, tipo_respuesta, obligatoria, requiere_foto, "
                            " estado_trabajo, created_by) "
                            "VALUES (%s,%s,%s,%s,%s,'levantamiento','foto',1,1,'pendiente',%s)",
                            (visita_id, idx,
                             f"📷 Documentar: {(m.get('nombre') or 'equipo')[:240]}",
                             "Capturar fotos generales del equipo + N° serie + placa + datos técnicos.",
                             m["id"], current_username() or 'sistema')
                        )
            except Exception as e_ot:
                print(f"[lev_crear] no se pudo crear OT espejo: {e_ot}", flush=True)
                visita_id = None

        conn.commit()

        # ══════════════════════════════════════════════════════════════
        # APLICAR PLANTILLAS (POST-commit, defensivo)
        #
        # 1) Plantilla estándar del tipo de OT (busca por nombre o tipo_visita)
        # 2) Plantillas EXTRA por equipo (data.plantillas_por_equipo)
        # ══════════════════════════════════════════════════════════════
        items_plantilla = 0

        def _aplicar_plantilla_a_equipos(plantilla_id, mq_ids):
            """Clona los items de la plantilla y los inserta como tareas
            de la OT para CADA máquina del listado. Retorna n items creados.

            BUG FIX 2026-05-17 — DEDUP: si ya existe (visita_id, plantilla_id,
            maquina_id) en mant_visita_tareas, SKIP esa máquina. Esto evita
            duplicación cuando la misma plantilla se intenta aplicar 2 veces
            (ej: paso 1 estándar del tipo + paso 2 plantillas_por_equipo).
            """
            nonlocal items_plantilla
            if not plantilla_id or not mq_ids:
                return 0
            items_plant = mysql_fetchall(
                "SELECT * FROM mant_tarea_plantilla_items "
                "WHERE plantilla_id=%s ORDER BY orden, id",
                (plantilla_id,)
            ) or []
            if not items_plant:
                return 0
            conn2 = get_mysql()
            n_added = 0
            try:
                with conn2.cursor() as cur2:
                    cur2.execute(
                        "SELECT COALESCE(MAX(orden),0) AS mx "
                        "FROM mant_visita_tareas WHERE visita_id=%s",
                        (visita_id,)
                    )
                    next_orden = int((cur2.fetchone() or {}).get("mx") or 0)
                    for mq_id in mq_ids:
                        # DEDUP: ¿ya hay tareas de esta plantilla para esta máquina?
                        cur2.execute(
                            "SELECT COUNT(*) AS n FROM mant_visita_tareas "
                            " WHERE visita_id=%s AND plantilla_id=%s AND maquina_id=%s",
                            (visita_id, plantilla_id, mq_id)
                        )
                        _dup = cur2.fetchone() or {}
                        if (_dup.get("n") or 0) > 0:
                            print(f"[lev_crear] DEDUP — plantilla {plantilla_id} ya aplicada "
                                  f"a máquina {mq_id} en visita {visita_id}, skip", flush=True)
                            continue
                        m_row = mysql_fetchone(
                            "SELECT nombre, serie FROM mant_maquinas WHERE id=%s",
                            (mq_id,)
                        )
                        m_nombre = m_row.get("nombre") if m_row else f"#{mq_id}"
                        for it in items_plant:
                            next_orden += 1
                            titulo_t = it["titulo"]
                            sufijo = m_nombre
                            if m_row and m_row.get("serie"):
                                sufijo += f" (S/N: {m_row['serie']})"
                            titulo_full = f"{titulo_t} — {sufijo}"[:300]
                            cur2.execute(
                                "INSERT INTO mant_visita_tareas "
                                "(visita_id, orden, titulo, descripcion, tipo, "
                                " maquina_id, plantilla_id, tipo_respuesta, obligatoria, "
                                " requiere_foto, unidad, rango_min, rango_max, "
                                " opciones_lista_json, estado_trabajo, created_by) "
                                "VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,"
                                "        %s,%s,%s,%s,'pendiente',%s)",
                                (visita_id, next_orden, titulo_full,
                                 it.get("descripcion"), tipo_ot, mq_id,
                                 plantilla_id,  # FK origen
                                 it["tipo_respuesta"],
                                 it.get("obligatoria") or 0,
                                 it.get("requiere_foto") or 0,
                                 it.get("unidad"), it.get("rango_min"),
                                 it.get("rango_max"),
                                 it.get("opciones_lista_json"),
                                 current_username())
                            )
                            n_added += 1
                conn2.commit()
            finally:
                conn2.close()
            items_plantilla += n_added
            return n_added

        # 1) Plantilla estándar del tipo
        #
        # BUG FIX 2026-05-17 — Si el usuario ya pasó plantillas explícitas
        # en plantillas_por_equipo, NO aplicamos la estándar automática:
        # el usuario sabe lo que quiere, evitamos duplicación silenciosa.
        # (El dedup interno de _aplicar_plantilla_a_equipos también lo
        # cubriría, pero saltar el paso 1 entero es más limpio y eficiente.)
        if visita_id and equipo_ids and not plantillas_por_equipo:
            try:
                # Mapeo tipo_ot → nombre de plantilla estándar (convención del proyecto)
                plantilla_estandar_por_tipo = {
                    'levantamiento':  'Levantamiento fotográfico estándar',
                    'instalacion':    'Instalación estándar',
                    'preventiva':     'Mantención preventiva estándar',
                    'correctiva':     'Mantención correctiva estándar',
                    'visita_tecnica': 'Visita técnica estándar',
                    'inspeccion':     'Inspección estándar',
                    'garantia':       'Garantía estándar',
                }
                nombre_plant = plantilla_estandar_por_tipo.get(tipo_ot)
                plant_id = None
                if nombre_plant:
                    plant = mysql_fetchone(
                        "SELECT id FROM mant_tarea_plantillas "
                        "WHERE nombre=%s AND COALESCE(activa,1)=1 LIMIT 1",
                        (nombre_plant,)
                    )
                    if plant: plant_id = plant["id"]
                # Fallback: buscar por tipo_visita
                if not plant_id:
                    plant = mysql_fetchone(
                        "SELECT id FROM mant_tarea_plantillas "
                        "WHERE tipo_visita=%s AND COALESCE(activa,1)=1 "
                        "ORDER BY id LIMIT 1",
                        (tipo_ot,)
                    )
                    if plant: plant_id = plant["id"]
                if plant_id:
                    _aplicar_plantilla_a_equipos(plant_id, equipo_ids)
            except Exception as e_pl:
                print(f"[lev_crear] aplicar plantilla estándar falló: {e_pl}", flush=True)

        # 2) Plantillas EXTRA por equipo
        if visita_id and plantillas_por_equipo:
            try:
                for mid, pids in plantillas_por_equipo.items():
                    if mid not in equipo_ids:
                        continue  # equipo no incluido en la OT
                    for pid in pids:
                        try:
                            _aplicar_plantilla_a_equipos(pid, [mid])
                        except Exception as _ep:
                            print(f"[lev_crear] plantilla extra {pid} para mid {mid} falló: {_ep}", flush=True)
            except Exception as e_pl2:
                print(f"[lev_crear] plantillas extra fallaron: {e_pl2}", flush=True)

        # ══════════════════════════════════════════════════════════════
        # FIX 2026-05-22 (Daniel — caso Vitacura OT 161/162/163):
        # Si el chequeo previo `_tiene_plantillas` dio True porque existe
        # una plantilla con el `nombre` o `tipo_visita` esperado, pero esa
        # plantilla tiene 0 items en `mant_tarea_plantilla_items`, el
        # técnico se queda con UNA OT con 4 equipos y 0 tareas → no puede
        # documentar nada y al cerrar la ficha NO se hereda info.
        #
        # Si tras aplicar plantillas no se creó NINGÚN ítem (items_plantilla
        # quedó en 0) y NO hay tareas legacy creadas dentro del cursor
        # (fallback "📷 Documentar"), insertamos AHORA el fallback como
        # safety net. Idempotente: DEDUP via COUNT, no duplica si ya hay
        # tareas para esta visita.
        # ══════════════════════════════════════════════════════════════
        if visita_id and items_plantilla == 0:
            try:
                _existing = mysql_fetchone(
                    "SELECT COUNT(*) AS n FROM mant_visita_tareas WHERE visita_id=%s",
                    (visita_id,)
                ) or {}
                _n_existing = int(_existing.get("n") or 0)
                if _n_existing == 0:
                    # Cargar máquinas otra vez (cur ya cerrado tras commit)
                    _ph = ",".join(["%s"] * len(equipo_ids))
                    _maqs = mysql_fetchall(
                        f"SELECT id, nombre FROM mant_maquinas "
                        f" WHERE id IN ({_ph}) AND cliente_id=%s "
                        f" ORDER BY id",
                        tuple(list(equipo_ids) + [cid])
                    ) or []
                    _conn_fb = get_mysql()
                    try:
                        with _conn_fb.cursor() as _cur_fb:
                            for _idx, _m in enumerate(_maqs, 1):
                                _cur_fb.execute(
                                    "INSERT INTO mant_visita_tareas "
                                    "(visita_id, orden, titulo, descripcion, maquina_id, "
                                    " tipo, tipo_respuesta, obligatoria, requiere_foto, "
                                    " estado_trabajo, created_by) "
                                    "VALUES (%s,%s,%s,%s,%s,'levantamiento','foto',1,1,"
                                    "        'pendiente',%s)",
                                    (visita_id, _idx,
                                     f"📷 Documentar: {(_m.get('nombre') or 'equipo')[:240]}",
                                     "Capturar fotos generales del equipo + N° serie + placa "
                                     "+ datos técnicos.",
                                     _m["id"], current_username() or 'sistema')
                                )
                                items_plantilla += 1
                        _conn_fb.commit()
                        print(f"[lev_crear] fallback aplicado vid={visita_id} "
                              f"({len(_maqs)} tarea(s) 📷 Documentar) — plantilla del "
                              f"tipo '{tipo_ot}' sin items.", flush=True)
                    finally:
                        _conn_fb.close()
            except Exception as _e_fb:
                print(f"[lev_crear] fallback safety-net falló: {_e_fb}", flush=True)

        try: _mant_log("levantamiento", lev_id, "creado",
                       f"{n_items} equipo(s) · OT {numero_ot or '—'} · "
                       f"{len(tecnico_ids)} técnico(s) · "
                       f"{items_plantilla} items plantilla")
        except Exception: pass

        return jsonify({
            "ok": True,
            "id": lev_id,
            "n_items": n_items,
            "visita_id": visita_id,
            "numero_ot": numero_ot if visita_id else None,
            "ot_url": f"/mantenciones/ot/{visita_id}" if visita_id else None,
            "tecnicos_asignados": len(tecnico_ids),
            "items_plantilla_aplicados": items_plantilla,
            "mensaje": (
                f"Levantamiento creado con {n_items} equipo(s) e items de plantilla "
                f"aplicados ({items_plantilla} tareas). "
                f"La OT quedó programada para {fecha_prog}"
                + (f" {hora_ini}" if hora_ini else "")
                + f" — número {numero_ot}."
            ),
        })
    except Exception as e:
        try: conn.rollback()
        except Exception: pass
        return jsonify({"ok": False, "error": str(e)}), 500
    finally:
        try: conn.close()
        except Exception: pass


@app.route("/mantenciones/api/levantamientos/<int:lid>", methods=["GET", "PATCH", "DELETE"])
@_mant_required
def mant_lev_detalle(lid):
    """GET: detalle + items + fotos.  PATCH: actualizar metadata.  DELETE: cancelar."""
    lev = mysql_fetchone("SELECT * FROM mant_levantamientos WHERE id=%s", (lid,))
    if not lev:
        return jsonify({"ok": False, "error": "Levantamiento no encontrado"}), 404

    if request.method == "DELETE":
        if lev["estado"] == "cerrado":
            return jsonify({"ok": False, "error": "No se puede eliminar un levantamiento cerrado"}), 400
        mysql_execute("UPDATE mant_levantamientos SET estado='cancelado' WHERE id=%s", (lid,))
        try: _mant_log("levantamiento", lid, "cancelado", "")
        except Exception: pass
        return jsonify({"ok": True})

    if request.method == "PATCH":
        d = request.get_json(silent=True) or {}
        sets, vals = [], []
        for k in ("titulo", "tecnico", "notas"):
            if k in d:
                sets.append(f"{k}=%s")
                vals.append((d[k] or "")[:500])
        if sets:
            vals.append(lid)
            mysql_execute(f"UPDATE mant_levantamientos SET {', '.join(sets)} WHERE id=%s", tuple(vals))
        return jsonify({"ok": True})

    # GET: items + fotos
    items = mysql_fetchall(
        "SELECT * FROM mant_levantamiento_items WHERE levantamiento_id=%s ORDER BY id",
        (lid,)
    ) or []
    # Fotos por item (1 query batch)
    fotos = mysql_fetchall(
        "SELECT id, item_id, cloudinary_url, tipo_foto, descripcion, created_at "
        "  FROM mant_levantamiento_fotos WHERE levantamiento_id=%s ORDER BY id",
        (lid,)
    ) or []
    fotos_por_item = {}
    for f in fotos:
        fotos_por_item.setdefault(f["item_id"], []).append({
            "id": f["id"],
            "url": f["cloudinary_url"],
            "tipo": f["tipo_foto"],
            "descripcion": f.get("descripcion") or "",
            "created_at": str(f["created_at"])[:16] if f.get("created_at") else "",
        })
    for it in items:
        it["fotos"] = fotos_por_item.get(it["id"], [])
        it["estado_label"] = _lev_estado_label(it.get("estado_capturado", "operativo"))
        for k in ('created_at', 'updated_at'):
            if it.get(k): it[k] = str(it[k])[:16]

    lev = dict(lev)
    for k in ('fecha_inicio', 'fecha_cierre', 'created_at', 'updated_at'):
        if lev.get(k): lev[k] = str(lev[k])[:16]
    return jsonify({"ok": True, "levantamiento": lev, "items": items})


@app.route("/mantenciones/api/levantamientos/<int:lid>/items", methods=["POST"])
@_mant_required
def mant_lev_item_crear(lid):
    """Agregar un equipo al levantamiento (puede ser una máquina existente o crear ad-hoc).
    FASE 4: si el levantamiento tiene OT espejo (visita_id), también se crea
    automáticamente una tarea tipo='foto' en la OT para ese equipo, así el
    técnico ve el nuevo equipo en su checklist sin pasos adicionales.
    """
    lev = mysql_fetchone(
        "SELECT id, cliente_id, estado, visita_id FROM mant_levantamientos WHERE id=%s",
        (lid,)
    )
    if not lev:
        return jsonify({"ok": False, "error": "Levantamiento no encontrado"}), 404
    if lev["estado"] == "cerrado":
        return jsonify({"ok": False, "error": "Levantamiento cerrado — no acepta más equipos"}), 400

    d = request.get_json(silent=True) or {}
    maquina_id = d.get("maquina_id")
    nombre = (d.get("nombre") or "").strip()[:300]

    if not maquina_id and not nombre:
        return jsonify({"ok": False, "error": "Indica una máquina existente o un nombre nuevo"}), 400

    snap = {"nombre": nombre, "sku": "", "serie": ""}
    if maquina_id:
        m = mysql_fetchone(
            "SELECT nombre, sku, serie FROM mant_maquinas WHERE id=%s AND cliente_id=%s",
            (maquina_id, lev["cliente_id"])
        )
        if not m:
            return jsonify({"ok": False, "error": "Máquina no pertenece al cliente"}), 400
        snap = {"nombre": m.get("nombre") or nombre,
                "sku": m.get("sku") or "",
                "serie": m.get("serie") or ""}

    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            cur.execute(
                "INSERT INTO mant_levantamiento_items "
                "(levantamiento_id, maquina_id, nombre_snap, sku_snap, serie_snap, "
                " estado_capturado, ubicacion) "
                "VALUES (%s,%s,%s,%s,%s,%s,%s)",
                (lid, maquina_id, snap["nombre"], snap["sku"], snap["serie"],
                 d.get("estado_capturado") or "operativo",
                 (d.get("ubicacion") or "")[:200])
            )
            iid = cur.lastrowid
            cur.execute(
                "UPDATE mant_levantamientos SET total_equipos = "
                "(SELECT COUNT(*) FROM mant_levantamiento_items WHERE levantamiento_id=%s) "
                "WHERE id=%s",
                (lid, lid)
            )
            # FASE 4: sincronizar con la OT espejo (si existe).
            # Crear una tarea tipo='foto' por el nuevo equipo si:
            #   - hay OT espejo (visita_id)
            #   - hay maquina_id (no ad-hoc sin equipo identificado)
            #   - no existe ya una tarea para esa máquina en la OT
            if lev.get("visita_id") and maquina_id:
                cur.execute(
                    "SELECT id FROM mant_visita_tareas "
                    "WHERE visita_id=%s AND maquina_id=%s LIMIT 1",
                    (lev["visita_id"], maquina_id)
                )
                ya_existe = cur.fetchone()
                if not ya_existe:
                    # Calcular siguiente `orden`
                    cur.execute(
                        "SELECT COALESCE(MAX(orden),0)+1 AS o FROM mant_visita_tareas "
                        "WHERE visita_id=%s",
                        (lev["visita_id"],)
                    )
                    next_orden = (cur.fetchone() or {}).get("o", 1)
                    cur.execute(
                        "INSERT INTO mant_visita_tareas "
                        "(visita_id, orden, titulo, descripcion, maquina_id, "
                        " tipo, tipo_respuesta, obligatoria, requiere_foto, "
                        " estado_trabajo, created_by) "
                        "VALUES (%s,%s,%s,%s,%s,'levantamiento','foto',1,1,"
                        " 'pendiente',%s)",
                        (lev["visita_id"], next_orden,
                         f"📷 Documentar: {snap['nombre'][:240]}",
                         "Capturar fotos generales + N° serie + placa + datos técnicos.",
                         maquina_id, current_username() or 'sistema')
                    )
        conn.commit()
        return jsonify({"ok": True, "id": iid})
    except Exception as e:
        try: conn.rollback()
        except Exception: pass
        return jsonify({"ok": False, "error": str(e)}), 500
    finally:
        try: conn.close()
        except Exception: pass


@app.route("/mantenciones/api/levantamiento-items/<int:iid>", methods=["PATCH", "DELETE"])
@_mant_required
def mant_lev_item_update(iid):
    """Actualizar estado/observaciones/ubicación de un item."""
    item = mysql_fetchone(
        "SELECT id, levantamiento_id, maquina_id FROM mant_levantamiento_items WHERE id=%s",
        (iid,)
    )
    if not item:
        return jsonify({"ok": False, "error": "Item no encontrado"}), 404

    if request.method == "DELETE":
        mysql_execute("DELETE FROM mant_levantamiento_items WHERE id=%s", (iid,))
        mysql_execute(
            "UPDATE mant_levantamientos SET total_equipos = "
            "(SELECT COUNT(*) FROM mant_levantamiento_items WHERE levantamiento_id=%s) "
            "WHERE id=%s",
            (item["levantamiento_id"], item["levantamiento_id"])
        )
        return jsonify({"ok": True})

    d = request.get_json(silent=True) or {}
    sets, vals = [], []
    estados_validos = ('operativo','advertencia','fuera_servicio','en_reparacion','dado_baja','no_encontrado')
    # Campos editables del item (incluye los nuevos campos de calidad fitness)
    for k in (
        "estado_capturado", "ubicacion", "horas_uso", "anomalias", "observaciones",
        "completado",
        # Nuevos campos relevantes para máquinas fitness:
        "fecha_documento", "marca", "modelo", "anio_fabricacion",
        "voltaje", "ultima_intervencion", "componentes_json",
    ):
        if k in d:
            v = d[k]
            if k == "estado_capturado" and v not in estados_validos:
                continue
            if k in ("horas_uso", "anio_fabricacion"):
                try: v = int(v) if v not in (None, "") else None
                except Exception: continue
            if k in ("fecha_documento", "ultima_intervencion"):
                # Espera string YYYY-MM-DD o None. Si viene "", lo guardamos como NULL.
                if v in ("", None): v = None
            if k == "completado":
                v = 1 if v else 0
            sets.append(f"{k}=%s")
            vals.append(v)
    if not sets:
        return jsonify({"ok": True, "noop": True})
    vals.append(iid)
    mysql_execute(f"UPDATE mant_levantamiento_items SET {', '.join(sets)} WHERE id=%s", tuple(vals))
    return jsonify({"ok": True})


@app.route("/mantenciones/api/levantamiento-items/<int:iid>/fotos", methods=["POST"])
@_mant_required
def mant_lev_item_subir_foto(iid):
    """Sube una foto del item a Cloudinary y la asocia a la máquina si aplica."""
    item = mysql_fetchone(
        "SELECT li.*, l.cliente_id FROM mant_levantamiento_items li "
        "JOIN mant_levantamientos l ON l.id = li.levantamiento_id "
        "WHERE li.id=%s",
        (iid,)
    )
    if not item:
        return jsonify({"ok": False, "error": "Item no encontrado"}), 404

    f = request.files.get("foto") or request.files.get("archivo")
    if not f or not f.filename:
        return jsonify({"ok": False, "error": "Sin archivo"}), 400

    tipo_foto = (request.form.get("tipo_foto") or "general").strip().lower()[:60]
    descripcion = (request.form.get("descripcion") or "").strip()[:300]

    if not _CLD_READY:
        return jsonify({"ok": False, "error": "Cloudinary no configurado — contacta al administrador"}), 503

    try:
        f.stream.seek(0)
        public_id = f"lev_{item['levantamiento_id']}_item_{iid}_{int(time.time())}"
        folder = f"ilus/mant/levantamientos/{item['levantamiento_id']}"
        res = _cloud_upload_image_full(f.stream, public_id, folder=folder)
    except Exception as e:
        return jsonify({"ok": False, "error": f"Error subiendo a Cloudinary: {e}"}), 500

    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            cur.execute(
                "INSERT INTO mant_levantamiento_fotos "
                "(item_id, levantamiento_id, maquina_id, cloudinary_url, "
                " cloudinary_public_id, tipo_foto, descripcion, bytes, tomada_por) "
                "VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s)",
                (iid, item["levantamiento_id"], item.get("maquina_id"),
                 res["url"], res["public_id"], tipo_foto, descripcion,
                 res.get("size", 0), current_username() or 'tecnico')
            )
            fid = cur.lastrowid
            # Actualizar contadores
            cur.execute(
                "UPDATE mant_levantamiento_items SET n_fotos = "
                "(SELECT COUNT(*) FROM mant_levantamiento_fotos WHERE item_id=%s) "
                "WHERE id=%s", (iid, iid)
            )
            cur.execute(
                "UPDATE mant_levantamientos SET total_fotos = "
                "(SELECT COUNT(*) FROM mant_levantamiento_fotos WHERE levantamiento_id=%s) "
                "WHERE id=%s", (item["levantamiento_id"], item["levantamiento_id"])
            )
            # Si tiene máquina asociada, también copiar a mant_maquina_fotos
            # para que aparezca en la ficha del equipo (timeline).
            # FIX 2026-05-21: archivo_path es NOT NULL en mant_maquina_fotos
            # (CREATE TABLE original) — pasamos string vacío, y usamos
            # tomada_at (no created_at, que es el alias agregado por migración).
            if item.get("maquina_id"):
                try:
                    # Anti-duplicado: si ya existe foto con esta cloudinary_url
                    # para esta máquina, no duplicamos (Daniel reportó fotos
                    # del levantamiento no aparecían — el INSERT podía fallar
                    # silenciosamente por NOT NULL constraint en archivo_path).
                    cur.execute(
                        "SELECT id FROM mant_maquina_fotos "
                        " WHERE maquina_id=%s AND cloudinary_url=%s LIMIT 1",
                        (item["maquina_id"], res["url"])
                    )
                    if not cur.fetchone():
                        cur.execute(
                            "INSERT INTO mant_maquina_fotos "
                            "(maquina_id, archivo_path, cloudinary_url, cloudinary_public_id, "
                            " levantamiento_id, descripcion, tomada_por, tomada_at) "
                            "VALUES (%s, '', %s, %s, %s, %s, %s, NOW())",
                            (item["maquina_id"], res["url"], res["public_id"],
                             item["levantamiento_id"],
                             f"[{tipo_foto}] {descripcion}".strip()[:500],
                             current_username() or 'tecnico')
                        )
                        print(f"[lev_foto] copiada a mant_maquina_fotos "
                              f"m={item['maquina_id']} lev={item['levantamiento_id']}",
                              flush=True)
                except Exception as e_mf:
                    print(f"[promover-lev] foto saltada porque INSERT "
                          f"a mant_maquina_fotos falló: {e_mf} "
                          f"(m={item.get('maquina_id')} lev={item.get('levantamiento_id')} "
                          f"url={res.get('url','')[:80]})",
                          flush=True)
        conn.commit()
    except Exception as e:
        try: conn.rollback()
        except Exception: pass
        return jsonify({"ok": False, "error": f"Error guardando en BD: {e}"}), 500
    finally:
        try: conn.close()
        except Exception: pass

    # Registrar evento en timeline del equipo
    if item.get("maquina_id"):
        _lev_registrar_evento(
            item["maquina_id"], item["cliente_id"],
            "foto_agregada", f"Nueva foto ({tipo_foto}) durante levantamiento #{item['levantamiento_id']}",
            "mant_levantamientos", item["levantamiento_id"],
            {"item_id": iid, "tipo_foto": tipo_foto}
        )

    return jsonify({
        "ok": True,
        "id": fid,
        "url": res["url"],
        "tipo_foto": tipo_foto,
    })


@app.route("/mantenciones/api/levantamiento-fotos/<int:fid>", methods=["DELETE"])
@_mant_required
def mant_lev_foto_del(fid):
    """Elimina una foto del levantamiento (también de Cloudinary)."""
    foto = mysql_fetchone(
        "SELECT cloudinary_public_id, item_id, levantamiento_id "
        "  FROM mant_levantamiento_fotos WHERE id=%s",
        (fid,)
    )
    if not foto:
        return jsonify({"ok": False, "error": "Foto no encontrada"}), 404

    if foto.get("cloudinary_public_id") and _CLD_READY:
        try:
            _cloudinary_uploader.destroy(foto["cloudinary_public_id"], resource_type="image")
        except Exception as e:
            print(f"[lev_foto_del] Cloudinary delete fail: {e}", flush=True)

    mysql_execute("DELETE FROM mant_levantamiento_fotos WHERE id=%s", (fid,))
    # Recontar
    mysql_execute(
        "UPDATE mant_levantamiento_items SET n_fotos = "
        "(SELECT COUNT(*) FROM mant_levantamiento_fotos WHERE item_id=%s) "
        "WHERE id=%s", (foto["item_id"], foto["item_id"])
    )
    mysql_execute(
        "UPDATE mant_levantamientos SET total_fotos = "
        "(SELECT COUNT(*) FROM mant_levantamiento_fotos WHERE levantamiento_id=%s) "
        "WHERE id=%s", (foto["levantamiento_id"], foto["levantamiento_id"])
    )
    return jsonify({"ok": True})


@app.route("/mantenciones/api/levantamientos/<int:lid>/cerrar", methods=["POST"])
@_mant_required
def mant_lev_cerrar(lid):
    """Cierra el levantamiento + la OT espejo de forma auditable (Fase 4).

    Acciones al cerrar:
    1. Levantamiento → estado='cerrado', fecha_cierre, closed_by.
    2. Por cada item con máquina → evento en timeline del equipo.
    3. OT espejo (si existe):
       a. Vincula las fotos del levantamiento (mant_maquina_fotos donde
          levantamiento_id = lid) como evidencia de la OT (mant_visita_fotos
          con tipo='levantamiento'), marcando la tarea correspondiente.
       b. Marca cada tarea de la OT como completada (estado_trabajo='completada')
          y guarda observaciones desde el item del levantamiento.
       c. OT pasa a estado='cerrada' (no solo 'completada' — es el estado
          auditable final del modelo Fracttal).
       d. diagnostico auto-generado con resumen del levantamiento.
       e. cerrada_por = usuario actual, cerrada_at = NOW().
    """
    lev = mysql_fetchone("SELECT * FROM mant_levantamientos WHERE id=%s", (lid,))
    if not lev:
        return jsonify({"ok": False, "error": "No encontrado"}), 404
    if lev["estado"] == "cerrado":
        return jsonify({"ok": False, "error": "Ya estaba cerrado"}), 400

    user = current_username() or 'sistema'
    mysql_execute(
        "UPDATE mant_levantamientos SET estado='cerrado', fecha_cierre=NOW(), closed_by=%s "
        "WHERE id=%s",
        (user, lid)
    )
    # Registrar evento por cada equipo levantado
    items = mysql_fetchall(
        "SELECT id, maquina_id, n_fotos, estado_capturado, nombre_snap, "
        "       ubicacion, observaciones "
        "FROM mant_levantamiento_items "
        "WHERE levantamiento_id=%s AND maquina_id IS NOT NULL",
        (lid,)
    ) or []
    for it in items:
        _lev_registrar_evento(
            it["maquina_id"], lev["cliente_id"],
            "levantamiento",
            f"Levantamiento #{lid} cerrado · estado: {_lev_estado_label(it.get('estado_capturado'))} · {it.get('n_fotos',0)} foto(s)",
            "mant_levantamientos", lid,
            {"estado": it.get("estado_capturado"), "n_fotos": it.get("n_fotos", 0)}
        )

    fotos_vinculadas = 0
    tareas_cerradas = 0
    # Si tiene OT espejo: cierre auditable completo
    if lev.get("visita_id"):
        vid = lev["visita_id"]
        try:
            # 3.a — Vincular fotos del levantamiento como evidencia de la OT.
            # Fuente: mant_levantamiento_fotos (tabla específica del levantamiento,
            # tiene item_id que mapea directo a la máquina vía mant_levantamiento_items).
            # Se replican como filas en mant_visita_fotos apuntando a la tarea
            # correspondiente y manteniendo el cloudinary_url (sin re-uploadear).
            fotos_lev = mysql_fetchall(
                "SELECT lf.id, lf.maquina_id, lf.cloudinary_url, lf.descripcion, "
                "       lf.tomada_por, lf.tipo_foto "
                "FROM mant_levantamiento_fotos lf "
                "WHERE lf.levantamiento_id=%s",
                (lid,)
            ) or []
            conn = get_mysql()
            try:
                with conn.cursor() as cur:
                    # Mapeo maquina_id → tarea_id de la OT espejo
                    cur.execute(
                        "SELECT id, maquina_id FROM mant_visita_tareas "
                        "WHERE visita_id=%s AND maquina_id IS NOT NULL",
                        (vid,)
                    )
                    tareas_oot = cur.fetchall() or []
                    map_mq_tarea = {t["maquina_id"]: t["id"] for t in tareas_oot}

                    for f in fotos_lev:
                        # Saltar si ya existe la vinculación (evita duplicados al
                        # cerrar idempotente).
                        cloudinary_url = f.get("cloudinary_url") or ""
                        if not cloudinary_url:
                            continue
                        cur.execute(
                            "SELECT id FROM mant_visita_fotos "
                            "WHERE visita_id=%s "
                            "  AND COALESCE(cloudinary_url,'')=%s "
                            "LIMIT 1",
                            (vid, cloudinary_url)
                        )
                        if cur.fetchone():
                            continue
                        tid_mq = map_mq_tarea.get(f.get("maquina_id"))
                        # mant_visita_fotos.archivo_path es NOT NULL, así que
                        # le pasamos el cloudinary_url como path también (ambas
                        # apuntan al mismo recurso persistente).
                        cur.execute(
                            "INSERT INTO mant_visita_fotos "
                            "(visita_id, tarea_id, maquina_id, archivo_path, "
                            " cloudinary_url, tipo_foto, descripcion, tomada_por) "
                            "VALUES (%s,%s,%s,%s,%s,'levantamiento',%s,%s)",
                            (vid, tid_mq, f.get("maquina_id"),
                             cloudinary_url,  # archivo_path = url para compat
                             cloudinary_url,
                             (f.get("descripcion") or '')[:500],
                             (f.get("tomada_por") or user)[:190])
                        )
                        fotos_vinculadas += 1

                    # 3.b — Marcar tareas como completadas con observación del item
                    for it in items:
                        tid_mq = map_mq_tarea.get(it["maquina_id"])
                        if not tid_mq:
                            continue
                        obs = (it.get("observaciones") or "").strip()
                        ubic = (it.get("ubicacion") or "").strip()
                        est = _lev_estado_label(it.get("estado_capturado"))
                        observ_final = f"Estado capturado: {est}"
                        if ubic: observ_final += f" · Ubicación: {ubic}"
                        if obs: observ_final += f" · {obs[:300]}"
                        cur.execute(
                            "UPDATE mant_visita_tareas SET "
                            "  completada=1, completada_at=NOW(), completada_por=%s, "
                            "  estado_trabajo='completada', "
                            "  observaciones=%s "
                            "WHERE id=%s",
                            (user, observ_final[:1000], tid_mq)
                        )
                        tareas_cerradas += 1

                    # 3.c, 3.d, 3.e — Cerrar OT auditable
                    diagnostico_auto = (
                        f"Levantamiento fotográfico #{lid} cerrado el "
                        f"{_now_chile_str('%d/%m/%Y %H:%M')}. "
                        f"{len(items)} equipo(s) documentado(s) · "
                        f"{lev.get('total_fotos',0)} foto(s) capturadas · "
                        f"{fotos_vinculadas} foto(s) vinculadas a esta OT."
                    )
                    cur.execute(
                        "UPDATE mant_visitas SET "
                        "  estado='cerrada', "
                        "  fecha_realizada=COALESCE(fecha_realizada, CURDATE()), "
                        "  hora_real_fin=COALESCE(hora_real_fin, NOW()), "
                        "  cerrada_at=COALESCE(cerrada_at, NOW()), "
                        "  cerrada_por=%s, "
                        "  diagnostico=COALESCE(NULLIF(diagnostico,''), %s) "
                        "WHERE id=%s",
                        (user, diagnostico_auto, vid)
                    )
                conn.commit()
            finally:
                conn.close()
            # ── Promoción levantamiento → ficha de equipo (async) ──
            # La OT espejo del levantamiento ya está cerrada y suele ser
            # tipo='levantamiento'. Promovemos datos a mant_maquinas.
            try:
                _promover_levantamiento_async(vid, usuario=user)
            except Exception:
                pass
        except Exception as e_ot:
            print(f"[lev_cerrar] error procesando OT espejo: {e_ot}", flush=True)

    try: _mant_log("levantamiento", lid, "cerrado",
                   f"{len(items)} equipo(s) · {lev.get('total_fotos',0)} foto(s) · "
                   f"{fotos_vinculadas} vinculadas a OT · {tareas_cerradas} tareas cerradas")
    except Exception: pass
    return jsonify({
        "ok": True,
        "items_procesados": len(items),
        "visita_cerrada": bool(lev.get("visita_id")),
        "visita_id": lev.get("visita_id"),
        "fotos_vinculadas_a_ot": fotos_vinculadas,
        "tareas_cerradas": tareas_cerradas,
    })


@app.route("/mantenciones/maquinas/<int:mid>")
@_mant_required
def mant_maquina_ficha(mid):
    """Ficha completa del equipo del cliente con:
    - Datos del equipo (foto, marca, modelo, año, voltaje, ubicación)
    - Historial completo de OTs gestionadas (cronológico)
    - Galería de fotos cronológica
    - Stats: cuántas OTs, cuántas fotos, primera/última visita, técnicos
    - Audit log: cambios en serie + eventos

    Permisos: si role=tecnico, solo puede ver equipos que pertenecen a
    una OT que tiene asignada (como principal o colaborador).
    """
    eq = mysql_fetchone(
        "SELECT m.*, c.razon_social, c.id AS cliente_id, c.direccion AS cli_direccion, "
        "       c.comuna AS cli_comuna, c.email_empresa AS cli_email, "
        "       c.tel_empresa AS cli_tel "
        "  FROM mant_maquinas m "
        "  JOIN mant_clientes c ON c.id = m.cliente_id "
        " WHERE m.id=%s",
        (mid,)
    )
    if not eq:
        flash("Equipo no encontrado.", "danger")
        return redirect(url_for("mant_clientes"))
    eq = dict(eq)

    # Permisos: técnico/tecnico_externo solo ve equipos que están en OTs asignadas a él
    # 🔐 SEGURIDAD (2026-05-17): se añadió tecnico_externo (antes solo tecnico).
    u = getattr(g, "user", None) or {}
    role_u = (u.get("role") or "").lower()
    if role_u in ("tecnico", "tecnico_externo"):
        uid = u.get("id")
        autorizado = mysql_fetchone(
            "SELECT 1 FROM mant_visita_tareas vt "
            "  JOIN mant_visitas v ON v.id = vt.visita_id "
            " WHERE vt.maquina_id=%s "
            "   AND (v.tecnico_user_id=%s "
            "        OR v.id IN (SELECT visita_id FROM mant_visita_tecnicos "
            "                    WHERE tecnico_user_id=%s)) "
            " LIMIT 1",
            (mid, uid, uid)
        )
        if not autorizado:
            print(
                f"[SECURITY] {uid} ({u.get('username')}) intento abrir ficha "
                f"equipo mid={mid} sin OT asignada (role={role_u})",
                flush=True
            )
            flash("Este equipo no está en ninguna OT asignada a ti.", "warning")
            return redirect(url_for("mant_ots_list"))

    # Historial COMPLETO de intervenciones (cronológico DESC) — Daniel:
    # "Igual sí me gustaría saber dentro de la ficha, parte, si es que
    # le hicieron mantención, cuándo, quién lo hizo, quién lo gestionó,
    # por qué, todo." — Esto incluye TODAS las OTs (no solo
    # levantamientos), con info enriquecida: diagnóstico, observaciones,
    # número de fotos por equipo y flag de si el levantamiento se aplicó
    # a esta ficha.
    ots_rows = mysql_fetchall(
        "SELECT DISTINCT v.id, v.numero_ot, v.titulo, v.fecha_programada, "
        "       v.hora_inicio, v.hora_fin, v.tipo, v.estado, v.descripcion, "
        "       v.observaciones, v.diagnostico, "
        "       v.modalidad_cobro, v.cerrada_at, v.created_by, "
        "       COALESCE(u.nombre, u.username) AS tecnico_nombre, "
        "       (SELECT COUNT(*) FROM mant_visita_fotos f "
        "          WHERE f.visita_id=v.id AND f.maquina_id=%s) AS fotos_count, "
        "       (SELECT MAX(ml.aplicado_a_ficha) "
        "          FROM mant_maquina_levantamientos ml "
        "         WHERE ml.visita_id=v.id AND ml.maquina_id=%s) AS lev_aplicado "
        "  FROM mant_visitas v "
        "  JOIN mant_visita_tareas t ON t.visita_id = v.id "
        "  LEFT JOIN app_users u ON u.id = v.tecnico_user_id "
        " WHERE t.maquina_id=%s "
        " GROUP BY v.id "
        " ORDER BY v.fecha_programada DESC, v.id DESC LIMIT 100",
        (mid, mid, mid)
    ) or []
    # ── PERF 2026-05-18 (audit Daniel) ─────────────────────────────
    # Antes: N+1 — 1 query por cada OT en `ots_rows` para traer su primera
    # foto. Para una ficha con 100 OTs eran 100 queries extras.
    # Ahora: 1 sola query batched que trae la primera foto por OT vía
    # subquery con MIN(created_at). Luego dict lookup en Python.
    fotos_por_ot = {}
    try:
        ot_ids = [int(r["id"]) for r in ots_rows if r.get("id")]
        if ot_ids:
            # Placeholder list para IN (...)
            # FIX 2026-05-21: usar tomada_at en vez de created_at (la columna
            # se llama tomada_at en mant_visita_fotos según CREATE TABLE).
            ph = ",".join(["%s"] * len(ot_ids))
            rows_foto = mysql_fetchall(
                f"SELECT f.visita_id, f.archivo_path "
                f"  FROM mant_visita_fotos f "
                f"  JOIN mant_visita_tareas t ON t.id = f.tarea_id "
                f"  JOIN (SELECT f2.visita_id, MIN(f2.tomada_at) AS minc "
                f"          FROM mant_visita_fotos f2 "
                f"          JOIN mant_visita_tareas t2 ON t2.id = f2.tarea_id "
                f"         WHERE f2.visita_id IN ({ph}) AND t2.maquina_id=%s "
                f"         GROUP BY f2.visita_id) x "
                f"    ON x.visita_id = f.visita_id AND x.minc = f.tomada_at "
                f" WHERE t.maquina_id=%s ",
                tuple(ot_ids) + (mid, mid)
            ) or []
            for rf in rows_foto:
                if rf.get("visita_id") and rf["visita_id"] not in fotos_por_ot:
                    fotos_por_ot[rf["visita_id"]] = rf.get("archivo_path")
    except Exception:
        pass

    ots = []
    for r in ots_rows:
        d = dict(r)
        if d.get("fecha_programada"):
            d["fecha_programada"] = str(d["fecha_programada"])[:10]
        if d.get("hora_inicio"):
            d["hora_inicio"] = str(d["hora_inicio"])[:5]
        if d.get("hora_fin"):
            d["hora_fin"] = str(d["hora_fin"])[:5]
        if d.get("cerrada_at"):
            d["cerrada_at"] = str(d["cerrada_at"])[:16]
        d["fotos_count"] = int(d.get("fotos_count") or 0)
        d["lev_aplicado"] = bool(d.get("lev_aplicado"))
        # Foto destacada (batched arriba — sin queries individuales)
        d["foto_destacada"] = fotos_por_ot.get(d["id"])
        ots.append(d)

    # Fotos cronológicas del equipo (de mant_maquina_fotos — capturadas
    # por el técnico en el modo ejecución como foto principal del equipo)
    # FIX 2026-05-21: orden por tomada_at (created_at puede no existir en
    # filas viejas si la migración aún no corrió).
    fotos_rows = mysql_fetchall(
        "SELECT id, archivo_path, cloudinary_url, descripcion, tomada_por, "
        "       tomada_at AS created_at, levantamiento_id "
        "  FROM mant_maquina_fotos WHERE maquina_id=%s "
        " ORDER BY tomada_at DESC LIMIT 200",
        (mid,)
    ) or []
    fotos = []
    for r in fotos_rows:
        url = r.get("cloudinary_url") or (
            f"/static/uploads/mantenciones/{r['archivo_path']}"
            if r.get("archivo_path") else ""
        )
        if not url:
            continue
        fotos.append({
            "id": r["id"],
            "url": url,
            "descripcion": r.get("descripcion") or "",
            "tomada_por": r.get("tomada_por") or "",
            "created_at": str(r["created_at"])[:16] if r.get("created_at") else "",
        })

    # Audit log: eventos del equipo
    eventos_rows = mysql_fetchall(
        "SELECT id, tipo, descripcion, fecha_evento, created_by "
        "  FROM mant_maquina_eventos WHERE maquina_id=%s "
        " ORDER BY fecha_evento DESC LIMIT 50",
        (mid,)
    ) or []
    eventos = []
    for e in eventos_rows:
        d = dict(e)
        if d.get("fecha_evento"):
            d["fecha_evento"] = str(d["fecha_evento"])[:16]
        eventos.append(d)

    # Stats compactas (incluye breakdown para card de historial)
    _estados_abiertos = ("programada", "en_curso", "en_ejecucion", "pendiente_aprobacion")
    stats = {
        "total_ots": len(ots),
        "total_fotos": len(fotos),
        "ots_cerradas": sum(1 for o in ots if o.get("estado") == "cerrada"),
        "ots_abiertas": sum(1 for o in ots if o.get("estado") in _estados_abiertos),
        "ots_canceladas": sum(1 for o in ots if o.get("estado") == "cancelada"),
        "primera_visita": ots[-1]["fecha_programada"] if ots else None,
        "ultima_visita": ots[0]["fecha_programada"] if ots else None,
        "tecnicos": list({o.get("tecnico_nombre") for o in ots if o.get("tecnico_nombre")}),
        # Conteo por tipo para chips/filtros
        "por_tipo": {},
    }
    for _o in ots:
        _t = (_o.get("tipo") or "otro").lower()
        stats["por_tipo"][_t] = stats["por_tipo"].get(_t, 0) + 1

    # ── Levantamientos de esta máquina (último + historial) ──
    # Daniel pidió que en la ficha del equipo se vea la información
    # que rellenó el técnico SOLAMENTE durante el levantamiento de
    # ficha. Otras OTs (preventiva, correctiva, etc.) quedan en el
    # historial pero no se mezclan acá.
    levantamientos = []
    try:
        lev_rows = mysql_fetchall(
            "SELECT ml.id, ml.visita_id, ml.fecha_levantamiento, ml.tecnico_nombre, "
            "       ml.datos_json, ml.fotos_count, ml.observaciones, "
            "       ml.aplicado_a_ficha, ml.aplicado_at, ml.created_at, "
            "       v.numero_ot, v.titulo AS ot_titulo "
            "  FROM mant_maquina_levantamientos ml "
            "  LEFT JOIN mant_visitas v ON v.id = ml.visita_id "
            " WHERE ml.maquina_id=%s "
            " ORDER BY ml.fecha_levantamiento DESC, ml.id DESC "
            " LIMIT 50",
            (mid,)
        ) or []
        for r in lev_rows:
            d = dict(r)
            if d.get("fecha_levantamiento"):
                d["fecha_levantamiento"] = str(d["fecha_levantamiento"])[:10]
            if d.get("aplicado_at"):
                d["aplicado_at"] = str(d["aplicado_at"])[:16]
            if d.get("created_at"):
                d["created_at"] = str(d["created_at"])[:16]
            # Parsear datos_json para mostrarlos como lista
            d["datos"] = []
            if d.get("datos_json"):
                try:
                    d["datos"] = json.loads(d["datos_json"]) or []
                except Exception:
                    d["datos"] = []
            d.pop("datos_json", None)
            # Adjuntar fotos de la OT vinculadas a este equipo
            try:
                fr = mysql_fetchall(
                    "SELECT id, archivo_path, descripcion, tomada_por, tomada_at "
                    "  FROM mant_visita_fotos "
                    " WHERE visita_id=%s AND maquina_id=%s "
                    " ORDER BY tomada_at ASC LIMIT 12",
                    (d["visita_id"], mid)
                ) or []
                d["fotos"] = [
                    {
                        "url": f.get("archivo_path"),
                        "descripcion": f.get("descripcion") or "",
                        "tomada_por": f.get("tomada_por") or "",
                        "tomada_at": str(f["tomada_at"])[:16] if f.get("tomada_at") else "",
                    }
                    for f in fr if f.get("archivo_path")
                ]
            except Exception:
                d["fotos"] = []
            d["numero_ot"] = d.get("numero_ot") or f"VS-{d['visita_id']:05d}"
            levantamientos.append(d)
    except Exception as _e_lev:
        # La tabla puede no existir si la migración no corrió todavía
        print(f"[maquina_ficha] no se pudo cargar levantamientos m={mid}: {_e_lev}",
              flush=True)
        levantamientos = []
    ultimo_levantamiento = levantamientos[0] if levantamientos else None

    # ── Flag is_admin: el template muestra controles override de foto ──
    perms = g.get("permissions") or {}
    is_admin = bool(perms.get("superadmin") or perms.get("admin"))

    return render_template(
        "mantenciones/maquina_ficha.html",
        equipo=eq,
        ots=ots,
        fotos=fotos,
        eventos=eventos,
        stats=stats,
        levantamientos=levantamientos,
        ultimo_levantamiento=ultimo_levantamiento,
        is_admin=is_admin,
    )


@app.route("/mantenciones/api/maquinas/<int:mid>/timeline")
@_mant_required
def mant_maquina_timeline(mid):
    """Timeline de la 'ficha potente' del equipo: eventos + fotos + visitas."""
    eventos = mysql_fetchall(
        "SELECT id, tipo, descripcion, fecha_evento, referencia_tabla, referencia_id, "
        "       metadata_json, created_by "
        "  FROM mant_maquina_eventos WHERE maquina_id=%s "
        " ORDER BY fecha_evento DESC LIMIT 100",
        (mid,)
    ) or []
    for e in eventos:
        if e.get("fecha_evento"):
            e["fecha_evento"] = str(e["fecha_evento"])[:16]
        if e.get("metadata_json"):
            try: e["metadata"] = json.loads(e["metadata_json"])
            except Exception: e["metadata"] = None
        e.pop("metadata_json", None)
    return jsonify({"ok": True, "eventos": eventos})


@app.route("/mantenciones/api/maquinas/<int:mid>/historial-ots")
@_mant_required
def mant_maquina_historial_ots(mid):
    """Historial de OTs ejecutadas sobre este equipo.
    Une con mant_visita_tareas (donde la tarea tiene maquina_id=mid) y devuelve
    cada OT distinta con fecha, hora, tipo, estado, técnico responsable y
    usuario que la cerró.
    """
    rows = mysql_fetchall(
        """SELECT DISTINCT v.id, v.numero_ot, v.titulo, v.fecha_programada,
                  v.hora_inicio, v.hora_fin, v.hora_real_inicio, v.hora_real_fin,
                  v.tipo, v.estado, v.descripcion, v.tecnico,
                  v.cerrada_at, v.created_by,
                  COALESCE(u.nombre, u.username) AS tecnico_nombre,
                  u.username AS tecnico_username
             FROM mant_visitas v
             JOIN mant_visita_tareas t ON t.visita_id=v.id
             LEFT JOIN app_users u ON u.id=v.tecnico_user_id
            WHERE t.maquina_id=%s
            ORDER BY v.fecha_programada DESC, v.id DESC
            LIMIT 100""",
        (mid,)
    ) or []
    out = []
    for r in rows:
        out.append({
            "id":              r["id"],
            "numero_ot":       r.get("numero_ot") or f"VS-{r['id']:05d}",
            "titulo":          r.get("titulo") or "",
            "fecha":           str(r["fecha_programada"])[:10] if r.get("fecha_programada") else "",
            "hora_inicio":     str(r["hora_inicio"])[:5] if r.get("hora_inicio") else "",
            "hora_fin":        str(r["hora_fin"])[:5] if r.get("hora_fin") else "",
            "hora_real_ini":   str(r["hora_real_inicio"])[:16] if r.get("hora_real_inicio") else "",
            "hora_real_fin":   str(r["hora_real_fin"])[:16] if r.get("hora_real_fin") else "",
            "tipo":            r.get("tipo") or "",
            "estado":          r.get("estado") or "",
            "descripcion":     r.get("descripcion") or "",
            "tecnico":         r.get("tecnico_nombre") or r.get("tecnico") or "",
            "tecnico_username": r.get("tecnico_username") or "",
            "creado_por":      r.get("created_by") or "",
            "cerrada_at":      str(r["cerrada_at"])[:16] if r.get("cerrada_at") else "",
            # Link directo a la ficha OT
            "url":             f"/mantenciones/ot/{r['id']}",
        })
    return jsonify({"ok": True, "ots": out, "total": len(out)})


# ════════════════════════════════════════════════════════════════════════
# FICHA TÉCNICA INLINE (JSON) — usado en el modal "Ver ficha técnica"
# del flujo de levantamiento (ot_ejecutar.html) y desde la ficha del
# cliente, tab Equipos. Snapshot completo con trazabilidad profunda.
#
# Daniel (2026-05-21): "Cuántas veces se ha visitado este equipo (no el
# cliente, el equipo específico) + historial cambios serial + estado +
# galería de fotos por visita + alertas dinámicas + contratos relacionados".
#
# Performance: queries críticas indexadas (mant_visita_tareas.maquina_id,
# mant_maquina_fotos.maquina_id, mant_maquina_audit.maquina_id). Para
# fichas con >20 OTs históricas, se usa paginación implícita (LIMIT 100
# en historial + LIMIT 50 en seriales/estados).
# ════════════════════════════════════════════════════════════════════════

# ─────────────────────────────────────────────────────────────────────
# ENDPOINT BATCH FICHA TÉCNICA (Daniel 2026-05-26 audit DevTools):
# El frontend mostraba 51 fetch (uno por máquina × 3.6s) = N+1 grave.
# Este endpoint devuelve un dict {id: ficha_resumida} de muchos equipos
# en UNA sola request, con datos LIGHT suficientes para la tabla.
# El detalle profundo (todas las tabs) sigue en el endpoint individual.
# ─────────────────────────────────────────────────────────────────────
@app.route("/mantenciones/api/maquinas/ficha-tecnica-batch")
@_mant_required
def mant_maquinas_ficha_tecnica_batch():
    """Versión LIGHT batch para la tabla de equipos del cliente.

    Query: ?ids=1,2,3,4,5 (máximo 200 ids)

    Devuelve { ok, items: { "1": {nombre, foto_url, score, ...}, ... } }

    Para datos profundos (historial, alertas, revisiones), usar el
    endpoint individual /api/maquinas/<mid>/ficha-tecnica.
    """
    ids_param = (request.args.get("ids") or "").strip()
    if not ids_param:
        return jsonify({"ok": True, "items": {}})
    try:
        ids = [int(x) for x in ids_param.split(",") if x.strip()]
        ids = list(dict.fromkeys(ids))[:200]  # dedup + cap
    except (ValueError, TypeError):
        return jsonify({"ok": False, "error": "ids inválidos"}), 400
    if not ids:
        return jsonify({"ok": True, "items": {}})

    placeholders = ",".join(["%s"] * len(ids))

    # 1 query — datos básicos de los equipos
    eq_rows = mysql_fetchall(
        f"SELECT id, cliente_id, nombre, sku, serie, marca, modelo, "
        f"       estado, estado_op, foto_url, familia_equipo, "
        f"       ubicacion_sala, anio_fabricacion, fecha_fin_garantia "
        f"  FROM mant_maquinas WHERE id IN ({placeholders})",
        tuple(ids)
    ) or []

    # 1 query — última foto por equipo (Cloudinary o disco)
    fotos_map = {}
    try:
        rows_f = mysql_fetchall(
            f"SELECT maquina_id, MAX(tomada_at) AS ultima, "
            f"       COUNT(*) AS n_fotos "
            f"  FROM mant_maquina_fotos WHERE maquina_id IN ({placeholders}) "
            f" GROUP BY maquina_id",
            tuple(ids)
        ) or []
        for r in rows_f:
            fotos_map[r["maquina_id"]] = {
                "ultima_foto": str(r["ultima"])[:10] if r.get("ultima") else "",
                "n_fotos": int(r.get("n_fotos") or 0),
            }
    except Exception:
        pass

    # 1 query — última revisión por equipo (estado + fecha)
    rev_map = {}
    try:
        rows_r = mysql_fetchall(
            f"SELECT maquina_id, estado_revision, revisado_por, revisado_at "
            f"  FROM mant_visita_equipos "
            f" WHERE maquina_id IN ({placeholders}) "
            f"   AND revisado_at IS NOT NULL "
            f" ORDER BY revisado_at DESC",
            tuple(ids)
        ) or []
        for r in rows_r:
            mid_r = r["maquina_id"]
            if mid_r not in rev_map:  # tomar solo la más reciente
                rev_map[mid_r] = {
                    "ultima_revision_fecha": str(r["revisado_at"])[:10] if r.get("revisado_at") else "",
                    "ultima_revision_estado": r.get("estado_revision") or "",
                    "ultima_revision_por": r.get("revisado_por") or "",
                }
    except Exception:
        pass

    items = {}
    hoy = datetime.now().date()
    for eq in eq_rows:
        mid = eq["id"]
        # Score de calidad LIGHT (criterios rápidos sin queries extras)
        fotos_data = fotos_map.get(mid, {})
        rev_data   = rev_map.get(mid, {})
        score = 0
        if eq.get("foto_url"):           score += 12
        if eq.get("serie"):              score += 10
        if eq.get("sku"):                score += 8
        if eq.get("familia_equipo") and eq.get("familia_equipo") != "otros": score += 8
        if eq.get("ubicacion_sala"):     score += 8
        if eq.get("marca") or eq.get("modelo"): score += 8
        if eq.get("anio_fabricacion"):   score += 6
        if fotos_data.get("n_fotos", 0) > 0:    score += 10
        if rev_data.get("ultima_revision_fecha"): score += 10
        if eq.get("fecha_fin_garantia"): score += 4
        # +16 puntos no calculables en batch (contrato, observaciones)
        # se considera "perfecto" al 84 en batch
        estado_calidad = (
            "completa" if score >= 70
            else "buena" if score >= 50
            else "revisar_datos" if score >= 30
            else "incompleta"
        )
        items[str(mid)] = {
            "id":         mid,
            "nombre":     eq.get("nombre") or "",
            "sku":        eq.get("sku") or "",
            "serie":      eq.get("serie") or "",
            "marca":      eq.get("marca") or "",
            "modelo":     eq.get("modelo") or "",
            "familia":    eq.get("familia_equipo") or "",
            "ubicacion":  eq.get("ubicacion_sala") or "",
            "estado":     eq.get("estado") or "activo",
            "foto_url":   eq.get("foto_url") or "",
            "n_fotos":    fotos_data.get("n_fotos", 0),
            "ultima_foto":          fotos_data.get("ultima_foto", ""),
            "ultima_revision_fecha":  rev_data.get("ultima_revision_fecha", ""),
            "ultima_revision_estado": rev_data.get("ultima_revision_estado", ""),
            "ultima_revision_por":    rev_data.get("ultima_revision_por", ""),
            "calidad_score":   score,
            "calidad_estado":  estado_calidad,
        }
    return jsonify({"ok": True, "items": items, "count": len(items)})


# ── Cache 60s del JSON ficha-tecnica por máquina (Daniel 2026-05-27) ──
# Live audit: 7-9 queries × 400ms latencia red = 3.2s por click en ojo.
# El dict completo es ~3KB. Cachear 60s por maquina_id corta esto a ~10ms.
# Invalidación: llamar _ft_cache_invalidar(mid) tras editar el equipo.
_FT_JSON_CACHE = {}  # mid -> (data_dict, ts)
_FT_JSON_LOCK  = threading.Lock()
_FT_JSON_TTL   = 60


def _ft_cache_invalidar(mid=None):
    """Llamar tras editar equipo / agregar foto / cambiar serie / nueva OT."""
    with _FT_JSON_LOCK:
        if mid is None:
            _FT_JSON_CACHE.clear()
        else:
            _FT_JSON_CACHE.pop(int(mid), None)


@app.route("/mantenciones/api/maquinas/<int:mid>/ficha-tecnica")
@_mant_required
def mant_maquina_ficha_tecnica_json(mid):
    """Snapshot JSON profundo de la ficha técnica del equipo.
    Cacheado 60s por maquina_id (audit DevTools: era 3.2s por click).

    Estructura devuelta:
      - equipo       → datos básicos + cliente + ubicación + garantía
      - stats        → contadores y métricas (visitas, fotos, edad, días desde última)
      - historial_visitas    → últimas 100 OTs sobre este equipo
      - historial_seriales   → audit log de cambios de N° serie
      - historial_estado     → audit log de cambios de estado
      - fotos_galeria        → galería permanente del equipo (mant_maquina_fotos)
      - contratos_relacionados → contratos vigentes del cliente
      - alertas      → alertas dinámicas calculadas
    """
    # Cache hit (rápido y seguro: la ficha cambia con frecuencia DE MINUTOS)
    _now_ft = time.time()
    with _FT_JSON_LOCK:
        _entry_ft = _FT_JSON_CACHE.get(mid)
    if _entry_ft and (_now_ft - _entry_ft[1]) < _FT_JSON_TTL:
        return jsonify(_entry_ft[0])

    eq = mysql_fetchone(
        "SELECT m.*, c.razon_social, c.rut AS cli_rut, c.direccion AS cli_direccion, "
        "       c.comuna AS cli_comuna "
        "  FROM mant_maquinas m "
        "  JOIN mant_clientes c ON c.id = m.cliente_id "
        " WHERE m.id=%s",
        (mid,)
    )
    if not eq:
        return jsonify({"ok": False, "error": "Equipo no encontrado"}), 404
    eq = dict(eq)

    # Permisos: técnico solo ve si la máquina está en una OT asignada a él.
    u = getattr(g, "user", None) or {}
    role_u = (u.get("role") or "").lower()
    if role_u in ("tecnico", "tecnico_externo"):
        uid = u.get("id")
        autorizado = mysql_fetchone(
            "SELECT 1 FROM mant_visita_tareas vt "
            "  JOIN mant_visitas v ON v.id = vt.visita_id "
            " WHERE vt.maquina_id=%s "
            "   AND (v.tecnico_user_id=%s "
            "        OR v.id IN (SELECT visita_id FROM mant_visita_tecnicos "
            "                    WHERE tecnico_user_id=%s)) "
            " LIMIT 1",
            (mid, uid, uid)
        )
        if not autorizado:
            return jsonify({"ok": False, "error": "Equipo no asignado a tus OTs"}), 403

    hoy = datetime.now().date()
    cliente_id = eq.get("cliente_id")

    # ── 1. Fotos galería (mant_maquina_fotos) ──────────────────────
    # ORDER BY tomada_at (existe desde la migración inicial). NO usamos
    # created_at porque puede no estar poblado en filas viejas.
    fotos_rows = mysql_fetchall(
        "SELECT id, archivo_path, cloudinary_url, descripcion, tipo_foto, "
        "       tomada_por, tomada_at, visita_origen, levantamiento_id "
        "  FROM mant_maquina_fotos WHERE maquina_id=%s "
        " ORDER BY tomada_at DESC LIMIT 50",
        (mid,)
    ) or []
    fotos_galeria = []
    foto_principal_url = (eq.get("foto_url") or "").strip()
    for r in fotos_rows:
        url = r.get("cloudinary_url") or (
            f"/static/uploads/mantenciones/{r['archivo_path']}"
            if r.get("archivo_path") else ""
        )
        if not url:
            continue
        # Para la primera (más reciente) que tenga visita_origen, marcamos
        # como referencia para la "última foto del último levantamiento"
        if not foto_principal_url and url:
            foto_principal_url = url
        fotos_galeria.append({
            "id": r["id"],
            "url": url,
            "tipo_foto": r.get("tipo_foto") or "principal",
            "descripcion": r.get("descripcion") or "",
            "tomada_por": r.get("tomada_por") or "",
            "fecha": str(r["tomada_at"])[:16] if r.get("tomada_at") else "",
            "visita_origen": r.get("visita_origen"),
            "levantamiento_id": r.get("levantamiento_id"),
        })

    # ── 2. Historial de visitas (TODAS las OTs con tareas sobre este equipo) ──
    visitas_rows = mysql_fetchall(
        "SELECT DISTINCT v.id, v.numero_ot, v.titulo, v.tipo, v.estado, "
        "       v.fecha_programada, v.cerrada_at, v.observaciones, v.diagnostico, "
        "       v.factura_tido, v.factura_nudo, "
        "       COALESCE(u.nombre, u.username) AS tecnico_nombre, "
        "       (SELECT COUNT(*) FROM mant_visita_fotos f "
        "          WHERE f.visita_id=v.id AND f.maquina_id=%s) AS fotos_count "
        "  FROM mant_visitas v "
        "  JOIN mant_visita_tareas t ON t.visita_id=v.id "
        "  LEFT JOIN app_users u ON u.id=v.tecnico_user_id "
        " WHERE t.maquina_id=%s "
        " GROUP BY v.id "
        " ORDER BY v.fecha_programada DESC, v.id DESC LIMIT 100",
        (mid, mid)
    ) or []
    historial_visitas = []
    n_preventivas = 0
    n_correctivas = 0
    n_levantamientos = 0
    ultima_fecha = None
    ultima_tipo = None
    ultima_preventiva = None
    for r in visitas_rows:
        tipo_v = (r.get("tipo") or "").lower()
        if tipo_v == "preventiva":
            n_preventivas += 1
            if not ultima_preventiva and r.get("fecha_programada"):
                ultima_preventiva = r["fecha_programada"]
        elif tipo_v == "correctiva":
            n_correctivas += 1
        elif tipo_v == "levantamiento":
            n_levantamientos += 1
        if ultima_fecha is None and r.get("fecha_programada"):
            ultima_fecha = r["fecha_programada"]
            ultima_tipo = r.get("tipo") or ""
        factura = None
        if r.get("factura_tido") and r.get("factura_nudo"):
            factura = {"tido": r["factura_tido"], "nudo": r["factura_nudo"]}
        historial_visitas.append({
            "id": r["id"],
            "numero_ot": r.get("numero_ot") or f"VS-{r['id']:05d}",
            "titulo": r.get("titulo") or "",
            "fecha": str(r["fecha_programada"])[:10] if r.get("fecha_programada") else "",
            "tipo": r.get("tipo") or "",
            "estado": r.get("estado") or "",
            "tecnico": r.get("tecnico_nombre") or "",
            "observaciones": (r.get("observaciones") or "")[:300],
            "diagnostico": (r.get("diagnostico") or "")[:300],
            "fotos_count": int(r.get("fotos_count") or 0),
            "cerrada_at": str(r["cerrada_at"])[:16] if r.get("cerrada_at") else "",
            "factura": factura,
            "url": f"/mantenciones/ot/{r['id']}",
        })

    # ── 3. Historial de seriales (mant_maquina_audit, campo='serie') ──
    historial_seriales = []
    try:
        ser_rows = mysql_fetchall(
            "SELECT fecha, valor_antes, valor_nuevo, motivo, usuario "
            "  FROM mant_maquina_audit "
            " WHERE maquina_id=%s AND campo='serie' "
            " ORDER BY fecha DESC LIMIT 50",
            (mid,)
        ) or []
        for r in ser_rows:
            historial_seriales.append({
                "fecha": str(r["fecha"])[:16] if r.get("fecha") else "",
                "valor_anterior": r.get("valor_antes") or "",
                "valor_nuevo": r.get("valor_nuevo") or "",
                "razon": r.get("motivo") or "",
                "usuario": r.get("usuario") or "",
            })
    except Exception:
        historial_seriales = []

    # ── 4. Historial de estado (mant_maquina_audit, campo='estado') ──
    historial_estado = []
    try:
        est_rows = mysql_fetchall(
            "SELECT fecha, valor_antes, valor_nuevo, motivo, usuario "
            "  FROM mant_maquina_audit "
            " WHERE maquina_id=%s AND campo IN ('estado','estado_op','dado_baja') "
            " ORDER BY fecha DESC LIMIT 50",
            (mid,)
        ) or []
        for r in est_rows:
            historial_estado.append({
                "fecha": str(r["fecha"])[:16] if r.get("fecha") else "",
                "estado_anterior": r.get("valor_antes") or "",
                "estado_nuevo": r.get("valor_nuevo") or "",
                "razon": r.get("motivo") or "",
                "usuario": r.get("usuario") or "",
            })
    except Exception:
        historial_estado = []

    # ── 5. Contratos relacionados (vigentes / por vencer) ──
    contratos = []
    try:
        c_rows = mysql_fetchall(
            "SELECT id, nombre, fecha_inicio, fecha_vencimiento, es_indefinido, "
            "       estado, monto_mensual, sla_horas "
            "  FROM mant_contratos "
            " WHERE cliente_id=%s "
            "   AND estado IN ('vigente','indefinido','por_vencer') "
            " ORDER BY fecha_inicio DESC LIMIT 10",
            (cliente_id,)
        ) or []
        for r in c_rows:
            dias_restantes = None
            if r.get("fecha_vencimiento") and not r.get("es_indefinido"):
                fv = r["fecha_vencimiento"]
                if isinstance(fv, datetime):
                    fv = fv.date()
                try:
                    dias_restantes = (fv - hoy).days
                except Exception:
                    dias_restantes = None
            contratos.append({
                "id": r["id"],
                "nombre": r.get("nombre") or "",
                "fecha_inicio": str(r["fecha_inicio"])[:10] if r.get("fecha_inicio") else "",
                "fecha_vencimiento": str(r["fecha_vencimiento"])[:10] if r.get("fecha_vencimiento") else "",
                "es_indefinido": bool(r.get("es_indefinido")),
                "estado": r.get("estado") or "vigente",
                "dias_restantes": dias_restantes,
            })
    except Exception:
        contratos = []

    # ── 6. STATS calculadas ────────────────────────────────────────
    dias_desde_ultima = None
    if ultima_fecha:
        f_ult = ultima_fecha
        if isinstance(f_ult, datetime):
            f_ult = f_ult.date()
        try:
            dias_desde_ultima = (hoy - f_ult).days
        except Exception:
            dias_desde_ultima = None

    edad_anios = None
    if eq.get("anio_fabricacion"):
        try:
            edad_anios = round(hoy.year - int(eq["anio_fabricacion"]) +
                              (hoy.month - 1) / 12.0, 1)
        except Exception:
            edad_anios = None

    dias_en_garantia = None
    if eq.get("fecha_fin_garantia"):
        fg = eq["fecha_fin_garantia"]
        if isinstance(fg, datetime):
            fg = fg.date()
        try:
            dias_en_garantia = (fg - hoy).days
        except Exception:
            dias_en_garantia = None

    stats = {
        "n_visitas_total": len(historial_visitas),
        "n_visitas_preventivas": n_preventivas,
        "n_visitas_correctivas": n_correctivas,
        "n_levantamientos": n_levantamientos,
        "n_fotos_total": len(fotos_galeria),
        "n_cambios_serial": len(historial_seriales),
        "n_cambios_estado": len(historial_estado),
        "ultima_visita_fecha": str(ultima_fecha)[:10] if ultima_fecha else None,
        "ultima_visita_tipo": ultima_tipo or "",
        "dias_desde_ultima_visita": dias_desde_ultima,
        "edad_anios": edad_anios,
        "dias_en_garantia": dias_en_garantia,
    }

    # ── 7. ALERTAS dinámicas ───────────────────────────────────────
    alertas = []
    # Garantía
    if dias_en_garantia is not None:
        if dias_en_garantia < 0:
            alertas.append({
                "severidad": "warning",
                "icono": "shield-x",
                "texto": f"Garantía vencida hace {abs(dias_en_garantia)} día(s)",
            })
        elif dias_en_garantia <= 30:
            alertas.append({
                "severidad": "warning",
                "icono": "shield-exclamation",
                "texto": f"Garantía vence en {dias_en_garantia} día(s)",
            })
    # Visitas preventivas
    if not n_preventivas and len(historial_visitas) > 0:
        alertas.append({
            "severidad": "info",
            "icono": "calendar-x",
            "texto": "Este equipo nunca ha tenido una mantención preventiva",
        })
    elif n_preventivas and dias_desde_ultima is not None and dias_desde_ultima > 120:
        alertas.append({
            "severidad": "warning",
            "icono": "clock-history",
            "texto": f"Sin visita preventiva en {dias_desde_ultima // 30} mes(es)",
        })
    # Serial cambiado recientemente
    if historial_seriales:
        try:
            f_cambio = historial_seriales[0].get("fecha")
            if f_cambio:
                f_d = datetime.strptime(f_cambio[:10], "%Y-%m-%d").date()
                dias_cambio = (hoy - f_d).days
                if dias_cambio <= 60:
                    alertas.append({
                        "severidad": "info",
                        "icono": "info-circle",
                        "texto": f"Serial cambiado hace {dias_cambio} día(s) — verificar coincidencia con activo físico",
                    })
        except Exception:
            pass
    # Estado: si está dado de baja
    if (eq.get("estado") or "").lower() == "baja":
        alertas.append({
            "severidad": "danger",
            "icono": "x-octagon",
            "texto": "Equipo dado de baja",
        })
    elif (eq.get("estado_op") or "").lower() in ("critico", "fuera_servicio"):
        alertas.append({
            "severidad": "danger",
            "icono": "exclamation-triangle",
            "texto": f"Estado operacional: {eq.get('estado_op')}",
        })
    # Sin fotos
    if not fotos_galeria and len(historial_visitas) > 0:
        alertas.append({
            "severidad": "info",
            "icono": "image",
            "texto": "Sin fotos en la galería del equipo — captura una en la próxima visita",
        })

    # ── 8. Datos del equipo (formateados) ──────────────────────────
    out_eq = {
        "id": eq["id"],
        "cliente_id": cliente_id,
        "razon_social": eq.get("razon_social") or "",
        "cli_rut": eq.get("cli_rut") or "",
        "cli_direccion": eq.get("cli_direccion") or "",
        "cli_comuna": eq.get("cli_comuna") or "",
        "nombre": eq.get("nombre") or "",
        "sku": eq.get("sku") or "",
        "serie": eq.get("serie") or "",
        "serie_actual": eq.get("serie") or "",
        "marca": eq.get("marca") or "",
        "modelo": eq.get("modelo") or "",
        "anio_fabricacion": eq.get("anio_fabricacion"),
        "voltaje": eq.get("voltaje") or "",
        "ubicacion_sala": eq.get("ubicacion_sala") or "",
        "ubicacion_cliente": eq.get("ubicacion_cliente") or "",
        "familia_equipo": eq.get("familia_equipo") or "",
        "fecha_instalacion": str(eq["fecha_instalacion"])[:10] if eq.get("fecha_instalacion") else "",
        "fecha_fin_garantia": str(eq["fecha_fin_garantia"])[:10] if eq.get("fecha_fin_garantia") else "",
        "estado": eq.get("estado") or "activo",
        "estado_op": eq.get("estado_op") or "operativo",
        "estado_capturado": eq.get("estado_capturado") or "",
        "tiene_dano": bool(eq.get("tiene_dano")),
        "observaciones": eq.get("observaciones") or "",
        "foto_url": eq.get("foto_url") or "",
        "foto_principal_url": foto_principal_url,
        "tag_1": eq.get("tag_1") or "",
        "tag_2": eq.get("tag_2") or "",
        "ultima_intervencion": str(eq["ultima_intervencion"])[:10] if eq.get("ultima_intervencion") else "",
        "visitas_count": int(eq.get("visitas_count") or 0),
        "doc_origen": eq.get("doc_origen") or "",
        "doc_fecha": str(eq["doc_fecha"])[:10] if eq.get("doc_fecha") else "",
        # 2026-05-26 (Daniel) — Datos físicos visibles en tab Resumen
        "peso_kg": float(eq["peso_kg"]) if eq.get("peso_kg") is not None else None,
        "dimensiones": eq.get("dimensiones") or "",
        "color": eq.get("color") or "",
    }

    # ── 9. (2026-05-21 Daniel) — Última revisión + timeline desde
    #       mant_visita_equipos. Da contexto inmediato al usuario sobre
    #       el estado real del equipo en la última visita.
    ultima_revision = None
    revisiones_counters = {
        "total": 0, "verificado": 0, "con_cambios": 0,
        "saltado": 0, "falla_detectada": 0,
    }
    revisiones_timeline = []
    try:
        rev_rows = mysql_fetchall(
            "SELECT ve.visita_id, ve.estado_revision, ve.razon_saltado, "
            "       ve.observacion_tecnico, ve.revisado_at, ve.revisado_por, "
            "       v.numero_ot, v.tipo AS visita_tipo, v.fecha_programada, "
            "       v.estado AS visita_estado "
            "  FROM mant_visita_equipos ve "
            "  JOIN mant_visitas v ON v.id = ve.visita_id "
            " WHERE ve.maquina_id=%s "
            " ORDER BY COALESCE(ve.revisado_at, v.fecha_programada) DESC, ve.id DESC "
            " LIMIT 50",
            (mid,)
        ) or []
        for _r in rev_rows:
            _est = (_r.get("estado_revision") or "verificado").lower()
            revisiones_counters["total"] += 1
            revisiones_counters[_est] = revisiones_counters.get(_est, 0) + 1
            revisiones_timeline.append({
                "visita_id":       _r["visita_id"],
                "numero_ot":       _r.get("numero_ot") or f"VS-{_r['visita_id']:05d}",
                "tipo_visita":     _r.get("visita_tipo") or "",
                "estado_visita":   _r.get("visita_estado") or "",
                "fecha":           str(_r["fecha_programada"])[:10] if _r.get("fecha_programada") else "",
                "revisado_at":     str(_r["revisado_at"])[:16] if _r.get("revisado_at") else "",
                "revisado_por":    _r.get("revisado_por") or "",
                "estado_revision": _est,
                "razon_saltado":   _r.get("razon_saltado") or "",
                "observacion":     _r.get("observacion_tecnico") or "",
                "url_ot":          f"/mantenciones/ot/{_r['visita_id']}",
            })
        if revisiones_timeline:
            ultima_revision = revisiones_timeline[0]
    except Exception as _e_rev:
        print(f"[ficha-tecnica] revisiones load error: {_e_rev}", flush=True)

    # ── CALIDAD DE FICHA 2026-05-26 (Daniel — Ficha técnica CMMS) ──
    # Score 0-100 con criterios objetivos. Daniel quiere ver de un vistazo
    # qué equipos tienen ficha completa vs incompleta para priorizar
    # levantamientos pendientes. Cada criterio aporta puntos:
    _cal_score = 0
    _cal_checks = []
    def _cal_add(criterio, puntos, cumple):
        nonlocal _cal_score
        if cumple:
            _cal_score += puntos
        _cal_checks.append({
            "criterio": criterio, "puntos": puntos, "cumple": bool(cumple)
        })
    _cal_add("Foto principal cargada", 12, bool(foto_principal_url or fotos_galeria))
    _cal_add("Número de serie informado", 10, bool(eq.get("serie")))
    _cal_add("SKU informado", 8, bool(eq.get("sku")))
    _cal_add("Categoría / familia", 8, bool(eq.get("familia_equipo") and eq.get("familia_equipo") != "otros"))
    _cal_add("Ubicación informada", 8, bool(eq.get("ubicacion_sala") or eq.get("ubicacion_cliente")))
    _cal_add("Marca / modelo", 8, bool(eq.get("marca") or eq.get("modelo")))
    _cal_add("Año de fabricación", 6, bool(eq.get("anio_fabricacion")))
    _cal_add("Contrato vigente asociado", 12, bool(contratos))
    _cal_add("Al menos una foto en galería", 10, len(fotos_galeria) >= 1)
    _cal_add("Al menos un levantamiento/revisión", 10, bool(revisiones_timeline) or bool(historial_visitas))
    _cal_add("Observaciones registradas", 4, bool(eq.get("observaciones")))
    _cal_add("Fecha de garantía conocida", 4, bool(eq.get("fecha_fin_garantia") or eq.get("fecha_instalacion")))
    _cal_score = min(100, _cal_score)
    _cal_estado = (
        "completa" if _cal_score >= 80
        else "buena" if _cal_score >= 60
        else "revisar_datos" if _cal_score >= 40
        else "incompleta"
    )
    calidad_ficha = {
        "score": _cal_score,
        "estado": _cal_estado,
        "criterios": _cal_checks,
        "pendientes": [c["criterio"] for c in _cal_checks if not c["cumple"]],
    }

    _ft_response = {
        "ok": True,
        "equipo": out_eq,
        "stats": stats,
        "historial_visitas": historial_visitas,
        "historial_seriales": historial_seriales,
        "historial_estado": historial_estado,
        "fotos_galeria": fotos_galeria,
        "contratos_relacionados": contratos,
        "alertas": alertas,
        # 2026-05-26 (Daniel — ficha CMMS) — calidad de información
        "calidad_ficha": calidad_ficha,
        # 2026-05-21 (Daniel) — trazabilidad por equipo
        "ultima_revision": ultima_revision,
        "revisiones_timeline": revisiones_timeline,
        "revisiones_counters": revisiones_counters,
        # Compatibilidad backward — endpoints antiguos esperan estos campos
        "fotos": fotos_galeria[:8],
        "contratos": contratos,
        "ots": [
            {
                "id": h["id"],
                "numero_ot": h["numero_ot"],
                "titulo": h["titulo"],
                "tipo": h["tipo"],
                "estado": h["estado"],
                "fecha": h["fecha"],
                "tecnico": h["tecnico"],
                "url": h["url"],
            }
            for h in historial_visitas[:5]
        ],
        "ficha_url": f"/mantenciones/maquinas/{mid}",
    }
    # Guardar en cache (TTL 60s) — siguiente click en ese equipo es instantáneo
    with _FT_JSON_LOCK:
        _FT_JSON_CACHE[mid] = (_ft_response, time.time())
    return jsonify(_ft_response)


# ════════════════════════════════════════════════════════════════════════
# SYNC fotos del levantamiento → galería del equipo (Daniel 2026-05-26)
# Soluciona el caso histórico donde el INSERT a mant_maquina_fotos pudo
# fallar silenciosamente (try/except en upload de foto del levantamiento)
# y dejó las fotos huérfanas en mant_levantamiento_fotos.
# Anti-duplicado por cloudinary_url. Idempotente.
# ════════════════════════════════════════════════════════════════════════
@app.route("/mantenciones/api/maquinas/<int:mid>/sync-fotos-lev", methods=["POST"])
@_mant_required
def mant_maquina_sync_fotos_lev(mid):
    """Copia fotos huérfanas de mant_levantamiento_fotos → mant_maquina_fotos."""
    eq = mysql_fetchone("SELECT id, cliente_id FROM mant_maquinas WHERE id=%s", (mid,))
    if not eq:
        return jsonify({"ok": False, "error": "Equipo no encontrado"}), 404

    # 1) Fotos del levantamiento que apuntan a este equipo
    huerfanas = mysql_fetchall(
        """
        SELECT lf.id, lf.levantamiento_id, lf.cloudinary_url, lf.cloudinary_public_id,
               lf.tipo_foto, lf.descripcion, lf.tomada_por, lf.tomada_at
          FROM mant_levantamiento_fotos lf
         WHERE lf.maquina_id = %s
           AND lf.cloudinary_url IS NOT NULL
           AND lf.cloudinary_url <> ''
           AND NOT EXISTS (
                 SELECT 1 FROM mant_maquina_fotos mf
                  WHERE mf.maquina_id = lf.maquina_id
                    AND mf.cloudinary_url = lf.cloudinary_url
               )
        """,
        (mid,)
    ) or []

    # 2) Fotos de visitas que apuntan a este equipo (alternativo)
    huerfanas_vis = mysql_fetchall(
        """
        SELECT vf.id, vf.visita_id, vf.cloudinary_url, vf.cloudinary_public_id,
               vf.tipo_foto, vf.descripcion, vf.subida_por AS tomada_por, vf.created_at AS tomada_at
          FROM mant_visita_fotos vf
         WHERE vf.maquina_id = %s
           AND vf.cloudinary_url IS NOT NULL
           AND vf.cloudinary_url <> ''
           AND NOT EXISTS (
                 SELECT 1 FROM mant_maquina_fotos mf
                  WHERE mf.maquina_id = vf.maquina_id
                    AND mf.cloudinary_url = vf.cloudinary_url
               )
        """,
        (mid,)
    ) or []

    copiadas = 0
    errores = []
    conn = get_mysql()
    try:
        with conn.cursor() as cur:
            for f in huerfanas:
                try:
                    cur.execute(
                        """
                        INSERT INTO mant_maquina_fotos
                          (maquina_id, archivo_path, cloudinary_url, cloudinary_public_id,
                           levantamiento_id, tipo_foto, descripcion, tomada_por, tomada_at)
                        VALUES (%s, '', %s, %s, %s, %s, %s, %s, %s)
                        """,
                        (
                            mid,
                            f["cloudinary_url"],
                            f.get("cloudinary_public_id") or "",
                            f.get("levantamiento_id"),
                            (f.get("tipo_foto") or "principal")[:30],
                            (f.get("descripcion") or "")[:500],
                            (f.get("tomada_por") or "sync")[:190],
                            f.get("tomada_at"),
                        )
                    )
                    copiadas += 1
                except Exception as e_one:
                    errores.append(f"lev_foto#{f['id']}: {str(e_one)[:120]}")
            for f in huerfanas_vis:
                try:
                    cur.execute(
                        """
                        INSERT INTO mant_maquina_fotos
                          (maquina_id, archivo_path, cloudinary_url, cloudinary_public_id,
                           visita_origen, tipo_foto, descripcion, tomada_por, tomada_at)
                        VALUES (%s, '', %s, %s, %s, %s, %s, %s, %s)
                        """,
                        (
                            mid,
                            f["cloudinary_url"],
                            f.get("cloudinary_public_id") or "",
                            f.get("visita_id"),
                            (f.get("tipo_foto") or "principal")[:30],
                            (f.get("descripcion") or "")[:500],
                            (f.get("tomada_por") or "sync")[:190],
                            f.get("tomada_at"),
                        )
                    )
                    copiadas += 1
                except Exception as e_one:
                    errores.append(f"vis_foto#{f['id']}: {str(e_one)[:120]}")
        conn.commit()
    except Exception as e:
        try: conn.rollback()
        except Exception: pass
        return jsonify({"ok": False, "error": f"Error en sync: {str(e)[:200]}"}), 500
    finally:
        try: conn.close()
        except Exception: pass

    return jsonify({
        "ok": True,
        "copiadas": copiadas,
        "candidatas_lev": len(huerfanas),
        "candidatas_vis": len(huerfanas_vis),
        "errores": errores[:5],   # primeros 5 errores si hubo
    })


# ════════════════════════════════════════════════════════════════════════
# PATCH equipo — Edición desde el modal "Ficha técnica" (Daniel 2026-05-21)
# Permite cambiar serial / estado / observaciones / ubicación con audit log
# automático. Whitelist estricto de campos editables.
# ════════════════════════════════════════════════════════════════════════
@app.route("/mantenciones/api/maquinas/<int:mid>", methods=["PATCH"])
@_mant_required
def mant_maquina_patch(mid):
    """Actualiza campos editables del equipo con auditoría completa.

    Campos permitidos (whitelist):
      serie, marca, modelo, voltaje, anio_fabricacion,
      ubicacion_sala, observaciones, estado, estado_op,
      fecha_instalacion, fecha_fin_garantia, tag_1, tag_2

    Cada cambio en un campo CRÍTICO (serie, estado, estado_op) genera un
    insert en mant_maquina_audit con valor_antes / valor_nuevo / motivo /
    usuario / fecha. Requiere `motivo` (≥5 chars) para cambios críticos.
    """
    eq = mysql_fetchone(
        "SELECT id, cliente_id, serie, marca, modelo, voltaje, "
        "       anio_fabricacion, ubicacion_sala, observaciones, "
        "       estado, estado_op, fecha_instalacion, fecha_fin_garantia, "
        "       tag_1, tag_2 "
        "  FROM mant_maquinas WHERE id=%s",
        (mid,)
    )
    if not eq:
        return jsonify({"ok": False, "error": "Equipo no encontrado"}), 404

    # Permisos: técnico/tecnico_externo NO puede editar la ficha desde acá.
    # Solo admin/superadmin/ejecutivo. La edición durante una OT pasa por
    # /api/visitas/<vid>/equipo/<mid>/datos (controlado por _tecnico_owns_visita).
    u = getattr(g, "user", None) or {}
    role_u = (u.get("role") or "").lower()
    if role_u in ("tecnico", "tecnico_externo"):
        return jsonify({
            "ok": False,
            "error": "Solo administrador, ejecutivo o supervisor puede editar "
                     "la ficha del equipo. Si necesitas cambiar algo, hazlo "
                     "desde la OT donde estás trabajando.",
        }), 403

    d = request.get_json(silent=True) or {}
    motivo = (d.get("motivo") or "").strip()[:500]

    # Whitelist con tipo y longitud máxima
    str_fields = {
        "serie": 100, "marca": 120, "modelo": 120, "voltaje": 40,
        "ubicacion_sala": 200, "observaciones": 5000,
        "tag_1": 80, "tag_2": 80,
    }
    estado_values = ("activo", "inactivo", "baja")
    estado_op_values = ("operativo", "advertencia", "critico",
                        "fuera_servicio", "en_mantencion", "en_reparacion")
    sets, vals, cambios_criticos = [], [], []

    # Campos string
    for k, maxlen in str_fields.items():
        if k in d:
            v_nuevo = (str(d.get(k) or "").strip())[:maxlen] or None
            v_antes = eq.get(k) or None
            sets.append(f"{k}=%s"); vals.append(v_nuevo)
            if k == "serie" and (v_antes or "") != (v_nuevo or ""):
                if len(motivo) < 5:
                    return jsonify({
                        "ok": False,
                        "error": "El cambio de N° serie requiere un motivo "
                                 "de al menos 5 caracteres.",
                    }), 400
                cambios_criticos.append(("serie", v_antes, v_nuevo))

    # Estado / estado_op (validar enum)
    if "estado" in d:
        v_nuevo = (str(d.get("estado") or "").strip().lower()) or None
        if v_nuevo not in (None,) + estado_values:
            return jsonify({"ok": False, "error": f"Estado inválido: {v_nuevo}"}), 400
        v_antes = (eq.get("estado") or "").lower() or None
        if v_antes != v_nuevo:
            if len(motivo) < 5:
                return jsonify({
                    "ok": False,
                    "error": "El cambio de estado del equipo requiere un motivo "
                             "de al menos 5 caracteres.",
                }), 400
            cambios_criticos.append(("estado", v_antes, v_nuevo))
        sets.append("estado=%s"); vals.append(v_nuevo)

    if "estado_op" in d:
        v_nuevo = (str(d.get("estado_op") or "").strip().lower()) or None
        if v_nuevo not in (None,) + estado_op_values:
            return jsonify({"ok": False, "error": f"Estado operacional inválido: {v_nuevo}"}), 400
        v_antes = (eq.get("estado_op") or "").lower() or None
        if v_antes != v_nuevo:
            cambios_criticos.append(("estado_op", v_antes, v_nuevo))
        sets.append("estado_op=%s"); vals.append(v_nuevo)

    # Numéricos
    if "anio_fabricacion" in d:
        try:
            v = int(d["anio_fabricacion"]) if d["anio_fabricacion"] not in (None, "") else None
        except (TypeError, ValueError):
            v = None
        sets.append("anio_fabricacion=%s"); vals.append(v)

    # Fechas (validar formato ISO)
    for f in ("fecha_instalacion", "fecha_fin_garantia"):
        if f in d:
            raw = (str(d.get(f) or "").strip()) or None
            if raw:
                try:
                    datetime.strptime(raw, "%Y-%m-%d")
                except ValueError:
                    return jsonify({"ok": False, "error": f"Formato inválido en {f} (usa YYYY-MM-DD)"}), 400
            sets.append(f"{f}=%s"); vals.append(raw)

    if not sets:
        return jsonify({"ok": False, "error": "Sin campos para actualizar"}), 400

    vals.append(mid)
    try:
        mysql_execute(
            f"UPDATE mant_maquinas SET {','.join(sets)} WHERE id=%s",
            tuple(vals)
        )
    except Exception as e:
        return jsonify({"ok": False, "error": f"Error guardando: {e}"}), 500

    # Audit log para cambios críticos
    usuario = current_username() or "sistema"
    for campo, antes, nuevo in cambios_criticos:
        try:
            mysql_execute(
                "INSERT INTO mant_maquina_audit "
                "(maquina_id, cliente_id, campo, valor_antes, valor_nuevo, "
                " motivo, usuario) VALUES (%s,%s,%s,%s,%s,%s,%s)",
                (mid, eq.get("cliente_id"), campo,
                 antes or "", nuevo or "",
                 motivo or "(sin motivo registrado)",
                 usuario[:190])
            )
        except Exception as _e_aud:
            print(f"[mant_maquina_patch] audit {campo} fallo: {_e_aud}",
                  flush=True)

    # Audit log general
    try:
        cambios_resumen = ", ".join([f"{c}: '{a}' → '{n}'" for c, a, n in cambios_criticos]) \
                        or "edición general"
        _mant_log("maquina", mid, "ficha_editada", cambios_resumen[:500])
    except Exception:
        pass

    return jsonify({
        "ok": True,
        "cambios_criticos": [
            {"campo": c, "antes": a, "nuevo": n}
            for c, a, n in cambios_criticos
        ],
        "actualizado_en": _now_chile_str("%d/%m/%Y %H:%M"),
    })


@app.route("/mantenciones/api/maquinas/<int:mid>/fotos")
@_mant_required
def mant_maquina_fotos_list(mid):
    """Galería de fotos del equipo (todas: viejas filesystem + nuevas Cloudinary).
    FIX 2026-05-21: order by tomada_at — created_at puede no estar poblado."""
    rows = mysql_fetchall(
        "SELECT id, archivo_path, cloudinary_url, descripcion, tomada_por, "
        "       tomada_at AS created_at, levantamiento_id "
        "  FROM mant_maquina_fotos WHERE maquina_id=%s "
        " ORDER BY tomada_at DESC LIMIT 200",
        (mid,)
    ) or []
    out = []
    for r in rows:
        url = r.get("cloudinary_url") or (
            f"/static/uploads/mantenciones/{r['archivo_path']}" if r.get("archivo_path") else ""
        )
        if not url:
            continue
        out.append({
            "id": r["id"],
            "url": url,
            "descripcion": r.get("descripcion") or "",
            "tomada_por": r.get("tomada_por") or "",
            "created_at": str(r["created_at"])[:16] if r.get("created_at") else "",
            "levantamiento_id": r.get("levantamiento_id"),
            "persistente": bool(r.get("cloudinary_url")),
        })
    return jsonify({"ok": True, "fotos": out})


# ─────────────────────────────────────────────
#  Arranque — inicializar tablas al cargar módulo
#  (funciona con `python app.py` Y `flask run`)
# ─────────────────────────────────────────────

try:
    from pickups_module import register_pickup_routes
    register_pickup_routes(app, globals())
    print("[ILUS] Modulo de retiros registrado.")
except Exception as _pickup_reg_err:
    print(f"[ILUS][WARN] register_pickup_routes: {_pickup_reg_err}")

# ════════════════════════════════════════════════════════════════════════
#  COLD-START PERFORMANCE — saltar migraciones idempotentes en cada worker
# ════════════════════════════════════════════════════════════════════════
# Audit Daniel 2026-05-18: cada worker Gunicorn (max-requests=1000 + jitter)
# se recicla periódicamente. Al arrancar, app.py ejecuta:
#   - init_db()               → ~50 ALTER TABLE  + 5 CREATE TABLE
#   - init_transporte_tables()
#   - init_comunicaciones_tables()
#   - init_mantenciones_tables() → ~200 ALTER TABLE + 30 CREATE TABLE
# TOTAL: ~272 ALTER + 85 CREATE en cada cold start. Cada ALTER fallido
# (porque la columna existe) es un round-trip a Clever Cloud MySQL — entre
# 5-30ms cada uno. Worst case: 10+ segundos de cold-start.
#
# Solución: ENV VAR `ILUS_SKIP_MIGRATIONS=1` salta TODAS las migraciones.
# La primera vez que se despliega (o cuando se agrega una migración nueva),
# Daniel desactiva la env var por 1 deploy, luego la reactiva.
# Default es CORRER las migraciones (backward compatible).
_SKIP_MIGS = (os.environ.get("ILUS_SKIP_MIGRATIONS", "").strip().lower()
              in ("1", "true", "yes", "on"))

# ── ⚡ Pool pymssql Random SQL Server: warmup + keepalive ─────────────────
# 1) WARMUP: el pool se inicializa lazy en la primera query. Eso paga
#    ~500-1000ms en el PRIMER request (handshake TLS + login). Lo forzamos
#    en boot para que los requests reales nazcan calientes.
# 2) KEEPALIVE: cloud.random.cl cierra conexiones IDLE después de ~5-10
#    minutos. Si Daniel deja la app abierta y no hace queries en un rato, la
#    siguiente query paga reconexión (~500-3000ms). Un thread daemon hace
#    "SELECT 1" cada 60s para mantener la conexión cached siempre viva.
# 3) FAILSAFE: si Random SQL está caído, ambos fallan silenciosos y el resto
#    del app sigue funcionando (sin cubicador/SQL pero sin crashear).
try:
    import threading as _th
    def _warmup_random_pool():
        try:
            t0 = time.time()
            pool = _random_sql_pool()
            if pool is None:
                print("[RANDOM SQL][warmup] pool no inicializado (falta config o ImportError)",
                      flush=True)
                return
            # Ejecutar query trivial para forzar handshake + abrir conexión cached
            _random_sql_query("SELECT TOP 1 1 AS x FROM MAEEN", max_rows=1)
            print(f"[RANDOM SQL][warmup] pool caliente en {int((time.time()-t0)*1000)}ms",
                  flush=True)
        except Exception as _wu_e:
            print(f"[RANDOM SQL][warmup] falló (no crítico): {_wu_e}", flush=True)
    _th.Thread(target=_warmup_random_pool, daemon=True, name="random-sql-warmup").start()

    def _keepalive_random_pool():
        """Mantiene viva la conexión cached del pool con un ping cada 60s.
        Sin esto, la primera query después de >5min idle paga reconexión
        (los famosos 5189ms que reportó Daniel)."""
        # Espera inicial: dejar que el warmup termine
        time.sleep(75)
        while True:
            try:
                t0 = time.time()
                _random_sql_query("SELECT 1 AS x", max_rows=1)
                ms = int((time.time() - t0) * 1000)
                if ms > 800:
                    # Si el ping mismo tarda >800ms, la conexión estaba muerta
                    # y se reconectó. Lo logueamos para ver si hay patrones.
                    print(f"[RANDOM SQL][keepalive] ping lento ({ms}ms) — "
                          f"posible reconnect", flush=True)
            except Exception:
                # Silencioso — no queremos spam si Random SQL está caído
                pass
            time.sleep(60)
    _th.Thread(target=_keepalive_random_pool, daemon=True,
               name="random-sql-keepalive").start()
    print("[RANDOM SQL] Keepalive activo (ping cada 60s para evitar idle disconnect)",
          flush=True)
except Exception as _wu_outer:
    print(f"[RANDOM SQL][warmup/keepalive] no se pudo agendar: {_wu_outer}", flush=True)


def _ensure_transporte_columns():
    """Garantiza las columnas nuevas de transport_commitments AUNQUE
    ILUS_SKIP_MIGRATIONS esté activo.

    Con el skip de migraciones (cold-start rápido), las columnas agregadas
    en código nuevo NO se aplican en prod hasta correr migraciones manualmente.
    Eso dejó el detalle del manifiesto con 500 ("Unknown column 'region'").
    Esta función chequea information_schema (1 SELECT barato) y agrega solo las
    columnas faltantes — idempotente y rápida (no toca nada si ya existen)."""
    needed = {
        "region":             "VARCHAR(80) NULL",
        "cod_postal":         "VARCHAR(20) NULL",
        "peso_export":        "DECIMAL(10,3) DEFAULT 0",
        "n_bultos":           "INT DEFAULT 1",
        "cobertura_pct":      "DECIMAL(5,1) DEFAULT 0",
        "cant_total_zz":      "DECIMAL(12,3) DEFAULT 0",
        "cant_despachada_zz": "DECIMAL(12,3) DEFAULT 0",
        "observaciones":      "TEXT NULL",
        "zz_skus":            "VARCHAR(120) NULL",
        # Finanzas/margen (visión Daniel 2026-05-25): control de ganancia/pérdida.
        "zz_envio":           "DECIMAL(12,2) DEFAULT 0",  # lo que cobró SPHS por el despacho (ERP)
        "costo_courier":      "DECIMAL(12,2) DEFAULT 0",  # lo que SPHS paga al courier (cotizado)
        "autorizado_por":     "VARCHAR(190) NULL",        # quién autoriza si va sin precio / a pérdida
        "motivo_envio":       "VARCHAR(500) NULL",        # motivo/observación obligatoria
        "es_garantia":        "TINYINT(1) DEFAULT 0",     # si el envío es por garantía
        # Cubicaje declarado (máxima información, que corra aguas abajo y no se pierda)
        "peso_real":          "DECIMAL(12,3) DEFAULT 0",  # kg reales totales del documento
        "peso_vol":           "DECIMAL(12,3) DEFAULT 0",  # kg volumétricos totales
        "volumen_m3":         "DECIMAL(12,4) DEFAULT 0",  # volumen total en m³
        "peso_predominante":  "DECIMAL(12,3) DEFAULT 0",  # max(real,vol) por línea, sumado
        "productos_json":     "MEDIUMTEXT NULL",           # productos declarados del doc (árbol manifiesto)
    }
    existing = {
        (r.get("COLUMN_NAME") or "").lower()
        for r in (mysql_fetchall(
            "SELECT COLUMN_NAME FROM information_schema.COLUMNS "
            "WHERE TABLE_SCHEMA=DATABASE() AND TABLE_NAME='transport_commitments'"
        ) or [])
    }
    faltantes = [c for c in needed if c.lower() not in existing]
    for col in faltantes:
        try:
            mysql_execute(f"ALTER TABLE transport_commitments ADD COLUMN {col} {needed[col]}")
            print(f"[ensure_tr_cols] columna agregada: {col}", flush=True)
        except Exception as e_add:
            print(f"[ensure_tr_cols] no se pudo agregar {col}: {e_add}", flush=True)
    return faltantes


def _ensure_transport_couriers_formato_export():
    """Garantiza la columna transport_couriers.formato_export AUNQUE
    ILUS_SKIP_MIGRATIONS esté activo. Sin esta columna, el export del
    manifiesto cae con OperationalError (1054) 'Unknown column'.

    Es idempotente: SELECT a information_schema + ALTER solo si falta.
    También repuebla valores conocidos (FedEx, Clickex, Felca/Milling)
    para que la auto-detección del export agarre el formato correcto."""
    try:
        existing = {
            (r.get("COLUMN_NAME") or "").lower()
            for r in (mysql_fetchall(
                "SELECT COLUMN_NAME FROM information_schema.COLUMNS "
                "WHERE TABLE_SCHEMA=DATABASE() AND TABLE_NAME='transport_couriers'"
            ) or [])
        }
    except Exception as _eci:
        print(f"[ensure_couriers_fmt] no se pudo leer schema: {_eci}", flush=True)
        return False
    if "formato_export" not in existing:
        try:
            mysql_execute(
                "ALTER TABLE transport_couriers ADD COLUMN formato_export "
                "VARCHAR(20) DEFAULT 'generic' "
                "COMMENT 'Plantilla de carga masiva: fedex|simplyroute|clickex|generic'"
            )
            print("[ensure_couriers_fmt] columna formato_export agregada", flush=True)
        except Exception as _ec:
            print(f"[ensure_couriers_fmt] no se pudo agregar columna: {_ec}", flush=True)
            return False
    # Repoblar valores conocidos (no pisa si ya están seteados a algo distinto de 'generic'/NULL)
    seeds = [
        ("fedex",       "fedex"),
        ("clickex",     "clickex"),
        ("felca",       "simplyroute"),
        ("milling",     "simplyroute"),
        ("melling",     "simplyroute"),
    ]
    for kw, fmt in seeds:
        try:
            mysql_execute(
                "UPDATE transport_couriers SET formato_export=%s "
                "WHERE LOWER(nombre) LIKE %s "
                "AND (formato_export IS NULL OR formato_export='' OR formato_export='generic')",
                (fmt, f"%{kw}%")
            )
        except Exception:
            pass
    return True


def _ensure_transporte_labels_table():
    """Garantiza la tabla transport_labels AUNQUE ILUS_SKIP_MIGRATIONS esté activo.

    Es la base de trazabilidad de las etiquetas de bultos (módulo de etiquetas
    de transporte). Una fila por bulto. CREATE TABLE IF NOT EXISTS es idempotente
    y barato — no hace nada si la tabla ya existe. Requiere app context
    (mysql_execute usa get_db())."""
    mysql_execute("""
        CREATE TABLE IF NOT EXISTS transport_labels (
            id            INT AUTO_INCREMENT PRIMARY KEY,
            commitment_id INT NOT NULL,
            manifest_id   INT NULL,
            bulto_num     INT NOT NULL,
            bulto_total   INT NOT NULL,
            courier       VARCHAR(80),
            estado        VARCHAR(40)  DEFAULT 'generada',
            tracking_code VARCHAR(60)  NULL,
            created_at    DATETIME     DEFAULT CURRENT_TIMESTAMP,
            updated_at    DATETIME     NULL,
            UNIQUE KEY uq_label (commitment_id, manifest_id, bulto_num),
            INDEX idx_lbl_commitment (commitment_id),
            INDEX idx_lbl_manifest   (manifest_id)
        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
    """)


def _ensure_mant_reportes_columns():
    """Garantiza columnas nuevas de mant_reportes AUNQUE ILUS_SKIP_MIGRATIONS=1.

    Igual que _ensure_transporte_columns: con el skip de migraciones, las
    columnas agregadas en init_mantenciones_tables NO se aplican en prod.
    Sin esto, leer/escribir `garantia_aplica` en los reportes daría
    'Unknown column'. 1 SELECT barato en cold-start; ALTER solo la 1ª vez."""
    needed = {
        # Garantía transversal a nivel de reporte (separada del tipo).
        "garantia_aplica": "TINYINT(1) NOT NULL DEFAULT 0 "
                           "COMMENT 'Garantía: 1=aplica (cubierto), 0=no aplica (pago)'",
    }
    existing = {
        (r.get("COLUMN_NAME") or "").lower()
        for r in (mysql_fetchall(
            "SELECT COLUMN_NAME FROM information_schema.COLUMNS "
            "WHERE TABLE_SCHEMA=DATABASE() AND TABLE_NAME='mant_reportes'"
        ) or [])
    }
    faltantes = [c for c in needed if c.lower() not in existing]
    for col in faltantes:
        try:
            mysql_execute(f"ALTER TABLE mant_reportes ADD COLUMN {col} {needed[col]}")
            print(f"[ensure_rep_cols] columna agregada: {col}", flush=True)
        except Exception as e_add:
            print(f"[ensure_rep_cols] no se pudo agregar {col}: {e_add}", flush=True)

    # Garantizar que el ENUM de `tipo` incluya 'visita_tecnica' (separación
    # garantía↔tipo). Idempotente: solo hace MODIFY si falta el valor. Mantiene
    # 'garantia' por compat con reportes viejos.
    try:
        _tipo_col = mysql_fetchone(
            "SELECT COLUMN_TYPE FROM information_schema.COLUMNS "
            "WHERE TABLE_SCHEMA=DATABASE() AND TABLE_NAME='mant_reportes' "
            "  AND COLUMN_NAME='tipo'")
        _ct = ((_tipo_col or {}).get("COLUMN_TYPE") or "").lower()
        if _ct and "visita_tecnica" not in _ct:
            mysql_execute(
                "ALTER TABLE mant_reportes MODIFY tipo "
                "ENUM('mantencion','instalacion','inspeccion','visita_tecnica',"
                "'garantia','otro') DEFAULT 'mantencion'")
            print("[ensure_rep_cols] ENUM tipo ampliado con 'visita_tecnica'", flush=True)
    except Exception as e_enum:
        print(f"[ensure_rep_cols] no se pudo ampliar ENUM tipo: {e_enum}", flush=True)
    return faltantes


